// @ts-check
// The DRC first-visit intro animation: the logotype's Swedish-flag vortex
// (blue disc, twisted yellow arms) — a fleet of them, spinning at different
// sizes — untwists into beach-umbrella canopies, gets its contours drawn and
// its color removed until only a wire drawing remains, and then the camera
// swings a quarter circle down from the top view while the wireframe
// umbrellas — now fully 3D, shaft and hook included — spin, sway and sink
// slowly out of the sky. The umbrella is the tier's own symbol: DRC is the
// sheltered, all-client-side side of the site.
//
// Structured like every DRC module: a PURE core (the timeline parameters and
// the 3D geometry — everything below `playUmbrellaIntro`) that runs in Node
// for the unit suite (public/js/umbrella-intro.test.js), and a DOM layer
// (one fixed canvas, requestAnimationFrame) that only ever runs in the
// browser. No dependencies, no server involvement — the animation is a
// static asset like the rest of the /cure tier.
//
// The whole thing is decoration: tap anywhere to skip, and the caller gates
// it on first visit + prefers-reduced-motion. Nothing downstream awaits it
// for correctness.

// ---- the timeline (pure) -----------------------------------------------------------

// The whole scene runs 2.5× the originally-designed pace (2026-07-12
// directive: the first cut was "a little bit slow"), scaled further by the
// admin's site-config `anim_speed` slider (served publicly at GET
// /api/anim; slider center = 1 = exactly this default). Speed scales the
// CLOCK, not the marks — T below stays the designed shape, and everything
// (phases, spin, sway, sink) hastens uniformly.
export const BASE_SPEED = 2.5;

/** The admin multiplier, defensively: garbage in → the default 1; honest
 * values clamp to [0.25, 4] (the same clamp src/config.js enforces).
 * @param {unknown} v */
export function clampAnimMult(v) {
  const n = Number(v);
  if (!Number.isFinite(n) || n <= 0) return 1;
  return Math.min(4, Math.max(0.25, n));
}

// Phase boundaries in ms of DESIGN time (divide by BASE_SPEED × multiplier
// for wall-clock). One shared clock; every visual parameter below is
// a ramp between two of these marks, so the phases overlap smoothly instead
// of cutting: swirl → untwist → contours drawn while color drains → the
// quarter-circle camera drop → fade.
export const T = {
  swirlEnd: 3200, // pure logo-vortex spinning & pulsing until here
  untwistEnd: 5800, // arms straighten: vortex → umbrella top view
  wireEnd: 7600, // contours fully drawn
  fillGone: 8600, // color fully removed — wire only
  tiltStart: 8600, // camera starts the quarter circle…
  tiltEnd: 12600, // …and is level with the umbrellas here
  fadeStart: 13600,
  end: 14800,
};

/** @param {number} v */
export const clamp01 = (v) => (v < 0 ? 0 : v > 1 ? 1 : v);

/** Smoothstep — every ramp uses it so phase edges have no velocity kinks.
 * @param {number} v */
export const smooth = (v) => {
  v = clamp01(v);
  return v * v * (3 - 2 * v);
};

/** @param {number} t @param {number} a @param {number} b */
const ramp = (t, a, b) => smooth((t - a) / (b - a));

/**
 * Every time-driven visual parameter at clock time t (ms).
 * @param {number} t
 * @returns {{twist:number, scallop:number, wire:number, fill:number,
 *           cam:number, camP:number, shaft:number, spinRate:number,
 *           pulse:number, fade:number, done:boolean}}
 */
export function paramsAt(t) {
  const camP = ramp(t, T.tiltStart, T.tiltEnd);
  return {
    // 1 = the logo's full vortex twist, 0 = straight umbrella ribs.
    twist: 1 - ramp(t, T.swirlEnd, T.untwistEnd),
    // The scalloped umbrella edge grows in exactly as the twist leaves.
    scallop: ramp(t, T.swirlEnd, T.untwistEnd),
    // Contour drawing progress (ribs → rings → edge, staggered in draw).
    wire: ramp(t, T.untwistEnd, T.wireEnd),
    // Panel color; starts draining once the contours are half drawn.
    fill: 1 - ramp(t, (T.untwistEnd + T.wireEnd) / 2, T.fillGone),
    // Camera pitch: 0 = straight down (top view) … π/2 = side view.
    cam: (camP * Math.PI) / 2,
    camP,
    // Shaft + hook exist only once perspective starts to mean anything.
    shaft: clamp01(camP * 1.8),
    // Spin never stops, but calms from vortex-fast to a lazy umbrella turn.
    spinRate: 1 - 0.7 * ramp(t, T.swirlEnd, T.tiltStart),
    // The size-pulsing of the swirl phase, gone by the wire phase.
    pulse: 1 - ramp(t, T.untwistEnd, T.wireEnd),
    fade: 1 - ramp(t, T.fadeStart, T.end),
    done: t >= T.end,
  };
}

// ---- the geometry (pure) -----------------------------------------------------------

export const PANELS = 8; // 4 yellow + 4 blue, alternating — the untwisted logo
export const MAX_TWIST = 2.35; // radians of arm curl at the canopy edge, twist=1

/** Angular offset of a rib at radius fraction r for a given twist level —
 * the logo's arm curl. Sub-linear in r so the curl concentrates outward,
 * matching the logotype.
 * @param {number} rFrac @param {number} twist */
export function twistOffset(rFrac, twist) {
  return twist * MAX_TWIST * Math.pow(clamp01(rFrac), 0.75);
}

/** Scalloped canopy edge: radius factor across one panel (frac 0..1 rib to
 * rib) — 1 at the ribs, dipping between them as `scallop` grows.
 * @param {number} panelFrac @param {number} scallop @param {number} [depth] */
export function scallopFactor(panelFrac, scallop, depth = 0.085) {
  return 1 - depth * scallop * Math.sin(Math.PI * clamp01(panelFrac));
}

/** Canopy dome height (z, up positive) at radius fraction r: apex at the
 * center, rim at 0.
 * @param {number} rFrac @param {number} domeH */
export function canopyZ(rFrac, domeH) {
  return domeH * (1 - rFrac * rFrac);
}

/** Orthographic camera pitching about the world x-axis. cam=0 looks straight
 * down (top view: screen y = -y); cam=π/2 looks from the side (screen
 * y = -z, i.e. up in the world is up on screen).
 * @param {{x:number, y:number, z:number}} p @param {number} cam
 * @returns {{x:number, y:number}} */
export function project(p, cam) {
  return { x: p.x, y: -(p.y * Math.cos(cam) + p.z * Math.sin(cam)) };
}

// The fleet: a handful of umbrellas in deliberately different sizes, spins
// and directions ("a bunch of them, in different sizes"). fx/fy are
// viewport fractions of the top-view scatter; zLift is how high each one
// hangs in the sky once the camera drops (fraction of the viewport height);
// delay staggers their appearance at the start.
export const FLEET = [
  { fx: 0.30, fy: 0.34, s: 0.335, speed: 1.0, dir: 1, phase: 0.0, zLift: 0.55, delay: 0 },
  { fx: 0.72, fy: 0.24, s: 0.215, speed: 1.35, dir: -1, phase: 1.7, zLift: 0.95, delay: 260 },
  { fx: 0.55, fy: 0.64, s: 0.42, speed: 0.8, dir: 1, phase: 3.1, zLift: 0.18, delay: 520 },
  { fx: 0.15, fy: 0.74, s: 0.175, speed: 1.6, dir: -1, phase: 4.2, zLift: 1.25, delay: 780 },
  { fx: 0.87, fy: 0.68, s: 0.26, speed: 1.15, dir: 1, phase: 2.3, zLift: 0.75, delay: 1040 },
  { fx: 0.43, fy: 0.11, s: 0.145, speed: 1.8, dir: -1, phase: 5.0, zLift: 1.6, delay: 1300 },
];

// ---- the DOM layer (browser only) --------------------------------------------------

const YELLOW = "#f5c518"; // the logotype's golden swirl
const BLUE = "#1a56b0"; // the logotype's flag-blue field
const INK = "#3d3418"; // drc.css --text: the wire drawing's ink
const KHAKI = "#c3b091"; // drc.css --bg

let playing = false;

/**
 * Plays the intro once over the whole viewport. Resolves the caller via
 * onDone when finished or skipped (tap anywhere). Never throws into the
 * caller — animation failure must not cost a chat. `speed` is the admin
 * multiplier from /api/anim (1 = default; the 2.5× BASE_SPEED is applied
 * here on top of it).
 * @param {{ onDone?: () => void, speed?: number }} [opts]
 */
export function playUmbrellaIntro(opts = {}) {
  const onDone = opts.onDone || (() => {});
  const clockRate = BASE_SPEED * clampAnimMult(opts.speed);
  if (playing || typeof document === "undefined") {
    onDone();
    return;
  }
  playing = true;

  const canvas = document.createElement("canvas");
  canvas.setAttribute("aria-hidden", "true");
  canvas.style.cssText =
    "position:fixed;inset:0;z-index:30;width:100%;height:100%;cursor:pointer;" +
    "transition:opacity .3s ease;";
  document.body.appendChild(canvas);
  const ctx = canvas.getContext("2d");
  if (!ctx) {
    canvas.remove();
    playing = false;
    onDone();
    return;
  }

  function resize() {
    const dpr = Math.min(2, window.devicePixelRatio || 1);
    canvas.width = Math.round(window.innerWidth * dpr);
    canvas.height = Math.round(window.innerHeight * dpr);
    ctx?.setTransform(dpr, 0, 0, dpr, 0, 0);
  }
  resize();
  window.addEventListener("resize", resize);

  // Per-umbrella mutable state: accumulated spin angle (integrated so the
  // spin-rate ramp slows the turn without any angle jump).
  const fleet = FLEET.map((u) => ({ ...u, spin: u.phase * 1.3 }));

  const start = performance.now();
  let last = start;
  let raf = 0;

  // First tap stops and REMOVES the animation immediately — no fade-out to
  // wait through, nothing left in the way of the page underneath.
  canvas.addEventListener("pointerdown", cleanup);

  function cleanup() {
    cancelAnimationFrame(raf);
    window.removeEventListener("resize", resize);
    canvas.remove();
    playing = false;
    onDone();
  }

  /** One canopy point through the whole pipeline: local canopy coords →
   * spin → sway → world offset → camera projection → screen px.
   * @param {{x:number,y:number,z:number}} p
   * @param {{cosRX:number,sinRX:number,cosRY:number,sinRY:number,
   *          cx:number,worldY:number,zOff:number,cam:number,H:number}} f */
  function toScreen(p, f) {
    // sway about x, then y (small dangling angles, only in the 3D phase)
    const y1 = p.y * f.cosRX - p.z * f.sinRX;
    const z1 = p.y * f.sinRX + p.z * f.cosRX;
    const x1 = p.x * f.cosRY + z1 * f.sinRY;
    const z2 = -p.x * f.sinRY + z1 * f.cosRY;
    const pr = project({ x: x1, y: f.worldY + y1, z: f.zOff + z2 }, f.cam);
    return { x: f.cx + pr.x, y: f.H * 0.5 + pr.y };
  }

  /** @param {number} now */
  function frame(now) {
    if (!ctx) return cleanup();
    // Design-time clock: real elapsed ms × the speed (BASE_SPEED × the
    // admin multiplier). dt drives the spin integration, so it scales too.
    const dt = Math.min(50, now - last) * clockRate;
    last = now;
    const t = (now - start) * clockRate;
    const P = paramsAt(t);
    if (P.done) return cleanup();

    const W = window.innerWidth;
    const H = window.innerHeight;
    const S = Math.min(W, H);

    // Backdrop: the tier's khaki, with a sky sheen growing from the top as
    // the camera comes level.
    ctx.clearRect(0, 0, W, H);
    ctx.fillStyle = KHAKI;
    ctx.fillRect(0, 0, W, H);
    if (P.camP > 0) {
      const sky = ctx.createLinearGradient(0, 0, 0, H * 0.7);
      sky.addColorStop(0, `rgba(255,255,255,${0.38 * P.camP})`);
      sky.addColorStop(1, "rgba(255,255,255,0)");
      ctx.fillStyle = sky;
      ctx.fillRect(0, 0, W, H);
    }

    for (const u of fleet) {
      const appear = smooth((t - u.delay) / 500);
      if (appear <= 0) continue;
      u.spin += u.dir * u.speed * P.spinRate * 0.0016 * dt;

      const pulse = 1 + 0.14 * P.pulse * Math.sin(t * 0.0023 * u.speed + u.phase);
      const R = u.s * S * 0.55 * (0.6 + 0.4 * appear) * pulse;
      const domeH = 0.34 * R;
      const swayAmp = 0.11 * P.camP;
      const rx = swayAmp * Math.sin(t * 0.0011 + u.phase);
      const ry = 0.8 * swayAmp * Math.cos(t * 0.0009 + u.phase * 1.4);
      // "Dangle down from the sky": each umbrella lifts to its own height
      // as the camera drops, then sinks slowly for the rest of the scene.
      const sink = t > T.tiltStart ? ((t - T.tiltStart) / 1000) * 0.022 * H : 0;
      const f = {
        cosRX: Math.cos(rx),
        sinRX: Math.sin(rx),
        cosRY: Math.cos(ry),
        sinRY: Math.sin(ry),
        cx: u.fx * W,
        worldY: (0.5 - u.fy) * H * 0.8,
        zOff: u.zLift * P.camP * H * 0.3 - sink,
        cam: P.cam,
        H,
      };

      /** @param {number} rFrac @param {number} theta @param {number} [edgeF] */
      const pt = (rFrac, theta, edgeF) => {
        const a = theta + twistOffset(rFrac, P.twist) + u.spin;
        const r = rFrac * R * (edgeF ?? 1);
        return toScreen(
          { x: r * Math.cos(a), y: r * Math.sin(a), z: canopyZ(rFrac, domeH) },
          f
        );
      };

      const panelA = (2 * Math.PI) / PANELS;

      // -- colored panels (the vortex, then the beach-umbrella top) --------
      if (P.fill > 0.01) {
        ctx.globalAlpha = P.fill * appear;
        for (let i = 0; i < PANELS; i++) {
          const a0 = i * panelA;
          const a1 = a0 + panelA;
          ctx.beginPath();
          const c = pt(0, a0);
          ctx.moveTo(c.x, c.y);
          for (let k = 1; k <= 8; k++) {
            const p = pt(k / 8, a0);
            ctx.lineTo(p.x, p.y);
          }
          for (let k = 0; k <= 10; k++) {
            const fr = k / 10;
            const p = pt(1, a0 + fr * panelA, scallopFactor(fr, P.scallop));
            ctx.lineTo(p.x, p.y);
          }
          for (let k = 8; k >= 0; k--) {
            const p = pt(k / 8, a1);
            ctx.lineTo(p.x, p.y);
          }
          ctx.closePath();
          ctx.fillStyle = i % 2 ? BLUE : YELLOW;
          ctx.fill();
        }
      }

      // -- the wire drawing (contours), drawn in progressively ------------
      if (P.wire > 0) {
        // Staggered so the contours visibly get DRAWN: ribs first, then the
        // inner rings, then the scalloped edge closes the figure.
        const ribP = clamp01(P.wire / 0.45);
        const ringP = clamp01((P.wire - 0.25) / 0.45);
        const edgeP = clamp01((P.wire - 0.5) / 0.5);
        ctx.globalAlpha = appear;
        ctx.strokeStyle = INK;
        ctx.lineWidth = Math.max(1, R * 0.014);
        ctx.lineCap = "round";
        ctx.lineJoin = "round";

        if (ribP > 0) {
          for (let i = 0; i < PANELS; i++) {
            const a0 = i * panelA;
            const steps = Math.ceil(12 * ribP);
            ctx.beginPath();
            const c = pt(0, a0);
            ctx.moveTo(c.x, c.y);
            for (let k = 1; k <= steps; k++) {
              const p = pt(Math.min(k / 12, ribP), a0);
              ctx.lineTo(p.x, p.y);
            }
            ctx.stroke();
          }
        }
        for (const ringR of [0.45, 0.75]) {
          if (ringP <= 0) break;
          const total = 48;
          const steps = Math.ceil(total * ringP);
          ctx.beginPath();
          const p0 = pt(ringR, 0);
          ctx.moveTo(p0.x, p0.y);
          for (let k = 1; k <= steps; k++) {
            const p = pt(ringR, (k / total) * 2 * Math.PI);
            ctx.lineTo(p.x, p.y);
          }
          ctx.stroke();
        }
        if (edgeP > 0) {
          const perPanel = 10;
          const total = PANELS * perPanel;
          const steps = Math.ceil(total * edgeP);
          ctx.beginPath();
          const p0 = pt(1, 0, scallopFactor(0, P.scallop));
          ctx.moveTo(p0.x, p0.y);
          for (let k = 1; k <= steps; k++) {
            const panel = Math.floor((k - 1) / perPanel);
            const fr = (k - panel * perPanel) / perPanel;
            const p = pt(1, (panel + fr) * panelA, scallopFactor(fr, P.scallop));
            ctx.lineTo(p.x, p.y);
          }
          ctx.stroke();
        }

        // -- shaft, tip and hook: the third dimension ----------------------
        if (P.shaft > 0) {
          ctx.globalAlpha = appear * P.shaft;
          ctx.lineWidth = Math.max(1.2, R * 0.02);
          const axis = (/** @type {number} */ z) =>
            toScreen({ x: 0, y: 0, z }, f);
          const tip = axis(domeH + 0.22 * R);
          const apex = axis(domeH);
          const bottom = axis(-0.95 * R);
          ctx.beginPath();
          ctx.moveTo(tip.x, tip.y);
          ctx.lineTo(apex.x, apex.y);
          ctx.moveTo(apex.x, apex.y);
          ctx.lineTo(bottom.x, bottom.y);
          ctx.stroke();
          // The J-hook, in the plane the spin carries around.
          const hr = 0.13 * R;
          ctx.beginPath();
          let first = true;
          for (let k = 0; k <= 14; k++) {
            const a = Math.PI + (k / 14) * (Math.PI + 0.6);
            const hx = hr + hr * Math.cos(a);
            const hz = -0.95 * R + hr * Math.sin(a);
            const p = toScreen(
              {
                x: hx * Math.cos(u.spin),
                y: hx * Math.sin(u.spin),
                z: hz,
              },
              f
            );
            if (first) {
              ctx.moveTo(p.x, p.y);
              first = false;
            } else ctx.lineTo(p.x, p.y);
          }
          ctx.stroke();
        }
      }
      ctx.globalAlpha = 1;
    }

    // Skip hint.
    ctx.globalAlpha = 0.55;
    ctx.fillStyle = INK;
    ctx.font = "13px system-ui, sans-serif";
    ctx.textAlign = "center";
    ctx.fillText("tap to skip", W / 2, H - 18);
    ctx.globalAlpha = 1;

    canvas.style.opacity = String(P.fade);
    raf = requestAnimationFrame(frame);
  }

  raf = requestAnimationFrame(frame);
}

// Thin fetch wrappers for /api/games/tokemon/* (the games-registry dispatch
// seam, src/games.js) — every call returns the parsed JSON body; non-2xx
// throws an Error carrying the server's message so the UI can toast it
// verbatim.

/**
 * @param {string} path  Route under /api/games/tokemon/.
 * @param {RequestInit} [opts]
 * @returns {Promise<any>} The parsed body; non-2xx throws an Error with
 *   `.status` and `.body` attached.
 */
async function call(path, opts) {
  const res = await fetch(`/api/games/tokemon/${path}`, opts);
  let body = null;
  try {
    body = await res.json();
  } catch {
    body = null;
  }
  if (!res.ok) {
    const err = new Error(body?.error || `HTTP ${res.status}`);
    err.status = res.status;
    err.body = body;
    throw err;
  }
  return body;
}

const post = (path, payload) =>
  call(path, {
    method: "POST",
    headers: { "content-type": "application/json" },
    body: JSON.stringify(payload ?? {}),
  });

export const getState = () => call("state");
export const chooseStarter = (starter) => post("starter", { starter });
export const getSpawns = (lat, lng) => call(`spawns?lat=${lat.toFixed(6)}&lng=${lng.toFixed(6)}`);
export const encounter = (spawnId, lat, lng) => post("encounter", { spawnId, lat, lng });
export const collect = (spawnId, lat, lng) => post("collect", { spawnId, lat, lng });
export const battleAction = (action) => post("battle", { action });
export const heal = () => post("heal");
export const party = (payload) => post("party", payload);
export const scene = (lat, lng, heading) =>
  call(`scene?lat=${lat.toFixed(6)}&lng=${lng.toFixed(6)}&heading=${Math.round(heading)}`);
export const go = (command, lat, lng, heading) => post("go", { command, lat, lng, heading });

// The battle overlay: renders the server's battle state, sends one intent
// per turn, and plays the returned event list back as log lines + HP-bar
// updates. All rules live server-side — this file only presents. The event
// vocabulary it renders is the BattleEvent typedef in src/tokemon.js.

const TYPE_LABEL = {
  neural: "Neural",
  compute: "Compute",
  data: "Data",
  code: "Code",
  spark: "Spark",
  logic: "Logic",
  adversarial: "Adversarial",
  phantom: "Phantom",
};

const BALL_LABEL = { tokeball: "Tokeball", megaball: "Megaball", hyperball: "Hyperball" };
const HEAL_LABEL = { potion: "Patch (+20)", superpotion: "Hotfix (+50)", revive: "Reboot" };

const esc = (s) => String(s).replace(/[&<>"]/g, (c) => ({ "&": "&amp;", "<": "&lt;", ">": "&gt;", '"': "&quot;" })[c]);
const sleep = (ms) => new Promise((r) => setTimeout(r, ms));

/**
 * @param {HTMLElement} root  Where the overlay element is appended.
 * @param {{
 *   onAction: (action: object) => Promise<{events?: object[], battle?: object|null, save?: object}>,
 *   onEnd?: (result: string, save: object) => void,
 * }} hooks  onAction posts one battle intent; onEnd fires after the
 *   overlay closes (won/lost/caught/fled).
 * @returns {{open: (battle: object, save: object) => void, isOpen: () => boolean}}
 */
export function createBattleUI(root, { onAction, onEnd }) {
  let save = null;
  let battle = null;
  let busy = false;
  let moveNames = {}; // moveId → display name, learned from the party payload

  const el = document.createElement("div");
  el.id = "tk-battle";
  el.hidden = true;
  root.appendChild(el);

  const active = () => save?.party.find((c) => c.uid === battle?.activeUid) || null;

  function hpBar(hp, maxHp) {
    const pct = Math.max(0, Math.min(100, (hp / maxHp) * 100));
    const cls = pct < 20 ? "crit" : pct < 50 ? "low" : "";
    return `<div class="tk-hpbar"><div class="tk-hpfill ${cls}" style="width:${pct}%"></div></div>
      <span class="tk-hpnum">${hp}/${maxHp}</span>`;
  }

  function creatureCard(c, side) {
    if (!c) return "";
    const types = (c.types || []).map((t) => `<span class="tk-type tk-type-${t}">${TYPE_LABEL[t]}</span>`).join("");
    return `<div class="tk-card tk-${side}">
      <div class="tk-card-head"><span class="tk-emoji">${c.emoji || "❔"}</span>
        <b>${esc(c.name)}</b> <span class="tk-lv">Lv ${c.level}</span> ${types}
        ${side === "foe" && c.count > 1 ? `<span class="tk-lv">${c.idx + 1}/${c.count}</span>` : ""}</div>
      ${hpBar(c.hp, c.maxHp)}
    </div>`;
  }

  function actionsHtml() {
    const me = active();
    if (!me) return "";
    const moves = me.moves
      .map(
        (m) => `<button class="tk-move tk-type-${m.type}" data-move="${m.id}" ${m.pp <= 0 || busy ? "disabled" : ""}>
          ${esc(m.name)}<small>${TYPE_LABEL[m.type]} · ${m.power} · PP ${m.pp}/${m.maxPp}</small></button>`,
      )
      .join("");
    const balls = Object.entries(BALL_LABEL)
      .filter(([id]) => save.items[id] > 0)
      .map(([id, label]) => `<button data-ball="${id}" ${busy ? "disabled" : ""}>${label} ×${save.items[id]}</button>`)
      .join("");
    const heals = Object.entries(HEAL_LABEL)
      .filter(([id]) => save.items[id] > 0)
      .map(([id, label]) => `<button data-item="${id}" ${busy ? "disabled" : ""}>${label} ×${save.items[id]}</button>`)
      .join("");
    const switches = save.party
      .filter((c) => c.uid !== me.uid && c.hp > 0)
      .map((c) => `<button data-switch="${c.uid}" ${busy ? "disabled" : ""}>${c.emoji} ${esc(c.name)} Lv ${c.level} (${c.hp}/${c.maxHp})</button>`)
      .join("");
    const wild = battle.kind === "wild";
    return `
      <div class="tk-moves">${moves}</div>
      <div class="tk-actrow">
        ${wild ? `<div class="tk-sub"><span>Catch:</span>${balls || "<i>no balls</i>"}</div>` : ""}
        <div class="tk-sub"><span>Items:</span>${heals || "<i>none</i>"}</div>
        ${switches ? `<div class="tk-sub"><span>Switch:</span>${switches}</div>` : ""}
        ${wild ? `<button class="tk-run" data-run ${busy ? "disabled" : ""}>Run</button>` : ""}
      </div>`;
  }

  function render() {
    if (!battle) {
      el.hidden = true;
      return;
    }
    el.hidden = false;
    const header = battle.kind === "villain" ? `<div class="tk-villain">🦹 Villain <b>${esc(battle.villain)}</b> challenges you!</div>` : "";
    el.innerHTML = `
      <div class="tk-battle-box">
        ${header}
        ${creatureCard(battle.foe, "foe")}
        ${creatureCard(activeAsCard(), "self")}
        <div class="tk-log" id="tk-log"></div>
        <div class="tk-actions">${actionsHtml()}</div>
      </div>`;
    el.querySelectorAll("[data-move]").forEach((b) => b.addEventListener("click", () => act({ type: "move", move: b.dataset.move })));
    el.querySelectorAll("[data-ball]").forEach((b) => b.addEventListener("click", () => act({ type: "catch", ball: b.dataset.ball })));
    el.querySelectorAll("[data-item]").forEach((b) => b.addEventListener("click", () => act({ type: "item", item: b.dataset.item, uid: active()?.uid })));
    el.querySelectorAll("[data-switch]").forEach((b) => b.addEventListener("click", () => act({ type: "switch", uid: b.dataset.switch })));
    el.querySelector("[data-run]")?.addEventListener("click", () => act({ type: "run" }));
  }

  function activeAsCard() {
    const me = active();
    if (!me) return null;
    return { ...me, types: me.types };
  }

  function logLine(text, cls = "") {
    const log = el.querySelector("#tk-log");
    if (!log) return;
    const div = document.createElement("div");
    div.className = cls;
    div.textContent = text;
    log.appendChild(div);
    log.scrollTop = log.scrollHeight;
  }

  function nameOfMove(id) {
    return moveNames[id] || id.replace(/_/g, " ");
  }

  function learnMoveNames(s) {
    for (const c of [...(s?.party || []), ...(s?.box || [])]) {
      for (const m of c.moves || []) moveNames[m.id] = m.name;
    }
  }

  // Present one server event as a log line (and update cards where cheap).
  function describe(e) {
    const meName = active()?.name || "Your Tokemon";
    const foeName = battle?.foe?.name ? `Wild ${battle.foe.name}` : "The foe";
    const attacker = e.who === "player" ? meName : foeName;
    switch (e.t) {
      case "hit": {
        let extra = "";
        if (e.mult > 1) extra = " It's super effective!";
        else if (e.mult < 1) extra = " Not very effective…";
        if (e.crit) extra += " Critical hit!";
        return `${attacker} used ${nameOfMove(e.move)} — ${e.dmg} damage.${extra}`;
      }
      case "miss":
        return `${attacker} used ${nameOfMove(e.move)}… it missed!`;
      case "immune":
        return `${attacker}'s ${nameOfMove(e.move)} doesn't affect the target.`;
      case "faint":
        return e.who === "foe" ? `${foeName} fainted!` : `${meName} fainted!`;
      case "xp":
        return `${meName} gained ${e.gained} XP.`;
      case "levelup":
        return `${meName} grew to level ${e.level}!`;
      case "learned":
        return `${meName} learned ${nameOfMove(e.move)}!`;
      case "forgot":
        return `${meName} forgot ${nameOfMove(e.move)}.`;
      case "evolved":
        return `What?! ${meName} is evolving… it became ${e.to.charAt(0).toUpperCase() + e.to.slice(1)}!`;
      case "caught":
        return `Gotcha! It was caught and sent to your ${e.where}!`;
      case "broke_free":
        return "Oh no — it broke free!";
      case "escaped":
        return "Got away safely.";
      case "escape_failed":
        return "Couldn't escape!";
      case "switched":
        return e.forced ? "Go — next Tokemon!" : "Come back! Go!";
      case "foe_next":
        return `The villain sends out ${e.foe?.name} (Lv ${e.foe?.level})!`;
      case "item_used":
        return "Item used.";
      case "reward":
        return `Victory spoils: ${Object.entries(e.reward).map(([k, v]) => `${v}× ${BALL_LABEL[k] || HEAL_LABEL[k] || k}`).join(", ")}.`;
      case "end":
        return e.result === "won" ? "You won the battle!" : e.result === "lost" ? "You're out of able Tokemon… you black out." : null;
      default:
        return null;
    }
  }

  // Send one intent, then play the returned events back sequentially (paced
  // sleeps, live HP updates on hits) before adopting the new server state.
  async function act(action) {
    if (busy || !battle) return;
    busy = true;
    render(); // disable buttons
    let result;
    try {
      result = await onAction(action);
    } catch (err) {
      busy = false;
      logLine(err.message || "That didn't work.", "tk-err");
      render();
      return;
    }
    // Play events over the CURRENT card state, then adopt the new state.
    for (const e of result.events || []) {
      const text = describe(e);
      if (text) logLine(text, e.t === "hit" && e.who === "foe" ? "tk-foe-line" : "");
      // Live HP updates mid-playback for hits.
      if (e.t === "hit") {
        const card = e.who === "player" ? el.querySelector(".tk-foe") : el.querySelector(".tk-self");
        const target = e.who === "player" ? result.battle?.foe : null;
        if (card && e.defenderHp !== undefined) {
          const num = card.querySelector(".tk-hpnum");
          const max = target?.maxHp || Number(num?.textContent.split("/")[1] || 1);
          const fill = card.querySelector(".tk-hpfill");
          const pct = Math.max(0, Math.min(100, (e.defenderHp / max) * 100));
          if (fill) fill.style.width = `${pct}%`;
          if (num) num.textContent = `${e.defenderHp}/${max}`;
        }
      }
      await sleep(e.t === "hit" || e.t === "faint" ? 550 : 350);
    }
    save = result.save || save;
    learnMoveNames(save);
    battle = result.battle || null;
    busy = false;
    if (!battle) {
      const end = (result.events || []).find((x) => x.t === "end");
      await sleep(900);
      el.hidden = true;
      onEnd?.(end?.result || "done", save);
    } else {
      render();
    }
  }

  return {
    open(b, s) {
      battle = b;
      save = s;
      learnMoveNames(s);
      busy = false;
      render();
      if (battle.kind === "wild" && battle.foe) logLine(`A wild ${battle.foe.name} (Lv ${battle.foe.level}) appeared!`);
      if (battle.kind === "villain") logLine(`Villain ${battle.villain} wants to fight! (${battle.foe.count} Tokemon)`);
    },
    isOpen: () => !el.hidden,
  };
}

// Tokemon bootstrap: player state, movement (GPS follow, tap-to-walk, or
// TEXT COMMANDS — "go north 200 m", "gå till Kungsgatan 1"), spawn polling +
// markers, the street-view AR mode (creatures overlaid on real imagery),
// encounters, and the party/bag/dex panels. Game rules all live server-side
// (src/tokemon.js, src/tokemon-nav.js) — this is presentation and movement.

import * as api from "./api.js";
import { createBattleUI } from "./battle.js";
import { createMap } from "./map.js";
import { createStreetView } from "./street.js";

const WALK_SPEED = 4; // m/s — brisk tap-to-walk so desktop play isn't a slog
const SPAWN_POLL_MS = 30_000;
const DEFAULT_POS = { lat: 59.3326, lng: 18.0649 }; // Sergels torg, Stockholm

/** Escape text for interpolation into innerHTML. @type {(s: unknown) => string} */
const esc = (s) => String(s).replace(/[&<>"]/g, (c) => ({ "&": "&amp;", "<": "&lt;", ">": "&gt;", '"': "&quot;" })[c]);

// ---- Game state (server-owned save + local presentation state) ----
let save = null; // the server's publicSave payload — refreshed by every mutating call
let pos = { ...DEFAULT_POS }; // the player's position (GPS, tap-walk, or text command)
let walkTarget = null; // {lat, lng} the tap-to-walk animation is heading for
let gpsWatch = null; // geolocation watch id while GPS follow is on
let spawns = []; // last /spawns payload, minus locally consumed ones
let encounterRadius = 80; // server-confirmed tappable radius (m)
let lastSpawnFetch = { t: 0, lat: 0, lng: 0 };
let map = null;
let battleUI = null;
let follow = true; // keep the camera on the player

// Street mode: current camera heading, the pane module, and where/which-way
// the last frame was captured. Frames are billed server-side (edge-cached
// per pano+heading), so a new one is fetched only on deliberate changes —
// mode open, turns, commands, walk arrival — never on GPS jitter.
let mode = "map"; // "map" | "street"
let heading = 0;
let street = null;
let lastScene = null; // {lat, lng, heading}

const $ = (id) => document.getElementById(id);

/**
 * Transient status line at the bottom of the screen.
 * @param {string} msg
 * @param {number} [ms]
 */
function toast(msg, ms = 2600) {
  const t = $("tk-toast");
  t.textContent = msg;
  t.hidden = false;
  clearTimeout(toast._h);
  toast._h = setTimeout(() => (t.hidden = true), ms);
}

/** Great-circle distance in meters (mirrors src/tokemon.js haversineM). */
function haversineM(lat1, lng1, lat2, lng2) {
  const R = 6371000;
  const toRad = (d) => (d * Math.PI) / 180;
  const a =
    Math.sin(toRad(lat2 - lat1) / 2) ** 2 +
    Math.cos(toRad(lat1)) * Math.cos(toRad(lat2)) * Math.sin(toRad(lng2 - lng1) / 2) ** 2;
  return 2 * R * Math.asin(Math.sqrt(a));
}

// ---------------------------------------------------------------------------
// Movement

/** Move the player: recenter (when following), redraw, maybe re-poll spawns. */
function setPos(lat, lng) {
  pos = { lat, lng };
  if (follow) map.setCenter(lat, lng);
  renderMarkers();
  maybeFetchSpawns();
}

/** rAF loop: advance the tap-to-walk animation at WALK_SPEED. */
function tick(last) {
  const now = performance.now();
  const dt = Math.min(1, (now - (last || now)) / 1000);
  if (walkTarget) {
    const d = haversineM(pos.lat, pos.lng, walkTarget.lat, walkTarget.lng);
    if (d < 1.5) {
      walkTarget = null;
      refreshScene(); // arrived — show the street from here
    } else {
      const step = Math.min(1, (WALK_SPEED * dt) / d);
      setPos(pos.lat + (walkTarget.lat - pos.lat) * step, pos.lng + (walkTarget.lng - pos.lng) * step);
    }
  }
  requestAnimationFrame(() => tick(now));
}

/** Toggle GPS follow; every failure degrades to tap-to-walk with a toast. */
function toggleGps() {
  if (gpsWatch != null) {
    navigator.geolocation.clearWatch(gpsWatch);
    gpsWatch = null;
    $("tk-gps").classList.remove("on");
    toast("GPS off — tap the map to walk.");
    return;
  }
  if (!navigator.geolocation) {
    toast("This browser has no geolocation — tap the map to walk.");
    return;
  }
  gpsWatch = navigator.geolocation.watchPosition(
    (p) => {
      walkTarget = null;
      $("tk-gps").classList.add("on");
      setPos(p.coords.latitude, p.coords.longitude);
    },
    () => {
      toast("Couldn't read your location — tap the map to walk instead.");
      navigator.geolocation.clearWatch(gpsWatch);
      gpsWatch = null;
      $("tk-gps").classList.remove("on");
    },
    { enableHighAccuracy: true, maximumAge: 3000, timeout: 15000 },
  );
}

// ---------------------------------------------------------------------------
// Spawns & markers

/**
 * Re-poll /spawns when stale (SPAWN_POLL_MS) or the player moved 90 m+;
 * `force` skips both checks (after battles, collects, and commands).
 */
async function maybeFetchSpawns(force = false) {
  const now = Date.now();
  const moved = haversineM(pos.lat, pos.lng, lastSpawnFetch.lat, lastSpawnFetch.lng);
  if (!force && now - lastSpawnFetch.t < SPAWN_POLL_MS && moved < 90) return;
  lastSpawnFetch = { t: now, lat: pos.lat, lng: pos.lng };
  try {
    const r = await api.getSpawns(pos.lat, pos.lng);
    spawns = r.spawns || [];
    encounterRadius = r.encounterRadiusM || 80;
    renderMarkers();
  } catch (err) {
    if (err.status === 503) showFatal(err.message);
  }
}

/** Redraw all spawn markers + the player marker (diffed by id in map.js). */
function renderMarkers() {
  if (!map) return;
  const markers = spawns.map((s) => ({
    id: s.id,
    lat: s.lat,
    lng: s.lng,
    cls: `tk-spawn tk-${s.kind}` + (haversineM(pos.lat, pos.lng, s.lat, s.lng) <= encounterRadius ? " near" : ""),
    html: `<span>${s.emoji}</span>${s.kind === "creature" ? `<i>Lv ${s.level}</i>` : s.kind === "villain" ? `<i>${esc(s.villain)}</i>` : ""}`,
    onClick: () => tapSpawn(s),
  }));
  markers.push({ id: "__player", lat: pos.lat, lng: pos.lng, cls: "tk-player", html: "🧭" });
  map.setMarkers(markers);
}

/**
 * Tap on a spawn (map marker or street overlay): within reach → collect the
 * item or start the battle; out of reach → walk toward it.
 * @param {{id: string, kind: string, lat: number, lng: number}} s
 */
async function tapSpawn(s) {
  const d = haversineM(pos.lat, pos.lng, s.lat, s.lng);
  if (d > encounterRadius) {
    walkTarget = { lat: s.lat, lng: s.lng };
    toast(`${Math.round(d)} m away — walking there…`);
    return;
  }
  try {
    if (s.kind === "item") {
      const r = await api.collect(s.id, pos.lat, pos.lng);
      save = r.save;
      toast(`Picked up ${r.collected.count}× ${r.collected.item}!`);
      spawns = spawns.filter((x) => x.id !== s.id);
      renderMarkers();
      renderHud();
      refreshScene(true);
    } else {
      const r = await api.encounter(s.id, pos.lat, pos.lng);
      save = r.save;
      battleUI.open(r.battle, save);
    }
  } catch (err) {
    toast(err.message);
    if (err.status === 400 && /any more/i.test(err.message || "")) {
      spawns = spawns.filter((x) => x.id !== s.id);
      renderMarkers();
    }
  }
}

// ---------------------------------------------------------------------------
// Street mode & text commands

/** Switch between the map and the street-view AR pane. @param {"map"|"street"} next */
function setMode(next) {
  mode = next;
  $("tk-street").hidden = mode !== "street";
  $("tk-mode").textContent = mode === "street" ? "🗺 Map" : "🛰 Street";
  if (mode === "street") refreshScene(true);
}

// Fetch a new frame when in street mode and the view meaningfully changed
// (>15 m moved or any heading change); `force` skips the movement check.
async function refreshScene(force = false) {
  if (mode !== "street" || !street) return;
  const changed =
    !lastScene ||
    lastScene.heading !== Math.round(heading) ||
    haversineM(pos.lat, pos.lng, lastScene.lat, lastScene.lng) > 15;
  if (!force && !changed) return;
  lastScene = { lat: pos.lat, lng: pos.lng, heading: Math.round(heading) };
  street.showLoading();
  try {
    const s = await api.scene(pos.lat, pos.lng, heading);
    street.render(s);
  } catch (err) {
    street.showMessage(err.message || "Couldn't fetch the street view.");
  }
}

// A tap on an overlaid spawn: near → interact (same endpoints as the map
// markers); far → walk toward it, the scene refreshes on arrival. The
// overlay carries lat/lng so this works even when the spawn has dropped
// out of the local `spawns` list.
function tapStreetSpawn(o) {
  const s = spawns.find((x) => x.id === o.id) || { id: o.id, kind: o.kind, lat: o.lat, lng: o.lng };
  tapSpawn(s);
}

/** Send the command bar's text to POST …/go and apply the returned move/turn. */
async function submitCommand() {
  const input = $("tk-cmd");
  const command = input.value.trim();
  if (!command) return;
  input.value = "";
  try {
    const r = await api.go(command, pos.lat, pos.lng, heading);
    heading = r.heading ?? heading;
    if (r.pos) {
      walkTarget = null;
      follow = true;
      setPos(r.pos.lat, r.pos.lng);
    }
    toast(r.say || "Done.");
    maybeFetchSpawns(true);
    refreshScene(true);
  } catch (err) {
    toast(err.message);
  }
}

// ---------------------------------------------------------------------------
// HUD & panels

function renderHud() {
  const lead = save?.party?.[0];
  $("tk-lead").innerHTML = lead
    ? `${lead.emoji} <b>${esc(lead.name)}</b> Lv ${lead.level} · ${lead.hp}/${lead.maxHp} HP`
    : "No Tokemon yet";
  $("tk-balls").textContent = `⭕ ${save?.items?.tokeball ?? 0}`;
}

function closePanels() {
  $("tk-panel").hidden = true;
}

function openPanel(html) {
  const p = $("tk-panel");
  p.innerHTML = `<button class="tk-close" id="tk-panel-close">✕</button>${html}`;
  p.hidden = false;
  $("tk-panel-close").addEventListener("click", closePanels);
}

/**
 * One party/box row with its actions (lead/box/to-party + usable heals).
 * @param {any} c  A publicSave creature.
 * @param {"party"|"box"} where
 */
function creatureRow(c, where) {
  const pct = Math.max(0, Math.min(100, (c.hp / c.maxHp) * 100));
  const actions =
    where === "party"
      ? `<button data-op="lead" data-uid="${c.uid}">Lead</button>
         <button data-op="box" data-uid="${c.uid}">Box</button>`
      : `<button data-op="party" data-uid="${c.uid}">To party</button>`;
  const heals = ["potion", "superpotion", "revive"]
    .filter((i) => (save.items[i] || 0) > 0)
    .map((i) => `<button data-op="item" data-item="${i}" data-uid="${c.uid}">${i === "potion" ? "Patch" : i === "superpotion" ? "Hotfix" : "Reboot"}</button>`)
    .join("");
  return `<div class="tk-row">
    <div class="tk-row-main"><span class="tk-emoji">${c.emoji}</span>
      <b>${esc(c.name)}</b> Lv ${c.level} <small>${c.hp}/${c.maxHp} HP · ${c.moves.map((m) => esc(m.name)).join(", ")}</small>
      <div class="tk-hpbar"><div class="tk-hpfill${pct < 20 ? " crit" : pct < 50 ? " low" : ""}" style="width:${pct}%"></div></div>
    </div>
    <div class="tk-row-actions">${actions}${heals}</div>
  </div>`;
}

function openParty() {
  const party = (save.party || []).map((c) => creatureRow(c, "party")).join("") || "<p>No Tokemon in the party.</p>";
  const box = (save.box || []).map((c) => creatureRow(c, "box")).join("");
  openPanel(`<h2>Party</h2>${party}${box ? `<h2>Box</h2>${box}` : ""}`);
  $("tk-panel").querySelectorAll("[data-op]").forEach((b) =>
    b.addEventListener("click", async () => {
      try {
        const payload = { op: b.dataset.op, uid: b.dataset.uid };
        if (b.dataset.item) payload.item = b.dataset.item;
        const r = await api.party(payload);
        save = r.save;
        renderHud();
        openParty();
      } catch (err) {
        toast(err.message);
      }
    }),
  );
}

const ITEM_LABEL = {
  tokeball: ["⭕ Tokeball", "catches wild Tokemon"],
  megaball: ["🔵 Megaball", "a better catch rate"],
  hyperball: ["🟡 Hyperball", "the best catch rate"],
  potion: ["🩹 Patch", "restores 20 HP"],
  superpotion: ["💊 Hotfix", "restores 50 HP"],
  revive: ["♻️ Reboot", "revives a fainted Tokemon"],
};

function openBag() {
  const rows = Object.entries(ITEM_LABEL)
    .map(([id, [label, desc]]) => `<div class="tk-row"><div class="tk-row-main"><b>${label}</b> ×${save.items[id] || 0} <small>${desc}</small></div></div>`)
    .join("");
  openPanel(`<h2>Bag</h2>${rows}
    <h2>Progress</h2>
    <div class="tk-row"><div class="tk-row-main">Caught ${save.stats.caught} · Battles won ${save.stats.battlesWon} · Villains beaten ${save.stats.villainsBeaten} · Items collected ${save.stats.itemsCollected}</div></div>`);
}

function openDex() {
  const entries = Object.entries(save.dex || {});
  const rows = entries.length
    ? entries
        .map(
          ([id, d]) =>
            `<div class="tk-row"><div class="tk-row-main"><b>${esc(id)}</b> <small>seen ${d.seen} · caught ${d.caught}</small></div></div>`,
        )
        .join("")
    : "<p>Nothing recorded yet — go find some Tokemon!</p>";
  openPanel(`<h2>Tokedex (${entries.filter(([, d]) => d.caught > 0).length} caught)</h2>${rows}`);
}

async function doHeal() {
  try {
    const r = await api.heal();
    save = r.save;
    renderHud();
    toast("Recharged — the whole team is at full power!");
  } catch (err) {
    if (err.status === 429 && err.body?.readyAt) {
      toast(`Recharge ready ${new Date(err.body.readyAt).toLocaleTimeString()}.`);
    } else {
      toast(err.message);
    }
  }
}

// ---------------------------------------------------------------------------
// Starter flow & fatal states

function showStarterPick() {
  const choices = (save.starters || [])
    .map(
      (s) => `<button class="tk-starter" data-id="${s.id}">
        <span class="tk-emoji">${s.emoji}</span><b>${esc(s.name)}</b><small>${s.types.join(", ")}</small></button>`,
    )
    .join("");
  openPanel(`<h2>Welcome to Tokemon!</h2>
    <p>Wild Tokemon roam the real streets around you. Walk up to them (GPS, or tap the
    map to stroll), catch them with Tokeballs, and take on the villains of Team Glitch.</p>
    <p><b>Choose your first Tokemon:</b></p>
    <div class="tk-starters">${choices}</div>`);
  $("tk-panel").querySelectorAll(".tk-starter").forEach((b) =>
    b.addEventListener("click", async () => {
      try {
        const r = await api.chooseStarter(b.dataset.id);
        save = r.save;
        closePanels();
        renderHud();
        toast(`${save.party[0].name} joined you — go explore!`);
      } catch (err) {
        toast(err.message);
      }
    }),
  );
}

function showFatal(msg) {
  openPanel(`<h2>Tokemon</h2><p>${esc(msg || "The game is unavailable right now.")}</p>`);
}

// ---------------------------------------------------------------------------
// Boot

/** Wire the static chrome (HUD buttons, mode toggle, command bar) — once. */
function wireControls() {
  $("tk-mode").addEventListener("click", () => setMode(mode === "street" ? "map" : "street"));
  $("tk-cmdbar").addEventListener("submit", (e) => {
    e.preventDefault();
    submitCommand();
  });

  $("tk-gps").addEventListener("click", toggleGps);
  $("tk-center").addEventListener("click", () => {
    follow = true;
    map.setCenter(pos.lat, pos.lng);
  });
  $("tk-party").addEventListener("click", openParty);
  $("tk-bag").addEventListener("click", openBag);
  $("tk-dex").addEventListener("click", openDex);
  $("tk-heal").addEventListener("click", doHeal);
  // Panning the map manually stops the camera-follow until recentered.
  $("tk-map").addEventListener("pointermove", (e) => {
    if (e.buttons) follow = false;
  });
}

async function boot() {
  map = createMap($("tk-map"), {
    zoom: 17,
    onTap: (ll) => {
      walkTarget = ll;
      follow = true;
    },
  });
  battleUI = createBattleUI(document.body, {
    onAction: (action) => api.battleAction(action),
    onEnd: (result, s) => {
      save = s || save;
      renderHud();
      maybeFetchSpawns(true);
      refreshScene(true); // a consumed spawn must leave the imagery too
      if (result === "caught") toast("Registered to the Tokedex!");
      if (result === "lost") toast("Your team fainted — Recharge or use Reboots.");
    },
  });

  street = createStreetView($("tk-street"), {
    onTapSpawn: tapStreetSpawn,
    onTurn: (delta) => {
      heading = (((heading + delta) % 360) + 360) % 360;
      refreshScene(true);
    },
  });
  wireControls();

  try {
    const r = await api.getState();
    save = r.save;
  } catch (err) {
    showFatal(err.status === 401 ? "Sign in first, then reload this page." : err.message);
    return;
  }
  renderHud();

  // Resume a battle that survived a reload.
  if (save.battle) battleUI.open(save.battle, save);
  else if (!save.starter) showStarterPick();

  // One best-effort location fix to start somewhere real; the map stays
  // usable without it (tap-to-walk from the default location).
  if (navigator.geolocation) {
    navigator.geolocation.getCurrentPosition(
      (p) => setPos(p.coords.latitude, p.coords.longitude),
      () => setPos(pos.lat, pos.lng),
      { maximumAge: 60_000, timeout: 8000 },
    );
  }
  setPos(pos.lat, pos.lng);
  maybeFetchSpawns(true);
  setInterval(() => maybeFetchSpawns(), SPAWN_POLL_MS);
  requestAnimationFrame(() => tick());
}

boot();

// A minimal slippy map over OpenStreetMap raster tiles — no library, in
// keeping with the project's no-dependency stance (the whole thing is Web
// Mercator math plus absolutely-positioned <img> tiles under one CSS
// transform). OSM's tile usage policy is honored: light, user-driven load
// and the attribution line index.html renders.

const TILE = 256;

// Web Mercator world-pixel projections at zoom z (and their inverses).
export const lngToX = (lng, z) => ((lng + 180) / 360) * TILE * 2 ** z;
export const latToY = (lat, z) => {
  const r = (lat * Math.PI) / 180;
  return ((1 - Math.log(Math.tan(r) + 1 / Math.cos(r)) / Math.PI) / 2) * TILE * 2 ** z;
};
export const xToLng = (x, z) => (x / (TILE * 2 ** z)) * 360 - 180;
export const yToLat = (y, z) => {
  const n = Math.PI - (2 * Math.PI * y) / (TILE * 2 ** z);
  return (180 / Math.PI) * Math.atan(0.5 * (Math.exp(n) - Math.exp(-n)));
};

/**
 * @param {HTMLElement} container  Fills this element; pointer events are
 *   claimed for drag-to-pan and tap-to-walk.
 * @param {{zoom?: number, onTap?: (ll: {lat: number, lng: number}) => void}} [opts]
 * @returns {{
 *   setCenter: (lat: number, lng: number) => void,
 *   getCenter: () => {lat: number, lng: number},
 *   setMarkers: (list: Array<{id: string, lat: number, lng: number, html: string, cls?: string, onClick?: (m: object) => void}>) => void,
 *   destroy: () => void,
 * }} Markers are diffed by id, so callers re-send the full list each render.
 */
export function createMap(container, { zoom = 17, onTap } = {}) {
  const world = document.createElement("div"); // shared coordinate space
  world.className = "tk-world";
  const tileLayer = document.createElement("div");
  const markerLayer = document.createElement("div");
  world.appendChild(tileLayer);
  world.appendChild(markerLayer);
  container.appendChild(world);

  let center = { lat: 59.3326, lng: 18.0649 };
  const tiles = new Map(); // "x:y" (world tile indices) → img
  const markers = new Map(); // id → {el, lat, lng}

  // FLOATING ORIGIN — the load-bearing detail of this map. World-pixel
  // coordinates at zoom 17 reach ~18 million px (x = 18.4M at Stockholm's
  // longitude), which is past WebKit's ~2^24 (16.7M) rasterization limit:
  // iOS Safari silently dropped every tile <img> positioned there while the
  // emoji markers survived on their own composited layers ("map is blank,
  // markers float in the void", reported 2026-07-09). So nothing is ever
  // positioned at world coordinates: everything is placed RELATIVE to an
  // integer tile origin near the viewport, and the origin re-anchors when
  // the center drifts, keeping every offset within a few thousand px.
  let origin = null; // {tx, ty}

  const originPx = () => ({ x: origin.tx * TILE, y: origin.ty * TILE });

  function ensureOrigin() {
    const tx = Math.floor(lngToX(center.lng, zoom) / TILE);
    const ty = Math.floor(latToY(center.lat, zoom) / TILE);
    if (origin && Math.abs(tx - origin.tx) < 30 && Math.abs(ty - origin.ty) < 30) return;
    origin = { tx, ty };
    // Re-anchor everything already in the DOM to the new origin.
    for (const [key, img] of tiles) {
      const [wtx, wty] = key.split(":").map(Number);
      img.style.left = `${(wtx - origin.tx) * TILE}px`;
      img.style.top = `${(wty - origin.ty) * TILE}px`;
    }
    for (const m of markers.values()) place(m.el, m.lat, m.lng);
  }

  function render() {
    const w = container.clientWidth;
    const h = container.clientHeight;
    ensureOrigin();
    const o = originPx();
    const cx = lngToX(center.lng, zoom) - o.x; // origin-relative center
    const cy = latToY(center.lat, zoom) - o.y;
    world.style.transform = `translate(${Math.round(w / 2 - cx)}px, ${Math.round(h / 2 - cy)}px)`;
    // Tiles covering the viewport plus a one-tile skirt (world indices).
    const x0 = origin.tx + Math.floor((cx - w / 2) / TILE) - 1;
    const x1 = origin.tx + Math.floor((cx + w / 2) / TILE) + 1;
    const y0 = origin.ty + Math.floor((cy - h / 2) / TILE) - 1;
    const y1 = origin.ty + Math.floor((cy + h / 2) / TILE) + 1;
    const max = 2 ** zoom;
    const wanted = new Set();
    for (let tx = x0; tx <= x1; tx++) {
      for (let ty = y0; ty <= y1; ty++) {
        if (ty < 0 || ty >= max) continue;
        const wx = ((tx % max) + max) % max; // wrap longitude
        const key = `${tx}:${ty}`;
        wanted.add(key);
        if (!tiles.has(key)) {
          const img = document.createElement("img");
          img.className = "tk-tile";
          img.src = `https://tile.openstreetmap.org/${zoom}/${wx}/${ty}.png`;
          img.style.left = `${(tx - origin.tx) * TILE}px`;
          img.style.top = `${(ty - origin.ty) * TILE}px`;
          img.draggable = false;
          img.alt = "";
          // A failed tile is forgotten so the next render retries it.
          img.addEventListener("error", () => {
            tiles.delete(key);
            img.remove();
          });
          tileLayer.appendChild(img);
          tiles.set(key, img);
        }
      }
    }
    for (const [key, img] of tiles) {
      if (!wanted.has(key)) {
        img.remove();
        tiles.delete(key);
      }
    }
  }

  function place(el, lat, lng) {
    const o = originPx();
    el.style.left = `${Math.round(lngToX(lng, zoom) - o.x)}px`;
    el.style.top = `${Math.round(latToY(lat, zoom) - o.y)}px`;
  }

  function setMarkers(list) {
    const wanted = new Set(list.map((m) => m.id));
    for (const [id, m] of markers) {
      if (!wanted.has(id)) {
        m.el.remove();
        markers.delete(id);
      }
    }
    for (const m of list) {
      let cur = markers.get(m.id);
      if (!cur) {
        const el = document.createElement("div");
        el.className = `tk-marker ${m.cls || ""}`;
        el.addEventListener("click", (e) => {
          e.stopPropagation();
          m.onClick?.(m);
        });
        markerLayer.appendChild(el);
        cur = { el };
        markers.set(m.id, cur);
      }
      cur.lat = m.lat; // kept so a re-anchor can re-place every marker
      cur.lng = m.lng;
      cur.el.className = `tk-marker ${m.cls || ""}`;
      if (cur.el.innerHTML !== m.html) cur.el.innerHTML = m.html;
      place(cur.el, m.lat, m.lng);
    }
  }

  // Drag to pan; a sub-6px pointerup is a tap (walk target).
  let drag = null;
  container.addEventListener("pointerdown", (e) => {
    drag = { x: e.clientX, y: e.clientY, lat: center.lat, lng: center.lng, moved: false };
    container.setPointerCapture(e.pointerId);
  });
  container.addEventListener("pointermove", (e) => {
    if (!drag) return;
    const dx = e.clientX - drag.x;
    const dy = e.clientY - drag.y;
    if (Math.abs(dx) + Math.abs(dy) > 6) drag.moved = true;
    if (drag.moved) {
      center = {
        lat: yToLat(latToY(drag.lat, zoom) - dy, zoom),
        lng: xToLng(lngToX(drag.lng, zoom) - dx, zoom),
      };
      render();
    }
  });
  container.addEventListener("pointerup", (e) => {
    if (drag && !drag.moved && onTap) {
      const rect = container.getBoundingClientRect();
      const cx = lngToX(center.lng, zoom) + (e.clientX - rect.left - rect.width / 2);
      const cy = latToY(center.lat, zoom) + (e.clientY - rect.top - rect.height / 2);
      onTap({ lat: yToLat(cy, zoom), lng: xToLng(cx, zoom) });
    }
    drag = null;
  });
  container.addEventListener("pointercancel", () => (drag = null));

  const onResize = () => render();
  window.addEventListener("resize", onResize);
  render();

  return {
    setCenter(lat, lng) {
      center = { lat, lng };
      render();
    },
    getCenter: () => ({ ...center }),
    setMarkers,
    destroy() {
      window.removeEventListener("resize", onResize);
      world.remove();
    },
  };
}

// Street mode: the real-world AR pane. Renders the server's scene — a
// Street View frame captured at the player's position and heading — and
// overlays the projected spawns (creatures/items/villains) INSIDE the
// imagery at the x/y/scale the server computed (src/tokemon-nav.js).
// Navigation happens outside this module (text commands, look buttons,
// walking); this pane only presents and reports taps.

const esc = (s) => String(s).replace(/[&<>"]/g, (c) => ({ "&": "&amp;", "<": "&lt;", ">": "&gt;", '"': "&quot;" })[c]);

/**
 * @param {HTMLElement} container  The #tk-street pane.
 * @param {{
 *   onTapSpawn?: (overlay: object) => void,
 *   onTurn?: (deltaDeg: number) => void,
 * }} hooks  onTapSpawn gets the tapped server overlay ({id, kind, lat, lng,
 *   near, …}); onTurn gets ±45° from the turn buttons.
 * @returns {{render: (scene: object) => void, showLoading: () => void, showMessage: (msg: string) => void}}
 */
export function createStreetView(container, { onTapSpawn, onTurn }) {
  container.innerHTML = `
    <div class="tk-sv-stage">
      <img class="tk-sv-img" alt="Street view" draggable="false">
      <div class="tk-sv-overlays"></div>
      <div class="tk-sv-note" hidden></div>
      <div class="tk-sv-compass"></div>
      <button class="tk-sv-turn tk-sv-left" type="button" aria-label="Turn left">⟲</button>
      <button class="tk-sv-turn tk-sv-right" type="button" aria-label="Turn right">⟳</button>
    </div>`;
  const img = container.querySelector(".tk-sv-img");
  const overlaysEl = container.querySelector(".tk-sv-overlays");
  const note = container.querySelector(".tk-sv-note");
  const compass = container.querySelector(".tk-sv-compass");
  container.querySelector(".tk-sv-left").addEventListener("click", () => onTurn?.(-45));
  container.querySelector(".tk-sv-right").addEventListener("click", () => onTurn?.(45));

  const COMPASS = ["N", "NE", "E", "SE", "S", "SW", "W", "NW"];

  // The pane's self-explaining empty state (loading, no coverage, knob off).
  function showMessage(msg) {
    img.removeAttribute("src");
    img.classList.add("empty");
    overlaysEl.innerHTML = "";
    compass.textContent = "";
    note.textContent = msg;
    note.hidden = false;
  }

  // Draw one …/scene payload: the frame, the compass line, and the spawn
  // overlays at the server-projected xPct/yPct/scale.
  function render(scene) {
    if (!scene?.available) {
      showMessage(scene?.message || "Street view is unavailable here.");
      return;
    }
    note.hidden = true;
    img.classList.remove("empty");
    img.src = scene.image;
    compass.textContent =
      COMPASS[Math.round(scene.heading / 45) % 8] + ` ${scene.heading}°` + (scene.date ? ` · imagery ${scene.date}` : "");
    overlaysEl.innerHTML = "";
    for (const o of scene.overlays || []) {
      const b = document.createElement("button");
      b.type = "button";
      b.className = `tk-sv-spawn${o.near ? " near" : ""}`;
      b.style.left = `${o.xPct}%`;
      b.style.top = `${o.yPct}%`;
      b.style.fontSize = `${Math.round(30 * o.scale)}px`;
      b.innerHTML = `<span>${o.emoji}</span><i>${esc(o.name || "")}${o.kind === "creature" ? ` Lv ${o.level}` : ""} · ${o.distM} m</i>`;
      b.addEventListener("click", () => onTapSpawn?.(o));
      overlaysEl.appendChild(b);
    }
  }

  return {
    render,
    showLoading: () => showMessage("Fetching the street…"),
    showMessage,
  };
}

/* Tokemon — standalone game page styling (dark, glassy, matching the app's
   floating-chrome look without importing its CSS). */

* { box-sizing: border-box; }
html, body {
  margin: 0; height: 100%; overflow: hidden;
  font-family: -apple-system, BlinkMacSystemFont, "Segoe UI", Roboto, sans-serif;
  background: #101418; color: #e8ecf1;
}
button { font: inherit; cursor: pointer; }
a { color: #7fb4ff; }

/* ---- Map ---- */
#tk-map {
  position: fixed; inset: 0; overflow: hidden; touch-action: none;
  background: #1b232b; cursor: grab; user-select: none; -webkit-user-select: none;
}
.tk-world { position: absolute; left: 0; top: 0; will-change: transform; }
.tk-tile { position: absolute; width: 256px; height: 256px; filter: saturate(0.85) brightness(0.92); }

.tk-marker {
  position: absolute; transform: translate(-50%, -85%);
  display: flex; flex-direction: column; align-items: center;
  font-size: 26px; line-height: 1; cursor: pointer; z-index: 2;
  text-shadow: 0 2px 6px rgba(0,0,0,.6);
}
.tk-marker i {
  font-style: normal; font-size: 11px; background: rgba(10,14,18,.8);
  border-radius: 8px; padding: 1px 6px; margin-top: 2px; white-space: nowrap;
}
.tk-marker.near { filter: drop-shadow(0 0 6px #7fe08a); }
.tk-marker.tk-villain { font-size: 30px; }
.tk-marker.tk-player {
  font-size: 30px; z-index: 3; transform: translate(-50%, -50%);
  filter: drop-shadow(0 0 8px #66aaff);
}

/* ---- HUD ---- */
#tk-hud {
  position: fixed; top: 10px; left: 10px; right: 10px; z-index: 10;
  display: flex; align-items: center; gap: 12px;
  background: rgba(16,20,24,.85); -webkit-backdrop-filter: blur(8px); backdrop-filter: blur(8px);
  border: 1px solid rgba(255,255,255,.08); border-radius: 14px; padding: 8px 14px;
}
#tk-back { text-decoration: none; font-size: 20px; }
#tk-lead { flex: 1; font-size: 14px; }
#tk-balls { font-size: 14px; }

#tk-bar {
  position: fixed; bottom: 12px; left: 50%; transform: translateX(-50%); z-index: 10;
  display: flex; gap: 6px; flex-wrap: wrap; justify-content: center;
  background: rgba(16,20,24,.85); -webkit-backdrop-filter: blur(8px); backdrop-filter: blur(8px);
  border: 1px solid rgba(255,255,255,.08); border-radius: 16px; padding: 8px;
  max-width: calc(100vw - 16px);
}
#tk-bar button {
  background: #223041; color: #e8ecf1; border: 1px solid rgba(255,255,255,.1);
  border-radius: 10px; padding: 8px 12px; font-size: 13px;
}
#tk-bar button:active { transform: scale(.96); }
#tk-bar #tk-gps.on { background: #2e6b3f; }

#tk-toast {
  position: fixed; bottom: 76px; left: 50%; transform: translateX(-50%); z-index: 30;
  background: rgba(10,14,18,.92); border: 1px solid rgba(255,255,255,.12);
  padding: 8px 16px; border-radius: 12px; font-size: 14px; max-width: 90vw;
}

#tk-attrib {
  position: fixed; right: 6px; top: 64px; z-index: 5;
  font-size: 10px; opacity: .75; background: rgba(10,14,18,.6);
  padding: 2px 6px; border-radius: 6px;
}

/* ---- Panels (party/bag/dex/starter) ---- */
.tk-panel {
  position: fixed; z-index: 40; inset: auto 10px 70px 10px; max-height: 70vh; overflow-y: auto;
  background: rgba(16,20,24,.96); border: 1px solid rgba(255,255,255,.1);
  border-radius: 16px; padding: 16px;
}
@media (min-width: 640px) { .tk-panel { left: 50%; right: auto; transform: translateX(-50%); width: 520px; } }
.tk-panel h2 { margin: 4px 0 10px; font-size: 16px; }
.tk-panel p { font-size: 14px; line-height: 1.45; }
.tk-close { position: absolute; top: 8px; right: 10px; background: none; border: none; color: #e8ecf1; font-size: 16px; }

.tk-row {
  display: flex; align-items: center; justify-content: space-between; gap: 10px;
  border-top: 1px solid rgba(255,255,255,.06); padding: 8px 0; font-size: 14px;
}
.tk-row-main { flex: 1; min-width: 0; }
.tk-row-main small { display: block; opacity: .7; font-size: 12px; margin-top: 2px; }
.tk-row-actions { display: flex; gap: 4px; flex-wrap: wrap; }
.tk-row-actions button {
  background: #223041; color: #e8ecf1; border: 1px solid rgba(255,255,255,.1);
  border-radius: 8px; padding: 4px 8px; font-size: 12px;
}
.tk-emoji { font-size: 22px; margin-right: 4px; }

.tk-starters { display: flex; gap: 8px; }
.tk-starter {
  flex: 1; display: flex; flex-direction: column; align-items: center; gap: 4px;
  background: #223041; color: #e8ecf1; border: 1px solid rgba(255,255,255,.12);
  border-radius: 12px; padding: 14px 6px;
}
.tk-starter .tk-emoji { font-size: 34px; }
.tk-starter small { opacity: .7; }

/* ---- Battle ---- */
#tk-battle {
  position: fixed; inset: 0; z-index: 50; display: flex; align-items: center; justify-content: center;
  background: rgba(6,8,10,.82); -webkit-backdrop-filter: blur(4px); backdrop-filter: blur(4px); padding: 10px;
}
/* The explicit display:flex above beats the `hidden` attribute's UA-level
   display:none — without this override the (empty) overlay permanently
   covers the whole game as a dark glass panel (reported on iPhone,
   2026-07-09). Keep this rule next to any hidden-toggled element that
   also sets its own display. */
#tk-battle[hidden] { display: none; }
.tk-battle-box {
  width: 100%; max-width: 560px; max-height: 96vh; overflow-y: auto;
  background: #131a21; border: 1px solid rgba(255,255,255,.12); border-radius: 18px; padding: 14px;
}
.tk-villain { font-size: 14px; margin-bottom: 8px; }
.tk-card { border: 1px solid rgba(255,255,255,.08); border-radius: 12px; padding: 10px; margin-bottom: 8px; }
.tk-card.tk-foe { background: #1d1622; }
.tk-card.tk-self { background: #14202a; }
.tk-card-head { display: flex; align-items: center; gap: 6px; font-size: 14px; flex-wrap: wrap; }
.tk-lv { opacity: .7; font-size: 12px; }
.tk-type { font-size: 10px; border-radius: 6px; padding: 1px 6px; background: #2a3542; }
.tk-hpbar { height: 8px; border-radius: 4px; background: #0b0f13; margin-top: 8px; overflow: hidden; }
.tk-hpfill { height: 100%; background: #58c07a; transition: width .4s; }
.tk-hpfill.low { background: #d8b13c; }
.tk-hpfill.crit { background: #d85b4b; }
.tk-hpnum { font-size: 11px; opacity: .75; }

.tk-log {
  min-height: 64px; max-height: 130px; overflow-y: auto; font-size: 13px; line-height: 1.5;
  background: #0d1216; border-radius: 10px; padding: 8px 10px; margin: 8px 0;
}
.tk-log .tk-err { color: #ff9a8a; }
.tk-log .tk-foe-line { color: #f2c2bc; }

.tk-moves { display: grid; grid-template-columns: 1fr 1fr; gap: 6px; }
.tk-move {
  background: #223041; color: #e8ecf1; border: 1px solid rgba(255,255,255,.12);
  border-radius: 10px; padding: 8px; text-align: left; font-size: 13px;
}
.tk-move small { display: block; opacity: .65; font-size: 11px; }
.tk-move:disabled { opacity: .4; }
.tk-actrow { margin-top: 8px; display: flex; flex-direction: column; gap: 6px; font-size: 13px; }
.tk-sub { display: flex; align-items: center; gap: 6px; flex-wrap: wrap; }
.tk-sub span { opacity: .7; font-size: 12px; }
.tk-sub button, .tk-run {
  background: #223041; color: #e8ecf1; border: 1px solid rgba(255,255,255,.12);
  border-radius: 8px; padding: 5px 10px; font-size: 12px;
}
.tk-run { align-self: flex-end; background: #40262a; }

/* Type accents on move buttons — one class per TYPES entry in
   src/tokemon.js (the renamed Gen 1 types); battle.js emits tk-type-<id>. */
.tk-type-compute { border-left: 3px solid #e0653a; }
.tk-type-data { border-left: 3px solid #3a8fe0; }
.tk-type-code { border-left: 3px solid #4fae53; }
.tk-type-spark { border-left: 3px solid #e0c33a; }
.tk-type-logic { border-left: 3px solid #c05bd8; }
.tk-type-adversarial { border-left: 3px solid #b3452f; }
.tk-type-phantom { border-left: 3px solid #6a5bb8; }
.tk-type-neural { border-left: 3px solid #9aa5ad; }

/* ---- Street mode (the real-world AR view) ---- */
#tk-street {
  position: fixed; inset: 0; z-index: 6; /* over the map, under HUD/bar */
  display: flex; align-items: center; justify-content: center;
  background: #0b0f13;
}
#tk-street[hidden] { display: none; } /* display:flex beats the hidden attr — see #tk-battle */
.tk-sv-stage {
  position: relative; width: min(100vw, 78vh); max-width: 640px;
  aspect-ratio: 1 / 1;
}
.tk-sv-img { width: 100%; height: 100%; object-fit: cover; border-radius: 8px; display: block; }
.tk-sv-img.empty { visibility: hidden; }
.tk-sv-overlays { position: absolute; inset: 0; pointer-events: none; }
.tk-sv-spawn {
  position: absolute; transform: translate(-50%, -90%); pointer-events: auto;
  background: none; border: none; line-height: 1; cursor: pointer;
  display: flex; flex-direction: column; align-items: center;
  filter: drop-shadow(0 3px 5px rgba(0,0,0,.7));
}
.tk-sv-spawn i {
  font-style: normal; font-size: 11px; color: #fff;
  background: rgba(10,14,18,.75); border-radius: 8px; padding: 1px 6px; margin-top: 2px;
  white-space: nowrap;
}
.tk-sv-spawn.near { filter: drop-shadow(0 0 8px #7fe08a); }
.tk-sv-note {
  position: absolute; inset: 0; display: flex; align-items: center; justify-content: center;
  text-align: center; padding: 24px; font-size: 14px; color: #c7d0d9;
}
.tk-sv-note[hidden] { display: none; } /* same hidden-vs-display gotcha */
.tk-sv-compass {
  position: absolute; top: 8px; left: 50%; transform: translateX(-50%);
  font-size: 12px; background: rgba(10,14,18,.75); border-radius: 8px; padding: 2px 10px;
}
.tk-sv-turn {
