/**
 * Fetches fresh settings and renders the Settings sub-view: the
 * cloud-storage, Shodan, and Google Maps knobs, each disabled (with a
 * note) when the server can't back it.
 * @param {PanelCtx} ctx
 */
export async function loadSettingsView(ctx) {
  ctx.body.innerHTML = `
    <button id="settingsbackbtn" type="button" class="back-link">← Back</button>
    <p class="section-lbl">Settings</p>
    <p class="muted">Loading…</p>`;
  document.getElementById("settingsbackbtn").addEventListener("click", () => ctx.show("summary"));

  let s = null;
  if (ctx.me?.email) {
    try {
      s = await loadSettings(true); // fresh — another device may have flipped it
    } catch {
      s = null;
    }
  }
  const usable = !!s?.available?.storage;
  const shodanUsable = !!s?.available?.shodan;
  const googleMapsUsable = !!s?.available?.google_maps;
  const note = !ctx.me?.email
    ? "Settings need a signed-in account (break-glass sessions have none)."
    : s === null
      ? "Could not load settings — try again in a moment."
      : "";
  const cloudNote = usable
    ? ""
    : `<p class="muted setting-note">Cloud storage isn't configured on this server, so history stays in this browser only.</p>`;
  const shodanNote = shodanUsable
    ? ""
    : `<p class="muted setting-note">Shodan isn't configured on this server (no API key), so this stays off.</p>`;
  const googleMapsNote = googleMapsUsable
    ? ""
    : `<p class="muted setting-note">Google Maps isn't configured on this server (no Google Maps API key), so this stays off.</p>`;

  ctx.body.innerHTML = `
    <button id="settingsbackbtn" type="button" class="back-link">← Back</button>
    <p class="section-lbl">Settings</p>
    ${settingRow({
      id: "cloudknob",
      label: "Store history in the cloud",
      checked: usable && s?.server_history,
      disabled: !usable,
      popId: "cloudpop",
      info: CLOUD_INFO,
    })}
    ${cloudNote}
    <p id="syncstatus" class="muted setting-note" hidden></p>
    ${settingRow({
      id: "shodanknob",
      label: "Shodan host intelligence",
      checked: shodanUsable && s?.shodan_mcp,
      disabled: !shodanUsable,
      popId: "shodanpop",
      info: SHODAN_INFO,
    })}
    ${shodanNote}
    <p id="shodanstatus" class="muted setting-note" hidden></p>
    ${settingRow({
      id: "gmapsknob",
      label: "Google Maps & Street View",
      checked: googleMapsUsable && s?.google_maps,
      disabled: !googleMapsUsable,
      popId: "gmapspop",
      info: GOOGLEMAPS_INFO,
    })}
    ${googleMapsNote}
    <p id="gmapsstatus" class="muted setting-note" hidden></p>
    ${renderConfigKnobs(ctx.me)}
    ${note ? `<p class="muted setting-note">${note}</p>` : ""}`;
  document.getElementById("settingsbackbtn").addEventListener("click", () => ctx.show("summary"));
  wireSettingPopovers(ctx.body);
  wireFeedbackKnob(ctx);
  wireSandboxKnob(ctx);
  wireDeveloperKnob(ctx);

  if (usable) wireCloudStorageKnob();
  if (shodanUsable) {
    wireSimpleKnob("shodanknob", "shodanstatus", setShodanMcp, {
      on: "Shodan is on — IPs and hostnames you mention are looked up during research.",
      off: "Shodan is off — nothing is sent to Shodan.",
    });
  }
  if (googleMapsUsable) {
    wireSimpleKnob("gmapsknob", "gmapsstatus", setGoogleMaps, {
      on: "Google Maps is on — addresses you mention (and located photos) are looked up on Google Maps & Street View.",
      off: "Google Maps is off — nothing is sent to Google.",
    });
  }
}

// The cloud knob is the one setting whose flip triggers a bulk move
// (sync.js): ON pushes everything local up, OFF drains everything down and
// wipes the cloud — the status line narrates progress and the outcome.
function wireCloudStorageKnob() {
  const knob = document.getElementById("cloudknob");
  const status = document.getElementById("syncstatus");
  const progress = (msg) => { status.textContent = msg; };
  knob.addEventListener("change", async () => {
    const on = knob.checked;
    knob.disabled = true;
    status.hidden = false;
    try {
      await setServerHistory(on);
      if (on) {
        const r = await syncToServer(progress);
        status.textContent =
          `Cloud storage is on — ${r.pushed} item(s) uploaded.` +
          (r.errors.length ? ` ${r.errors.length} item(s) failed and will retry on the next sync.` : "");
      } else {
        const r = await syncToClient(progress);
        status.textContent = r.wiped
          ? r.checked
            ? `Cloud storage is off — all ${r.checked} cloud item(s) are in this browser` +
              ` (${r.pulled} newly downloaded, the rest were already here); cloud copies removed.`
            : "Cloud storage is off — the cloud held nothing to download; cloud copies removed."
          : "Downloaded what was reachable, but some items failed — the cloud copies were kept. Toggle again to retry.";
      }
    } catch (err) {
      knob.checked = !on; // the setting didn't change server-side
      status.textContent = err?.message || "Could not update the setting.";
    } finally {
      knob.disabled = false;
    }
  });
}

/**
 * Wires a settings knob whose flip is a single /api/settings write (the
 * Shodan and Google Maps rows): optimistic toggle, status text on the
 * outcome, revert on failure.
 * @param {string} knobId    checkbox element id
 * @param {string} statusId  status <p> element id
 * @param {(on: boolean) => Promise<any>} setter  settings.js write
 * @param {{on: string, off: string}} texts  status line per new state
 */
function wireSimpleKnob(knobId, statusId, setter, texts) {
  const knob = document.getElementById(knobId);
  const status = document.getElementById(statusId);
  knob.addEventListener("change", async () => {
    const on = knob.checked;
    knob.disabled = true;
    status.hidden = false;
    try {
      await setter(on);
      status.textContent = on ? texts.on : texts.off;
    } catch (err) {
      knob.checked = !on;
      status.textContent = err?.message || "Could not update the setting.";
    } finally {
      knob.disabled = false;
    }
  });
}

// The account panel's core views + shared building blocks (the panel SHELL —
// initAccountPanel, PanelCtx, showView — lives in account.js):
// - "summary" (default): the rolling 5-hour window (the one that actually
//   governs whether you can send another message right now) plus navigation.
// - "full": drills into the calendar windows (today / this week / this
//   month) — reuses the cached /api/me response, no extra fetch.
// - "games": the games shelf (GET /api/games).
// Plus the pieces every view shares: the settings switch row (settingRow),
// its press-and-hold info popovers (wireSettingPopovers), the header's
// notification badge (renderNotifBadge), and the Settings view's
// Feedback-mode / execution-sandbox rows (renderConfigKnobs +
// wireFeedbackKnob / wireSandboxKnob — rendered by account-settings.js).

import { escapeHtml } from "./notifications.js";
import {
  bashLiteAvailable,
  bashLiteOn,
  developerModeAvailable,
  developerModeOn,
  feedbackAvailable,
  feedbackModeOn,
  setBashLiteMcp,
  setDeveloperMode,
  setFeedbackMode,
} from "./settings.js";
import { applyFeedbackMode } from "./turns.js";

/** @typedef {import("./account.js").PanelCtx} PanelCtx */

// One settings switch row — the shared building block of the Settings
// sub-view's knobs. A single line — one label,
// one info glyph, one switch — with the full explanation tucked into a
// press-and-hold popover (the same gesture the composer's web-search knob
// uses; see wireSettingPopovers). The switch itself is the original
// slide-toggle design the composer's web-search knob used before it became
// the spiderweb (generic .switch classes, not tied to the composer). A row
// is shown disabled (forced off) when the account can't use it —
// break-glass identity, or a server missing the feature's backing — rather
// than hidden, so the state stays explainable.
export function settingRow({ id, label, checked, disabled, popId, info }) {
  // The label may carry markup (the sandbox row's Experimental badge), which
  // is fine inside the visible span but must NOT be interpolated into the
  // aria-label ATTRIBUTE — its quotes break out of the attribute and leak
  // markup fragments as visible text. The accessible name gets a
  // tags-stripped, escaped copy.
  const plainLabel = escapeHtml(String(label).replace(/<[^>]*>/g, " ").replace(/\s+/g, " ").trim());
  return `
    <div class="settings-item">
      <div class="settings-row">
        <span class="settings-label">${label}
          <button type="button" class="setting-info" data-pop="${popId}" aria-label="More about “${plainLabel}”">ⓘ</button>
        </span>
        <label class="switch">
          <input type="checkbox" id="${id}"${checked ? " checked" : ""}${disabled ? " disabled" : ""}>
          <span class="switch-track"><span class="switch-thumb"></span></span>
        </label>
      </div>
      <div class="setting-pop" id="${popId}" hidden>${info}</div>
    </div>`;
}

// Feedback mode's knob lives in the Settings view with every other
// configuration knob (2026-07-11 directive: ALL configuration under the
// header's gear icon).
const FEEDBACK_INFO = `<strong>Feedback mode</strong><br>
  <b>On:</b> every reply — including earlier ones — gets a <b>Feedback</b>
  button. Press it to tell the developers what was good or bad about that
  answer; your note is sent together with the question and the reply it's
  about. The development agent reads every submission, and its answers show
  up as a dialogue under <b>Feedback</b> here in the account panel.<br>
  <b>Off (default):</b> no feedback buttons, nothing is sent.<br>
  <b>Privacy:</b> only what you choose to submit is stored — the comment you
  write plus that one question and reply — readable by the site's
  developers. Withdrawing an entry deletes it, thread included.`;

// The execution-sandbox knob sits beside it in Settings (short note; the
// full story is in the /help pages). Enabling it reloads the page so the
// app comes back cross-origin isolated and the in-browser Linux VM can boot.
const SANDBOX_INFO = `<strong>Execution sandbox (bash) — Experimental</strong><br>
  Boots a real Linux <b>inside this browser</b> so the assistant can run shell
  commands to answer you (e.g. “run ls”). Everything runs on your device —
  nothing leaves the browser. The first use downloads a Linux image, so it's
  slow to start; enabling it reloads the page.`;

// The developer-mode knob unlocks introspection: ask the assistant about the
// site's own implementation and it answers from the deployed source snapshot
// (and can explore the tree at /src when the sandbox is also enabled).
const DEVELOPER_INFO = `<strong>Developer mode</strong><br>
  <b>On:</b> unlocks <b>introspection mode</b> — ask about this site's own
  implementation (“how are you built?”, “show me src/pipeline.js”) and the
  assistant answers from a snapshot of the exact source code this deployment
  runs. With the execution sandbox also on, the whole source tree is mounted
  at <code>/src</code> inside the in-browser Linux VM so the assistant can
  explore it with real shell commands.<br>
  <b>Off (default):</b> implementation questions are answered like any other
  research question.<br>
  The source is public on GitHub; this knob is about keeping developer
  tooling out of the way, not secrecy.`;

/**
 * The Feedback-mode and execution-sandbox rows the Settings view renders
 * under the server-backed knobs (account-settings.js) — knob state from
 * the cached /api/settings copy, both gated on a signed-in account.
 * Wire with wireFeedbackKnob + wireSandboxKnob after insertion.
 * @param {object} me  cached /api/me payload
 * @returns {string} HTML
 */
export function renderConfigKnobs(me) {
  // Break-glass admin (no email): can't persist per-account settings — the
  // /api/settings PUT needs a D1 user row — but the two BROWSER-ONLY features
  // are ON for it by default (settings.js bashLiteEnabled/developerModeEnabled
  // force them true for isSecretAdmin). Previously this returned "" and the
  // developer/introspection AND sandbox knobs were simply ABSENT from the
  // admin's Settings panel — reported as "the introspection knob doesn't
  // move": there was no knob to move. Show them as read-only ON instead, so
  // the admin sees the state honestly. Feedback needs a user row (it stores
  // per-user threads), so it stays out of the admin view.
  if (!me?.email) {
    return (
      settingRow({
        id: "sbknob",
        label: `Execution sandbox <span class="exp-badge">Experimental</span>`,
        checked: true,
        disabled: true,
        popId: "sbpop",
        info: SANDBOX_INFO,
      }) +
      settingRow({
        id: "devknob",
        label: "Developer mode",
        checked: true,
        disabled: true,
        popId: "devpop",
        info: DEVELOPER_INFO,
      }) +
      `<p class="muted setting-note">Admin session: the execution sandbox and developer (introspection) mode are on by default. Sign in with a Google account to switch these per account.</p>`
    );
  }
  return (
    settingRow({
      id: "fbknob",
      label: "Feedback mode",
      checked: feedbackAvailable() && feedbackModeOn(),
      disabled: !feedbackAvailable(),
      popId: "fbpop",
      info: FEEDBACK_INFO,
    }) +
    '<p id="fbstatus" class="muted setting-note" hidden></p>' +
    settingRow({
      id: "sbknob",
      label: `Execution sandbox <span class="exp-badge">Experimental</span>`,
      checked: bashLiteAvailable() && bashLiteOn(),
      disabled: !bashLiteAvailable(),
      popId: "sbpop",
      info: SANDBOX_INFO,
    }) +
    '<p id="sbstatus" class="muted setting-note" hidden></p>' +
    settingRow({
      id: "devknob",
      label: "Developer mode",
      checked: developerModeAvailable() && developerModeOn(),
      disabled: !developerModeAvailable(),
      popId: "devpop",
      info: DEVELOPER_INFO,
    }) +
    '<p id="devstatus" class="muted setting-note" hidden></p>'
  );
}

/**
 * Renders the header's notification counter from the cached /api/me
 * payload (hidden at zero).
 * @param {PanelCtx} ctx
 */
export function renderNotifBadge(ctx) {
  const total = ctx.me?.notifications?.total || 0;
  if (total > 0) {
    ctx.badge.textContent = total > 99 ? "99+" : String(total);
    ctx.badge.hidden = false;
  } else {
    ctx.badge.hidden = true;
  }
}

// Press-and-hold (or click the ⓘ) on a settings row opens its detail
// popover — the same gesture the composer's web-search knob uses. Only one
// popover is open at a time; a click anywhere outside closes it.
export function wireSettingPopovers(root) {
  const closeAll = () => root.querySelectorAll(".setting-pop").forEach((p) => (p.hidden = true));
  root.querySelectorAll(".setting-info").forEach((btn) => {
    const pop = root.querySelector(`#${btn.dataset.pop}`);
    if (!pop) return;
    let holdTimer = 0;
    const open = () => {
      const wasHidden = pop.hidden;
      closeAll();
      pop.hidden = !wasHidden;
    };
    btn.addEventListener("click", (e) => {
      e.stopPropagation();
      open();
    });
    btn.addEventListener("pointerdown", () => {
      holdTimer = setTimeout(() => {
        closeAll();
        pop.hidden = false;
      }, 500);
    });
    for (const ev of ["pointerup", "pointerleave", "pointercancel"]) {
      btn.addEventListener(ev, () => clearTimeout(holdTimer));
    }
  });
  // The info-button handlers above are on freshly rendered elements each
  // time, but the outside-click closer lives on the persistent
  // #account-body — bind it once so re-opening Settings doesn't stack it.
  if (!root._popCloserBound) {
    root._popCloserBound = true;
    root.addEventListener("click", (e) => {
      if (!e.target.closest(".setting-pop") && !e.target.closest(".setting-info")) {
        root.querySelectorAll(".setting-pop").forEach((p) => (p.hidden = true));
      }
    });
  }
}

// ---- games view --------------------------------------------------------------

// The "games" view — the games shelf, rendered from the server's games
// registry (GET /api/games, src/games.js) so a newly registered game
// appears here with no client change. Games open in a NEW TAB like the
// other page links (same-tab navigation would abort an in-flight research
// request). A game whose backing is missing on this server is shown
// disabled with the reason — the same explain-don't-hide posture as the
// settings rows.
export async function loadGamesView(ctx) {
  const shell = (inner) => `
    <button id="gamesbackbtn" type="button" class="back-link">← Back</button>
    <p class="section-lbl">Games</p>
    ${inner}`;
  const wireBack = () =>
    document.getElementById("gamesbackbtn").addEventListener("click", () => ctx.show("summary"));
  ctx.body.innerHTML = shell('<p class="muted">Loading…</p>');
  wireBack();
  let games = null;
  try {
    const res = await fetch("/api/games");
    if (res.ok) games = (await res.json()).games || [];
  } catch { /* games stays null → error state below */ }
  if (!games) {
    ctx.body.innerHTML = shell('<p class="muted">Could not load the games list — try again in a moment.</p>');
    wireBack();
    return;
  }
  const rows = games.length
    ? games
        .map((g) =>
          g.available
            ? `<div class="account-actions">
                 <a href="${escapeHtml(g.path)}" target="_blank" rel="noopener">${escapeHtml(g.emoji)} ${escapeHtml(g.name)} — ${escapeHtml(g.tagline)}</a>
               </div>
               <p class="muted">${escapeHtml(g.description)}</p>`
            : `<div class="account-actions"><a aria-disabled="true">${escapeHtml(g.emoji)} ${escapeHtml(g.name)}</a></div>
               <p class="muted">Needs ${escapeHtml(g.requires || "server configuration")} — not available on this server.</p>`,
        )
        .join("")
    : '<p class="muted">No games are registered on this server.</p>';
  ctx.body.innerHTML = shell(rows);
  wireBack();
}

// The Feedback-mode knob (Settings view): persists via /api/settings
// (feedback_mode) and flips the body's `feedback-mode` class so every
// on-screen reply — existing ones included — shows/hides its Feedback
// button immediately (turns.js). Popovers are wired by the view
// (wireSettingPopovers once over the whole body), not here.
export function wireFeedbackKnob(ctx) {
  const knob = document.getElementById("fbknob");
  if (!knob || knob.disabled) return;
  const status = document.getElementById("fbstatus");
  knob.addEventListener("change", async () => {
    const on = knob.checked;
    knob.disabled = true;
    status.hidden = false;
    try {
      await setFeedbackMode(on);
      applyFeedbackMode(on);
      status.textContent = on
        ? "Feedback mode is on — every reply now has a Feedback button."
        : "Feedback mode is off. Your existing feedback dialogues stay under Feedback.";
    } catch (err) {
      knob.checked = !on;
      status.textContent = err?.message || "Could not update the setting.";
    } finally {
      knob.disabled = false;
    }
  });
}

// The execution-sandbox knob (Settings view): persists via /api/settings
// (bash_lite_mcp). Enabling changes how the PAGE must be served (cross-origin
// isolation for the in-browser Linux VM), which only takes effect on the next
// load — so on enable we save then reload; disabling just saves.
export function wireSandboxKnob(ctx) {
  const knob = document.getElementById("sbknob");
  if (!knob || knob.disabled) return;
  const status = document.getElementById("sbstatus");
  knob.addEventListener("change", async () => {
    const on = knob.checked;
    knob.disabled = true;
    status.hidden = false;
    status.textContent = "Saving…";
    try {
      await setBashLiteMcp(on);
      if (on) {
        status.textContent = "Sandbox enabled — reloading so it can start…";
        setTimeout(() => location.reload(), 800);
      } else {
        status.textContent = "Sandbox disabled.";
        knob.disabled = false;
      }
    } catch (err) {
      knob.checked = !on;
      status.textContent = err?.message || "Could not update the setting.";
      knob.disabled = false;
    }
  });
}

// The developer-mode knob (Settings view): persists via /api/settings
// (developer_mode). Nothing about page serving changes (unlike the sandbox
// knob) — introspection engages per conversation from the next send.
/** @param {PanelCtx} ctx */
export function wireDeveloperKnob(ctx) {
  const knob = /** @type {HTMLInputElement | null} */ (document.getElementById("devknob"));
  if (!knob || knob.disabled) return;
  const status = document.getElementById("devstatus");
  knob.addEventListener("change", async () => {
    const on = knob.checked;
    knob.disabled = true;
    status.hidden = false;
    try {
      await setDeveloperMode(on);
      status.textContent = on
        ? "Developer mode is on — ask about this site's own source code to enter introspection mode."
        : "Developer mode is off.";
    } catch (err) {
      knob.checked = !on;
      status.textContent = err?.message || "Could not update the setting.";
    } finally {
      knob.disabled = false;
    }
  });
}

// ---- summary & usage rendering (pure HTML builders) ---------------------------

/**
 * The summary view's HTML: identity line, the 5-hour usage block, the
 * Feedback-mode knob (signed-in accounts), and the navigation buttons.
 * @param {object} me  cached /api/me payload
 * @returns {string} HTML
 */
export function renderSummary(me) {
  const who = me.email
    ? `${me.name && me.name !== me.email ? me.name + " · " : ""}${me.email}`
    : "Site administrator";
  const msgCount = me.notifications?.total || 0;
  const fbCount = me.notifications?.unread_feedback || 0;
  return `
    <p class="who">${who}<span class="role-badge">${me.unlimited ? "admin · unlimited" : me.role}</span></p>
    ${me.unlimited ? '<p class="muted">Break-glass admin session — usage is tracked under the shared "admin" identity with no personal quota. Sign in with Google to see your own bars.</p>' : ""}
    ${!me.unlimited && !me.enforced ? '<p class="muted">Admin account: bars are shown for reference and keep counting past 100% — nothing blocks you.</p>' : ""}
    ${usageBlock("Last 5 hours", me.windows.h5, true)}
    ${me.db_configured ? "" : '<p class="muted">Accounts database not configured yet — usage tracking and quotas are off.</p>'}
    <!-- Page links open NEW TABS: even though history now persists across
         reloads (encrypted, local — see /help/), a same-tab navigation
         would still abort any in-flight research request. -->
    <div class="account-actions">
      <button id="messagesbtn" type="button"${msgCount ? ' class="has-badge"' : ""}>Messages${msgCount ? ` (${msgCount})` : ""}</button>
      ${me.email ? `<button id="feedbackbtn" type="button">Feedback${fbCount ? ` (${fbCount})` : ""}</button>` : ""}
      <button id="fullusagebtn" type="button">Full usage &amp; history</button>
      <button id="settingsbtn" type="button">Settings</button>
      <button id="gamesbtn" type="button">Games</button>
      <a href="/build/" target="_blank" rel="noopener">About this project</a>
      <a href="/story/" target="_blank" rel="noopener">The build story</a>
      <a href="/architecture/" target="_blank" rel="noopener">The architecture story</a>
      <a href="/pulse/" target="_blank" rel="noopener">Project pulse</a>
      <a href="/help/" target="_blank" rel="noopener">Documentation</a>
      ${me.role === "admin" ? '<a href="/admin" target="_blank" rel="noopener">Admin interface</a>' : ""}
      <button id="logoutbtn" type="button">Sign out</button>
    </div>`;
}

// Drill-down: the three windows that don't gate your next message (today /
// this week / this month), for when you actually want the full picture.
export function renderFullUsage(me) {
  const periods = [
    ["Today", "day"],
    ["This week", "week"],
    ["This month", "month"],
  ];
  const blocks = periods.map(([label, p]) => usageBlock(label, me.windows[p], false)).join("");
  return `
    <button id="usagebackbtn" type="button" class="back-link">← Back</button>
    <p class="section-lbl">Full usage history</p>
    ${blocks}`;
}

// Users see: an OPAQUE research-budget bar (cost-backed server-side, but
// only a percentage ever reaches the client — never amounts) and plain
// search counts. Currency is the admin's concern.
function usageBlock(label, win, rolling) {
  const fmtN = (n) => {
    if (n >= 1e6) return (n / 1e6).toFixed(n >= 1e7 ? 0 : 1) + "M";
    if (n >= 1e3) return (n / 1e3).toFixed(n >= 1e4 ? 0 : 1) + "K";
    return String(n);
  };
  const track = (pct) =>
    `<div class="usage-track"><div class="usage-fill${pct >= 90 ? " hot" : ""}" style="width:${Math.min(100, pct)}%"></div></div>`;
  const budgetPct = win.budget_pct;
  const budgetBar =
    budgetPct == null
      ? `<div class="usage-row"><span>Research budget</span><span>no cap</span></div>${track(0)}`
      : `<div class="usage-row"><span>Research budget</span><span>${budgetPct}%</span></div>${track(budgetPct)}`;
  const sPct = win.searches_limit > 0 ? (win.searches / win.searches_limit) * 100 : 0;
  const searchBar =
    `<div class="usage-row"><span>Web searches · ${fmtN(win.searches)}${win.searches_limit > 0 ? " of " + fmtN(win.searches_limit) : ""}</span>
      <span>${win.searches_limit > 0 ? Math.round(sPct) + "%" : ""}</span></div>${track(sPct)}`;
  const reset = win.reset
    ? `${rolling ? "frees up" : "resets"} ${new Date(win.reset).toLocaleString()}`
    : "";
  return `<div class="usage-block"><div class="lbl">${label}${reset ? " · " + reset : ""}</div>
    ${budgetBar}
    ${searchBar}
  </div>`;
}

// Account & usage panel: /api/me rendered as quota bars (opaque budget
// percentage + search counts per window), documentation/admin links, and
// sign-out. Opened from the header's account button.
//
// This file is the panel SHELL: initAccountPanel (the boot wiring), the
// shared PanelCtx, and the showView dispatcher. The six views' renderers
// live in their own modules:
// - "summary" (default), "full", and "games" — plus the shared building
//   blocks (settingRow, the info popovers, the notification badge, the
//   summary's Feedback-mode knob): account-views.js.
// - "messages" (the message center): account-messages.js.
// - "settings" (the cloud-storage / Shodan / Google Maps knobs):
//   account-settings.js.
// - "feedback" (the user's feedback dialogue threads): account-feedback.js.
//
// Each view is a top-level load*/render* function taking the shared panel
// context (created once by initAccountPanel) so the sections stay
// independently readable; the context carries the DOM refs plus the cached
// /api/me payload the badge and views render from.

import { loadFeedbackView } from "./account-feedback.js";
import { loadMessagesView } from "./account-messages.js";
import { loadSettingsView } from "./account-settings.js";
import { loadGamesView, renderFullUsage, renderNotifBadge, renderSummary } from "./account-views.js";

/**
 * The panel context shared by every view function in the account-* view
 * modules — created once in initAccountPanel and threaded through
 * explicitly.
 * @typedef {object} PanelCtx
 * @property {HTMLElement} overlay  #account — the full-screen overlay
 * @property {HTMLElement} body     #account-body — every view renders here
 * @property {HTMLElement} badge    #notif-badge — the header's counter
 * @property {?object} me           cached /api/me payload (null until fetched)
 * @property {(view: string) => void} show  switches the visible view
 */

// ---- panel bootstrap ---------------------------------------------------------

/**
 * Wires the account panel once at boot: the eager /api/me fetch that feeds
 * the header's notification badge, and the open/close handlers on the
 * header button and overlay.
 * @returns {void}
 */
export function initAccountPanel() {
  const ctx = {
    overlay: document.getElementById("account"),
    body: document.getElementById("account-body"),
    badge: document.getElementById("notif-badge"),
    me: null,
    show: null,
  };
  ctx.show = (view) => showView(ctx, view);

  // Fetched eagerly (not just on account-button click) so the notification
  // badge — personal messages, and for admins also pending approvals + open
  // alerts — shows straight from the main chat view, not only after opening
  // the account panel.
  fetch("/api/me")
    .then((res) => (res.ok ? res.json() : null))
    .then((data) => {
      if (data) {
        ctx.me = data;
        renderNotifBadge(ctx);
      }
    })
    .catch(() => {});

  // Two doors into the same panel: the account button opens the summary,
  // the header's gear opens the Settings view directly (all configuration
  // lives there — 2026-07-11 directive).
  const openPanel = async (view) => {
    ctx.overlay.hidden = false;
    ctx.body.innerHTML = '<p class="muted">Loading…</p>';
    try {
      const res = await fetch("/api/me");
      if (!res.ok) throw new Error("HTTP " + res.status);
      ctx.me = await res.json();
      renderNotifBadge(ctx);
      ctx.show(view);
    } catch {
      ctx.body.innerHTML = '<p class="muted">Could not load account info.</p>';
    }
  };
  document.getElementById("accountbtn").addEventListener("click", () => openPanel("summary"));
  document.getElementById("gearbtn")?.addEventListener("click", () => openPanel("settings"));
  document.getElementById("accountclose").addEventListener("click", () => {
    ctx.overlay.hidden = true;
  });
  ctx.overlay.addEventListener("click", (e) => {
    if (e.target === ctx.overlay) ctx.overlay.hidden = true;
  });
}

/**
 * View dispatcher: renders the named view into the panel body and wires
 * its controls. The summary/full views render synchronously from the
 * cached /api/me; the rest fetch their own data.
 * @param {PanelCtx} ctx
 * @param {"summary"|"full"|"messages"|"settings"|"feedback"|"games"} view
 */
function showView(ctx, view) {
  if (view === "messages") {
    loadMessagesView(ctx);
    return;
  }
  if (view === "settings") {
    loadSettingsView(ctx);
    return;
  }
  if (view === "feedback") {
    loadFeedbackView(ctx);
    return;
  }
  if (view === "games") {
    loadGamesView(ctx);
    return;
  }
  ctx.body.innerHTML = view === "full" ? renderFullUsage(ctx.me) : renderSummary(ctx.me);
  if (view === "full") {
    document.getElementById("usagebackbtn").addEventListener("click", () => ctx.show("summary"));
  } else {
    document.getElementById("fullusagebtn")?.addEventListener("click", () => ctx.show("full"));
    document.getElementById("messagesbtn")?.addEventListener("click", () => ctx.show("messages"));
    document.getElementById("settingsbtn")?.addEventListener("click", () => ctx.show("settings"));
    document.getElementById("feedbackbtn")?.addEventListener("click", () => ctx.show("feedback"));
    document.getElementById("gamesbtn")?.addEventListener("click", () => ctx.show("games"));
    document.getElementById("logoutbtn").addEventListener("click", async () => {
      await fetch("/logout", { method: "POST" });
      location.href = "/login";
    });
  }
}

// Pure, import-free helpers behind the research-activity UI (activity.js) —
// the DOM-free logic pulled out so it's directly unit-testable without loading
// settings.js / imagedeck.js (the pattern sse.js and message-content.js follow).
// activity.js imports these back and re-exports the ones other modules use, so
// its public surface is unchanged.

// Convert the Street View SDK's zoom to the Static API's fov so a captured
// frame matches what's on screen (zoom 0 ≈ 180° wide, zoom 1 ≈ 90°, each level
// halves it; Static accepts 10-120).
export function zoomToFov(zoom) {
  const z = Number.isFinite(Number(zoom)) ? Number(zoom) : 1;
  return Math.round(Math.min(120, Math.max(10, 180 / Math.pow(2, z))));
}

// Compacts a status event before it enters the per-turn research log (the
// "Copy research JSON" source): `streetview_frames` carries whole JPEG data
// URLs — hundreds of KB that would bloat the export — so only the frame count
// and directions are recorded, and `quiz` carries the full question set —
// several KB already persisted in the conversation's embeds registry — so
// only its title and question count are. Everything else passes through
// unchanged.
export function sanitizeResearchEvent(s) {
  if (s?.type === "streetview_frames") {
    const frames = Array.isArray(s.frames) ? s.frames : [];
    return { type: s.type, query: s.query, frames: frames.length, directions: frames.map((f) => f?.dir || f?.label || "") };
  }
  if (s?.type === "quiz") {
    return {
      type: s.type,
      title: s.quiz?.title || "",
      questions: Array.isArray(s.quiz?.questions) ? s.quiz.questions.length : 0,
    };
  }
  return s;
}

// Which provider ran a search must always be visible on the card (a user
// report showed Hugging Face Hub and web searches rendering identically as
// "Searched ..."): the events carry `source` (slug) + `service` (display
// name) since 2026-07-08; absent fields (older stored events) fall back to
// the web wording.
export function searchServiceName(info) {
  return (info && info.service) || "Web search";
}

// The stats footer text from the `done` event (model, duration, tokens,
// searches). Pure string builder; renderStats writes it into the DOM.
export function formatStatsLine(s) {
  const parts = [];
  if (s.model) parts.push(String(s.model).split("/").pop());
  if (s.duration_ms != null) parts.push((s.duration_ms / 1000).toFixed(1) + " s");
  const tokens = (s.prompt_tokens || 0) + (s.completion_tokens || 0);
  if (tokens) parts.push(tokens.toLocaleString() + " tokens");
  if (s.searches) parts.push(s.searches + (s.searches === 1 ? " search" : " searches"));
  return parts.join(" · ");
}

/**
 * One entry in a turn's researchLog: a sanitized SSE status event, or a
 * client-recorded marker ({event: "error"|"stopped"|"stream_dropped", …}),
 * stamped with `t` = ms since the turn started. Written by stream.js's
 * recordResearchEvent and turns.js's setError; read only here.
 * @typedef {object} ResearchLogEntry
 * @property {number} t        ms since the turn started
 * @property {string} [type]   SSE status type (search_done, step_done, done, …)
 * @property {string} [event]  client-side marker (error, stopped, stream_dropped)
 */

/**
 * Structured, JSON-serializable record of a turn's whole research process —
 * the source for the "Copy research JSON" button. Pure (reads only plain turn
 * fields, no DOM). `timeline` is the raw ordered event log (ResearchLogEntry[]);
 * `steps`/`searches`/`sources` are convenience projections of it.
 * @param {object} turn  the turn object (turns.js addAssistantTurn)
 * @returns {object} the debug record ({question, model, stats, steps,
 *   searches, sources, answer, answerChars, errored, errors, timeline})
 */
export function buildResearchDebugJson(turn) {
  const log = Array.isArray(turn.researchLog) ? turn.researchLog : [];
  const searches = log
    .filter((e) => e.type === "search_done")
    .map((e) => ({
      round: e.round,
      query: e.query,
      source: e.source || "web",
      service: e.service || "Web search",
      results: e.results,
      duration_ms: e.duration_ms,
      sources: (e.sources || []).map((s) => ({ title: s.title, url: s.url })),
    }));
  const steps = log
    .filter((e) => e.type === "step_done")
    .map((e) => ({ id: e.id, label: e.label, details: Array.isArray(e.details) ? e.details : [] }));
  // Every cited source, deduped by URL across all search rounds.
  const seen = new Set();
  const sources = [];
  for (const s of searches) {
    for (const src of s.sources) {
      if (src.url && !seen.has(src.url)) {
        seen.add(src.url);
        sources.push(src);
      }
    }
  }
  const d = turn.doneStats;
  const stats = d
    ? {
        model: d.model,
        rounds: d.rounds,
        searches: d.searches,
        duration_ms: d.duration_ms,
        prompt_tokens: d.prompt_tokens,
        completion_tokens: d.completion_tokens,
      }
    : null;
  // Every error the turn hit, server- or client-side (setError records them
  // all into the log). `answer` is the full resulting generation exactly as
  // rendered — including any post-validation revision, a "*(Stopped.)*"
  // marker, or an appended "[…error…]" note — so the export is the complete
  // response, not just its metadata.
  const answer = turn.text || "";
  const errors = log.filter((e) => e.event === "error").map((e) => e.error);
  return {
    question: turn.question || "",
    model: turn.model || d?.model || "",
    stats,
    steps,
    searches,
    sources,
    answer,
    answerChars: answer.length,
    errored: !!turn.errored,
    errors,
    timeline: log,
  };
}

// Research-activity UI: the step bars streamed during a run (searches and
// generic pipeline steps), the stats footer, and the end-of-run collapse
// into a single expandable summary bar. All functions operate on the `turn`
// object created by turns.js; scrolling is the caller's concern.

import { mapsEmbedKey } from "./settings.js";
import {
  addDeckEntries,
  keylessMapEmbedUrl,
  keylessStreetViewEmbedUrl,
  nearestDeckIndex,
  openDeck,
  resetDeck,
} from "./imagedeck.js";
import {
  buildResearchDebugJson,
  formatStatsLine,
  sanitizeResearchEvent,
  searchServiceName,
  zoomToFov,
} from "./activity-core.js";

// Re-exported so importers of activity.js (stream.js, the unit tests) keep
// their existing import paths; the implementations live in activity-core.js.
export { buildResearchDebugJson, sanitizeResearchEvent, searchServiceName };

// ---- Street View SDK panorama + current-view (POV) capture ------------------
//
// The inline Street View is a real Maps JavaScript API StreetViewPanorama
// (the Street View SDK) rather than a Maps Embed iframe, because ONLY the SDK
// exposes where the user has panned/moved (pano id, position, heading, pitch,
// zoom) — an Embed iframe is cross-origin and reports nothing. The current
// POV is tracked here and stream.js sends it as `street_view_pov` with every
// following /api/chat query, so the server can capture and reason about the
// exact frame on the user's screen. If the SDK can't load (e.g. the browser
// key isn't enabled for the Maps JavaScript API), the old iframe renders as a
// fallback — navigable, just without POV capture.

let currentPov = null; // the view the user last panned/moved to (this session)
let currentMapView = null; // the interactive MAP view they last panned/zoomed to
let mapsApiPromise = null; // lazy one-time SDK load
let sdkAuthFailed = false; // Google rejected the key for the JS API (gm_authFailure)
const panoFallbacks = new Set(); // per-panorama "replace me with the iframe" closures
let lockActiveEmbed = null; // locks the newest panorama when a newer one renders
let lockActiveMapEmbed = null; // locks the newest interactive map likewise

// What stream.js attaches to the next /api/chat body, or null when no live
// panorama exists (fresh session, iframe fallback, reloaded conversation).
export function getStreetViewPov() {
  return currentPov;
}

// The map sibling: the center/zoom of the live interactive map, sent as
// body.map_view so a follow-up can capture exactly the area on screen.
export function getMapView() {
  return currentMapView;
}

// The image deck's "continue from this point" anchor (requested
// 2026-07-09): asking from the lightbox's chat panel makes THAT image's
// position the current map view for the next message — the same map_view
// anchor the live interactive map maintains, so the server's whole anchor
// machinery (moves, nearby search, here-asks, scene captures) continues
// from that waypoint. Any live panorama's POV is cleared: the user is
// explicitly speaking from the deck image, not the on-screen panorama.
export function setMapViewAnchor(point) {
  const lat = Number(point?.lat);
  const lng = Number(point?.lng);
  if (!Number.isFinite(lat) || !Number.isFinite(lng)) return;
  currentPov = null;
  currentMapView = { lat, lng, zoom: 17 };
}

// The photo sibling (requested 2026-07-09): asking from a PHOTO deck image
// makes that image's exact view — position AND heading — the current POV,
// so the server's POV path captures precisely that frame, answers about
// it, and renders a fresh Street View there as the new current location.
export function setPovAnchor(point) {
  const lat = Number(point?.lat);
  const lng = Number(point?.lng);
  if (!Number.isFinite(lat) || !Number.isFinite(lng)) return;
  const heading = Number.isFinite(Number(point?.heading)) ? ((Math.round(Number(point.heading)) % 360) + 360) % 360 : 0;
  currentMapView = null;
  currentPov = { panoId: "", lat, lng, heading, pitch: 0, fov: 90 };
}

// New chat / switching conversations: the panorama/map on screen no longer
// belongs to the conversation being sent, so its view must not ride along —
// and the outgoing conversation's embeds must not be locked by the next
// conversation's first embed (the DOM is cleared; the closures must not
// linger and fire at a dead element's expense). The image deck is
// conversation-scoped too.
export function resetStreetViewPov() {
  currentPov = null;
  currentMapView = null;
  lockActiveEmbed = null;
  lockActiveMapEmbed = null;
  resetDeck();
}

// The SDK script can load fine and STILL fail afterwards: Google validates
// the key asynchronously and, on rejection (key not enabled for the Maps
// JavaScript API, referer not allowed, invalid key), paints a "Sorry!
// Something went wrong." panel INTO the map container and calls the global
// gm_authFailure hook — the script's onerror never fires (a reported bug:
// that error panel sat where the panorama should be). Hook it once: replace
// every live panorama with the Embed iframe fallback, drop the now-dead POV,
// and route all future renders straight to the iframe.
function installAuthFailureHook() {
  if (globalThis.__drGmAuthHooked) return;
  globalThis.__drGmAuthHooked = true;
  globalThis.gm_authFailure = () => {
    sdkAuthFailed = true;
    currentPov = null; // no live panorama ⇒ no current view to send
    currentMapView = null; // ditto for the interactive map
    for (const fallback of panoFallbacks) {
      try {
        fallback();
      } catch {
        // best-effort — a failed swap just leaves Google's error panel
      }
    }
    panoFallbacks.clear();
  };
}

// Loads the Maps JS SDK once, on demand (only when a streetview_embed event
// actually arrives). Uses the documented async bootstrap (loading=async +
// callback). A failed load clears the promise so a later turn can retry.
function loadMapsApi(key) {
  if (globalThis.google?.maps?.StreetViewPanorama) return Promise.resolve(globalThis.google.maps);
  if (!mapsApiPromise) {
    mapsApiPromise = new Promise((resolve, reject) => {
      const timer = setTimeout(() => reject(new Error("maps js sdk timeout")), 10_000);
      globalThis.__drMapsReady = () => {
        clearTimeout(timer);
        resolve(globalThis.google?.maps || null);
      };
      const s = document.createElement("script");
      const params = new URLSearchParams({ key, v: "weekly", loading: "async", callback: "__drMapsReady" });
      s.src = `https://maps.googleapis.com/maps/api/js?${params}`;
      s.async = true;
      s.onerror = () => {
        clearTimeout(timer);
        reject(new Error("maps js sdk failed to load"));
      };
      document.head.appendChild(s);
    }).catch((err) => {
      mapsApiPromise = null; // allow a retry on a later turn
      throw err;
    });
  }
  return mapsApiPromise;
}

// Shared shell of both persistent embeds (Street View panorama and
// interactive map): the labeled wrapper and the container box the SDK (or
// the iframe fallback) renders into.
function makeEmbedShell(labelText) {
  const wrap = document.createElement("div");
  wrap.className = "streetview-embed";
  const label = document.createElement("div");
  label.className = "streetview-embed-label";
  label.textContent = labelText;
  const box = document.createElement("div");
  box.className = "streetview-pano";
  wrap.append(label, box);
  return { wrap, label, box };
}

// The keyless <iframe> both embeds fall back to when the SDK can't run —
// see the renderIframeFallback comments in each renderer for why the
// fallback must be keyless.
function keylessIframe(title, src) {
  const iframe = document.createElement("iframe");
  iframe.loading = "lazy";
  iframe.allow = "fullscreen";
  iframe.title = title;
  iframe.src = src;
  return iframe;
}

// Interactive Street View, from a `streetview_embed` status event. Unlike the
// activity steps (which collapse when the run finishes), this is inserted
// into the turn body so it PERSISTS beside the answer. Uses the browser key
// from /api/settings (referrer-locked) — no key means no inline panorama,
// just the keyless Street View link the answer already carries. Live-session
// only: a reloaded conversation shows the answer + link, not the panorama
// (same as the step traces).
export function renderStreetViewEmbed(turn, s) {
  const key = mapsEmbedKey();
  if (!key || !turn?.el || turn._svEmbed) return;
  const lat = Number(s.lat);
  const lng = Number(s.lng);
  if (!Number.isFinite(lat) || !Number.isFinite(lng)) return;

  const { wrap, label, box } = makeEmbedShell("Street View — drag to look around");
  turn.el.insertBefore(wrap, turn.stats);
  turn._svEmbed = wrap;

  // Only the LATEST view stays navigable: rendering this one locks the
  // previous panorama (pointer events off, dimmed, honest label, POV
  // recording stopped) AND any live interactive map, so "the current view"
  // the server reasons about is always the single view in sight — with
  // several live embeds, panning an OLD one could hijack the view sent
  // with follow-ups (reported 2026-07-09).
  if (lockActiveEmbed) lockActiveEmbed();
  if (lockActiveMapEmbed) lockActiveMapEmbed();
  currentMapView = null;
  let locked = false;
  lockActiveEmbed = () => {
    locked = true;
    wrap.classList.add("locked");
    label.textContent = "Street View — earlier view (locked); continue in the latest panorama";
  };

  // The iframe fallback for every way the SDK can fail (script load error,
  // timeout, missing class, async key rejection) — still navigable, just
  // without the current-view capture. KEYLESS, deliberately: a key the JS
  // API just rejected (or one lacking the Maps Embed API service) would
  // render embed/v1 as a white rejection page — a fallback that can itself
  // fail invisibly is no fallback (chat_logs #170/#171; see imagedeck.js).
  const renderIframeFallback = () => {
    box.replaceChildren(
      keylessIframe("Google Street View", keylessStreetViewEmbedUrl(lat, lng, Number(s.heading) || 0, Number(s.pitch) || 0)),
    );
    label.textContent = "Street View — drag to look around";
  };

  // Google already rejected this key for the JS API — don't render its error
  // panel again, go straight to the iframe.
  if (sdkAuthFailed) {
    renderIframeFallback();
    return;
  }
  installAuthFailureHook();

  loadMapsApi(key)
    .then((maps) => {
      if (sdkAuthFailed) throw new Error("maps js auth failed");
      if (!maps?.StreetViewPanorama) throw new Error("StreetViewPanorama unavailable");
      const pano = new maps.StreetViewPanorama(box, {
        position: { lat, lng },
        // Heading/pitch ride along on the POV path (the panorama continues
        // exactly where the user's captured current view was) — absent on an
        // address lookup, where north/level is the neutral start.
        pov: {
          heading: Number.isFinite(Number(s.heading)) ? Number(s.heading) : 0,
          pitch: Number.isFinite(Number(s.pitch)) ? Number(s.pitch) : 0,
        },
        zoom: 1,
        addressControl: false,
        fullscreenControl: true,
      });
      // Track the CURRENT view — a new panorama (a later lookup) simply takes
      // over the shared slot, matching "the street view on screen". A locked
      // (superseded) panorama records nothing: only the latest view counts.
      const record = () => {
        if (locked) return;
        try {
          const pos = pano.getPosition();
          const pov = pano.getPov();
          if (!pos || !pov) return;
          currentPov = {
            panoId: typeof pano.getPano() === "string" ? pano.getPano() : "",
            lat: pos.lat(),
            lng: pos.lng(),
            heading: Math.round(((Number(pov.heading) % 360) + 360) % 360) || 0,
            pitch: Math.round(Number(pov.pitch) || 0),
            fov: zoomToFov(pano.getZoom()),
          };
        } catch {
          // POV capture is best-effort — the panorama itself keeps working.
        }
      };
      pano.addListener("pov_changed", record);
      pano.addListener("position_changed", record);
      pano.addListener("pano_changed", record);
      record();
      label.textContent = "Street View — drag to look around; follow-up questions see your current view";
      // If Google rejects the key AFTER the panorama rendered (gm_authFailure
      // fires whenever), this closure swaps it for the working iframe.
      panoFallbacks.add(renderIframeFallback);
    })
    .catch(renderIframeFallback);
}

// Interactive road map, from a `map_embed` status event — the no-coverage
// counterpart of the Street View embed: the location resolved but Google has
// no panorama near it, so a navigable MAP of the area stands in beside the
// answer (requested 2026-07-09). Handled with full panorama parity (also
// requested 2026-07-09): a real Maps JS SDK google.maps.Map whose pans/zooms
// are tracked into the map view sent with follow-up queries (body.map_view),
// with only the LATEST view (map or panorama) navigable — older embeds lock.
// SDK failure → Maps Embed API iframe fallback (place mode with a marker
// when a resolved address is named, view mode for a continue-from-here
// map) — still navigable, just without the current-view capture. Same key
// discipline: the browser key comes from /api/settings, never the event.
export function renderMapEmbed(turn, s) {
  const key = mapsEmbedKey();
  if (!key || !turn?.el || turn._mapEmbed) return;
  const lat = Number(s.lat);
  const lng = Number(s.lng);
  if (!Number.isFinite(lat) || !Number.isFinite(lng)) return;
  const zoom = Number.isFinite(Number(s.zoom)) ? Math.round(Number(s.zoom)) : 17;

  const baseLabel = s.q ? `Map — ${s.q}` : "Map — drag and zoom to explore";
  const { wrap, label, box } = makeEmbedShell(baseLabel);
  turn.el.insertBefore(wrap, turn.stats);
  turn._mapEmbed = wrap;

  // One live view at a time, across BOTH embed kinds: a new map locks the
  // previous map AND any live panorama (whose stale POV must not ride along
  // with follow-ups about this map).
  if (lockActiveEmbed) lockActiveEmbed();
  currentPov = null;
  if (lockActiveMapEmbed) lockActiveMapEmbed();
  let locked = false;
  lockActiveMapEmbed = () => {
    locked = true;
    currentMapView = null;
    wrap.classList.add("locked");
    label.textContent = "Map — earlier view (locked); continue in the latest map";
  };

  const renderIframeFallback = () => {
    // KEYLESS embed, deliberately: the key-based embed/v1 renders a white
    // rejection page when the key lacks the Maps Embed API service, and a
    // fallback that can itself fail invisibly is no fallback (same class as
    // the image deck's white mini-map, chat_logs #170/#171 — see
    // imagedeck.js keylessMapEmbedUrl). q=lat,lng drops a marker either way.
    box.replaceChildren(keylessIframe("Google Maps", keylessMapEmbedUrl(lat, lng, zoom)));
    label.textContent = baseLabel;
  };

  if (sdkAuthFailed) {
    renderIframeFallback();
    return;
  }
  installAuthFailureHook();

  loadMapsApi(key)
    .then((maps) => {
      if (sdkAuthFailed) throw new Error("maps js auth failed");
      if (!maps?.Map) throw new Error("Map unavailable");
      const map = new maps.Map(box, {
        center: { lat, lng },
        zoom,
        streetViewControl: false,
        mapTypeControl: false,
        fullscreenControl: true,
      });
      if (s.q && maps.Marker) new maps.Marker({ position: { lat, lng }, map, title: s.q });
      // A journey (map_embed's optional `path` field — the "show how we
      // traveled" view): numbered markers at every stop, a polyline
      // between them, and the viewport fitted to the whole route. Clients
      // that don't know the field render the same event as a plain
      // centered map (the sse-protocol forward-compat rule).
      const path = Array.isArray(s.path)
        ? s.path
            .map((p) => ({ lat: Number(p?.lat), lng: Number(p?.lng) }))
            .filter((p) => Number.isFinite(p.lat) && Number.isFinite(p.lng))
        : [];
      if (path.length >= 2 && maps.Polyline) {
        new maps.Polyline({ path, map, strokeColor: "#2563eb", strokeOpacity: 0.9, strokeWeight: 4 });
        if (maps.Marker) {
          path.forEach((p, i) => {
            // Plain numbered pins. (Waypoints briefly rendered deck-image
            // MINIATURES here — removed by explicit decision 2026-07-10:
            // they cluttered the map. Clicking a pin still opens the deck
            // at that stop's image when one exists.)
            const m = new maps.Marker({ position: p, map, label: String((i + 1) % 10), title: `Stop ${i + 1}` });
            const deckIdx = nearestDeckIndex(p.lat, p.lng, 30);
            if (deckIdx >= 0) m.addListener("click", () => openDeck(deckIdx));
          });
        }
        if (maps.LatLngBounds) {
          const bounds = new maps.LatLngBounds();
          path.forEach((p) => bounds.extend(p));
          map.fitBounds(bounds);
        }
      }
      // Track the CURRENT view on "idle" (fires once per settled pan/zoom).
      // Rounded (~1m / integer zoom) so re-asking about the same area hits
      // the server's capture cache instead of re-billing a Static fetch.
      const record = () => {
        if (locked) return;
        try {
          const c = map.getCenter();
          if (!c) return;
          currentMapView = {
            lat: Math.round(c.lat() * 1e5) / 1e5,
            lng: Math.round(c.lng() * 1e5) / 1e5,
            zoom: Math.round(Number(map.getZoom()) || zoom),
          };
        } catch {
          // view capture is best-effort — the map itself keeps working
        }
      };
      map.addListener("idle", record);
      record();
      label.textContent = `${baseLabel}; follow-up questions see your current view`;
      // Key rejected asynchronously (gm_authFailure) → swap for the iframe.
      panoFallbacks.add(renderIframeFallback);
    })
    .catch(renderIframeFallback);
}

// The snapped Street View frames the server's vision helper reasoned about,
// from a `streetview_frames` status event — rendered as a captioned thumbnail
// strip in the turn body so the user sees the SAME imagery the model saw.
// Persists beside the answer like the embed (and like it, is live-session
// only: a reloaded conversation keeps the answer + link, not the images).
export function renderStreetViewFrames(turn, s) {
  if (!turn?.el) return;
  const frames = (Array.isArray(s.frames) ? s.frames : []).filter(
    (f) => typeof f?.url === "string" && f.url.startsWith("data:image/"),
  );
  if (!frames.length) return;
  if (turn._svFrames) turn._svFrames.remove(); // one strip per turn — last event wins

  const wrap = document.createElement("div");
  wrap.className = "streetview-frames";
  const label = document.createElement("div");
  label.className = "streetview-embed-label";
  // A server-provided title wins: the road-map fallback (no Street View
  // coverage at the resolved location) must not be headed "Street View".
  label.textContent = s.title || `Street View — ${s.query || "resolved location"}`;
  const strip = document.createElement("div");
  strip.className = "streetview-frames-strip";
  // Every frame joins the conversation-wide image deck (imagedeck.js) so a
  // click opens the enlarged slideshow at exactly this image; frames carry
  // lat/lng from the server (optional — older events just get no mini-map).
  const deckStart = addDeckEntries(
    frames.map((f) => ({
      url: f.url,
      caption: f.label || (f.dir ? `looking ${f.dir}` : "") || s.query || "",
      lat: f.lat,
      lng: f.lng,
      heading: f.heading,
      kind: f.kind,
    })),
  );
  frames.forEach((f, i) => {
    const fig = document.createElement("figure");
    const img = document.createElement("img");
    img.src = f.url;
    img.loading = "lazy";
    // A frame carries either a cardinal direction ("north") or a free-form
    // label ("your current view" — the POV capture path).
    const caption = f.label || (f.dir ? `looking ${f.dir}` : "");
    img.alt = caption ? `Street View — ${caption}` : "Street View";
    fig.appendChild(img);
    if (caption) {
      const cap = document.createElement("figcaption");
      cap.textContent = caption;
      fig.appendChild(cap);
    }
    fig.classList.add("deck-openable");
    fig.title = "Click to enlarge";
    fig.addEventListener("click", () => openDeck(deckStart + i));
    strip.appendChild(fig);
  });
  wrap.append(label, strip);
  // Before the embed if one is already rendered, else before the stats footer.
  turn.el.insertBefore(wrap, turn._svEmbed || turn.stats);
  turn._svFrames = wrap;
}


// Shared by startGenericStep/startSearchStep: one in-progress step bar — a
// <details class="step"> with a spinner + label summary. Toggling stays
// blocked until `toggleGateClass` appears on the element (generic steps
// unlock via "expandable", search steps via "finished") — before that there
// is nothing inside to show.
function makeStepDom(labelText, toggleGateClass) {
  const details = document.createElement("details");
  details.className = "step";
  const summary = document.createElement("summary");
  const spin = document.createElement("span");
  spin.className = "spin";
  const label = document.createElement("span");
  label.textContent = labelText;
  summary.append(spin, label);
  details.appendChild(summary);
  details.addEventListener("click", (e) => {
    if (!details.classList.contains(toggleGateClass)) e.preventDefault();
  });
  return { details, summary, label };
}

/**
 * Generic pipeline steps (plan / gap check / synthesis / validation).
 * @param {object} turn  the turn object (turns.js addAssistantTurn)
 * @param {string} id    step id — step_done events resolve it by this key
 * @param {string} label initial label text (spinner shown beside it)
 */
export function startGenericStep(turn, id, label) {
  const step = makeStepDom(label, "expandable");
  turn.activity.appendChild(step.details);
  turn.steps[id] = step;
}

// Updates an in-progress step's label in place (spinner kept) — e.g. the
// recovery step ticking "Still researching… (Ns)" so a long wait reads as
// live progress, not a frozen screen. No-op if the step doesn't exist.
export function updateGenericStep(turn, id, label) {
  const step = turn.steps[id];
  if (step) step.label.textContent = label;
}

// Shared by finishGenericStep/finishSearchStep: marks a step's details/
// summary as finished — adds the "finished" class and swaps the spinner
// for a checkmark. Doesn't touch "expandable"; callers add that based on
// whether they have anything to show inside.
function markFinished(step) {
  step.details.classList.add("finished");
  step.summary.querySelector(".spin")?.remove();
  const check = document.createElement("span");
  check.className = "check";
  check.textContent = "✓";
  step.summary.prepend(check);
}

export function finishGenericStep(turn, s) {
  const step = turn.steps[s.id];
  if (!step) return;
  markFinished(step);
  step.label.textContent = s.label || "";
  const items = Array.isArray(s.details) ? s.details : [];
  if (items.length) {
    step.details.classList.add("expandable");
    const ul = document.createElement("ul");
    for (const it of items) {
      const li = document.createElement("li");
      li.textContent = String(it);
      ul.appendChild(li);
    }
    step.details.appendChild(ul);
  }
}

// "Searching the web: …" with a spinner.
//
// Searches within one round run concurrently server-side (src/pipeline.js),
// so several search_start events can arrive before any search_done — keyed
// by query text (pipeline.js already dedupes queries within a round, so
// this is always a unique key) rather than assuming strict start/done
// pairing.
export function startSearchStep(turn, info) {
  const query = info.query || "";
  // Toggle gate "finished": blocked while running (no sources to show yet).
  const step = makeStepDom(searchServiceName(info) + ": “" + query + "”", "finished");
  turn.activity.appendChild(step.details);
  // Keyed by provider + query: the same query text may legitimately run on
  // both the web and an auxiliary source in one round.
  (turn.pendingSearchSteps ||= new Map()).set((info.source || "web") + "|" + query, step);
}

// Resolve the step: checkmark, counts, timing, expandable source list.
export function finishSearchStep(turn, info) {
  const step = turn.pendingSearchSteps?.get((info.source || "web") + "|" + info.query);
  if (!step) return;
  turn.pendingSearchSteps.delete((info.source || "web") + "|" + info.query);
  markFinished(step);
  step.details.classList.add("expandable");
  const n = info.results ?? 0;
  step.label.textContent =
    searchServiceName(info) + " “" + info.query + "” · " +
    n + (n === 1 ? " result" : " results") + " · " +
    Math.round(info.duration_ms ?? 0) + " ms";
  const ul = document.createElement("ul");
  for (const src of info.sources || []) {
    const li = document.createElement("li");
    const a = document.createElement("a");
    a.href = src.url;
    a.textContent = src.title || src.url;
    a.target = "_blank";
    a.rel = "noopener";
    li.appendChild(a);
    ul.appendChild(li);
  }
  step.details.appendChild(ul);
}

// Stats footer from the `done` event (model, duration, tokens). The line text
// is built by the pure formatStatsLine (activity-core.js).
export function renderStats(turn, s) {
  turn.searchCount = s.searches || 0;
  turn.stats.textContent = formatStatsLine(s);
}

// Stop any step still showing a spinner now that the run is over. Every step
// normally gets its own step_done, but a RECOVERED answer (a stream that
// dropped and finished server-side) doesn't replay the step_done events for
// whatever was mid-flight when the connection died — so that step (a gap
// check, a search, synthesis) would spin FOREVER beside a finished answer,
// making a completed run look like it's still processing (the reported bug).
// Settle them neutrally: remove the spinner and add a muted mark, not the
// green ✓ (we don't have the step's verified result, only that the run has
// ended). Idempotent and safe to call on already-finished steps.
export function settlePendingSteps(turn) {
  const settle = (step) => {
    if (!step || step.details.classList.contains("finished")) return;
    step.summary.querySelector(".spin")?.remove();
    step.details.classList.add("finished");
    if (!step.summary.querySelector(".check, .settled")) {
      const mark = document.createElement("span");
      mark.className = "settled";
      mark.textContent = "✓";
      step.summary.prepend(mark);
    }
  };
  for (const id in turn.steps) settle(turn.steps[id]);
  if (turn.pendingSearchSteps) {
    for (const [, step] of turn.pendingSearchSteps) settle(step);
    turn.pendingSearchSteps.clear();
  }
}

// Collapse the live activity bars into one expandable summary once the
// answer is complete. Leaves a lone bar (e.g. a direct reply) as-is. The
// .done class keeps the summary bar visible when re-expanded, so the group
// can always be folded back to a single bar.
export function collapseActivity(turn) {
  settlePendingSteps(turn); // stop any spinner a dropped/recovered run left behind
  const steps = turn.activity.querySelectorAll(":scope > .step");
  if (steps.length <= 1) return;
  const searches = turn.searchCount;
  turn.activityLabel.textContent = searches
    ? `Research process · ${steps.length} steps · ${searches} search${searches === 1 ? "" : "es"}`
    : `Research process · ${steps.length} steps`;
  // A debug affordance that lives at the top of the expanded step list:
  // copies a full JSON record of every research task this run performed
  // (steps, queries, service lookups, timings, sources, stats) for pasting
  // into Claude Code. Only added once, and only for real multi-step runs.
  if (!turn.activity.querySelector(":scope > .activity-debug")) {
    turn.activity.prepend(makeCopyDebugButton(turn));
  }
  turn.activityWrap.classList.add("done");
  turn.activityWrap.open = false;
}

function makeCopyDebugButton(turn) {
  const bar = document.createElement("div");
  bar.className = "activity-debug";
  const btn = document.createElement("button");
  btn.type = "button";
  btn.className = "debug-copy-btn";
  btn.textContent = "Copy research JSON";
  btn.title =
    "Copy a JSON record of every research task this run performed — paste into Claude Code to debug";
  btn.addEventListener("click", async (e) => {
    // Inside the <details> content, so a click here must not toggle it.
    e.preventDefault();
    e.stopPropagation();
    try {
      await navigator.clipboard.writeText(JSON.stringify(buildResearchDebugJson(turn), null, 2));
      btn.textContent = "Copied ✓";
    } catch {
      btn.textContent = "Copy failed";
    }
    setTimeout(() => { btn.textContent = "Copy research JSON"; }, 1500);
  });
  bar.appendChild(btn);
  return bar;
}

