// @ts-check
// The AGENT ACTIVITY BACKDROP's pure core (the one testable half of the
// feature; the DOM glue is agent-backdrop.js). When the execution sandbox runs
// commands we deliberately DO NOT pop the terminal panel open any more — it
// covered the screen and broke the prompt-first flow. Instead the raw commands
// and their output drift faintly across the sky-blue page background, so the
// user keeps some visibility into what the agent is doing without ever leaving
// the composer.
//
// This module owns the model behind that layer, kept pure so it runs in Node's
// test runner with no DOM:
//
//   - a small ring-buffered, multi-CHANNEL transcript (one channel per agent,
//     so several concurrent agents each get their own raw view), plus the
//     round-robin that "clips back and forth" between them when more than one
//     is active, and
//   - the user's transparency preference parsing/clamping (a slider, 0 = the
//     layer is off, up to 100 = fully at its faint ceiling).
//
// Everything here is total: bad input degrades to a default or an empty list,
// never throws — the backdrop is decoration and must never break a request.

// How many lines each channel keeps. The layer only ever shows the tail, so
// this is both the render window and the memory cap.
export const MAX_LINES = 80;
// Hard cap on a single displayed line so one runaway command can't blow up the
// DOM (the raw output is decoration, not a pager).
export const MAX_LINE_CHARS = 400;
// Default transparency (percent). On but faint — visible texture, not a wall.
export const DEFAULT_OPACITY_PCT = 22;
// How long each channel stays on screen before the backdrop clips to the next
// one, when several agents are active at once (milliseconds). Exported so the
// DOM timer and the tests agree on one number.
export const CHANNEL_CLIP_MS = 4200;

/** @typedef {{ command: string, exitCode: number, stdout: string, stderr: string }} ShellRun */
/** @typedef {{ maxLines: number, channels: Record<string, string[]>, order: string[], active: string | null }} BackdropModel */

/**
 * Collapse a value to a single trimmed, length-capped display line.
 * @param {unknown} s
 */
export function clampLine(s) {
  const one = String(s == null ? "" : s).replace(/[\r\n\t]+/g, " ").replace(/\s+$/g, "");
  return one.length > MAX_LINE_CHARS ? one.slice(0, MAX_LINE_CHARS - 1) + "…" : one;
}

/**
 * A fresh, empty backdrop model.
 * @param {{ maxLines?: number }} [opts]
 * @returns {BackdropModel}
 */
export function createBackdropModel(opts = {}) {
  const maxLines = Number.isFinite(Number(opts.maxLines)) && Number(opts.maxLines) > 0
    ? Math.trunc(Number(opts.maxLines))
    : MAX_LINES;
  return { maxLines, channels: Object.create(null), order: [], active: null };
}

/**
 * Register a channel if new (first one becomes active). Returns the channel id.
 * @param {BackdropModel} model
 * @param {string} channel
 */
export function ensureChannel(model, channel) {
  const id = String(channel || "shell") || "shell";
  if (!model.channels[id]) {
    model.channels[id] = [];
    model.order.push(id);
    if (model.active == null) model.active = id;
  }
  return id;
}

/**
 * Append one or more raw lines to a channel, focus it (a channel with fresh
 * output becomes the active one so the user sees the newest work), and cap the
 * ring. Returns the lines actually stored (clamped).
 * @param {BackdropModel} model
 * @param {string} channel
 * @param {string[]} lines
 */
export function pushLines(model, channel, lines) {
  const id = ensureChannel(model, channel);
  const buf = model.channels[id];
  const stored = [];
  for (const raw of Array.isArray(lines) ? lines : [lines]) {
    const line = clampLine(raw);
    buf.push(line);
    stored.push(line);
  }
  while (buf.length > model.maxLines) buf.shift();
  model.active = id; // newest activity wins the screen
  return stored;
}

/**
 * Push a proposed command as a prompt line (`$ cmd`).
 * @param {BackdropModel} model
 * @param {string} channel
 * @param {string} command
 */
export function pushCommand(model, channel, command) {
  return pushLines(model, channel, ["$ " + clampLine(command)]);
}

/**
 * Turn a finished ShellRun into raw display lines: its stdout then stderr, one
 * line each, with a trailing `[exit N]` marker when the command failed. Empty
 * trailing lines are dropped so the layer isn't padded with blanks.
 * @param {ShellRun} run
 * @returns {string[]}
 */
export function formatResultLines(run) {
  /** @type {string[]} */
  const out = [];
  /** @param {unknown} text */
  const push = (text) => {
    const s = String(text == null ? "" : text);
    if (!s) return;
    for (const ln of s.split("\n")) out.push(clampLine(ln));
  };
  push(run && run.stdout);
  push(run && run.stderr);
  while (out.length && out[out.length - 1] === "") out.pop();
  const code = Number(run && run.exitCode);
  if (Number.isFinite(code) && code !== 0) out.push("[exit " + Math.trunc(code) + "]");
  return out;
}

/**
 * Push a finished command's raw output into its channel.
 * @param {BackdropModel} model
 * @param {string} channel
 * @param {ShellRun} run
 */
export function pushResult(model, channel, run) {
  return pushLines(model, channel, formatResultLines(run));
}

/**
 * The lines of a specific channel (a copy; [] when unknown).
 * @param {BackdropModel} model
 * @param {string} channel
 */
export function channelLines(model, channel) {
  const buf = model.channels[String(channel)];
  return Array.isArray(buf) ? buf.slice() : [];
}

/**
 * The lines of the currently-shown channel.
 * @param {BackdropModel} model
 */
export function activeLines(model) {
  return model.active == null ? [] : channelLines(model, model.active);
}

/**
 * How many channels (agents) the backdrop is tracking.
 * @param {BackdropModel} model
 */
export function channelCount(model) {
  return model.order.length;
}

/**
 * Advance the active channel to the next one in round-robin order — the "clip
 * back and forth between agents" step. A no-op (returns the same id) when zero
 * or one channel is present. Returns the newly-active id.
 * @param {BackdropModel} model
 */
export function clipToNextChannel(model) {
  if (model.order.length <= 1) return model.active;
  const i = model.active == null ? -1 : model.order.indexOf(model.active);
  model.active = model.order[(i + 1) % model.order.length];
  return model.active;
}

// ---- transparency preference ------------------------------------------------

/**
 * Clamp any value to an integer percentage in [0, 100].
 * @param {unknown} n
 */
export function clampOpacityPct(n) {
  const v = Math.round(Number(n));
  if (!Number.isFinite(v)) return DEFAULT_OPACITY_PCT;
  return Math.max(0, Math.min(100, v));
}

/**
 * Parse the stored preference (a bare number, a numeric string, or null/absent)
 * into a clamped percentage, falling back to the default when unset or garbage.
 * @param {unknown} raw
 * @returns {number} 0..100
 */
export function parseOpacityPref(raw) {
  if (raw == null || raw === "") return DEFAULT_OPACITY_PCT;
  const v = Number(raw);
  if (!Number.isFinite(v)) return DEFAULT_OPACITY_PCT;
  return clampOpacityPct(v);
}

/**
 * Whether a given percentage means the layer is shown at all.
 * @param {number} pct
 */
export function backdropEnabled(pct) {
  return clampOpacityPct(pct) > 0;
}

/**
 * Map the user's 0..100 slider to the layer's actual CSS opacity. The ceiling
 * is deliberately below 1 (0.55) so even "full" stays a faint backdrop the
 * chat reads cleanly over — the slider tunes within the faint band, it does
 * not turn the page into a terminal.
 * @param {number} pct
 * @returns {number} 0..0.55
 */
export function opacityCss(pct) {
  return +(clampOpacityPct(pct) / 100 * 0.55).toFixed(3);
}

// Tests for the agent-activity backdrop's pure core (agent-backdrop-core.js):
// the multi-channel ring-buffer transcript, the round-robin that clips between
// agents, the ShellRun→lines formatting, and the transparency-preference
// parsing/clamping. Runs in plain Node — no DOM. The DOM glue (agent-backdrop.js)
// is browser-only and deliberately untested here.

import test from "node:test";
import assert from "node:assert/strict";

import {
  DEFAULT_OPACITY_PCT,
  MAX_LINES,
  MAX_LINE_CHARS,
  activeLines,
  backdropEnabled,
  channelCount,
  channelLines,
  clampLine,
  clampOpacityPct,
  clipToNextChannel,
  createBackdropModel,
  ensureChannel,
  formatResultLines,
  opacityCss,
  parseOpacityPref,
  pushCommand,
  pushLines,
  pushResult,
} from "./agent-backdrop-core.js";

test("clampLine collapses whitespace and caps length", () => {
  assert.equal(clampLine("a\nb\tc  "), "a b c");
  const long = "x".repeat(MAX_LINE_CHARS + 50);
  const out = clampLine(long);
  assert.equal(out.length, MAX_LINE_CHARS);
  assert.ok(out.endsWith("…"));
  assert.equal(clampLine(null), "");
  assert.equal(clampLine(undefined), "");
});

test("createBackdropModel starts empty with the default cap", () => {
  const m = createBackdropModel();
  assert.equal(m.maxLines, MAX_LINES);
  assert.equal(channelCount(m), 0);
  assert.equal(m.active, null);
  assert.deepEqual(activeLines(m), []);
  // custom cap honored; garbage falls back to default
  assert.equal(createBackdropModel({ maxLines: 5 }).maxLines, 5);
  assert.equal(createBackdropModel({ maxLines: -3 }).maxLines, MAX_LINES);
});

test("ensureChannel registers once and sets the first as active", () => {
  const m = createBackdropModel();
  assert.equal(ensureChannel(m, "a"), "a");
  assert.equal(m.active, "a");
  ensureChannel(m, "a"); // idempotent
  ensureChannel(m, "b");
  assert.equal(channelCount(m), 2);
  assert.equal(m.active, "a"); // adding a channel doesn't steal focus
  // empty/nullish channel names collapse to "shell"
  assert.equal(ensureChannel(m, ""), "shell");
  assert.equal(ensureChannel(m, null), "shell");
});

test("pushCommand renders a prompt line and focuses the channel", () => {
  const m = createBackdropModel();
  ensureChannel(m, "a");
  ensureChannel(m, "b");
  assert.equal(m.active, "a");
  pushCommand(m, "b", "ls -la /etc");
  assert.equal(m.active, "b"); // newest activity wins
  assert.deepEqual(channelLines(m, "b"), ["$ ls -la /etc"]);
});

test("pushLines caps the ring to maxLines (oldest dropped)", () => {
  const m = createBackdropModel({ maxLines: 3 });
  pushLines(m, "a", ["1", "2", "3", "4", "5"]);
  assert.deepEqual(channelLines(m, "a"), ["3", "4", "5"]);
});

test("formatResultLines yields stdout then stderr, drops trailing blanks, marks failure", () => {
  assert.deepEqual(
    formatResultLines({ command: "x", exitCode: 0, stdout: "one\ntwo\n", stderr: "" }),
    ["one", "two"],
  );
  const withErr = formatResultLines({ command: "x", exitCode: 2, stdout: "out", stderr: "boom" });
  assert.deepEqual(withErr, ["out", "boom", "[exit 2]"]);
  // exit 0 => no marker; all-empty => no lines
  assert.deepEqual(formatResultLines({ command: "x", exitCode: 0, stdout: "", stderr: "" }), []);
});

test("pushResult stores formatted output into the channel", () => {
  const m = createBackdropModel();
  pushResult(m, "shell", { command: "echo hi", exitCode: 0, stdout: "hi\n", stderr: "" });
  assert.deepEqual(channelLines(m, "shell"), ["hi"]);
});

test("clipToNextChannel round-robins only when >1 channel", () => {
  const m = createBackdropModel();
  // zero/one channel: no-op
  assert.equal(clipToNextChannel(m), null);
  ensureChannel(m, "a");
  assert.equal(clipToNextChannel(m), "a");
  ensureChannel(m, "b");
  ensureChannel(m, "c");
  m.active = "a";
  assert.equal(clipToNextChannel(m), "b");
  assert.equal(clipToNextChannel(m), "c");
  assert.equal(clipToNextChannel(m), "a"); // wraps
});

test("clampOpacityPct clamps to [0,100] and rounds; garbage => default", () => {
  assert.equal(clampOpacityPct(50), 50);
  assert.equal(clampOpacityPct(-10), 0);
  assert.equal(clampOpacityPct(250), 100);
  assert.equal(clampOpacityPct(33.6), 34);
  assert.equal(clampOpacityPct("nope"), DEFAULT_OPACITY_PCT);
});

test("parseOpacityPref falls back to default for unset/garbage, else clamps", () => {
  assert.equal(parseOpacityPref(null), DEFAULT_OPACITY_PCT);
  assert.equal(parseOpacityPref(""), DEFAULT_OPACITY_PCT);
  assert.equal(parseOpacityPref("abc"), DEFAULT_OPACITY_PCT);
  assert.equal(parseOpacityPref("40"), 40);
  assert.equal(parseOpacityPref(0), 0);
  assert.equal(parseOpacityPref(999), 100);
});

test("backdropEnabled is false only at 0", () => {
  assert.equal(backdropEnabled(0), false);
  assert.equal(backdropEnabled(1), true);
  assert.equal(backdropEnabled(100), true);
});

test("opacityCss maps 0..100 into the faint band 0..0.55", () => {
  assert.equal(opacityCss(0), 0);
  assert.equal(opacityCss(100), 0.55);
  assert.ok(opacityCss(50) > 0 && opacityCss(50) < 0.55);
});

// The AGENT ACTIVITY BACKDROP — the DOM half of the feature (pure model +
// preference logic live in agent-backdrop-core.js). NOT `// @ts-check`: this is
// browser glue (document/localStorage), guarded so importing it in Node — which
// happens transitively via sandbox.js ← drc-research.js, a Node-tested module —
// never touches a browser global at load time.
//
// Instead of popping the sandbox terminal open (which covered the screen and
// broke the prompt-first flow), the raw commands and output the agent runs
// drift faintly across the page's sky-blue background, and — THIS is the whole
// UX — a small TRANSPARENCY BAR appears while the terminal is running so the
// user tunes how visible that layer is, right there, live. There is NO settings
// entry: the bar IS the control, shown only during activity and auto-hidden
// when the terminal goes quiet. When the layer is turned all the way off (0),
// the text layer is not built or rendered at all (optimized away) — only the
// tiny bar shows, so the user can bring it back.
//
// The single feed point is execInSandbox in sandbox.js, so BOTH tiers (DRS and
// DRC) and any agent that runs commands surface here automatically. Callers may
// pass a channel id per agent; when several are active the layer clips between
// them. The chosen transparency is remembered per browser (localStorage) so the
// bar comes back where the user left it — but it is never a config screen.

import {
  CHANNEL_CLIP_MS,
  activeLines,
  backdropEnabled,
  channelCount,
  clipToNextChannel,
  createBackdropModel,
  opacityCss,
  parseOpacityPref,
  pushCommand,
  pushResult,
} from "./agent-backdrop-core.js";

const STORE_KEY = "dr_agent_backdrop";
// How long the transparency bar lingers after the last command before it
// auto-hides (the terminal has gone quiet). Kept alive while the user is
// touching it.
const BAR_HIDE_MS = 6000;

const model = createBackdropModel();
let layer = null; // the fixed background text element (built lazily, only when on)
let pre = null; // the <pre> the active channel renders into
let bar = null; // the floating transparency slider (built lazily on first activity)
let barRange = null;
let barVal = null;
let clipTimer = 0; // round-robin between channels when >1 is active
let hideTimer = 0; // auto-hide the bar after inactivity
let interacting = false; // user is touching the bar — don't auto-hide
let pref = null; // cached opacity percentage (lazy-read from localStorage)

// ---- preference persistence (remembered position, NOT a settings screen) ----

function readPref() {
  if (pref != null) return pref;
  let raw = null;
  try {
    if (typeof localStorage !== "undefined") raw = localStorage.getItem(STORE_KEY);
  } catch { /* private mode / disabled storage */ }
  pref = parseOpacityPref(raw);
  return pref;
}

function writePref(pct) {
  pref = pct;
  try {
    if (typeof localStorage !== "undefined") localStorage.setItem(STORE_KEY, String(pct));
  } catch { /* ignore */ }
}

function valLabel(pct) {
  return pct <= 0 ? "Off" : pct + "%";
}

/** The current transparency (0..100) — remembered slider position. */
export function backdropOpacityPct() {
  return readPref();
}

/** Whether the layer is enabled (non-zero). */
export function backdropOn() {
  return backdropEnabled(readPref());
}

/**
 * Set the transparency (0..100), persist it, and apply it live. 0 removes the
 * text layer from view (and skips building it). Used by the bar's slider.
 * @param {number} pct
 */
export function setBackdropOpacity(pct) {
  const v = parseOpacityPref(pct);
  writePref(v);
  applyPref();
}

// ---- the background text layer ----------------------------------------------

function ensureLayer() {
  if (layer || typeof document === "undefined" || !document.body) return layer;
  layer = document.createElement("div");
  layer.id = "dr-agent-backdrop";
  layer.setAttribute("aria-hidden", "true");
  pre = document.createElement("pre");
  pre.className = "dr-agent-backdrop-text";
  layer.appendChild(pre);
  document.body.appendChild(layer);
  applyOpacity();
  return layer;
}

function applyOpacity() {
  if (!layer) return;
  const pct = readPref();
  if (!backdropEnabled(pct)) {
    layer.style.display = "none";
    return;
  }
  layer.style.display = "";
  layer.style.opacity = String(opacityCss(pct));
}

// Apply the current preference to the world: build/show the text layer when on,
// hide it when off (0) — the "if not shown at all, just optimize that case".
function applyPref() {
  if (backdropOn()) {
    ensureLayer();
    render();
    applyOpacity();
    syncClipTimer();
  } else {
    applyOpacity(); // hides the layer if it exists; nothing built if it doesn't
    syncClipTimer();
  }
}

function render() {
  if (!pre) return;
  // Newest at the bottom, like a real terminal tail; the CSS clips the top so
  // the visible window is always the most recent work.
  pre.textContent = activeLines(model).join("\n");
}

// Start/stop the round-robin that clips between agents. Only runs when more
// than one channel is active AND the layer is visible.
function syncClipTimer() {
  const shouldRun = channelCount(model) > 1 && backdropOn() && typeof setInterval !== "undefined";
  if (shouldRun && !clipTimer) {
    clipTimer = setInterval(() => {
      clipToNextChannel(model);
      render();
    }, CHANNEL_CLIP_MS);
  } else if (!shouldRun && clipTimer) {
    clearInterval(clipTimer);
    clipTimer = 0;
  }
}

// ---- the floating transparency bar (the whole UX) ---------------------------

function ensureBar() {
  if (bar || typeof document === "undefined" || !document.body) return bar;
  bar = document.createElement("div");
  bar.id = "dr-backdrop-bar";
  bar.className = "dr-backdrop-bar";
  bar.hidden = true;

  const icon = document.createElement("span");
  icon.className = "dr-backdrop-bar-icon";
  icon.textContent = "◐";
  icon.title = "Sandbox terminal — background transparency";

  barRange = document.createElement("input");
  barRange.type = "range";
  barRange.min = "0";
  barRange.max = "100";
  barRange.step = "1";
  barRange.className = "dr-backdrop-range";
  barRange.setAttribute("aria-label", "Terminal backdrop transparency");
  barRange.value = String(readPref());

  barVal = document.createElement("span");
  barVal.className = "dr-backdrop-bar-val";
  barVal.textContent = valLabel(readPref());

  barRange.addEventListener("input", () => {
    const pct = Number(barRange.value) || 0;
    setBackdropOpacity(pct);
    if (barVal) barVal.textContent = valLabel(pct);
    interacting = true;
    keepBarAlive();
  });
  barRange.addEventListener("change", () => { interacting = false; scheduleHide(); });
  bar.addEventListener("pointerenter", () => { interacting = true; showBar(); });
  bar.addEventListener("pointerleave", () => { interacting = false; scheduleHide(); });

  bar.appendChild(icon);
  bar.appendChild(barRange);
  bar.appendChild(barVal);
  document.body.appendChild(bar);
  return bar;
}

function showBar() {
  ensureBar();
  if (!bar) return;
  if (barRange) barRange.value = String(readPref());
  if (barVal) barVal.textContent = valLabel(readPref());
  bar.hidden = false;
  keepBarAlive();
}

function keepBarAlive() {
  if (hideTimer) { clearTimeout(hideTimer); hideTimer = 0; }
  scheduleHide();
}

function scheduleHide() {
  if (hideTimer) { clearTimeout(hideTimer); hideTimer = 0; }
  if (interacting || typeof setTimeout === "undefined") return;
  hideTimer = setTimeout(() => {
    if (bar && !interacting) bar.hidden = true;
  }, BAR_HIDE_MS);
}

// ---- the feed (called from execInSandbox) -----------------------------------

// A command or its output arrived → the terminal is running: show the bar (the
// control), and — only when the layer isn't turned off — build/render the faint
// text. At 0 the bar still shows so the user can bring the layer back, but no
// text layer is built or updated (the optimized case).
function feed(fn, channel, payload) {
  try {
    showBar();
    if (!backdropOn()) return; // off — optimize: skip the text layer entirely
    ensureLayer();
    fn(model, channel || "shell", payload);
    render();
    syncClipTimer();
  } catch { /* the backdrop is decoration — never break the caller */ }
}

/** Show a proposed command (`$ cmd`) on the given agent's channel. */
export function feedCommand(channel, command) {
  feed(pushCommand, channel, command);
}

/** Show a finished command's raw stdout/stderr on the given agent's channel. */
export function feedResult(channel, run) {
  feed(pushResult, channel, run);
}

// Deepresearch.se chat client — bootstrap and wiring.
//
// Module map (what this file wires):
//   timescale.js      — slider position <-> seconds mapping (pure)
//   turns.js          — user bubbles + assistant turns (content, tools, typing)
//   activity.js       — live research step bars, stats footer, embeds, collapse
//   models.js         — model dropdown (catalog, persistence, vision lookup)
//   attachments.js    — pending images/documents, downscaling, card row
//   account.js        — account & usage panel (/api/me)
//   stream.js         — conversation history + /api/chat SSE send loop
//   history-ui.js     — the encrypted local-history drawer
//   projects.js/-ui   — project records, panel, header chip
//   settings.js       — cached /api/settings (cloud/feedback knob state)
//   sync.js           — boot-time cloud reconcile (push diff + pullNewer)
//   imagedeck.js      — the conversation-wide image deck (onDeckAsk hook)
//   pending-answer.js — the resume-across-relaunch pointer
//
// This file wires the page: scrolling, composer controls (slider, search
// knob, autogrow, submit), and the module initializers.

import { initAccountPanel } from "./account.js";
import { hasPending, indexingBusy, initAttachments, syncAttachState, takeAttachments } from "./attachments.js";
import { refreshProjects, setActiveProject } from "./projects.js";
import { initProjectsUi } from "./projects-ui.js";
