  clearHistory,
  conversationAsText,
  conversationStarted,
  initStream,
  isStreaming,
  resumePendingAnswer,
  sendMessage,
  stopGeneration,
} from "./stream.js";
import { BUDGET_MAX_S, BUDGET_MIN_S, fmtBudget, posToSeconds, secondsToPos } from "./timescale.js";
import { applyFeedbackMode, clearChatDom, EMPTY_TEXT, initTurns } from "./turns.js";

// ---- Elements -------------------------------------------------------------

const chat = document.getElementById("chat");
const form = document.getElementById("form");
const input = document.getElementById("input");
const send = document.getElementById("send");

// ---- Auto-follow scrolling ---------------------------------------------
// Streaming pins the view to the bottom ONLY while the user is already
// there. Scrolling up detaches (no yank-back on the next token) and shows
// the jump-down button; pressing it — or scrolling back down yourself —
// re-attaches.

// The chrome (header items, composer) floats as fixed glass panes over
// the content — nothing hides or slides; the chat scrolls beneath and
// shows through the translucency and the gaps between items.
const jumpBtn = document.getElementById("jumpdown");
let autoFollow = true;

chat.addEventListener("scroll", () => {
  const nearBottom = chat.scrollHeight - chat.scrollTop - chat.clientHeight < 48;
  autoFollow = nearBottom;
  jumpBtn.hidden = nearBottom;
});
jumpBtn.addEventListener("click", () => {
  // Instant, not smooth: a smooth animation fires intermediate scroll
  // events that read as "user scrolled away" and re-detach — and the
  // bottom keeps moving while content streams.
  autoFollow = true;
  chat.scrollTop = chat.scrollHeight;
  jumpBtn.hidden = true;
});
const scrollDown = (force = false) => {
  if (force) autoFollow = true;
  if (autoFollow) chat.scrollTop = chat.scrollHeight;
};

// ---- Module wiring ---------------------------------------------------------

initTurns(chat, scrollDown, { isBusy: isStreaming });
initModels(document.getElementById("model"), { onChange: syncAttachState });
initAttachments(
  document.getElementById("attach"),
  document.getElementById("file"),
  document.getElementById("pending"),
  document.getElementById("camera"),
  document.getElementById("camerafile"),
);
initAccountPanel();
// Account settings (the cloud-storage knob): fetched once at boot so the
// storage modules' synchronous serverHistoryOn() checks have an answer.
// Cloud storage is ON by default — most accounts never touch the knob —
// so boot also runs a quiet background reconcile: push anything local the
// cloud doesn't have yet (diff-only; skips up-to-date items) and pull
// conversations written from other devices. Entirely fail-soft and
// deliberately not awaited — the app is fully usable while it runs.
loadSettings()
  .then((s) => {
    // Feedback mode (account panel knob): reveal the per-reply Feedback
    // buttons — turns.js keeps them in the DOM, the body class shows them.
    applyFeedbackMode(s?.feedback_mode === true);
    // Experimental execution sandbox self-heal: the sandbox needs the page to
    // be cross-origin isolated (COEP), which the server only sends when the
    // bash_lite knob is on. If the knob is on but THIS page loaded without
    // isolation (a tab open from before the knob was flipped, or a stale
    // cache), the sandbox silently can't boot. Reload ONCE to fetch the
    // now-isolated shell — guarded by sessionStorage so a server that never
    // sends COEP can't cause a reload loop.
    if (s?.bash_lite_mcp === true && !window.crossOriginIsolated && !sessionStorage.getItem("dr_coep_reload")) {
      sessionStorage.setItem("dr_coep_reload", "1");
      // NOT location.reload(): an installed iOS PWA relaunches from a shell
      // cached ON THE DEVICE that predates the COEP header, and reload() keeps
      // returning that same non-isolated copy (observed live: fresh JS but
      // client_diag.coi=false). Navigate to a FRESH URL instead — a distinct
      // path forces a real network fetch of /rver (which the server sends with
      // COEP), which no on-device or bfcache copy can satisfy.
      location.replace(location.pathname + "?_coep=" + Date.now());
      return;
    }
    if (window.crossOriginIsolated) sessionStorage.removeItem("dr_coep_reload");
    if (!s?.server_history) return;
    syncToServer().catch(() => {});
    pullNewer().catch(() => {});
  })
  .catch(() => {});

// bfcache / PWA-resume self-heal: a page restored from the back-forward cache
// (Safari especially, and any tab navigated away-and-back) keeps its ORIGINAL
// isolation state and does NOT re-run the module-top self-heal above — so a
// tab that was ever shown non-isolated stays non-isolated (and the sandbox
// silently refuses) across every resume. On a bfcache restore, re-check and
// reload to fetch the now-isolated shell. `persisted` is true only for an
// actual bfcache restore, so a normal navigation never triggers this.
window.addEventListener("pageshow", (e) => {
  if (e.persisted && bashLiteOn() && !window.crossOriginIsolated) {
    sessionStorage.removeItem("dr_coep_reload");
    location.replace(location.pathname + "?_coep=" + Date.now());
  }
});

// ---- Research time-target slider ----------------------------------------
// Persisted as seconds; sent as time_budget_s with each request (the server
// plans the spend — src/budget.js). Position mapping in timescale.js.

const budgetSlider = document.getElementById("budget");
const budgetVal = document.getElementById("budgetval");
let budgetS = 60;
const savedBudget = parseInt(localStorage.getItem("budget_s"), 10);
if (savedBudget >= BUDGET_MIN_S && savedBudget <= BUDGET_MAX_S) budgetS = savedBudget;
budgetSlider.value = secondsToPos(budgetS);
const updateBudgetVal = () => { budgetVal.textContent = fmtBudget(budgetS); };
budgetSlider.addEventListener("input", () => {
  budgetS = posToSeconds(Number(budgetSlider.value));
  updateBudgetVal();
  localStorage.setItem("budget_s", String(budgetS));
});
updateBudgetVal();

// ---- Web-search knob ------------------------------------------------------
// Default on. Off = the answer comes from the model only; the time slider
// is moot then, so it dims.

const webSearchBox = document.getElementById("websearch");
webSearchBox.checked = localStorage.getItem("web_search") !== "off";
const syncSearchToggle = () => {
  budgetSlider.disabled = !webSearchBox.checked;
  document.getElementById("composer").classList.toggle("nosearch", !webSearchBox.checked);
};
webSearchBox.addEventListener("change", () => {
  localStorage.setItem("web_search", webSearchBox.checked ? "on" : "off");
  syncSearchToggle();
});
syncSearchToggle();

// The web-search popover opens on a press-and-hold of the spiderweb knob
// itself (the separate 🔍 button was dropped to give the slider its space).
// A held press must NOT also flip the toggle, so the label's click is
// swallowed when the hold timer fired.
const searchPop = document.getElementById("searchpop");
const searchToggle = document.getElementById("searchtoggle");
let holdTimer = 0;
let holdFired = false;
searchToggle.addEventListener("pointerdown", () => {
  holdFired = false;
  holdTimer = setTimeout(() => {
    holdFired = true;
    searchPop.hidden = false;
  }, 500);
});
for (const ev of ["pointerup", "pointerleave", "pointercancel"]) {
  searchToggle.addEventListener(ev, () => clearTimeout(holdTimer));
}
searchToggle.addEventListener("click", (e) => {
  if (holdFired) {
    e.preventDefault();
    e.stopPropagation();
    holdFired = false;
  }
});
searchToggle.addEventListener("contextmenu", (e) => e.preventDefault());
document.addEventListener("click", (e) => {
  if (!searchPop.hidden && !searchPop.contains(e.target)) searchPop.hidden = true;
});

// ---- The ghost: the door to DRC (2026-07-10 directive) ----------------------
// Upper right, directly left of the account button. The ghost symbol's NEW
// MEANING: it TAKES YOU to ghost territory — DRC, "deep research secure",
// the khaki client-side twin at /cure where this server is not in any data
// path at all (your own API keys, browser-local storage, model calls
// straight from the browser). That is a structurally stronger anonymity
// than the old per-conversation incognito toggle ever was: there is
// nothing for the server to log in DRC, ever. The server keeps honoring
// `incognito: true` on /api/chat (the anonymous-chat API promise stands —
// src/chatlog.js), but the ghost UI now points at the real thing. Always
// visible, never locked.

const ghostBtn = document.getElementById("ghostbtn");

function syncGhostState() {
  ghostBtn.hidden = false;
  ghostBtn.disabled = false;
  ghostBtn.title =
    "Ghost mode — DeepResearch.Se/cure: the khaki client-side twin where this server never sees your chats (your own API keys, browser-local storage)";
}

ghostBtn.addEventListener("click", () => {
  // In the installed PWA the webview's status-bar tint is pinned at
  // launch — iOS ignores the destination page's theme-color on in-app
  // navigation (on-device-trace skill, 2026-07-10: the khaki /cure under
  // a still-blue bar). Ghost mode therefore opens in its OWN browsing
  // context from a standalone app; plain navigation everywhere else.
  const standalone =
    /** @type {any} */ (navigator).standalone === true ||
    matchMedia("(display-mode: standalone)").matches;
  if (standalone) window.open("/cure", "_blank");
  else location.assign("/cure");
});
syncGhostState();

// ---- Copy conversation ------------------------------------------------------
// Directly below the account button: copies the whole on-screen conversation
// as plain text — "User: …" / "Assistant: …" turns, with images and appended
// context blocks (documents, project materials) reduced to one-line
// references (stream.js's conversationAsText). Visible only once there is a
// conversation to copy; the icon flips to a checkmark briefly as the
// confirmation (a title attribute alone is invisible on touch devices).

const copyBtn = document.getElementById("copybtn");
const COPY_ICON = copyBtn.innerHTML;
const COPIED_ICON =
  '<svg width="18" height="18" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round" aria-hidden="true"><polyline points="20 6 9 17 4 12"/></svg>';
let copiedTimer = 0;

function syncCopyState() {
  copyBtn.hidden = !conversationStarted();
}

copyBtn.addEventListener("click", async () => {
  const text = conversationAsText();
  if (!text) return;
  try {
    await navigator.clipboard.writeText(text);
  } catch {
    // The async clipboard API can be missing or denied (older webviews) —
    // fall back to the legacy selection path so the button still works.
    const ta = document.createElement("textarea");
    ta.value = text;
    ta.style.position = "fixed";
    ta.style.opacity = "0";
    document.body.appendChild(ta);
    ta.select();
    try { document.execCommand("copy"); } catch { /* nothing left to try */ }
    ta.remove();
  }
  copyBtn.innerHTML = COPIED_ICON;
  copyBtn.classList.add("copied");
  clearTimeout(copiedTimer);
  copiedTimer = setTimeout(() => {
    copyBtn.innerHTML = COPY_ICON;
    copyBtn.classList.remove("copied");
  }, 1500);
});
syncCopyState();

// ---- Header: clear chat / chat history / projects ---------------------------

// The header's "New chat" leaves any project context (a plain chat);
// "New chat in project" (projects-ui.js) passes keepProject so the fresh
// conversation adopts the project it was started from.
function newChat(keepProject = false) {
  if (keepProject !== true) setActiveProject(null);
  clearHistory(); // also resets the (API-level) incognito flag
  clearChatDom();
  syncCopyState();
  input.focus();
}
document.getElementById("clearbtn").addEventListener("click", () => newChat());

// Loading a saved conversation restores the model/time-target/web-search
// settings it was sent with, same as re-opening a real chat-app
// conversation. Shared by the history sidebar and the project panel.
function applyRecordSettings(record) {
  if (record.model) selectModel(record.model);
  if (Number.isFinite(record.budgetS) && record.budgetS >= BUDGET_MIN_S && record.budgetS <= BUDGET_MAX_S) {
    budgetS = record.budgetS;
    budgetSlider.value = secondsToPos(budgetS);
    updateBudgetVal();
    localStorage.setItem("budget_s", String(budgetS));
  }
  webSearchBox.checked = record.webSearch !== false;
  localStorage.setItem("web_search", webSearchBox.checked ? "on" : "off");
  syncSearchToggle();
  syncCopyState(); // …and the loaded conversation is copyable
}

// Encrypted local history sidebar (public/js/history-ui.js + history-store.js).
const historySidebar = initHistorySidebar({
  onNew: newChat,
  onLoad: applyRecordSettings,
});
// Projects (public/js/projects.js + projects-ui.js): collections of chats
// and files with their own cloud knob and retrieval scope.
initProjectsUi({ onNew: newChat, onLoad: applyRecordSettings });
refreshProjects().catch(() => {});
initStream(scrollDown, { onHistoryChange: () => historySidebar.onSaved() });

// The composer's send/stop button toggle. Defined HERE — before the
// pending-answer resume below can call it — because setSendMode reads the
// icon consts; a `const` used before its initializer is a temporal-dead-zone
// crash, and readPending() being true at load would otherwise throw
// "Cannot access 'STOP_ICON' before initialization" and abort the whole
// bootstrap (no handlers attach, the page is dead). While a response streams,
// the same button switches from send (arrow) to stop (square) — never
// disabled, so it stays clickable to interrupt generation. stream.js keeps
// whatever streamed so far as normal context, so the composer is immediately
// ready for a follow-up.
const SEND_ICON = send.innerHTML;
const STOP_ICON =
  '<svg width="14" height="14" viewBox="0 0 24 24" fill="currentColor" aria-hidden="true"><rect x="5" y="5" width="14" height="14" rx="2"/></svg>';
function setSendMode(streaming) {
  send.innerHTML = streaming ? STOP_ICON : SEND_ICON;
  send.classList.toggle("stop", streaming);
  send.setAttribute("aria-label", streaming ? "Stop generating" : "Send");
  send.title = streaming ? "Stop generating" : "Send";
}

// Resume-across-relaunch: if a previous session kicked off research and was
// discarded (a backgrounded PWA iOS reclaimed) before the answer arrived,
// reopen that conversation and poll the server-parked answer back. The
// research finished on the server regardless (src/chat.js's ctx.waitUntil);
// this collects it. Fire-and-forget and fail-soft — never blocks boot. The
// button reflects the streaming state so a tap Stops rather than sends,
// resetting whatever the outcome.
if (readPending()) setSendMode(true);
resumePendingAnswer({ onLoad: applyRecordSettings })
  .catch(() => {})
  .finally(() => setSendMode(false));

// ---- First-visit privacy notice (acknowledgement kept in a cookie) --------

const privacy = document.getElementById("privacy");
if (!/(?:^|;\s*)dr_privacy_ack=1/.test(document.cookie)) privacy.hidden = false;
document.getElementById("privacyok").addEventListener("click", () => {
  document.cookie = "dr_privacy_ack=1; max-age=31536000; path=/; SameSite=Lax; Secure";
  privacy.hidden = true;
});

// ---- Composer ---------------------------------------------------------------

// Single-line composer that grows with content up to the CSS max-height,
// then scrolls internally.
const autogrow = () => {
  input.style.height = "auto";
  input.style.height = input.scrollHeight + "px";
};
input.addEventListener("input", autogrow);

// Introspection mode's mascot (developer mode): as soon as what the user is
// TYPING reads as an ask about this site's own implementation, TIN — the
// titanium robot — slides in with the answer-route picker, so the private
// (own-key, browser-direct) choice can be made BEFORE the question is sent.
// Debounced; a no-op with the knob off. See public/js/introspect-ui.js.
initIntrospectUi({ tier: "drs" });
let introspectTypeTimer = 0;
input.addEventListener("input", () => {
  clearTimeout(introspectTypeTimer);
  introspectTypeTimer = setTimeout(() => {
    if (developerModeOn()) noteIntrospectionText(input.value);
  }, 350);
});

// The image deck's per-image chat panel (imagedeck.js): asking there
// anchors the next message at that image's position (the map_view anchor —
// activity.js setMapViewAnchor) and then goes through the ordinary composer
// path, so quotas, attachments state, streaming controls and history all
// behave exactly like a typed message. (The deck's mini-map needs no key —
// it uses the keyless maps embed; see imagedeck.js keylessMapEmbedUrl.)
onDeckAsk((text, point) => {
  // A PHOTO image anchors as a POV (position + heading — the server's POV
  // path reproduces exactly that frame and renders a fresh Street View
  // there as the new current location); a MAP image anchors as a map view.
  if (point) (point.kind === "map" ? setMapViewAnchor : setPovAnchor)(point);
  input.value = text;
  form.requestSubmit();
});

form.addEventListener("submit", async (e) => {
  e.preventDefault();
  if (isStreaming()) {
    stopGeneration();
    return;
  }
  const text = input.value.trim();
  if (!text && !hasPending()) return;
  if (indexingBusy()) {
    alert("Still indexing an attached document — try again in a moment (the card shows progress).");
    return;
  }
  input.value = "";
  autogrow();
  setSendMode(true);
  const { images, docs } = takeAttachments();
  await sendMessage(text, {
    images,
    docs,
    model: selectedModelId(),
    budgetS,
    webSearch: webSearchBox.checked,
  });
  setSendMode(false);
  syncCopyState();
  input.focus();
});

// Enter inserts a line break — nothing is sent until the arrow is tapped
// (form submit). The input just grows via the autogrow handler above.

// CSS<->JS freshness handshake (the counterpart of app.css's
// --css-version): the boot guard walks and repairs the JS MODULE graph,
// but a device that heuristically cached the STYLESHEET before the
// no-cache asset policy keeps rendering with stale rules forever — on
// 2026-07-08 that made history rows invisible on a real iPhone while
// every module was current. If the marker doesn't match, fetch the
// stylesheet with cache:"reload" (bypasses AND overwrites the cached
// entry) and swap the link so the fresh rules apply without a reload.
const CSS_VERSION = "h25";
try {
  const seen = getComputedStyle(document.documentElement).getPropertyValue("--css-version").trim();
  if (seen !== CSS_VERSION) {
    fetch("/css/app.css", { cache: "reload" })
      .then(() => {
        const link = document.querySelector('link[rel="stylesheet"][href*="app.css"]');
        if (link) link.href = "/css/app.css?v=" + CSS_VERSION;
      })
      .catch(() => {});
  }
} catch {
  // never let the freshness probe break boot
}

// Boot completed: every module linked and every handler above is attached.
// index.html's inline boot guard blocks native form submits until this flag
// exists (see the guard's comment for the stale-module incident it covers).
window.__appReady = true;

// Pending attachments: images (vision models) + documents (pdf/docx/md/txt).
// Owns the attachment state and the card row at the bottom of the composer;
// images are downscaled client-side to fit the provider's ~1 MB body limit,
// documents are parsed to text via docs.js. The send path collects both
// with takeAttachments().

import { docExt, isParsableDoc, parseDocFile } from "./docs.js";
import { extractExif, formatExifSummary } from "./exif.js";
import { currentModel, selectModel, visionFallback } from "./models.js";
import { archiveFile } from "./opfs.js";
import { activeProjectCloudOn } from "./projects.js";
import { indexDocument } from "./rag.js";

const MAX_IMAGES = 4;
const MAX_DOCS = 3;
const MAX_RAW_BYTES = 25 * 1024 * 1024; // sanity cap on input files
// The LLM provider rejects request bodies over ~1 MB, so images are
// downscaled to JPEG data URLs within these budgets before attaching.
const PER_IMAGE_CHARS = 280000;
const TOTAL_IMAGE_CHARS = 700000;
// Documents become extracted text inside the message; the server caps a
// message at 32K chars, so each doc gets a slice of that.
const PER_DOC_CHARS = 9000;
// Documents past the inline budget go through RAG instead of truncation
// (public/js/rag.js): parsed in full up to this ceiling (~ thousands of
// pages), chunked, embedded, and retrieved per question.
const RAG_PARSE_MAX_CHARS = 8_000_000;

let attachBtn;
let cameraBtn;
let pendingBox;
// {kind:"image",name,dataUrl,metadata,metadataSensitive,gps} |
// {kind:"doc",name,ext,text,truncated,metadata,metadataSensitive}
// `metadata` is a formatted summary string (EXIF for images, docProps/
// tracked-changes/comments for docx, Info-dict for pdf) or null — see
// exif.js / docs.js. Included in the outgoing message by stream.js. `gps`
// (images only) is the raw {lat,lon}, sent separately to the server for
// reverse geocoding (src/geocode.js) rather than resolved client-side.
let attachments = [];

const isImageFile = (f) => /^image\//.test(f.type) || /\.(png|jpe?g|webp|gif)$/i.test(f.name);
const images = () => attachments.filter((a) => a.kind === "image");
const docs = () => attachments.filter((a) => a.kind === "doc");

/**
 * One-time wiring from app.js.
 * @param {HTMLElement} attachBtnEl   the paperclip button
 * @param {HTMLInputElement} fileInputEl  hidden file input (any supported type)
 * @param {HTMLElement} pendingBoxEl  the pending-card row container
 * @param {?HTMLElement} cameraBtnEl  the camera button (optional)
 * @param {?HTMLInputElement} cameraInputEl  hidden image-only capture input (optional)
 */
export function initAttachments(attachBtnEl, fileInputEl, pendingBoxEl, cameraBtnEl, cameraInputEl) {
  attachBtn = attachBtnEl;
  cameraBtn = cameraBtnEl;
  pendingBox = pendingBoxEl;
  attachBtn.addEventListener("click", () => fileInputEl.click());
  wireFileInput(fileInputEl, { imagesOnly: false });
  // Camera: an image-only input carrying capture="environment", so a phone
  // opens the camera directly to snap a photo (desktop falls back to an
  // image picker). A snapped photo is just an image attachment — it reuses
  // the exact same downscale / EXIF / vision-fallback path as a picked one.
  if (cameraBtn && cameraInputEl) {
    cameraBtn.addEventListener("click", () => cameraInputEl.click());
    wireFileInput(cameraInputEl, { imagesOnly: true });
  }
  syncAttachState();
}

// Wire one hidden <input type=file> to the ingest path. `imagesOnly` (the
// camera input) rejects non-image captures instead of trying to parse them
// as documents.
function wireFileInput(inputEl, { imagesOnly }) {
  inputEl.addEventListener("change", async () => {
    const files = [...inputEl.files];
    inputEl.value = "";
    for (const file of files) {
      if (file.size > MAX_RAW_BYTES) {
        alert(file.name + " is too large.");
        continue;
      }
      if (isImageFile(file)) await addImageFile(file);
      else if (imagesOnly) alert(file.name + ": not an image.");
      else if (isParsableDoc(file)) await addDocFile(file);
      else alert(file.name + ": unsupported type. Use images or pdf, docx, md, txt.");
    }
  });
}

export function hasPending() {
  return attachments.length > 0;
}

// True while a large document is still being chunked/embedded — the send
// button waits for this (app.js) so a question can't outrun its own
// attachment's index.
export function indexingBusy() {
  return attachments.some((a) => a.indexing);
}

// Archival of originals lives in opfs.js's archiveFile (encrypted except
// RAG-indexed docs). Attachments made inside a project chat inherit that
// project's cloud opt-out — a cloud-off project's attachments never reach
// R2, matching the per-project knob's promise.
function archiveOriginal(fileId, file, { plaintext = false } = {}) {
  return archiveFile(fileId, file, { plaintext, cloud: activeProjectCloudOn() });
}

/**
 * Hand over everything pending for a send and clear the row.
 * @returns {{images: object[], docs: object[]}} the pending attachment
 *   objects (shapes documented at the `attachments` declaration above)
 */
export function takeAttachments() {
  const taken = { images: images(), docs: docs() };
  attachments = [];
  renderPending();
  return taken;
}

// Re-check vision capability after a model change: documents attach on
// every model; images need vision. The button stays fully active either
// way — the vision question is handled per-file.
export function syncAttachState() {
  const vision = !!currentModel()?.vision;
  attachBtn.title = vision
    ? "Attach images or documents (pdf, docx, md, txt)"
    : "Attach documents (pdf, docx, md, txt) — images need a vision model";
  // The camera only ever produces images; on a non-vision model it stays
  // tappable (the snap path offers a one-tap switch) but dims to signal it.
  if (cameraBtn) {
    cameraBtn.title = vision ? "Take a photo" : "Take a photo — needs a vision model";
    cameraBtn.classList.toggle("dim", !vision);
  }
  if (!vision && images().length) {
    attachments = attachments.filter((a) => a.kind !== "image");
    renderPending();
  }
}

// Each attachment renders as a rounded card (thumb or file icon + name)
// with a white circular × in its upper-right corner — on their own line
// at the bottom of the glass pane.
function renderPending() {
  pendingBox.replaceChildren();
  attachments.forEach((a, i) => {
    const card = document.createElement("div");
    card.className = "att-card";
    if (a.kind === "image") {
      const img = document.createElement("img");
      img.src = a.dataUrl;
      img.alt = a.name;
      card.appendChild(img);
    } else {
      const icon = document.createElement("span");
      icon.className = "icon";
      icon.textContent = "📄";
      card.appendChild(icon);
    }
    const meta = document.createElement("div");
    meta.className = "meta";
    const name = document.createElement("div");
    name.className = "name";
    name.textContent = a.name;
    name.title = a.name;
    const sub = document.createElement("div");
    sub.className = "sub";
    if (a.kind === "image") sub.textContent = "image";
    else if (a.indexing) sub.textContent = `${a.ext} · indexing… ${a.progress || 0}%`;
    else if (a.rag) sub.textContent = `${a.ext} · indexed (${a.chunkCount} parts)`;
    else sub.textContent = a.ext + (a.truncated ? " · truncated" : "");
    meta.append(name, sub);
    if (a.metadata) {
      const badge = document.createElement("div");
      badge.className = "att-meta-badge" + (a.metadataSensitive ? " att-meta-sensitive" : "");
      badge.textContent = a.metadataSensitive
        ? (a.kind === "image" ? "📍 location data included" : "⚠️ tracked changes included")
        : "ℹ️ metadata included";
      badge.title = a.metadata; // full extracted summary, visible on hover/tap-hold
      meta.appendChild(badge);
    }
    card.appendChild(meta);
    const rm = document.createElement("button");
    rm.type = "button";
    rm.className = "att-remove";
    rm.textContent = "✕";
    rm.title = "Remove attachment";
    rm.setAttribute("aria-label", "Remove " + a.name);
    rm.addEventListener("click", () => {
      attachments.splice(i, 1);
      renderPending();
    });
    card.appendChild(rm);
    pendingBox.appendChild(card);
  });
}

async function addImageFile(file) {
  if (!currentModel()?.vision) {
    // Explain and offer a one-tap switch to a vision-capable model.
    const alt = visionFallback();
    if (!alt) {
      alert("Images need a vision-capable model and none is available right now.");
      return;
    }
    if (!confirm("Image attachments need a vision-capable model.\nSwitch to " + alt.name + "?")) return;
    selectModel(alt.id);
  }
  if (images().length >= MAX_IMAGES) {
    alert("Max " + MAX_IMAGES + " images per message.");
    return;
  }
  const used = images().reduce((s, a) => s + a.dataUrl.length, 0);
  const budget = Math.min(PER_IMAGE_CHARS, TOTAL_IMAGE_CHARS - used);
  if (budget < 60000) {
    alert("Image size budget for this message is full — send these first.");
    return;
  }
  try {
    // EXIF must come from the ORIGINAL bytes — downscaleImage's canvas
    // re-encode strips all metadata, so this has to happen first (a File
    // can be read more than once; this doesn't consume what downscaleImage
    // reads afterward).
    const exif = await extractImageMetadata(file);
    const dataUrl = await downscaleImage(file, budget);
    if (!dataUrl) {
      alert("Could not compress " + file.name + " enough to send.");
      return;
    }
    const fileId = crypto.randomUUID();
    archiveOriginal(fileId, file); // fire-and-forget — see above
    attachments.push({
      kind: "image",
      name: file.name,
      fileId,
      dataUrl,
      metadata: exif.summary,
      metadataSensitive: exif.hasGps,
      gps: exif.gps, // raw {lat,lon} — sent to the server for reverse geocoding (src/geocode.js)
    });
    renderPending();
  } catch {
    alert("Could not read " + file.name + " as an image.");
  }
}

async function extractImageMetadata(file) {
  try {
    const meta = extractExif(await file.arrayBuffer());
    return { summary: formatExifSummary(meta), hasGps: !!meta?.gps, gps: meta?.gps || null };
  } catch {
    return { summary: null, hasGps: false, gps: null }; // never let metadata extraction block the attach
  }
}

async function addDocFile(file) {
  if (docs().length >= MAX_DOCS) {
    alert("Max " + MAX_DOCS + " documents per message.");
    return;
  }
  try {
    // Parse in full first: whether this goes inline or through RAG depends
    // on how much text actually comes out, not on file size.
    const { text, truncated, metadata, hasTrackedDeletions } = await parseDocFile(file, RAG_PARSE_MAX_CHARS);
    const fileId = crypto.randomUUID();
    // Fire-and-forget archival (see archiveOriginal). Only the RAG path
    // below stores the original readable — an inline doc's original is
    // encrypted like any other file.
    archiveOriginal(fileId, file, { plaintext: text.length > PER_DOC_CHARS });

    if (text.length <= PER_DOC_CHARS) {
      // Small document: the original inline path, unchanged.
      attachments.push({
        kind: "doc",
        name: file.name,
        fileId,
        ext: docExt(file),
        text,
        truncated,
        metadata,
        metadataSensitive: hasTrackedDeletions,
      });
      renderPending();
      return;
    }

    // Large document: index for retrieval instead of truncating to the
    // first ~2 pages. The card shows live indexing progress; sending waits
    // for it (app.js checks indexingBusy). If indexing fails (embedding
    // endpoint down), degrade to exactly the pre-RAG behavior: first
    // PER_DOC_CHARS chars inline, marked truncated.
    const att = {
      kind: "doc",
      name: file.name,
      fileId,
      ext: docExt(file),
      rag: true,
      docId: fileId,
      chars: text.length,
      indexing: true,
      progress: 0,
      metadata,
      metadataSensitive: hasTrackedDeletions,
    };
    attachments.push(att);
    renderPending();
    try {
      const { chunkCount } = await indexDocument(fileId, file.name, text, {
        cloud: activeProjectCloudOn(),
        onProgress: (done, total) => {
          att.progress = Math.round((100 * done) / total);
          renderPending();
        },
      });
      att.chunkCount = chunkCount;
    } catch (err) {
      console.warn("rag: indexing failed, falling back to inline truncation", err);
      att.rag = false;
      att.docId = null;
      att.text = text.slice(0, PER_DOC_CHARS);
      att.truncated = true;
      // Not a RAG doc after all — replace the readable archived copy with
      // an encrypted one (the plaintext exception exists only for indexed
      // documents).
      archiveOriginal(fileId, file);
    } finally {
      att.indexing = false;
      renderPending();
    }
  } catch (err) {
    alert(err?.message || "Could not read " + file.name + ".");
  }
}

// Phone photos are several MB but the LLM provider rejects request bodies
// over ~1 MB — resize to max 1280px and walk JPEG quality (then dimensions)
// down until the data URL fits the budget.
async function downscaleImage(file, budgetChars) {
  const img = await loadImage(file);
  const iw = img.width || img.naturalWidth;
  const ih = img.height || img.naturalHeight;
  if (!iw || !ih) return null;
  let edge = 1280;
  while (edge >= 320) {
    const scale = Math.min(1, edge / Math.max(iw, ih));
    const canvas = document.createElement("canvas");
    canvas.width = Math.max(1, Math.round(iw * scale));
    canvas.height = Math.max(1, Math.round(ih * scale));
    canvas.getContext("2d").drawImage(img, 0, 0, canvas.width, canvas.height);
    for (const q of [0.8, 0.65, 0.5]) {
      const url = canvas.toDataURL("image/jpeg", q);
      if (url.length <= budgetChars) return url;
    }
    edge = Math.round(edge * 0.7);
  }
  return null;
}

function loadImage(file) {
  return createImageBitmap(file).catch(
    () =>
      new Promise((resolve, reject) => {
        const img = new Image();
        img.onload = () => resolve(img);
        img.onerror = reject;
        img.src = URL.createObjectURL(file);
      }),
  );
}

// @ts-check
// The DRS client driver of the experimental bash-lite agent (the
// `bash_lite_mcp` knob). The sandbox is an x86 Linux emulator running in THIS
// browser (public/js/sandbox.js, CheerpX); the shared pure core — parsing,
// normalization, transcript building, and the generic agentic loop — lives in
// public/js/bash-core.js (one source of truth for server, DRS, and DRC alike).
//
// What is DRS-SPECIFIC, and therefore lives here, is where the step decision
// comes from: on DRS the command choice runs server-side (/api/bash/step —
// the keys are there), so this module supplies the fetch-backed step function
// and a runShellLoop wrapper stream.js drives before a /api/chat send:
//
//   1. runShellLoop asks the server (/api/bash/step) what to run next, runs it
//      in the sandbox, and repeats until the model is done or the round cap is
//      hit (the loop mechanics themselves are bash-core.js's runShellLoop).
//   2. The collected transcript (commands + real output) is handed back to
//      stream.js, which attaches it to /api/chat as `shell_transcript` so the
//      answer is written from the real results.
//
// NO function calling — the server's step endpoint returns a plain command
// list parsed from a fenced block. Fully fail-soft: any failure ends the loop
// with whatever was gathered and the answer proceeds normally.

import { MAX_SHELL_ROUNDS, runShellLoop as coreRunShellLoop } from "./bash-core.js";

// Re-export the shared pure API so existing consumers (and tests) can keep
// importing everything bash-lite from this module.
export {
  MAX_SHELL_ROUNDS,
  MAX_COMMANDS_PER_ROUND,
  MAX_OUTPUT_CHARS,
  MAX_COMMAND_CHARS,
  bashIntent,
  parseShellRequest,
  normalizeExecResult,
  formatShellResult,
  buildShellTranscript,
  buildStepUserMessage,
} from "./bash-core.js";

/** @typedef {import('./bash-core.js').ShellRun} ShellRun */

// Ask the server for the next command(s), given the conversation and the runs
// so far. Returns the parsed proposal or a done signal on any failure (the
// loop then stops and the answer proceeds normally). Exported for tests.
/**
 * @param {object[]} messages
 * @param {ShellRun[]} transcript
 * @param {typeof fetch} [fetchImpl]
 * @returns {Promise<{ commands: string[], done: boolean, reasoning: string }>}
 */
export async function fetchShellStep(messages, transcript, fetchImpl = fetch) {
  try {
    const res = await fetchImpl("/api/bash/step", {
      method: "POST",
      headers: { "content-type": "application/json" },
      body: JSON.stringify({ messages, transcript }),
    });
    const data = await res.json().catch(() => null);
    if (!res.ok || !data) return { commands: [], done: true, reasoning: "" };
    return {
      commands: Array.isArray(data.commands) ? data.commands.filter((/** @type {any} */ c) => typeof c === "string") : [],
      done: data.done === true,
      reasoning: typeof data.reasoning === "string" ? data.reasoning : "",
    };
  } catch {
    return { commands: [], done: true, reasoning: "" };
  }
}

/**
 * The DRS-shaped agentic shell loop: bash-core.js's generic runShellLoop with
 * the step decision wired to /api/bash/step. The MODEL decides whether a shell
 * is needed at all (round 1 asks it cold; it returns done for anything that
 * doesn't need one), and `ensureReady` boots the VM lazily only once a command
 * is actually proposed — see the core driver for the full semantics. Never
 * throws.
 * @param {{
 *   messages: object[],
 *   exec: (command: string) => Promise<{ exitCode: number, stdout: string, stderr: string }>,
 *   ensureReady?: () => Promise<boolean>,
 *   onStep?: (info: { round: number, reasoning: string, commands: string[] }) => void,
 *   onResult?: (run: ShellRun) => void,
 *   maxRounds?: number,
 *   fetchImpl?: typeof fetch,
 * }} params
 * @returns {Promise<ShellRun[]>}
 */
export function runShellLoop({ messages, exec, ensureReady, onStep, onResult, maxRounds = MAX_SHELL_ROUNDS, fetchImpl = fetch }) {
  return coreRunShellLoop({
    step: (transcript) => fetchShellStep(messages, transcript, fetchImpl),
    exec,
    ensureReady,
    onStep,
    onResult,
    maxRounds,
  });
}

// Unit tests for the DRS client driver of the bash-lite agent
// (public/js/bash-agent.js): the /api/bash/step fetch wrapper and the
// DRS-shaped runShellLoop over the shared core driver, against a mock step
// endpoint + mock sandbox. The pure logic (intent gate, parser, transcript,
// generic loop) is implemented once in bash-core.js and tested in
// bash-core.test.js; here we also pin the re-export contract (the client
// surface IS the core, not a mirror).
import { test, describe } from "node:test";
import assert from "node:assert/strict";
import * as driver from "./bash-agent.js";
import * as core from "./bash-core.js";
import { fetchShellStep, runShellLoop } from "./bash-agent.js";

// ---- the re-export contract (replaces the old hand-mirror parity suite) ---

describe("DRS driver re-exports the shared core", () => {
  test("every pure export IS the core's implementation (same function object)", () => {
    for (const name of [
      "bashIntent",
      "parseShellRequest",
      "normalizeExecResult",
      "formatShellResult",
      "buildShellTranscript",
      "buildStepUserMessage",
    ]) {
      assert.equal(driver[name], core[name], `${name} must be re-exported, not re-implemented`);
    }
    for (const name of ["MAX_SHELL_ROUNDS", "MAX_COMMANDS_PER_ROUND", "MAX_OUTPUT_CHARS", "MAX_COMMAND_CHARS"]) {
      assert.equal(driver[name], core[name], name);
    }
  });

  test("runShellLoop is the DRS wrapper, not the generic core driver", () => {
    assert.notEqual(driver.runShellLoop, core.runShellLoop);
  });
});

// ---- fetchShellStep ------------------------------------------------------

describe("fetchShellStep", () => {
  test("returns the parsed proposal on success", async () => {
    const fake = async () => ({ ok: true, json: async () => ({ commands: ["echo hi"], done: false, reasoning: "check" }) });
    const r = await fetchShellStep([], [], /** @type {any} */ (fake));
    assert.deepEqual(r.commands, ["echo hi"]);
    assert.equal(r.done, false);
  });

  test("degrades to done on a non-ok response", async () => {
    const fake = async () => ({ ok: false, json: async () => ({ error: "nope" }) });
    const r = await fetchShellStep([], [], /** @type {any} */ (fake));
    assert.equal(r.done, true);
    assert.deepEqual(r.commands, []);
  });

  test("degrades to done when fetch throws", async () => {
    const fake = async () => { throw new Error("network"); };
    const r = await fetchShellStep([], [], /** @type {any} */ (fake));
    assert.equal(r.done, true);
  });

  test("coerces junk fields", async () => {
    const fake = async () => ({ ok: true, json: async () => ({ commands: ["ok", 5, null], done: "yes", reasoning: 3 }) });
    const r = await fetchShellStep([], [], /** @type {any} */ (fake));
    assert.deepEqual(r.commands, ["ok"]);
    assert.equal(r.done, false); // only strict true is done
    assert.equal(r.reasoning, "");
  });

  test("POSTs the conversation and the transcript so far to /api/bash/step", async () => {
    let captured;
    const fake = async (url, init) => {
      captured = { url, body: JSON.parse(init.body) };
      return { ok: true, json: async () => ({ commands: [], done: true, reasoning: "" }) };
    };
    const messages = [{ role: "user", content: "ls /" }];
    const transcript = [{ command: "pwd", exitCode: 0, stdout: "/root\n", stderr: "" }];
    await fetchShellStep(messages, transcript, /** @type {any} */ (fake));
    assert.equal(captured.url, "/api/bash/step");
    assert.deepEqual(captured.body, { messages, transcript });
  });
});

// ---- runShellLoop (DRS shape: step = /api/bash/step) ----------------------

describe("runShellLoop (DRS)", () => {
  test("runs proposed commands, feeds results back, stops when done", async () => {
    // Step 1 proposes two commands, step 2 says done.
    const steps = [
      { ok: true, json: async () => ({ commands: ["echo a", "echo b"], done: false, reasoning: "" }) },
      { ok: true, json: async () => ({ commands: [], done: true, reasoning: "" }) },
    ];
    let i = 0;
    const fetchImpl = async () => steps[i++];
    const execCalls = [];
    const exec = async (cmd) => { execCalls.push(cmd); return { exitCode: 0, stdout: cmd + "-out", stderr: "" }; };

    const transcript = await runShellLoop({ messages: [], exec, fetchImpl: /** @type {any} */ (fetchImpl) });
    assert.deepEqual(execCalls, ["echo a", "echo b"]);
    assert.equal(transcript.length, 2);
    assert.equal(transcript[0].command, "echo a");
    assert.equal(transcript[0].stdout, "echo a-out");
  });

  test("the second round's request carries the first round's transcript", async () => {
    const bodies = [];
    const steps = [
      { ok: true, json: async () => ({ commands: ["echo a"], done: false, reasoning: "" }) },
      { ok: true, json: async () => ({ commands: [], done: true, reasoning: "" }) },
    ];
    let i = 0;
    const fetchImpl = async (_url, init) => { bodies.push(JSON.parse(init.body)); return steps[i++]; };
    const exec = async (cmd) => ({ exitCode: 0, stdout: cmd, stderr: "" });
    await runShellLoop({ messages: [], exec, fetchImpl: /** @type {any} */ (fetchImpl) });
    assert.equal(bodies[0].transcript.length, 0);
    assert.equal(bodies[1].transcript.length, 1);
    assert.equal(bodies[1].transcript[0].command, "echo a");
  });

  test("honors the round cap even if the model never says done", async () => {
    const fetchImpl = async () => ({ ok: true, json: async () => ({ commands: ["echo x"], done: false, reasoning: "" }) });
    const exec = async () => ({ exitCode: 0, stdout: "x", stderr: "" });
    const transcript = await runShellLoop({ messages: [], exec, fetchImpl: /** @type {any} */ (fetchImpl), maxRounds: 3 });
    assert.equal(transcript.length, 3); // one command per round, capped at 3
  });

  test("ensureReady is NOT called when the model needs no shell (lazy boot)", async () => {
    // The model decides: immediate done → the VM must never boot.
    const fetchImpl = async () => ({ ok: true, json: async () => ({ commands: [], done: true, reasoning: "" }) });
    let booted = 0;
    const ensureReady = async () => { booted++; return true; };
    const exec = async () => ({ exitCode: 0, stdout: "", stderr: "" });
    const transcript = await runShellLoop({ messages: [], exec, ensureReady, fetchImpl: /** @type {any} */ (fetchImpl) });
    assert.equal(booted, 0);
    assert.deepEqual(transcript, []);
  });

  test("ensureReady is called ONCE on the first proposed command", async () => {
    const steps = [
      { ok: true, json: async () => ({ commands: ["echo a"], done: false, reasoning: "" }) },
      { ok: true, json: async () => ({ commands: ["echo b"], done: false, reasoning: "" }) },
      { ok: true, json: async () => ({ commands: [], done: true, reasoning: "" }) },
    ];
    let i = 0;
    const fetchImpl = async () => steps[i++];
    let booted = 0;
    const ensureReady = async () => { booted++; return true; };
    const exec = async (cmd) => ({ exitCode: 0, stdout: cmd, stderr: "" });
    const transcript = await runShellLoop({ messages: [], exec, ensureReady, fetchImpl: /** @type {any} */ (fetchImpl) });
    assert.equal(booted, 1); // booted once, not per round
    assert.equal(transcript.length, 2);
  });

  test("a failed boot stops the loop with an empty transcript", async () => {
    const fetchImpl = async () => ({ ok: true, json: async () => ({ commands: ["echo a"], done: false, reasoning: "" }) });
    const ensureReady = async () => false; // can't boot
    let execCalls = 0;
    const exec = async () => { execCalls++; return { exitCode: 0, stdout: "", stderr: "" }; };
    const transcript = await runShellLoop({ messages: [], exec, ensureReady, fetchImpl: /** @type {any} */ (fetchImpl) });
    assert.equal(execCalls, 0);
    assert.deepEqual(transcript, []);
  });
});

// @ts-check
// The bash-lite agent's SHARED PURE CORE — the single source of truth for the
// experimental in-browser Linux execution sandbox (the `bash_lite_mcp` knob on
// DRS, `bashLite` on DRC).
//
// The sandbox is a JavaScript x86 Linux emulator (CheerpX) that boots IN THE
// BROWSER (public/js/sandbox.js) — the server never runs a shell — so the
// agentic loop is client-orchestrated. The model proposes shell commands in a
// plain fenced ```bash block (a TEXT convention — NO function calling,
// invariant 1, so this works on any model in the catalog), the browser sandbox
// runs them, the output feeds back, and it loops until the model is done. The
// collected transcript then rides into synthesis as one more labeled research-
// context block, exactly like an enrichment (src/enrichment.js).
//
// WHY THIS FILE LIVES UNDER public/js/: the exact same deterministic logic is
// needed in THREE places — the Worker (src/bash-api.js parses the model's
// step; src/pipeline.js builds the synthesis block), the DRS client
// (public/js/bash-agent.js drives the loop against /api/bash/step), and the
// DRC client (public/js/drc-research.js drives the loop against the user's own
// provider). A browser can only import modules the Worker actually serves
// (public/), while the Worker's bundler (wrangler/esbuild) can import from any
// repo path — so the shared module must live here, and src/bash-agent.js is a
// thin re-export façade over it. Until 2026-07-11 the server and client each
// kept a hand-mirrored copy with "keep in lock-step" comments and a parity
// test; this module replaces that mirror discipline with one implementation.
// Do NOT reintroduce a copy — import (or re-export) this file instead.
//
// What lives here (pure, I/O-free, Node-tested in bash-core.test.js):
//   - bashIntent:            does a message LOOK like it wants a shell? (EN+SV)
//   - parseShellRequest:     read the model's fenced-block command proposal
//   - normalizeExecResult:   clamp an untrusted {exitCode,stdout,stderr}
//   - formatShellResult:     render one executed command back for the next turn
//   - buildShellTranscript:  the labeled context block synthesis reads
//   - buildStepUserMessage:  the per-round user message both step callers send
//   - runShellLoop:          the generic agentic driver (step fn injected)
//
// The whole capability is fail-soft: a missed intent, an empty proposal, a
// failing step call, or a sandbox that never boots all degrade to a normal
// answer.

// Hard caps — the loop and every rendered chunk are bounded so a runaway
// command (or a hostile model) cannot blow the context window or spin
// forever. Shared by both tiers so DRS and DRC agree on the limits.
export const MAX_SHELL_ROUNDS = 6; // agentic iterations before we synthesize regardless
export const MAX_COMMANDS_PER_ROUND = 6; // commands accepted from one model turn
export const MAX_OUTPUT_CHARS = 4000; // per-command stdout/stderr kept in the transcript
export const MAX_COMMAND_CHARS = 2000; // a single command line is clamped to this

// ---- intent gate ----------------------------------------------------------

// Does the latest user message LOOK like it asks to run a shell / execute code
// / compute something in the sandbox? A non-authoritative HEURISTIC — NOT the
// execution gate. The MODEL decides whether a shell is actually needed (it is
// asked cold each turn via bashAgentPrompt and returns SHELL_DONE for anything
// that doesn't need one), because a regex misses obvious asks like "list
// files" or "run la -la" (the production defect, chat_logs #200/#201). This is
// kept as a cheap classifier for callers that want a quick signal without a
// model call; deterministic and typo-tolerant with FULL Swedish parity.
// Exported for unit tests.
//
// The gate matches when the message contains an execution VERB/NOUN that is
// about running commands or code — not the many innocent senses of "run"
// ("run a marathon", "in the long run"), which is why "run" alone never
// matches; it needs a shell/command/code/script object or an explicit
// sandbox/terminal reference.
/**
 * @param {string} text the latest user message
 * @returns {boolean}
 */
export function bashIntent(text) {
  const t = String(text || "").toLowerCase();
  if (!t.trim()) return false;
  return SHELL_PATTERNS.some((re) => re.test(t));
}

// The intent patterns. English and Swedish are kept side by side, one pair
// per concept, so parity is auditable at a glance (and enforced by the
// parity unit test). Typos mirror the English typo sets per invariant 6.
const SHELL_PATTERNS = [
  // "shell" / "bash" / "command line" / "terminal" — the tool itself.
  // EN: shell, bash, zsh, command line/prompt, terminal, console
  /\b(shell|bash|zsh|command[- ]?line|command[- ]?prompt|terminal|console)\b/,
  // SV: skal(et), skal-kommando, kommandorad(en), terminal(en), konsol(en)
  /\b(skal(et)?|kommando ?rad(en)?|kommandotolk(en)?|terminal(en)?|konsol(en)?)\b/,

  // run / execute + a command/code/script/computation object.
  // EN: run/execute this command|code|script|program|snippet|calculation
  /\b(run|execute|exec)\b[^.\n]{0,40}\b(command|commands|code|script|scripts|program|programs|snippet|snippets|binary|binaries|calculation|calculations|computation|computations)\b/,
  // EN: run/execute the command|code|... (command first is covered above; the
  // reverse "the code, run it" order):
  /\b(command|code|script|program|snippet|calculation|computation)\b[^.\n]{0,20}\b(run|execute|exec)\b/,
  // SV: kör/köra/exekvera det här kommandot|koden|skriptet|programmet|beräkningen
  /\b(kör|köra|exekvera|exekvering)\b[^.\n]{0,40}\b(kommando(t|n)?|kod(en)?|skript(et|en)?|program(met)?|snutt(en)?|beräkning(en|ar|arna)?)\b/,
  // SV: reverse order "koden, kör den"
  /\b(kommando(t|n)?|kod(en)?|skript(et|en)?|program(met)?|beräkning(en)?)\b[^.\n]{0,20}\b(kör|köra|exekvera)\b/,

  // explicit "in the sandbox / in a linux vm / on the emulator".
  // EN: in the sandbox / in a VM / linux vm / emulator
  /\bin (the |a |your )?(sandbox|linux(-| )?(vm|box)?|vm|emulator)\b/,
  // SV: i sandlådan / i en linux-vm / i emulatorn
  /\bi (en |din )?(sandlåd(a|an)|linux(-| )?(vm|burk)?|vm|emulator(n)?)\b/,

  // compute / calculate + (this|the) — a request to actually work a number
  // out rather than explain it. Kept explicit (needs a "this/the/for me"
  // object) so "how do you calculate X" (a knowledge question) doesn't match.
  // EN: compute/calculate this/the …, work this out, crunch the numbers
  /\b(compute|calculate|crunch|evaluate)\b[^.\n]{0,30}\b(this|the|these|for me)\b/,
  // SV: beräkna/räkna ut det här, kör beräkningen
  /\b(beräkna|räkna ut|räkna ?ut|evaluera)\b[^.\n]{0,30}\b(det|den|det här|dessa|åt mig)\b/,

  // pipe/grep/awk/sed and friends spelled out as a request ("pipe this
  // through jq", "grep the file for …") — a strong shell signal in any
  // language. Command names are language-neutral, so this one pattern serves
  // both; the surrounding verb parity is covered by the rules above.
  /\b(pipe (this|it|the)|grep (through|the|for)|use (jq|awk|sed|grep) (on|to|for))\b/,
];

// ---- the model's command proposal -----------------------------------------

/**
 * One executed command and what the sandbox returned.
 * @typedef {{ command: string, exitCode: number, stdout: string, stderr: string }} ShellRun
 */

/**
 * The model's parsed step: the commands to run this round, whether it has
 * declared itself done, and its plain-language reasoning (the prose outside
 * the code block — surfaced in the activity UI so the run is legible).
 * @typedef {{ commands: string[], done: boolean, reasoning: string }} ShellProposal
 */

// Parse one agent turn. The convention (see prompts.js bashAgentPrompt): the
// model writes brief reasoning, then EITHER a fenced ```bash (or ```sh /
// ```shell / ```console) block whose non-comment lines are the commands to
// run, OR — when it has everything it needs — the literal marker SHELL_DONE
// and no block. Lenient and never throws: no block AND no explicit request
// means done (there's nothing left to run), which is the natural terminator.
//
// Commands are split on newlines (one command per line; a multi-line command
// can still use trailing `\` continuations, joined here), comments and blanks
// dropped, each clamped to MAX_COMMAND_CHARS, and the batch capped at
// MAX_COMMANDS_PER_ROUND. Exported for unit tests.
/**
 * @param {string} text the model's raw completion for this step
 * @returns {ShellProposal}
 */
export function parseShellRequest(text) {
  const raw = String(text || "");
  const doneMarker = /(^|\s)(SHELL_DONE|\[done\]|<<done>>)(\s|$)/i.test(raw);

  const block = extractFirstCodeBlock(raw);
  const reasoning = reasoningText(raw, block);

  if (!block) {
    // No command block: the model is done (explicit marker or simply nothing
    // more to run). Either way the loop terminates.
    return { commands: [], done: true, reasoning };
  }

  const commands = splitCommands(block.body);
  if (!commands.length) {
    // A block with no runnable lines is treated as done rather than looping
    // on an empty request.
    return { commands: [], done: true, reasoning };
  }
  // A done marker alongside a block is contradictory; honor the block (run
  // these, then the next turn decides) unless the block is empty.
  return { commands, done: doneMarker && !commands.length, reasoning };
}

// Pull the first fenced code block whose info-string names a shell language
// (bash/sh/shell/console/zsh) or is bare (```). Returns {lang, body} or null.
/**
 * @param {string} text
 * @returns {{ lang: string, body: string } | null}
 */
function extractFirstCodeBlock(text) {
  const fence = /```([^\n`]*)\n([\s\S]*?)```/g;
  let m;
  while ((m = fence.exec(text))) {
    const lang = (m[1] || "").trim().toLowerCase();
    if (lang === "" || SHELL_LANGS.has(lang)) {
      return { lang, body: m[2] || "" };
    }
  }
  return null;
}

const SHELL_LANGS = new Set(["bash", "sh", "shell", "console", "zsh", "shellsession"]);

// The prose outside the (first) code block — the model's reasoning, trimmed
// and collapsed to one line for the activity UI. Empty when there's nothing.
/**
 * @param {string} raw
 * @param {{ body: string } | null} block
 * @returns {string}
 */
function reasoningText(raw, block) {
  let prose = raw;
  if (block) prose = raw.replace(/```[^\n`]*\n[\s\S]*?```/g, " ");
  return prose
    .replace(/(^|\s)(SHELL_DONE|\[done\]|<<done>>)(\s|$)/gi, " ")
    .replace(/\s+/g, " ")
    .trim()
    .slice(0, 400);
}

// Split a shell block into individual command lines: join `\`-continuations,
// drop comments (# …) and blank lines, clamp each, cap the batch.
/**
 * @param {string} body
 * @returns {string[]}
 */
function splitCommands(body) {
  const joined = String(body || "").replace(/\\\n/g, " ");
  const out = [];
  for (const line of joined.split("\n")) {
    const cmd = line.trim();
    if (!cmd) continue;
    if (cmd.startsWith("#")) continue;
    out.push(cmd.slice(0, MAX_COMMAND_CHARS));
    if (out.length >= MAX_COMMANDS_PER_ROUND) break;
  }
  return out;
}

// ---- execution results ----------------------------------------------------

// Coerce an untrusted exec result (it comes back from the browser sandbox
// bridge, or — in DRS — round-trips through the client) into a clean ShellRun:
// numeric exit code, string streams clamped to MAX_OUTPUT_CHARS with a
// truncation marker. Never throws. Exported for unit tests.
/**
 * @param {string} command
 * @param {any} result the raw {exitCode,stdout,stderr} from the sandbox
 * @returns {ShellRun}
 */
export function normalizeExecResult(command, result) {
  const r = result && typeof result === "object" ? result : {};
  const exitCode = Number.isFinite(Number(r.exitCode)) ? Math.trunc(Number(r.exitCode)) : 1;
  return {
    command: String(command || "").slice(0, MAX_COMMAND_CHARS),
    exitCode,
    stdout: clampOutput(r.stdout),
    stderr: clampOutput(r.stderr),
  };
}

/**
 * @param {any} s
 * @returns {string}
 */
function clampOutput(s) {
  const str = typeof s === "string" ? s : s == null ? "" : String(s);
  if (str.length <= MAX_OUTPUT_CHARS) return str;
  return str.slice(0, MAX_OUTPUT_CHARS) + `\n…[truncated ${str.length - MAX_OUTPUT_CHARS} chars]`;
}

// Render one executed command + result back into the transcript the model
// sees on the next agent turn (and that buildShellTranscript folds into the
// synthesis context). Deterministic formatting so both tiers read identically.
/**
 * @param {ShellRun} run
 * @returns {string}
 */
export function formatShellResult(run) {
  const r = normalizeExecResult(run.command, run);
  const parts = [`$ ${r.command}`, `exit: ${r.exitCode}`];
  if (r.stdout.trim()) parts.push(`stdout:\n${r.stdout.replace(/\s+$/, "")}`);
  if (r.stderr.trim()) parts.push(`stderr:\n${r.stderr.replace(/\s+$/, "")}`);
  if (!r.stdout.trim() && !r.stderr.trim()) parts.push("(no output)");
  return parts.join("\n");
}

// ---- the transcript block synthesis reads ---------------------------------

// The labeled context block appended to the synthesis input (pipeline.js
// shellSection / drc-research.js), mirroring the enrichment-block convention:
// a titled block the answer prompt is told it may use and cite as "the
// sandbox". Empty string when no command ran — so the synthesis input is
// byte-identical to a run without the sandbox. Exported for unit tests.
/**
 * @param {ShellRun[]} runs
 * @returns {string}
 */
export function buildShellTranscript(runs) {
  const list = Array.isArray(runs) ? runs.filter((r) => r && r.command) : [];
  if (!list.length) return "";
  const body = list.map((r) => formatShellResult(r)).join("\n\n");
  return (
    "Linux sandbox session (commands the assistant ran in the in-browser " +
    "execution sandbox and their real output — treat this as ground truth " +
    "you produced, and refer to it as \"the sandbox\" when you use it):\n" +
    body
  );
}

// ---- the per-round step message --------------------------------------------

// The USER message for one agent-step model call, shared by both step callers
// (src/bash-api.js on DRS, drc-research.js's provider call on DRC) so the two
// tiers ask the model the exact same question: the task, the conversation
// context, and — after the first round — the transcript so far. The system
// half stays tier-specific (prompts.js bashAgentPrompt / drcBashAgentPrompt).
/**
 * @param {{ task: string, context: string, priorBlock?: string }} params
 * @returns {string}
 */
export function buildStepUserMessage({ task, context, priorBlock = "" }) {
  return (
    `Task (latest user message):\n${task}\n\nConversation context:\n${context}\n\n` +
    (priorBlock
      ? `${priorBlock}\n\nDecide the next command(s), or reply SHELL_DONE if the answer has everything it needs.`
      : "No commands have run yet. Decide the first command(s) to run, or reply SHELL_DONE if a shell is not actually needed.")
  );
}

// ---- the agentic loop driver ------------------------------------------------

/**
 * Run the agentic shell loop: repeatedly ask the MODEL what to run next (via
 * the injected `step`) and execute it in the sandbox, until the model is done
 * or the round cap is hit. Generic over WHO answers the step — DRS injects a
 * /api/bash/step fetch (public/js/bash-agent.js), DRC injects a direct call to
 * the user's own provider (drc-research.js) — so both tiers share one driver.
 *
 * The MODEL decides whether a shell is needed at all — round 1 asks it cold,
 * and it returns done immediately for anything that doesn't need a shell, so
 * this is safe to run for every message when the knob is on (no brittle
 * client-side keyword gate). `ensureReady` boots the VM LAZILY — it's called
 * only once the model actually proposes a command, so a message that needs no
 * shell never boots the (expensive) VM. Never throws — a failing step or exec
 * ends the loop with whatever was gathered so far.
 * @param {{
 *   step: (transcript: ShellRun[], round: number) => Promise<ShellProposal>,
 *   exec: (command: string) => Promise<{ exitCode: number, stdout: string, stderr: string }>,
 *   ensureReady?: () => Promise<boolean>,
 *   onStep?: (info: { round: number, reasoning: string, commands: string[] }) => void,
 *   onResult?: (run: ShellRun) => void,
 *   maxRounds?: number,
 * }} params
 * @returns {Promise<ShellRun[]>}
 */
export async function runShellLoop({ step, exec, ensureReady, onStep, onResult, maxRounds = MAX_SHELL_ROUNDS }) {
  /** @type {ShellRun[]} */
  const transcript = [];
  // null = not yet booted; true/false = boot outcome. No ensureReady → ready.
  let ready = ensureReady ? null : true;
  for (let round = 1; round <= maxRounds; round++) {
    /** @type {ShellProposal} */
    let proposal;
    try {
      proposal = await step(transcript, round);
    } catch {
      break; // a failing step ends the loop with what we have (fail-soft)
    }
    const commands = Array.isArray(proposal?.commands)
      ? proposal.commands.filter((c) => typeof c === "string" && c)
      : [];
    if (proposal?.done === true || !commands.length) break;
    // The model wants to run something — boot the VM now (once). If it can't
    // boot, stop with whatever we have rather than looping on failures.
    if (ready === null && ensureReady) ready = await ensureReady();
    if (!ready) break;
    if (onStep) onStep({ round, reasoning: typeof proposal.reasoning === "string" ? proposal.reasoning : "", commands });
    for (const command of commands) {
      let res;
      try {
        res = await exec(command);
      } catch (err) {
        res = { exitCode: 1, stdout: "", stderr: String((/** @type {any} */ (err))?.message || err) };
      }
      const run = {
        command,
        exitCode: Number.isFinite(Number(res?.exitCode)) ? Math.trunc(Number(res.exitCode)) : 1,
        stdout: typeof res?.stdout === "string" ? res.stdout : "",
        stderr: typeof res?.stderr === "string" ? res.stderr : "",
      };
      transcript.push(run);
      if (onResult) onResult(run);
    }
  }
  return transcript;
}

// Unit tests for the bash-lite agent's shared pure core (bash-core.js) — the
// ONE implementation behind the server façade (src/bash-agent.js), the DRS
