// ---- runShellLoop (the generic driver, step injected) ----------------------
// The DRS shape (step = /api/bash/step fetch) is covered in
// bash-agent.test.js; these exercise the raw driver the way DRC drives it.

describe("runShellLoop (generic driver)", () => {
  test("runs proposed commands, feeds the transcript back to the step, stops when done", async () => {
    const seenTranscripts = [];
    const steps = [
      { commands: ["echo a", "echo b"], done: false, reasoning: "start" },
      { commands: [], done: true, reasoning: "" },
    ];
    let i = 0;
    const step = async (transcript) => {
      seenTranscripts.push(transcript.length);
      return steps[i++];
    };
    const exec = async (cmd) => ({ exitCode: 0, stdout: cmd + "-out", stderr: "" });
    const transcript = await runShellLoop({ step, exec });
    assert.deepEqual(seenTranscripts, [0, 2]); // round 2 sees both runs
    assert.equal(transcript.length, 2);
    assert.equal(transcript[0].stdout, "echo a-out");
  });

  test("a THROWING step ends the loop with what was gathered (fail-soft)", async () => {
    const steps = [
      async () => ({ commands: ["echo a"], done: false, reasoning: "" }),
      async () => { throw new Error("provider down"); },
    ];
    let i = 0;
    const transcript = await runShellLoop({
      step: () => steps[i++](),
      exec: async () => ({ exitCode: 0, stdout: "a", stderr: "" }),
    });
    assert.equal(transcript.length, 1);
  });

  test("honors the round cap even if the model never says done", async () => {
    const step = async () => ({ commands: ["echo x"], done: false, reasoning: "" });
    const exec = async () => ({ exitCode: 0, stdout: "x", stderr: "" });
    const transcript = await runShellLoop({ step, exec, maxRounds: 3 });
    assert.equal(transcript.length, 3); // one command per round, capped at 3
  });

  test("a throwing exec becomes a failed run, loop continues", async () => {
    const steps = [
      { commands: ["boom"], done: false, reasoning: "" },
      { commands: [], done: true, reasoning: "" },
    ];
    let i = 0;
    const transcript = await runShellLoop({
      step: async () => steps[i++],
      exec: async () => { throw new Error("exec failed"); },
    });
    assert.equal(transcript.length, 1);
    assert.equal(transcript[0].exitCode, 1);
    assert.match(transcript[0].stderr, /exec failed/);
  });

  test("ensureReady is NOT called when the model needs no shell (lazy boot)", async () => {
    let booted = 0;
    const transcript = await runShellLoop({
      step: async () => ({ commands: [], done: true, reasoning: "" }),
      exec: async () => ({ exitCode: 0, stdout: "", stderr: "" }),
      ensureReady: async () => { booted++; return true; },
    });
    assert.equal(booted, 0);
    assert.deepEqual(transcript, []);
  });

  test("ensureReady is called ONCE on the first proposed command", async () => {
    const steps = [
      { commands: ["echo a"], done: false, reasoning: "" },
      { commands: ["echo b"], done: false, reasoning: "" },
      { commands: [], done: true, reasoning: "" },
    ];
    let i = 0;
    let booted = 0;
    const transcript = await runShellLoop({
      step: async () => steps[i++],
      exec: async (cmd) => ({ exitCode: 0, stdout: cmd, stderr: "" }),
      ensureReady: async () => { booted++; return true; },
    });
    assert.equal(booted, 1); // booted once, not per round
    assert.equal(transcript.length, 2);
  });

  test("a failed boot stops the loop with an empty transcript", async () => {
    let execCalls = 0;
    const transcript = await runShellLoop({
      step: async () => ({ commands: ["echo a"], done: false, reasoning: "" }),
      exec: async () => { execCalls++; return { exitCode: 0, stdout: "", stderr: "" }; },
      ensureReady: async () => false, // can't boot
    });
    assert.equal(execCalls, 0);
    assert.deepEqual(transcript, []);
  });

  test("onStep and onResult fire with the round's commands and each run", async () => {
    const steps = [
      { commands: ["echo a", "echo b"], done: false, reasoning: "why" },
      { commands: [], done: true, reasoning: "" },
    ];
    let i = 0;
    const stepEvents = [];
    const results = [];
    await runShellLoop({
      step: async () => steps[i++],
      exec: async (cmd) => ({ exitCode: 0, stdout: cmd, stderr: "" }),
      onStep: (info) => stepEvents.push(info),
      onResult: (run) => results.push(run.command),
    });
    assert.equal(stepEvents.length, 1);
    assert.equal(stepEvents[0].round, 1);
    assert.equal(stepEvents[0].reasoning, "why");
    assert.deepEqual(stepEvents[0].commands, ["echo a", "echo b"]);
    assert.deepEqual(results, ["echo a", "echo b"]);
  });

  test("junk proposals (non-string commands, missing fields) never throw", async () => {
    const steps = [
      { commands: ["ok", 5, null, ""], done: false, reasoning: 3 },
      /** @type {any} */ (null),
    ];
    let i = 0;
    const transcript = await runShellLoop({
      step: async () => steps[i++],
      exec: async (cmd) => ({ exitCode: 0, stdout: cmd, stderr: "" }),
    });
    assert.deepEqual(transcript.map((r) => r.command), ["ok"]);
  });
});

// @ts-check
// Project-chat RAG: conversations INSIDE a project are indexed into the
// same retrieval store as the project's documents and notes (rag.js), so
// an answer worked out in one project chat is retrievable context in every
// other chat of that project. The consequence — stated plainly because it
// is a deliberate storage-rule change — is that project chats follow the
// SAME readable-when-indexed exception as RAG-indexed documents: their
// records rest plaintext in both locations (history-store.js /
// src/storage.js), since the index already holds their text readable.
// Non-project chats are neither indexed nor affected — they keep the
// original encrypted-always posture.
//
// The index grows WITH the conversation: stream.js calls indexChatTurns
// after every persisted exchange, and only the not-yet-indexed messages
// are chunked and embedded (rag.js's appendToDoc; the doc row's `srcMsgs`
// counter remembers how far indexing got, so a failed embed simply retries
// on the next turn). One conversation = one doc, id `chat-<convId>`, named
// by the conversation's title.
//
// The pure helpers (chatDocId/chatConvId, messageIndexText, chatIndexText,
// and the sibling-chat scope picker) are unit-tested in Node — keep this
// module import-safe outside a browser, same as rag.js.

import { appendToDoc, deleteDoc, getDoc } from "./rag.js";
import { serverHistoryOn } from "./settings.js";

const CHAT_DOC_PREFIX = "chat-";

/**
 * One conversation message as history-store.js persists it. Multimodal
 * user turns carry an array of parts; only the text parts are indexable.
 * @typedef {{role?: string, content?: string | Array<{type?: string, text?: string}>}} ChatMessage
 */

// Retrieval scope cap: the server's /api/rag/query accepts at most 20
// docIds, and project docs + this conversation's own attachments come
// first — sibling chats fill what's left, newest first.
export const MAX_SIBLING_CHATS = 10;

// ---- pure helpers (unit-tested) ---------------------------------------------

/**
 * @param {string} convId
 * @returns {string}
 */
export function chatDocId(convId) {
  return CHAT_DOC_PREFIX + convId;
}

/**
 * The conversation id behind a chat doc id, or null for any other doc.
 * @param {unknown} docId
 * @returns {string | null}
 */
export function chatConvId(docId) {
  return typeof docId === "string" && docId.startsWith(CHAT_DOC_PREFIX)
    ? docId.slice(CHAT_DOC_PREFIX.length)
    : null;
}

// Context blocks the client appends to the outgoing user message
// (message-content.js / project-context.js). They are stripped before
// indexing: their sources (documents, project materials, other chats,
// image metadata) are already indexed or carried elsewhere — re-indexing
// retrieval excerpts through the chat would echo them back into the index
// as duplicate, second-hand chunks.
const APPENDED_BLOCK = /\n\n--- (Attached document:|Project:|Related project chat:|Image metadata:)/;

/**
 * The indexable text of one message: the text itself for assistant turns,
 * the user's actual question (appended context blocks stripped, text parts
 * of multimodal content joined) for user turns.
 * @param {ChatMessage | null | undefined} message
 * @returns {string}
 */
export function messageIndexText(message) {
  const c = message?.content;
  let text =
    typeof c === "string"
      ? c
      : (Array.isArray(c) ? c : [])
          .filter((p) => p?.type === "text")
          .map((p) => p.text || "")
          .join("\n");
  const cut = text.search(APPENDED_BLOCK);
  if (cut >= 0) text = text.slice(0, cut);
  return text.trim();
}

/**
 * The indexable text of messages[fromMsg..]: labeled turns, empty ones
 * skipped. The title leads the very first increment (fromMsg 0) so
 * retrieval can match on it — the same convention as project notes
 * (project-context.js's noteToText).
 * @param {ChatMessage[] | null | undefined} messages
 * @param {number} [fromMsg]
 * @param {string} [title]
 * @returns {string}
 */
export function chatIndexText(messages, fromMsg = 0, title = "") {
  const parts = [];
  for (const m of (messages || []).slice(fromMsg)) {
    const text = messageIndexText(m);
    if (!text) continue;
    parts.push((m?.role === "assistant" ? "Assistant:" : "User:") + "\n" + text);
  }
  if (!parts.length) return "";
  const head = fromMsg === 0 && String(title || "").trim() ? "Conversation: " + String(title).trim() + "\n\n" : "";
  return head + parts.join("\n\n");
}

/**
 * The sibling chats a project conversation retrieves across: every OTHER
 * conversation of the same project (the current one is already in context),
 * newest first, capped. `conversations` is listConversations' output
 * (already newest-first).
 * @param {Array<{id: string, title?: string, projectId?: string, updatedAt?: number}> | null | undefined} conversations
 * @param {string | null | undefined} projectId
 * @param {string | null | undefined} currentConvId
 * @returns {Array<{id: string, name: string}>}
 */
export function siblingChatDocs(conversations, projectId, currentConvId) {
  if (!projectId) return [];
  return (conversations || [])
    .filter((c) => c.projectId === projectId && c.id !== currentConvId)
    .slice(0, MAX_SIBLING_CHATS)
    .map((c) => ({ id: chatDocId(c.id), name: c.title || "Untitled chat" }));
}

// ---- index maintenance (stream.js / projects.js) -----------------------------

/**
 * Index whatever this conversation has that isn't indexed yet. Called after
 * every persisted exchange; fail-soft by contract of the caller (a thrown
 * error just means the same turns are retried on the next persist, because
 * srcMsgs only advances on success).
 * @param {{convId?: string, title?: string, messages?: ChatMessage[], cloud?: boolean}} args
 * @returns {Promise<{chunkCount: number, appended: number} | null>} null when there was nothing new to index
 */
export async function indexChatTurns({ convId, title, messages, cloud = true }) {
  if (!convId || !messages?.length) return null;
  const docId = chatDocId(convId);
  const doc = await getDoc(docId);
  const fromMsg = doc?.srcMsgs || 0;
  if (messages.length <= fromMsg) return null; // nothing new since the last index pass
  const text = chatIndexText(messages, fromMsg, title);
  if (!text) return null;
  return appendToDoc(docId, String(title || "").trim() || "Untitled chat", text, {
    cloud,
    meta: { kind: "chat", srcMsgs: messages.length },
  });
}

/**
 * Remove a conversation's slice of the index, both rests — the chat-doc
 * counterpart of projects.js's removeFileFromProject cleanup. Harmless for
 * a conversation that was never indexed.
 * @param {string} convId
 */
export async function deleteChatIndex(convId) {
  const docId = chatDocId(convId);
  await deleteDoc(docId).catch(() => {});
  if (serverHistoryOn()) {
    fetch("/api/rag/docs/" + encodeURIComponent(docId), { method: "DELETE" }).catch(() => {});
  }
}

// Node tests for chat-rag.js's pure helpers: chat doc ids, block-stripping index text, the sibling-chat scope picker.
import { test } from "node:test";
import assert from "node:assert/strict";

import {
  MAX_SIBLING_CHATS,
  chatConvId,
  chatDocId,
  chatIndexText,
  messageIndexText,
  siblingChatDocs,
} from "./chat-rag.js";

test("chatDocId/chatConvId round-trip; chatConvId rejects non-chat ids", () => {
  const convId = "0f3b1c9a-1234-4abc-9def-0123456789ab";
  assert.equal(chatDocId(convId), "chat-" + convId);
  assert.equal(chatConvId(chatDocId(convId)), convId);
  assert.equal(chatConvId("some-file-uuid"), null);
  assert.equal(chatConvId(""), null);
  assert.equal(chatConvId(undefined), null);
});

test("messageIndexText reads string and multimodal content", () => {
  assert.equal(messageIndexText({ role: "user", content: "  plain question  " }), "plain question");
  assert.equal(
    messageIndexText({
      role: "user",
      content: [
        { type: "image_url", image_url: { url: "data:image/jpeg;base64,AA" } },
        { type: "text", text: "what is in this photo?" },
      ],
    }),
    "what is in this photo?",
  );
  assert.equal(messageIndexText({ role: "user", content: [] }), "");
  assert.equal(messageIndexText(null), "");
});

test("messageIndexText strips every appended context-block family", () => {
  const blocks = [
    "\n\n--- Attached document: report.pdf ---\nsecret doc text\n--- End of document ---",
    "\n\n--- Project: Alpha ---\ninventory\n--- End of project ---",
    "\n\n--- Related project chat: Earlier chat (an earlier conversation in this project, indexed for retrieval) ---\nexcerpt\n--- End of chat excerpts ---",
    "\n\n--- Image metadata: photo.jpg ---\nGPS: 1, 2\n--- End of image metadata ---",
  ];
  for (const block of blocks) {
    const out = messageIndexText({ role: "user", content: "the real question" + block });
    assert.equal(out, "the real question", "block not stripped: " + block.slice(0, 40));
  }
  // Everything after the FIRST block goes, even when several follow.
  const out = messageIndexText({ role: "user", content: "q" + blocks[1] + blocks[0] });
  assert.equal(out, "q");
});

test("chatIndexText labels turns and leads with the title on the first increment only", () => {
  const messages = [
    { role: "user", content: "first question" },
    { role: "assistant", content: "first answer" },
    { role: "user", content: "follow-up" },
    { role: "assistant", content: "second answer" },
  ];
  const first = chatIndexText(messages.slice(0, 2), 0, "My research");
  assert.ok(first.startsWith("Conversation: My research\n\n"));
  assert.ok(first.includes("User:\nfirst question"));
  assert.ok(first.includes("Assistant:\nfirst answer"));

  const increment = chatIndexText(messages, 2, "My research");
  assert.ok(!increment.includes("Conversation:"));
  assert.ok(!increment.includes("first question"));
  assert.ok(increment.includes("User:\nfollow-up"));
  assert.ok(increment.includes("Assistant:\nsecond answer"));
});

test("chatIndexText skips empty messages and returns '' when nothing is indexable", () => {
  assert.equal(chatIndexText([], 0, "t"), "");
  assert.equal(chatIndexText([{ role: "user", content: "   " }], 0, "t"), "");
  const out = chatIndexText(
    [
      { role: "user", content: [{ type: "image_url", image_url: {} }] },
      { role: "assistant", content: "described the image" },
    ],
    0,
    "",
  );
  assert.equal(out, "Assistant:\ndescribed the image");
});

test("siblingChatDocs scopes to the project, excludes the current chat, caps, and names", () => {
  const conversations = [
    { id: "current", title: "Me", projectId: "p1", updatedAt: 9 },
    { id: "c1", title: "Sibling one", projectId: "p1", updatedAt: 8 },
    { id: "c2", title: "", projectId: "p1", updatedAt: 7 },
    { id: "other", title: "Other project", projectId: "p2", updatedAt: 6 },
    { id: "plain", title: "No project", projectId: null, updatedAt: 5 },
  ];
  const docs = siblingChatDocs(conversations, "p1", "current");
  assert.deepEqual(docs, [
    { id: "chat-c1", name: "Sibling one" },
    { id: "chat-c2", name: "Untitled chat" },
  ]);
  assert.deepEqual(siblingChatDocs(conversations, null, "current"), []);

  const many = Array.from({ length: MAX_SIBLING_CHATS + 5 }, (_, i) => ({
    id: "c" + i,
    title: "t" + i,
    projectId: "p1",
    updatedAt: i,
  }));
  assert.equal(siblingChatDocs(many, "p1", "nope").length, MAX_SIBLING_CHATS);
});

// @ts-check
// Client-side document parsing for attachments: pdf, docx, md, txt.
// Everything runs in the browser — file contents never touch our server
// except as the extracted text (and, since metadata extraction below, a
// metadata summary) embedded in the chat message.
//
// - txt/md: read directly, no metadata (plain text carries none).
// - pdf: pdf.js (vendored, ~1.8MB with worker) dynamically imported ONLY
//   when a PDF is actually attached. Metadata comes from pdf.js's own
//   getMetadata() (the PDF Info dictionary — Author/Producer/dates/etc).
// - docx: a .docx is a ZIP with the text in word/document.xml. Parsed here
//   with a minimal central-directory reader + DecompressionStream
//   ("deflate-raw") — no library needed. Metadata additionally pulls
//   docProps/core.xml (author, last-modified-by, dates, revision),
//   docProps/app.xml (company/application), word/comments.xml (reviewer
//   comments), and unaccepted tracked changes in word/document.xml itself
//   — insertions AND deletions, since Word keeps deleted text physically
//   present in the file (as <w:delText>) even though it renders as struck
//   through / hidden. This is a well-known real-world metadata leak class
//   (e.g. redacted content resurfacing via tracked changes) — surfaced
//   here explicitly and labeled, rather than silently blended into the
//   document's main text the way a naive tag-stripping pass would.

const EXT_RE = /\.(pdf|docx|md|txt)$/i;

/**
 * One tracked change or reviewer comment pulled out of a docx.
 * @typedef {{author: string, date: string, text: string}} DocxRevision
 */

/** @param {File} file */
export function isParsableDoc(file) {
  return EXT_RE.test(file.name);
}

/**
 * @param {File} file
 * @returns {string} lowercased extension, "" when not parsable
 */
export function docExt(file) {
  return (file.name.match(EXT_RE)?.[1] || "").toLowerCase();
}

/**
 * Parse one attachment. metadata is a formatted summary string or null
 * (txt/md never have any; pdf/docx do when the file actually carries some).
 * hasTrackedDeletions flags the one docx case worth calling out as
 * sensitive on its own — unaccepted deletions are content someone tried to
 * remove, physically still present in the file (see the header comment) —
 * as opposed to routine author/date properties. Throws with a
 * user-presentable message.
 * @param {File} file
 * @param {number} maxChars inline cap; longer text is cut and flagged truncated
 * @returns {Promise<{text: string, truncated: boolean, metadata: string | null, hasTrackedDeletions: boolean}>}
 */
export async function parseDocFile(file, maxChars) {
  const ext = docExt(file);
  let text, metadata = null, hasTrackedDeletions = false;
  if (ext === "txt" || ext === "md") {
    text = await file.text();
  } else if (ext === "pdf") {
    ({ text, metadata } = await parsePdf(file, maxChars));
  } else if (ext === "docx") {
    ({ text, metadata, hasTrackedDeletions } = await parseDocx(file));
  } else {
    throw new Error("Unsupported file type.");
  }
  text = String(text || "").replace(/\r\n/g, "\n").replace(/[ \t]+\n/g, "\n").trim();
  if (!text) throw new Error("No readable text found in " + file.name + ".");
  const truncated = text.length > maxChars;
  return { text: truncated ? text.slice(0, maxChars) : text, truncated, metadata, hasTrackedDeletions };
}

// ---- PDF (lazy pdf.js) -----------------------------------------------------

/** @type {Promise<any> | null} */
let pdfjsPromise = null;
function loadPdfjs() {
  if (!pdfjsPromise) {
    // Served URL, not a package specifier — the typechecker can't resolve it.
    // @ts-ignore
    pdfjsPromise = import("/vendor/pdfjs/pdf.min.mjs").then((m) => {
      m.GlobalWorkerOptions.workerSrc = "/vendor/pdfjs/pdf.worker.min.mjs";
      return m;
    });
  }
  return pdfjsPromise;
}

/**
 * @param {File} file
 * @param {number} maxChars
 * @returns {Promise<{text: string, metadata: string | null}>}
 */
async function parsePdf(file, maxChars) {
  const pdfjs = await loadPdfjs();
  const doc = await pdfjs.getDocument({ data: await file.arrayBuffer() }).promise;
  let out = "";
  /** @type {string | null} */
  let metadata = null;
  try {
    const meta = await doc.getMetadata().catch(() => null);
    metadata = formatPdfMetadata(meta?.info);
    for (let i = 1; i <= doc.numPages; i++) {
      const page = await doc.getPage(i);
      const tc = await page.getTextContent();
      out += tc.items.map((/** @type {{str: string}} */ it) => it.str).join(" ") + "\n\n";
      // A little slack past the cap so the caller can mark truncation.
      if (out.length > maxChars + 2000) break;
    }
  } finally {
    doc.destroy();
  }
  return { text: out, metadata };
}

/**
 * PDF's Info dictionary — Title/Author/Subject/Keywords/Creator/Producer
 * plus CreationDate/ModDate in PDF's own "D:YYYYMMDDHHmmSS" date format.
 * @param {Record<string, any> | null | undefined} info pdf.js getMetadata().info
 * @returns {string | null}
 */
export function formatPdfMetadata(info) {
  if (!info) return null;
  const lines = [];
  if (info.Title) lines.push(`Title: ${info.Title}`);
  if (info.Author) lines.push(`Author: ${info.Author}`);
  if (info.Subject) lines.push(`Subject: ${info.Subject}`);
  if (info.Keywords) lines.push(`Keywords: ${info.Keywords}`);
  if (info.Creator) lines.push(`Created with: ${info.Creator}`);
  if (info.Producer) lines.push(`PDF producer: ${info.Producer}`);
  const created = parsePdfDate(info.CreationDate);
  if (created) lines.push(`Created: ${created}`);
  const modified = parsePdfDate(info.ModDate);
  if (modified) lines.push(`Modified: ${modified}`);
  return lines.length ? lines.join("\n") : null;
}

/**
 * @param {unknown} s
 * @returns {string | null}
 */
function parsePdfDate(s) {
  if (typeof s !== "string") return null;
  const m = s.match(/^D:(\d{4})(\d{2})(\d{2})(\d{2})?(\d{2})?(\d{2})?/);
  if (!m) return null;
  const [, y, mo, d, h = "00", mi = "00", se = "00"] = m;
  return `${y}-${mo}-${d} ${h}:${mi}:${se}`;
}

// ---- DOCX (minimal ZIP + document.xml + docProps + comments) --------------

/** @param {Uint8Array<ArrayBuffer>} bytes */
async function inflateRaw(bytes) {
  const stream = new Blob([bytes]).stream().pipeThrough(new DecompressionStream("deflate-raw"));
  return new Uint8Array(await new Response(stream).arrayBuffer());
}

/**
 * Reads whichever of `wanted` zip entry names are actually present.
 * Entries not in the archive are simply absent from the result — most docx
 * files have no comments.xml, for instance.
 * @param {File} file
 * @param {Set<string>} wanted
 * @returns {Promise<Map<string, Uint8Array>>} entry name → decompressed bytes
 */
async function readZipEntries(file, wanted) {
  const buf = new Uint8Array(await file.arrayBuffer());
  const dv = new DataView(buf.buffer);

  let eocd = -1;
  const stop = Math.max(0, buf.length - 65557);
  for (let i = buf.length - 22; i >= stop; i--) {
    if (dv.getUint32(i, true) === 0x06054b50) { eocd = i; break; }
  }
  if (eocd < 0) throw new Error(file.name + " does not look like a valid .docx file.");
  let off = dv.getUint32(eocd + 16, true); // central directory offset
  const count = dv.getUint16(eocd + 10, true);

  /** @type {Map<string, Uint8Array>} */
  const out = new Map();
  for (let n = 0; n < count && out.size < wanted.size; n++) {
    if (dv.getUint32(off, true) !== 0x02014b50) break;
    const method = dv.getUint16(off + 10, true);
    const csize = dv.getUint32(off + 20, true);
    const nameLen = dv.getUint16(off + 28, true);
    const extraLen = dv.getUint16(off + 30, true);
    const commentLen = dv.getUint16(off + 32, true);
    const lho = dv.getUint32(off + 42, true);
    const name = new TextDecoder().decode(buf.subarray(off + 46, off + 46 + nameLen));
    if (wanted.has(name)) {
      // Local header repeats name/extra lengths (extra may differ).
      const lNameLen = dv.getUint16(lho + 26, true);
      const lExtraLen = dv.getUint16(lho + 28, true);
      const start = lho + 30 + lNameLen + lExtraLen;
      const raw = buf.subarray(start, start + csize);
      out.set(name, method === 8 ? await inflateRaw(raw) : raw);
    }
    off += 46 + nameLen + extraLen + commentLen;
  }
  return out;
}

const WANTED_PARTS = new Set([
  "word/document.xml",
  "docProps/core.xml",
  "docProps/app.xml",
  "word/comments.xml",
]);

/**
 * @param {File} file
 * @returns {Promise<{text: string, metadata: string | null, hasTrackedDeletions: boolean}>}
 */
async function parseDocx(file) {
  const entries = await readZipEntries(file, WANTED_PARTS);
  const documentBytes = entries.get("word/document.xml");
  if (!documentBytes) throw new Error("Could not find the document text inside " + file.name + ".");
  const decoder = new TextDecoder();

  const { mainXml, insertions, deletions } = extractTrackedChanges(decoder.decode(documentBytes));
  const text = docxXmlToText(mainXml);

  const coreProps = entries.has("docProps/core.xml") ? extractCoreProps(decoder.decode(entries.get("docProps/core.xml"))) : {};
  const appProps = entries.has("docProps/app.xml") ? extractAppProps(decoder.decode(entries.get("docProps/app.xml"))) : {};
  const comments = entries.has("word/comments.xml") ? extractComments(decoder.decode(entries.get("word/comments.xml"))) : [];

  return {
    text,
    metadata: formatDocxMetadata({ coreProps, appProps, insertions, deletions, comments }),
    hasTrackedDeletions: deletions.length > 0,
  };
}

/**
 * Removes <w:del>...</w:del> blocks (deleted-but-still-present text) from
 * the main flow entirely, collecting their content separately; unwraps
 * <w:ins>...</w:ins> blocks (keeping their content in the main flow, same
 * as Word's own rendering of an unaccepted insertion) while also recording
 * who inserted what. Must run on the RAW xml (tags intact) before
 * docxXmlToText's generic tag-stripping.
 * @param {string} xml word/document.xml
 * @returns {{mainXml: string, insertions: DocxRevision[], deletions: DocxRevision[]}}
 */
function extractTrackedChanges(xml) {
  /** @type {DocxRevision[]} */
  const deletions = [];
  /** @type {DocxRevision[]} */
  const insertions = [];

  let mainXml = xml.replace(/<w:del\b([^>]*)>([\s\S]*?)<\/w:del>/g, (_, attrs, inner) => {
    const text = [...inner.matchAll(/<w:delText[^>]*>([\s\S]*?)<\/w:delText>/g)].map((m) => m[1]).join("");
    if (text.trim()) deletions.push({ author: xmlAttr(attrs, "author"), date: xmlAttr(attrs, "date"), text: decodeXmlEntities(text) });
    return "";
  });

  mainXml = mainXml.replace(/<w:ins\b([^>]*)>([\s\S]*?)<\/w:ins>/g, (_, attrs, inner) => {
    const text = [...inner.matchAll(/<w:t[^>]*>([\s\S]*?)<\/w:t>/g)].map((m) => m[1]).join("");
    if (text.trim()) insertions.push({ author: xmlAttr(attrs, "author"), date: xmlAttr(attrs, "date"), text: decodeXmlEntities(text) });
    return inner;
  });

  return { mainXml, insertions, deletions };
}

/**
 * @param {string} xml word/comments.xml
 * @returns {DocxRevision[]}
 */
function extractComments(xml) {
  /** @type {DocxRevision[]} */
  const comments = [];
  for (const m of xml.matchAll(/<w:comment\b([^>]*)>([\s\S]*?)<\/w:comment>/g)) {
    const text = [...m[2].matchAll(/<w:t[^>]*>([\s\S]*?)<\/w:t>/g)].map((mm) => mm[1]).join("");
    if (text.trim()) comments.push({ author: xmlAttr(m[1], "author"), date: xmlAttr(m[1], "date"), text: decodeXmlEntities(text) });
  }
  return comments;
}

/**
 * @param {string} attrs a tag's raw attribute string
 * @param {string} name w:-namespaced attribute local name
 */
function xmlAttr(attrs, name) {
  return attrs.match(new RegExp(`w:${name}="([^"]*)"`))?.[1] || "";
}

/**
 * Matches both namespace-prefixed tags (core.xml: <dc:creator>) and
 * unprefixed ones (app.xml: <Company>).
 * @param {string} xml
 * @param {string} localName
 * @returns {string | null}
 */
function extractTagText(xml, localName) {
  const m = xml.match(new RegExp(`<(?:[\\w]+:)?${localName}\\b[^>]*>([\\s\\S]*?)<\\/(?:[\\w]+:)?${localName}>`));
  return m ? decodeXmlEntities(m[1].trim()) || null : null;
}

/** @param {string} xml docProps/core.xml */
function extractCoreProps(xml) {
  return {
    creator: extractTagText(xml, "creator"),
    lastModifiedBy: extractTagText(xml, "lastModifiedBy"),
    created: extractTagText(xml, "created"),
    modified: extractTagText(xml, "modified"),
    revision: extractTagText(xml, "revision"),
    title: extractTagText(xml, "title"),
    subject: extractTagText(xml, "subject"),
    keywords: extractTagText(xml, "keywords"),
  };
}

/** @param {string} xml docProps/app.xml */
function extractAppProps(xml) {
  return {
    company: extractTagText(xml, "Company"),
    manager: extractTagText(xml, "Manager"),
    application: extractTagText(xml, "Application"),
  };
}

// Bounds how many tracked-change/comment entries get listed — a
// pathological review history shouldn't blow the per-doc character budget.
const MAX_LISTED = 20;

/**
 * @param {{
 *   coreProps: Partial<ReturnType<typeof extractCoreProps>>,
 *   appProps: Partial<ReturnType<typeof extractAppProps>>,
 *   insertions: DocxRevision[],
 *   deletions: DocxRevision[],
 *   comments: DocxRevision[],
 * }} parts
 * @returns {string | null}
 */
function formatDocxMetadata({ coreProps, appProps, insertions, deletions, comments }) {
  /** @type {string[]} */
  const lines = [];
  if (coreProps.creator) lines.push(`Author: ${coreProps.creator}`);
  if (coreProps.lastModifiedBy && coreProps.lastModifiedBy !== coreProps.creator) {
    lines.push(`Last modified by: ${coreProps.lastModifiedBy}`);
  }
  if (coreProps.created) lines.push(`Created: ${coreProps.created}`);
  if (coreProps.modified) lines.push(`Modified: ${coreProps.modified}`);
  if (coreProps.revision) lines.push(`Revision: ${coreProps.revision}`);
  if (coreProps.title) lines.push(`Title: ${coreProps.title}`);
  if (coreProps.subject) lines.push(`Subject: ${coreProps.subject}`);
  if (coreProps.keywords) lines.push(`Keywords: ${coreProps.keywords}`);
  if (appProps.company) lines.push(`Company: ${appProps.company}`);
  if (appProps.manager) lines.push(`Manager: ${appProps.manager}`);
  if (appProps.application) lines.push(`Created with: ${appProps.application}`);

  const listBlock = (/** @type {string} */ label, /** @type {DocxRevision[]} */ items) => {
    lines.push("", `${label} (${items.length}):`);
    for (const it of items.slice(0, MAX_LISTED)) {
      const who = it.author || "Unknown";
      const when = it.date ? ` on ${it.date.slice(0, 10)}` : "";
      lines.push(`  - by ${who}${when}: "${it.text.trim()}"`);
    }
    if (items.length > MAX_LISTED) lines.push(`  - (${items.length - MAX_LISTED} more not shown)`);
  };
  if (deletions.length) listBlock("Unaccepted tracked deletions — text removed but still present in the file", deletions);
  if (insertions.length) listBlock("Unaccepted tracked insertions", insertions);
  if (comments.length) listBlock("Reviewer comments", comments);

  return lines.length ? lines.join("\n") : null;
}

/** @param {string} s */
function decodeXmlEntities(s) {
  return s
    .replace(/&amp;/g, "&")
    .replace(/&lt;/g, "<")
    .replace(/&gt;/g, ">")
    .replace(/&quot;/g, '"')
    .replace(/&apos;/g, "'")
    .replace(/&#(\d+);/g, (_, d) => String.fromCodePoint(Number(d)));
}

/** @param {string} xml tracked-changes-stripped word/document.xml */
function docxXmlToText(xml) {
  return decodeXmlEntities(
    xml
      .replace(/<w:tab[^>]*\/>/g, "\t")
      .replace(/<w:br[^>]*\/>/g, "\n")
      .replace(/<\/w:p>/g, "\n")
      .replace(/<[^>]+>/g, ""),
  );
}

// Node tests for docs.js: the docx ZIP reader, property/tracked-change/comment extraction, PDF metadata formatting.
import { test, describe } from "node:test";
import assert from "node:assert/strict";
import zlib from "node:zlib";
import { parseDocFile, formatPdfMetadata } from "./docs.js";

// ---- test-only minimal ZIP writer -----------------------------------------
// Independent of docs.js's own zip READER, so this isn't tautological.
// Supports both STORED (method 0) and DEFLATE (method 8, via Node's zlib —
// exercises docs.js's DecompressionStream("deflate-raw") inflate path)
// entries, matching the two shapes real .docx producers use.

function buildZip(entries) {
  const encoder = new TextEncoder();
  const localParts = [];
  const centralParts = [];
  let offset = 0;

  for (const { name, content, deflate = false } of entries) {
    const nameBytes = encoder.encode(name);
    const data = encoder.encode(content);
    const compressed = deflate ? zlib.deflateRawSync(Buffer.from(data)) : Buffer.from(data);
    const method = deflate ? 8 : 0;
    const crc = zlib.crc32(Buffer.from(data));

    const local = Buffer.alloc(30 + nameBytes.length);
    local.writeUInt32LE(0x04034b50, 0);
    local.writeUInt16LE(20, 4); // version needed
    local.writeUInt16LE(0, 6); // flags
    local.writeUInt16LE(method, 8);
    local.writeUInt16LE(0, 10); // mod time
    local.writeUInt16LE(0, 12); // mod date
    local.writeUInt32LE(crc >>> 0, 14);
    local.writeUInt32LE(compressed.length, 18);
    local.writeUInt32LE(data.length, 22);
    local.writeUInt16LE(nameBytes.length, 26);
    local.writeUInt16LE(0, 28); // extra length
    Buffer.from(nameBytes).copy(local, 30);
    localParts.push(local, compressed);

    const central = Buffer.alloc(46 + nameBytes.length);
    central.writeUInt32LE(0x02014b50, 0);
    central.writeUInt16LE(20, 4); // version made by
    central.writeUInt16LE(20, 6); // version needed
    central.writeUInt16LE(0, 8); // flags
    central.writeUInt16LE(method, 10);
    central.writeUInt16LE(0, 12);
    central.writeUInt16LE(0, 14);
    central.writeUInt32LE(crc >>> 0, 16);
    central.writeUInt32LE(compressed.length, 20);
    central.writeUInt32LE(data.length, 24);
    central.writeUInt16LE(nameBytes.length, 28);
    central.writeUInt16LE(0, 30); // extra length
    central.writeUInt16LE(0, 32); // comment length
    central.writeUInt16LE(0, 34); // disk number
    central.writeUInt16LE(0, 36); // internal attrs
    central.writeUInt32LE(0, 38); // external attrs
    central.writeUInt32LE(offset, 42); // local header offset
    Buffer.from(nameBytes).copy(central, 46);
    centralParts.push(central);

    offset += local.length + compressed.length;
  }

  const centralStart = offset;
  const centralBuf = Buffer.concat(centralParts);
  const eocd = Buffer.alloc(22);
  eocd.writeUInt32LE(0x06054b50, 0);
  eocd.writeUInt16LE(0, 4);
  eocd.writeUInt16LE(0, 6);
  eocd.writeUInt16LE(entries.length, 8);
  eocd.writeUInt16LE(entries.length, 10);
  eocd.writeUInt32LE(centralBuf.length, 12);
  eocd.writeUInt32LE(centralStart, 16);
  eocd.writeUInt16LE(0, 20);

  return Buffer.concat([...localParts, centralBuf, eocd]);
}

const CONTENT_TYPES = '<?xml version="1.0"?><Types/>';
const RELS = '<?xml version="1.0"?><Relationships/>';

function docxFile(name, { documentXml, coreXml, appXml, commentsXml, deflate = false }) {
  const entries = [
    { name: "[Content_Types].xml", content: CONTENT_TYPES, deflate },
    { name: "_rels/.rels", content: RELS, deflate },
    { name: "word/document.xml", content: documentXml, deflate },
  ];
  if (coreXml) entries.push({ name: "docProps/core.xml", content: coreXml, deflate });
  if (appXml) entries.push({ name: "docProps/app.xml", content: appXml, deflate });
  if (commentsXml) entries.push({ name: "word/comments.xml", content: commentsXml, deflate });
  return new File([buildZip(entries)], name);
}

const W = 'xmlns:w="http://schemas.openxmlformats.org/wordprocessingml/2006/main"';
const doc = (bodyXml) =>
  `<?xml version="1.0"?><w:document ${W}><w:body>${bodyXml}</w:body></w:document>`;

describe("parseDocFile / docx", () => {
  test("plain docx with no docProps: text extracted, metadata is null", async () => {
    const file = docxFile("plain.docx", {
      documentXml: doc("<w:p><w:r><w:t>Hello world</w:t></w:r></w:p>"),
    });
    const { text, metadata } = await parseDocFile(file, 9000);
    assert.equal(text, "Hello world");
    assert.equal(metadata, null);
  });

  test("works identically whether entries are STORED or DEFLATEd", async () => {
    const body = "<w:p><w:r><w:t>Deflated content check</w:t></w:r></w:p>";
    const stored = docxFile("stored.docx", { documentXml: doc(body), deflate: false });
    const deflated = docxFile("deflated.docx", { documentXml: doc(body), deflate: true });
    const a = await parseDocFile(stored, 9000);
    const b = await parseDocFile(deflated, 9000);
