// DRC's storage adapter — BROWSER-LOCAL ONLY, by product definition: DRC
// ("deep research secure", C for CLIENT-side) keeps everything on the
// user's machine. The sealed project state (drc-core.js: AES-256-GCM
// under the secret-derived blob key) rests in this browser's localStorage
// as base64, keyed by the secret-derived blob id — so what's on disk is
// ciphertext exactly like every other at-rest surface of this site, and
// nothing project-derived ever reaches the server (which, for DRC, serves
// static files and public replay JSONs and NOTHING else).
//
// This module is deliberately the SEAM: everything above it (the page
// wiring) speaks get/put/delete-by-id, so a future opt-in remote copy —
// DRS territory — would be a second adapter, not a rewrite. The backend
// is injectable for Node tests (any Storage-shaped object); the default
// is this browser's localStorage.
//
// localStorage over IndexedDB, a deliberate judgement call: DRC states
// are text conversations (no attached-file bytes — those are DRS
// features), so the ~5 MB quota is generous, and the synchronous
// key-value API keeps this adapter small enough to audit at a glance.

const PREFIX = "drc:project:"; // + blobId → base64(sealed bytes)

/** @returns {Storage | null} */
function defaultBackend() {
  try {
    return typeof localStorage !== "undefined" ? localStorage : null;
  } catch {
    return null; // storage blocked (some private modes) — DRC degrades to tab-memory
  }
}

export function drcStoreAvailable(backend = defaultBackend()) {
  return !!backend;
}

/**
 * @param {string} blobId
 * @param {Uint8Array} bytes the sealed state (drc-core sealFreeState output)
 * @param {Storage | null} [backend]
 * @returns {boolean} false when storage is unavailable/full — callers keep
 *   working from memory and say so, never throw at the user
 */
export function putSealedProject(blobId, bytes, backend = defaultBackend()) {
  if (!backend) return false;
  try {
    backend.setItem(PREFIX + blobId, bytesToB64(bytes));
    return true;
  } catch {
    return false; // quota — the tab-memory copy remains authoritative
  }
}

/**
 * @param {string} blobId
 * @param {Storage | null} [backend]
 * @returns {Uint8Array | null}
 */
export function getSealedProject(blobId, backend = defaultBackend()) {
  if (!backend) return null;
  const b64 = backend.getItem(PREFIX + blobId);
  if (!b64) return null;
  try {
    return b64ToBytes(b64);
  } catch {
    return null; // corrupted row — treat as absent rather than crash the open
  }
}

/** @param {string} blobId @param {Storage | null} [backend] */
export function deleteSealedProject(blobId, backend = defaultBackend()) {
  backend?.removeItem(PREFIX + blobId);
}

/**
 * The blob ids stored in this browser — lets the page say "N saved
 * project(s) on this device" without being able to name or read any.
 * @param {Storage | null} [backend]
 * @returns {string[]}
 */
export function listSealedProjects(backend = defaultBackend()) {
  if (!backend) return [];
  const ids = [];
  for (let i = 0; i < backend.length; i++) {
    const key = backend.key(i);
    if (key && key.startsWith(PREFIX)) ids.push(key.slice(PREFIX.length));
  }
  return ids;
}

// Chunked base64 (multi-hundred-KB states are normal; one big
// String.fromCharCode overflows the argument list).
function bytesToB64(bytes) {
  let binary = "";
  for (let i = 0; i < bytes.length; i += 0x8000) {
    binary += String.fromCharCode.apply(null, bytes.subarray(i, i + 0x8000));
  }
  return btoa(binary);
}

function b64ToBytes(b64) {
  const binary = atob(b64);
  const bytes = new Uint8Array(binary.length);
  for (let i = 0; i < binary.length; i++) bytes[i] = binary.charCodeAt(i);
  return bytes;
}

import test from "node:test";
import assert from "node:assert/strict";
import {
  deleteSealedProject,
  drcStoreAvailable,
  getSealedProject,
  listSealedProjects,
  putSealedProject,
} from "./drc-store.js";

// A Storage-shaped mock (the adapter's injectable backend — in the browser
// it's localStorage).
function mockStorage() {
  const map = new Map();
  return {
    get length() {
      return map.size;
    },
    key: (i) => [...map.keys()][i] ?? null,
    getItem: (k) => (map.has(k) ? map.get(k) : null),
    setItem: (k, v) => map.set(k, String(v)),
    removeItem: (k) => map.delete(k),
    _map: map,
  };
}

test("availability follows the backend", () => {
  assert.equal(drcStoreAvailable(mockStorage()), true);
  assert.equal(drcStoreAvailable(null), false);
});

test("put/get/delete round-trip sealed bytes", () => {
  const s = mockStorage();
  const bytes = new Uint8Array(100_000); // chunk-boundary territory
  for (let i = 0; i < bytes.length; i++) bytes[i] = (i * 31) & 0xff;
  assert.equal(putSealedProject("BLOB1BLOB1BLOB1BLOB1", bytes, s), true);
  assert.deepEqual(getSealedProject("BLOB1BLOB1BLOB1BLOB1", s), bytes);
  deleteSealedProject("BLOB1BLOB1BLOB1BLOB1", s);
  assert.equal(getSealedProject("BLOB1BLOB1BLOB1BLOB1", s), null);
});

test("only ciphertext-bearing base64 rests in the backend", () => {
  const s = mockStorage();
  putSealedProject("IDID", new TextEncoder().encode("this is sealed input"), s);
  const stored = [...s._map.values()][0];
  assert.match(stored, /^[A-Za-z0-9+/=]+$/); // base64, not raw text
});

test("listSealedProjects returns only this adapter's ids", () => {
  const s = mockStorage();
  s.setItem("unrelated", "x");
  putSealedProject("AAAA", new Uint8Array(32), s);
  putSealedProject("BBBB", new Uint8Array(32), s);
  assert.deepEqual(listSealedProjects(s).sort(), ["AAAA", "BBBB"]);
});

test("fail-soft: no backend, quota errors, and corrupted rows never throw", () => {
  assert.equal(putSealedProject("X", new Uint8Array(8), null), false);
  assert.equal(getSealedProject("X", null), null);
  assert.deepEqual(listSealedProjects(null), []);
  deleteSealedProject("X", null); // no throw

  const full = mockStorage();
  full.setItem = () => {
    throw new Error("QuotaExceededError");
  };
  assert.equal(putSealedProject("X", new Uint8Array(8), full), false);

  const corrupt = mockStorage();
  corrupt.setItem("drc:project:BAD", "%%%not-base64%%%");
  assert.equal(getSealedProject("BAD", corrupt), null);
});

// @ts-check
// The conversation embeds registry — the pipeline-embedded elements'
// bookkeeping, extracted from stream.js.
//
// Elements the pipeline embedded into a turn's body this conversation —
// the Street View panorama (`streetview_embed`) and vision-frame strip
// (`streetview_frames`). Recorded so the copy-to-clipboard export can
// reference them with stable per-conversation id numbers ("[Embedded
// element #N: …]" — message-content.js's embedRef); persisted in the
// conversation record (`embeds`, additive) so a reloaded conversation's
// export still references them even though the live panorama itself is
// session-only. `msgIndex` is the index of the assistant message the
// element renders beside — captured as history.length while the answer
// streams, which is exactly where that answer lands on completion.
//
// stream.js owns the conversation this registry keys off: initEmbeds wires
// its live message array (a stable reference — stream.js clears it in
// place, never reassigns it) and the persist hook a quiz completed after
// its stream ended needs. Everything else goes through the exports below.

/**
 * One pipeline-embedded element recorded for a turn. Kind-specific metadata
 * (coordinates, frame data URLs, the quiz payload and its answers) rides
 * along as extra properties.
 * @typedef {object} EmbedEntry
 * @property {number} id        stable per-conversation number (copy-text references)
 * @property {string} kind      "streetview_embed" | "map_embed" | "streetview_frames" | "quiz"
 * @property {number} msgIndex  index of the assistant message it renders beside
 */

/** A message array entry (stream.js's history shape). */
/** @typedef {{role: string, content: string|object[], [extra: string]: any}} HistoryMessage */

/** @type {HistoryMessage[]} the live conversation array (stream.js's `history`) */
let history = [];
/** @type {() => Promise<void>} persists the conversation with the latest send's metadata */
let persist = async () => {};

/**
 * One-time wiring from stream.js.
 * @param {{history: HistoryMessage[], persist: () => Promise<void>}} deps
 */
export function initEmbeds(deps) {
  history = deps.history;
  persist = deps.persist;
}

/** @type {Array<EmbedEntry & {[extra: string]: any}>} */
let convEmbeds = []; // [{id, kind, msgIndex, …kind-specific metadata}]

/**
 * The registry for the conversation currently on screen — read for
 * persistence (`embeds` in the conversation record), the copy-text export,
 * and reload rendering.
 * @returns {Array<EmbedEntry & {[extra: string]: any}>}
 */
export function getEmbeds() {
  return convEmbeds;
}

/**
 * Replace the registry — a loaded record's `embeds` list (normalized: any
 * non-array means none), or `[]` when the conversation state resets.
 * @param {any} list
 */
export function setEmbeds(list) {
  convEmbeds = Array.isArray(list) ? list : [];
}

/**
 * @param {{kind: string, [extra: string]: any}} meta
 * @returns {EmbedEntry & {[extra: string]: any}}
 */
export function recordEmbed(meta) {
  const existing = convEmbeds.find((e) => e.msgIndex === history.length && e.kind === meta.kind);
  if (existing) {
    // Mirror the render behavior (activity.js/quiz.js): one panorama per
    // turn (repeats ignored), one frame strip per turn (last event wins),
    // one quiz per turn (repeats ignored).
    if (meta.kind === "streetview_frames") Object.assign(existing, meta);
    return existing;
  }
  const id = convEmbeds.reduce((m, e) => Math.max(m, e.id || 0), 0) + 1;
  const entry = { id, msgIndex: history.length, ...meta };
  convEmbeds.push(entry);
  return entry;
}

// The interaction hooks one quiz card (public/js/quiz.js) gets for its
// embeds-registry entry: answers persist into the entry as they're given,
// and completion appends the result summary to the quiz's assistant message
// in history — so follow-up questions (and the copy-conversation export)
// know the score and what was missed — then persists. The `completed` guard
// keeps a reloaded, already-finished quiz from appending the summary twice.
/**
 * @param {EmbedEntry & {[extra: string]: any}} embed
 */
export function quizHooks(embed) {
  return {
    answers: Array.isArray(embed.answers) ? embed.answers : [],
    /** @param {any[]} answers */
    onAnswer(answers) {
      embed.answers = answers;
    },
    /** @param {string} summary */
    onComplete(summary) {
      if (embed.completed) return;
      embed.completed = true;
      const msg = history[embed.msgIndex];
      if (msg && msg.role === "assistant" && typeof msg.content === "string") {
        msg.content += "\n\n" + summary;
      }
      persist().catch(() => {});
    },
  };
}

// An exchange that reverted its user message (send failed, stopped before
// any text) also drops the embeds recorded for the answer that never
// landed — their msgIndex now points past the end of history.
export function pruneEmbeds() {
  convEmbeds = convEmbeds.filter((e) => e.msgIndex < history.length);
}

// Frame images are the one bulky embed payload (~150 KB per data URL). Cap
// the total stored across the conversation at ~4 MB by dropping the URLS
// from the OLDEST frame embeds first — their metadata (query, directions)
// stays for the copy-text export; only the reload-render of those old turns
// degrades back to text.
const MAX_EMBED_BYTES = 4_000_000;
export function capEmbedBytes() {
  let total = 0;
  for (const e of convEmbeds) {
    for (const f of e.frames || []) total += (f.url || "").length;
  }
  for (const e of convEmbeds) {
    if (total <= MAX_EMBED_BYTES) break;
    for (const f of e.frames || []) {
      total -= (f.url || "").length;
      delete f.url;
    }
  }
}

// @ts-check
// Minimal JPEG/EXIF parser — no library, operates on the raw ArrayBuffer.
// Must run on the ORIGINAL file bytes before attachments.js's canvas-based
// downscale, since re-encoding through <canvas>.toDataURL() strips all
// metadata. PNG/WebP/GIF are not handled (real-world EXIF is overwhelmingly
// a JPEG/camera-photo phenomenon) — extractExif() returns null for them.
//
// Extracted fields can include the photo's GPS location, capture time, and
// device — genuinely sensitive, not just informational. Callers are
// responsible for surfacing that to the user before it's sent anywhere
// (see attachments.js's metadata badge + CLAUDE.md's documentation).

const APP1 = 0xffe1;
const EXIF_IFD_POINTER = 0x8769;
const GPS_IFD_POINTER = 0x8825;

/** Bytes per unit for each TIFF field type this parser reads. @type {Record<number, number>} */
const TYPE_SIZES = { 1: 1, 2: 1, 3: 2, 4: 4, 5: 8, 7: 1, 9: 4, 10: 8 };

/**
 * One decoded IFD field. `value` is an array of numbers (length `count`),
 * except ASCII fields where readValue assembles the bytes into a single
 * one-element string array.
 * @typedef {{type: number, count: number, value: Array<number | string>}} IfdEntry
 */

/**
 * The extracted metadata (every field may be null when absent).
 * @typedef {object} ExifSummary
 * @property {string | null} make
 * @property {string | null} model
 * @property {string | null} software
 * @property {string | null} artist
 * @property {string | null} copyright
 * @property {string | null} description
 * @property {string | null} dateTimeOriginal "YYYY-MM-DD HH:MM:SS"
 * @property {{lat: number, lon: number, altitude: number | null} | null} gps signed decimal degrees
 */

/**
 * @param {ArrayBuffer} arrayBuffer the ORIGINAL file bytes (pre-downscale)
 * @returns {ExifSummary | null} null: no EXIF / not a JPEG / malformed
 */
export function extractExif(arrayBuffer) {
  try {
    return parseJpegExif(new DataView(arrayBuffer));
  } catch {
    // Malformed/truncated segment: degrade to "no metadata" rather than
    // blocking the attachment — the image itself is still perfectly usable.
    return null;
  }
}

/**
 * @param {DataView} dv
 * @returns {ExifSummary | null}
 */
function parseJpegExif(dv) {
  if (dv.byteLength < 4 || dv.getUint16(0) !== 0xffd8) return null; // not a JPEG (SOI)

  let offset = 2;
  while (offset + 4 <= dv.byteLength) {
    const marker = dv.getUint16(offset);
    if ((marker & 0xff00) !== 0xff00) break; // not a marker — malformed
    if (marker === 0xffd8 || marker === 0xffd9) { offset += 2; continue; } // SOI/EOI, no length
    if (marker >= 0xffd0 && marker <= 0xffd7) { offset += 2; continue; } // RSTn, no length
    if (marker === 0xffda) break; // SOS: entropy-coded data follows, no more markers before it

    const length = dv.getUint16(offset + 2); // includes the 2 length bytes, excludes the marker
    if (marker === APP1 && hasExifHeader(dv, offset + 4)) {
      return parseTiff(dv, offset + 4 + 6); // skip "Exif\0\0"
    }
    offset += 2 + length;
  }
  return null;
}

/**
 * @param {DataView} dv
 * @param {number} at
 */
function hasExifHeader(dv, at) {
  if (at + 6 > dv.byteLength) return false;
  return (
    dv.getUint8(at) === 0x45 && dv.getUint8(at + 1) === 0x78 && dv.getUint8(at + 2) === 0x69 &&
    dv.getUint8(at + 3) === 0x66 && dv.getUint8(at + 4) === 0 && dv.getUint8(at + 5) === 0
  );
}

/**
 * @param {DataView} dv
 * @param {number} tiffStart byte offset of the TIFF header (after "Exif\0\0")
 * @returns {ExifSummary | null}
 */
function parseTiff(dv, tiffStart) {
  const bom = dv.getUint16(tiffStart);
  let little;
  if (bom === 0x4949) little = true;
  else if (bom === 0x4d4d) little = false;
  else return null;
  if (dv.getUint16(tiffStart + 2, little) !== 42) return null;

  const ifd0Offset = dv.getUint32(tiffStart + 4, little);
  const ifd0 = readIfd(dv, tiffStart, tiffStart + ifd0Offset, little);

  /** @type {ExifSummary} */
  const out = {
    make: asString(ifd0.get(0x010f)),
    model: asString(ifd0.get(0x0110)),
    software: asString(ifd0.get(0x0131)),
    artist: asString(ifd0.get(0x013b)),
    copyright: asString(ifd0.get(0x8298)),
    description: asString(ifd0.get(0x010e)),
    dateTimeOriginal: null,
    gps: null,
  };

  const exifPtr = ifd0.get(EXIF_IFD_POINTER);
  if (exifPtr && typeof exifPtr.value[0] === "number") {
    const exifIfd = readIfd(dv, tiffStart, tiffStart + exifPtr.value[0], little);
    out.dateTimeOriginal = asDateTime(exifIfd.get(0x9003)) || asDateTime(exifIfd.get(0x9004));
  }

  const gpsPtr = ifd0.get(GPS_IFD_POINTER);
  if (gpsPtr && typeof gpsPtr.value[0] === "number") {
    const gpsIfd = readIfd(dv, tiffStart, tiffStart + gpsPtr.value[0], little);
    out.gps = readGps(gpsIfd);
  }

  if (!out.make && !out.model && !out.software && !out.artist && !out.copyright &&
      !out.description && !out.dateTimeOriginal && !out.gps) {
    return null; // header present but nothing usable — treat as "no metadata"
  }
  return out;
}

/**
 * Reads one IFD into a Map keyed by tag.
 * @param {DataView} dv
 * @param {number} tiffStart all IFD value offsets are relative to this
 * @param {number} ifdOffset absolute byte offset of the IFD
 * @param {boolean} little byte order from the TIFF header
 * @returns {Map<number, IfdEntry>}
 */
function readIfd(dv, tiffStart, ifdOffset, little) {
  /** @type {Map<number, IfdEntry>} */
  const entries = new Map();
  if (ifdOffset <= 0 || ifdOffset + 2 > dv.byteLength) return entries;
  const count = dv.getUint16(ifdOffset, little);
  let p = ifdOffset + 2;
  for (let i = 0; i < count && p + 12 <= dv.byteLength; i++, p += 12) {
    const tag = dv.getUint16(p, little);
    const type = dv.getUint16(p + 2, little);
    const num = dv.getUint32(p + 4, little);
    const unitSize = TYPE_SIZES[type];
    if (!unitSize) continue; // unknown type — skip rather than misread
    const totalSize = unitSize * num;
    const valueAt = totalSize <= 4 ? p + 8 : tiffStart + dv.getUint32(p + 8, little);
    entries.set(tag, { type, count: num, value: readValue(dv, valueAt, type, num, little) });
  }
  return entries;
}

/**
 * @param {DataView} dv
 * @param {number} at absolute byte offset of the value
 * @param {number} type TIFF field type
 * @param {number} count
 * @param {boolean} little
 * @returns {Array<number | string>} see IfdEntry's `value` shape
 */
function readValue(dv, at, type, count, little) {
  /** @type {number[]} */
  const out = [];
  for (let i = 0; i < count; i++) {
    if (at + TYPE_SIZES[type] * (i + 1) > dv.byteLength) break;
    switch (type) {
      case 1: case 7: out.push(dv.getUint8(at + i)); break; // BYTE / UNDEFINED
      case 2: out.push(dv.getUint8(at + i)); break; // ASCII (assembled below)
      case 3: out.push(dv.getUint16(at + i * 2, little)); break; // SHORT
      case 4: out.push(dv.getUint32(at + i * 4, little)); break; // LONG
      case 5: { // RATIONAL
        const o = at + i * 8;
        out.push(dv.getUint32(o, little) / (dv.getUint32(o + 4, little) || 1));
        break;
      }
      case 9: out.push(dv.getInt32(at + i * 4, little)); break; // SLONG
      case 10: { // SRATIONAL
        const o = at + i * 8;
        out.push(dv.getInt32(o, little) / (dv.getInt32(o + 4, little) || 1));
        break;
      }
      default: break;
    }
  }
  if (type === 2) return [bytesToAscii(out)]; // ASCII: one assembled string
  return out;
}

/** @param {number[]} bytes */
function bytesToAscii(bytes) {
  let s = "";
  for (const b of bytes) {
    if (b === 0) break; // stop at the null terminator
    s += String.fromCharCode(b);
  }
  return s;
}

/**
 * @param {IfdEntry | undefined} entry
 * @returns {string | null}
 */
function asString(entry) {
  const v = entry?.value?.[0];
  return typeof v === "string" && v ? v : null;
}

/**
 * EXIF DateTimeOriginal is "YYYY:MM:DD HH:MM:SS" — normalize the date
 * separators for readability without pulling in a date-parsing library.
 * @param {IfdEntry | undefined} entry
 * @returns {string | null}
 */
function asDateTime(entry) {
  const v = asString(entry);
  if (!v) return null;
  const m = v.match(/^(\d{4}):(\d{2}):(\d{2}) (\d{2}:\d{2}:\d{2})$/);
  return m ? `${m[1]}-${m[2]}-${m[3]} ${m[4]}` : v;
}

/**
 * @param {Array<number | string> | undefined} values [degrees, minutes, seconds]
 * @returns {number | null}
 */
function dmsToDecimal(values) {
  if (!Array.isArray(values) || values.length < 3) return null;
  // ASCII fields collapse to a single-element array (readValue), so a
  // 3+-element value is necessarily numeric.
  const [deg, min, sec] = /** @type {number[]} */ (values);
  return deg + min / 60 + sec / 3600;
}

/**
 * @param {Map<number, IfdEntry>} gpsIfd
 * @returns {ExifSummary["gps"]}
 */
function readGps(gpsIfd) {
  const latRef = asString(gpsIfd.get(1));
  const lonRef = asString(gpsIfd.get(3));
  const latDms = gpsIfd.get(2)?.value;
  const lonDms = gpsIfd.get(4)?.value;
  const lat = dmsToDecimal(latDms);
  const lon = dmsToDecimal(lonDms);
  if (lat == null || lon == null) return null;
  const signedLat = latRef === "S" ? -lat : lat;
  const signedLon = lonRef === "W" ? -lon : lon;
  const altRef = gpsIfd.get(5)?.value?.[0];
  const altVal = gpsIfd.get(6)?.value?.[0];
  const altitude = typeof altVal === "number" ? (altRef === 1 ? -altVal : altVal) : null;
  return { lat: round6(signedLat), lon: round6(signedLon), altitude };
}

/** @param {number} n */
function round6(n) {
  return Math.round(n * 1e6) / 1e6;
}

/**
 * Human/LLM-readable summary block, or null if there's nothing to show.
 * @param {ExifSummary | null | undefined} meta
 * @returns {string | null}
 */
export function formatExifSummary(meta) {
  if (!meta) return null;
  const lines = [];
  const camera = [meta.make, meta.model].filter(Boolean).join(" ");
  if (camera) lines.push(`Camera: ${camera}`);
  if (meta.dateTimeOriginal) lines.push(`Captured: ${meta.dateTimeOriginal}`);
  if (meta.software) lines.push(`Software: ${meta.software}`);
  if (meta.artist) lines.push(`Artist/Author: ${meta.artist}`);
  if (meta.copyright) lines.push(`Copyright: ${meta.copyright}`);
  if (meta.description) lines.push(`Description: ${meta.description}`);
  if (meta.gps) {
    const { lat, lon, altitude } = meta.gps;
    lines.push(
      `GPS location: ${lat}, ${lon}` +
        (altitude != null ? ` (altitude ${altitude} m)` : "") +
        ` — https://www.openstreetmap.org/?mlat=${lat}&mlon=${lon}&zoom=15`,
    );
  }
  return lines.length ? lines.join("\n") : null;
}

// Node tests for exif.js: GPS/camera/timestamp extraction, byte-order handling, malformed-input safety.
import { test, describe } from "node:test";
import assert from "node:assert/strict";
import { extractExif, formatExifSummary } from "./exif.js";

// ---- test-only TIFF/EXIF encoder --------------------------------------
// Independent of exif.js's own reading code (so this isn't tautological):
// builds a real byte-accurate TIFF structure via straightforward two-pass
// layout (compute each IFD's size first — always possible without knowing
// pointer values, since pointer entries are always inline LONGs — then
// resolve pointers and serialize).

function asciiBytes(str) {
  const withNull = str + "\0";
  return Uint8Array.from(withNull, (c) => c.charCodeAt(0));
}

// entries: [{tag, kind: "ascii", str} | {tag, kind: "long", value} | {tag, kind: "rational", rationals: [[n,d],...]} | {tag, kind: "byte", value}]
function layoutIfd(entries) {
  const headerSize = 2 + entries.length * 12 + 4;
  let poolSize = 0;
  const withSizes = entries.map((e) => {
    if (e.kind === "ascii") {
      const bytes = asciiBytes(e.str);
      const external = bytes.length > 4;
      const size = external ? bytes.length : 0;
      const at = external ? poolSize : null;
      if (external) poolSize += size;
      return { ...e, bytes, external, at };
    }
    if (e.kind === "rational") {
      const size = e.rationals.length * 8; // always external (min 8 > 4)
      const at = poolSize;
      poolSize += size;
      return { ...e, external: true, at };
    }
    return { ...e, external: false }; // long/byte: always inline
  });
  return { entries: withSizes, headerSize, poolSize, totalSize: headerSize + poolSize };
}

function serializeIfd(layout, ifdStart, little) {
  const buf = new Uint8Array(layout.totalSize);
  const dv = new DataView(buf.buffer);
  dv.setUint16(0, layout.entries.length, little);
  let p = 2;
  const poolStart = layout.headerSize;
  for (const e of layout.entries) {
    if (e.kind === "ascii") {
      dv.setUint16(p, e.tag, little);
      dv.setUint16(p + 2, 2, little); // ASCII
      dv.setUint32(p + 4, e.bytes.length, little);
      if (e.external) {
        dv.setUint32(p + 8, ifdStart + poolStart + e.at, little);
        buf.set(e.bytes, poolStart + e.at);
      } else {
        buf.set(e.bytes, p + 8);
      }
    } else if (e.kind === "rational") {
      dv.setUint16(p, e.tag, little);
      dv.setUint16(p + 2, 5, little); // RATIONAL
      dv.setUint32(p + 4, e.rationals.length, little);
      dv.setUint32(p + 8, ifdStart + poolStart + e.at, little);
      let rp = poolStart + e.at;
      for (const [n, d] of e.rationals) {
        dv.setUint32(rp, n, little);
        dv.setUint32(rp + 4, d, little);
        rp += 8;
      }
    } else if (e.kind === "long") {
      dv.setUint16(p, e.tag, little);
      dv.setUint16(p + 2, 4, little); // LONG
      dv.setUint32(p + 4, 1, little);
      dv.setUint32(p + 8, e.value, little);
    } else if (e.kind === "byte") {
      dv.setUint16(p, e.tag, little);
      dv.setUint16(p + 2, 1, little); // BYTE
      dv.setUint32(p + 4, 1, little);
      buf[p + 8] = e.value;
    }
    p += 12;
  }
  dv.setUint32(p, 0, little); // next-IFD offset
  return buf;
}

// Builds a minimal JPEG (SOI + APP1/Exif + EOI) with IFD0 (make/model/
// software), an optional Exif SubIFD (dateTimeOriginal), and an optional
// GPS IFD (lat/lon/altitude). `little` picks the TIFF byte order.
function buildExifJpeg({ make, model, software, dateTimeOriginal, gps, little = true } = {}) {
  const ifd0Entries = [];
  if (make) ifd0Entries.push({ tag: 0x010f, kind: "ascii", str: make });
  if (model) ifd0Entries.push({ tag: 0x0110, kind: "ascii", str: model });
  if (software) ifd0Entries.push({ tag: 0x0131, kind: "ascii", str: software });

  const exifEntries = [];
  if (dateTimeOriginal) exifEntries.push({ tag: 0x9003, kind: "ascii", str: dateTimeOriginal });

  const gpsEntries = [];
  if (gps) {
    gpsEntries.push({ tag: 1, kind: "ascii", str: gps.lat < 0 ? "S" : "N" });
    gpsEntries.push({ tag: 2, kind: "rational", rationals: decToDmsRationals(Math.abs(gps.lat)) });
    gpsEntries.push({ tag: 3, kind: "ascii", str: gps.lon < 0 ? "W" : "E" });
    gpsEntries.push({ tag: 4, kind: "rational", rationals: decToDmsRationals(Math.abs(gps.lon)) });
    if (gps.altitude != null) {
      gpsEntries.push({ tag: 5, kind: "byte", value: gps.altitude < 0 ? 1 : 0 });
      gpsEntries.push({ tag: 6, kind: "rational", rationals: [[Math.round(Math.abs(gps.altitude) * 100), 100]] });
    }
  }

  if (exifEntries.length) ifd0Entries.push({ tag: 0x8769, kind: "long", value: 0 }); // patched below
  if (gpsEntries.length) ifd0Entries.push({ tag: 0x8825, kind: "long", value: 0 }); // patched below

  const ifd0Layout = layoutIfd(ifd0Entries);
  const tiffHeaderSize = 8;
  const ifd0Start = tiffHeaderSize;
  let cursor = ifd0Start + ifd0Layout.totalSize;

  let exifStart = 0, exifLayout = null;
  if (exifEntries.length) {
    exifLayout = layoutIfd(exifEntries);
    exifStart = cursor;
    cursor += exifLayout.totalSize;
  }
  let gpsStart = 0, gpsLayout = null;
  if (gpsEntries.length) {
    gpsLayout = layoutIfd(gpsEntries);
    gpsStart = cursor;
    cursor += gpsLayout.totalSize;
  }

  // Patch the pointer values now that sub-IFD offsets are known.
  for (const e of ifd0Layout.entries) {
    if (e.tag === 0x8769) e.value = exifStart;
    if (e.tag === 0x8825) e.value = gpsStart;
  }

  const tiff = new Uint8Array(cursor);
  const dv = new DataView(tiff.buffer);
  dv.setUint16(0, little ? 0x4949 : 0x4d4d, false);
  dv.setUint16(2, 42, little);
  dv.setUint32(4, ifd0Start, little);
  tiff.set(serializeIfd(ifd0Layout, ifd0Start, little), ifd0Start);
  if (exifLayout) tiff.set(serializeIfd(exifLayout, exifStart, little), exifStart);
  if (gpsLayout) tiff.set(serializeIfd(gpsLayout, gpsStart, little), gpsStart);

  const exifHeader = Uint8Array.from("Exif\0\0", (c) => c.charCodeAt(0));
  const app1Payload = new Uint8Array(exifHeader.length + tiff.length);
  app1Payload.set(exifHeader, 0);
  app1Payload.set(tiff, exifHeader.length);

  const app1Length = app1Payload.length + 2; // includes the 2 length bytes
  const jpeg = new Uint8Array(2 + 2 + 2 + app1Payload.length + 2);
  const jdv = new DataView(jpeg.buffer);
  jdv.setUint16(0, 0xffd8); // SOI
  jdv.setUint16(2, 0xffe1); // APP1
  jdv.setUint16(4, app1Length);
  jpeg.set(app1Payload, 6);
  jdv.setUint16(6 + app1Payload.length, 0xffd9); // EOI
  return jpeg.buffer;
}

function decToDmsRationals(decimalAbs) {
  const deg = Math.floor(decimalAbs);
  const minFull = (decimalAbs - deg) * 60;
  const min = Math.floor(minFull);
  const sec = (minFull - min) * 3600 / 60; // seconds
  return [[deg, 1], [min, 1], [Math.round(sec * 1000), 1000]];
}

// ---- tests ---------------------------------------------------------------

describe("extractExif", () => {
  test("extracts camera make/model/software plus GPS and capture time (little-endian)", () => {
    const buf = buildExifJpeg({
      make: "Apple",
      model: "iPhone 14 Pro",
      software: "17.4.1",
      dateTimeOriginal: "2024:05:01 14:32:00",
      gps: { lat: 40.7128, lon: -74.006, altitude: 10 },
      little: true,
    });
    const meta = extractExif(buf);
    assert.equal(meta.make, "Apple");
    assert.equal(meta.model, "iPhone 14 Pro");
    assert.equal(meta.software, "17.4.1");
    assert.equal(meta.dateTimeOriginal, "2024-05-01 14:32:00");
    assert.ok(meta.gps);
    assert.ok(Math.abs(meta.gps.lat - 40.7128) < 1e-3);
    assert.ok(Math.abs(meta.gps.lon - -74.006) < 1e-3);
    assert.equal(meta.gps.altitude, 10);
  });

  test("also works with big-endian ('MM') TIFF byte order", () => {
    const buf = buildExifJpeg({ make: "Canon", model: "EOS R5", little: false });
    const meta = extractExif(buf);
    assert.equal(meta.make, "Canon");
    assert.equal(meta.model, "EOS R5");
    assert.equal(meta.gps, null);
  });

  test("southern/western hemisphere GPS refs negate correctly", () => {
    const buf = buildExifJpeg({ gps: { lat: -33.8688, lon: 151.2093, altitude: null } });
    const meta = extractExif(buf);
    assert.ok(meta.gps.lat < 0, "S ref must produce a negative latitude");
    assert.ok(meta.gps.lon > 0, "E ref must produce a positive longitude");
    assert.ok(Math.abs(meta.gps.lat - -33.8688) < 1e-3);
    assert.ok(Math.abs(meta.gps.lon - 151.2093) < 1e-3);
  });

  test("a camera photo with no GPS tag at all returns gps: null, not a throw", () => {
    const buf = buildExifJpeg({ make: "Sony", model: "A7IV" });
    const meta = extractExif(buf);
    assert.equal(meta.gps, null);
    assert.equal(meta.make, "Sony");
  });

  test("a plain JPEG with no APP1/Exif segment at all returns null", () => {
    // SOI, a harmless APP0/JFIF-shaped segment, EOI — no APP1 anywhere.
    const jpeg = new Uint8Array([0xff, 0xd8, 0xff, 0xe0, 0x00, 0x04, 0x4a, 0x46, 0xff, 0xd9]);
    assert.equal(extractExif(jpeg.buffer), null);
  });

  test("non-JPEG bytes (e.g. a PNG signature) return null rather than throwing", () => {
    const png = new Uint8Array([0x89, 0x50, 0x4e, 0x47, 0x0d, 0x0a, 0x1a, 0x0a, 0, 0, 0, 0]);
    assert.doesNotThrow(() => extractExif(png.buffer));
    assert.equal(extractExif(png.buffer), null);
  });

  test("an empty or tiny buffer is handled safely", () => {
    assert.equal(extractExif(new ArrayBuffer(0)), null);
    assert.equal(extractExif(new ArrayBuffer(2)), null);
  });

  test("a truncated/corrupted APP1 segment degrades to null instead of throwing", () => {
    const buf = buildExifJpeg({ make: "Apple", model: "iPhone 14 Pro", gps: { lat: 1, lon: 2 } });
    const truncated = buf.slice(0, buf.byteLength - 20); // cut off mid GPS pool
    assert.doesNotThrow(() => extractExif(truncated));
  });

  test("an IFD entry only has a value, never leaks raw byte offsets as fields", () => {
    const buf = buildExifJpeg({ make: "Apple" });
    const meta = extractExif(buf);
    assert.deepEqual(Object.keys(meta).sort(), [
      "artist", "copyright", "dateTimeOriginal", "description", "gps", "make", "model", "software",
    ]);
  });
});

describe("formatExifSummary", () => {
  test("null metadata formats to null", () => {
    assert.equal(formatExifSummary(null), null);
  });

  test("renders camera, capture time, and a clickable GPS link", () => {
    const meta = extractExif(buildExifJpeg({
      make: "Apple", model: "iPhone 14 Pro", dateTimeOriginal: "2024:05:01 14:32:00",
      gps: { lat: 40.7128, lon: -74.006, altitude: 10 },
    }));
    const summary = formatExifSummary(meta);
    assert.match(summary, /Camera: Apple iPhone 14 Pro/);
    assert.match(summary, /Captured: 2024-05-01 14:32:00/);
    assert.match(summary, /GPS location: 40\.7128, -74\.006/);
    assert.match(summary, /openstreetmap\.org/);
  });

  test("omits fields that weren't present", () => {
    const meta = extractExif(buildExifJpeg({ make: "Sony", model: "A7IV" }));
    const summary = formatExifSummary(meta);
    assert.match(summary, /Camera: Sony A7IV/);
    assert.doesNotMatch(summary, /GPS/);
    assert.doesNotMatch(summary, /Captured/);
  });
});

// Encrypted, fully client-side chat history: every past conversation is
// stored in this browser's IndexedDB, AES-256-GCM encrypted with a key
// this module fetches from GET /api/history-key (src/history-key.js) and
// keeps ONLY in memory for the life of the page — never written to
// localStorage, sessionStorage, or IndexedDB itself.
//
// What this buys (documented in full for users at /help/):
//   - Offline extraction of this browser's storage (a stolen device, a
//     disk image) recovers only ciphertext — the key that unlocks it was
//     never persisted anywhere on disk.
//   - A server compromise recovers the server-side secret the key is
//     derived from, but never the ciphertext itself, since conversations
//     never leave this browser.
//   - History does not sync across browsers/devices — each one holds its
//     own encrypted copy — and clearing this browser's site data deletes
//     it for good; there is no server-side copy to recover it from.
//
// IndexedDB (not localStorage) because conversations — especially with
// attached images — can be large, and its async, structured API is the
// modern standard for exactly this amount of client-side data.

// Cloud copies (opt-in): when the account's server_history knob is ON
// (settings.js), every locally-saved record is ALSO mirrored — as the
// same opaque {iv, ciphertext} blob, still unreadable without the key —
// to the server's R2 store (src/storage.js), and deletes propagate. The
// local IndexedDB copy always stays (lazy cache + the only copy when the
// knob is off). Bulk moves in either direction live in sync.js; this
// module only dual-writes the record it just touched.
//
// THE ONE EXCEPTION — project chats rest READABLE, in both locations.
// Conversations inside a project are RAG-indexed (chat-rag.js) so the
// project's other chats can retrieve from them, and this app's storage
// rule is that indexed material rests readable (the index already holds
// its text in the clear — encrypting the record would protect nothing
// the index doesn't expose; same rule as RAG-indexed documents). Their
// records are stored as {data} instead of {iv, ciphertext}. Everything
// outside a project keeps the encrypted-always posture above.

import { serverHistoryOn } from "./settings.js";

const DB_NAME = "dr_history";
// v2 adds the "projects" store (public/js/projects.js): one encrypted
// record per project, same {iv, ciphertext} shape as a conversation.
const DB_VERSION = 2;
const STORE = "conversations";
const PROJECTS = "projects";

let dbPromise = null;
let keyPromise = null;

function openDb() {
  if (dbPromise) return dbPromise;
  dbPromise = new Promise((resolve, reject) => {
    const req = indexedDB.open(DB_NAME, DB_VERSION);
    req.onupgradeneeded = () => {
      const db = req.result;
      if (!db.objectStoreNames.contains(STORE)) {
        const store = db.createObjectStore(STORE, { keyPath: "id" });
        store.createIndex("updatedAt", "updatedAt");
      }
      if (!db.objectStoreNames.contains(PROJECTS)) {
        db.createObjectStore(PROJECTS, { keyPath: "id" });
      }
    };
    req.onsuccess = () => resolve(req.result);
    req.onerror = () => reject(req.error);
  });
  return dbPromise;
}

// Fetched once per page load and held only in this module-level variable —
// never written to disk-backed storage. A reload re-fetches it (cheap: one
// authenticated GET), which is the point — nothing persists at rest.
function historyKey() {
  if (!keyPromise) {
    keyPromise = fetch("/api/history-key")
      .then((res) => {
        if (!res.ok) throw new Error("history key unavailable");
        return res.json();
      })
      .then(({ key }) =>
        crypto.subtle.importKey("raw", base64ToBytes(key), { name: "AES-GCM" }, false, [
          "encrypt",
          "decrypt",
        ]),
      )
      .catch((err) => {
        keyPromise = null; // let a later call retry instead of caching the failure
        throw err;
      });
  }
  return keyPromise;
}

// Whether encrypted history is usable at all right now (server configured
// it, IndexedDB exists in this browser). The sidebar hides itself when this
// is false rather than offering a feature that silently can't persist.
export async function historyAvailable() {
  if (typeof indexedDB === "undefined") return false;
  try {
    await historyKey();
    return true;
  } catch {
    return false;
  }
}

async function encryptRecord(key, obj) {
  const iv = crypto.getRandomValues(new Uint8Array(12));
  const plain = new TextEncoder().encode(JSON.stringify(obj));
  const cipher = await crypto.subtle.encrypt({ name: "AES-GCM", iv }, key, plain);
  return { iv: bytesToBase64(iv), ciphertext: bytesToBase64(new Uint8Array(cipher)) };
}

async function decryptRecord(key, iv, ciphertext) {
  const plain = await crypto.subtle.decrypt(
    { name: "AES-GCM", iv: base64ToBytes(iv) },
    key,
    base64ToBytes(ciphertext),
  );
  return JSON.parse(new TextDecoder().decode(plain));
}

// Raw-bytes variants for original attached files (attachments.js /
// sync.js): same key, same AES-GCM, but binary in/out — the 12-byte IV is
// prepended to the ciphertext so one opaque byte blob is the whole stored
// form. Throws when the key is unavailable; callers must then store
// NOTHING rather than fall back to plaintext (same fail-closed rule as
// the conversation store).
export async function encryptBytes(buf) {
  const key = await historyKey();
  const iv = crypto.getRandomValues(new Uint8Array(12));
  const cipher = new Uint8Array(await crypto.subtle.encrypt({ name: "AES-GCM", iv }, key, buf));
  const out = new Uint8Array(12 + cipher.length);
  out.set(iv, 0);
  out.set(cipher, 12);
  return out;
}

export async function decryptBytes(bytes) {
  const key = await historyKey();
  const iv = bytes.slice(0, 12);
  return new Uint8Array(await crypto.subtle.decrypt({ name: "AES-GCM", iv }, key, bytes.slice(12)));
}

function reqToPromise(req) {
  return new Promise((resolve, reject) => {
    req.onsuccess = () => resolve(req.result);
    req.onerror = () => reject(req.error);
  });
}

// One stored row → its conversation data, whichever form it rests in:
// readable {data} for project chats (see the header), encrypted
// {iv, ciphertext} for everything else.
async function readRecordData(r) {
  if (r.data) return r.data;
  const key = await historyKey();
  return decryptRecord(key, r.iv, r.ciphertext);
}

// Sidebar listing: every encrypted conversation must be decrypted just to
// read its title (the title lives inside the ciphertext, same as the rest
// of the content — it can reveal the topic, so it isn't left in the
// clear). Fine at the scale a single person's chat history reaches; a
// record that fails to decrypt (corrupted, or encrypted under a
// since-rotated secret) is skipped rather than crashing the whole list.
/**
 * @returns {Promise<Array<{id: string, title: string, updatedAt: number,
 *   projectId: ?string}>>} newest first; undecryptable rows are skipped
 *   (counted by undecryptableConversations)
 */
export async function listConversations() {
  const db = await openDb();
  const records = await reqToPromise(db.transaction(STORE, "readonly").objectStore(STORE).getAll());
  const items = [];
  lastUndecryptable = 0;
  for (const r of records) {
    try {
      const data = await readRecordData(r);
      items.push({ id: r.id, title: data.title, updatedAt: r.updatedAt, projectId: r.projectId || null });
    } catch {
      // Undecryptable — leave it out of the list rather than break the
      // sidebar, but COUNT it so the sidebar can say "N conversations can't
      // be decrypted" instead of presenting a silently empty list (an
      // undecryptable store looks identical to an empty one otherwise —
      // that ambiguity cost real debugging time on 2026-07-08).
      lastUndecryptable++;
    }
  }
  items.sort((a, b) => b.updatedAt - a.updatedAt);
  return items;
}

// How many stored conversations the LAST listConversations() call had to
// skip because they wouldn't decrypt (corrupted, or written under a
// different key). 0 until a list has run.
let lastUndecryptable = 0;
export function undecryptableConversations() {
  return lastUndecryptable;
}

/**
 * @param {string} id
 * @returns {Promise<?object>} the decrypted conversation data (stream.js
 *   ConversationRecord), or null when no row exists
 */
export async function loadConversation(id) {
  const db = await openDb();
  const r = await reqToPromise(db.transaction(STORE, "readonly").objectStore(STORE).get(id));
  if (!r) return null;
  return readRecordData(r);
}

// data: {title, messages, model, budgetS, webSearch, createdAt, updatedAt,
// ragDocs, projectId}. The row keeps projectId OUTSIDE the ciphertext —
// LOCALLY ONLY (never uploaded; the cloud body below carries just the
// stored form + timestamps): it's a random uuid revealing grouping, not
// content, and sync needs it to honor a project's cloud-off knob without
// decrypting every record. A conversation WITH a projectId is a project
// chat — RAG-indexed for cross-chat retrieval, so its record rests
// readable ({data}) instead of encrypted (the header explains the rule).
// opts.cloud=false skips the cloud mirror even when the account knob is
// on — that's the per-project opt-out (public/js/projects.js decides).
/**
 * @param {string} id
 * @param {object} data  the conversation record (stream.js ConversationRecord)
 * @param {{cloud?: boolean}} [opts]
 */
export async function saveConversation(id, data, { cloud = true } = {}) {
  const db = await openDb();
  let stored;
  let body;
  if (data.projectId) {
    stored = { data };
    body = { data, updatedAt: data.updatedAt, createdAt: data.createdAt };
  } else {
    const key = await historyKey();
    const enc = await encryptRecord(key, data);
    stored = { iv: enc.iv, ciphertext: enc.ciphertext };
    body = { iv: enc.iv, ciphertext: enc.ciphertext, updatedAt: data.updatedAt, createdAt: data.createdAt };
  }
  const record = {
    id,
    updatedAt: data.updatedAt,
    projectId: data.projectId || null,
    ...stored,
  };
  await reqToPromise(
    db.transaction(STORE, "readwrite").objectStore(STORE).put(record),
  );
  // Cloud mirror (fire-and-forget): a failed push must never surface as a
  // chat error — sync.js reconciles by updatedAt on the next opportunity.
  if (serverHistoryOn() && cloud) {
    fetch("/api/convos/" + encodeURIComponent(id), {
      method: "PUT",
      headers: { "content-type": "application/json" },
      body: JSON.stringify(body),
    }).catch(() => {});
  }
}

export async function deleteConversation(id) {
  const db = await openDb();
  await reqToPromise(db.transaction(STORE, "readwrite").objectStore(STORE).delete(id));
  if (serverHistoryOn()) {
    fetch("/api/convos/" + encodeURIComponent(id), { method: "DELETE" }).catch(() => {});
  }
}

// ---- raw (storage-form) record access for sync.js ---------------------------
// Sync moves records in their stored form as-is — ciphertext blobs without
// a decrypt/re-encrypt round trip (no need for the key on the bulk path),
// readable {data} records (project chats) verbatim.

export async function exportEncryptedRecords() {
  const db = await openDb();
  const records = await reqToPromise(db.transaction(STORE, "readonly").objectStore(STORE).getAll());
  return records.map((r) => ({
    id: r.id,
    updatedAt: r.updatedAt,
    projectId: r.projectId || null,
    iv: r.iv,
    ciphertext: r.ciphertext,
    data: r.data,
  }));
}

// Imports one server-side record (either stored form), last-write-wins by
// updatedAt. Returns true when the local store actually changed. For an
// encrypted record the projectId row field is recovered by decrypting the
// incoming blob (this device has the key) — the cloud copy deliberately
// doesn't carry it in the clear; a readable project-chat record carries it
// in its data.
/**
 * @param {string} id
 * @param {object} record  server-side stored form ({iv, ciphertext} or {data})
 * @returns {Promise<boolean>} true when the local store actually changed
 */
export async function importEncryptedRecord(id, record) {
  const isPlain = record?.data && typeof record.data === "object";
  if (!isPlain && (!record?.iv || !record?.ciphertext)) return false;
  const db = await openDb();
  const existing = await reqToPromise(db.transaction(STORE, "readonly").objectStore(STORE).get(id));
  const updatedAt = Number(record.updatedAt) || 0;
  if (existing && existing.updatedAt >= updatedAt) return false;
  let projectId = existing?.projectId || null;
  let stored;
  if (isPlain) {
    projectId = record.data.projectId || null;
    stored = { data: record.data };
  } else {
    stored = { iv: record.iv, ciphertext: record.ciphertext };
    try {
      const key = await historyKey();
      const data = await decryptRecord(key, record.iv, record.ciphertext);
      projectId = data.projectId || null;
    } catch {
      // Undecryptable content still imports (it may decrypt after a key
      // becomes available again); it just can't be project-scoped yet.
    }
  }
  await reqToPromise(
    db
      .transaction(STORE, "readwrite")
      .objectStore(STORE)
      .put({ id, updatedAt, projectId, ...stored }),
  );
  return true;
}

// ---- project records (public/js/projects.js owns the shape) ----------------
// Same encrypted-record pattern as conversations, in their own store and
// their own R2 family. `data`: {name, files, notes?, serverStorage,
// createdAt, updatedAt} — everything, name included, inside the ciphertext.

export async function saveProjectRecord(id, data, { cloud = true } = {}) {
  const key = await historyKey();
  const db = await openDb();
  const enc = await encryptRecord(key, data);
  await reqToPromise(
    db
      .transaction(PROJECTS, "readwrite")
      .objectStore(PROJECTS)
      .put({ id, updatedAt: data.updatedAt, iv: enc.iv, ciphertext: enc.ciphertext }),
  );
  if (serverHistoryOn() && cloud) {
    fetch("/api/projects/" + encodeURIComponent(id), {
      method: "PUT",
      headers: { "content-type": "application/json" },
      body: JSON.stringify({
        iv: enc.iv,
        ciphertext: enc.ciphertext,
        updatedAt: data.updatedAt,
        createdAt: data.createdAt,
      }),
    }).catch(() => {});
  }
}

export async function listProjectRecords() {
  const key = await historyKey();
  const db = await openDb();
  const records = await reqToPromise(
    db.transaction(PROJECTS, "readonly").objectStore(PROJECTS).getAll(),
  );
  const items = [];
  for (const r of records) {
    try {
      items.push({ id: r.id, ...(await decryptRecord(key, r.iv, r.ciphertext)) });
    } catch {
      // Undecryptable — skip rather than break the projects list.
    }
  }
  items.sort((a, b) => (b.updatedAt || 0) - (a.updatedAt || 0));
  return items;
}

export async function deleteProjectRecord(id, { cloud = true } = {}) {
  const db = await openDb();
  await reqToPromise(db.transaction(PROJECTS, "readwrite").objectStore(PROJECTS).delete(id));
  if (serverHistoryOn() && cloud) {
    fetch("/api/projects/" + encodeURIComponent(id), { method: "DELETE" }).catch(() => {});
  }
}

export async function exportEncryptedProjectRecords() {
  const db = await openDb();
  const records = await reqToPromise(
    db.transaction(PROJECTS, "readonly").objectStore(PROJECTS).getAll(),
  );
  return records.map((r) => ({ id: r.id, updatedAt: r.updatedAt, iv: r.iv, ciphertext: r.ciphertext }));
}

export async function importEncryptedProjectRecord(id, record) {
  if (!record?.iv || !record?.ciphertext) return false;
  const db = await openDb();
  const existing = await reqToPromise(
    db.transaction(PROJECTS, "readonly").objectStore(PROJECTS).get(id),
  );
  const updatedAt = Number(record.updatedAt) || 0;
  if (existing && existing.updatedAt >= updatedAt) return false;
  await reqToPromise(
    db
      .transaction(PROJECTS, "readwrite")
      .objectStore(PROJECTS)
      .put({ id, updatedAt, iv: record.iv, ciphertext: record.ciphertext }),
  );
  return true;
}

function bytesToBase64(bytes) {
  let binary = "";
  for (const b of bytes) binary += String.fromCharCode(b);
  return btoa(binary);
}

function base64ToBytes(b64) {
  const binary = atob(b64);
  const bytes = new Uint8Array(binary.length);
  for (let i = 0; i < binary.length; i++) bytes[i] = binary.charCodeAt(i);
  return bytes;
}

// Left-side "chat history" drawer: lists this browser's locally-stored,
// encrypted past conversations (public/js/history-store.js) — labelled by
// their first question, clickable to reopen, renamable, deletable. The
// header's history button hides itself entirely when encrypted history
// isn't available (server not configured, or no IndexedDB) rather than
// offering a feature that silently can't persist anything.

import { escapeHtml } from "./notifications.js";
import {
  deleteConversation,
  historyAvailable,
  listConversations,
  loadConversation,
  saveConversation,
  undecryptableConversations,
} from "./history-store.js";
import { renderProjectsList } from "./projects-ui.js";
import { loadSettings, serverHistoryOn, settingsLoaded, storageAvailable } from "./settings.js";
import { applyLoadedConversation, currentConversationId } from "./stream.js";
import { pullNewer } from "./sync.js";

/**
 * Wires the history drawer once at boot. Both callbacks come from app.js,
 * which owns the composer state (model/budget/search-toggle) this module
 * has no access to.
 * @param {{onNew?: () => void, onLoad?: (record: object) => void}} [opts]
 *   onLoad receives the opened conversation record (stream.js
 *   ConversationRecord) so app.js can restore its send settings
 * @returns {{onSaved: (id?: string) => void}} hook stream.js calls after
 *   every autosaved turn
 */
export function initHistorySidebar(opts = {}) {
  const btn = document.getElementById("historybtn");
  const overlay = document.getElementById("historysidebar");
  const list = document.getElementById("historylist");
  const closeBtn = document.getElementById("historyclose");
  const newBtn = document.getElementById("historynewbtn");
  const onNew = opts.onNew || (() => {});
  const onLoad = opts.onLoad || (() => {});

  historyAvailable().then((ok) => { btn.hidden = !ok; });

  // Diagnostic note under the list: an empty pane must SAY why it's empty
  // (records that won't decrypt, a cloud restore in progress) instead of
  // looking identical to "no chats saved" — that silent ambiguity cost
  // real debugging time on 2026-07-08.
  const note = document.createElement("p");
  note.className = "history-note";
  note.hidden = true;
  list.after(note);
  let baseNote = "";
  let pulling = false;
  let lastPull = null; // result of this pane-open's pullNewer, once it lands
  function updateNote() {
    const text = pulling ? "Checking the cloud for conversations…" : baseNote;
    note.textContent = text;
    note.hidden = !text;
  }

  async function refresh() {
    list.innerHTML = '<p class="muted">Loading…</p>';
    renderProjectsList().catch(() => {});
    const items = await listConversations();
    // Project conversations live inside their project's panel — the main
    // list shows plain chats only, so nothing appears twice.
    const plain = items.filter((c) => !c.projectId);
    renderList(plain);

    // An empty (or thinned) pane must explain itself — every silent branch
    // here has been mistaken for data loss at least once (2026-07-08).
    const parts = [];
    const skipped = undecryptableConversations();
    if (skipped) {
      parts.push(`${skipped} saved conversation${skipped === 1 ? "" : "s"} can't be decrypted on this device right now — not deleted, just unreadable with the current key. Reload the page (signed in) and reopen this panel to retry.`);
    }
    if (!plain.length) {
      const projectChats = items.length - plain.length;
      if (projectChats) parts.push(`${projectChats} conversation${projectChats === 1 ? " lives" : "s live"} inside projects — open the project to see them.`);
      if (!settingsLoaded()) parts.push("Account settings couldn't be loaded, so cloud copies weren't checked — reload the page to retry.");
      else if (!storageAvailable()) parts.push("Cloud storage isn't available for this account, so only this device's copies can be shown.");
      else if (!serverHistoryOn()) parts.push("Cloud backup is switched off in Settings, so only this device's copies can be shown.");
      else if (lastPull) {
        if (lastPull.failed) parts.push(`Cloud restore incomplete: ${lastPull.pulled} restored, ${lastPull.failed} failed — reopen this panel to retry.`);
        else if (lastPull.checked && lastPull.pulled) parts.push(`${lastPull.pulled} conversation${lastPull.pulled === 1 ? " was" : "s were"} restored from the cloud but this device's storage didn't keep them — fully close and reopen the app, then reopen this panel.`);
        else if (lastPull.checked) parts.push(`The cloud holds ${lastPull.checked} conversation${lastPull.checked === 1 ? "" : "s"} but none could be restored here — fully close and reopen the app, then reopen this panel.`);
      }
    }
    // Always-on one-line status: which build this is and what this device
    // actually holds — the ground truth that a screenshot of the pane can
    // carry to a debugging session (a stale cached client, the leading
    // suspect for "works in tests, empty on the phone", outs itself by
    // showing no stamp at all).
    const pullBit = lastPull
      ? ` · cloud: ${lastPull.checked} checked, ${lastPull.pulled} restored${lastPull.failed ? `, ${lastPull.failed} failed` : ""}`
      : pulling ? " · cloud: checking…" : "";
    // Compact always-on status stamp (build marker + what this device
    // holds + the cloud pull's outcome). Deliberately kept after the
    // 2026-07-08 debugging marathon: it costs one muted line and turns
    // any user screenshot into a build/data report — see the
    // on-device-trace skill before removing it.
    parts.push(`[h21 · ${plain.length} here${items.length - plain.length ? ` + ${items.length - plain.length} in projects` : ""}${skipped ? ` + ${skipped} unreadable` : ""}${pullBit}${cssBit()}]`);
    baseNote = parts.join(" ");
    updateNote();
  }

  // Stylesheet freshness — checked HERE (not only in app.js) because a
  // wedged device can hold a stale module MIX where app.js (and its
  // handshake) is old while this module is current. A mismatched
  // stylesheet gets one force-refresh per page load, and the stamp
  // shows what was seen so the state is visible in any report.
  const CSS_WANT = "h21";
  let cssFixTried = false;
  function cssBit() {
    let seen = "";
    try {
      seen = getComputedStyle(document.documentElement).getPropertyValue("--css-version").trim();
    } catch { /* leave empty */ }
    if (seen === CSS_WANT) return "";
    if (!cssFixTried) {
      cssFixTried = true;
      fetch("/css/app.css", { cache: "reload" })
        .then(() => {
          const link = document.querySelector('link[rel="stylesheet"][href*="app.css"]');
          if (link) link.href = "/css/app.css?v=" + CSS_WANT;
          setTimeout(() => { if (!overlay.hidden) refresh(); }, 400);
        })
        .catch(() => {});
    }
    return ` · css ${seen || "old"}→refreshing`;
  }

  const PENCIL_SVG =
    '<svg width="15" height="15" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round" aria-hidden="true"><path d="M17 3a2.85 2.83 0 1 1 4 4L7.5 20.5 2 22l1.5-5.5Z"/><path d="m15 5 4 4"/></svg>';
  const TRASH_SVG =
    '<svg width="15" height="15" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round" aria-hidden="true"><path d="M3 6h18"/><path d="M19 6v14a2 2 0 0 1-2 2H7a2 2 0 0 1-2-2V6"/><path d="M8 6V4a2 2 0 0 1 2-2h4a2 2 0 0 1 2 2v2"/><line x1="10" y1="11" x2="10" y2="17"/><line x1="14" y1="11" x2="14" y2="17"/></svg>';

  function renderList(items) {
    if (!items.length) {
      list.innerHTML = '<p class="muted">No saved conversations yet.</p>';
      return;
    }
    const activeId = currentConversationId();
    // At REST a chat row contains ONLY the open button — the exact
    // structure of a project row. That's load-bearing on iOS: rows that
    // permanently carry an absolutely-positioned (even invisible) action
    // strip inside the backdrop-filtered panel render INVISIBLE on real
    // iOS Safari (2026-07-08 device incident; Linux WebKit can't
    // reproduce it). The strip is mounted lazily by attachSwipe when a
    // swipe or hover actually happens, and removed again on close.
    list.innerHTML = items
      .map(
        (c) => `
      <div class="history-item${c.id === activeId ? " active" : ""}" data-id="${c.id}">
        <button type="button" class="history-open" data-id="${c.id}">
          <span class="history-title">${escapeHtml(c.title)}</span>
          <span class="history-when">${relativeTime(c.updatedAt)}</span>
        </button>
      </div>`,
      )
      .join("");

    list.querySelectorAll(".history-item").forEach(attachSwipe);
    list.querySelectorAll(".history-open").forEach((el) => {
      el.addEventListener("click", () => {
        // A tap on a swiped-open row (or right after a swipe gesture)
        // just closes the actions — it shouldn't also open the chat.
        const item = el.closest(".history-item");
        if (item.dataset.swipeLock === "1" || item.classList.contains("swiped")) {
          delete item.dataset.swipeLock;
          closeActions(item);
          return;
        }
        openConversation(el.dataset.id);
      });
    });
  }

  // Mount the rename/delete strip into a row on demand (see renderList's
  // comment for why it can't live in the markup permanently). EVERY
  // style the interaction depends on is INLINE: a device wedged on a
  // stale cached stylesheet (2026-07-08: one had a pre-swipe app.css
  // that knew no .history-actions layout — the strip rendered as a
  // plain block and shoved the card downward, with the buttons hidden
  // by an old opacity rule) must still get a working, correctly-laid-
  // out swipe. The classes remain for fresh-CSS cosmetics only.
  const BTN_CSS =
    "flex:none;width:36px;height:36px;border-radius:10px;display:grid;" +
    "place-items:center;padding:0;background:rgba(255,255,255,.45);" +
    "border:1px solid rgba(255,255,255,.55);opacity:1;";
  function mountActions(item) {
    let strip = item.querySelector(".history-actions");
    if (strip) return strip;
    strip = document.createElement("div");
    strip.className = "history-actions";
    strip.style.cssText =
      "position:absolute;top:0;right:0;bottom:0;width:88px;display:flex;" +
      "align-items:center;justify-content:flex-end;gap:.35rem;" +
      "padding-right:.2rem;margin:0;opacity:0;pointer-events:none;";
    strip.innerHTML =
      `<button type="button" class="history-rename" style="${BTN_CSS}color:#2f5d8e;" title="Rename" aria-label="Rename conversation">${PENCIL_SVG}</button>` +
      `<button type="button" class="history-delete" style="${BTN_CSS}color:#d64545;" title="Delete" aria-label="Delete conversation">${TRASH_SVG}</button>`;
    const id = item.dataset.id;
    strip.querySelector(".history-rename").addEventListener("click", (e) => {
      e.stopPropagation();
      renameConversation(id);
    });
    strip.querySelector(".history-delete").addEventListener("click", (e) => {
      e.stopPropagation();
      removeConversation(id);
    });
    item.insertBefore(strip, item.firstChild);
    return strip;
  }
  function showStrip(strip, on) {
    if (!strip) return;
    strip.style.opacity = on ? "1" : "0";
    strip.style.pointerEvents = on ? "auto" : "none";
  }

  // Slide the card back (if it's out) and restore the rest-state DOM
  // once the settle animation has finished. All inline styles — see
  // mountActions for why nothing here may depend on the stylesheet.
  function closeActions(item) {
    const row = item.querySelector(".history-open");
    showStrip(item.querySelector(".history-actions"), false);
    if (item.classList.contains("swiped")) {
      item.classList.remove("swiped");
      row.style.transition = "margin-left .18s ease";
      row.style.marginLeft = "0px";
    }
    setTimeout(() => {
      if (item.classList.contains("swiped")) return; // re-opened meanwhile
      item.classList.remove("swiping");
      row.style.transition = "";
      row.style.marginLeft = "";
      item.style.overflow = "";
      const strip = item.querySelector(".history-actions");
      // The :hover exception only applies where hover is REAL: on iOS the
      // emulated hover sticks to the last-touched card for seconds
      // (device trace: mouseleave arrived 14s after the gesture), which
      // kept dead strips mounted.
      if (strip && !(HAS_HOVER && item.matches(":hover"))) strip.remove();
    }, 200);
  }

  // Whether this device has a real hover state (a mouse). iOS reports
  // hover:none but still fires mouse-compat events on taps — attaching
  // hover handlers there turned strips visibly ON at every tap and left
  // them stuck until the emulated hover finally moved (device trace,
  // 2026-07-08).
  const HAS_HOVER = typeof matchMedia === "function" && matchMedia("(hover: hover)").matches;

  // Touch swipe-to-reveal: dragging a row left slides it over by the
  // action strip's width, exposing rename + delete. Swiping back (or
  // tapping the row, or swiping any other row) closes it. Mouse users
  // keep the hover reveal; this only drives touch/pen. The card follows
  // the finger via inline margin-left — pure layout, NEVER transform
  // (transforms on these rows break painting on real iOS, see app.css) —
  // then settles parked at -REVEAL_PX (.swiped) or back at rest, where
  // every interaction artifact (strip, clip, margin) is removed again.
  //
  // GESTURE PLUMBING (2026-07-08, real-device iteration 5): on real iOS
  // Safari the drag must be driven by TOUCH events with preventDefault()
  // once horizontal intent is detected. Pointer events + touch-action:
  // pan-y are NOT honored for a horizontal drag inside this vertically
  // scrollable panel — iOS starts a native scroll (the list visibly
  // nudges a few px), fires pointercancel, and never delivers the moves,
  // so the card never slides. Synthetic-event tests can't catch this
  // (they bypass native gesture arbitration); only a real device shows it.
  const REVEAL_PX = 88; // matches .history-actions width in app.css
  function attachSwipe(item) {
    const row = item.querySelector(".history-open");
    let startX = 0, startY = 0, axis = null, tracking = false;

    function claim() {
      // Mark the gesture so the tap that may follow doesn't open the chat.
      item.dataset.swipeLock = "1";
      mountActions(item);
      item.classList.add("swiping");
      item.style.overflow = "hidden";
      // Close any other card that's sitting open.
      list.querySelectorAll(".history-item.swiped").forEach((other) => {
        if (other !== item) closeActions(other);
      });
    }

    function drag(dx) {
      const from = item.classList.contains("swiped") ? -REVEAL_PX : 0;
      const offset = Math.max(-REVEAL_PX, Math.min(0, from + dx));
      row.style.transition = "none"; // follow the finger, no easing lag
      row.style.marginLeft = offset + "px";
      // The strip (painting above the static card) fades in as the gap opens.
      const strip = item.querySelector(".history-actions");
      if (strip) strip.style.opacity = String(Math.min(1, -offset / REVEAL_PX));
    }

    function finish(dx, aborted) {
      const from = item.classList.contains("swiped") ? -REVEAL_PX : 0;
      const offset = aborted ? 0 : from + dx;
      if (offset < -REVEAL_PX / 2) {
        row.style.transition = "margin-left .18s ease";
        row.style.marginLeft = -REVEAL_PX + "px";
        item.classList.add("swiped");
        showStrip(item.querySelector(".history-actions"), true);
        setTimeout(() => { item.classList.remove("swiping"); }, 200);
      } else {
        closeActions(item);
      }
      // Let the click that follows the gesture see the lock, then clear it.
      setTimeout(() => { delete item.dataset.swipeLock; }, 0);
    }

    function moveLogic(dx, dy, preventDefaultFn) {
      if (!axis) {
        if (Math.abs(dx) < 8 && Math.abs(dy) < 8) return;
        axis = Math.abs(dx) > Math.abs(dy) ? "x" : "y";
        if (axis === "x") claim();
      }
      if (axis !== "x") return;
      preventDefaultFn(); // keep iOS from stealing the gesture for scroll
      drag(dx);
    }

    if ("ontouchstart" in window) {
      // iOS choreography (real-device iteration 6): ALL DOM/style
      // mutations happen at TOUCHSTART — mounting the strip or toggling
      // overflow once the finger is moving makes iOS CANCEL the active
      // touch (h7–h10: strip flashed, card snapped back, list nudged).
      // The axis is decided at ~4px of movement — before iOS's own
      // ~10px scroll slop commits — and the first claimed move calls
      // preventDefault() so the panel never starts scrolling. A
      // touchcancel after the claim honors the drag done so far
      // instead of snapping back.
      let lastDx = 0;
      // Undo the touchstart pre-mutations for a gesture that turned out
      // to be a tap or a vertical scroll — nothing visible ever changed.
      function releaseRest() {
        if (item.classList.contains("swiped") || item.classList.contains("swiping")) return;
        item.style.overflow = "";
        const strip = item.querySelector(".history-actions");
        if (strip && !(HAS_HOVER && item.matches(":hover"))) strip.remove();
      }
      item.addEventListener("touchstart", (e) => {
        if (e.touches.length !== 1) return;
        tracking = true;
        axis = null;
        lastDx = 0;
        startX = e.touches[0].clientX;
        startY = e.touches[0].clientY;
        mountActions(item);
        item.style.overflow = "hidden";
      }, { passive: true });
      // passive: false — preventDefault() must actually work here.
      item.addEventListener("touchmove", (e) => {
        if (!tracking || e.touches.length !== 1) return;
        const t = e.touches[0];
        const dx = t.clientX - startX;
        const dy = t.clientY - startY;
        if (!axis) {
          if (Math.abs(dx) < 4 && Math.abs(dy) < 4) return;
          axis = Math.abs(dx) >= Math.abs(dy) ? "x" : "y";
          if (axis === "x") {
            item.dataset.swipeLock = "1";
            item.classList.add("swiping");
            list.querySelectorAll(".history-item.swiped").forEach((other) => {
              if (other !== item) closeActions(other);
            });
          } else {
            releaseRest(); // vertical: hand the gesture back to the scroller
            // iOS-Mail convention: scrolling the list closes any card
            // that's sitting open, so its buttons never linger while the
            // user has visibly moved on.
            list.querySelectorAll(".history-item.swiped").forEach((other) => {
              if (other !== item) closeActions(other);
            });
          }
        }
        if (axis !== "x") return;
        if (e.cancelable) e.preventDefault();
        lastDx = dx;
        drag(dx);
      }, { passive: false });
      const end = () => {
        if (!tracking) return;
        tracking = false;
        if (axis === "x") finish(lastDx, false);
        else releaseRest();
      };
      item.addEventListener("touchend", end);
      item.addEventListener("touchcancel", end);
    } else {
      item.addEventListener("pointerdown", (e) => {
        if (e.pointerType === "mouse") return;
        tracking = true;
        axis = null;
        startX = e.clientX;
        startY = e.clientY;
      });
      item.addEventListener("pointermove", (e) => {
        if (!tracking) return;
        moveLogic(e.clientX - startX, e.clientY - startY, () => {});
      });
      const settle = (e) => {
        if (!tracking) return;
        tracking = false;
        if (axis !== "x") return;
        // pointercancel's coordinates are unreliable: treat as aborted.
        finish(e.clientX - startX, e.type === "pointercancel");
      };
      item.addEventListener("pointerup", settle);
      item.addEventListener("pointercancel", settle);
    }

    // Mouse hover shows the strip as an overlay (no slide); leaving
    // removes it again (unless swiped open). ONLY on real-hover devices:
    // iOS fires these as tap-compat events — attaching them there showed
    // strips on every tap and left them stuck until the sticky emulated
    // hover moved on (device trace, 2026-07-08).
    if (HAS_HOVER) {
      item.addEventListener("mouseenter", () => {
        showStrip(mountActions(item), true);
      });
      item.addEventListener("mouseleave", () => {
        if (!item.classList.contains("swiped")) closeActions(item);
      });
    }
  }

  async function openConversation(id) {
    const record = await loadConversation(id);
    if (!record) return;
    applyLoadedConversation({ ...record, id });
    onLoad(record);
    close();
  }

  async function renameConversation(id) {
    const record = await loadConversation(id);
    if (!record) return;
    const name = prompt("Rename conversation", record.title);
    if (!name || !name.trim()) return;
    await saveConversation(id, { ...record, title: name.trim().slice(0, 60) });
    refresh();
  }

  async function removeConversation(id) {
    if (!confirm("Delete this conversation? This can't be undone.")) return;
    await deleteConversation(id);
    if (id === currentConversationId()) onNew();
    refresh();
  }

  // Pin the drawer's ✕ to the exact screen rect of the header's history
  // button, so on a phone the same tap position opens and closes the
  // drawer (the fixed-position styling lives in app.css).
  function placeCloseBtn() {
    const r = btn.getBoundingClientRect();
    if (!r.width) return; // button hidden/unlaid-out: keep the CSS fallback
    closeBtn.style.top = r.top + "px";
    closeBtn.style.left = r.left + "px";
    closeBtn.style.width = r.width + "px";
    closeBtn.style.height = r.height + "px";
  }

  // Slide animation (app.css): .open drives the panel/backdrop transition;
  // hidden is only flipped once the slide-out has finished so the drawer
  // animates instead of popping. Kept at ~180ms — fast, just not abrupt.
  const ANIM_MS = 200;
  let hideTimer = null;

  function open() {
    clearTimeout(hideTimer);
    placeCloseBtn();
    overlay.hidden = false;
    // Two frames so the browser paints the closed state first — adding
    // .open in the same frame would skip the transition entirely.
    requestAnimationFrame(() => requestAnimationFrame(() => overlay.classList.add("open")));
    refresh();
    // Cloud-storage accounts: fetch anything newer written from another
    // device (no-op while the knob is off) and re-render if it actually
    // brought something down. Visible while it runs — a device restoring
    // its whole history pulls for several seconds and must not read as
    // "no saved conversations" meanwhile.
    lastPull = null;
    if (serverHistoryOn()) {
      pulling = true;
      updateNote();
      pullNewer()
        .then((res) => { lastPull = res; })
        .catch(() => { lastPull = { ran: true, checked: 0, pulled: 0, failed: 1 }; })
        .finally(() => {
          pulling = false;
          // Re-render regardless of the count: the note must reflect the
          // pull's outcome (including "nothing came down"), not just its
          // successes. But NEVER rebuild the list mid-interaction — a
          // re-render destroys the card the finger is dragging (observed
          // as the card "switching places" on a real device).
          if (!overlay.hidden && !list.querySelector(".swiping, .swiped")) refresh();
          else updateNote();
        });
    } else if (settingsLoaded() === false) {
      // Settings never loaded (likely an auth/network failure at boot) —
      // retry now so a recovered session heals without a full reload.
      loadSettings(true)
        .then(() => { if (!overlay.hidden) open(); })
        .catch(() => { if (!overlay.hidden) refresh(); });
    }
  }
  function close() {
    overlay.classList.remove("open");
    clearTimeout(hideTimer);
    hideTimer = setTimeout(() => { overlay.hidden = true; }, ANIM_MS);
  }

  btn.addEventListener("click", open);
  closeBtn.addEventListener("click", close);
  newBtn.addEventListener("click", () => {
    onNew();
    close();
  });
  overlay.addEventListener("click", (e) => {
    if (e.target === overlay) close();
  });
  window.addEventListener("resize", () => {
    if (!overlay.hidden) placeCloseBtn();
  });

  return {
    // stream.js calls this after every autosaved turn — refresh the list
    // (and the active highlight) only if the panel is actually open (and
    // no card is mid-swipe — a rebuild would destroy it under the finger),
    // so a background chat doesn't do decrypt-everything work for no reason.
    onSaved: () => {
      if (!overlay.hidden && !list.querySelector(".swiping, .swiped")) refresh();
    },
  };
}

function relativeTime(ts) {
  const mins = Math.round((Date.now() - ts) / 60000);
  if (mins < 1) return "just now";
  if (mins < 60) return mins + "m ago";
  const hours = Math.round(mins / 60);
  if (hours < 24) return hours + "h ago";
  const days = Math.round(hours / 24);
  if (days < 7) return days + "d ago";
  return new Date(ts).toLocaleDateString();
}

// @ts-check
// The conversation-level IMAGE DECK (requested 2026-07-09): every Street
// View frame / map image a reply shows joins one ordered, conversation-wide
// deck. Clicking a thumbnail (in a frames strip, or a waypoint miniature on
// the interactive map) opens the deck's LIGHTBOX: the image enlarged, ‹/›
// navigation through every image the conversation has produced so far, a
// miniature map in the upper-left corner of the current image's position
// (clicking it opens actual Google Maps), and a per-image chat panel —
// asking there anchors the next message AT that image's position, so the
// conversation continues from that point on the map (the same map_view
// anchor mechanism the live interactive map uses; activity.js/app.js wire
// the handler).
//
// The deck is live-session only, like the frame strips themselves (data
// URLs are never persisted — a reloaded conversation keeps answers and
// links, not imagery). The registry/order/nearest-lookup core is pure and
// import-safe in Node (no DOM until the lightbox opens) — unit-tested in
// imagedeck.test.js.

// ---- pure core -----------------------------------------------------------------

/**
 * One deck image, in conversation order. Coordinates are null when the
 * frame carried none (older servers / map-kind frames) — the lightbox then
 * hides the mini-map.
 * @typedef {object} DeckEntry
 * @property {string} url data: image URL
 * @property {string} caption
 * @property {number | null} lat
 * @property {number | null} lng
 * @property {number} heading the frame's viewing direction (degrees)
 * @property {"photo" | "map"} kind
 */

/**
 * The position payload an ask-from-this-image sends along — the map_view
 * anchor stream.js attaches to the outgoing message.
 * @typedef {{lat: number, lng: number, heading: number, kind: "photo" | "map"}} DeckPoint
 */

/** @type {DeckEntry[]} */
let entries = []; // conversation order

export function resetDeck() {
  entries = [];
  closeDeck();
}

/** @returns {DeckEntry[]} */
export function deckEntries() {
  return entries;
}

/**
 * Registers a reply's images (already validated data URLs). Returns the
 * index of the first added entry so callers can open the deck at the
 * clicked thumbnail.
 * @param {Array<{url?: unknown, caption?: string, lat?: unknown, lng?: unknown, heading?: unknown, kind?: string}> | null | undefined} frames
 * @returns {number}
 */
export function addDeckEntries(frames) {
  const start = entries.length;
  for (const f of Array.isArray(frames) ? frames : []) {
    if (typeof f?.url !== "string" || !f.url.startsWith("data:image/")) continue;
    const lat = Number(f.lat);
    const lng = Number(f.lng);
    const heading = Number(f.heading);
    entries.push({
      url: f.url,
      caption: f.caption || "",
      lat: Number.isFinite(lat) ? lat : null,
      lng: Number.isFinite(lng) ? lng : null,
      // The frame's viewing direction — lets an ask-from-this-image
      // reproduce EXACTLY this view as the POV anchor.
      heading: Number.isFinite(heading) ? heading : 0,
      kind: f.kind === "map" ? "map" : "photo",
    });
  }
  return start;
}

/**
 * Keyless Google Maps embed URL — the classic `output=embed` surface, which
 * needs NO API key or service enablement (it 301s to google.com/maps/embed
 * and renders a normal navigable map). The key-based Embed API
 * (embed/v1/*) is deliberately NOT used for the mini-map: when the site's
 * key lacks the "Maps Embed API" service, embed/v1 renders a WHITE
 * rejection page that is undetectable from outside the iframe — observed
 * live 2026-07-09 (chat_logs #170/#171, "mini image in maps view is just
 * white") while the very same key served the JS SDK and Static Maps fine.
 * Pure — unit-tested in imagedeck.test.js.
 * @param {number} lat
 * @param {number} lng
 * @param {number} [zoom]
 * @returns {string}
 */
export function keylessMapEmbedUrl(lat, lng, zoom = 16) {
  return `https://maps.google.com/maps?${new URLSearchParams({
    q: `${lat},${lng}`,
    z: String(Math.round(Number(zoom) || 16)),
    output: "embed",
  })}`;
}

/**
 * Keyless Street View embed — same rationale and surface as
 * keylessMapEmbedUrl (the classic output=svembed form, 301s to
 * google.com/maps/embed with the panorama params). The cbp pitch field is
 * INVERTED relative to the SDK's pitch (verified against the embed?pb
 * redirect: cbp …,-10 → pb 4f10), hence the negation. Pure — unit-tested.
 * @param {number} lat
 * @param {number} lng
 * @param {number} [heading]
 * @param {number} [pitch]
 * @returns {string}
 */
export function keylessStreetViewEmbedUrl(lat, lng, heading = 0, pitch = 0) {
  return `https://maps.google.com/maps?${new URLSearchParams({
    layer: "c",
    cbll: `${lat},${lng}`,
    cbp: `11,${Math.round(Number(heading) || 0)},0,0,${-Math.round(Number(pitch) || 0)}`,
    output: "svembed",
  })}`;
}

/**
 * Equirectangular meters — same approximation as the server's
 * distanceMeters (src/googlemaps-text.js).
 * @param {number} lat1
 * @param {number} lng1
 * @param {number} lat2
 * @param {number} lng2
 */
function metersBetween(lat1, lng1, lat2, lng2) {
  const rad = Math.PI / 180;
  const x = (lng2 - lng1) * rad * Math.cos(((lat1 + lat2) / 2) * rad);
  const y = (lat2 - lat1) * rad;
  return Math.sqrt(x * x + y * y) * 6371000;
}

/**
 * The LATEST deck image at (or within maxM of) a position — "clicking a
 * waypoint miniature takes you to that image in the deck up to that point":
 * among the images within the radius, the most RECENT visit wins (not the
 * geometrically closest — an early exact-position image must not shadow a
 * later revisit), so the deck opens on the image the user last saw there.
 * Pure.
 * @param {number} lat
 * @param {number} lng
 * @param {number} [maxM]
 * @returns {number} deck index, or -1 when nothing is near
 */
export function nearestDeckIndex(lat, lng, maxM = 30) {
  let best = -1;
  for (let i = 0; i < entries.length; i++) {
    const e = entries[i];
    if (e.lat == null || e.lng == null) continue;
    if (metersBetween(e.lat, e.lng, lat, lng) <= maxM) best = i;
  }
  return best;
}

// ---- lightbox (DOM from here down) ----------------------------------------------

/** @type {((text: string, point: DeckPoint | null) => void) | null} */
let askHandler = null; // wired by app.js

/** @param {(text: string, point: DeckPoint | null) => void} fn */
export function onDeckAsk(fn) {
  askHandler = fn;
}

/** @type {HTMLElement | null} */
let overlay = null;
let current = 0;

export function closeDeck() {
  if (overlay) {
    overlay.remove();
    overlay = null;
    document.removeEventListener("keydown", onKey);
  }
}

/** @param {KeyboardEvent} e */
function onKey(e) {
  if (e.key === "Escape") closeDeck();
  else if (e.key === "ArrowLeft") show(current - 1);
  else if (e.key === "ArrowRight") show(current + 1);
}

/** @type {(lat: number, lng: number) => string} */
const mapsLink = (lat, lng) => `https://www.google.com/maps/search/?api=1&query=${lat},${lng}`;

/** @param {number} index */
function show(index) {
  const box = overlay;
  if (!box || !entries.length) return;
  current = Math.max(0, Math.min(entries.length - 1, index));
  const e = entries[current];
  /** @type {HTMLImageElement} */ (box.querySelector(".imagedeck-img")).src = e.url;
  /** @type {HTMLElement} */ (box.querySelector(".imagedeck-caption")).textContent =
    e.caption || (e.kind === "map" ? "map view" : "");
  /** @type {HTMLElement} */ (box.querySelector(".imagedeck-pos")).textContent = `${current + 1} / ${entries.length}`;
  /** @type {HTMLButtonElement} */ (box.querySelector(".imagedeck-prev")).disabled = current === 0;
  /** @type {HTMLButtonElement} */ (box.querySelector(".imagedeck-next")).disabled = current === entries.length - 1;

  // Mini-map, upper-left: a KEYLESS Google Maps embed of THIS image's
  // position (pointer-events off — the wrapping link is the click target,
  // opening actual Google Maps). Keyless deliberately: see
  // keylessMapEmbedUrl. Hidden when the entry carries no coordinates, and
  // for map-kind entries the link alone stands (the big image IS a map).
  const mini = /** @type {HTMLElement} */ (box.querySelector(".imagedeck-minimap"));
  mini.replaceChildren();
  if (e.lat != null && e.lng != null) {
    const a = document.createElement("a");
    a.href = mapsLink(e.lat, e.lng);
    a.target = "_blank";
    a.rel = "noopener";
    a.title = "Open in Google Maps";
    if (e.kind !== "map") {
      const iframe = document.createElement("iframe");
      iframe.loading = "lazy";
      iframe.title = "Mini map";
      iframe.src = keylessMapEmbedUrl(e.lat, e.lng, 16);
      a.appendChild(iframe);
    } else {
      a.textContent = "Open in Google Maps";
      a.className = "imagedeck-maplink";
    }
    mini.appendChild(a);
    mini.hidden = false;
  } else {
    mini.hidden = true;
  }
  const input = /** @type {HTMLInputElement} */ (box.querySelector(".imagedeck-ask input"));
  input.placeholder = e.lat != null ? "Ask about this place — continues the chat from here…" : "Ask about this image…";
}

/**
 * Touch swipe: left/right anywhere on the lightbox (except the ask input)
 * steps through the deck — the mobile complement to the ‹/› buttons and
 * arrow keys (reported 2026-07-09: "can't swipe back or forth when looking
 * at an image").
 * @param {HTMLElement} box the lightbox overlay
 */
function wireSwipeNavigation(box) {
  /** @type {number | null} */
  let swipeX = null;
  /** @type {number | null} */
  let swipeY = null;
  box.addEventListener(
    "touchstart",
    (ev) => {
      if (/** @type {Element} */ (ev.target).closest(".imagedeck-ask")) return;
      swipeX = ev.touches[0].clientX;
      swipeY = ev.touches[0].clientY;
    },
    { passive: true },
  );
  box.addEventListener(
    "touchend",
    (ev) => {
      if (swipeX == null || swipeY == null) return;
      const t = ev.changedTouches[0];
      const dx = t.clientX - swipeX;
      const dy = t.clientY - swipeY;
      swipeX = swipeY = null;
      if (Math.abs(dx) > 40 && Math.abs(dx) > Math.abs(dy) * 1.5) show(current + (dx < 0 ? 1 : -1));
    },
    { passive: true },
  );
}

/** @param {number} index deck index to open at */
export function openDeck(index) {
  if (!entries.length || typeof document === "undefined") return;
  closeDeck();
  const box = document.createElement("div");
  box.className = "imagedeck-overlay";
  box.innerHTML =
    '<div class="imagedeck-frame">' +
    '<button class="imagedeck-close" aria-label="Close">×</button>' +
    '<div class="imagedeck-minimap" hidden></div>' +
    '<img class="imagedeck-img" alt="Enlarged view">' +
    '<button class="imagedeck-prev" aria-label="Previous">‹</button>' +
    '<button class="imagedeck-next" aria-label="Next">›</button>' +
    '<div class="imagedeck-bar"><span class="imagedeck-caption"></span><span class="imagedeck-pos"></span></div>' +
    '<form class="imagedeck-ask"><input type="text" autocomplete="off"><button type="submit">Ask</button></form>' +
    "</div>";
  overlay = box;
  box.addEventListener("click", (ev) => {
    if (ev.target === box) closeDeck();
  });
  /** @type {HTMLElement} */ (box.querySelector(".imagedeck-close")).addEventListener("click", closeDeck);
  /** @type {HTMLElement} */ (box.querySelector(".imagedeck-prev")).addEventListener("click", () => show(current - 1));
  /** @type {HTMLElement} */ (box.querySelector(".imagedeck-next")).addEventListener("click", () => show(current + 1));
  /** @type {HTMLElement} */ (box.querySelector(".imagedeck-ask")).addEventListener("submit", (ev) => {
    ev.preventDefault();
    const input = /** @type {HTMLInputElement} */ (box.querySelector(".imagedeck-ask input"));
    const text = (input.value || "").trim();
    if (!text) return;
    const e = entries[current];
    const point = e.lat != null && e.lng != null ? { lat: e.lat, lng: e.lng, heading: e.heading, kind: e.kind } : null;
    closeDeck();
    if (askHandler) askHandler(text, point);
  });
  wireSwipeNavigation(box);
  document.addEventListener("keydown", onKey);
  document.body.appendChild(box);
  show(index);
}

// Node tests for imagedeck.js's pure core: entry validation/order, keyless embed URLs, latest-within-radius lookup.
import { test, beforeEach } from "node:test";
import assert from "node:assert/strict";

import {
  addDeckEntries,
  deckEntries,
  keylessMapEmbedUrl,
  keylessStreetViewEmbedUrl,
  nearestDeckIndex,
  resetDeck,
} from "./imagedeck.js";

// The deck's pure core (registry order, validation, nearest-waypoint
// lookup) runs in Node unmodified — the lightbox DOM only exists once
// openDeck is called in a browser.

const IMG = "data:image/jpeg;base64,AAAA";

beforeEach(() => resetDeck());

test("addDeckEntries keeps conversation order and returns the strip's start index", () => {
  assert.equal(addDeckEntries([{ url: IMG, caption: "first" }]), 0);
  const start = addDeckEntries([
    { url: IMG, caption: "second", lat: 59.45, lng: 17.8 },
    { url: IMG, caption: "third", kind: "map", lat: 59.46, lng: 17.81 },
  ]);
  assert.equal(start, 1);
  const entries = deckEntries();
  assert.equal(entries.length, 3);
  assert.deepEqual(entries.map((e) => e.caption), ["first", "second", "third"]);
  assert.equal(entries[0].lat, null); // coordinates optional — mini-map just hides
  assert.equal(entries[1].kind, "photo");
  assert.equal(entries[2].kind, "map");
});

test("addDeckEntries drops non-data-URL frames and coerces junk coordinates", () => {
  addDeckEntries([
    { url: "https://example.com/x.jpg", caption: "remote — rejected" },
    { url: IMG, caption: "kept", lat: "not-a-number", lng: 17.8 },
    null,
  ]);
  const entries = deckEntries();
  assert.equal(entries.length, 1);
  assert.equal(entries[0].lat, null); // one bad coordinate → no position at all
});

test("entries keep the frame's heading so an ask reproduces exactly that view", () => {
  addDeckEntries([
    { url: IMG, caption: "faced SE", lat: 59.45, lng: 17.8, heading: 156 },
    { url: IMG, caption: "no heading", lat: 59.46, lng: 17.81 },
  ]);
  const entries = deckEntries();
  assert.equal(entries[0].heading, 156);
  assert.equal(entries[1].heading, 0); // defaults straight north
});

test("nearestDeckIndex finds the LATEST image within the radius — the deck opens where the user last was", () => {
