// ---- the bubble content -----------------------------------------------------------

function bubbleHtml() {
  const intro =
    tier === "drc"
      ? `<b>Introspection mode.</b> I can read my own source code here too — ask how
         I'm built, or name a file like <code>src/pipeline.js</code>.
         <p id="iui-note" class="private">🔒 You're on the secure tier: every model call
