test("embedRef formats each embed kind with its id number", () => {
  assert.equal(
    embedRef({ id: 1, kind: "streetview_embed", lat: 59.33421, lng: 18.06324 }),
    "[Embedded element #1: interactive Google Street View panorama at 59.33421, 18.06324]",
  );
  assert.equal(
    embedRef({ id: 2, kind: "streetview_frames", query: "Kungsgatan 1, Stockholm", directions: ["north", "east", "", "your current view"] }),
    '[Embedded element #2: Street View frames of "Kungsgatan 1, Stockholm" (north, east, your current view)]',
  );
  // No query, no directions — still a well-formed reference.
  assert.equal(embedRef({ id: 3, kind: "streetview_frames" }), "[Embedded element #3: Street View frames]");
  // The interactive map embed (the no-Street-View-coverage stand-in).
  assert.equal(
    embedRef({ id: 8, kind: "map_embed", lat: 59.65, lng: 17.12, q: "Basaltgatan 3, Enköping" }),
    "[Embedded element #8: interactive Google Map at 59.65, 17.12 (Basaltgatan 3, Enköping)]",
  );
  assert.equal(embedRef({ id: 9, kind: "map_embed", lat: 1, lng: 2 }), "[Embedded element #9: interactive Google Map at 1, 2]");
  // An unknown kind (a future source's embed) never silently vanishes.
  assert.equal(embedRef({ id: 4, kind: "sonar_sweep" }), "[Embedded element #4: sonar_sweep]");
  // The inline quiz: title + question count, completion marker when done
  // (the score itself lives in the summary appended to the turn text).
  assert.equal(
    embedRef({ id: 5, kind: "quiz", quiz: { title: "Nordic capitals", questions: [{}, {}, {}] } }),
    '[Embedded element #5: interactive quiz "Nordic capitals" — 3 questions]',
  );
  assert.equal(
    embedRef({ id: 6, kind: "quiz", completed: true, quiz: { title: "Q", questions: [{}] } }),
    '[Embedded element #6: interactive quiz "Q" — 1 question, completed]',
  );
  assert.equal(embedRef({ id: 7, kind: "quiz" }), "[Embedded element #7: interactive quiz]");
});

test("conversationCopyText appends embed references under their assistant turn", () => {
  const messages = [
    { role: "user", content: "what is at these coordinates?" },
    { role: "assistant", content: "It's the Royal Palace." },
    { role: "user", content: "and further north?" },
    { role: "assistant", content: "The museum." },
  ];
  const embeds = [
    { id: 1, kind: "streetview_embed", msgIndex: 1, lat: 59.1, lng: 18.2 },
    { id: 2, kind: "streetview_frames", msgIndex: 3, query: "museum", directions: ["north"] },
  ];
  const out = conversationCopyText(messages, embeds);
  const paras = out.split("\n\n");
  assert.equal(paras[1], "Assistant: It's the Royal Palace.\n[Embedded element #1: interactive Google Street View panorama at 59.1, 18.2]");
  assert.equal(paras[3], 'Assistant: The museum.\n[Embedded element #2: Street View frames of "museum" (north)]');
});

test("conversationCopyText without embeds is unchanged and out-of-range embeds are ignored", () => {
  const messages = [{ role: "user", content: "q" }, { role: "assistant", content: "a" }];
  assert.equal(conversationCopyText(messages), "User: q\n\nAssistant: a");
  assert.equal(
    conversationCopyText(messages, [{ id: 1, kind: "streetview_embed", msgIndex: 9, lat: 1, lng: 2 }]),
    "User: q\n\nAssistant: a",
  );
});

test("asksStreetViewHere gates the device-geolocation prompt to explicit here-asks", () => {
  assert.equal(asksStreetViewHere("street view here"), true);
  assert.equal(asksStreetViewHere("popup street view at my current location"), true);
  assert.equal(asksStreetViewHere("gatuvy här"), true);
  assert.equal(asksStreetViewHere("streer view here"), true); // typo-tolerant like the server gate
  assert.equal(asksStreetViewHere("street view of Storgatan 4"), false);
  assert.equal(asksStreetViewHere("what is here?"), false);
  assert.equal(asksStreetViewHere(""), false);
  assert.equal(asksStreetViewHere(undefined), false);
});

test("asksStreetViewHere takes the Swedish parity forms", () => {
  assert.equal(asksStreetViewHere("visa gatuvyn min plats"), true);
  assert.equal(asksStreetViewHere("gatubild där jag är"), true);
  assert.equal(asksStreetViewHere("gatuvy härifrån"), true);
  assert.equal(asksStreetViewHere("gatubilden av Storgatan 4"), false);
  // "there" must not read as "here" (the boundary guard on both sides).
  assert.equal(asksStreetViewHere("street view over there"), false);
});

// The conversation-level prefilter — the verbatim 2026-07-09 report:
// "Where am i now" → "Street view" → "My location" never requested the
// device location, so the server could only deny.
test("asksDeviceLocation fires on a plain where-am-I ask (EN + SV, typo set)", () => {
  assert.equal(asksDeviceLocation(["Where am i now"]), true);
  assert.equal(asksDeviceLocation(["where am I?"]), true);
  assert.equal(asksDeviceLocation(["wher am i"]), true); // typo set, like the SV-word gate
  assert.equal(asksDeviceLocation(["where are we right now?"]), true);
  assert.equal(asksDeviceLocation(["var är jag nu"]), true);
  assert.equal(asksDeviceLocation(["vart är vi?"]), true);
  assert.equal(asksDeviceLocation(["var befinner jag mig?"]), true);
  // Figurative/prose "where are we/am I" must NOT fire.
  assert.equal(asksDeviceLocation(["where are we going with this"]), false);
  assert.equal(asksDeviceLocation(["where am i going wrong here in the code"]), false);
  assert.equal(asksDeviceLocation(["var är vi på väg"]), false);
});

test("asksNearbyPlace: type word + nearby word requests the device location on a fresh chat", () => {
  assert.equal(asksNearbyPlace("Gas station near e18 there"), true);
  assert.equal(asksNearbyPlace("nearest pharmacy"), true);
  assert.equal(asksNearbyPlace("närmaste bensinstation"), true);
  assert.equal(asksNearbyPlace("finns det någon mack i närheten?"), true);
  assert.equal(asksNearbyPlace("restaurants in Oslo"), false); // no nearby word
  assert.equal(asksNearbyPlace("what is that there?"), false); // no type word
  assert.equal(asksNearbyPlace(""), false);
  // It rides into the conversation-level prefilter as a latest-turn shape.
  assert.equal(asksDeviceLocation(["nearest gas station"]), true);
});

test("asksCrossBarrier + teleport verbs request the device location when no live view exists", () => {
  assert.equal(asksCrossBarrier("Get to the other side of the railway"), true);
  assert.equal(asksCrossBarrier("hoppa över spåret"), true);
  assert.equal(asksCrossBarrier("andra sidan av bron"), true);
  assert.equal(asksCrossBarrier("the houses on the other side of the river are much older than these ones"), false);
  assert.equal(asksCrossBarrier(""), false);
  assert.equal(asksNearbyPlace("teleport to the gas station"), true);
  assert.equal(asksNearbyPlace("ta mig till närmaste mack"), true);
  assert.equal(asksDeviceLocation(["get to the other side of the railway"]), true);
});

test("asksRelocation + relocation fragments request the device location — the verbatim Hemköp report", () => {
  // 2026-07-09, logged maps_intent "none": the server matchers were ready
  // but the client never sent a location to anchor them.
  assert.equal(asksRelocation("Lets go to hemköp stälet"), true);
  assert.equal(asksRelocation("teleport to willys"), true);
  assert.equal(asksRelocation("gå till ica maxi"), true);
  assert.equal(asksRelocation("Legs go to coop"), true); // the adjacent-key typo opener
  assert.equal(asksRelocation("when I go to the shop each week I usually take the bus home"), false); // prose
  assert.equal(asksRelocation(""), false);
  assert.equal(asksDeviceLocation(["Lets go to hemköp stälet"]), true);
  // The follow-up fragment answering the clarify also needs the anchor.
  assert.equal(asksDeviceLocation(["Lets go to hemköp stälet", "Hemköp stäket"]), true);
  // A short fragment with NO recent relocation/nearby ask stays silent.
  assert.equal(asksDeviceLocation(["tell me about semlor", "Hemköp stäket"]), false);
});

test("asksPhysicalLocation: explicit real-position asks only, EN + SV", () => {
  assert.equal(asksPhysicalLocation("street view at my actual location"), true);
  assert.equal(asksPhysicalLocation("show me where I actually am"), true);
  assert.equal(asksPhysicalLocation("gatuvy min faktiska plats"), true);
  assert.equal(asksPhysicalLocation("visa där jag faktiskt är"), true);
  // Plain here-words are NOT physical — they keep anchoring to the live view.
  assert.equal(asksPhysicalLocation("street view here"), false);
  assert.equal(asksPhysicalLocation("my location"), false);
  assert.equal(asksPhysicalLocation("min plats"), false);
  assert.equal(asksPhysicalLocation(""), false);
  // A physical ask also counts as a device-location ask outright.
  assert.equal(asksDeviceLocation(["show me my actual location"]), true);
});

test("asksDeviceLocation reads a short here-fragment against an earlier street-view turn", () => {
  // The reported conversation, verbatim.
  assert.equal(asksDeviceLocation(["Where am i now", "Street view", "My location"]), true);
  assert.equal(asksDeviceLocation(["gatuvy", "min plats"]), true);
  assert.equal(asksDeviceLocation(["street view", "här"]), true);
  assert.equal(asksDeviceLocation(["streer view", "use my location"]), true); // typo-tolerant SV word
  // No earlier street-view turn → a bare fragment stays silent.
