// Model dropdown: catalog from /api/models, selection persisted in
// localStorage. If the catalog can't load, the dropdown stays hidden and
// the server default applies. Models the provider reports as down render
// disabled and become selectable again when they come back. Each option is
// flag-prefixed with its provider's country of processing (data goes where
// the provider resides — Berget/EU vs the US providers).

import { labelWithFlag, regionForModelEntry } from "./provider-region.js";

let sel;
let onChange = () => {};
let knownModels = []; // /api/models entries, for vision capability lookup

export function initModels(selectEl, opts = {}) {
  sel = selectEl;
  onChange = opts.onChange || onChange;
  sel.addEventListener("change", () => {
    localStorage.setItem("model", sel.value);
    onChange();
  });
  loadModels();
}

/**
 * The catalog entry for the current selection (undefined until loaded).
 * @returns {object|undefined} /api/models entry ({id, name, vision, up, pricing})
 */
export function currentModel() {
  return knownModels.find((m) => m.id === sel.value);
}

/**
 * The id to send with /api/chat — empty while the dropdown is hidden
 * (catalog unavailable), letting the server default apply.
 * @returns {string}
 */
export function selectedModelId() {
  return !sel.hidden && sel.value ? sel.value : "";
}

/**
 * A usable vision-capable model, for the "switch to attach images?" offer.
 * @returns {object|undefined}
 */
export function visionFallback() {
  return knownModels.find((m) => m.vision && m.up !== false);
}

/**
 * Programmatic selection (loading a saved conversation, the vision-switch
 * offer) — persists and fires onChange like a user pick.
 * @param {string} id
 */
export function selectModel(id) {
  sel.value = id;
  localStorage.setItem("model", id);
  onChange();
}

async function loadModels() {
  try {
    const res = await fetch("/api/models");
    if (!res.ok) return;
    const data = await res.json();
    const models = data.models || [];
    if (models.length === 0) return;
    knownModels = models;
    sel.replaceChildren();
    for (const m of models) {
      const opt = document.createElement("option");
      opt.value = m.id;
      const region = regionForModelEntry(m);
      const base = m.up === false ? m.name + " (unavailable)" : m.name;
      opt.textContent = labelWithFlag(region ? region.flag : "", base);
      if (m.up === false) opt.disabled = true;
      opt.title = [m.pricing, region ? "Processed in " + region.country : ""]
        .filter(Boolean).join(" · ");
      sel.appendChild(opt);
    }
    const usable = (m) => m.up !== false;
    const saved = localStorage.getItem("model");
    const pick = models.some((m) => m.id === saved && usable(m)) ? saved
      : models.some((m) => m.id === data.default && usable(m)) ? data.default
      : (models.find(usable) || models[0]).id;
    sel.value = pick;
    sel.hidden = false;
    onChange();
  } catch { /* keep dropdown hidden; server default applies */ }
}

// Shared by account.js's message-center admin section and admin.js's full
// notification center — the pieces of alert/pending-user rendering that are
// genuinely identical between the two views (their surrounding markup and
// verbosity differ deliberately, per CLAUDE.md's admin-has-more-features
// design, so only the truly shared fragments live here).

/**
 * @param {*} s  coerced to string
 * @returns {string} with &<>"' HTML-entity-escaped
 */
export function escapeHtml(s) {
  return String(s).replace(/[&<>"']/g, (c) => ({
    "&": "&amp;", "<": "&lt;", ">": "&gt;", '"': "&quot;", "'": "&#39;",
  })[c]);
}

// The alert severity badge — identical markup in both views.
export function alertSeverityBadge(alert) {
  const cls = alert.severity === "critical" ? "critical" : "pending";
  return `<span class="badge ${cls}">${escapeHtml(alert.severity)}</span>`;
}

// "New sign-in awaiting approval: NAME" — identical text in both views'
// pending-user rows (only the surrounding markup differs).
export function pendingApprovalLine(user) {
  return `New sign-in awaiting approval: ${escapeHtml(user.name || user.email)}`;
}

// Original attached files, stored in OPFS (Origin Private File System) —
// every file the user attaches (image or document) keeps its ORIGINAL
// bytes here, keyed by a generated file id. IndexedDB holds only the
// small metadata rows (name/type/size — in the shared dr_rag database,
// public/js/rag.js's `files` store); the bytes themselves live in OPFS,
// which is the storage layer actually built for file-sized data (real
// file handles, streaming writes, no structured-clone copies of
// multi-MB blobs through the IDB transaction machinery).
//
// This module is a dumb byte store: callers hand it the STORAGE FORM of
// the file. For everything except RAG-indexed documents that form is
// AES-GCM ciphertext under the never-persisted history key
// (attachments.js encrypts via history-store.js's encryptBytes before
// calling in; `meta.enc` records which form a file is in). RAG-indexed
// documents are the ONE class stored readable — their search index needs
// readable text anyway, and that asymmetry is disclosed in the settings
// UI. What's stored here never leaves the browser unless the user's
// cloud-storage knob is ON (public/js/sync.js mirrors the same stored
// bytes, encrypted or not, to R2).
//
// Fails soft everywhere: no OPFS (older Safari) just means originals
// aren't archived — attachments keep working exactly as before.

import { encryptBytes } from "./history-store.js";
import { filesMetaStore } from "./rag.js";
import { serverHistoryOn } from "./settings.js";

const DIR = "originals";

async function dir(create) {
  const root = await navigator.storage.getDirectory();
  return root.getDirectoryHandle(DIR, { create });
}

export async function opfsAvailable() {
  try {
    if (!navigator.storage?.getDirectory) return false;
    const d = await dir(true);
    // createWritable is the main-thread write path; Safari gained it late.
    const handle = await d.getFileHandle(".probe", { create: true });
    const ok = typeof handle.createWritable === "function";
    await d.removeEntry(".probe").catch(() => {});
    return ok;
  } catch {
    return false;
  }
}

// Store one file in its storage form (already encrypted unless it's a
// RAG-indexed document — see the header). `meta` = {name, type, enc} —
// kept in IndexedDB so listing never has to walk OPFS; `type` is the
// ORIGINAL MIME type (the stored bytes may be ciphertext), `enc` says
// which form the bytes are in.
export async function saveOriginal(id, blob, meta) {
  const d = await dir(true);
  const handle = await d.getFileHandle(id, { create: true });
  const writable = await handle.createWritable();
  await writable.write(blob);
  await writable.close();
  await filesMetaStore.put({
    id,
    name: meta?.name || id,
    type: meta?.type || blob.type || "application/octet-stream",
    enc: meta?.enc === true,
    size: blob.size,
    addedAt: Date.now(),
  });
}

/**
 * @param {string} id
 * @returns {Promise<?File>} the stored bytes (whatever form they rest in —
 *   check the meta row's `enc` flag), or null when absent/unavailable
 */
export async function loadOriginal(id) {
  try {
    const d = await dir(false);
    const handle = await d.getFileHandle(id);
    return await handle.getFile();
  } catch {
    return null;
  }
}

export async function deleteOriginal(id) {
  try {
    const d = await dir(false);
    await d.removeEntry(id);
  } catch {
    // already gone — deletion is idempotent
  }
  await filesMetaStore.delete(id);
}

/**
 * @returns {Promise<Array<{id: string, name: string, type: string,
 *   enc: boolean, size: number, addedAt: number}>>} the metadata rows —
 *   listing never has to walk OPFS itself
 */
export async function listOriginals() {
  return filesMetaStore.getAll();
}

// One-stop archival used by attachments.js AND projects.js: original bytes
// → OPFS (and, when both the account knob and the caller's scope allow it,
// mirrored to R2). Pure archival — never blocks or fails the caller.
//
// Everything is AES-GCM ENCRYPTED under the same never-persisted history
// key conversations use, before it rests anywhere — with ONE deliberate
// exception: `plaintext: true`, used only for RAG-indexed documents, whose
// search index needs readable text anyway (disclosed in the settings UI).
// Images especially always take the encrypted path. If the key is
// unavailable, the encrypted class stores NOTHING at all — never a
// plaintext fallback. `cloud: false` skips the R2 mirror even when the
// account knob is on (the per-project storage opt-out).
export async function archiveFile(fileId, file, { plaintext = false, cloud = true } = {}) {
  try {
    let stored = file;
    let enc = false;
    if (!plaintext) {
      try {
        stored = new Blob([await encryptBytes(await file.arrayBuffer())], {
          type: "application/octet-stream",
        });
        enc = true;
      } catch {
        return; // no key — store nothing rather than plaintext
      }
    }
    if (await opfsAvailable()) {
      await saveOriginal(fileId, stored, { name: file.name, type: file.type, enc });
    }
    if (cloud && serverHistoryOn()) {
      fetch("/api/files/" + encodeURIComponent(fileId), {
        method: "PUT",
        headers: {
          "content-type": "application/octet-stream",
          "x-file-name": encodeURIComponent(file.name),
          "x-file-type": file.type || "application/octet-stream",
          "x-file-enc": enc ? "1" : "0",
        },
        body: stored,
      }).catch(() => {});
    }
  } catch {
    // no OPFS / storage denied — the caller's flow continues unaffected
  }
}

// Remove a file everywhere it can rest: OPFS + meta row, and (when the
// account knob is on) the R2 copy. Used by projects.js when a file is
// removed from a project or the project is deleted.
export async function purgeFile(fileId) {
  await deleteOriginal(fileId);
  if (serverHistoryOn()) {
    fetch("/api/files/" + encodeURIComponent(fileId), { method: "DELETE" }).catch(() => {});
  }
}

// @ts-check
// Resume-across-relaunch pointer for an in-flight research answer.
//
// The server finishes every research run even after the client vanishes
// (src/chat.js's ctx.waitUntil) and parks the answer for 15 min
// (src/answers.js). stream.js's in-session recovery picks that up when the
// tab survives. But iOS can DISCARD a backgrounded PWA entirely — a cold
// relaunch loses all in-memory state (the request id, the on-screen turn),
// so before this there was nothing left to poll with and the finished
// answer expired unclaimed. This pointer closes that last gap: the research
// still completed on the server, and the next launch collects it.
//
// PRIVACY: the marker is METADATA ONLY — conversation id, request id, the
// settings, a timestamp. NEVER any message text. The question itself lives
// only in the encrypted IndexedDB record (history-store.js); this pointer
// just says "that conversation is awaiting request R". So nothing readable
// at rest is added by this feature — the same posture as the rest of the
// app. Incognito chats persist nothing, so stream.js writes no marker for
// them (there's no encrypted record to reopen either).
//
// It is deliberately localStorage: it must survive a full PWA discard and
// cold relaunch, which in-memory state and (on iOS) sessionStorage do not.
// Single-slot — one in-flight answer at a time; a new send overwrites it.

const KEY = "dr_pending_answer";
export const PENDING_TTL_MS = 15 * 60 * 1000; // matches src/answers.js ANSWER_TTL_MS

/**
 * The stored pointer: conversation id, the answer-recovery request id, the
 * send-time settings a resumed turn needs, and when the send started.
 * Metadata only — never message text (see the privacy note above).
 * @typedef {{convId: string, requestId: string, startedAt: number, [extra: string]: unknown}} PendingPointer
 */

/**
 * Pure: validate + freshness-check a raw stored string. Returns the pointer
 * object, or null if it's absent, malformed, the wrong shape, or older than
 * the TTL — past which src/answers.js has already purged the parked answer,
 * so resuming it could only 404. Kept pure (storage/clock injected by the
 * wrappers below) so it's unit-tested in Node.
 * @param {string | null | undefined} raw
 * @param {number} now epoch ms
 * @param {number} [ttlMs]
 * @returns {PendingPointer | null}
 */
export function parsePending(raw, now, ttlMs = PENDING_TTL_MS) {
  if (!raw) return null;
  let p;
  try {
    p = JSON.parse(raw);
  } catch {
    return null;
  }
  if (!p || typeof p !== "object") return null;
  if (typeof p.convId !== "string" || !p.convId) return null;
  if (typeof p.requestId !== "string" || !p.requestId) return null;
  if (typeof p.startedAt !== "number" || !Number.isFinite(p.startedAt)) return null;
  if (now - p.startedAt >= ttlMs) return null; // past the recovery window
  return p;
}

// Browser wrappers (not unit-tested — localStorage/Date). All fail-soft:
// storage access can throw (private mode, disabled storage, quota) and must
// never break a send or a boot.

/** @param {PendingPointer} p */
export function writePending(p) {
  try {
    localStorage.setItem(KEY, JSON.stringify(p));
  } catch {
    /* storage unavailable — resume-across-relaunch just won't be available */
  }
}

/**
 * @param {number} [now] epoch ms
 * @returns {PendingPointer | null}
 */
export function readPending(now = Date.now()) {
  try {
    return parsePending(localStorage.getItem(KEY), now);
  } catch {
    return null;
  }
}

export function clearPending() {
  try {
    localStorage.removeItem(KEY);
  } catch {
    /* nothing to do */
  }
}

// Node tests for pending-answer.js's pure pointer validation (parsePending).
import { test, describe } from "node:test";
import assert from "node:assert/strict";
import { parsePending, PENDING_TTL_MS } from "./pending-answer.js";

// The localStorage/Date wrappers (writePending/readPending/clearPending)
// are browser glue, verified live; the pure freshness+shape validation is
// what decides whether a boot resumes or discards a pointer, so it's tested.
describe("parsePending", () => {
  const good = JSON.stringify({
    convId: "abc-123",
    requestId: "req-xyz",
    startedAt: 1_000_000,
    model: "m",
    budgetS: 60,
    webSearch: true,
  });

  test("returns the pointer when well-formed and fresh", () => {
    const p = parsePending(good, 1_000_000 + 1000);
    assert.equal(p.convId, "abc-123");
    assert.equal(p.requestId, "req-xyz");
  });

  test("returns null once older than the TTL (parked answer already purged)", () => {
    assert.equal(parsePending(good, 1_000_000 + PENDING_TTL_MS + 1), null);
    // exactly at the TTL boundary is treated as expired
    assert.equal(parsePending(good, 1_000_000 + PENDING_TTL_MS), null);
  });

  test("returns null for absent / empty / non-JSON input", () => {
    assert.equal(parsePending("", 0), null);
    assert.equal(parsePending(null, 0), null);
    assert.equal(parsePending(undefined, 0), null);
    assert.equal(parsePending("{not json", 0), null);
  });

  test("returns null when required identifiers are missing or wrong type", () => {
    assert.equal(parsePending(JSON.stringify({ requestId: "r", startedAt: 0 }), 0), null); // no convId
    assert.equal(parsePending(JSON.stringify({ convId: "c", startedAt: 0 }), 0), null); // no requestId
    assert.equal(parsePending(JSON.stringify({ convId: "c", requestId: "r" }), 0), null); // no startedAt
    assert.equal(parsePending(JSON.stringify({ convId: 1, requestId: "r", startedAt: 0 }), 0), null);
    assert.equal(parsePending(JSON.stringify({ convId: "c", requestId: "r", startedAt: "nope" }), 0), null);
  });

  test("respects a custom TTL", () => {
    assert.equal(parsePending(good, 1_000_000 + 4999, 5000).convId, "abc-123");
    assert.equal(parsePending(good, 1_000_000 + 5001, 5000), null);
  });
});

// @ts-check
// Pure helpers for the projects feature (public/js/projects.js) — kept
// import-free so the Node unit suite can exercise them directly, the same
// pattern as rag.js's pure core.

/**
 * One project material as projects.js stores it (file, image, or note).
 * @typedef {object} ProjectFile
 * @property {string} [id] retrieval doc id (present when indexed)
 * @property {string} [name]
 * @property {"image" | "text" | "doc" | string} [kind]
 * @property {boolean} [indexed]
 * @property {string} [metadata] extracted EXIF / document metadata summary
 */

/**
 * @typedef {object} Project
 * @property {string} [name]
 * @property {ProjectFile[]} [files]
 */

// The per-doc metadata slice and total block budget: the project context
// block is INVENTORY + image metadata, not content — document content
// arrives via retrieval excerpts, so this stays small even for a project
// full of material.
const META_CHARS = 900;
const BLOCK_MAX_CHARS = 6000;

export const PROJECT_NAME_MAX = 80;
export const NOTE_TITLE_MAX = 120;
export const NOTE_TEXT_MAX = 500_000;

/**
 * @param {unknown} name
 * @returns {string} trimmed, capped, never empty
 */
export function normalizeProjectName(name) {
  const n = String(name || "").trim().slice(0, PROJECT_NAME_MAX);
  return n || "Untitled project";
}

/**
 * A note ("text content with header and content") is stored/indexed as a
 * single text document; the title leads the text so retrieval can match on
 * it too.
 * @param {unknown} title
 * @param {unknown} content
 * @returns {string}
 */
export function noteToText(title, content) {
  const t = String(title || "").trim().slice(0, NOTE_TITLE_MAX);
  const c = String(content || "").trim().slice(0, NOTE_TEXT_MAX);
  return (t ? t + "\n\n" : "") + c;
}

/**
 * Doc ids eligible for retrieval in this project's scope.
 * @param {Project | null | undefined} project
 * @returns {string[]}
 */
export function projectDocIds(project) {
  /** @type {string[]} */
  const ids = [];
  for (const f of project?.files || []) {
    if (f.indexed && f.id) ids.push(f.id);
  }
  return ids;
}

/**
 * The "project materials" block appended to every message sent inside a
 * project: an inventory of the project's files and notes, plus extracted
 * image metadata (EXIF — capture time/place/device) since images aren't
 * otherwise readable to a text pipeline. Document CONTENT is deliberately
 * absent here — the indexed files contribute retrieval excerpts through
 * the same mechanism attachments use.
 * @param {Project | null | undefined} project
 * @returns {string} the labeled block ("" when there's nothing to describe)
 */
export function buildProjectContext(project) {
  const files = project?.files || [];
  if (!project || (!files.length && !project.name)) return "";
  const lines = [`--- Project: ${normalizeProjectName(project.name)} ---`];
  if (files.length) lines.push("Materials in this project:");
  else lines.push("(no materials added yet)");
  for (const f of files) {
    const kind =
      f.kind === "image" ? "image" : f.kind === "text" ? "note" : f.kind === "doc" ? "document" : "file";
    const indexed = f.indexed ? ", indexed for retrieval — relevant excerpts are supplied separately" : "";
    lines.push(`- ${f.name} (${kind}${indexed})`);
    if (f.metadata) {
      const meta = String(f.metadata).slice(0, META_CHARS);
      lines.push(
        `  [${f.kind === "image" ? "Image metadata" : "Document metadata"}]`,
        ...meta.split("\n").map((l) => "  " + l),
      );
    }
    if (lines.join("\n").length > BLOCK_MAX_CHARS) break;
  }
  lines.push(`--- End of project ---`);
  let out = lines.join("\n");
  if (out.length > BLOCK_MAX_CHARS + 500) out = out.slice(0, BLOCK_MAX_CHARS + 500);
  return "\n\n" + out;
}

