function status(msg) {
  const el = document.getElementById("pstatus");
  if (!el) return;
  el.hidden = !msg;
  el.textContent = msg || "";
}

function wirePanel(p) {
  const body = document.getElementById("projectbody");

  // ---- the per-project cloud knob -------------------------------------
  const knob = document.getElementById("projectcloud");
  const kstatus = document.getElementById("projectsyncstatus");
  knob?.addEventListener("change", async () => {
    const on = knob.checked;
    knob.disabled = true;
    kstatus.hidden = false;
    const progress = (m) => { kstatus.textContent = m; };
    try {
      await setProjectCloud(p.id, on);
      if (on) {
        const r = await pushProjectScope(p.id, progress);
        kstatus.textContent =
          `This project is stored in the cloud — ${r.pushed} item(s) uploaded.` +
          (r.errors.length ? ` ${r.errors.length} failed (will retry on the next sync).` : "");
      } else {
        const r = await drainProjectScope(p.id, progress);
        kstatus.textContent = r.drained
          ? `This project now lives only in this browser — ${r.removed} cloud object(s) removed.`
          : "Some items couldn't be confirmed locally — their cloud copies were kept. Toggle again to retry.";
        if (!r.drained) {
          await setProjectCloud(p.id, true); // don't pretend it's local-only
          knob.checked = true;
        }
      }
      renderProjectsList();
    } catch (err) {
      knob.checked = !on;
      kstatus.textContent = err?.message || "Could not update the project setting.";
    } finally {
      knob.disabled = false;
    }
  });

  // ---- the encrypted vault copy (public/js/vault.js) --------------------
  const vaultBtn = document.getElementById("pvaultstore");
  const vaultStatus = document.getElementById("pvaultstatus");
  const setVaultStatus = (msg) => {
    vaultStatus.hidden = !msg;
    vaultStatus.textContent = msg || "";
  };
  vaultBtn?.addEventListener("click", async () => {
    vaultBtn.disabled = true;
    document.getElementById("pvaultsecret").hidden = true;
    try {
      const r = await storeProjectToVault(p.id, setVaultStatus);
      const summary = `Stored: ${r.counts.conversations} chat(s), ${r.counts.files} file(s), ${r.counts.docs} index document(s).`;
      setVaultStatus(
        r.missingFiles.length
          ? `${summary} ${r.missingFiles.length} file(s) had no local original and were left out: ${r.missingFiles.join(", ")}.`
          : summary,
      );
      // The one and only display of the secret — it is never persisted.
      document.getElementById("pvaultsecrettext").textContent = r.secret;
      document.getElementById("pvaultsecret").hidden = false;
      vaultBtn.textContent = "Store again";
    } catch (err) {
      setVaultStatus(err?.message || "Storing the encrypted copy failed.");
    } finally {
      vaultBtn.disabled = false;
    }
  });
  document.getElementById("pvaultcopy")?.addEventListener("click", async () => {
    const text = document.getElementById("pvaultsecrettext").textContent;
    const btn = document.getElementById("pvaultcopy");
    try {
      await navigator.clipboard.writeText(text);
      btn.textContent = "Copied ✓";
      setTimeout(() => {
        btn.textContent = "Copy";
      }, 2000);
    } catch {
      // Clipboard API denied (some in-app browsers): select the secret so a
      // manual copy is one keystroke away.
      const range = document.createRange();
      range.selectNodeContents(document.getElementById("pvaultsecrettext"));
      const sel = window.getSelection();
      sel.removeAllRanges();
      sel.addRange(range);
      btn.textContent = "Select + copy manually";
    }
  });

  // ---- chat / rename / delete ------------------------------------------
  document.getElementById("pchat").addEventListener("click", () => {
    setActiveProject(p.id);
    onNew(true); // keepProject: fresh chat, first send adopts the active project
    closePanel();
  });
  document.getElementById("pdelete").addEventListener("click", async () => {
    if (!confirm(`Delete "${p.name}" with its files and chats? This can't be undone.`)) return;
    status("Deleting project…");
    await deleteProject(p.id);
    renderProjectsList();
    closePanel();
    onNew();
  });

  // ---- add files (picker + drag-and-drop) --------------------------------
  const input = document.getElementById("pfileinput");
  document.getElementById("pfiles").addEventListener("click", () => input.click());
  input.addEventListener("change", async () => {
    const files = [...input.files];
    input.value = "";
    await ingest(files);
  });
  const drop = document.getElementById("pdrop");
  for (const evt of ["dragover", "dragenter"]) {
    drop.addEventListener(evt, (e) => {
      e.preventDefault();
      drop.classList.add("dragging");
    });
  }
  drop.addEventListener("dragleave", () => drop.classList.remove("dragging"));
  drop.addEventListener("drop", async (e) => {
    e.preventDefault();
    drop.classList.remove("dragging");
    await ingest([...(e.dataTransfer?.files || [])]);
  });

  async function ingest(files) {
    if (!files.length) return;
    status("Adding files…");
    const { errors } = await addFilesToProject(p.id, files, status);
    status(errors.length ? "Some files failed: " + errors.join("; ") : "");
    await renderPanel();
    renderProjectsList();
  }

  // ---- the note form (always open — no toggle button) ----------------------
  document.getElementById("ptextsave").addEventListener("click", async () => {
    const title = document.getElementById("ptexttitle").value;
    const content = document.getElementById("ptextcontent").value;
    if (!content.trim() && !title.trim()) return;
    status("Indexing note…");
    try {
      await addTextToProject(p.id, title, content);
      status("");
      await renderPanel(); // also clears the form for the next note
      renderProjectsList();
    } catch (err) {
      status(err?.message || "Could not save the note.");
    }
  });

  // ---- file removal + opening chats ---------------------------------------
  body.querySelectorAll(".pf-remove").forEach((el) => {
    el.addEventListener("click", async () => {
      if (!confirm("Remove this file from the project?")) return;
      await removeFileFromProject(p.id, el.dataset.id);
      await renderPanel();
      renderProjectsList();
    });
  });
  body.querySelectorAll(".history-open.pconv").forEach((el) => {
    el.addEventListener("click", async () => {
      const record = await loadConversation(el.dataset.id);
      if (!record) return;
      applyLoadedConversation({ ...record, id: el.dataset.id });
      onLoad(record);
      closePanel();
    });
  });
}

// Projects: named collections of chats and files (public/js/projects-ui.js
// renders them; this module owns the data and the rules).
//
// A project's record — name, file inventory (with extracted image/document
// metadata), notes, and its per-project cloud knob — is ONE encrypted blob
// (history-store.js `projects` store locally, R2 `projects/{uid}/{id}` in
// cloud mode), exactly the conversation-record pattern. Its files live in
// the same OPFS/R2 file store as attachment originals (encrypted, except
// RAG-indexed documents) and its indexable material (documents AND text
// notes, of any size — project material is reference material, so
// everything indexable IS indexed) goes through the same RAG pipeline as
// large attachments. Images aren't indexable — they contribute their
// extracted EXIF metadata to the chat context instead (see
// project-context.js), which is exactly the capture-time/place/device
// material the research pipeline is meant to use.
//
// Scope is the invariant to protect: a chat inside a project retrieves
// across THAT project's indexed docs, its sibling chats in the project
// (indexed as they grow — chat-rag.js), plus its own attachments — never
// another project's (retrieval is by explicit docId list, so isolation is
// structural, and the e2e suite asserts it). Because project chats are
// indexed, their records rest READABLE like every other indexed material
// (history-store.js documents the rule).
//
// The per-project cloud knob is a SCOPED version of the account knob:
// serverStorage !== false means the project follows the account setting;
// an explicit false keeps everything in this project — record,
// conversations, files, RAG index — out of the cloud (dual-writes skip it,
// sync skips it, and flipping it off drains what was already up there;
// public/js/sync.js implements the bulk moves).

import { deleteChatIndex } from "./chat-rag.js";
import { docExt, isParsableDoc, parseDocFile } from "./docs.js";
import { extractExif, formatExifSummary } from "./exif.js";
import {
  decryptBytes,
  deleteConversation,
  deleteProjectRecord,
  listConversations,
  listProjectRecords,
  saveProjectRecord,
} from "./history-store.js";
import { archiveFile, listOriginals, loadOriginal, purgeFile } from "./opfs.js";
import { buildProjectContext, normalizeProjectName, noteToText, projectDocIds } from "./project-context.js";
import { deleteDoc, indexDocument } from "./rag.js";
import { serverHistoryOn } from "./settings.js";

const MAX_FILES_PER_PROJECT = 100;
const MAX_RAW_BYTES = 25 * 1024 * 1024; // same input cap as attachments
const PARSE_MAX_CHARS = 8_000_000;

const isImageFile = (f) => /^image\//.test(f.type) || /\.(png|jpe?g|webp|gif)$/i.test(f.name);

// ---- cache + change notification --------------------------------------------

let projects = []; // decrypted records, newest first
let loadedOnce = false;
let activeId = null;
const listeners = new Set();

function notify() {
  for (const fn of listeners) {
    try {
      fn();
    } catch {
      // one broken listener must not break the rest
    }
  }
}

export function onProjectsChange(fn) {
  listeners.add(fn);
  return () => listeners.delete(fn);
}

export async function refreshProjects() {
  projects = await listProjectRecords();
  loadedOnce = true;
  notify();
  return projects;
}

export async function listProjects() {
  if (!loadedOnce) await refreshProjects();
  return projects;
}

export function getProject(id) {
  return projects.find((p) => p.id === id) || null;
}

// ---- active project (the chat context) ---------------------------------------

export function activeProjectId() {
  return activeId;
}

export function setActiveProject(id) {
  activeId = id || null;
  notify();
}

export function activeProject() {
  return activeId ? getProject(activeId) : null;
}

/**
 * The knob answer every storage-touching module asks. Unknown/absent
 * project (or none active) means "follow the account setting" — true.
 * @param {?string} projectId
 * @returns {boolean}
 */
export function projectCloudOn(projectId) {
  if (!projectId) return true;
  const p = getProject(projectId);
  return p ? p.serverStorage !== false : true;
}

export function activeProjectCloudOn() {
  return projectCloudOn(activeId);
}

export function activeProjectDocIds() {
  return projectDocIds(activeProject());
}

export function activeProjectContext() {
  return buildProjectContext(activeProject());
}

// fileId → projectId across every project (sync.js uses this to honor
// cloud-off projects when pushing files/RAG docs).
export function fileProjectMap() {
  const map = new Map();
  for (const p of projects) {
    for (const f of p.files || []) map.set(f.id, p.id);
  }
  return map;
}

// ---- record persistence -------------------------------------------------------

async function persistProject(project) {
  project.updatedAt = Date.now();
  const { id, ...data } = project;
  await saveProjectRecord(id, { ...data }, { cloud: project.serverStorage !== false });
  const i = projects.findIndex((p) => p.id === id);
  if (i >= 0) projects[i] = project;
  else projects.unshift(project);
  notify();
  return project;
}

export async function createProject(name) {
  const project = {
    id: crypto.randomUUID(),
    name: normalizeProjectName(name),
    serverStorage: true, // follow the account default; the knob opts out
    files: [],
    createdAt: Date.now(),
    updatedAt: Date.now(),
  };
  return persistProject(project);
}

export async function renameProject(id, name) {
  const p = getProject(id);
  if (!p) return null;
  p.name = normalizeProjectName(name);
  return persistProject(p);
}

// Flip the record's knob only — the bulk consequences (push up / drain
// down) are sync.js's pushProjectScope / drainProjectScope, driven by the
// UI so it can show progress.
export async function setProjectCloud(id, on) {
  const p = getProject(id);
  if (!p) return null;
  p.serverStorage = on !== false;
  return persistProject(p);
}

// The project's current vault id (public/js/vault.js): remembered INSIDE
// the encrypted record so re-storing can rotate — upload under the new
// secret's id, delete the old blob. The id reveals nothing (it's an HKDF
// output; the secret itself is never stored anywhere).
export async function setProjectVaultId(id, vaultId) {
  const p = getProject(id);
  if (!p) return null;
  p.vaultId = vaultId || null;
  return persistProject(p);
}

// ---- files & notes -------------------------------------------------------------

// One added file → one inventory entry. Documents and notes are ALWAYS
// indexed (project material is reference material); images contribute
// extracted EXIF instead; anything else is archived (encrypted) without
// indexing. onProgress(label) feeds the panel's status line.
async function addOneFile(project, file, onProgress = () => {}) {
  if ((project.files || []).length >= MAX_FILES_PER_PROJECT) {
    throw new Error(`A project holds at most ${MAX_FILES_PER_PROJECT} files.`);
  }
  if (file.size > MAX_RAW_BYTES) throw new Error(file.name + " is too large (25 MB max).");
  const cloud = project.serverStorage !== false;
  const fileId = crypto.randomUUID();
  const entry = {
    id: fileId,
    name: file.name,
    type: file.type || "application/octet-stream",
    size: file.size,
    kind: "file",
    indexed: false,
    addedAt: Date.now(),
  };

  if (isImageFile(file)) {
    entry.kind = "image";
    try {
      const meta = extractExif(await file.arrayBuffer());
      entry.metadata = formatExifSummary(meta);
      if (meta?.gps) entry.gps = meta.gps;
    } catch {
      // metadata extraction must never block the add
    }
    // A small preview rides INSIDE the encrypted project record (a few KB
    // of JPEG data URL), so the panel can show the picture itself — the
    // OPFS/R2 original is ciphertext and can't be used as an <img> src.
    entry.thumb = await makeThumb(file);
    await archiveFile(fileId, file, { cloud });
    return entry;
  }

  if (isParsableDoc(file)) {
    entry.kind = "doc";
    onProgress(`Reading ${file.name}…`);
    const { text, metadata } = await parseDocFile(file, PARSE_MAX_CHARS);
    entry.ext = docExt(file);
    if (metadata) entry.metadata = metadata;
    try {
      onProgress(`Indexing ${file.name}…`);
      const { chunkCount } = await indexDocument(fileId, file.name, text, {
        cloud,
        onProgress: (done, total) =>
          onProgress(`Indexing ${file.name}… ${Math.round((100 * done) / total)}%`),
      });
      entry.indexed = true;
      entry.chunkCount = chunkCount;
      // Indexed → its original is the one readable class (the index has
      // the text anyway).
      await archiveFile(fileId, file, { plaintext: true, cloud });
    } catch (err) {
      console.warn("projects: indexing failed, storing unindexed", err);
      await archiveFile(fileId, file, { cloud }); // encrypted, unindexed
    }
    return entry;
  }

  // Unsupported for indexing — archived (encrypted) so it's not lost.
  await archiveFile(fileId, file, { cloud });
  return entry;
}

/**
 * Adds files to a project one by one, persisting after each so a failure
 * mid-batch loses nothing already ingested.
 * @param {string} id  project id
 * @param {File[]} files
 * @param {(msg: string) => void} [onProgress]  status-line narration
 * @returns {Promise<{project: object, errors: string[]}>} per-file failures
 *   are collected, never thrown
 */
export async function addFilesToProject(id, files, onProgress = () => {}) {
  const p = getProject(id);
  if (!p) throw new Error("Project not found.");
  const errors = [];
  for (const file of files) {
    try {
      const entry = await addOneFile(p, file, onProgress);
      p.files = [...(p.files || []), entry];
      await persistProject(p);
    } catch (err) {
      errors.push(`${file.name}: ${err?.message || "failed"}`);
    }
  }
  return { project: p, errors };
}

// "Text content with header and content" — a note. Stored and indexed as
// a small text document (title leads the indexed text so retrieval can
// match on it), listed in the inventory under its title.
export async function addTextToProject(id, title, content) {
  const p = getProject(id);
  if (!p) throw new Error("Project not found.");
  const text = noteToText(title, content);
  if (!text.trim()) throw new Error("The note needs some content.");
  const cloud = p.serverStorage !== false;
  const fileId = crypto.randomUUID();
  const name = (String(title || "").trim() || "Note").slice(0, 120);
  const entry = {
    id: fileId,
    name,
    type: "text/markdown",
    size: text.length,
    kind: "text",
    indexed: false,
    addedAt: Date.now(),
  };
  try {
    const { chunkCount } = await indexDocument(fileId, name, text, { cloud });
    entry.indexed = true;
    entry.chunkCount = chunkCount;
    await archiveFile(fileId, new File([text], name + ".md", { type: "text/markdown" }), {
      plaintext: true,
      cloud,
    });
  } catch (err) {
    console.warn("projects: note indexing failed, storing encrypted", err);
    await archiveFile(fileId, new File([text], name + ".md", { type: "text/markdown" }), { cloud });
  }
  p.files = [...(p.files || []), entry];
  await persistProject(p);
  return entry;
}

// Thumbnail for the panel's file list: canvas-downscaled to ~112px JPEG,
// capped to a few KB so a project full of photos keeps its record small.
// (Same canvas approach as attachments.js's downscaleImage, tuned for a
// list preview instead of a model input.) Returns null when the bytes
// aren't decodable as an image.
async function makeThumb(blob) {
  try {
    const img = await createImageBitmap(blob).catch(
      () =>
        new Promise((resolve, reject) => {
          const el = new Image();
          el.onload = () => resolve(el);
          el.onerror = reject;
          el.src = URL.createObjectURL(blob);
        }),
    );
    const w = img.width || img.naturalWidth;
    const h = img.height || img.naturalHeight;
    if (!w || !h) return null;
    const scale = Math.min(1, 112 / Math.max(w, h));
    const canvas = document.createElement("canvas");
    canvas.width = Math.max(1, Math.round(w * scale));
    canvas.height = Math.max(1, Math.round(h * scale));
    canvas.getContext("2d").drawImage(img, 0, 0, canvas.width, canvas.height);
    for (const q of [0.75, 0.6, 0.45]) {
      const url = canvas.toDataURL("image/jpeg", q);
      if (url.length <= 24_000) return url;
    }
  } catch {
    // undecodable — the list falls back to the kind icon
  }
  return null;
}

// Backfill for images added before thumbnails existed: rebuild the preview
// from the OPFS original (decrypting it — image originals rest encrypted)
// and persist it into the record. Returns true when the record changed.
export async function ensureThumb(projectId, fileId) {
  const p = getProject(projectId);
  const f = (p?.files || []).find((x) => x.id === fileId);
  if (!f || f.kind !== "image" || f.thumb) return false;
  let blob = await loadOriginal(fileId);
  if (!blob) return false;
  try {
    const meta = (await listOriginals()).find((m) => m.id === fileId);
    if (meta?.enc) {
      blob = new Blob([await decryptBytes(new Uint8Array(await blob.arrayBuffer()))], {
        type: f.type || "image/jpeg",
      });
    }
  } catch {
    return false; // key unavailable — keep the icon
  }
  const thumb = await makeThumb(blob);
  if (!thumb) return false;
  f.thumb = thumb;
  await persistProject(p);
  return true;
}

export async function removeFileFromProject(id, fileId) {
  const p = getProject(id);
  if (!p) return;
  const entry = (p.files || []).find((f) => f.id === fileId);
  p.files = (p.files || []).filter((f) => f.id !== fileId);
  await persistProject(p);
  await purgeFile(fileId);
  if (entry?.indexed) {
    await deleteDoc(fileId).catch(() => {});
    if (serverHistoryOn()) {
      fetch("/api/rag/docs/" + encodeURIComponent(fileId), { method: "DELETE" }).catch(() => {});
    }
  }
}

// ---- conversations in a project -------------------------------------------------

export async function conversationsOfProject(id) {
  return (await listConversations()).filter((c) => c.projectId === id);
}

// Deleting a project removes EVERYTHING in its scope: files (both rests),
// its slice of the RAG index (both rests), its conversations (both rests),
// then the record itself. The remote deletes are harmless no-ops for a
// project that was cloud-off (nothing is up there).
export async function deleteProject(id) {
  const p = getProject(id);
  if (!p) return;
  for (const f of [...(p.files || [])]) {
    await removeFileFromProject(id, f.id).catch(() => {});
  }
  for (const c of await conversationsOfProject(id)) {
    await deleteChatIndex(c.id).catch(() => {}); // its slice of the RAG index, both rests
    await deleteConversation(c.id).catch(() => {});
  }
  await deleteProjectRecord(id);
  projects = projects.filter((x) => x.id !== id);
  if (activeId === id) activeId = null;
  notify();
}

// @ts-check
// Country-of-processing badges for the model / provider selectors.
//
// Every LLM provider processes the conversation wherever it is hosted, so each
// selector prefixes a provider (or a model) with the flag of that destination:
// data goes where your provider resides. Berget is EU (Sweden); OpenAI,
// Anthropic and Groq are US. A local / on-device option — nothing leaves the
// browser — gets NO flag.
//
// Pure, dependency-free and SHARED so the mapping lives in exactly one place:
// the DRS composer dropdown (`models.js`), the /cure provider picker + model
// dropdown (`cure/drc.js`, `cure/index.html`), and the introspection route
// picker (`introspect-core.js`) all read from here. Node-testable.

/** @typedef {{ country: string, flag: string }} Region */

/** @type {Record<string, Region>} */
export const PROVIDER_REGIONS = {
  berget: { country: "Sweden", flag: "🇸🇪" },
  openai: { country: "United States", flag: "🇺🇸" },
  anthropic: { country: "United States", flag: "🇺🇸" },
  groq: { country: "United States", flag: "🇺🇸" },
};

/**
 * The processing region for a provider key ("berget" | "openai" | "anthropic"
 * | "groq"), or null for an unknown / local one (render no flag). Never throws.
 * @param {unknown} providerKey
 * @returns {Region | null}
 */
export function regionForProvider(providerKey) {
  if (typeof providerKey !== "string") return null;
  return PROVIDER_REGIONS[providerKey.toLowerCase()] || null;
}

/**
 * The flag for a provider key, or "" for unknown / local. Never throws.
 * @param {unknown} providerKey
 * @returns {string}
 */
export function flagForProvider(providerKey) {
  const r = regionForProvider(providerKey);
  return r ? r.flag : "";
}

/**
 * The processing region for a DRS `/api/models` catalog entry. The catalog
 * marks secondary providers explicitly (`provider: "anthropic" | "openai"`); a
 * Berget entry has no `provider` field, so an absent one means Berget.
 * @param {{ provider?: string } | null | undefined} entry
 * @returns {Region | null}
 */
export function regionForModelEntry(entry) {
  return regionForProvider(entry?.provider || "berget");
}

/**
 * A flag-prefixed label: `"🇸🇪 Mistral Small"`. With no flag the name is
 * returned unchanged (a local option). Never throws.
 * @param {string} flag
 * @param {string} name
 * @returns {string}
 */
export function labelWithFlag(flag, name) {
  return flag ? `${flag} ${name}` : String(name ?? "");
}

// Unit tests for provider-region.js — the country-of-processing flag mapping
// shared by every model / provider selector.

import { test } from "node:test";
import assert from "node:assert/strict";
import {
  PROVIDER_REGIONS,
  flagForProvider,
  labelWithFlag,
  regionForModelEntry,
  regionForProvider,
} from "./provider-region.js";

test("Berget is Sweden; OpenAI/Anthropic/Groq are the US", () => {
  assert.equal(regionForProvider("berget").country, "Sweden");
  assert.equal(regionForProvider("berget").flag, "🇸🇪");
  for (const id of ["openai", "anthropic", "groq"]) {
    assert.equal(regionForProvider(id).country, "United States");
    assert.equal(regionForProvider(id).flag, "🇺🇸");
  }
});

test("provider key match is case-insensitive", () => {
  assert.equal(flagForProvider("Berget"), "🇸🇪");
  assert.equal(flagForProvider("OPENAI"), "🇺🇸");
});

test("an unknown or local provider gets no region and no flag", () => {
  assert.equal(regionForProvider("local"), null);
  assert.equal(regionForProvider(""), null);
  assert.equal(regionForProvider(undefined), null);
  assert.equal(regionForProvider(42), null);
  assert.equal(flagForProvider("local"), "");
  assert.equal(flagForProvider(null), "");
});

test("regionForModelEntry: explicit secondary provider vs Berget default", () => {
  assert.equal(regionForModelEntry({ provider: "anthropic" }).flag, "🇺🇸");
  assert.equal(regionForModelEntry({ provider: "openai" }).flag, "🇺🇸");
  // A Berget catalog entry carries no provider field → defaults to Berget.
  assert.equal(regionForModelEntry({ id: "mistralai/x" }).flag, "🇸🇪");
  assert.equal(regionForModelEntry({}).flag, "🇸🇪");
  assert.equal(regionForModelEntry(null).flag, "🇸🇪");
});

test("labelWithFlag prefixes a flag, or returns the name unchanged when local", () => {
  assert.equal(labelWithFlag("🇸🇪", "Mistral Small"), "🇸🇪 Mistral Small");
  assert.equal(labelWithFlag("", "Local model"), "Local model");
});

test("every registered region has a country and a flag", () => {
  for (const [id, r] of Object.entries(PROVIDER_REGIONS)) {
    assert.ok(r.country, `${id} has a country`);
    assert.ok(r.flag, `${id} has a flag`);
  }
});

// @ts-check
// The inline-quiz turn element: an interactive card the pipeline's `quiz`
// status event renders into the turn body (like the Street View embeds, it
// persists beside the answer rather than collapsing with the activity
// steps). One question at a time — the alternatives as buttons PLUS a
// free-text "answer in your own words" field — with immediate feedback and
// an explanation after each answer, then a final score verdict with a
// per-question recap.
//
// Grading: multiple-choice picks grade locally (the quiz payload carries
// the correct index — this is a self-study tool, not an exam); a free-text
// answer grades via POST /api/quiz/grade (one small JSON call, meaning over
// wording). Grading failures are fail-soft: the answer is marked ungraded,
// shown with the reference answer, and excluded from the score with a
// visible note — never a broken quiz.
//
// State/persistence contract (stream.js owns both sides): `hooks.answers`
// seeds previously given answers (a reloaded conversation resumes, or shows
// the finished recap), `hooks.onAnswer(answers)` fires after every answer
// (recorded into the conversation's embeds registry), and
// `hooks.onComplete(summaryText)` fires once when the last question is
// answered — stream.js appends the summary to the assistant message in
// history so follow-up questions (and the copy-conversation export) carry
// the result, then persists.
//
// The scoring/summary helpers are pure and DOM-free at import time, so the
// Node unit suite (quiz.test.js) exercises them directly — the same
// pattern as rag.js's pure core.

// ---- pure core -------------------------------------------------------------

/**
 * One quiz question as normalizeQuiz (src/quiz.js) guarantees it: the
 * alternatives, the index of the correct one, an optional explanation.
 * @typedef {{question: string, alternatives: string[], correct: number, explanation?: string}} QuizQuestion
 */

/**
 * @typedef {{title?: string, questions?: QuizQuestion[]}} Quiz
 */

/**
 * One answer entry: either {pick: <alternative index>} or
 * {free: <text>, correct: true|false|null, comment} — null `correct` means
 * the grading call failed and the answer counts as ungraded.
 * @typedef {{pick?: number, free?: string, correct?: boolean | null, comment?: string}} QuizAnswer
 */

/**
 * renderQuiz's state/persistence contract (see the module header).
 * @typedef {object} QuizHooks
 * @property {QuizAnswer[]} [answers] previously given answers to resume from
 * @property {(answers: QuizAnswer[]) => void} [onAnswer]
 * @property {(summaryText: string) => void} [onComplete]
 */

/**
 * true | false | null (ungraded) for one answered question.
 * @param {QuizQuestion | undefined} question
 * @param {QuizAnswer | undefined} answer
 * @returns {boolean | null}
 */
export function answerVerdict(question, answer) {
  if (!question || !answer) return null;
  if (typeof answer.pick === "number") return answer.pick === question.correct;
  if (typeof answer.free === "string") return typeof answer.correct === "boolean" ? answer.correct : null;
  return null;
}

/**
 * Score across the answers given so far: `correct` out of `total` questions,
 * with `ungraded` free-text answers excluded from `correct` but counted so
 * the verdict can say so.
 * @param {Quiz | null | undefined} quiz
 * @param {QuizAnswer[] | null | undefined} answers
 * @returns {{correct: number, total: number, ungraded: number}}
 */
export function quizScore(quiz, answers) {
  const qs = quiz?.questions || [];
  let correct = 0;
  let ungraded = 0;
  (answers || []).forEach((a, i) => {
    const v = answerVerdict(qs[i], a);
    if (v === true) correct++;
    else if (v === null && a) ungraded++;
  });
  return { correct, total: qs.length, ungraded };
}

/**
 * @param {Quiz | null | undefined} quiz
 * @param {QuizAnswer[] | null | undefined} answers
 * @returns {boolean}
 */
export function quizDone(quiz, answers) {
  const total = quiz?.questions?.length || 0;
  return total > 0 && (answers || []).length >= total;
}

/**
 * @param {unknown} s
 * @param {number} max
 */
const clip = (s, max) => {
  const t = String(s ?? "").trim();
  return t.length > max ? t.slice(0, max - 1) + "…" : t;
};

/**
 * The plain-text result block stream.js appends to the assistant message in
 * history when the quiz completes — model-readable context for follow-ups
 * ("what did I get wrong?") that also rides the copy-conversation export
 * and the reloaded bubble. Deliberately NOT one of the "--- … ---" labeled
 * context blocks: those are stripped by the export/indexing paths, and this
 * one should stay visible everywhere.
 * @param {Quiz | null | undefined} quiz
 * @param {QuizAnswer[] | null | undefined} answers
 * @returns {string}
 */
export function quizSummaryText(quiz, answers) {
  const { correct, total, ungraded } = quizScore(quiz, answers);
  const lines = [
    `[Quiz completed: "${clip(quiz?.title || "Quiz", 80)}" — score ${correct}/${total}` +
      (ungraded ? ` (${ungraded} written answer${ungraded === 1 ? "" : "s"} could not be graded)` : "") +
      "]",
  ];
  (quiz?.questions || []).forEach((q, i) => {
    const a = (answers || [])[i];
    const v = answerVerdict(q, a);
    const mark = v === true ? "✓" : v === false ? "✗" : "–";
    let detail = "";
    if (typeof a?.free === "string") {
      detail = ` — answered in own words: "${clip(a.free, 120)}"`;
      if (v === false) detail += `; correct: "${clip(q.alternatives[q.correct], 120)}"`;
      if (v === null) detail += " (ungraded)";
    } else if (v === false && a) {
      detail = ` — answered "${clip(q.alternatives[a.pick ?? -1] ?? "?", 120)}"; correct: "${clip(q.alternatives[q.correct], 120)}"`;
    }
    lines.push(`${i + 1}. ${mark} ${clip(q.question, 200)}${detail}`);
  });
  return lines.join("\n");
}

// ---- grading call ------------------------------------------------------

/**
 * Grades ONE free-text answer. Resolves to {correct, comment} or null
 * (service down / quota blocked / unparseable) — the caller renders null as
 * "ungraded", never an error.
 * @param {QuizQuestion} question
 * @param {string} answer
 * @returns {Promise<{correct: boolean, comment: string} | null>}
 */
async function gradeFreeText(question, answer) {
  try {
    const res = await fetch("/api/quiz/grade", {
      method: "POST",
      headers: { "content-type": "application/json" },
      body: JSON.stringify({
        items: [
          {
            question: question.question,
            reference: question.alternatives[question.correct],
            answer,
          },
        ],
      }),
    });
    if (!res.ok) return null;
    const data = await res.json();
    const r = Array.isArray(data?.results) ? data.results[0] : null;
    return r && typeof r.correct === "boolean" ? { correct: r.correct, comment: String(r.comment || "") } : null;
  } catch {
    return null;
  }
}

// ---- DOM ---------------------------------------------------------------

const ALT_LETTERS = "ABCDEFGH";

/**
 * The slice of turns.js's turn object the quiz card uses. `_quizCard` is
 * this module's own idempotence marker on it.
 * @typedef {{el: HTMLElement, stats: HTMLElement, _quizCard?: HTMLElement}} QuizTurn
 */

/**
 * Renders the interactive quiz card into the turn body (before the stats
 * footer). One quiz per turn — a repeat event for the same turn is ignored,
 * matching the panorama's behavior. `hooks`: see the module header.
 * @param {QuizTurn | null | undefined} turn
 * @param {Quiz | null | undefined} quiz
 * @param {QuizHooks} [hooks]
 */
export function renderQuiz(turn, quiz, hooks = {}) {
  if (!turn?.el || turn._quizCard) return;
  const questions = Array.isArray(quiz?.questions) ? quiz.questions : [];
  if (!questions.length || !quiz) return;

  const wrap = document.createElement("div");
  wrap.className = "quiz-card";
  turn.el.insertBefore(wrap, turn.stats);
  turn._quizCard = wrap;

  // Answers given so far (seeded from a stored conversation's embed record).
  const answers = (Array.isArray(hooks.answers) ? hooks.answers : []).slice(0, questions.length);

  // Guards double-answering while the current question's feedback is up (or
  // a grading call is in flight); reset when Next re-renders.
  let settled = false;

  const render = () => {
    wrap.replaceChildren();
    if (quizDone(quiz, answers)) renderVerdict();
    else renderQuestion(answers.length);
  };

  const head = (/** @type {string} */ label) => {
    const h = document.createElement("div");
    h.className = "quiz-head";
    const title = document.createElement("span");
    title.className = "quiz-title";
    title.textContent = quiz.title || "Quiz";
    const progress = document.createElement("span");
    progress.className = "quiz-progress";
    progress.textContent = label;
    h.append(title, progress);
    return h;
  };

  /** @param {number} idx */
  function renderQuestion(idx) {
    const q = questions[idx];
    wrap.appendChild(head(`Question ${idx + 1} of ${questions.length}`));
    const qEl = document.createElement("div");
    qEl.className = "quiz-question";
    qEl.textContent = q.question;
    wrap.appendChild(qEl);

    const alts = document.createElement("div");
    alts.className = "quiz-alts";
    const altBtns = q.alternatives.map((alt, i) => {
      const btn = document.createElement("button");
      btn.type = "button";
      btn.className = "quiz-alt";
      const letter = document.createElement("span");
      letter.className = "quiz-alt-letter";
      letter.textContent = ALT_LETTERS[i] || String(i + 1);
      const text = document.createElement("span");
      text.textContent = alt;
      btn.append(letter, text);
      btn.addEventListener("click", () => {
        if (settled) return;
        settled = true;
        settle(q, { pick: i }, { altBtns, freeArea, freeBtn });
      });
      alts.appendChild(btn);
      return btn;
    });
    wrap.appendChild(alts);

    // The final alternative: answer in your own words.
    const freeWrap = document.createElement("div");
    freeWrap.className = "quiz-free";
    const freeLabel = document.createElement("div");
    freeLabel.className = "quiz-free-label";
    freeLabel.textContent = "…or answer in your own words:";
    const freeArea = document.createElement("textarea");
    freeArea.className = "quiz-free-input";
    freeArea.rows = 2;
    freeArea.placeholder = "Type your answer";
    const freeBtn = document.createElement("button");
    freeBtn.type = "button";
    freeBtn.className = "quiz-free-submit";
    freeBtn.textContent = "Submit answer";
    freeBtn.addEventListener("click", async () => {
      const text = freeArea.value.trim();
      if (!text || settled) return;
      settled = true;
      freeBtn.disabled = true;
      freeArea.disabled = true;
      for (const b of altBtns) b.disabled = true;
      freeBtn.textContent = "Grading…";
      const graded = await gradeFreeText(q, text);
      settle(
        q,
        { free: text, correct: graded ? graded.correct : null, comment: graded ? graded.comment : "" },
        { altBtns, freeArea, freeBtn },
      );
    });
    freeArea.addEventListener("keydown", (e) => {
      if (e.key === "Enter" && !e.shiftKey) {
        e.preventDefault();
        freeBtn.click();
      }
    });
    freeWrap.append(freeLabel, freeArea, freeBtn);
    wrap.appendChild(freeWrap);
  }

  /**
   * Record the answer, then show feedback in place: reveal the correct
   * alternative, the verdict for a free-text answer, the explanation, and
   * the Next / See result button.
   * @param {QuizQuestion} q
   * @param {QuizAnswer} answer
   * @param {{altBtns: HTMLButtonElement[], freeArea: HTMLTextAreaElement, freeBtn: HTMLButtonElement}} els
   */
  function settle(q, answer, els) {
    answers.push(answer);
    try {
      hooks.onAnswer?.(answers.slice());
    } catch {
      // persistence problems must never break the quiz interaction
    }
    const verdict = answerVerdict(q, answer);

    for (let i = 0; i < els.altBtns.length; i++) {
      const b = els.altBtns[i];
      b.disabled = true;
      if (i === q.correct) b.classList.add("correct");
      if (typeof answer.pick === "number" && i === answer.pick && verdict === false) b.classList.add("incorrect");
    }
    els.freeArea.disabled = true;
    els.freeBtn.disabled = true;
    els.freeBtn.textContent = "Submit answer";

    const fb = document.createElement("div");
    fb.className = "quiz-feedback " + (verdict === true ? "good" : verdict === false ? "bad" : "ungraded");
    const line = document.createElement("div");
    line.className = "quiz-verdict-line";
    line.textContent = verdict === true ? "✓ Correct" : verdict === false ? "✗ Not quite" : "– Couldn't grade this answer (it won't count toward your score)";
    fb.appendChild(line);
    if (typeof answer.free === "string") {
      const ref = document.createElement("div");
      ref.className = "quiz-reference";
      ref.textContent = (answer.comment ? answer.comment + " " : "") + `Reference answer: ${q.alternatives[q.correct]}`;
      fb.appendChild(ref);
    }
    if (q.explanation) {
      const ex = document.createElement("div");
      ex.className = "quiz-explain";
      ex.textContent = q.explanation;
      fb.appendChild(ex);
    }
    const next = document.createElement("button");
    next.type = "button";
    next.className = "quiz-next";
    next.textContent = answers.length >= questions.length ? "See your result" : "Next question";
    next.addEventListener("click", () => {
      settled = false;
      render();
    });
    fb.appendChild(next);
    wrap.appendChild(fb);
  }

  function renderVerdict() {
    const { correct, total, ungraded } = quizScore(quiz, answers);
    wrap.appendChild(head("Result"));
    const score = document.createElement("div");
    score.className = "quiz-score";
    score.textContent = `You scored ${correct} of ${total}`;
    wrap.appendChild(score);
    if (ungraded) {
      const note = document.createElement("div");
      note.className = "quiz-ungraded-note";
      note.textContent = `${ungraded} written answer${ungraded === 1 ? "" : "s"} couldn't be graded and ${ungraded === 1 ? "isn't" : "aren't"} counted.`;
      wrap.appendChild(note);
    }
    const recap = document.createElement("ol");
    recap.className = "quiz-recap";
    questions.forEach((q, i) => {
      const v = answerVerdict(q, answers[i]);
      const li = document.createElement("li");
      li.className = v === true ? "good" : v === false ? "bad" : "ungraded";
      const mark = document.createElement("span");
      mark.className = "quiz-recap-mark";
      mark.textContent = v === true ? "✓" : v === false ? "✗" : "–";
      const text = document.createElement("span");
      text.textContent = q.question;
      li.append(mark, text);
      if (v === false) {
        const fix = document.createElement("div");
        fix.className = "quiz-recap-fix";
        fix.textContent = `Correct: ${q.alternatives[q.correct]}`;
        li.appendChild(fix);
      }
      recap.appendChild(li);
    });
    wrap.appendChild(recap);
    try {
      hooks.onComplete?.(quizSummaryText(quiz, answers));
    } catch {
      // history/persistence problems must never break the verdict display
    }
  }

  render();
}

// Node tests for quiz.js's pure core: verdicts, scoring, the completed-quiz summary block.
import { test, describe } from "node:test";
import assert from "node:assert/strict";
import { answerVerdict, quizDone, quizScore, quizSummaryText } from "./quiz.js";

const quiz = {
  title: "Nordic capitals",
  questions: [
    { question: "Capital of Sweden?", alternatives: ["Oslo", "Stockholm", "Malmö"], correct: 1, explanation: "" },
    { question: "Capital of Norway?", alternatives: ["Oslo", "Bergen"], correct: 0, explanation: "" },
    { question: "Capital of Denmark?", alternatives: ["Aarhus", "Copenhagen"], correct: 1, explanation: "" },
  ],
};

describe("answerVerdict", () => {
  test("grades multiple-choice picks against the correct index", () => {
    assert.equal(answerVerdict(quiz.questions[0], { pick: 1 }), true);
    assert.equal(answerVerdict(quiz.questions[0], { pick: 0 }), false);
  });

  test("free-text answers carry their graded verdict; ungraded is null", () => {
    assert.equal(answerVerdict(quiz.questions[0], { free: "stockholm", correct: true, comment: "" }), true);
    assert.equal(answerVerdict(quiz.questions[0], { free: "oslo", correct: false, comment: "" }), false);
    assert.equal(answerVerdict(quiz.questions[0], { free: "stockholm", correct: null, comment: "" }), null);
  });

  test("missing question or answer is null, never a throw", () => {
    assert.equal(answerVerdict(undefined, { pick: 1 }), null);
    assert.equal(answerVerdict(quiz.questions[0], undefined), null);
    assert.equal(answerVerdict(quiz.questions[0], {}), null);
  });
});

describe("quizScore / quizDone", () => {
  test("counts correct answers and tracks ungraded free text separately", () => {
    const answers = [{ pick: 1 }, { free: "Oslo", correct: null, comment: "" }, { pick: 0 }];
    assert.deepEqual(quizScore(quiz, answers), { correct: 1, total: 3, ungraded: 1 });
  });

  test("partial progress is not done; full is", () => {
    assert.equal(quizDone(quiz, [{ pick: 1 }]), false);
    assert.equal(quizDone(quiz, [{ pick: 1 }, { pick: 0 }, { pick: 1 }]), true);
    assert.equal(quizDone({ questions: [] }, []), false);
  });
});

describe("quizSummaryText", () => {
  test("produces the score header and one marked line per question", () => {
    const answers = [
      { pick: 1 },
      { pick: 1 }, // wrong (correct is 0)
      { free: "København", correct: true, comment: "" },
    ];
    const s = quizSummaryText(quiz, answers);
    const lines = s.split("\n");
    assert.equal(lines[0], '[Quiz completed: "Nordic capitals" — score 2/3]');
    assert.match(lines[1], /^1\. ✓ Capital of Sweden\?$/);
    assert.match(lines[2], /^2\. ✗ Capital of Norway\? — answered "Bergen"; correct: "Oslo"$/);
    assert.match(lines[3], /^3\. ✓ Capital of Denmark\? — answered in own words: "København"$/);
  });

  test("notes ungraded written answers in the header and marks their lines", () => {
    const answers = [{ pick: 1 }, { pick: 0 }, { free: "?", correct: null, comment: "" }];
    const s = quizSummaryText(quiz, answers);
    assert.match(s, /score 2\/3 \(1 written answer could not be graded\)/);
    assert.match(s, /3\. – .*\(ungraded\)/);
  });

  test("an incorrect written answer shows the correct alternative", () => {
    const answers = [{ pick: 1 }, { pick: 0 }, { free: "Aarhus is the capital", correct: false, comment: "" }];
    const s = quizSummaryText(quiz, answers);
    assert.match(s, /3\. ✗ .*answered in own words: "Aarhus is the capital"; correct: "Copenhagen"/);
  });
});

// @ts-check
// Client-side document RAG: lets a conversation carry documents far past
// the 32K inline-message cap (hundreds or thousands of pages). A large
// attachment is chunked here, embedded through POST /api/embed (Berget's
// embedding model — the API token is a Worker secret, so embedding always
// goes through the server; the DOCUMENT TEXT of a locally-indexed file
// still transits the server only per-chunk for embedding and is not
// stored there), and indexed. Each question then retrieves only the most
// relevant excerpts into the outgoing message (stream.js).
//
// Where the index lives follows the account's cloud-storage knob
// (settings.js):
//   OFF (default) — IndexedDB in this browser (database `dr_rag`):
//     chunk text + Float32Array vectors, cosine top-k computed right here.
//     Nothing is stored server-side.
//   ON — ALSO pushed to the server (Vectorize + an exportable R2 copy,
//     src/rag.js), and queries prefer the server index (works across
//     devices); the local copy stays as a lazy cache and fallback.
//
// The RAG index is NOT encrypted (in either location): retrieval needs
// readable chunk text. Conversations outside projects stay encrypted
// regardless (history-store.js); PROJECT chats are themselves indexed
// (chat-rag.js) and therefore follow the same readable-when-indexed rule
// as documents — the settings UI spells out this split.
//
// The pure helpers (chunkText, cosineSim, topKChunks, f32/b64 codecs) are
// exported for the Node unit suite — keep this module import-safe outside
// a browser (no top-level DOM/IDB access).

import { serverHistoryOn, serverRagAvailable } from "./settings.js";

const DB_NAME = "dr_rag";
const DB_VERSION = 1;

const EMBED_BATCH = 32; // server allows 48/call — headroom for prefixes
const MAX_CHUNKS = 6000; // matches the server's per-doc cap
export const CHUNK_TARGET_CHARS = 1400;
export const CHUNK_OVERLAP_CHARS = 200;

/**
 * One piece of a chunked document, in document order.
 * @typedef {{seq: number, text: string}} Chunk
 */

/**
 * The `docs` store row: per-document bookkeeping (the chunk text/vectors
 * live in the `chunks` store). Extra fields ride along via appendToDoc's
 * `meta` (chat-rag.js keeps its srcMsgs counter here).
 * @typedef {object} DocRow
 * @property {string} id
 * @property {string} name
 * @property {number} chunkCount
 * @property {number} dims embedding dimensions
 * @property {number} chars total source characters indexed
 * @property {number} addedAt epoch ms
 * @property {number} [srcMsgs]
 */

/**
 * The `chunks` store row: one embedded chunk, keyed `<docId>:<seq>`.
 * @typedef {{key: string, docId: string, seq: number, text: string, vector: Float32Array}} ChunkRow
 */

/**
 * One retrieval hit, best-first.
 * @typedef {{docId: string, seq: number, text: string, score: number}} Match
 */

// ---- pure helpers (unit-tested) ---------------------------------------------

/**
 * Sliding chunker: ~targetChars pieces, preferring paragraph/sentence/line
 * breaks in the back half of the window, with overlapChars of continuity
 * between consecutive chunks so a fact straddling a boundary is still
 * retrievable.
 * @param {string | null | undefined} text
 * @param {{targetChars?: number, overlapChars?: number}} [opts]
 * @returns {Chunk[]}
 */
export function chunkText(text, { targetChars = CHUNK_TARGET_CHARS, overlapChars = CHUNK_OVERLAP_CHARS } = {}) {
  const clean = String(text || "")
    .replace(/\r\n/g, "\n")
    .replace(/[ \t]+/g, " ")
    .replace(/\n{3,}/g, "\n\n")
    .trim();
  if (!clean) return [];
  /** @type {string[]} */
  const chunks = [];
  let start = 0;
  while (start < clean.length && chunks.length < MAX_CHUNKS) {
    let end = Math.min(start + targetChars, clean.length);
    if (end < clean.length) {
      const window = clean.slice(start, end);
      const brk = Math.max(
        window.lastIndexOf("\n\n"),
        window.lastIndexOf(". "),
        window.lastIndexOf("\n"),
      );
      if (brk > targetChars * 0.5) end = start + brk + 1;
    }
    const piece = clean.slice(start, end).trim();
    if (piece) chunks.push(piece);
    if (end >= clean.length) break;
    start = Math.max(end - overlapChars, start + 1);
  }
  return chunks.map((t, seq) => ({ seq, text: t }));
}

/**
 * @param {ArrayLike<number>} a
 * @param {ArrayLike<number>} b
 * @returns {number} cosine similarity over the shared prefix (0 when a norm is 0)
 */
export function cosineSim(a, b) {
  let dot = 0;
  let na = 0;
  let nb = 0;
  const n = Math.min(a.length, b.length);
  for (let i = 0; i < n; i++) {
    dot += a[i] * b[i];
    na += a[i] * a[i];
    nb += b[i] * b[i];
  }
  const denom = Math.sqrt(na) * Math.sqrt(nb);
  return denom ? dot / denom : 0;
}

/**
 * The k most query-similar chunks, best first.
 * @param {Array<{docId: string, seq: number, text: string, vector: ArrayLike<number>}>} chunks
 * @param {ArrayLike<number>} queryVector
 * @param {number} k
 * @returns {Match[]}
 */
export function topKChunks(chunks, queryVector, k) {
  return chunks
    .map((c) => ({ docId: c.docId, seq: c.seq, text: c.text, score: cosineSim(queryVector, c.vector) }))
    .sort((a, b) => b.score - a.score)
    .slice(0, k);
}

/**
 * @param {ArrayLike<number>} arr embedding vector
 * @returns {string} base64 of the little-endian float32 bytes
 */
export function f32ToB64(arr) {
  const bytes = new Uint8Array(Float32Array.from(arr).buffer);
  let binary = "";
  const CHUNK = 0x8000;
  for (let i = 0; i < bytes.length; i += CHUNK) {
    binary += String.fromCharCode(...bytes.subarray(i, i + CHUNK));
  }
  return btoa(binary);
}

/**
 * @param {string} b64
 * @returns {Float32Array}
 */
export function b64ToF32(b64) {
  const binary = atob(b64);
  const bytes = new Uint8Array(binary.length);
  for (let i = 0; i < binary.length; i++) bytes[i] = binary.charCodeAt(i);
  return new Float32Array(bytes.buffer);
}

// ---- IndexedDB --------------------------------------------------------------

/** @type {Promise<IDBDatabase> | null} */
let dbPromise = null;

/** @returns {Promise<IDBDatabase>} */
function openDb() {
  if (dbPromise) return dbPromise;
  dbPromise = new Promise((resolve, reject) => {
    const req = indexedDB.open(DB_NAME, DB_VERSION);
    req.onupgradeneeded = () => {
      const db = req.result;
      if (!db.objectStoreNames.contains("docs")) db.createObjectStore("docs", { keyPath: "id" });
      if (!db.objectStoreNames.contains("chunks")) {
        const store = db.createObjectStore("chunks", { keyPath: "key" });
        store.createIndex("docId", "docId");
      }
      // Metadata rows for OPFS-stored original files (public/js/opfs.js).
      if (!db.objectStoreNames.contains("files")) db.createObjectStore("files", { keyPath: "id" });
    };
    req.onsuccess = () => resolve(req.result);
    req.onerror = () => reject(req.error);
  });
  return dbPromise;
}

/**
 * @template T
 * @param {IDBRequest<T>} req
 * @returns {Promise<T>}
 */
const reqToPromise = (req) =>
  new Promise((resolve, reject) => {
    req.onsuccess = () => resolve(req.result);
    req.onerror = () => reject(req.error);
  });

/**
 * @param {string} name object store name
 * @param {IDBTransactionMode} mode
 * @returns {Promise<IDBObjectStore>} the store on a fresh single-store transaction
 */
async function store(name, mode) {
  const db = await openDb();
  return db.transaction(name, mode).objectStore(name);
}

// Small facade opfs.js uses for its metadata rows, so the OPFS module never
// has to know this database's layout.
export const filesMetaStore = {
  /** @param {{id: string, [k: string]: unknown}} rec */
  put: async (rec) => reqToPromise((await store("files", "readwrite")).put(rec)),
  /** @param {string} id */
  delete: async (id) => reqToPromise((await store("files", "readwrite")).delete(id)),
  getAll: async () => reqToPromise((await store("files", "readonly")).getAll()),
};

// ---- embedding via the server proxy -----------------------------------------

/**
 * @param {string[]} texts
 * @param {"passage" | "query"} kind embedding prefix the server applies
 * @returns {Promise<{vectors: Float32Array[], dims: number, model: string}>}
 */
async function embedBatch(texts, kind) {
  const res = await fetch("/api/embed", {
    method: "POST",
    headers: { "content-type": "application/json" },
    body: JSON.stringify({ texts, kind }),
  });
  const data = await res.json().catch(() => null);
  if (!res.ok) throw new Error(data?.error || "Embedding failed (" + res.status + ")");
  return { vectors: data.vectors.map(b64ToF32), dims: data.dims, model: data.model };
}

// ---- the index --------------------------------------------------------------

/** @param {string} docId */
export async function hasDoc(docId) {
  return !!(await reqToPromise((await store("docs", "readonly")).get(docId)));
}

/**
 * @param {string} docId
 * @returns {Promise<DocRow | null>}
 */
export async function getDoc(docId) {
  return (await reqToPromise((await store("docs", "readonly")).get(docId))) || null;
}

/** @returns {Promise<DocRow[]>} */
export async function listDocs() {
  return reqToPromise((await store("docs", "readonly")).getAll());
}

/** @param {string} docId */
export async function deleteDoc(docId) {
  const chunks = await chunksForDoc(docId);
  const s = await store("chunks", "readwrite");
  for (const c of chunks) s.delete(c.key);
  await reqToPromise((await store("docs", "readwrite")).delete(docId));
}

/**
 * @param {string} docId
 * @returns {Promise<ChunkRow[]>}
 */
async function chunksForDoc(docId) {
  const s = await store("chunks", "readonly");
  return reqToPromise(s.index("docId").getAll(docId));
}

/**
 * Doc row + all its chunk rows in ONE transaction, so a failure can't leave
 * a doc row pointing at half-written chunks.
 * @param {DocRow} doc
 * @param {Chunk[]} chunks
 * @param {Float32Array[]} vectors parallel to `chunks`
 */
async function putDocLocally(doc, chunks, vectors) {
  const db = await openDb();
  await new Promise((resolve, reject) => {
    const tx = db.transaction(["docs", "chunks"], "readwrite");
    tx.objectStore("docs").put(doc);
    const cs = tx.objectStore("chunks");
    chunks.forEach((c, i) => {
      cs.put({ key: `${doc.id}:${c.seq}`, docId: doc.id, seq: c.seq, text: c.text, vector: vectors[i] });
    });
    tx.oncomplete = resolve;
    tx.onerror = () => reject(tx.error);
  });
}

/**
 * One locally-indexed document in its portable form — the same
 * chunks-plus-b64-vectors shape the server index stores in R2 and
 * importDoc below accepts, so moving a doc never re-embeds. Used by the
 * server push right below and by the project vault archive
 * (public/js/vault.js).
 * @param {string} docId
 * @returns {Promise<?{docId: string, name: string, chunks: Chunk[],
 *   vectors: string[], createdAt: number}>} null when the doc isn't in the
 *   local index
 */
export async function exportDoc(docId) {
  const doc = await reqToPromise((await store("docs", "readonly")).get(docId));
  if (!doc) return null;
  const chunks = (await chunksForDoc(docId)).sort((a, b) => a.seq - b.seq);
  return {
    docId,
    name: doc.name,
    chunks: chunks.map((c) => ({ seq: c.seq, text: c.text })),
    vectors: chunks.map((c) => f32ToB64(c.vector)),
    createdAt: doc.addedAt || Date.now(),
  };
}

/**
 * Push one locally-indexed document to the server index (vectors included,
 * so the server never re-embeds). Used at index time when the knob is on,
 * and by sync.js when it's switched on later.
 * @param {string} docId
 */
export async function pushDocToServer(docId) {
  const data = await exportDoc(docId);
  if (!data) throw new Error("Document not in the local index.");
  const res = await fetch("/api/rag/index", {
    method: "POST",
    headers: { "content-type": "application/json" },
    body: JSON.stringify(data),
  });
  if (!res.ok) {
    const data = await res.json().catch(() => null);
    throw new Error(data?.error || "Server indexing failed (" + res.status + ")");
  }
}

/**
 * Chunk + embed + store one document. opts.cloud=false skips the server
 * mirror even when the account knob is on — the per-project storage opt-out
 * (public/js/projects.js decides).
 * @param {string} docId
 * @param {string} name display name
 * @param {string} fullText
 * @param {{onProgress?: (done: number, total: number) => void, cloud?: boolean}} [opts]
 *   onProgress drives the attachment card's indexing badge
 * @returns {Promise<{chunkCount: number, truncated: boolean}>}
 */
export async function indexDocument(docId, name, fullText, { onProgress, cloud = true } = {}) {
  const chunks = chunkText(fullText);
  if (!chunks.length) throw new Error("No indexable text.");
  const truncated = chunks.length >= MAX_CHUNKS; // chunker stops there — tail unindexed
  const vectors = new Array(chunks.length);
  for (let i = 0; i < chunks.length; i += EMBED_BATCH) {
    const batch = chunks.slice(i, i + EMBED_BATCH);
    const { vectors: vs } = await embedBatch(batch.map((c) => c.text), "passage");
    vs.forEach((v, j) => { vectors[i + j] = v; });
    onProgress?.(Math.min(i + EMBED_BATCH, chunks.length), chunks.length);
  }
  const doc = {
    id: docId,
    name,
    chunkCount: chunks.length,
    dims: vectors[0].length,
    chars: fullText.length,
    addedAt: Date.now(),
  };
  await putDocLocally(doc, chunks, vectors);
  // Mirror to the server index when cloud storage is on — fail-soft: a
  // hiccup here leaves a perfectly working local index (sync.js re-pushes).
  if (cloud && serverHistoryOn() && serverRagAvailable()) {
    try {
      await pushDocToServer(docId);
    } catch (err) {
      console.warn("rag: server mirror failed, keeping local index", err);
    }
  }
  return { chunkCount: chunks.length, truncated };
}

/**
 * Incrementally extend an indexed doc (creating it on first call) — the
 * growing-source case (project chats, chat-rag.js): only the NEW text is
 * chunked and embedded, appended after the existing chunks. `meta` fields
 * ride on the doc row (chat-rag.js keeps its srcMsgs progress counter
 * there). The server mirror re-pushes the WHOLE doc — /api/rag/index
 * replaces per docId and vectors travel along, so nothing is re-embedded;
 * for turn-sized increments that's bandwidth, not spend.
 * @param {string} docId
 * @param {string} name display name
 * @param {string} text the NEW text only
 * @param {{meta?: object, cloud?: boolean}} [opts]
 * @returns {Promise<{chunkCount: number, appended: number}>}
 */
export async function appendToDoc(docId, name, text, { meta = {}, cloud = true } = {}) {
  const existing = await getDoc(docId);
  const startSeq = existing?.chunkCount || 0;
  const pieces = chunkText(text)
    .map((c) => ({ seq: startSeq + c.seq, text: c.text }))
    .slice(0, Math.max(0, MAX_CHUNKS - startSeq)); // server per-doc cap
  if (!pieces.length) return { chunkCount: startSeq, appended: 0 };
  const vectors = new Array(pieces.length);
  for (let i = 0; i < pieces.length; i += EMBED_BATCH) {
    const batch = pieces.slice(i, i + EMBED_BATCH);
    const { vectors: vs } = await embedBatch(batch.map((c) => c.text), "passage");
    vs.forEach((v, j) => { vectors[i + j] = v; });
  }
  const doc = {
    id: docId,
    name,
    chunkCount: startSeq + pieces.length,
    dims: vectors[0].length,
    chars: (existing?.chars || 0) + text.length,
    addedAt: existing?.addedAt || Date.now(),
    ...meta,
  };
  await putDocLocally(doc, pieces, vectors);
  if (cloud && serverHistoryOn() && serverRagAvailable()) {
    try {
      await pushDocToServer(docId);
    } catch (err) {
      console.warn("rag: server mirror failed, keeping local index", err);
    }
  }
  return { chunkCount: doc.chunkCount, appended: pieces.length };
}

// ---- retrieval --------------------------------------------------------------

/**
 * @param {string[]} docIds
 * @param {string} queryText
 * @param {number} topK
 * @returns {Promise<Match[]>}
 */
async function retrieveLocal(docIds, queryText, topK) {
  const { vectors } = await embedBatch([queryText.slice(0, 2000)], "query");
  /** @type {ChunkRow[]} */
  const all = [];
  for (const docId of docIds) all.push(...(await chunksForDoc(docId)));
  return topKChunks(all, vectors[0], topK);
}

/**
 * @param {string[]} docIds
 * @param {string} queryText
 * @param {number} topK
 * @returns {Promise<Match[]>}
 */
async function retrieveServer(docIds, queryText, topK) {
  const res = await fetch("/api/rag/query", {
    method: "POST",
    headers: { "content-type": "application/json" },
    body: JSON.stringify({ query: queryText.slice(0, 2000), docIds, topK }),
  });
  const data = await res.json().catch(() => null);
  if (!res.ok) throw new Error(data?.error || "Retrieval failed (" + res.status + ")");
  return data.matches || [];
}

/**
 * The most relevant chunks for this question across the given documents.
 * Prefers the server index when cloud storage is on (it may hold documents
 * indexed on ANOTHER device); falls back to — and merges nothing from —
 * the local index when the server comes up empty or errors.
 * @param {string[]} docIds
 * @param {string} queryText
 * @param {number} [topK]
 * @returns {Promise<Match[]>}
 */
export async function retrieve(docIds, queryText, topK = 8) {
  if (!docIds.length || !queryText.trim()) return [];
  if (serverHistoryOn() && serverRagAvailable()) {
    try {
      const matches = await retrieveServer(docIds, queryText, topK);
      if (matches.length) return matches;
    } catch (err) {
      console.warn("rag: server retrieval failed, trying local index", err);
    }
  }
  try {
    return await retrieveLocal(docIds, queryText, topK);
  } catch (err) {
    console.warn("rag: retrieval failed", err);
    return [];
  }
}

/**
 * Positional fallback when semantic retrieval is unavailable (embedding
 * endpoint down mid-conversation): the opening chunks still give the model
 * the document's framing rather than nothing at all.
 * @param {string} docId
 * @param {number} [n]
 * @returns {Promise<Match[]>}
 */
export async function firstChunks(docId, n = 4) {
  const chunks = (await chunksForDoc(docId)).sort((a, b) => a.seq - b.seq).slice(0, n);
  return chunks.map((c) => ({ docId: c.docId, seq: c.seq, text: c.text, score: 0 }));
}

// ---- import (sync.js) ---------------------------------------------------------

/**
 * Import a document in the shape the server stores in R2 (src/rag.js) —
 * chunks + b64 vectors — so a cloud→local pull never re-embeds. sync.js's
 * push direction goes through pushDocToServer above.
 * @param {{docId?: string, name?: string, chunks?: Chunk[], vectors?: string[], createdAt?: number} | null | undefined} data
 * @returns {Promise<boolean>} false when the payload isn't importable
 */
export async function importDoc(data) {
  if (!data?.docId || !Array.isArray(data.chunks) || !Array.isArray(data.vectors)) return false;
  const vectors = data.vectors.map(b64ToF32);
  await putDocLocally(
    {
      id: data.docId,
      name: data.name || data.docId,
      chunkCount: data.chunks.length,
      dims: vectors[0]?.length || 0,
      chars: data.chunks.reduce((s, c) => s + (c.text?.length || 0), 0),
      addedAt: data.createdAt || Date.now(),
    },
    data.chunks,
    vectors,
  );
  return true;
}

// Node tests for rag.js's pure core: chunking coverage/overlap properties, cosine top-k, the f32⇄b64 vector codec.
import { test } from "node:test";
import assert from "node:assert/strict";

import {
  b64ToF32,
  chunkText,
  cosineSim,
  f32ToB64,
  topKChunks,
} from "./rag.js";

test("chunkText returns nothing for empty input", () => {
  assert.deepEqual(chunkText(""), []);
  assert.deepEqual(chunkText("   \n\n  "), []);
  assert.deepEqual(chunkText(null), []);
});

test("chunkText keeps a short text as one chunk", () => {
  const chunks = chunkText("A short paragraph.");
  assert.equal(chunks.length, 1);
  assert.deepEqual(chunks[0], { seq: 0, text: "A short paragraph." });
});

test("chunkText covers the whole text with sequential seqs and bounded sizes", () => {
  const para = "The quick brown fox jumps over the lazy dog. ".repeat(8).trim();
  const text = Array.from({ length: 40 }, (_, i) => `Section ${i}. ${para}`).join("\n\n");
  const chunks = chunkText(text, { targetChars: 1000, overlapChars: 150 });
  assert.ok(chunks.length > 5);
  chunks.forEach((c, i) => {
    assert.equal(c.seq, i);
    assert.ok(c.text.length <= 1000, `chunk ${i} too large (${c.text.length})`);
    assert.ok(c.text.trim().length > 0);
  });
  // Every section header must appear in some chunk — nothing skipped.
  for (let i = 0; i < 40; i++) {
    assert.ok(chunks.some((c) => c.text.includes(`Section ${i}.`)), `Section ${i} missing`);
  }
});

test("chunkText overlaps consecutive chunks for boundary continuity", () => {
  const text = ("word ".repeat(600)).trim(); // no natural breaks
  const chunks = chunkText(text, { targetChars: 800, overlapChars: 200 });
  assert.ok(chunks.length >= 2);
  const tail = chunks[0].text.slice(-60);
  assert.ok(chunks[1].text.includes(tail.slice(0, 30)), "no overlap between chunk 0 and 1");
});

test("chunkText makes progress on pathological input (never loops)", () => {
  // overlap >= target would stall a naive implementation
  const chunks = chunkText("x".repeat(5000), { targetChars: 100, overlapChars: 100 });
  assert.ok(chunks.length > 0);
  assert.ok(chunks.length < 5000);
});

test("cosineSim basics", () => {
  assert.equal(cosineSim([1, 0], [1, 0]), 1);
  assert.equal(cosineSim([1, 0], [0, 1]), 0);
  assert.equal(cosineSim([1, 0], [-1, 0]), -1);
  assert.equal(cosineSim([0, 0], [1, 1]), 0); // zero vector → 0, not NaN
});

test("topKChunks ranks by similarity and caps at k", () => {
  const chunks = [
    { docId: "d", seq: 0, text: "orthogonal", vector: new Float32Array([0, 1]) },
    { docId: "d", seq: 1, text: "aligned", vector: new Float32Array([1, 0.01]) },
    { docId: "d", seq: 2, text: "opposite", vector: new Float32Array([-1, 0]) },
    { docId: "d", seq: 3, text: "close", vector: new Float32Array([0.9, 0.4]) },
  ];
  const top = topKChunks(chunks, new Float32Array([1, 0]), 2);
  assert.equal(top.length, 2);
  assert.equal(top[0].text, "aligned");
  assert.equal(top[1].text, "close");
  assert.ok(top[0].score > top[1].score);
  assert.equal(top[0].docId, "d");
});

test("client f32/b64 codec round-trips (must match the server's)", () => {
  const v = new Float32Array([0.25, -3.5, 1e-6, 42]);
  const back = b64ToF32(f32ToB64(v));
  assert.equal(back.length, v.length);
  for (let i = 0; i < v.length; i++) assert.equal(back[i], v[i]);
});

// @ts-check
// Answer recovery — the polling client for the server's parked answers,
// extracted from stream.js.
//
// The server parks every finished answer in a short-lived cache
// (src/answers.js) keyed by x-request-id: if our stream dies, we poll the
// completed answer back instead of asking the user to resend; if it
// arrives intact, we ack so the server purges its copy immediately.
//
// This module is the transport half only — the poll loop with its rolling
// deadlines, the live "Still researching…" ticker, and the ack. What
// happens to a recovered answer (rendering it, appending it to history,
// persisting, arming the resume-across-relaunch pointer) stays with the
// conversation state in stream.js.

import { finishGenericStep, startGenericStep, updateGenericStep } from "./activity.js";

// Abort-aware sleep: a Stop press mid-wait resolves immediately instead of
// letting the button appear dead for up to a poll interval.
/**
 * @param {number} ms
 * @param {AbortSignal | null | undefined} signal
 * @returns {Promise<void>}
 */
const sleep = (ms, signal) =>
  new Promise((resolve) => {
    const timer = setTimeout(done, ms);
    function done() {
      clearTimeout(timer);
      signal?.removeEventListener("abort", done);
      resolve();
    }
    if (signal) signal.addEventListener("abort", done, { once: true });
  });

/** @param {string} requestId */
export function ackAnswer(requestId) {
  if (!requestId) return;
  fetch("/api/chat/answer?id=" + encodeURIComponent(requestId), { method: "DELETE" }).catch(() => {});
}

// The pipeline may still be researching when our connection dies (it runs
// to completion server-side), so keep polling until well past the time
// budget. Repeated 404s mean recovery isn't available (no DB, or expired).
// `isCurrent` going false ends the poll early if the user starts a new
// chat meanwhile.
// Polls the server-parked answer. Returns { data, reason } where reason is:
//   "done"    — data holds the recovered answer
//   "lost"    — the server confirmed the run died (stale heartbeat)
//   "gone"    — no recovery row (no DB, or already expired/purged)
//   "empty"   — the run finished but produced nothing
//   "timeout" — still running when the deadline passed
//   "aborted" — a new chat/load ended the poll
//   "stopped" — the user pressed Stop (signal aborted) — the wait ends NOW,
//               the composer/buttons come back, and the server finishes (and
//               parks) its answer unobserved
// Once the server confirms the run is still going, the step shows a live
// elapsed counter so a long research run reads as progress, not a frozen
// app.
//
// Deadlines: the initial budget-derived deadline only governs the wait for a
// FIRST sign of life. Every poll that confirms the run is STILL GOING (the
// server heartbeats its recovery row every 15s precisely so this is
// answerable) extends the deadline by a rolling window — a production run
// (2026-07-08, ref 614e6f19: a 20s budget that legitimately took 251s after
// synthesis stalls/retries on a loaded Mistral Medium) finished COMPLETE on
// the server, but the fixed budget+120s deadline had abandoned the poll at
// 140s, stranding the user with nothing while a finished answer sat in the
// cache. A dead run can't string us along: its heartbeat goes stale and the
// server answers "lost" within ~45s. The hard cap matches the server's
// 15-minute answer TTL — past that there is nothing left to recover.
const RECOVERY_RUNNING_EXTENSION_MS = 90_000;
const RECOVERY_HARD_CAP_MS = 15 * 60 * 1000;
//
// `startLabel` null → SILENT recovery: poll WITHOUT adding any banner. This
// was originally the DEFAULT for in-session drops ("keep the banners already
// on screen — the honest view"), but that design failed in production
// (2026-07-08, request a77001ac): the surviving banner was a single spinning
// "Checking Google Maps…" step that never advances (step_done events aren't
// replayed to a dead stream), so a 203s server run read as STUCK FOREVER.
// In-session drops now settle the dead spinners and show this step's live
// elapsed counter too — the counter is driven by its own 1-second ticker,
// decoupled from the (slower, latency-variable) network poll so it ticks
// evenly instead of lurching by the poll interval.
/**
 * @param {any} turn  the assistant turn the recovery step renders into
 * @param {string} requestId
 * @param {number | null | undefined} budgetS
 * @param {() => boolean} isCurrent  false once another conversation owns the screen
 * @param {string | null} [startLabel]
 * @param {AbortSignal | null} [signal]
 * @returns {Promise<{data: any, reason: string}>}
 */
export async function recoverAnswer(turn, requestId, budgetS, isCurrent, startLabel = null, signal = null) {
  if (!requestId) return { data: null, reason: "gone" };
  const showStep = !!startLabel;
  if (showStep) startGenericStep(turn, "recover", startLabel);
  const startedAt = Date.now();
  const hardCap = startedAt + RECOVERY_HARD_CAP_MS;
  let deadline = startedAt + ((budgetS || 60) + 120) * 1000;
  let misses = 0;
  let reason = "timeout";
  let running = false; // flips true once the server confirms it's still researching

  const ticker = showStep
    ? setInterval(() => {
        if (running) {
          updateGenericStep(turn, "recover", `Still researching on the server… (${Math.round((Date.now() - startedAt) / 1000)}s)`);
        }
      }, 1000)
    : null;

  try {
    // Poll immediately first: on a boot resume the server usually finished
    // while we were away, so the answer is already parked and the very first
    // poll returns it — no wait. Only if it's still running do we sleep/re-poll.
    while (Date.now() < deadline && isCurrent() && !signal?.aborted) {
      try {
        const res = await fetch("/api/chat/answer?id=" + encodeURIComponent(requestId));
        if (res.status === 404) {
          if (++misses >= 3) { reason = "gone"; break; }
        } else if (res.ok) {
          const data = await res.json();
          if (data.status === "done") {
            if (!data.text) { reason = "empty"; break; }
            if (showStep) finishGenericStep(turn, { id: "recover", label: "Answer recovered after connection loss" });
            return { data, reason: "done" };
          }
          if (data.status === "lost") { reason = "lost"; break; } // server run died
          misses = 0; // still researching
          running = true;
          // Confirmed alive: keep waiting past the budget-derived deadline
          // (rolling window, hard-capped) — see the constants above.
          deadline = Math.min(hardCap, Math.max(deadline, Date.now() + RECOVERY_RUNNING_EXTENSION_MS));
        }
      } catch {
        // still offline — keep trying until the deadline
      }
      await sleep(4000, signal);
    }
  } finally {
    if (ticker) clearInterval(ticker);
  }
  if (!isCurrent()) reason = "aborted";
  else if (signal?.aborted) reason = "stopped";
  if (showStep) {
    finishGenericStep(turn, {
      id: "recover",
      label:
        reason === "lost"
          ? "Research was interrupted on the server"
          : reason === "stopped"
            ? "Stopped waiting — the research continues on the server"
            : "Could not recover the answer",
    });
  }
  return { data: null, reason };
}

// PDF report generation for answers — branded DeepResearch.se.
// jsPDF (vendored, ~360KB) is injected on first use only, so the normal
// page load never pays for it.

let jspdfLoading = null;
function loadJsPdf() {
  if (window.jspdf) return Promise.resolve();
  if (!jspdfLoading) {
    jspdfLoading = new Promise((resolve, reject) => {
      const s = document.createElement("script");
      s.src = "/vendor/jspdf.umd.min.js";
      s.onload = resolve;
      s.onerror = () => reject(new Error("Could not load the PDF library."));
      document.head.appendChild(s);
    });
  }
  return jspdfLoading;
}

const ACCENT = [13, 79, 160]; // --accent
const TEXT = [10, 46, 92]; // --text
const MUTED = [47, 93, 142]; // --muted

// Light markdown -> flow of typed lines for the PDF: headings, bullets,
// plain paragraphs. Inline markers (** _ ` [n]) are kept readable.
function mdToBlocks(md) {
  const blocks = [];
  for (const raw of String(md).split("\n")) {
    const line = raw.replace(/\*\*([^*]+)\*\*/g, "$1").replace(/`([^`]+)`/g, "$1");
    const h = line.match(/^(#{1,4})\s+(.*)/);
    if (h) {
      blocks.push({ kind: "h" + h[1].length, text: h[2].trim() });
    } else if (/^\s*[-*•]\s+/.test(line)) {
      blocks.push({ kind: "li", text: line.replace(/^\s*[-*•]\s+/, "") });
    } else if (/^\s*\d+\.\s+/.test(line)) {
      // Numbered items keep their own "1." marker — no bullet on top.
      blocks.push({ kind: "li", text: line.trim(), ordered: true });
    } else {
      blocks.push({ kind: "p", text: line });
    }
  }
  return blocks;
}

/**
 * Generates and downloads the report.
 * @param {object} turn  the turn object (turns.js Turn) — .text is the
 *   markdown answer, .question the title, .images the embedded figures
 * @param {{model?: string}} [meta]  extra metadata printed under the title
 * @returns {Promise<void>} resolves once the share sheet / download started
 */
export async function downloadReport(turn, meta = {}) {
  await loadJsPdf();
  const { jsPDF } = window.jspdf;
  const doc = new jsPDF({ unit: "pt", format: "a4" });
  const W = doc.internal.pageSize.getWidth();
  const H = doc.internal.pageSize.getHeight();
  const M = 52; // margin
  const bodyW = W - 2 * M;
  let y = 0;

  const now = new Date();
  const dateStr = now.toISOString().slice(0, 16).replace("T", " ") + " UTC";

  const header = () => {
    doc.setFont("helvetica", "bold");
    doc.setFontSize(11);
    doc.setTextColor(...ACCENT);
    doc.text("DeepResearch.se", M, 36);
    doc.setFont("helvetica", "normal");
    doc.setFontSize(8.5);
    doc.setTextColor(...MUTED);
    doc.text("Research report · " + dateStr, W - M, 36, { align: "right" });
    doc.setDrawColor(...ACCENT);
    doc.setLineWidth(1.1);
    doc.line(M, 44, W - M, 44);
    y = 66;
  };
  const footer = () => {
    const page = doc.getCurrentPageInfo().pageNumber;
    doc.setFont("helvetica", "normal");
    doc.setFontSize(8);
    doc.setTextColor(...MUTED);
    doc.text("Generated by DeepResearch.se", M, H - 26);
    doc.text("Page " + page, W - M, H - 26, { align: "right" });
  };
  const newPage = () => {
    footer();
    doc.addPage();
    header();
  };
  const ensure = (needed) => {
    if (y + needed > H - 48) newPage();
  };

  header();

  // Question as the title.
  if (turn.question) {
    doc.setFont("helvetica", "bold");
    doc.setFontSize(14);
    doc.setTextColor(...TEXT);
    for (const line of doc.splitTextToSize(turn.question, bodyW)) {
      ensure(20);
      doc.text(line, M, y);
      y += 19;
    }
    y += 2;
  }
  if (meta.model) {
    doc.setFont("helvetica", "normal");
    doc.setFontSize(8.5);
    doc.setTextColor(...MUTED);
    ensure(14);
    doc.text("Model: " + meta.model, M, y);
    y += 18;
  }

  // Images the user attached to the question, embedded as figures under
  // the title — the same downscaled JPEG data URLs that went to the model.
  const maxImgH = H - 48 - 66; // printable height between header and footer
  for (const dataUrl of turn.images || []) {
    let props;
    try {
      props = doc.getImageProperties(dataUrl);
    } catch {
      continue; // unreadable image — never block the report over a figure
    }
    if (!props?.width || !props?.height) continue;
    let w = Math.min(bodyW, props.width * 0.75); // px at 96dpi → pt
    let h = (props.height / props.width) * w;
    if (h > maxImgH) {
      w *= maxImgH / h;
      h = maxImgH;
    }
    ensure(h + 6);
    doc.addImage(dataUrl, "JPEG", M, y, w, h);
    y += h + 14;
  }

  // Body.
  for (const b of mdToBlocks(turn.text)) {
    if (!b.text.trim()) {
      y += 7;
      continue;
    }
    let size = 10.5;
    let style = "normal";
    let indent = 0;
    let prefix = "";
    let lead = 15;
    if (b.kind === "h1") { size = 13; style = "bold"; lead = 20; y += 6; }
    else if (b.kind === "h2") { size = 12; style = "bold"; lead = 18; y += 5; }
    else if (b.kind === "h3" || b.kind === "h4") { size = 11; style = "bold"; lead = 16; y += 4; }
    else if (b.kind === "li") { indent = 14; prefix = b.ordered ? "" : "•  "; }
    doc.setFont("helvetica", style);
    doc.setFontSize(size);
    doc.setTextColor(...TEXT);
    const lines = doc.splitTextToSize(b.text, bodyW - indent - (prefix ? 10 : 0));
    lines.forEach((line, i) => {
      ensure(lead + 2);
      doc.text((i === 0 ? prefix : prefix ? "   " : "") + line, M + indent, y);
      y += lead;
    });
  }
  footer();

  const stamp = now.toISOString().slice(0, 16).replace(/[-:]/g, "").replace("T", "-");
  await savePdf(doc, `deepresearch-report-${stamp}.pdf`);
}

// NEVER use jsPDF's doc.save(): its Safari fallback navigates the page to
// the blob URL, and a navigation aborts every in-flight fetch (it killed a
// streaming answer in production). Hand the blob over ourselves instead —
// the native share sheet on touch devices (no navigation, and the natural
// way to save/AirDrop/mail a file on a phone), else a plain <a download>.
async function savePdf(doc, filename) {
  const blob = doc.output("blob");
  const file = new File([blob], filename, { type: "application/pdf" });
  const touch = matchMedia("(pointer: coarse)").matches;
  if (touch && navigator.canShare?.({ files: [file] })) {
    try {
      await navigator.share({ files: [file] });
      return;
    } catch (err) {
      if (err?.name === "AbortError") return; // user closed the sheet
      // Gesture expired or share refused — fall through to the download.
    }
  }
  const url = URL.createObjectURL(blob);
  const a = document.createElement("a");
  a.href = url;
  a.download = filename;
  document.body.appendChild(a);
  a.click();
  a.remove();
  // Keep the blob alive long enough for the download to start.
  setTimeout(() => URL.revokeObjectURL(url), 30_000);
}

// @ts-check
// The file-mounting pure core for the in-browser Linux sandbox (see the
// SANDBOX-HOST-COMMANDS design doc, part B). The browser-only orchestration
// lives in public/js/sandbox.js; this module holds the deterministic,
// I/O-free logic so it can be Node-tested (sandbox-files.test.js) and stays
// out of the CheerpX/DOM glue.
//
// The layout it builds:
//   /workspace/                 ← this chat session's files + guest scratch (persistent)
//   /workspace/INDEX.txt        ← the manifest below
//   /workspace/<projname>  ->  /mnt/<projname>-<hash>   ← friendly symlink (no hash)
//   /mnt/<projname>-<hash>/     ← the active project's own persistent mount
//
// Host bytes can't be written into an IDBDevice directly (no host writeFile),
// so they ingest through DataDevices at /mnt/in-s (session) and /mnt/in-p
// (project) and a boot script cp's them into the persistent tree — buildSeedScript()
// is that script. Everything here is pure string/byte manipulation.

// ---- caps -----------------------------------------------------------------

// Per-file and total byte budgets for the Tier-1 (DataDevice) mount, which
// holds the whole payload in page memory. Files over the per-file cap, or that
// would push the running total over the budget, are dropped and recorded in
// the manifest (Tier-2 WebDevice streaming is not built yet).
export const MAX_MOUNT_FILE_BYTES = 32 * 1024 * 1024; // 32 MB per file
export const MAX_MOUNT_TOTAL_BYTES = 64 * 1024 * 1024; // 64 MB across all mounted files

// ---- name sanitizing ------------------------------------------------------

/**
 * Sanitize an arbitrary file name into a safe basename for the guest FS:
 * basename only (drop any path), control chars and path separators removed,
 * whitespace collapsed. Never empty.
 * @param {string} name
 * @returns {string}
 */
export function sanitizeName(name) {
  let s = String(name == null ? "" : name);
  // basename: everything after the last / or \
  s = s.split(/[\\/]/).pop() || "";
  // drop control chars, NUL, and characters awkward in a shell path
  // eslint-disable-next-line no-control-regex
  s = s.replace(/[\x00-\x1f\x7f]/g, "").replace(/\s+/g, " ").trim();
  // no leading dots-only names or "." / ".."
  if (!s || s === "." || s === "..") return "file";
  return s.slice(0, 200);
}

/**
 * Sanitize a project name into a directory-name component: keep it readable
 * but restrict to a safe alphabet so it's clean in a mount path. Never empty.
 * @param {string} name
 * @returns {string}
 */
export function sanitizeProjName(name) {
  let s = String(name == null ? "" : name).trim().toLowerCase();
  s = s.replace(/[^a-z0-9._-]+/g, "-").replace(/^-+|-+$/g, "").replace(/-{2,}/g, "-");
  if (!s || s === "." || s === "..") return "project";
  return s.slice(0, 60);
}

/**
 * A short, stable, non-cryptographic hash of a project id, used to make the
 * project mount path unique and stable across sessions (FNV-1a, 8 hex chars).
 * @param {string} projId
 * @returns {string}
 */
export function projHash(projId) {
  const s = String(projId == null ? "" : projId);
  let h = 0x811c9dc5;
  for (let i = 0; i < s.length; i++) {
    h ^= s.charCodeAt(i);
    // FNV prime multiply, kept in 32-bit range
    h = Math.imul(h, 0x01000193) >>> 0;
  }
  return (h >>> 0).toString(16).padStart(8, "0");
}

/**
 * De-duplicate a list of already-sanitized names, appending -2, -3, … before
 * the extension on collision. Returns a new array in the same order.
 * @param {string[]} names
 * @returns {string[]}
 */
export function dedupeNames(names) {
  const seen = new Map();
  const out = [];
  for (const raw of names) {
    const name = raw || "file";
    if (!seen.has(name)) {
      seen.set(name, 1);
      out.push(name);
      continue;
    }
    const dot = name.lastIndexOf(".");
    const base = dot > 0 ? name.slice(0, dot) : name;
    const ext = dot > 0 ? name.slice(dot) : "";
    let n = seen.get(name) + 1;
    let candidate = `${base}-${n}${ext}`;
    while (seen.has(candidate)) {
      n += 1;
      candidate = `${base}-${n}${ext}`;
    }
    seen.set(name, n);
    seen.set(candidate, 1);
    out.push(candidate);
  }
  return out;
}

// ---- size cap -------------------------------------------------------------

/**
 * @typedef {{ name: string, type?: string, bytes: Uint8Array }} MountInput
 * @typedef {{ name: string, type: string, size: number, bytes: Uint8Array }} MountKept
 * @typedef {{ name: string, reason: string }} MountDropped
 */

/**
 * Apply the per-file and running-total byte caps, sanitizing + de-duplicating
 * kept names. Order preserved. Anything over a cap is dropped (recorded).
 * `startTotal` lets a second call (project files) continue the same budget.
 * @param {MountInput[]} files
 * @param {{ perFileMax?: number, totalMax?: number, startTotal?: number }} [opts]
 * @returns {{ kept: MountKept[], dropped: MountDropped[], total: number }}
 */
export function applySizeCap(files, opts = {}) {
  const perFileMax = opts.perFileMax ?? MAX_MOUNT_FILE_BYTES;
  const totalMax = opts.totalMax ?? MAX_MOUNT_TOTAL_BYTES;
  let total = opts.startTotal ?? 0;
  const kept = [];
  const dropped = [];
  const list = Array.isArray(files) ? files : [];
  const rawKeptNames = [];
  const staged = [];
  for (const f of list) {
    const bytes = f && f.bytes instanceof Uint8Array ? f.bytes : null;
    const name = sanitizeName(f && f.name);
    if (!bytes || bytes.length === 0) {
      dropped.push({ name, reason: "empty or unreadable" });
      continue;
    }
    if (bytes.length > perFileMax) {
      dropped.push({ name, reason: `over ${Math.round(perFileMax / (1024 * 1024))}MB per-file cap` });
      continue;
    }
    if (total + bytes.length > totalMax) {
      dropped.push({ name, reason: "over total size budget, no streaming backend" });
      continue;
    }
    total += bytes.length;
    rawKeptNames.push(name);
    staged.push({ type: String(f.type || "file"), size: bytes.length, bytes });
  }
  const deduped = dedupeNames(rawKeptNames);
  for (let i = 0; i < staged.length; i++) {
    kept.push({ name: deduped[i], type: staged[i].type, size: staged[i].size, bytes: staged[i].bytes });
  }
  return { kept, dropped, total };
}

// ---- the manifest ---------------------------------------------------------

/**
 * Build the /workspace/INDEX.txt text the model reads to discover what's
 * mounted. Tab-separated, one row per file, plus dropped-file markers.
 * @param {{
 *   session: MountKept[],
 *   project: { name: string, files: MountKept[] } | null,
 *   dropped?: Array<{ scope: string, name: string, reason: string }>,
 *   source?: { count: number, bytes: number } | null,
 * }} plan
 * @returns {string}
 */
export function buildManifest(plan) {
  const lines = [];
  lines.push("# Files mounted into this Linux sandbox.");
  lines.push("# Session files are in /workspace/. The active project's files are in");
  lines.push("# /workspace/" + (plan.project ? plan.project.name : "<projname>") + "/ (a symlink to its /mnt mount).");
  if (plan.source) {
    lines.push(
      `# INTROSPECTION: the deepresearch.se source snapshot (${plan.source.count} files, ${plan.source.bytes} bytes)`,
    );
    lines.push("# is mounted at /src (also reachable as /workspace/source) — ls/cat/grep it freely.");
  }
  lines.push("# columns: scope\\tname\\ttype\\tsize_bytes\\ttier");
  lines.push("");
  for (const f of plan.session || []) {
    lines.push(`session\t${f.name}\t${f.type}\t${f.size}\tdata`);
  }
  if (plan.project) {
    for (const f of plan.project.files || []) {
      lines.push(`project\t${f.name}\t${f.type}\t${f.size}\tdata`);
    }
  }
  for (const d of plan.dropped || []) {
    lines.push(`${d.scope}\t${d.name}\t-\t-\t[not mounted — ${d.reason}]`);
  }
  return lines.join("\n") + "\n";
}

// ---- shell helpers --------------------------------------------------------

/**
 * POSIX single-quote escape for interpolating a string into a /bin/sh command.
 * @param {string} s
 * @returns {string}
 */
export function shellEscape(s) {
  return "'" + String(s == null ? "" : s).replace(/'/g, "'\\''") + "'";
}

/**
 * Build the boot seed+symlink script: cp the two flat ingest DataDevices
 * (/mnt/in-s = session, /mnt/in-p = project) into the persistent volumes, stamp
 * the project id, and make the friendly no-hash symlink. Session is refreshed
 * each boot (cp -a); project is add/update-only (cp -an) so guest edits aren't
 * clobbered. The ingest devices are flat (files at their root) so we never
 * depend on DataDevice auto-creating nested directories.
 * @param {{ hasProject: boolean, projName?: string, projId?: string, hash?: string }} p
 * @returns {string}
 */
export function buildSeedScript(p) {
  const lines = [];
  if (p.hasProject) {
    const proj = `/mnt/${p.projName}-${p.hash}`;
    lines.push(`mkdir -p /workspace ${shellEscape(proj)}`);
    lines.push(`cp -a /mnt/in-s/. /workspace/ 2>/dev/null || true`);
    lines.push(`cp -an /mnt/in-p/. ${shellEscape(proj + "/")} 2>/dev/null || true`);
    lines.push(`printf '%s' ${shellEscape(String(p.projId || ""))} > ${shellEscape(proj + "/.projectid")} 2>/dev/null || true`);
    lines.push(`ln -sfn ${shellEscape(proj)} ${shellEscape("/workspace/" + p.projName)} 2>/dev/null || true`);
  } else {
    lines.push(`mkdir -p /workspace`);
    lines.push(`cp -a /mnt/in-s/. /workspace/ 2>/dev/null || true`);
  }
  return lines.join("\n");
}

// ---- the introspection source mount (developer mode) ------------------------

// Byte budget for the source snapshot's DataDevice mount (in page memory,
// like every Tier-1 mount). Today's whole snapshot is ~3 MB, so this is pure
// headroom, not a working limit.
export const MAX_SOURCE_TOTAL_BYTES = 24 * 1024 * 1024;

// A snapshot repo path safe to recreate inside the guest: relative, no
// traversal, a conservative alphabet (matches what the bundler emits).
const SAFE_REPO_PATH_RE = /^[A-Za-z0-9._][A-Za-z0-9._/-]*$/;

/**
 * Plan the introspection source mount: the snapshot's files (repo-relative
 * paths + full text, introspect-core.js's Snapshot shape) become FLAT entries
 * for one ingest DataDevice at /mnt/in-src (f0, f1, … — files at the device
 * root, the same no-nested-dirs discipline as the other ingest devices) plus
 * a seed script that recreates the real tree at /src. The script is written
 * INTO the device (as .seed) and run with `sh /mnt/in-src/.seed`, so a
 * hundreds-of-lines script never rides in argv. /src is refreshed on every
 * boot (it lives in the persistent overlay, so a stale copy would otherwise
 * survive reloads); a friendly /workspace/source symlink points at it.
 * @param {Array<{ p: string, s?: number, t: string }>} files
 * @param {{ totalMax?: number }} [opts]
 * @returns {{ entries: Array<{ flat: string, path: string, bytes: Uint8Array }>, seed: string, count: number, bytes: number, dropped: number } | null}
 */
export function planSourceMount(files, opts = {}) {
  const list = Array.isArray(files) ? files : [];
  const totalMax = opts.totalMax ?? MAX_SOURCE_TOTAL_BYTES;
  const enc = new TextEncoder();
  /** @type {Array<{ flat: string, path: string, bytes: Uint8Array }>} */
  const entries = [];
  const dirs = new Set();
  let bytes = 0;
  let dropped = 0;
  for (const f of list) {
    const path = typeof f?.p === "string" ? f.p : "";
    if (!SAFE_REPO_PATH_RE.test(path) || path.includes("..")) {
      dropped += 1;
      continue;
    }
    const b = enc.encode(typeof f.t === "string" ? f.t : "");
    if (!b.length || bytes + b.length > totalMax) {
      dropped += 1;
      continue;
    }
    bytes += b.length;
    const slash = path.lastIndexOf("/");
    if (slash > 0) dirs.add("/src/" + path.slice(0, slash));
    entries.push({ flat: "f" + entries.length, path, bytes: b });
  }
  if (!entries.length) return null;
  const lines = [];
  lines.push("rm -rf /src");
  lines.push("mkdir -p /src " + [...dirs].sort().map(shellEscape).join(" "));
  for (const e of entries) {
    lines.push(`cp /mnt/in-src/${e.flat} ${shellEscape("/src/" + e.path)}`);
  }
  lines.push("mkdir -p /workspace 2>/dev/null || true");
  lines.push("ln -sfn /src /workspace/source 2>/dev/null || true");
  return { entries, seed: lines.join("\n") + "\n", count: entries.length, bytes, dropped };
}

// The experimental in-browser Linux execution sandbox (the `bash_lite_mcp`
// knob). NOT type-checked (no `// @ts-check`): this is browser/CheerpX glue —
// dynamic CDN imports, xterm globals, WASM VM handles — with no meaningful
// static type surface. The pure, testable logic lives in bash-core.js.
//
// A JavaScript x86 emulator (CheerpX) boots a small Debian Linux
// ENTIRELY IN THIS BROWSER — the server never runs a shell. This module owns
// the VM lifecycle and exposes two things the rest of the app uses:
//
//   - a floating terminal panel (xterm.js) the user can OPT to open to watch
//     (and type into) the live shell — but it NO LONGER pops up on its own when
//     the agent runs commands. Auto-opening covered the screen and broke the
//     prompt-first flow; instead the raw commands + output drift faintly across
//     the page background (public/js/agent-backdrop.js, fed from execInSandbox
//     below), and the panel stays hidden unless the user explicitly opens it.
//   - execInSandbox(cmd) → {exitCode, stdout, stderr}: the programmatic bridge
//     the bash-lite agent loop (public/js/bash-agent.js) drives.
//
// CheerpX needs SharedArrayBuffer, which needs cross-origin isolation
// (COOP+COEP). The Worker serves the DRS app shell with COEP: require-corp
// only when this account's knob is on (src/index.js), so `crossOriginIsolated`
// is the definitive "can this run here" check — sandboxSupported() below.
//
// Ported from the proven terminal integration in aisecurityliteracy.dev
// (the exec marker protocol especially): a stock Debian cloud image, xterm
// wired via setCustomConsole, and a serialized exec queue that captures a
// command's stdout/stderr as base64 between unique markers so it survives the
// shared console. Everything here only ever runs in a browser (DOM, dynamic
// import of the CheerpX ESM) — there is no Node-testable surface, so the pure,
// testable logic lives in public/js/bash-core.js instead.

import {
  applySizeCap,
  buildManifest,
  buildSeedScript,
  planSourceMount,
  projHash,
  sanitizeProjName,
} from "./sandbox-files.js";
import { feedCommand, feedResult } from "./agent-backdrop.js";

const XTERM_CDN = "https://cdn.jsdelivr.net/npm/@xterm/xterm@5.5.0";
const XTERM_FIT_CDN = "https://cdn.jsdelivr.net/npm/@xterm/addon-fit@0.10.0";
const CHEERPX_CDN = "https://cxrtnc.leaningtech.com/1.2.6/cx.esm.js";
// The public WebVM Debian disk (streamed over WebSocket, cached in IndexedDB).
const DISK_URL = "wss://disks.webvm.io/debian_large_20230522_5044875331_2.ext2";
const IDB_CACHE_ID = "deepresearch-sandbox-vm";
// The persistent session workspace volume (its own IndexedDB, independent of
// the base-image block cache above) — mounted at /workspace. Per-project
// volumes are dr-proj-<hash>, created on demand.
const WORKSPACE_DB = "dr-sandbox-workspace";

/** @type {'off'|'booting'|'ready'|'error'} */
let vmState = "off";
let cx = null;
let term = null;
let fitAddon = null;
let cxReadFunc = null;
/** @type {Promise<boolean> | null} */
let bootPromise = null;
let execQueue = Promise.resolve();
let panel = null;
let statusEl = null;
// Persistent IDBDevice handles kept so exportFile() can read guest-written
// files back out (readFileAsBlob). Set during boot when a file provider is
// supplied; null otherwise.
let workspaceDev = null;
let projectDev = null;

// ---- client telemetry (reaches Workers Logs via /api/client-log) -----------
// The sandbox filesystem integration runs entirely in the browser, so its
// boot/mount/seed events are invisible to the server unless we ship them.
// sblog() buffers structured events (and mirrors them to the devtools console);
// flushSandboxLog() beacons the batch to /api/client-log, where the Worker
// re-emits each through the structured logger so it lands in the log URL
// (`wrangler tail` / Workers Logs). Levels are honored end to end: `debug`
// events only surface when the server's LOG_LEVEL=debug. sandboxFsSummary()
// exposes a compact last-mount summary that also rides on every /api/chat
// client_diag (so a mount problem shows in the chat log even without debug).
/** @type {Array<Record<string, any>>} */
let _fsLog = [];
let _fsSummary = null;

/**
 * @param {"debug"|"info"|"warn"|"error"} level
 * @param {string} event dotted name, e.g. "sandbox.fs.mount"
 * @param {Record<string, any>} [fields]
 */
export function sblog(level, event, fields = {}) {
  _fsLog.push({ level, event, ...fields });
  if (_fsLog.length > 300) _fsLog.shift();
  try {
    const fn = /** @type {any} */ (console)[level] || console.log;
    fn.call(console, "[sandbox] " + event, fields);
  } catch { /* console unavailable */ }
}

/** The compact last-mount summary folded into /api/chat client_diag. */
export function sandboxFsSummary() {
  return _fsSummary;
}

/** @param {Record<string, any> | null} s */
function setFsSummary(s) {
  _fsSummary = s;
}

// Fire-and-forget: beacon the buffered events to the Worker. Survives page
// teardown (sendBeacon) and never throws. On /cure (no auth) the POST simply
// fails and is swallowed — file mounting is a DRS feature.
function flushSandboxLog() {
  if (!_fsLog.length) return;
  const events = _fsLog.splice(0, _fsLog.length);
  try {
    const ua = (() => { try { return (navigator.userAgent || "").slice(0, 140); } catch { return "" } })();
    const body = JSON.stringify({ scope: "sandbox", ua, events });
    if (navigator.sendBeacon) {
      navigator.sendBeacon("/api/client-log", new Blob([body], { type: "application/json" }));
    } else {
      fetch("/api/client-log", {
        method: "POST",
        body,
        headers: { "content-type": "application/json" },
        keepalive: true,
      }).catch(() => {});
    }
  } catch { /* telemetry must never break the sandbox */ }
}

/** Whether the sandbox CAN run here: cross-origin isolation is present. */
export function sandboxSupported() {
  return typeof window !== "undefined" && window.crossOriginIsolated === true;
}

/** Whether the VM has finished booting and exec is available. */
export function sandboxReady() {
  return vmState === "ready";
}

// ---- DOM: the floating terminal panel --------------------------------------

function loadCSS(url) {
  return new Promise((resolve, reject) => {
    const link = document.createElement("link");
    link.rel = "stylesheet";
    link.href = url;
    link.crossOrigin = "anonymous";
    link.onload = resolve;
    link.onerror = () => reject(new Error("Failed to load CSS: " + url));
    document.head.appendChild(link);
  });
}

function loadScript(url) {
  return new Promise((resolve, reject) => {
    const script = document.createElement("script");
    script.src = url;
    script.crossOrigin = "anonymous";
    script.onload = resolve;
    script.onerror = () => reject(new Error("Failed to load script: " + url));
    document.head.appendChild(script);
  });
}

function buildPanel() {
  if (panel) return panel;
  panel = document.createElement("div");
  panel.id = "dr-sandbox";
  panel.className = "dr-sandbox hidden";
  panel.innerHTML = `
    <div class="dr-sandbox-bar">
      <span class="dr-sandbox-title">Linux sandbox <span class="exp-badge">Experimental</span></span>
      <span id="dr-sandbox-status" class="dr-sandbox-status">off</span>
      <button type="button" id="dr-sandbox-close" class="dr-sandbox-close" aria-label="Hide sandbox">×</button>
    </div>
    <div id="dr-sandbox-term" class="dr-sandbox-term"></div>`;
  document.body.appendChild(panel);
  statusEl = panel.querySelector("#dr-sandbox-status");
  panel.querySelector("#dr-sandbox-close").addEventListener("click", hideSandbox);
  return panel;
}

function setStatus(s) {
  vmState = s === "ready" || s === "booting" || s === "error" ? s : vmState;
  if (statusEl) statusEl.textContent = s;
}

export function showSandbox() {
  buildPanel().classList.remove("hidden");
  if (term && fitAddon) requestAnimationFrame(() => { try { fitAddon.fit(); } catch {} });
}

export function hideSandbox() {
  if (panel) panel.classList.add("hidden");
}

export function toggleSandbox() {
  if (!panel || panel.classList.contains("hidden")) showSandbox();
  else hideSandbox();
}

// ---- terminal I/O ----------------------------------------------------------

function writeData(buf, vt) {
  if (vt !== 1) return;
  if (term) term.write(new Uint8Array(buf));
}

function readData(str) {
  if (!cxReadFunc) return;
  for (let i = 0; i < str.length; i++) cxReadFunc(str.charCodeAt(i));
}

// ---- boot ------------------------------------------------------------------

/**
 * Boot the sandbox once (idempotent). Resolves true when the VM is ready to
 * exec, false if it cannot run (no cross-origin isolation) or boot failed.
 * The terminal panel is BUILT (so exec has a console) but deliberately left
 * hidden — activity surfaces on the faint page-background layer instead; the
 * user can still open the panel by hand (toggleSandbox) if they want the live
 * shell.
 *
 * `fileProvider` (optional) supplies the user's files to mount: an async
 * function resolving to `{ session: [{name,type,bytes}], project: {name, id,
 * files: [{name,type,bytes}]} | null }`. When given, the persistent
 * `/workspace` volume is mounted and the files are seeded into `/workspace` +
 * `/mnt/<projname>-<hash>` before the VM is marked ready. Fully fail-soft — a
 * provider that throws, or any mount/seed error, never blocks the boot.
 * @param {(() => Promise<any>) | null} [fileProvider]
 * @returns {Promise<boolean>}
 */
export function ensureSandboxBooted(fileProvider = null) {
  if (bootPromise) return bootPromise;
  bootPromise = bootVM(fileProvider).catch((err) => {
    const msg = (/** @type {any} */ (err))?.message || String(err);
    console.error("[sandbox] boot failed", err);
    sblog("error", "sandbox.boot_failed", { error: String(msg).slice(0, 200) });
    setFsSummary({ ...(sandboxFsSummary() || {}), err: String(msg).slice(0, 200) });
    flushSandboxLog();
    setStatus("error");
    return false;
  });
  return bootPromise;
}

/**
 * @param {(() => Promise<any>) | null} [fileProvider]
 */
async function bootVM(fileProvider = null) {
  const t0 = Date.now();
  const coi = typeof window !== "undefined" && window.crossOriginIsolated === true;
  const sab = typeof SharedArrayBuffer !== "undefined";
  sblog("info", "sandbox.boot_start", { coi, sab, provider: !!fileProvider });
  if (!sandboxSupported()) {
    sblog("warn", "sandbox.boot_unsupported", { coi, sab });
    setFsSummary({ n: 0, b: 0, proj: false, drop: 0, ms: Date.now() - t0, err: "not cross-origin isolated" });
    flushSandboxLog();
    setStatus("error");
    return false;
  }
  // Build the panel (exec needs the xterm console) but do NOT show it — the
  // agent's activity is surfaced faintly on the page background instead of
  // taking over the screen. The user can still open it by hand.
  buildPanel();
  setStatus("booting");

  await Promise.all([
    // The xterm stylesheet is purely cosmetic terminal styling — exec needs
    // none of it, so a failed/blocked CSS load must NOT abort the boot (it did:
    // a transient CDN miss on xterm.css took the whole sandbox down with
    // "Sandbox unavailable"). The two SCRIPTS are load-bearing (they define the
    // Terminal/FitAddon globals), so those stay fatal.
    loadCSS(XTERM_CDN + "/css/xterm.css").catch((e) => console.warn("[sandbox] xterm css skipped:", e?.message || e)),
    loadScript(XTERM_CDN + "/lib/xterm.js"),
    loadScript(XTERM_FIT_CDN + "/lib/addon-fit.js"),
  ]);

  const container = panel.querySelector("#dr-sandbox-term");
  // @ts-ignore — Terminal/FitAddon are attached to window by the CDN scripts.
  term = new Terminal({
    cursorBlink: true,
    convertEol: true,
    fontFamily: "'SF Mono', 'Fira Code', 'Cascadia Code', monospace",
    fontSize: window.innerWidth < 768 ? 12 : 13,
    theme: { background: "#101014", foreground: "#d6d6e6", cursor: "#c0caf5" },
  });
  // @ts-ignore
  fitAddon = new FitAddon.FitAddon();
  term.loadAddon(fitAddon);
  term.open(container);
  try { fitAddon.fit(); } catch {}
  term.onData(readData);
  container.addEventListener("keydown", (e) => e.stopPropagation());

  setStatus("loading CheerpX…");
  const CheerpX = await import(CHEERPX_CDN);

  setStatus("connecting disk…");
  const blockDevice = await CheerpX.CloudDevice.create(DISK_URL);
  const blockCache = await CheerpX.IDBDevice.create(IDB_CACHE_ID);
  const overlayDevice = await CheerpX.OverlayDevice.create(blockDevice, blockCache);

  const mounts = [
    { type: "ext2", dev: overlayDevice, path: "/" },
    { type: "devs", path: "/dev" },
    { type: "devpts", path: "/dev/pts" },
    { type: "proc", path: "/proc" },
    { type: "sys", path: "/sys" },
  ];

  // File mounting (design part B). When a provider is supplied: mount the
  // persistent /workspace volume, the two flat ingest DataDevices, and — if a
  // project is active — its own persistent volume at /mnt/<projname>-<hash>.
  // All fail-soft: any error here leaves the sandbox booting as a bare VM.
  /** @type {{ plan: any, inSession: any, inProject: any, inSource: any, projMount: string } | null} */
  let fileMount = null;
  if (fileProvider) {
    try {
      setStatus("preparing files…");
      const plan = await preparePlan(fileProvider);
      // Build the extra mounts in a LOCAL array and only commit them to the
      // real mounts once every device was created — a partial failure must not
      // leave a half-formed mount in the config passed to Linux.create.
      const extra = [];
      const wsDev = await CheerpX.IDBDevice.create(WORKSPACE_DB);
      extra.push({ type: "dir", dev: wsDev, path: "/workspace" });
      const inSession = await CheerpX.DataDevice.create();
      extra.push({ type: "dir", dev: inSession, path: "/mnt/in-s" });
      let inProject = null;
      let projMount = "";
      let projDev = null;
      if (plan && plan.project) {
        projMount = `/mnt/${plan.project.name}-${plan.project.hash}`;
        projDev = await CheerpX.IDBDevice.create("dr-proj-" + plan.project.hash);
        extra.push({ type: "dir", dev: projDev, path: projMount });
        inProject = await CheerpX.DataDevice.create();
        extra.push({ type: "dir", dev: inProject, path: "/mnt/in-p" });
      }
      // Introspection (developer mode): the source snapshot's ingest device.
      // Same Tier-1 DataDevice pattern as the session/project ingests — the
      // pre-bundled files stream in as raw bytes at the device root and the
      // seed script (planSourceMount) recreates the tree at /src.
      let inSource = null;
      if (plan && plan.source) {
        inSource = await CheerpX.DataDevice.create();
        extra.push({ type: "dir", dev: inSource, path: "/mnt/in-src" });
      }
      for (const m of extra) mounts.push(m);
      workspaceDev = wsDev;
      projectDev = projDev;
      fileMount = { plan, inSession, inProject, inSource, projMount };
      sblog("info", "sandbox.fs.mount", {
        workspace: "/workspace",
        project: projMount || null,
        ingest: inProject ? "/mnt/in-s,/mnt/in-p" : "/mnt/in-s",
        session_files: plan.session.length,
        project_files: plan.project ? plan.project.files.length : 0,
        source_files: plan.source ? plan.source.count : 0,
        dropped: plan.dropped.length,
        bytes: plan.bytes,
      });
    } catch (err) {
      const msg = (/** @type {any} */ (err))?.message || String(err);
      console.warn("[sandbox] file mount setup failed — booting without files", err);
      sblog("warn", "sandbox.fs.mount_failed", { error: String(msg).slice(0, 200) });
      fileMount = null;
    }
  }

  setStatus("starting Linux…");
  cx = await CheerpX.Linux.create({ mounts });

  // Seed the persistent volumes from the ingest devices, then make the symlink.
  if (fileMount) {
    try {
      setStatus("mounting files…");
      await seedFiles(fileMount);
    } catch (err) {
      const msg = (/** @type {any} */ (err))?.message || String(err);
      console.warn("[sandbox] file seed failed — continuing without files", err);
      sblog("warn", "sandbox.fs.seed_failed", { error: String(msg).slice(0, 200) });
    }
  }

  cxReadFunc = cx.setCustomConsole(writeData, term.cols, term.rows);
  setStatus("ready");
  vmState = "ready";

  // Expose the bridge for the agent loop and any test harness.
  window.__DR_SANDBOX = { ready: true, exec: execInSandbox };

  // Record the boot summary (also rides on client_diag) and, when files were
  // mounted, a real on-disk verification listing — the definitive "did the
  // files actually land" signal, at debug so heavy testing can see it via the
  // log URL without noising up production. Everything here is best-effort.
  const bootMs = Date.now() - t0;
  const plan = fileMount && fileMount.plan;
  setFsSummary({
    n: plan ? plan.session.length + (plan.project ? plan.project.files.length : 0) : 0,
    b: plan ? plan.bytes : 0,
    proj: !!(plan && plan.project),
    // Introspection source mount (developer mode): file count, 0 when absent.
    src: plan && plan.source ? plan.source.count : 0,
    drop: plan ? plan.dropped.length : 0,
    ms: bootMs,
    err: "",
  });
  sblog("info", "sandbox.boot_done", {
    ms: bootMs,
    files: _fsSummary ? _fsSummary.n : 0,
    bytes: _fsSummary ? _fsSummary.b : 0,
    project: !!(plan && plan.project),
  });
  if (fileMount) {
    try {
      const v = await execInSandbox(
        "echo '# /workspace'; ls -la /workspace 2>&1; echo '# project'; ls -la /workspace/*/ 2>/dev/null | head -40",
      );
      sblog("debug", "sandbox.fs.verify", { exit: v.exitCode, listing: String(v.stdout || "").slice(0, 1500) });
    } catch (err) {
      sblog("debug", "sandbox.fs.verify_failed", { error: String((/** @type {any} */ (err))?.message || err).slice(0, 200) });
    }
  }
  flushSandboxLog();

  // Interactive login shell in a loop (re-spawns if the user types exit).
  (async () => {
    while (vmState === "ready") {
      try {
        await cx.run("/bin/bash", ["--login"], {
          env: ["HOME=/root", "TERM=xterm-256color", "USER=root", "SHELL=/bin/bash", "LANG=en_US.UTF-8"],
          cwd: "/root",
          uid: 0,
          gid: 0,
        });
      } catch {
        break;
      }
    }
  })();

  return true;
}

// ---- file mounting (design part B) -----------------------------------------

// Call the provider and turn its raw {session, project, source} into a mount
// plan: size-capped, sanitized, de-duped kept lists + a manifest + the
// project's sanitized name/hash + the introspection source-mount plan. Pure
// logic lives in sandbox-files.js. Never throws for a bad provider payload —
// returns a session-only (or empty) plan.
/**
 * @param {() => Promise<any>} fileProvider
 * @returns {Promise<{ session: any[], project: any, source: any, manifest: string, dropped: any[], bytes: number }>}
 */
async function preparePlan(fileProvider) {
  const raw = (await fileProvider()) || {};
  const sessionCap = applySizeCap(Array.isArray(raw.session) ? raw.session : []);
  let total = sessionCap.total;
  const dropped = sessionCap.dropped.map((d) => ({ scope: "session", ...d }));
  let project = null;
  if (raw.project && Array.isArray(raw.project.files) && raw.project.files.length) {
    const projCap = applySizeCap(raw.project.files, { startTotal: total });
    total = projCap.total;
    for (const d of projCap.dropped) dropped.push({ scope: "project", ...d });
    project = {
      name: sanitizeProjName(raw.project.name),
      id: String(raw.project.id || ""),
      hash: projHash(raw.project.id),
      files: projCap.kept,
    };
  }
  // Introspection (developer mode): the pre-bundled source snapshot becomes
  // its own flat ingest + /src seed script — budgeted separately (it's a
  // fixed, known artifact, not user data competing for the session budget).
  let source = null;
  if (raw.source && Array.isArray(raw.source.files) && raw.source.files.length) {
    source = planSourceMount(raw.source.files);
    if (source) total += source.bytes;
  }
  const manifest = buildManifest({
    session: sessionCap.kept,
    project: project ? { name: project.name, files: project.files } : null,
    dropped,
    source: source ? { count: source.count, bytes: source.bytes } : null,
  });
  sblog("info", "sandbox.fs.plan", {
    session_files: sessionCap.kept.length,
    project_files: project ? project.files.length : 0,
    project_name: project ? project.name : null,
    source_files: source ? source.count : 0,
    total_bytes: total,
    dropped: dropped.length,
  });
  // Per-dropped-file detail at debug so a "why isn't my file there" can be
  // answered from the log URL without a repro.
  for (const d of dropped) sblog("debug", "sandbox.fs.dropped", { scope: d.scope, name: d.name, reason: d.reason });
  return { session: sessionCap.kept, project, source, manifest, dropped, bytes: total };
}

// Write the kept bytes into the flat ingest DataDevices (files at the device
// root — matches the documented DataDevice.writeFile pattern, no nested dirs),
// then run the seed+symlink script to cp them into the persistent volumes.
/**
 * @param {{ plan: any, inSession: any, inProject: any, projMount: string }} fm
 */
async function seedFiles(fm) {
  const { plan, inSession, inProject, inSource } = fm;
  const enc = new TextEncoder();
  // The manifest rides in as a session file so it lands at /workspace/INDEX.txt.
  await inSession.writeFile("/INDEX.txt", enc.encode(plan.manifest));
  for (const f of plan.session) {
    await inSession.writeFile("/" + f.name, f.bytes);
    sblog("debug", "sandbox.fs.write", { scope: "session", name: f.name, size: f.size });
  }
  if (plan.project && inProject) {
    for (const f of plan.project.files) {
      await inProject.writeFile("/" + f.name, f.bytes);
      sblog("debug", "sandbox.fs.write", { scope: "project", name: f.name, size: f.size });
    }
  }
  // The introspection source snapshot: flat pre-bundled files (f0, f1, …)
  // plus its own tree-building seed script, written INTO the device so the
  // (hundreds-of-lines) script never rides in argv.
  if (plan.source && inSource) {
    for (const e of plan.source.entries) {
      await inSource.writeFile("/" + e.flat, e.bytes);
    }
    await inSource.writeFile("/.seed", enc.encode(plan.source.seed));
    sblog("debug", "sandbox.fs.write", { scope: "source", name: "/src tree", size: plan.source.bytes });
  }
  const script = buildSeedScript({
    hasProject: !!plan.project,
    projName: plan.project?.name,
    projId: plan.project?.id,
    hash: plan.project?.hash,
  });
  const full = plan.source && inSource ? script + "\nsh /mnt/in-src/.seed 2>/dev/null || true" : script;
  const r = await cx.run("/bin/sh", ["-c", full], {
    env: ["HOME=/root", "TERM=dumb", "PATH=/usr/local/sbin:/usr/local/bin:/usr/sbin:/usr/bin:/sbin:/bin"],
    cwd: "/root",
    uid: 0,
    gid: 0,
  });
  sblog("info", "sandbox.fs.seed", {
    exit: r && Number.isFinite(r.status) ? r.status : null,
    project_mount: plan.project ? `/mnt/${plan.project.name}-${plan.project.hash}` : null,
    source_files: plan.source ? plan.source.count : 0,
  });
}

// Read a guest-written file back out into JS (the round-trip export): files
// under /workspace come from the session volume, files under a project mount
// from the project volume. Returns the Blob, or null if unavailable.
/**
 * @param {string} path an absolute guest path under /workspace or /mnt/<proj>
 * @returns {Promise<Blob | null>}
 */
export async function exportFile(path) {
  const p = String(path || "");
  try {
    let blob = null;
    if (p.startsWith("/workspace/") && workspaceDev) {
      blob = await workspaceDev.readFileAsBlob(p.slice("/workspace".length));
    } else if (p.startsWith("/mnt/") && projectDev) {
      // strip the mount prefix: /mnt/<name>-<hash>/rest → /rest
      const rest = p.replace(/^\/mnt\/[^/]+/, "");
      blob = await projectDev.readFileAsBlob(rest || "/");
    }
    sblog("debug", "sandbox.fs.export", { path: p.slice(0, 120), bytes: blob ? blob.size : 0, ok: !!blob });
    flushSandboxLog();
    return blob;
  } catch (err) {
    const msg = (/** @type {any} */ (err))?.message || String(err);
    console.warn("[sandbox] exportFile failed", err);
    sblog("warn", "sandbox.fs.export_failed", { path: p.slice(0, 120), error: String(msg).slice(0, 200) });
    flushSandboxLog();
  }
  return null;
}

// ---- exec bridge (marker protocol) -----------------------------------------

// Run one command and capture {exitCode, stdout, stderr}. Serialized through
// execQueue so concurrent calls don't stomp the shared custom console. Uses a
// unique marker + base64 so the captured output survives any stray banner the
// interactive shell emits. Ported from the aisl terminal integration.
/**
 * @param {string} command
 * @returns {Promise<{ exitCode: number, stdout: string, stderr: string }>}
 */
export function execInSandbox(command) {
  const run = async () => {
    if (vmState !== "ready" || !cx) return { exitCode: 1, stdout: "", stderr: "sandbox not ready" };
    // Surface the command on the faint page-background activity layer (never
    // throws — it's decoration). "shell" is the default single-agent channel;
    // multiple agents each pass their own id and the layer clips between them.
    feedCommand("shell", command);
    const id = Date.now().toString(36) + Math.random().toString(36).slice(2, 6);
    const marker = "###EXEC" + id + ":";
    const of = "/tmp/_o" + id;
    const ef = "/tmp/_e" + id;
    // Redirect stdout AND stderr to files, capture $? IMMEDIATELY (before any
    // pipe), THEN base64 the files. The prior form piped stdout into base64
    // and read $? after the pipe, so RC was base64's exit (always 0) — the
    // command's real exit code was lost. /bin/sh here is dash (no PIPESTATUS),
    // so the temp-file form is the correct way to preserve it. The
    // marker+base64 envelope is unchanged (base64 emits no ':' or '#').
    const wrapped =
      "( " + command + " ) >" + of + " 2>" + ef + "; RC=$?; " +
      "O=$(base64 -w0 " + of + " 2>/dev/null); E=$(base64 -w0 " + ef + " 2>/dev/null); " +
      "rm -f " + of + " " + ef + "; " +
      'printf "' + marker + '%s:%s:%d###\\n" "$O" "$E" "$RC"';
    const env = {
      env: ["HOME=/root", "TERM=dumb", "PATH=/usr/local/sbin:/usr/local/bin:/usr/sbin:/usr/bin:/sbin:/bin"],
      cwd: "/root",
      uid: 0,
      gid: 0,
    };
    const chunks = [];
    cx.setCustomConsole((buf) => chunks.push(new Uint8Array(buf)), 1024, 24);
    try {
      await cx.run("/bin/sh", ["-c", wrapped], env);
    } finally {
      if (term) cxReadFunc = cx.setCustomConsole(writeData, term.cols, term.rows);
    }
    let total = 0;
    for (const c of chunks) total += c.length;
    const combined = new Uint8Array(total);
    let off = 0;
    for (const c of chunks) { combined.set(c, off); off += c.length; }
    const raw = new TextDecoder().decode(combined);
    const re = new RegExp(marker.replace(/[.*+?^${}()|[\]\\]/g, "\\$&") + "([^:]*):([^:]*):(-?\\d+)###");
    const m = raw.match(re);
    if (!m) return { exitCode: 1, stdout: "", stderr: "exec: marker not found" };
    let stdout = "";
    let stderr = "";
    try { stdout = m[1] ? atob(m[1]) : ""; } catch {}
    try { stderr = m[2] ? atob(m[2]) : ""; } catch {}
    const result = { exitCode: parseInt(m[3], 10), stdout, stderr };
    feedResult("shell", result); // mirror the raw output to the background layer
    return result;
  };
  const next = execQueue.then(run, run);
  execQueue = next.then(() => {}, () => {});
  return next;
}

// @ts-check
// Per-account settings (GET/PUT /api/settings — src/settings.js): the
// server_history (cloud storage), shodan_mcp (Shodan host-intel),
// google_maps, and feedback_mode knobs. The cached copy answers the
// hot-path question every storage-touching module asks — "is cloud storage
// on?" — without a fetch per call; the answer only ever changes through
// updateSetting below (this tab) or on the next page load (another tab or
// device flipped it — an accepted, self-healing staleness window: the
// server rejects writes that its own copy of the knob forbids).

/**
 * The server's effective-settings response: the per-user knobs plus which
 * server-side capabilities exist at all (secrets/bindings present).
 * @typedef {object} Settings
 * @property {boolean} [server_history]
 * @property {boolean} [shodan_mcp]
 * @property {boolean} [google_maps]
 * @property {boolean} [feedback_mode]
 * @property {boolean} [bash_lite_mcp]
 * @property {boolean} [developer_mode]
 * @property {string} [maps_embed_key]
 * @property {{storage?: boolean, rag?: boolean, shodan?: boolean, google_maps?: boolean, feedback?: boolean, bash_lite?: boolean, developer?: boolean}} [available]
 */

/** @type {Settings | null} */
let settings = null;
/** @type {Promise<Settings> | null} */
let loadPromise = null;

/**
 * Fetch (or reuse the in-flight/cached fetch of) the account settings.
 * @param {boolean} [force] drop the cache and refetch
 * @returns {Promise<Settings>}
 */
export function loadSettings(force = false) {
  if (force) loadPromise = null;
  if (!loadPromise) {
    loadPromise = fetch("/api/settings")
      .then((res) => {
        if (!res.ok) throw new Error("settings unavailable");
        return res.json();
      })
      .then((data) => {
        settings = data;
        return data;
      })
      .catch((err) => {
        loadPromise = null; // retry on the next call instead of caching the failure
        throw err;
      });
  }
  return loadPromise;
}

// Synchronous view for hot paths (persist-after-every-turn, retrieval
// backend choice). False until loadSettings has resolved — the safe
// default: local-only behavior.
export function serverHistoryOn() {
  return settings?.server_history === true;
}

// Whether /api/settings has actually answered this page load. Lets UI
// distinguish "the knob is off" from "we never learned the knob's state"
// (auth or network failure) — the two need opposite user guidance.
export function settingsLoaded() {
  return settings !== null;
}

export function storageAvailable() {
  return settings?.available?.storage === true;
}

export function serverRagAvailable() {
  return settings?.available?.rag === true;
}

// Shodan host-intelligence enrichment knob (default off; needs the server's
// SHODAN_API_KEY, so it reads unavailable when the server has no key).
export function shodanOn() {
  return settings?.shodan_mcp === true;
}

export function shodanAvailable() {
  return settings?.available?.shodan === true;
}

