// @ts-check
// Incremental SSE parser — the pure core of stream.js's read loop, extracted
// so the line-buffering rules are testable in Node (no DOM needed). The
// server's stream is `data: <json>` events separated by blank lines, with
// `: keepalive` comment lines interleaved (CLAUDE.md, "/api/chat SSE
// protocol"); this parser owns exactly the byte-to-event step: carry a
// partial trailing line between reads, ignore comments/blank lines and the
// `[DONE]` terminator, and drop malformed JSON rather than throw (a torn
// keepalive or truncated frame must never kill the render loop).

/**
 * @returns {{ push(chunk: string): unknown[] }} stateful parser — one per stream
 */
export function createSseParser() {
  let buffer = "";
  return {
    // Feed one decoded chunk; returns the complete parsed events it finished.
    push(chunk) {
      buffer += chunk;
      const lines = buffer.split("\n");
      buffer = lines.pop() ?? ""; // partial trailing line waits for the next read
      const events = [];
      for (const line of lines) {
        if (!line.startsWith("data:")) continue;
        const data = line.slice(5).trim();
        if (!data || data === "[DONE]") continue;
        try {
          events.push(JSON.parse(data));
        } catch { /* ignore non-JSON lines */ }
      }
      return events;
    },
  };
}

// Node tests for sse.js: line buffering, keepalive/[DONE] filtering, malformed-JSON tolerance.
import { test, describe } from "node:test";
import assert from "node:assert/strict";
import { createSseParser } from "./sse.js";

describe("createSseParser", () => {
  test("parses complete data lines into events", () => {
    const p = createSseParser();
    const events = p.push('data: {"a":1}\n\ndata: {"b":2}\n\n');
    assert.deepEqual(events, [{ a: 1 }, { b: 2 }]);
  });

  test("carries a partial trailing line across pushes (chunk split mid-event)", () => {
    const p = createSseParser();
    assert.deepEqual(p.push('data: {"choices":[{"delta":{"con'), []);
    assert.deepEqual(p.push('tent":"hi"}}]}\n'), [{ choices: [{ delta: { content: "hi" } }] }]);
  });

  test("ignores keepalive comment lines and blank lines", () => {
    const p = createSseParser();
    assert.deepEqual(p.push(': keepalive\n\n: keepalive\n\ndata: {"x":1}\n'), [{ x: 1 }]);
  });

  test("ignores the [DONE] terminator", () => {
    const p = createSseParser();
    assert.deepEqual(p.push('data: {"x":1}\n\ndata: [DONE]\n\n'), [{ x: 1 }]);
  });

  test("drops malformed JSON instead of throwing", () => {
    const p = createSseParser();
    assert.deepEqual(p.push('data: {broken\n\ndata: {"ok":true}\n'), [{ ok: true }]);
  });

  test("a data line split exactly at the newline still parses", () => {
    const p = createSseParser();
    assert.deepEqual(p.push('data: {"x":1}'), []);
    assert.deepEqual(p.push("\n"), [{ x: 1 }]);
  });

  test("empty data payload is ignored", () => {
    const p = createSseParser();
    assert.deepEqual(p.push("data:\n\ndata:   \n"), []);
  });
});

