import { createSseParser } from "./sse.js";
import {
  capEmbedBytes,
  getEmbeds,
  initEmbeds,
  pruneEmbeds,
  quizHooks,
  recordEmbed,
  setEmbeds,
} from "./embeds.js";
import { ackAnswer, recoverAnswer } from "./recovery.js";

/**
 * Per-send options, captured from the composer (app.js) and threaded into
 * persistence so a stored conversation reopens with the settings it was
 * sent with.
 * @typedef {object} SendOpts
 * @property {object[]} [images]  pending image attachments ({name, dataUrl, gps, …})
 * @property {object[]} [docs]    pending document attachments ({name, text?, rag?, docId?, …})
 * @property {string} [model]     model id ("" = server default)
 * @property {?number} [budgetS]  research time budget in seconds
 * @property {boolean} [webSearch]
 */

/**
 * The stored conversation record (history-store.js encrypts and persists
 * it; history-ui.js/projects-ui.js reopen it via applyLoadedConversation).
 * @typedef {object} ConversationRecord
 * @property {string} title
 * @property {Array<{role: string, content: string|object[]}>} messages
 * @property {string} model
 * @property {?number} budgetS
 * @property {boolean} webSearch
 * @property {Array<{id: string, name: string}>} ragDocs
 * @property {import("./embeds.js").EmbedEntry[]} embeds
 * @property {?string} projectId
 * @property {number} createdAt
 * @property {number} updatedAt
 */

// ---- Conversation state -------------------------------------------------

const history = []; // {role, content} pairs sent to the API

// Large documents attached to this conversation (RAG-indexed — see
// public/js/rag.js): follow-up questions keep retrieving from them, so
// their ids/names are conversation state, persisted in the encrypted
// record (`ragDocs`) and restored on load.
let convRagDocs = []; // [{id, name}]

// ---- Embeds registry ----------------------------------------------------
// The pipeline-embedded elements' bookkeeping (recordEmbed / quizHooks /
// pruneEmbeds / capEmbedBytes and the registry itself) lives in
// public/js/embeds.js. Wired here with the live message array (`history` is
// a stable reference — cleared in place, never reassigned) and the persist
// hook a quiz completed after its stream ended needs; `lastSendOpts` is
// read at call time, so it always carries the latest send's metadata.
initEmbeds({ history, persist: () => persistConversation(lastSendOpts) });

// ---- Conversation identity & persistence ---------------------------------

// The project this conversation belongs to (null = none): adopted from the
// active project on the FIRST send of a fresh conversation, persisted in
// the encrypted record, restored on load. Project scope means: retrieval
// runs across the project's indexed docs too, the project-materials block
// (inventory + image EXIF) rides in each message, and persistence honors
// the project's cloud knob.
let convProjectId = null;

// The most recent send's persistence options (model/budget/webSearch) — a
// quiz answered AFTER its stream finished still needs to persist the
// conversation with the right metadata (quizHooks, embeds.js). Seeded from the
// record on load so a reload-then-finish doesn't clobber stored metadata.
let lastSendOpts = {};

let scrollDown = () => {};
let inFlight = false;
let controller = null; // AbortController of the in-flight request
// Bumped by clearHistory: a send that started under an older generation
// must never touch the new conversation's history or UI.
let generation = 0;

// Identity of the conversation currently in `history`, for the encrypted
// local-history sidebar (public/js/history-ui.js). Unset until the first
// exchange completes, so an abandoned empty chat never creates an entry.
let currentId = null;
let convTitle = null;
let convCreatedAt = null;
let onHistoryChange = () => {};

// Incognito (the header's ghost toggle): while true, persistConversation
// is a no-op — the conversation exists only in this tab's memory, never
// written to the encrypted local store or the cloud copy — AND every send
// carries `incognito: true` so the server keeps the exchange out of its
// full-visibility interaction log too (src/chatlog.js). Set only before
// the first message of a fresh conversation (app.js locks the toggle once
// the conversation has started) and reset by clearHistory / loading a
// saved conversation, so a chat can't retroactively vanish and a
// supposedly-incognito one can't retroactively persist.
let convIncognito = false;

export function setIncognito(on) {
  convIncognito = !!on;
}

export function isIncognito() {
  return convIncognito;
}

// True once the current conversation has content (a message in flight or
// landed, or a saved conversation loaded) — the point past which the
// incognito choice is locked.
export function conversationStarted() {
  return history.length > 0 || currentId !== null;
}

/**
 * One-time wiring from app.js.
 * @param {(force?: boolean) => void} scrollFn  auto-follow scroll callback
 * @param {{onHistoryChange?: (id: string) => void}} [opts]  fires after every persist/delete
 */
export function initStream(scrollFn, opts = {}) {
  scrollDown = scrollFn;
  onHistoryChange = opts.onHistoryChange || onHistoryChange;
}

// The id of the conversation currently on screen, or null for a fresh,
// not-yet-saved chat — used by the sidebar to highlight the active entry.
export function currentConversationId() {
  return currentId;
}

// The on-screen conversation as plain text for the header's copy button
// (app.js): "User: …" / "Assistant: …" turns with images and appended
// context blocks reduced to references — message-content.js's pure
// conversationCopyText over this tab's live history.
export function conversationAsText() {
  return conversationCopyText(history, getEmbeds());
}

// Replaces the on-screen conversation with a stored record — the shared
// core of the sidebar "load" and the boot-time pending-answer resume.
// Aborts any in-flight request and bumps `generation` exactly like
// clearHistory, so a stream from the conversation being replaced can never
// write into the newly opened one; then adopts the record's state and
// re-renders. Returns the new generation for callers that keep polling.
function openConversationRecord(id, record) {
  controller?.abort();
  controller = null;
  generation++;
  history.length = 0;
  history.push(...record.messages);
  currentId = id;
  convTitle = record.title || null;
  convCreatedAt = record.createdAt || null;
  convRagDocs = Array.isArray(record.ragDocs) ? record.ragDocs : [];
  setEmbeds(record.embeds); // normalized inside (any non-array means none)
  convIncognito = false; // a saved conversation is by definition not incognito
  // Reopening a project conversation re-enters that project's context
  // (and leaving one, a plain conversation leaves it).
  convProjectId = record.projectId || null;
  setActiveProject(convProjectId);
  // Finishing a reloaded quiz re-persists the conversation — with the
  // record's own metadata, not a stale (or empty) previous send's.
  lastSendOpts = { model: record.model || "", budgetS: record.budgetS ?? null, webSearch: record.webSearch !== false };
  renderStoredConversation(record.messages, getEmbeds(), { quizHooks });
  return generation;
}

/**
 * Sidebar "load": replace the on-screen conversation with a previously
 * saved one.
 * @param {ConversationRecord & {id: string}} record
 */
export function applyLoadedConversation(record) {
  openConversationRecord(record.id, record);
  resetStreetViewPov(); // any on-screen panorama belongs to the conversation being left
  clearPending(); // opening another conversation cancels any pending-answer resume
  scrollDown(true);
}

// Persists the current conversation after every completed exchange
// (success, stopped-with-partial-answer, or recovered/cut-off-with-
// partial-answer — anywhere an assistant reply actually lands in
// `history`). Silently a no-op if encrypted history isn't available
// (server not configured, or IndexedDB blocked) — the conversation still
// works for this tab, it just won't survive a reload.
async function persistConversation(opts) {
  if (convIncognito) return; // ghost toggle: this conversation is never written anywhere
  if (!history.length) return;
  if (!currentId) currentId = crypto.randomUUID();
  if (!convTitle) convTitle = deriveTitle(history);
  const now = Date.now();
  if (!convCreatedAt) convCreatedAt = now;
  try {
    await saveConversation(
      currentId,
      {
        title: convTitle,
        messages: history,
        model: opts?.model || "",
        budgetS: opts?.budgetS ?? null,
        webSearch: opts?.webSearch !== false,
        ragDocs: convRagDocs,
        embeds: getEmbeds(),
        projectId: convProjectId,
        createdAt: convCreatedAt,
        updatedAt: now,
      },
      { cloud: projectCloudOn(convProjectId) },
    );
    onHistoryChange(currentId);
  } catch {
    // See comment above — history storage being unavailable must never
    // surface as a chat error.
  }
  // Project chats are RAG-indexed as they grow (chat-rag.js): only the
  // turns not yet indexed are embedded, so this is one small embed call
  // per exchange. Fire-and-forget and fail-soft — an indexing hiccup
  // leaves srcMsgs where it was and the same turns retry after the next
  // exchange; it must never surface as a chat error.
  if (convProjectId && currentId) {
    indexChatTurns({
      convId: currentId,
      title: convTitle,
      messages: history.slice(),
      cloud: projectCloudOn(convProjectId),
    }).catch(() => {});
  }
}

// True while a /api/chat stream is running — downloads must wait (on iOS
// a download-triggered navigation aborts the in-flight fetch).
export function isStreaming() {
  return inFlight;
}

// New chat: forget the conversation AND abort any in-flight request —
// otherwise the invisible old stream keeps the send button hostage until
// it finishes, then leaks its answer into the fresh history.
export function clearHistory() {
  history.length = 0; // history lives only in this tab (encrypted copy aside)
  generation++;
  controller?.abort();
  controller = null;
  clearPending(); // "New chat" abandons any pending-answer resume too
  resetConversationMeta(); // the next send re-adopts whatever project is active
  convIncognito = false; // incognito is chosen per conversation, never inherited
  resetStreetViewPov(); // a fresh chat must not inherit the old panorama's view
}

// Forgets the identity/metadata of the current conversation (id, title,
// timestamps, RAG docs, embeds, project scope) — the messages themselves and
// the incognito flag are the caller's to handle.
function resetConversationMeta() {
  currentId = null;
  convTitle = null;
  convCreatedAt = null;
  convRagDocs = [];
  setEmbeds([]);
  convProjectId = null;
}

// Stop button: abort the in-flight request WITHOUT bumping `generation` —
// unlike clearHistory, the point here is to keep whatever streamed so far
// as normal context for a follow-up, not to discard it. sendMessage's
// catch block tells the two apart via `gen === generation`.
export function stopGeneration() {
  controller?.abort();
}

// ---- Answer recovery --------------------------------------------------
// The server parks every finished answer in a short-lived cache
// (src/answers.js) keyed by x-request-id: if our stream dies, we poll the
// completed answer back instead of asking the user to resend; if it
// arrives intact, we ack so the server purges its copy immediately.
// The transport half — the poll loop (recoverAnswer) and the ack — lives in
// public/js/recovery.js; this side owns what happens to a recovered answer,
// because all of it reads and writes this module's conversation state
// (history, identity, in-flight bookkeeping, persistence).

// A recovered answer landing in the conversation (boot-time resume, or
// in-session recovery after a dropped stream): render it — with its final
// stats when the server kept them — append it to history, purge the
// server's recovery copy, and persist.
async function deliverRecoveredAnswer(turn, recovered, requestId, opts) {
  setText(turn, recovered.text);
  if (recovered.stats) {
    turn.model = recovered.stats.model || "";
    turn.doneStats = recovered.stats;
    renderStats(turn, recovered.stats);
  }
  history.push({ role: "assistant", content: recovered.text });
  ackAnswer(requestId);
  await persistConversation(opts);
}

// A send that produced NO answer at all (empty completion, or a drop we
// couldn't recover): revert the unanswered question so a retry starts clean,
// and keep the encrypted record consistent with that. armPendingRecovery may
// have already persisted the question at stream start, so — unlike a plain
// pop — reconcile the stored record too: re-persist the reverted history for
// a follow-up, or delete the just-created record for a lone first message.
async function abandonUnanswered(opts) {
  clearPending();
  history.pop();
  pruneEmbeds(); // any embeds of the answer that never landed go with it
  if (!currentId) return; // nothing was persisted (incognito, or never armed)
  if (history.length) {
    await persistConversation(opts); // follow-up: store the reverted history
  } else {
    const id = currentId;
    resetConversationMeta(); // the discarded conversation is gone; next send starts fresh
    try { await deleteConversation(id); } catch { /* best effort */ }
    onHistoryChange(id);
  }
}

// Arm resume-across-relaunch for the in-flight send: persist the question to
// encrypted history NOW (so a cold boot after a PWA discard can show it) and
// drop a metadata-only pointer (pending-answer.js) the next boot polls the
// server-parked answer from. Incognito persists nothing anywhere, so it opts
// out entirely (no encrypted record to reopen, no pointer written). Both
// writes are fire-and-forget so the stream is never delayed.
function armPendingRecovery(requestId, opts) {
  if (convIncognito || !requestId) return;
  if (!currentId) currentId = crypto.randomUUID();
  persistConversation(opts).catch(() => {}); // question-only for now; re-persisted with the answer on completion
  writePending({
    convId: currentId,
    requestId,
    startedAt: Date.now(),
    model: opts.model || "",
    budgetS: opts.budgetS ?? null,
    webSearch: opts.webSearch !== false,
  });
}

// Called once on boot (app.js): if a previous session left an in-flight
// answer that a full app relaunch interrupted, reopen that conversation and
// poll the server-parked answer back. This is what lets a long research run
// survive the PWA being discarded while backgrounded — it finished on the
// server, and here the next launch collects it. Returns true if it resumed
// something. Fail-soft: any problem clears the pointer and returns false so
// boot proceeds normally.
export async function resumePendingAnswer({ onLoad } = {}) {
  if (inFlight) return false; // a live send is already going — don't fight it
  const pending = readPending();
  if (!pending) return false;

  let record = null;
  try {
    record = await loadConversation(pending.convId);
  } catch {
    record = null;
  }
  // The record must exist and still be awaiting its answer (a trailing user
  // turn, no assistant reply). If it already carries the answer, or is gone,
  // there's nothing to resume.
  const msgs = record?.messages;
  const awaiting = Array.isArray(msgs) && msgs.length > 0 && msgs[msgs.length - 1]?.role === "user";
  if (!awaiting) {
    clearPending();
    return false;
  }

  // Reopen the conversation — the pending pointer, not the sidebar, chose
  // it, and it stays armed until recovery settles below.
  const gen = openConversationRecord(pending.convId, record);
  if (onLoad) {
    try { onLoad(record); } catch { /* settings restore is best-effort */ }
  }

  const { text, imageUrls } = splitUserContent(msgs[msgs.length - 1].content);
  const turn = addAssistantTurn(text, imageUrls);
  scrollDown(true);

  const opts = { model: pending.model, budgetS: pending.budgetS, webSearch: pending.webSearch };
  // Mark the app as streaming while polling so the composer treats a click
  // as Stop, not a competing send that would race the recovered answer —
  // and give that Stop something to reach: this controller ends the wait.
  inFlight = true;
  controller = new AbortController();
  let recovered = null;
  let reason = "timeout";
  try {
    ({ data: recovered, reason } = await recoverAnswer(
      turn, pending.requestId, pending.budgetS, () => gen === generation, "Resuming your research…", controller.signal,
    ));
  } finally {
    inFlight = false;
    collapseActivity(turn);
  }
  if (gen !== generation || reason === "aborted") return false; // user navigated away while polling
  clearPending();
  if (recovered) {
    await deliverRecoveredAnswer(turn, recovered, pending.requestId, opts);
    return true;
  }
  if (reason === "stopped") {
    // The user chose not to wait. The question stays on screen as sent;
    // resending it is the retry path.
    setError(turn, "Stopped waiting for the previous answer. Your question is still here; send it again to re-run.");
    return false;
  }
  setError(
    turn,
    reason === "lost"
      ? "Your previous research was interrupted on the server before it finished — a long " +
        "time budget can exceed the hosting plan's per-request limit. Your question is still " +
        "here; try again, lowering the time budget if it recurs."
      : "Couldn't resume your previous research — it either finished after the 15-minute " +
        "recovery window closed or was interrupted. Your question is still here; just send it again.",
  );
  return false;
}

// ---- SSE event dispatch ---------------------------------------------------

// Dispatch one SSE event to the turn/activity renderers. Returns the updated
// text accumulator. Unknown status types fall through untouched — the
// protocol's forward-compatibility rule (see the sse-protocol skill).
function handleEvent(turn, evt, acc) {
  if (evt.error) {
    setError(turn, evt.error); // setError records it into researchLog
    return acc;
  }
  if (evt.status) {
    const s = evt.status;
    recordResearchEvent(turn, s);
    if (s.type === "search_start") startSearchStep(turn, s);
    else if (s.type === "search_done") finishSearchStep(turn, s);
    else if (s.type === "step_start") startGenericStep(turn, s.id, s.label || "");
    else if (s.type === "step_done") finishGenericStep(turn, s);
    else if (s.type === "streetview_embed") {
      renderStreetViewEmbed(turn, s);
      recordEmbed({ kind: "streetview_embed", lat: s.lat, lng: s.lng, heading: s.heading, pitch: s.pitch });
    } else if (s.type === "map_embed") {
      renderMapEmbed(turn, s);
      recordEmbed({ kind: "map_embed", lat: s.lat, lng: s.lng, zoom: s.zoom, q: s.q || "" });
    } else if (s.type === "streetview_frames") {
      renderStreetViewFrames(turn, s);
      recordEmbed({
        kind: "streetview_frames",
        query: s.query || "",
        directions: (Array.isArray(s.frames) ? s.frames : []).map((f) => f?.dir || f?.label || "").filter(Boolean),
        // The actual frame images (data URLs), so a conversation reopened
        // from history shows the imagery again instead of losing it
        // (reported: "all images are gone") — stored in the encrypted
        // record like user-attached images, size-capped by capEmbedBytes.
        frames: (Array.isArray(s.frames) ? s.frames : [])
          .filter((f) => typeof f?.url === "string")
          .map((f) => ({ dir: f.dir || "", label: f.label || "", url: f.url })),
      });
      capEmbedBytes();
    } else if (s.type === "quiz" && Array.isArray(s.quiz?.questions) && s.quiz.questions.length) {
      // The inline quiz (src/pipeline.js runQuizGeneration): the full
      // question set arrives in one event; the interaction — sequential
      // questions, alternatives + free-text, grading, the verdict — runs
      // entirely in quiz.js against the embeds-registry entry recorded
      // here, so the quiz (and its answers) survives reload like the
      // Street View elements do.
      const embed = recordEmbed({ kind: "quiz", quiz: s.quiz, answers: [] });
      renderQuiz(turn, s.quiz, quizHooks(embed));
    }
    else if (s.type === "done") {
      turn.model = s.model || ""; // titles the PDF report metadata
      turn.doneStats = s; // final stats for the debug-JSON export
      renderStats(turn, s);
    }
    else if (s.type === "discard_text") {
      resetForRevision(turn);
      return "";
    }
    // Unknown status types: ignore (forward compatibility).
    scrollDown();
    return acc;
  }
  const chunk = evt.choices?.[0]?.delta?.content;
  if (chunk) {
    acc += chunk;
    setText(turn, acc);
  }
  return acc;
}

// Append one research event to the turn's structured log, stamped with a
// relative timestamp (ms since the turn started). Text deltas are NOT
// recorded — this log is the research PROCESS (which services were queried,
// with what, in what order, how long each took), the source for the
// "Copy research JSON" debug button (activity.js). Bulky payloads (Street
// View frame data URLs) are compacted first (sanitizeResearchEvent).
function recordResearchEvent(turn, entry) {
  if (!turn.researchLog) return;
  turn.researchLog.push({ t: Date.now() - (turn.startedAt || Date.now()), ...sanitizeResearchEvent(entry) });
}

// ---- Send path ------------------------------------------------------------

// Builds the labeled excerpt blocks for every RAG-indexed document in this
// conversation: semantic retrieval against the question, a positional
// fallback for a newly attached doc retrieval missed entirely (a doc the
// user JUST attached must never be silently absent from its own turn),
// and a hard total-size budget.
async function buildRagBlocks(questionText, newRagDocs) {
  const project = convProjectId ? getProject(convProjectId) : null;
  const names = new Map(convRagDocs.map((d) => [d.id, d.name]));
  for (const f of project?.files || []) names.set(f.id, f.name);
  // Sibling chats: the project's OTHER conversations are indexed too
  // (chat-rag.js), so what was worked out in one project chat is
  // retrievable in this one. The current conversation is excluded — it's
  // already the context.
  let chatDocs = [];
  if (project) {
    try {
      chatDocs = siblingChatDocs(await listConversations(), convProjectId, currentId);
      for (const d of chatDocs) names.set(d.id, d.name);
    } catch {
      chatDocs = []; // sibling chats are optional context, never a blocker
    }
  }
  // Retrieval scope: this conversation's attached docs PLUS its project's
  // indexed material (documents, notes, sibling chats) — and nothing else
  // (no other project can leak in; the docId list IS the scope). Capped at
  // the server query's 20-docId limit, project material first.
  const docIds = [
    ...new Set([
      ...convRagDocs.map((d) => d.id),
      ...projectDocIds(project),
      ...chatDocs.map((d) => d.id),
    ]),
  ].slice(0, 20);
  const metaByDoc = new Map(newRagDocs.filter((d) => d.metadata).map((d) => [d.docId, d.metadata]));
  let matches = [];
  try {
    matches = await retrieve(docIds, questionText || "the attached document", 8);
  } catch {
    matches = [];
  }
  for (const d of newRagDocs) {
    if (!matches.some((m) => m.docId === d.docId)) {
      matches = matches.concat(await firstChunks(d.docId, 3).catch(() => []));
    }
  }
  if (!matches.length) return "";
  return ragExcerptBlocks(matches, names, metaByDoc, undefined, new Set(chatDocs.map((d) => d.id)));
}

// Build one outgoing user message's content (string, or multimodal parts
// when images ride along). Documents become labeled text blocks in the
// API message (never shown in the bubble); images become OpenAI-style
// multimodal parts. Extracted metadata (EXIF for images, docProps/
// tracked-changes/comments for docx, Info dict for pdf — see exif.js /
// docs.js) rides along as its own labeled block so it's research
// material, not silently dropped or silently blended into the main text.
//
// Large documents don't ride inline: they were RAG-indexed at attach
// time (attachments.js / rag.js) and contribute retrieved excerpts here
// instead — on this turn and on every follow-up in this conversation.
// A fresh conversation adopts the project that's active when its first
// message is sent; after that the conversation's own projectId rules —
// this is also where that adoption (convProjectId) and the conversation's
// RAG-doc roster (convRagDocs) are updated.
async function buildOutgoingUserContent(text, opts) {
  if (!currentId && !convProjectId) convProjectId = activeProjectId();
  const project = convProjectId ? getProject(convProjectId) : null;

  const newRagDocs = (opts.docs || []).filter((d) => d.rag && d.docId);
  for (const d of newRagDocs) {
    if (!convRagDocs.some((r) => r.id === d.docId)) {
      convRagDocs.push({ id: d.docId, name: d.name });
    }
  }
  let apiText = text;
  for (const d of opts.docs) {
    if (d.rag) continue; // excerpts appended below
    apiText += inlineDocBlock(d);
  }
  // Project materials: inventory + extracted image metadata (EXIF) as
  // context, then the same retrieval mechanism attachments use pulls the
  // relevant excerpts out of the project's indexed docs/notes.
  if (project) {
    apiText += buildProjectContext(project);
  }
  if (convRagDocs.length || project) {
    apiText += await buildRagBlocks(text, newRagDocs);
  }
  for (const a of opts.images) {
    apiText += imageMetadataBlock(a);
  }
  let content = apiText;
  if (opts.images.length) {
    content = [];
    if (apiText) content.push({ type: "text", text: apiText });
    for (const a of opts.images) {
      content.push({ type: "image_url", image_url: { url: a.dataUrl } });
    }
  }
  return content;
}

// The typed text of every user turn, oldest first (string or multimodal
// parts) — the device-location prefilter needs the EARLIER turns too: a
// short "My location" only reads as a here-ask because an earlier turn
// said "street view" (see asksDeviceLocation in message-content.js).
const userTexts = (msgs) =>
  msgs
    .filter((m) => m?.role === "user")
    .map((m) => {
      const c = m.content;
      if (typeof c === "string") return c;
      if (Array.isArray(c)) return c.find((p) => p?.type === "text")?.text || "";
      return "";
    });

// One-shot device geolocation for "street view here" asks: resolves null
// on any failure (no API, permission denied, timeout) — never throws, so
// the send path is never blocked by it. Coordinates rounded (~1m), the
// same cache-friendly precision the map view uses.
const deviceLocation = () =>
  new Promise((resolve) => {
    if (!navigator.geolocation) return resolve(null);
    try {
      navigator.geolocation.getCurrentPosition(
        (pos) =>
          resolve({
            lat: Math.round(pos.coords.latitude * 1e5) / 1e5,
            lng: Math.round(pos.coords.longitude * 1e5) / 1e5,
          }),
        () => resolve(null),
        { enableHighAccuracy: false, timeout: 8000, maximumAge: 120000 },
      );
    } catch {
      resolve(null);
    }
  });

// Assemble the /api/chat request body from the module's conversation state
// (history, incognito) plus this send's options and the live view anchors.
// May await the device's geolocation — only for the exact ask shapes
// documented inline, so the permission prompt never fires gratuitously.
async function buildChatPayload(opts) {
  const payload = {
    messages: stripOldImages(history),
    time_budget_s: opts.budgetS,
    web_search: opts.webSearch,
  };
  if (opts.model) payload.model = opts.model;
  // Ghost toggle: tells the server to keep this exchange out of the
  // server-side interaction log too (src/chatlog.js) — the same choice
  // that keeps it out of local/cloud chat history.
  if (convIncognito) payload.incognito = true;
  // Raw GPS coordinates ride separately from the message text — the
  // Worker resolves them to a place name (src/geocode.js) and appends
  // that as its own context block, rather than the client guessing.
  const imageLocations = opts.images
    .filter((a) => a.gps)
    .map((a) => ({ name: a.name, lat: a.gps.lat, lon: a.gps.lon }));
  if (imageLocations.length) payload.imageLocations = imageLocations;
  // The user's CURRENT view in the inline Street View panorama (they may
  // have panned/moved it) — the server captures exactly that frame when a
  // follow-up refers back to the imagery (src/enrichment.js). Null when no
  // live panorama exists this session.
  const streetViewPov = getStreetViewPov();
  if (streetViewPov) payload.street_view_pov = streetViewPov;
  // The map sibling: the center/zoom of the live interactive MAP (shown
  // when a location has no Street View coverage) — the server captures a
  // road-map image of exactly that area on a map-referencing follow-up.
  const mapView = getMapView();
  if (mapView) payload.map_view = mapView;
  // A here-ask ("street view here", a plain "where am I?", or a short
  // "my location" answer to an earlier street-view turn) with NO live
  // view on screen to anchor to: ask the browser for the device's
  // location (the permission prompt fires for exactly these asks,
  // nothing else) and send it as the jump anchor. EXCEPTION: an explicit
  // PHYSICAL-location ask ("my actual location", "min faktiska plats")
  // sends it even while a live view exists — the user has navigated the
  // view elsewhere and means their real position, and the server flips
  // the anchor precedence accordingly (pickLookup). Fail-soft:
  // denied/unavailable/timeout sends nothing and the server honestly
  // asks for location access instead.
  const texts = userTexts(history);
  const latestText = texts[texts.length - 1] || "";
  if (asksPhysicalLocation(latestText) || (!streetViewPov && !mapView && asksDeviceLocation(texts))) {
    const loc = await deviceLocation();
    if (loc) payload.user_location = loc;
  }
  return payload;
}

// The experimental bash-lite sandbox pre-pass (the `bash_lite_mcp` knob). When
// the knob is on and the sandbox can run here (cross-origin isolated), the
// MODEL — not a client-side keyword gate — decides whether this message needs a
// shell: the agentic loop (public/js/bash-agent.js) asks it cold, and it
// returns done immediately for anything that doesn't. So "list files", "run la
// -la", or any phrasing the old regex missed now work, because the model makes
// the call. The Linux VM boots LAZILY (bootOnce) — only once the model actually
// proposes a command — so ordinary chat with the knob on pays one cheap model
// call and never boots the VM. Returns the transcript for stream.js to attach
// as `shell_transcript`; the pipeline folds it into the answer as ground truth.
// Fully fail-soft: any problem returns [] and the answer proceeds normally.
/**
 * @param {object} turn the assistant turn (activity target)
 * @returns {Promise<Array<{command: string, exitCode: number, stdout: string, stderr: string}>>}
 */
async function maybeRunShellLoop(turn, opts) {
  try {
    if (!bashLiteOn()) return []; // knob off — feature disabled, nothing to do
    // Knob on but the page isn't cross-origin isolated (COEP): the sandbox
    // cannot boot. app.js self-heals by reloading once; if we still land here,
    // tell the user plainly instead of silently answering "I can't run code".
    if (!sandboxSupported()) {
      startGenericStep(turn, "sandbox", "Starting sandbox…");
      finishGenericStep(turn, {
        id: "sandbox",
        label: "Sandbox is enabled but this page isn't isolated yet — reload the page to start it.",
      });
      return [];
    }

    let booted = false;
    let ran = 0;
    // Boot the VM the first (and only the first) time the model asks to run
    // something — surfaced as a turn step so the user sees the (slow) first
    // boot. Returns whether the sandbox is usable.
    const fileProvider = buildSandboxFileProvider(opts);
    const bootOnce = async () => {
      startGenericStep(turn, "sandbox", "Booting Linux sandbox…");
      booted = await ensureSandboxBooted(fileProvider);
      if (!booted) finishGenericStep(turn, { id: "sandbox", label: "Sandbox unavailable — answering normally" });
      return booted;
    };
    const transcript = await runShellLoop({
      messages: stripOldImages(history),
      exec: execInSandbox,
      ensureReady: bootOnce,
      onResult: () => {
        ran++;
        updateGenericStep(turn, "sandbox", `Running in sandbox — ${ran} command${ran === 1 ? "" : "s"}…`);
      },
    });
    // Only report a finished step if we actually booted and ran (a message the
    // model judged not to need a shell shows no sandbox activity at all).
    if (booted && transcript.length) {
      finishGenericStep(turn, {
        id: "sandbox",
        label: `Ran ${transcript.length} command${transcript.length === 1 ? "" : "s"} in the Linux sandbox`,
        details: transcript.map((r) => `$ ${r.command}`),
      });
    }
    return transcript;
  } catch (err) {
    try { finishGenericStep(turn, { id: "sandbox", label: "Sandbox error — answering normally" }); } catch {}
    return [];
  }
}

// ---- introspection mode: the private (browser-direct) answer route -----------

// The source snapshot, fetched once per page load (multi-MB; introspection
// asks are rare and the artifact only changes with a deploy).
let introspectSnapshotPromise = null;
function introspectSnapshot() {
  if (!introspectSnapshotPromise) {
    introspectSnapshotPromise = fetch(SNAPSHOT_PATH)
      .then(async (res) => (res.ok ? validateSnapshot(await res.json()) : null))
      .catch(() => null);
  }
  return introspectSnapshotPromise;
}

// Introspection-engaged check for the CURRENT conversation (regex gate free;
// the snapshot loads only when a path-shaped mention needs confirming).
async function introspectionEngagedNow() {
  const texts = userTexts(history);
  if (introspectionActive(texts)) return true;
  if (!texts.some((t) => maybeRepoPathMention(t))) return false;
  const snap = await introspectSnapshot();
  return !!snap && introspectionActive(texts, snap);
}

// The friendly phase labels for the private run's single activity step.
const PRIVATE_PHASE_LABELS = {
  triage: "Planning (browser-direct)…",
  harvest: "Gathering notes (browser-direct)…",
  gap: "Auditing coverage (browser-direct)…",
  synth: "Writing the answer (browser-direct)…",
  validate: "Reviewing the draft (browser-direct)…",
  sandbox: "Running in the Linux sandbox…",
  answer: "Writing the answer (browser-direct)…",
  clarify: "Asking for a detail…",
};

// The PRIVATE introspection route: with developer mode on, the conversation
// in introspection mode, and a private (own-key) model picked in TIN's panel
// (introspect-ui.js), the whole exchange runs BROWSER-DIRECT through the
// client-side pipeline (drc-research.js) on the user's key — /api/chat is
// never called, so this site's server sees nothing of the conversation.
// Returns false (fall through to the normal server path) unless the route
// fully applies; once the run starts, every outcome settles HERE.
async function maybePrivateIntrospection(turn, opts, signal, gen) {
  let route = null;
  let snap = null;
  try {
    if (!developerModeOn()) return false;
    route = privateIntrospectionRoute();
    if (!route) return false;
    if (!(await introspectionEngagedNow())) return false;
    snap = await introspectSnapshot();
    if (!snap) return false; // no snapshot → no introspection to speak of
  } catch {
    return false; // any decision-phase problem → the ordinary server path
  }
  await runPrivateIntrospection(turn, opts, signal, gen, route, snap);
  return true;
}

async function runPrivateIntrospection(turn, opts, signal, gen, route, snap) {
  let acc = "";
  try {
    const texts = userTexts(history);
    startGenericStep(turn, "introspect", `Private introspection — ${route.model} on your ${route.label} key…`);
    recordResearchEvent(turn, { event: "private_introspection", provider: route.providerId, model: route.model });
    const block = buildIntrospectionBlock(snap, {
      latestText: texts[texts.length - 1] || "",
      sandboxMounted: bashLiteOn() && sandboxSupported(),
    });
    // The client pipeline works on plain text turns: flatten multimodal
    // content to its text parts (images can't ride the browser-direct wire).
    const messages = history.slice(-12).map((m) => ({
      role: m.role,
      content:
        typeof m.content === "string"
          ? m.content
          : Array.isArray(m.content)
            ? m.content.filter((p) => p?.type === "text").map((p) => p.text || "").join("\n")
            : "",
    })).filter((m) => m.content);
    const result = await runDrcResearch({
      providerId: route.providerId,
      apiKey: route.apiKey,
      model: route.model,
      messages,
      research: opts.webSearch !== false, // the composer knob keeps its meaning: phases on/off
      introspection: block,
      bash: bashLiteOn(),
      fileProvider: async () => ({ session: [], project: null, source: { files: snap.files } }),
      onStatus: (s) => {
        if (gen !== generation) return;
        if (s.type === "phase") {
          updateGenericStep(turn, "introspect", PRIVATE_PHASE_LABELS[s.phase] || "Working (browser-direct)…");
          recordResearchEvent(turn, { event: "phase", phase: s.phase });
        } else if (s.type === "discard_text") {
          acc = "";
          resetForRevision(turn);
        }
      },
      onDelta: (chunk) => {
        if (gen !== generation) return;
        acc += chunk;
        setText(turn, acc);
        scrollDown();
      },
      signal,
    });
    if (gen !== generation) return; // New chat took the conversation mid-run
    const answer = result?.answer || acc;
    if (answer) {
      setText(turn, answer);
      history.push({ role: "assistant", content: answer });
      finishGenericStep(turn, {
        id: "introspect",
        label: `Answered privately — browser → ${route.label} on your key; this site's server was not involved`,
      });
      await persistConversation(opts);
    } else {
      finishGenericStep(turn, { id: "introspect", label: "Private introspection produced no answer" });
      setError(turn, "No response received.");
      await abandonUnanswered(opts);
    }
  } catch (e) {
    if (gen !== generation) return;
    if (e?.name === "AbortError") {
      // The user pressed Stop: keep the partial as context, like the server path.
      finishGenericStep(turn, { id: "introspect", label: "Stopped" });
      if (acc) {
        const stopped = acc + "\n\n*(Stopped.)*";
        setText(turn, stopped);
        history.push({ role: "assistant", content: stopped });
        await persistConversation(opts);
      } else {
        setError(turn, "Stopped before any response arrived.");
        history.pop();
        pruneEmbeds();
      }
      return;
    }
    finishGenericStep(turn, { id: "introspect", label: "Private route failed" });
    setError(turn, (e?.message || "The private request failed.") + " (Your key, browser-direct — nothing was sent to this site's server.)");
    history.pop();
    pruneEmbeds();
  } finally {
    inFlight = false;
    collapseActivity(turn);
  }
}

// Build the file provider the sandbox seeds from (design part B): this send's
// attachments become /workspace files, the active project's files become the
// project mount. Returns an async fn the sandbox calls once, right before boot
// — deferred so the (possibly decrypting) byte loads only happen if the model
// actually needs the VM. Fully fail-soft: a file that won't load is skipped.
/**
 * @param {{ docs?: any[], images?: any[] }} opts the send options (attachments)
 * @returns {() => Promise<{ session: any[], project: any }>}
 */
function buildSandboxFileProvider(opts) {
  return async () => {
    let meta = [];
    try { meta = await listOriginals(); } catch { meta = [] }
    const encById = new Map(meta.map((m) => [m.id, m.enc === true]));

    // Bytes for one attachment/file: prefer already-parsed inline text, else
    // the OPFS original (decrypted when the meta row says it's encrypted).
    const bytesFor = async (fileId, inlineText, name) => {
      if (typeof inlineText === "string" && inlineText) {
        return new TextEncoder().encode(inlineText);
      }
      if (!fileId) return null;
      try {
        const file = await loadOriginal(fileId);
        if (!file) {
          sblog("debug", "sandbox.fs.source_missing", { name: String(name || "").slice(0, 120) });
          return null;
        }
        const raw = new Uint8Array(await file.arrayBuffer());
        if (encById.get(fileId)) {
          try {
            return await decryptBytes(raw);
          } catch {
            sblog("warn", "sandbox.fs.decrypt_failed", { name: String(name || "").slice(0, 120) });
            return null;
          }
        }
        return raw;
      } catch (err) {
        sblog("warn", "sandbox.fs.source_error", { name: String(name || "").slice(0, 120), error: String((/** @type {any} */ (err))?.message || err).slice(0, 160) });
        return null;
      }
    };

    const session = [];
    for (const d of (opts?.docs || [])) {
      const b = await bytesFor(d.fileId, d.text, d.name);
      if (b && b.length) session.push({ name: d.name, type: d.ext || "doc", bytes: b });
    }
    for (const im of (opts?.images || [])) {
      const b = await bytesFor(im.fileId, null, im.name);
      if (b && b.length) session.push({ name: im.name, type: "image", bytes: b });
    }

    let project = null;
    try {
      const p = activeProject();
      if (p && Array.isArray(p.files) && p.files.length) {
        const files = [];
        for (const f of p.files) {
          const b = await bytesFor(f.id, null, f.name);
          if (b && b.length) files.push({ name: f.name, type: f.kind || f.ext || "file", bytes: b });
        }
        if (files.length) project = { name: p.name, id: p.id, files };
      }
    } catch { /* no project / not available — session-only */ }

    // Introspection (developer mode): when this conversation asks about the
    // site's own implementation, fetch the pre-bundled source snapshot and
    // hand it to the sandbox as the `source` scope — sandbox.js streams the
    // files into a DataDevice and seeds the tree at /src (no unpacking in the
    // guest). Deferred like everything in this provider: the (multi-MB) fetch
    // only happens once the model actually proposes a command. Fail-soft.
    let source = null;
    try {
      if (developerModeOn()) {
        const texts = userTexts(history);
        const cheap = introspectionActive(texts) || texts.some((t) => maybeRepoPathMention(t));
        if (cheap) {
          const snap = await introspectSnapshot(); // page-lifetime cache
          if (snap && introspectionActive(texts, snap)) source = { files: snap.files };
        }
      }
    } catch { /* snapshot unavailable — mount without it */ }

    sblog("info", "sandbox.fs.provider", {
      session_files: session.length,
      project: project ? project.name : null,
      project_files: project ? project.files.length : 0,
      source_files: source ? source.files.length : 0,
    });
    return { session, project, source };
  };
}

/**
 * One send: text plus attachments already collected by the composer.
 * Pushes the user turn, streams /api/chat into a fresh assistant turn, and
 * settles every outcome (done / stopped / dropped-and-recovered / failed).
 * @param {string} text  the typed message
 * @param {SendOpts} opts
 * @returns {Promise<void>} resolves when the exchange has fully settled
 */
export async function sendMessage(text, opts) {
  const content = await buildOutgoingUserContent(text, opts);
  history.push({ role: "user", content });
  // Captured for out-of-band persistence (a quiz finished after this stream
  // ends re-persists with the same metadata — see quizHooks).
  lastSendOpts = { model: opts.model, budgetS: opts.budgetS, webSearch: opts.webSearch };
  const imageUrls = opts.images.map((a) => a.dataUrl);
  addUserBubble(text, imageUrls, opts.docs.map((d) => d.name));
  const turn = addAssistantTurn(text, imageUrls);
  let acc = "";
  inFlight = true;
  const gen = generation;
  controller = new AbortController();
  const signal = controller.signal;

  // INTROSPECTION MODE's private route (developer mode + TIN's picker set to
  // an own-key model + the conversation asking about this site's own
  // implementation): the exchange runs browser-direct on the user's key and
  // settles entirely inside runPrivateIntrospection — /api/chat, the
  // watchdog, and the recovery machinery below never engage (there is no
  // server request to watch or recover). Stop still works: it aborts the
  // same controller this send owns.
  if (await maybePrivateIntrospection(turn, opts, signal, gen)) return;

  // iOS suspends network for backgrounded apps/PWAs — the most common cause
  // of mid-stream drops. On return the torn-down socket frequently makes the
  // next reader.read() HANG with no error, so a plain try/catch would never
  // notice; the watchdog below detects the silence and switches to recovery.
  let wasHidden = document.hidden;
  let lastByteAt = Date.now(); // last time the stream produced ANY bytes (incl. keepalives)
  let staleAbort = false; // set when the watchdog (not the user) aborts, so the catch recovers
  const onVisibility = () => {
    if (document.hidden) {
      wasHidden = true;
    } else {
      // Back in the foreground: grant a fresh full stall window for the
      // connection to resume before the watchdog judges it dead (elapsed
      // time spent hidden must not count as silence — see isStreamStale).
      lastByteAt = Date.now();
    }
  };
  document.addEventListener("visibilitychange", onVisibility);
  const reqController = controller; // capture: clearHistory may reassign the module-level one
  const watchdog = setInterval(() => {
    if (isStreamStale(lastByteAt, Date.now(), document.hidden, STREAM_STALL_MS)) {
      staleAbort = true;
      try { reqController.abort(); } catch { /* already settled */ }
    }
  }, 5000);

  let requestId = "";
  try {
    const payload = await buildChatPayload(opts);
    // Introspection on the SERVER route: wave TIN in (the user may still
    // switch to the private route for the next message), and honor a remote
    // model explicitly picked in the panel over the composer dropdown.
    if (developerModeOn() && (await introspectionEngagedNow())) {
      engageIntrospection();
      const remoteModel = introspectionRemoteModel();
      if (remoteModel) payload.model = remoteModel;
    }
    // Experimental bash-lite sandbox: when the message wants a shell, run the
    // in-browser Linux agent loop first and attach its transcript so the
    // answer is written from the real command output. No-op (empty) unless the
    // knob is on and the sandbox can run — see maybeRunShellLoop.
    const shellTranscript = await maybeRunShellLoop(turn, opts);
    if (shellTranscript.length) payload.shell_transcript = shellTranscript;
    // Diagnostic: report the client's sandbox-readiness so a not-running
    // sandbox can be diagnosed from the chat log (src/chatlog.js meta) —
    // crossOriginIsolated is the gate the loop needs, and it can only be
    // observed in the actual browser session.
    payload.client_diag = {
      coi: typeof crossOriginIsolated !== "undefined" ? !!crossOriginIsolated : null,
      bl: bashLiteOn(),
      sb: sandboxSupported(),
      ran: shellTranscript.length,
      css: (() => { try { return getComputedStyle(document.documentElement).getPropertyValue("--css-version").trim(); } catch { return ""; } })(),
      // Browser capability probe: is SharedArrayBuffer even defined (the thing
      // cross-origin isolation gates), and which browser/version — so a
      // coi:false with the header served can be pinned to browser support.
      sab: typeof SharedArrayBuffer !== "undefined",
      ua: (() => { try { return (navigator.userAgent || "").slice(0, 140); } catch { return ""; } })(),
      // The last sandbox filesystem-mount summary (public/js/sandbox.js) — so a
      // mount problem shows in the chat log meta (src/chatlog.js) even without
      // the debug beacon: files mounted (n), bytes (b), a project mount (proj),
      // dropped count (drop), boot ms, and any error.
      fs: sandboxFsSummary() || undefined,
    };
    const res = await fetch("/api/chat", {
      method: "POST",
      headers: { "content-type": "application/json" },
      body: JSON.stringify(payload),
      signal,
    });
    requestId = res.headers.get("x-request-id") || "";

    const isJson = (res.headers.get("content-type") || "").includes("application/json");
    if (!res.ok || !res.body || isJson) {
      const err = await res.json().catch(() => ({ error: "Request failed (" + res.status + ")" }));
      if (gen === generation) {
        setError(turn, err.error || "Something went wrong.");
        history.pop();
        pruneEmbeds();
      }
      return;
    }

    // The stream is live and the server will finish + park this answer even
    // if we vanish. Make it resumable after a FULL app relaunch (iOS can
    // discard a backgrounded PWA, losing all in-memory state): persist the
    // question to encrypted history now and drop a metadata-only pointer the
    // next boot polls from. Fire-and-forget — never delays the stream.
    armPendingRecovery(requestId, opts);

    const reader = res.body.getReader();
    const decoder = new TextDecoder();
    const parser = createSseParser(); // line buffering + [DONE]/keepalive filtering (sse.js)
    while (true) {
      const { done, value } = await reader.read();
      lastByteAt = Date.now(); // any read (data, keepalive, or EOF) proves the socket is live
      if (done) break;
      for (const evt of parser.push(decoder.decode(value, { stream: true }))) {
        acc = handleEvent(turn, evt, acc);
      }
    }

    if (gen !== generation) {
      // Chat was cleared while the tail streamed in: nothing to render or
      // remember; purge the server's copy of an answer nobody will read.
      ackAnswer(requestId);
      return;
    }
    if (acc) {
      history.push({ role: "assistant", content: acc });
      ackAnswer(requestId); // delivered intact — purge the server's recovery copy
      clearPending(); // delivered — no relaunch resume needed
      await persistConversation(opts);
    } else if (isTyping(turn)) {
      setError(turn, "No response received.");
      await abandonUnanswered(opts);
    }
  } catch (e) {
    if (e?.name === "AbortError") {
      if (gen !== generation) {
        // New chat cleared history while this stream was still running:
        // nothing to keep, no error UI, no beacon, no recovery — just
        // purge the abandoned server copy.
        ackAnswer(requestId);
        return;
      }
      if (staleAbort) {
        // The watchdog aborted a silent/hung stream (typically a socket
        // torn down while the app was backgrounded), NOT the user pressing
        // Stop — the server is still finishing, so recover the answer
        // rather than treating the partial as a deliberate stop.
        await handleNetworkFailure(turn, new Error("stream stalled — connection went silent"), acc, requestId, wasHidden, gen, opts);
        return;
      }
      await handleStopped(turn, acc, requestId, opts);
      return;
    }
    await handleNetworkFailure(turn, e, acc, requestId, wasHidden, gen, opts);
  } finally {
    inFlight = false;
    clearInterval(watchdog);
    document.removeEventListener("visibilitychange", onVisibility);
    collapseActivity(turn); // research done → fold the step bars away
  }
}

// The user pressed Stop mid-stream: keep whatever streamed so far as
// normal (non-error) context — that's the whole point of stopping instead
// of just waiting, the partial answer is still there for a follow-up
// question. The server finishes the research in the background regardless
// (src/chat.js's ctx.waitUntil), so purge its recovery copy — nobody will
// poll for it.
async function handleStopped(turn, acc, requestId, opts) {
  recordResearchEvent(turn, { event: "stopped", received_chars: acc.length });
  ackAnswer(requestId);
  clearPending(); // user stopped deliberately — no relaunch resume
  if (acc) {
    const stopped = acc + "\n\n*(Stopped.)*";
    setText(turn, stopped);
    history.push({ role: "assistant", content: stopped });
    await persistConversation(opts);
  } else {
    setError(turn, "Stopped before any response arrived.");
    history.pop();
    pruneEmbeds();
  }
}

// Any non-abort exception (dropped connection, backgrounded-tab network
// suspension, etc): tell the server why the client's side died, try to
// recover the finished answer from the short-lived server cache, and only
// fall back to a visible error once recovery comes up empty.
async function handleNetworkFailure(turn, e, acc, requestId, wasHidden, gen, opts) {
  // Tell the server why the client's side died — it often can't know (a
  // download-triggered navigation or backgrounded tab kills the fetch
  // without a clean disconnect). sendBeacon survives page teardown.
  try {
    navigator.sendBeacon?.(
      "/api/client-error",
      new Blob(
        [JSON.stringify({
          request_id: requestId,
          error: String(e?.message || e).slice(0, 200),
          was_hidden: wasHidden,
          received_chars: acc.length,
        })],
        { type: "application/json" },
      ),
    );
  } catch { /* reporting must never mask the real error */ }

  // The server finishes the research even when our connection dies and
  // parks the answer in a short-lived recovery cache — poll it back
  // before bothering the user. Settle whatever spinner the dead stream left
  // behind (it can never receive its step_done) and show a live ticking
  // banner instead — a frozen "Checking Google Maps…" spinner reads as
  // stuck forever (reported), while "Still researching… (Ns)" reads as the
  // progress it actually is.
  settlePendingSteps(turn);
  // The wait must be STOPPABLE (reported 2026-07-08: a run stuck at "Still
  // researching… (120s)" with a Stop button that did nothing — the original
  // request's controller was already aborted, so stopGeneration() had
  // nothing left to reach). A fresh controller in the module slot puts the
  // Stop button back in charge of THIS wait; the server run itself can't be
  // cancelled (it finishes and parks its answer regardless — waitUntil), but
  // the user gets their composer and conversation buttons back immediately.
  // Claimed only while this send still owns the conversation (gen check) —
  // a stale failure path must never grab a newer send's Stop button.
  const recoveryController = new AbortController();
  if (gen === generation) controller = recoveryController;
  const { data: recovered, reason } = await recoverAnswer(
    turn, requestId, opts.budgetS, () => gen === generation,
    "Connection dropped — research continues on the server…",
    recoveryController.signal,
  );
  recordResearchEvent(turn, {
    event: "stream_dropped",
    error: String(e?.message || e),
    was_hidden: wasHidden,
    received_chars: acc.length,
    recovered: !!recovered,
    recover_reason: reason,
  });
  if (gen !== generation || reason === "aborted") {
    // Chat was cleared while recovery was polling — drop the result.
    ackAnswer(requestId);
    return;
  }
  // Reaching here means this tab is alive and handled the drop in-session
  // (the PWA-discard case never runs any of this — the page is gone — so
  // its pointer survives untouched for the next boot to resume). Either way
  // the outcome is now decided here, so the pointer has done its job.
  clearPending();
  if (recovered) {
    await deliverRecoveredAnswer(turn, recovered, requestId, opts);
    return;
  }
  if (reason === "stopped") {
    // The user pressed Stop during the wait: settle exactly like stopping a
    // live stream — keep any partial answer as normal context, no error UI.
    await handleStopped(turn, acc, requestId, opts);
    return;
  }

  const ref = requestId ? " (ref " + requestId.slice(0, 8) + ")" : "";
  setError(
    turn,
    reason === "lost"
      ? "The research was interrupted on the server before it could finish — a long time " +
        "budget can exceed the hosting plan's per-request limit. Please try again, and if it " +
        "keeps happening, lower the time budget (the slider). " +
        (acc ? "The partial answer above stays in context." : "") + ref
      : wasHidden
        ? "The connection dropped while the app was in the background — phones pause " +
          "network for backgrounded apps, and this one stayed away long enough that the " +
          "finished answer could no longer be retrieved. The research still completed on " +
          "the server; a shorter switch away recovers automatically. " +
          (acc ? "The partial answer above stays in context — just ask a follow-up." : "Please send again.") + ref
        : "Network error: " + e.message + ref,
  );
  if (acc) {
    // Keep whatever streamed before the connection dropped: the partial
    // answer is visible in the bubble, so it must be in the context of
    // follow-up questions too. The marker tells the model (and reader)
    // that it ends abruptly.
    history.push({
      role: "assistant",
      content: acc + "\n\n[This answer was cut off by a connection error.]",
    });
    await persistConversation(opts);
  } else {
    // Nothing arrived at all — drop the question so a retry starts clean
    // (and reconcile the record armPendingRecovery may have persisted).
    await abandonUnanswered(opts);
  }
}

// Bidirectional storage sync, driven by the account's cloud-storage knob
// (settings.js / src/settings.js) and — since projects — by each project's
// own knob (projects.js):
//
//   account knob ON  → syncToServer(): push every eligible local record —
//     conversations and project records in their STORED FORM (encrypted
//     ciphertext moved as-is; project chats rest readable because they're
//     RAG-indexed — history-store.js), OPFS-stored original files (also in
//     storage form: encrypted except RAG-indexed docs), and locally-indexed
//     RAG documents including chat docs (vectors included, so nothing is
//     re-embedded). "Eligible" excludes everything belonging to a project
//     whose own knob is OFF. Local copies STAY — they're the lazy cache
//     the app keeps reading first.
//   account knob OFF → syncToClient(): pull everything down (newer
//     records, missing files, missing RAG docs), then wipe the server
//     side with one DELETE /api/storage.
//   project knob ON  → pushProjectScope(): syncToServer restricted to that
//     one project's record, conversations, files and index.
//   project knob OFF → drainProjectScope(): pull that project's items down
//     where missing, then delete ONLY its cloud objects, item by item —
//     the rest of the account's cloud storage is untouched.
//
// While knobs are on, steady-state writes don't come through here —
// history-store.js dual-writes each record as it's saved and rag.js
// mirrors each document as it's indexed; sync.js covers the bulk moves and
// reconciliation (pullNewer on sidebar open / boot).
//
// Everything is last-write-wins by updatedAt and per-item fail-soft: one
// failed item is counted and skipped, never a wedged sync.

import { chatConvId, chatDocId } from "./chat-rag.js";
import {
  encryptBytes,
  exportEncryptedProjectRecords,
  exportEncryptedRecords,
  importEncryptedProjectRecord,
  importEncryptedRecord,
} from "./history-store.js";
import { listOriginals, loadOriginal, opfsAvailable, saveOriginal } from "./opfs.js";
import { fileProjectMap, getProject, listProjects, projectCloudOn, refreshProjects } from "./projects.js";
import { hasDoc, importDoc, listDocs, pushDocToServer } from "./rag.js";
import { serverHistoryOn, serverRagAvailable } from "./settings.js";

async function jsonOrNull(res) {
  return res.ok ? res.json().catch(() => null) : null;
}

// Records move in their stored form: encrypted {iv, ciphertext} for
// everything except project chats, which rest readable ({data}) because
// they're RAG-indexed (history-store.js explains the rule).
const putRecord = (family, rec) =>
  fetch(`/api/${family}/` + encodeURIComponent(rec.id), {
    method: "PUT",
    headers: { "content-type": "application/json" },
    body: JSON.stringify(
      rec.data
        ? { data: rec.data, updatedAt: rec.updatedAt }
        : { iv: rec.iv, ciphertext: rec.ciphertext, updatedAt: rec.updatedAt },
    ),
  });

// ---- knob ON: local → server -------------------------------------------------

/**
 * Bulk local → server push (the account knob flipping ON, and boot's
 * background reconcile).
 * @param {(msg: string) => void} [onProgress]  status-line narration
 * @param {?string} [scopeProjectId]  restricts the push to one project (the
 *   per-project knob flipping ON); without it, everything except cloud-off
 *   projects goes
 * @returns {Promise<{pushed: number, errors: string[]}>}
 */
export async function syncToServer(onProgress = () => {}, scopeProjectId = null) {
  const errors = [];
  let pushed = 0;
  await listProjects(); // make the knob/file maps below answerable
  const fileMap = fileProjectMap();
  // Eligibility under the project knobs: in scoped mode, ONLY the scoped
  // project's items; otherwise everything not owned by a cloud-off project.
  const projectOk = (projectId) =>
    scopeProjectId ? projectId === scopeProjectId : projectCloudOn(projectId || null);
  const fileOk = (fileId) => projectOk(fileMap.get(fileId) || null);

  // Project records (same encrypted-record push as conversations).
  onProgress("Uploading project records…");
  try {
    const remote = (await jsonOrNull(await fetch("/api/projects")))?.projects || [];
    const remoteAt = new Map(remote.map((p) => [p.id, p.updatedAt]));
    for (const rec of await exportEncryptedProjectRecords()) {
      if (!projectOk(rec.id)) continue;
      if ((remoteAt.get(rec.id) || 0) >= rec.updatedAt) continue;
      const res = await putRecord("projects", rec);
      if (res.ok) pushed++;
      else errors.push("project " + rec.id.slice(0, 8));
    }
  } catch {
    errors.push("project list");
  }

  // Conversations: push records the server doesn't have, or has older.
  onProgress("Uploading conversations…");
  try {
    const remote = (await jsonOrNull(await fetch("/api/convos")))?.conversations || [];
    const remoteAt = new Map(remote.map((c) => [c.id, c.updatedAt]));
    for (const rec of await exportEncryptedRecords()) {
      if (scopeProjectId ? rec.projectId !== scopeProjectId : !projectOk(rec.projectId)) continue;
      if ((remoteAt.get(rec.id) || 0) >= rec.updatedAt) continue;
      const res = await putRecord("convos", rec);
      if (res.ok) pushed++;
      else errors.push("conversation " + rec.id.slice(0, 8));
      onProgress(`Uploading conversations… ${pushed}`);
    }
  } catch {
    errors.push("conversation list");
  }

  // Original files (OPFS → R2, in storage form — encrypted for everything
  // except RAG-indexed documents). This pass is also the self-healing
  // migration for that rule: a file stored readable before the rule
  // existed (or by an older client) is re-encrypted in place first, and a
  // remote copy whose form doesn't match gets re-uploaded. A file that
  // SHOULD be encrypted but can't be (no key) is skipped entirely, never
  // uploaded readable.
  onProgress("Uploading files…");
  try {
    if (await opfsAvailable()) {
      const remoteFiles = (await jsonOrNull(await fetch("/api/files")))?.files || [];
      const remoteEnc = new Map(remoteFiles.map((f) => [f.id, f.enc === true]));
      const ragIds = new Set((await listDocs()).map((d) => d.id));
      for (const meta of await listOriginals()) {
        if (!fileOk(meta.id)) continue;
        let enc = meta.enc === true;
        if (!enc && !ragIds.has(meta.id)) {
          try {
            const plain = await loadOriginal(meta.id);
            if (!plain) continue;
            const stored = new Blob([await encryptBytes(await plain.arrayBuffer())], {
              type: "application/octet-stream",
            });
            await saveOriginal(meta.id, stored, { ...meta, enc: true });
            enc = true;
          } catch {
            continue; // no key — leave it local-only rather than upload readable
          }
        }
        if (remoteEnc.get(meta.id) === enc) continue; // present, and in the right form
        const blob = await loadOriginal(meta.id);
        if (!blob) continue;
        const res = await fetch("/api/files/" + encodeURIComponent(meta.id), {
          method: "PUT",
          headers: {
            "content-type": "application/octet-stream",
            "x-file-name": encodeURIComponent(meta.name || meta.id),
            "x-file-type": meta.type || "application/octet-stream",
            "x-file-enc": enc ? "1" : "0",
          },
          body: blob,
        });
        if (res.ok) pushed++;
        else errors.push("file " + (meta.name || meta.id));
      }
    }
  } catch {
    errors.push("file upload");
  }

  // RAG index (vectors ride along — no re-embedding). Chat docs
  // (`chat-<convId>` — indexed project-chat turns, chat-rag.js) take their
  // eligibility from their conversation's project; one whose conversation
  // no longer exists locally is an orphan and stays local.
  if (serverRagAvailable()) {
    onProgress("Uploading document index…");
    try {
      let convProject = new Map();
      try {
        convProject = new Map((await exportEncryptedRecords()).map((r) => [r.id, r.projectId || null]));
      } catch {
        // chat docs simply won't push this pass; files still do
      }
      const docOk = (docId) => {
        const cid = chatConvId(docId);
        if (cid !== null) return convProject.has(cid) && projectOk(convProject.get(cid));
        return fileOk(docId);
      };
      const remoteDocs = (await jsonOrNull(await fetch("/api/rag/docs")))?.docs || [];
      const remoteIds = new Set(remoteDocs.map((d) => d.id));
      for (const doc of await listDocs()) {
        if (!docOk(doc.id)) continue;
        if (remoteIds.has(doc.id)) continue;
        try {
          await pushDocToServer(doc.id);
          pushed++;
        } catch {
          errors.push("index for " + (doc.name || doc.id));
        }
      }
    } catch {
      errors.push("document index");
    }
  }

  return { pushed, errors };
}

export function pushProjectScope(projectId, onProgress = () => {}) {
  return syncToServer(onProgress, projectId);
}

// ---- knob OFF: server → local, then wipe --------------------------------------

/**
 * Bulk server → local pull, then wipe the cloud (the account knob flipping
 * OFF). `checked` counts every cloud item examined, `pulled` only those
 * that actually had to come down — items the browser already held (the
 * normal case for the device that wrote them) are verified present, not
 * re-downloaded. The distinction matters for the status line: "0
 * downloaded" out of 12 checked means "everything was already here", not
 * "nothing was preserved".
 * @param {(msg: string) => void} [onProgress]
 * @returns {Promise<{checked: number, pulled: number, errors: string[], wiped: boolean}>}
 */
export async function syncToClient(onProgress = () => {}) {
  const errors = [];
  let pulled = 0;
  let checked = 0;

  onProgress("Downloading project records…");
  try {
    const remote = (await jsonOrNull(await fetch("/api/projects")))?.projects || [];
    checked += remote.length;
    for (const item of remote) {
      const record = await jsonOrNull(await fetch("/api/projects/" + encodeURIComponent(item.id)));
      if (record && (await importEncryptedProjectRecord(item.id, record))) pulled++;
      else if (!record) errors.push("project " + item.id.slice(0, 8));
    }
    await refreshProjects();
  } catch {
    errors.push("project list");
  }

  onProgress("Downloading conversations…");
  try {
    const remote = (await jsonOrNull(await fetch("/api/convos")))?.conversations || [];
    checked += remote.length;
    for (const item of remote) {
      const record = await jsonOrNull(await fetch("/api/convos/" + encodeURIComponent(item.id)));
      if (record && (await importEncryptedRecord(item.id, record))) pulled++;
      else if (!record) errors.push("conversation " + item.id.slice(0, 8));
      onProgress(`Downloading conversations… ${pulled}`);
    }
  } catch {
    errors.push("conversation list");
  }

  onProgress("Downloading files…");
  try {
    if (await opfsAvailable()) {
      const localIds = new Set((await listOriginals()).map((f) => f.id));
      const remoteFiles = (await jsonOrNull(await fetch("/api/files")))?.files || [];
      checked += remoteFiles.length;
      for (const f of remoteFiles) {
        if (localIds.has(f.id)) continue;
        const res = await fetch("/api/files/" + encodeURIComponent(f.id));
        if (!res.ok) {
          errors.push("file " + (f.name || f.id));
          continue;
        }
        // Bytes move in storage form (encrypted unless it's a RAG doc) —
        // no decrypt/re-encrypt round trip, the enc flag just rides along.
        await saveOriginal(f.id, await res.blob(), {
          name: f.name,
          type: f.type,
          enc: f.enc === true,
        });
        pulled++;
      }
    }
  } catch {
    errors.push("file download");
  }

  onProgress("Downloading document index…");
  try {
    const remoteDocs = (await jsonOrNull(await fetch("/api/rag/docs")))?.docs || [];
    checked += remoteDocs.length;
    for (const d of remoteDocs) {
      if (await hasDoc(d.id)) continue;
      const data = await jsonOrNull(await fetch("/api/rag/docs/" + encodeURIComponent(d.id)));
      if (data && (await importDoc(data))) pulled++;
      else errors.push("index for " + (d.name || d.id));
    }
  } catch {
    errors.push("document index");
  }

  // Only wipe the server once everything above came down clean — a partial
  // pull must never end with the only complete copy deleted.
  if (!errors.length) {
    onProgress("Removing cloud copies…");
    try {
      const res = await fetch("/api/storage", { method: "DELETE" });
      if (!res.ok) errors.push("cloud wipe");
    } catch {
      errors.push("cloud wipe");
    }
  }

  return { checked, pulled, errors, wiped: !errors.length };
}

/**
 * Project knob OFF: the scoped version of the drain above. Pull anything
 * of this project's the browser is missing (a record written from another
 * device, a file uploaded elsewhere), then delete ONLY this project's
 * cloud objects — conversations, files, index entries, and the project
 * record — leaving the rest of the account's cloud storage untouched.
 * Same safety rule: nothing is deleted unless its local copy is confirmed.
 * @param {string} projectId
 * @param {(msg: string) => void} [onProgress]
 * @returns {Promise<{removed: number, errors: string[], drained: boolean}>}
 */
export async function drainProjectScope(projectId, onProgress = () => {}) {
  const errors = [];
  let removed = 0;

  // Reconcile first so "local copy exists" below is trustworthy even for
  // items written from another device.
  onProgress("Checking cloud copies…");
  await pullNewer().catch(() => {});
  await listProjects();
  const project = getProject(projectId);

  // Conversations of this project — each one's record, plus its slice of
  // the RAG index (project chats are indexed, chat-rag.js): the chat doc is
  // pulled down first if this browser is missing it, same confirm-then-
  // delete rule as files below.
  try {
    const mine = (await exportEncryptedRecords()).filter((r) => r.projectId === projectId);
    const remoteIds = new Set(
      ((await jsonOrNull(await fetch("/api/convos")))?.conversations || []).map((c) => c.id),
    );
    const remoteDocIds = new Set(
      ((await jsonOrNull(await fetch("/api/rag/docs")))?.docs || []).map((d) => d.id),
    );
    for (const rec of mine) {
      const docId = chatDocId(rec.id);
      if (remoteDocIds.has(docId)) {
        try {
          if (!(await hasDoc(docId))) {
            const data = await jsonOrNull(await fetch("/api/rag/docs/" + encodeURIComponent(docId)));
            if (data) await importDoc(data);
          }
          const delDoc = await fetch("/api/rag/docs/" + encodeURIComponent(docId), { method: "DELETE" });
          if (delDoc.ok || delDoc.status === 404) removed++;
          else errors.push("chat index " + rec.id.slice(0, 8));
        } catch {
          errors.push("chat index " + rec.id.slice(0, 8));
        }
      }
      if (!remoteIds.has(rec.id)) continue;
      const res = await fetch("/api/convos/" + encodeURIComponent(rec.id), { method: "DELETE" });
      if (res.ok || res.status === 404) removed++;
      else errors.push("conversation " + rec.id.slice(0, 8));
    }
  } catch {
    errors.push("conversations");
  }

  // Files + index entries of this project.
  onProgress("Removing project files from the cloud…");
  for (const f of project?.files || []) {
    try {
      // Confirm a local copy before deleting the cloud one.
      const local = await loadOriginal(f.id);
      if (!local) {
        const res = await fetch("/api/files/" + encodeURIComponent(f.id));
        if (res.ok) {
          await saveOriginal(f.id, await res.blob(), {
            name: f.name,
            type: f.type,
            enc: res.headers.get("x-file-enc") === "1",
          });
        } else if (res.status !== 404) {
          errors.push("file " + f.name);
          continue;
        }
      }
      const del = await fetch("/api/files/" + encodeURIComponent(f.id), { method: "DELETE" });
      if (del.ok || del.status === 404) removed++;
      else errors.push("file " + f.name);
      if (f.indexed) {
        if (!(await hasDoc(f.id))) {
          const data = await jsonOrNull(await fetch("/api/rag/docs/" + encodeURIComponent(f.id)));
          if (data) await importDoc(data);
        }
        const delDoc = await fetch("/api/rag/docs/" + encodeURIComponent(f.id), { method: "DELETE" });
        if (delDoc.ok || delDoc.status === 404) removed++;
        else errors.push("index for " + f.name);
      }
    } catch {
      errors.push("file " + (f.name || f.id));
    }
  }

  // The project record itself — last, so a partial drain stays listed in
  // the cloud and can be retried.
  if (!errors.length) {
    onProgress("Removing the project record…");
    try {
      const res = await fetch("/api/projects/" + encodeURIComponent(projectId), { method: "DELETE" });
      if (res.ok || res.status === 404) removed++;
      else errors.push("project record");
    } catch {
      errors.push("project record");
    }
  }

  return { removed, errors, drained: !errors.length };
}

// ---- steady-state reconciliation ----------------------------------------------

// Cheap "anything newer up there?" pass, run at boot and when the history
// sidebar opens while the knob is on: downloads only records another
// device (or a recovered session) wrote — project records included. This
// is what makes cloud history sync across devices without a heavyweight
// sync loop.
// `checked` counts the cloud's conversation records, `pulled` those
// actually brought down (projects included), `failed` conversations that
// SHOULD have come down but didn't (fetch error, import error). The result
// stays truthy-compatible with the old count-only return via `pulled`.
// Callers that only care whether anything changed keep reading `.pulled`;
// the history sidebar reads the rest to explain an empty pane instead of
// leaving it silent.
/** @returns {Promise<{ran: boolean, checked: number, pulled: number, failed: number}>} */
export async function pullNewer() {
  if (!serverHistoryOn()) return { ran: false, checked: 0, pulled: 0, failed: 0 };
  let pulled = 0;
  let checked = 0;
  let failed = 0;
  try {
    const remote = (await jsonOrNull(await fetch("/api/convos")))?.conversations || [];
    checked = remote.length;
    const localAt = new Map((await exportEncryptedRecords()).map((r) => [r.id, r.updatedAt]));
    for (const item of remote) {
      if ((localAt.get(item.id) || 0) >= item.updatedAt) continue;
      // Per-record fail-soft: one bad record must not silently abort the
      // rest of the restore (it used to — the whole loop died on the first
      // import that threw, leaving the device missing everything after it).
      try {
        const record = await jsonOrNull(await fetch("/api/convos/" + encodeURIComponent(item.id)));
        if (record && (await importEncryptedRecord(item.id, record))) pulled++;
        else failed++;
      } catch {
        failed++;
      }
    }
  } catch {
    // offline or misconfigured — the local list is still authoritative enough
    failed++;
  }
  try {
    const remote = (await jsonOrNull(await fetch("/api/projects")))?.projects || [];
    const localAt = new Map((await exportEncryptedProjectRecords()).map((r) => [r.id, r.updatedAt]));
    let changed = 0;
    for (const item of remote) {
      if ((localAt.get(item.id) || 0) >= item.updatedAt) continue;
      const record = await jsonOrNull(await fetch("/api/projects/" + encodeURIComponent(item.id)));
      if (record && (await importEncryptedProjectRecord(item.id, record))) changed++;
    }
    if (changed) {
      await refreshProjects();
      pulled += changed;
    }
  } catch {
    // same fail-soft rule
  }
  return { ran: true, checked, pulled, failed };
}

// @ts-check
// Research time-target scale (pure functions). The slider position (0-100)
// maps quadratically to 15s–10min so the low end has fine granularity while
// the top still reaches 10 minutes. Mirrored by the server's clamp in
// src/budget.js.

export const BUDGET_MIN_S = 15;
export const BUDGET_MAX_S = 600;

/**
 * @param {number} p slider position, 0-100
 * @returns {number} target seconds, clamped to [BUDGET_MIN_S, BUDGET_MAX_S]
 */
export function posToSeconds(p) {
  const raw = BUDGET_MIN_S + (BUDGET_MAX_S - BUDGET_MIN_S) * Math.pow(p / 100, 2);
  const step = raw < 60 ? 5 : raw < 180 ? 15 : 30; // human-friendly increments
  return Math.min(BUDGET_MAX_S, Math.max(BUDGET_MIN_S, Math.round(raw / step) * step));
}

/**
 * @param {number} s target seconds
 * @returns {number} slider position, 0-100 (inverse of posToSeconds' curve)
 */
export function secondsToPos(s) {
  return Math.round(100 * Math.sqrt((s - BUDGET_MIN_S) / (BUDGET_MAX_S - BUDGET_MIN_S)));
}

/**
 * @param {number} s seconds
 * @returns {string} human label ("45 s", "2 m", "2 m 30 s")
 */
export function fmtBudget(s) {
  if (s < 60) return s + " s";
  const m = Math.floor(s / 60), r = s % 60;
  return r ? m + " m " + r + " s" : m + " m";
}

// Chat turn rendering: user bubbles and assistant turns (activity wrapper +
// streamed content + Raw/Copy/PDF tools + stats footer). Initialize once
// with the chat container and a scroll callback.

import { renderMarkdownInto } from "./markdown.js";
import { downloadReport } from "./report.js";
import { renderMapEmbed, renderStreetViewEmbed, renderStreetViewFrames } from "./activity.js";
import { renderQuiz } from "./quiz.js";

export const EMPTY_TEXT =
  "Ask a research question to get started. I may ask a follow-up to narrow the scope, then search the web and report back with sources.";

let chat;
let scrollDown;
let isBusy = () => false;

/**
 * One-time wiring from app.js.
 * @param {HTMLElement} chatEl  the scrolling chat container
 * @param {(force?: boolean) => void} scrollFn  auto-follow scroll callback
 * @param {{isBusy?: () => boolean}} [opts]  gates the PDF download while streaming
 */
export function initTurns(chatEl, scrollFn, opts = {}) {
  chat = chatEl;
  scrollDown = scrollFn;
  isBusy = opts.isBusy || isBusy;
}

export function clearChatDom() {
  const empty = document.createElement("div");
  empty.className = "empty";
  empty.textContent = EMPTY_TEXT;
  chat.replaceChildren(empty);
}

const clearEmpty = () => { chat.querySelector(".empty")?.remove(); };

// Splits a stored {role:"user", content} entry back into bubble parts.
// Document attachments aren't reconstructed as chips here — their text was
// already embedded inline in the message when it was sent (see stream.js's
// sendMessage), so it simply shows as part of the message text on reload.
// (message-content.js exports a hardened twin used on the send path; this
// local copy only ever sees records this app itself wrote.)
function splitUserContent(content) {
  if (typeof content === "string") return { text: content, imageUrls: [] };
  const text = content
    .filter((p) => p.type === "text")
    .map((p) => p.text)
    .join("\n");
  const imageUrls = content.filter((p) => p.type === "image_url").map((p) => p.image_url.url);
  return { text, imageUrls };
}

// Loads a previously saved conversation (public/js/history-ui.js) into the
// chat DOM: user bubbles and assistant turns with their final text set
// directly, no typing animation or activity steps (those were live-session
// UI, never persisted — only the message content itself is saved). Street
// View elements ARE persisted (stream.js's `embeds` registry, keyed by
// assistant-message index) and re-rendered: the frame strip from its stored
// data URLs, and the interactive panorama rebuilt from its coordinates via
// the Maps JS SDK — a reopened conversation used to lose all imagery
// (reported bug). Frames whose URLs were size-capped away degrade to text.
// Quizzes re-render from their embed record too — resuming an unfinished one
// or showing the finished recap; `opts.quizHooks(embed)` (stream.js) wires
// their answers/completion back into the registry and history.
/**
 * @param {Array<{role: string, content: string|object[]}>} messages  the stored conversation
 * @param {object[]} [embeds]  the record's embeds registry (stream.js EmbedEntry[])
 * @param {{quizHooks?: (embed: object) => object}} [opts]
 */
export function renderStoredConversation(messages, embeds = [], opts = {}) {
  clearChatDom();
  let lastUser = { text: "", imageUrls: [] };
  messages.forEach((m, i) => {
    if (m.role === "user") {
      lastUser = splitUserContent(m.content);
      addUserBubble(lastUser.text, lastUser.imageUrls);
    } else if (m.role === "assistant" && typeof m.content === "string") {
      // question/images are threaded through so the PDF report button
      // works the same as it does on a live turn.
      const turn = addAssistantTurn(lastUser.text, lastUser.imageUrls);
      setText(turn, m.content);
      for (const e of embeds) {
        if (e?.msgIndex !== i) continue;
        if (e.kind === "streetview_embed") {
          renderStreetViewEmbed(turn, { lat: e.lat, lng: e.lng, heading: e.heading, pitch: e.pitch });
        } else if (e.kind === "map_embed") {
          renderMapEmbed(turn, { lat: e.lat, lng: e.lng, zoom: e.zoom, q: e.q || "" });
        } else if (e.kind === "streetview_frames" && e.frames?.some((f) => f?.url)) {
          renderStreetViewFrames(turn, { query: e.query || "", frames: e.frames.filter((f) => f?.url) });
        } else if (e.kind === "quiz" && e.quiz) {
          renderQuiz(turn, e.quiz, opts.quizHooks ? opts.quizHooks(e) : { answers: e.answers || [] });
        }
      }
    }
  });
}

/**
 * Appends a user bubble: message text, image thumbnails, document chips.
 * @param {string} text
 * @param {string[]} [imageUrls]  data URLs of attached images
 * @param {string[]} [docNames]   attached document names (chips)
 */
export function addUserBubble(text, imageUrls = [], docNames = []) {
  clearEmpty();
  const el = document.createElement("div");
  el.className = "msg user";
  el.textContent = text;
  if (imageUrls.length) {
    const imgs = document.createElement("div");
    imgs.className = "imgs";
    for (const url of imageUrls) {
      const img = document.createElement("img");
      img.src = url;
      imgs.appendChild(img);
    }
    el.appendChild(imgs);
  }
  if (docNames.length) {
    const docs = document.createElement("div");
    docs.className = "docs";
    for (const name of docNames) {
      const chip = document.createElement("span");
      chip.className = "doc-chip";
      chip.textContent = "📄 " + name;
      docs.appendChild(chip);
    }
    el.appendChild(docs);
  }
  chat.appendChild(el);
  scrollDown(true); // sending re-attaches auto-follow
}

/**
 * The per-reply handle every renderer works on — created here, mutated by
 * activity.js (steps/stats/embeds), stream.js (text, research log), and
 * report.js (PDF export).
 * @typedef {object} Turn
 * @property {HTMLElement} el            the .msg.assistant container
 * @property {HTMLElement} activityWrap  the <details class="activity"> wrapper
 * @property {HTMLElement} activity      the step-bar container
 * @property {HTMLElement} activityLabel the collapsed-summary label
 * @property {HTMLElement} content       the streamed-answer body
 * @property {HTMLElement} stats         the stats footer
 * @property {string} question           the user prompt (PDF report title)
 * @property {string[]} images           data URLs sent with it (embedded in the PDF)
 * @property {string} model              set from the `done` event
 * @property {Object<string, object>} steps  live generic steps by id
 * @property {string} text               the full answer text so far
 * @property {boolean} rawMode           Raw-button toggle state
 * @property {boolean} errored           setError was called
 * @property {number} searchCount        from the `done` event (collapse label)
 * @property {number} startedAt          anchors researchLog's relative timestamps
 * @property {object[]} researchLog      ordered research events (activity.js ResearchLogEntry)
 * @property {?object} doneStats         the final `done` event payload
 */

/**
 * An assistant turn = collapsible activity panel + streamed content (typing
 * icon until the first token) + Raw/Copy/PDF tools + stats footer.
 * @param {string} [question]  the user's prompt — becomes the PDF report's title
 * @param {string[]} [images]  the data URLs sent with it — embedded in the PDF report
 * @returns {Turn}
 */
export function addAssistantTurn(question = "", images = []) {
  clearEmpty();
  const el = document.createElement("div");
  el.className = "msg assistant";

  // Activity: a <details open> wrapper whose steps show live during
  // research, then collapse to the single summary bar on completion.
  const activityWrap = document.createElement("details");
  activityWrap.className = "activity";
  activityWrap.open = true;
  const activitySummary = document.createElement("summary");
  activitySummary.className = "activity-summary";
  const activityLabel = document.createElement("span");
  activitySummary.appendChild(activityLabel);
  const activity = document.createElement("div");
  activity.className = "activity-steps";
  activityWrap.append(activitySummary, activity);

  const tools = document.createElement("div");
  tools.className = "msg-tools";
  const content = document.createElement("div");
  showTyping(content);
  const stats = document.createElement("div");
  stats.className = "stats";
  el.append(activityWrap, tools, content, stats);
  chat.appendChild(el);
  scrollDown();

  const turn = {
    el, activityWrap, activity, activityLabel, content, stats,
    question, images, model: "",
    steps: {}, text: "", rawMode: false, errored: false, searchCount: 0,
    // Structured, ordered log of every research event this turn saw (steps,
    // searches, service lookups, the final stats) — the source for the
    // "Copy research JSON" debug button (activity.js). startedAt anchors the
    // per-event relative timestamps.
    startedAt: Date.now(),
    researchLog: [],
    doneStats: null,
  };
  tools.append(makeRawButton(turn), makeCopyButton(turn), makePdfButton(turn), makeFeedbackButton(turn));
  return turn;
}

// Feedback mode (the account panel's knob): while the body carries the
// `feedback-mode` class, every assistant turn's tools row shows a Feedback
// button — the button is ALWAYS in the DOM (live turns and reloaded ones
// alike), CSS shows/hides it, so flipping the knob applies to existing
// replies instantly with no re-render.
export function applyFeedbackMode(on) {
  document.body.classList.toggle("feedback-mode", on);
}

// The Feedback button opens a MODAL dialog (same overlay pattern as the
// account panel) — deliberately NOT an inline form: an inline textarea in
// the chat column competes with the ever-present composer, and on a phone
// the typing predictably lands in the composer and goes to the LLM instead
// of the feedback pipeline (observed live 2026-07-09: two feedback attempts
// arrived as chat questions #170/#171 while the feedback table stayed
// empty). A dimmed full-screen dialog is the unambiguous answer: while it's
// open, the composer isn't reachable at all.
function makeFeedbackButton(turn) {
  const btn = document.createElement("button");
  btn.type = "button";
  btn.className = "tool-btn feedback-btn";
  btn.textContent = "Feedback";
  btn.title = "Tell the developers about this reply";
  btn.addEventListener("click", () => openFeedbackDialog(turn));
  return btn;
}

function openFeedbackDialog(turn) {
  document.querySelector(".fb-overlay")?.remove(); // one dialog at a time
  const overlay = document.createElement("div");
  overlay.className = "fb-overlay";
  const card = document.createElement("div");
  card.className = "fb-card";

  const head = document.createElement("div");
  head.className = "fb-card-head";
  const title = document.createElement("strong");
  title.textContent = "Feedback to the developers";
  const close = document.createElement("button");
  close.type = "button";
  close.setAttribute("aria-label", "Close");
  close.textContent = "✕";
  close.addEventListener("click", () => overlay.remove());
  head.append(title, close);

  const about = document.createElement("p");
  about.className = "muted fb-about";
  const q = (turn.question || "").trim();
  about.textContent = q
    ? `About the reply to: “${q.length > 110 ? q.slice(0, 110) + "…" : q}”`
    : "About this reply";

  const ta = document.createElement("textarea");
  ta.rows = 4;
  ta.placeholder = "What was good or bad about this reply? What should change?";

  const note = document.createElement("p");
  note.className = "muted fb-note";
  note.textContent =
    "This goes to the site's developers — not to the AI. It's sent together with the question and reply above; answers show up under Feedback in your account panel.";

  const actions = document.createElement("div");
  actions.className = "fb-actions";
  const send = document.createElement("button");
  send.type = "button";
  send.className = "fb-send";
  send.textContent = "Send feedback";
  const cancel = document.createElement("button");
  cancel.type = "button";
  cancel.textContent = "Cancel";
  cancel.addEventListener("click", () => overlay.remove());
  const status = document.createElement("span");
  status.className = "muted fb-note";
  actions.append(send, cancel, status);

  send.addEventListener("click", async () => {
    const comment = ta.value.trim();
    if (!comment) {
      ta.focus();
      return;
    }
    send.disabled = true;
    send.textContent = "Sending…";
    try {
      const res = await fetch("/api/feedback", {
        method: "POST",
        headers: { "content-type": "application/json" },
        body: JSON.stringify({
          comment,
          question: turn.question || undefined,
          answer_excerpt: turn.text ? turn.text.slice(0, 8000) : undefined,
          model: turn.model || undefined,
          page: location.pathname,
        }),
      });
      if (!res.ok) {
        const data = await res.json().catch(() => null);
        throw new Error(data?.error || "HTTP " + res.status);
      }
      card.replaceChildren();
      const done = document.createElement("p");
      done.className = "fb-done";
      done.textContent = "Feedback sent ✓";
      const hint = document.createElement("p");
      hint.className = "muted";
      hint.textContent =
        "The developers read every submission — replies show up under Feedback in your account panel.";
      card.append(done, hint);
      setTimeout(() => overlay.remove(), 2500);
    } catch (err) {
      send.disabled = false;
      send.textContent = "Send feedback";
      status.textContent = (err?.message || "Could not send feedback.") + " Try again.";
    }
  });

  overlay.addEventListener("click", (e) => {
    if (e.target === overlay) overlay.remove();
  });
  overlay.addEventListener("keydown", (e) => {
    if (e.key === "Escape") overlay.remove();
  });

  card.append(head, about, ta, note, actions);
  overlay.appendChild(card);
  document.body.appendChild(overlay);
  ta.focus();
}

function makeRawButton(turn) {
  const rawBtn = document.createElement("button");
  rawBtn.type = "button";
  rawBtn.className = "tool-btn";
  rawBtn.textContent = "Raw";
  rawBtn.title = "Toggle raw text view";
  rawBtn.addEventListener("click", () => {
    turn.rawMode = !turn.rawMode;
    rawBtn.classList.toggle("active", turn.rawMode);
    renderContent(turn);
  });
  return rawBtn;
}

function makePdfButton(turn) {
  const btn = document.createElement("button");
  btn.type = "button";
  btn.className = "tool-btn";
  btn.textContent = "PDF";
  btn.title = "Download as a PDF report";
  btn.addEventListener("click", async () => {
    // Downloads wait while an answer is streaming: on iOS a download can
    // navigate the page, which aborts the in-flight fetch mid-answer.
    if (isBusy()) {
      btn.textContent = "when done";
      btn.title = "The report downloads after the current research finishes";
      setTimeout(() => { btn.textContent = "PDF"; }, 1500);
      return;
    }
    btn.disabled = true;
    btn.textContent = "…";
    try {
      await downloadReport(turn, { model: turn.model });
      btn.textContent = "PDF ✓";
    } catch {
      btn.textContent = "PDF failed";
    }
    setTimeout(() => { btn.textContent = "PDF"; btn.disabled = false; }, 1500);
  });
  return btn;
}

function makeCopyButton(turn) {
  const copyBtn = document.createElement("button");
  copyBtn.type = "button";
  copyBtn.className = "tool-btn";
  copyBtn.textContent = "Copy";
  copyBtn.title = "Copy raw response to clipboard";
  copyBtn.addEventListener("click", async () => {
    try {
      await navigator.clipboard.writeText(turn.text);
      copyBtn.textContent = "Copied ✓";
    } catch {
      copyBtn.textContent = "Copy failed";
    }
    setTimeout(() => { copyBtn.textContent = "Copy"; }, 1500);
  });
  return copyBtn;
}

// Default view is rendered markdown (sanitized); Raw toggles plain text.
function renderContent(turn) {
  const c = turn.content;
  if (turn.errored) {
    c.className = "content error-text";
    c.textContent = turn.text;
    return;
  }
  if (turn.rawMode) {
    c.className = "content";
    c.textContent = turn.text;
  } else {
    c.className = "content md";
    renderMarkdownInto(c, turn.text);
  }
}

function showTyping(content) {
  content.className = "content typing";
  content.replaceChildren();
  const icon = document.createElement("span");
  icon.className = "typing-icon";
  content.appendChild(icon);
}

/**
 * True while the turn still shows the typing indicator (no text yet).
 * @param {Turn} turn
 * @returns {boolean}
 */
export function isTyping(turn) {
  return turn.content.classList.contains("typing");
}

/**
 * Replaces the turn's full text (the stream re-sets the whole accumulator
 * on every delta) and re-renders it in the current Raw/markdown mode.
 * @param {Turn} turn
 * @param {string} text
 */
export function setText(turn, text) {
  if (isTyping(turn)) {
    turn.content.classList.remove("typing");
    turn.content.replaceChildren();
    turn.el.classList.add("has-text"); // reveal the Raw/Copy tools
  }
  turn.text = text;
  renderContent(turn);
  scrollDown();
}

/**
 * Appends an error message to the turn (kept beneath any partial answer)
 * and switches it to the error style.
 * @param {Turn} turn
 * @param {string} message
 */
export function setError(turn, message) {
  // setError is the single sink for EVERY error a turn can hit — server
  // errors (via stream.js's handleEvent), and the client-only ones that
  // never touch handleEvent (non-OK response, empty stream, network drop,
  // stop-before-any-output). Record each here so the "Copy research JSON"
  // debug export captures them all, with the same relative timestamp
  // convention as the rest of the research log.
  if (Array.isArray(turn.researchLog)) {
    turn.researchLog.push({ t: Date.now() - (turn.startedAt || Date.now()), event: "error", error: String(message) });
  }
  const text = turn.text ? turn.text + "\n\n[" + message + "]" : message;
  turn.errored = true;
  setText(turn, text);
}

// Post-validation replaced the draft: clear the bubble back to the typing
// indicator and wait for the corrected answer to stream.
export function resetForRevision(turn) {
  turn.text = "";
  turn.errored = false;
  turn.el.classList.remove("has-text");
  showTyping(turn.content);
}

// The DRC first-visit umbrella intro's PURE core (public/cure/umbrella.js):
// the phase timeline and the vortex→umbrella geometry. The canvas layer is
// DOM-only and stays live-verified, per the project convention.
import test from "node:test";
import assert from "node:assert/strict";

import {
  T,
  clamp01,
  smooth,
  paramsAt,
  PANELS,
  MAX_TWIST,
  twistOffset,
  scallopFactor,
  canopyZ,
  project,
  FLEET,
  BASE_SPEED,
  clampAnimMult,
} from "../cure/umbrella.js";

test("timeline marks are ordered and phases overlap only as designed", () => {
  assert.ok(T.swirlEnd < T.untwistEnd);
  assert.ok(T.untwistEnd < T.wireEnd);
  assert.ok(T.wireEnd <= T.fillGone);
  assert.ok(T.fillGone <= T.tiltStart);
  assert.ok(T.tiltStart < T.tiltEnd);
  assert.ok(T.tiltEnd < T.fadeStart);
  assert.ok(T.fadeStart < T.end);
});

test("swirl phase: full twist, full color, no wire, top-down camera", () => {
  for (const t of [0, 1500, T.swirlEnd]) {
    const p = paramsAt(t);
    assert.equal(p.twist, 1);
    assert.equal(p.fill, 1);
    assert.equal(p.wire, 0);
    assert.equal(p.cam, 0);
    assert.equal(p.shaft, 0);
    assert.equal(p.fade, 1);
    assert.equal(p.done, false);
  }
  // The size pulse is alive through the whole swirl.
  assert.equal(paramsAt(0).pulse, 1);
});

test("untwist end: arms straight, scallop fully grown, still colored", () => {
  const p = paramsAt(T.untwistEnd);
  assert.equal(p.twist, 0);
  assert.equal(p.scallop, 1);
  assert.equal(p.fill, 1); // color starts draining only mid-wire
  assert.equal(p.cam, 0);
});

test("wire end: contours fully drawn; color fully gone by fillGone", () => {
  assert.equal(paramsAt(T.wireEnd).wire, 1);
  assert.ok(paramsAt(T.wireEnd).fill < 1);
  assert.equal(paramsAt(T.fillGone).fill, 0);
  assert.equal(paramsAt(T.fillGone).pulse, 0);
});

test("tilt: camera sweeps exactly a quarter circle, shaft fades in", () => {
  assert.equal(paramsAt(T.tiltStart).cam, 0);
  const mid = paramsAt((T.tiltStart + T.tiltEnd) / 2);
  assert.ok(mid.cam > 0 && mid.cam < Math.PI / 2);
  assert.ok(mid.shaft > 0);
  const end = paramsAt(T.tiltEnd);
  assert.ok(Math.abs(end.cam - Math.PI / 2) < 1e-9);
  assert.equal(end.shaft, 1);
  assert.equal(end.fade, 1); // fade hasn't started at tilt end
});

test("fade and done", () => {
  assert.equal(paramsAt(T.end).fade, 0);
  assert.equal(paramsAt(T.end).done, true);
  assert.equal(paramsAt(T.end + 1000).done, true);
  assert.equal(paramsAt(T.fadeStart).done, false);
});

test("parameter monotonicity over the whole clock", () => {
  let prev = paramsAt(0);
  for (let t = 50; t <= T.end; t += 50) {
    const p = paramsAt(t);
    assert.ok(p.twist <= prev.twist + 1e-12, `twist rose at ${t}`);
    assert.ok(p.cam >= prev.cam - 1e-12, `cam fell at ${t}`);
    assert.ok(p.wire >= prev.wire - 1e-12, `wire fell at ${t}`);
    assert.ok(p.fill <= prev.fill + 1e-12, `fill rose at ${t}`);
    assert.ok(p.fade <= prev.fade + 1e-12, `fade rose at ${t}`);
    assert.ok(p.spinRate <= prev.spinRate + 1e-12, `spin sped up at ${t}`);
    prev = p;
  }
  // The spin never fully stops — umbrellas keep turning to the end.
  assert.ok(paramsAt(T.end).spinRate > 0.25);
});

test("speed: 2.5× base pace, admin multiplier clamped with 1 as the default", () => {
  assert.equal(BASE_SPEED, 2.5); // 2026-07-12 directive — the slider's center
  // Garbage and non-positives fall back to the default, never to a freeze.
  for (const bad of [undefined, null, "", "fast", NaN, 0, -3]) {
    assert.equal(clampAnimMult(bad), 1, `bad input ${String(bad)}`);
  }
  // Honest values pass through inside the clamp, numeric strings included.
  assert.equal(clampAnimMult(1), 1);
  assert.equal(clampAnimMult(0.5), 0.5);
  assert.equal(clampAnimMult("2"), 2);
  // The clamp matches src/config.js's server-side clamp: [0.25, 4].
  assert.equal(clampAnimMult(0.01), 0.25);
  assert.equal(clampAnimMult(99), 4);
  // Sanity of the wall-clock outcome: at the default multiplier the whole
  // scene now runs in under 6 s of real time.
  assert.ok(T.end / (BASE_SPEED * clampAnimMult(undefined)) < 6000);
});

test("smooth/clamp01 basics", () => {
  assert.equal(clamp01(-3), 0);
  assert.equal(clamp01(7), 1);
  assert.equal(smooth(0), 0);
  assert.equal(smooth(1), 1);
  assert.equal(smooth(0.5), 0.5);
  assert.ok(smooth(0.25) < 0.25); // ease-in
  assert.ok(smooth(0.75) > 0.75); // ease-out
});

test("twistOffset: zero at the center and at zero twist, max at the rim", () => {
  assert.equal(twistOffset(0, 1), 0);
  assert.equal(twistOffset(1, 0), 0);
  assert.equal(twistOffset(1, 1), MAX_TWIST);
  // Sub-linear in r: the curl concentrates toward the rim like the logo.
  assert.ok(twistOffset(0.5, 1) > 0.5 * MAX_TWIST);
  // Out-of-range radius is clamped, not extrapolated.
  assert.equal(twistOffset(2, 1), MAX_TWIST);
});

test("scallopFactor: flat at the ribs, dipping mid-panel, off at scallop 0", () => {
  assert.equal(scallopFactor(0, 1), 1);
  assert.equal(scallopFactor(1, 1), 1);
  assert.ok(scallopFactor(0.5, 1) < 1);
  assert.equal(scallopFactor(0.5, 0), 1);
  // Deeper scallop dips deeper.
  assert.ok(scallopFactor(0.5, 1, 0.2) < scallopFactor(0.5, 1, 0.05));
});

test("canopyZ: apex at the center, rim at zero, monotone dome", () => {
  assert.equal(canopyZ(0, 10), 10);
  assert.equal(canopyZ(1, 10), 0);
  assert.ok(canopyZ(0.5, 10) > canopyZ(0.9, 10));
});

test("project: top view shows the x/y plane, side view shows x/z", () => {
  const p = { x: 3, y: 5, z: 7 };
  const top = project(p, 0);
  assert.equal(top.x, 3);
  assert.equal(top.y, -5); // world y up = screen up (negative)
  const side = project(p, Math.PI / 2);
  assert.equal(side.x, 3);
  assert.ok(Math.abs(side.y - -7) < 1e-9); // world z up = screen up
});

test("the fleet is a real crowd: varied sizes, both spin directions", () => {
  assert.ok(FLEET.length >= 5);
  const sizes = FLEET.map((u) => u.s);
  assert.ok(Math.max(...sizes) / Math.min(...sizes) > 2, "size spread");
  assert.ok(FLEET.some((u) => u.dir === 1) && FLEET.some((u) => u.dir === -1));
  for (const u of FLEET) {
    assert.ok(u.fx > 0 && u.fx < 1 && u.fy > 0 && u.fy < 1);
    assert.ok(u.delay >= 0 && u.delay < T.swirlEnd / 2, "appears during swirl");
  }
  assert.equal(PANELS % 2, 0, "panels must alternate two colors evenly");
});

// The project vault's PURE CORE: secret generation/normalization, the
// Crockford base32 codec, HKDF locator/key derivation, archive
// encrypt/decrypt, the archive-shape check, and the chunked base64 helpers.
// Split out of vault.js (2026-07-11) so the CLIENT-SIDE tier can use the
// crypto without dragging in the DRS storage stack: DRC's drc-core.js builds
// its derivations on these primitives, and vault.js's store/load
// orchestration statically imports history-store.js / opfs.js / projects.js /
// rag.js — modules that are NOT public assets, so having them in the /cure
// module graph 401s for anonymous visitors and kills the whole client tier's
// JS (the drc-rag.js/bash-agent.js breakage class in src/index.js's
// isPublicAsset; found live 2026-07-11 — /cure served a dead graph with the
// static "d5" stamp because vault.js pulled the DRS chain in). This module
// imports NOTHING, is served publicly (allowlisted), and is import-safe in
// Node (vault.test.js exercises it through vault.js's re-exports).
//
// The secret is the whole key hierarchy:
//   secret (160 bits, CSPRNG)
//     ├─ HKDF-SHA-256(info="…vault id v1")  → the storage id (locator)
//     └─ HKDF-SHA-256(info="…vault key v1") → the AES-256-GCM key
// Knowing the secret is both finding the blob and decrypting it; the server
// never sees the secret or the key. The info strings are FROZEN — changing
// them breaks every stored secret.
//
// Secret format (generateVaultSecret): "DR1-" + 8 groups of 4 chars from the
// Crockford base32 alphabet (no I, L, O, U — nothing that misreads as 1 or
// 0), 160 bits from crypto.getRandomValues. Copy-safe by construction:
// case-insensitive, separators ignored, and the classic transcription
// mistakes (O for 0, I/l for 1) are mapped back on input
// (normalizeVaultSecret) — a secret read over the phone or retyped from
// paper still works.

// ---- the secret -----------------------------------------------------------------

// Crockford base32: digits + uppercase letters minus I, L, O, U. 32 symbols
// = 5 bits each; 32 chars = 160 bits.
const ALPHABET = "0123456789ABCDEFGHJKMNPQRSTVWXYZ";
const SECRET_BYTES = 20; // 160 bits
const SECRET_CHARS = (SECRET_BYTES * 8) / 5; // 32
const PREFIX = "DR1"; // marks what the string is; not part of the entropy

/** 160 bits from the CSPRNG, formatted "DR1-XXXX-XXXX-…" (8 groups of 4). */
export function generateVaultSecret() {
  const bytes = crypto.getRandomValues(new Uint8Array(SECRET_BYTES));
  const chars = encodeCrockford(bytes);
  return PREFIX + "-" + (chars.match(/.{4}/g) || []).join("-");
}

/**
 * Forgiving input normalization: uppercase, every separator dropped, the
 * "DR1" prefix stripped when present, and the classic misreads mapped back
 * (O→0, I→1, L→1). Returns the bare 32-char payload for a well-formed
 * secret; anything else comes back as-is-cleaned for vaultSecretValid to
 * reject.
 * @param {string} input
 * @returns {string}
 */
export function normalizeVaultSecret(input) {
  let s = String(input || "").toUpperCase().replace(/[^0-9A-Z]/g, "");
  // Map misreads BEFORE the prefix check, so even a mangled prefix
  // ("DRl-…", "DRi-…") is recognized and stripped.
  s = s.replace(/O/g, "0").replace(/[IL]/g, "1");
  if (s.length === SECRET_CHARS + PREFIX.length && s.startsWith(PREFIX)) s = s.slice(PREFIX.length);
  return s;
}

/** @param {string} input @returns {boolean} */
export function vaultSecretValid(input) {
  const s = normalizeVaultSecret(input);
  return s.length === SECRET_CHARS && [...s].every((c) => ALPHABET.includes(c));
}

/** @param {Uint8Array} bytes @returns {string} bit-exact base32, no padding */
export function encodeCrockford(bytes) {
  let out = "";
  let acc = 0;
  let nbits = 0;
  for (const b of bytes) {
    acc = (acc << 8) | b;
    nbits += 8;
    while (nbits >= 5) {
      out += ALPHABET[(acc >>> (nbits - 5)) & 31];
      nbits -= 5;
    }
  }
  if (nbits > 0) out += ALPHABET[(acc << (5 - nbits)) & 31];
  return out;
}

/** @param {string} s normalized base32 @returns {Uint8Array} */
export function decodeCrockford(s) {
  const out = new Uint8Array(Math.floor((s.length * 5) / 8));
  let acc = 0;
  let nbits = 0;
  let i = 0;
  for (const c of s) {
    const v = ALPHABET.indexOf(c);
    if (v < 0) throw new Error("Invalid character in secret: " + c);
    acc = (acc << 5) | v;
    nbits += 5;
    if (nbits >= 8) {
      out[i++] = (acc >>> (nbits - 8)) & 0xff;
      nbits -= 8;
    }
  }
  return out;
}

// ---- key derivation & the encrypted blob ---------------------------------------

// HKDF-SHA-256 over the secret's raw 160 bits, two independent outputs by
// info string. No salt needed: the IKM is itself uniform CSPRNG output.
/**
 * @param {string} secret
 * @returns {Promise<{id: string, key: CryptoKey}>}
 */
export async function deriveVaultLocator(secret) {
  if (!vaultSecretValid(secret)) throw new Error("That doesn't look like a valid vault secret.");
  const ikm = decodeCrockford(normalizeVaultSecret(secret));
  const master = await crypto.subtle.importKey("raw", ikm, "HKDF", false, ["deriveBits", "deriveKey"]);
  const salt = new Uint8Array(32);
  const idBits = await crypto.subtle.deriveBits(
    { name: "HKDF", hash: "SHA-256", salt, info: new TextEncoder().encode("deepresearch.se vault id v1") },
    master,
    160,
  );
  const key = await crypto.subtle.deriveKey(
    { name: "HKDF", hash: "SHA-256", salt, info: new TextEncoder().encode("deepresearch.se vault key v1") },
    master,
    { name: "AES-GCM", length: 256 },
    false,
    ["encrypt", "decrypt"],
  );
  return { id: encodeCrockford(new Uint8Array(idBits)), key };
}

/**
 * Archive object → one opaque byte blob: 12-byte IV + AES-256-GCM
 * ciphertext (tag included). The stored form and the wire form are the
 * same bytes.
 * @param {object} archive
 * @param {CryptoKey} key
 * @returns {Promise<Uint8Array>}
 */
export async function encryptVaultArchive(archive, key) {
  const iv = crypto.getRandomValues(new Uint8Array(12));
  const plain = new TextEncoder().encode(JSON.stringify(archive));
  const cipher = new Uint8Array(await crypto.subtle.encrypt({ name: "AES-GCM", iv }, key, plain));
  const out = new Uint8Array(12 + cipher.length);
  out.set(iv, 0);
  out.set(cipher, 12);
  return out;
}

/**
 * @param {Uint8Array} bytes
 * @param {CryptoKey} key
 * @returns {Promise<object>} throws on tamper/wrong key (GCM authenticates)
 */
export async function decryptVaultArchive(bytes, key) {
  const plain = await crypto.subtle.decrypt(
    { name: "AES-GCM", iv: bytes.slice(0, 12) },
    key,
    bytes.slice(12),
  );
  return JSON.parse(new TextDecoder().decode(plain));
}

// ---- the archive shape ------------------------------------------------------------

// {v: 1, kind, exportedAt, project: {id, name, files, serverStorage, …},
//  conversations: [{id, data}], files: [{id, name, type, bytes(b64)}],
//  ragDocs: [{docId, name, chunks, vectors}]}
export const ARCHIVE_KIND = "deepresearch-project";

/**
 * Structural check on a decrypted archive before anything is imported.
 * @param {any} a
 * @returns {boolean}
 */
export function validateVaultArchive(a) {
  return !!(
    a &&
    typeof a === "object" &&
    a.v === 1 &&
    a.kind === ARCHIVE_KIND &&
    a.project &&
    typeof a.project === "object" &&
    typeof a.project.id === "string" &&
    a.project.id &&
    typeof a.project.name === "string" &&
    Array.isArray(a.conversations) &&
    a.conversations.every((c) => c && typeof c.id === "string" && c.data && typeof c.data === "object") &&
    Array.isArray(a.files) &&
    a.files.every((f) => f && typeof f.id === "string" && typeof f.bytes === "string") &&
    Array.isArray(a.ragDocs) &&
    a.ragDocs.every((d) => d && typeof d.docId === "string" && Array.isArray(d.chunks) && Array.isArray(d.vectors))
  );
}

// Chunked base64 for file-sized buffers (String.fromCharCode over a whole
// multi-MB array overflows the argument list).
/** @param {Uint8Array} bytes @returns {string} */
export function bytesToB64(bytes) {
  let binary = "";
  for (let i = 0; i < bytes.length; i += 0x8000) {
    binary += String.fromCharCode.apply(null, bytes.subarray(i, i + 0x8000));
  }
  return btoa(binary);
}

/** @param {string} b64 @returns {Uint8Array} */
export function b64ToBytes(b64) {
  const binary = atob(b64);
  const bytes = new Uint8Array(binary.length);
  for (let i = 0; i < binary.length; i++) bytes[i] = binary.charCodeAt(i);
  return bytes;
}

// The project vault: store a whole project — record, conversations,
// original file bytes, and its slice of the RAG index (the dr_rag vector
// "database", vectors included so nothing re-embeds) — as ONE archive,
// encrypted IN THIS BROWSER under a secret only the user holds, and parked
// server-side (PUT /api/vault/:id, src/vault.js). This is how a LOCAL-ONLY
// project (its cloud knob off, or the whole account knob off) gets a
// backup / cross-device transport without giving up its privacy posture:
// the server stores one opaque blob — no names, no text, no index, not
// even which project it is.
//
// The secret is the whole key hierarchy:
//   secret (160 bits, CSPRNG)
//     ├─ HKDF-SHA-256(info="…vault id v1")  → the storage id (locator)
//     └─ HKDF-SHA-256(info="…vault key v1") → the AES-256-GCM key
// Knowing the secret is both finding the blob and decrypting it; the
// server never sees the secret or the key (unlike the history-key model,
// where the server could re-derive the key — here it holds nothing that
// decrypts anything). Losing the secret loses the copy — there is no
// recovery path, by design.
//
// Secret format (generateVaultSecret): "DR1-" + 8 groups of 4 chars from
// the Crockford base32 alphabet (no I, L, O, U — nothing that misreads as
// 1 or 0), 160 bits from crypto.getRandomValues. Copy-safe by
// construction: case-insensitive, separators ignored, and the classic
// transcription mistakes (O for 0, I/l for 1) are mapped back on input
// (normalizeVaultSecret) — a secret read over the phone or retyped from
// paper still works.
//
// Re-storing a project rotates the secret: the new archive goes up under
// the NEW secret's id, the record's remembered vaultId is updated, and the
// old blob is deleted — the previous secret stops working.
//
// The pure core (secret generation/normalization, the Crockford codec, key
// derivation, archive encrypt/decrypt/validation, the base64 helpers) lives
// in vault-core.js — import-safe, dependency-free, Node-tested
// (vault.test.js), and re-exported here so DRS consumers keep one import
// surface. It is a SEPARATE module because DRC's drc-core.js builds on those
// primitives and /cure's module graph must not drag in this file's DRS
// storage imports (history-store/opfs/projects — not public assets; a 401 in
// the graph kills the whole client tier). The store/load orchestration below
// touches IndexedDB/OPFS/fetch and is DRS-only.

import { chatDocId } from "./chat-rag.js";
import {
  decryptBytes,
  encryptBytes,
  loadConversation,
  saveConversation,
  saveProjectRecord,
} from "./history-store.js";
import { listOriginals, loadOriginal, opfsAvailable, saveOriginal } from "./opfs.js";
import {
  conversationsOfProject,
  getProject,
  refreshProjects,
  setProjectVaultId,
} from "./projects.js";
import { exportDoc, hasDoc, importDoc } from "./rag.js";
import {
  ARCHIVE_KIND,
  b64ToBytes,
  bytesToB64,
  decryptVaultArchive,
  deriveVaultLocator,
  encryptVaultArchive,
  generateVaultSecret,
  validateVaultArchive,
  vaultSecretValid,
} from "./vault-core.js";

export {
  ARCHIVE_KIND,
  b64ToBytes,
  bytesToB64,
  decodeCrockford,
  decryptVaultArchive,
  deriveVaultLocator,
  encodeCrockford,
  encryptVaultArchive,
  generateVaultSecret,
  normalizeVaultSecret,
  validateVaultArchive,
  vaultSecretValid,
} from "./vault-core.js";

// ---- store (project → encrypted archive → server) --------------------------------

/**
 * Packs the project and everything in its scope into one archive, encrypts
 * it under a FRESH secret, uploads it, and rotates: the record remembers
 * the new vault id and the previous blob (old secret) is deleted. The
 * plaintext never leaves the browser — file originals resting encrypted
 * under the history key are decrypted locally first so the archive depends
 * on nothing but the secret.
 * @param {string} projectId
 * @param {(msg: string) => void} [onProgress]
 * @returns {Promise<{secret: string, counts: {conversations: number,
 *   files: number, docs: number}, missingFiles: string[]}>}
 */
export async function storeProjectToVault(projectId, onProgress = () => {}) {
  const p = getProject(projectId);
  if (!p) throw new Error("Project not found.");
  const secret = generateVaultSecret();
  const { id: vaultId, key } = await deriveVaultLocator(secret);
  const previousVaultId = p.vaultId || null;

  onProgress("Packing conversations…");
  const conversations = [];
  for (const c of await conversationsOfProject(projectId)) {
    const data = await loadConversation(c.id).catch(() => null);
    if (data) conversations.push({ id: c.id, data });
  }

  onProgress("Packing files…");
  const files = [];
  const missingFiles = [];
  const metaById = new Map((await listOriginals().catch(() => [])).map((m) => [m.id, m]));
  for (const f of p.files || []) {
    const blob = await loadOriginal(f.id);
    if (!blob) {
      missingFiles.push(f.name || f.id);
      continue;
    }
    let bytes = new Uint8Array(await blob.arrayBuffer());
    if (metaById.get(f.id)?.enc) {
      // Encrypted under the history key — decrypt so the archive is
      // self-contained under the vault secret alone. Requires the key;
      // without it the file is reported missing, never packed unreadable.
      try {
        bytes = await decryptBytes(bytes);
      } catch {
        missingFiles.push(f.name || f.id);
        continue;
      }
    }
    files.push({ id: f.id, name: f.name, type: f.type || "application/octet-stream", bytes: bytesToB64(bytes) });
  }

  onProgress("Packing the document index…");
  const ragDocs = [];
  const docIds = [
    ...(p.files || []).filter((f) => f.indexed).map((f) => f.id),
    ...conversations.map((c) => chatDocId(c.id)),
  ];
  for (const docId of docIds) {
    const doc = await exportDoc(docId).catch(() => null);
    if (doc) ragDocs.push(doc);
  }

  const archive = {
    v: 1,
    kind: ARCHIVE_KIND,
    exportedAt: Date.now(),
    project: { ...p, vaultId },
    conversations,
    files,
    ragDocs,
  };

  onProgress("Encrypting…");
  const blob = await encryptVaultArchive(archive, key);

  onProgress("Uploading the encrypted archive…");
  const res = await fetch("/api/vault/" + encodeURIComponent(vaultId), {
    method: "PUT",
    headers: { "content-type": "application/octet-stream" },
    body: blob,
  });
  if (!res.ok) {
    const data = await res.json().catch(() => null);
    throw new Error(data?.error || "Storing the archive failed (" + res.status + ").");
  }

  // Remember the id (inside the encrypted record) so the next store rotates,
  // and retire the old blob — its secret stops working now.
  await setProjectVaultId(projectId, vaultId);
  if (previousVaultId && previousVaultId !== vaultId) {
    fetch("/api/vault/" + encodeURIComponent(previousVaultId), { method: "DELETE" }).catch(() => {});
  }

  return {
    secret,
    counts: { conversations: conversations.length, files: files.length, docs: ragDocs.length },
    missingFiles,
  };
}

// ---- load (secret → decrypt → import) ---------------------------------------------

/**
 * Fetches and decrypts the archive the secret points at, then imports it —
 * last-write-wins by updatedAt (the app-wide rule), gap-filling everything
 * missing. Import honors the archived project's OWN cloud posture: a
 * local-only project loads as local-only (its dual-writes stay off), so
 * loading never silently uploads anything readable.
 * @param {string} secret
 * @param {(msg: string) => void} [onProgress]
 * @returns {Promise<{projectId: string, name: string,
 *   imported: {record: boolean, conversations: number, files: number, docs: number}}>}
 */
export async function loadProjectFromVault(secret, onProgress = () => {}) {
  if (!vaultSecretValid(secret)) {
    throw new Error("That doesn't look like a vault secret (DR1-… with 32 characters).");
  }
  const { id: vaultId, key } = await deriveVaultLocator(secret);

  onProgress("Fetching the encrypted archive…");
  const res = await fetch("/api/vault/" + encodeURIComponent(vaultId));
  if (res.status === 404) throw new Error("No stored project found for that secret.");
  if (!res.ok) {
    const data = await res.json().catch(() => null);
    throw new Error(data?.error || "Fetching the archive failed (" + res.status + ").");
  }

  onProgress("Decrypting…");
  let archive;
  try {
    archive = await decryptVaultArchive(new Uint8Array(await res.arrayBuffer()), key);
  } catch {
    throw new Error("The archive could not be decrypted — it may be corrupted.");
  }
  if (!validateVaultArchive(archive)) throw new Error("The archive contents are not usable.");

  const project = archive.project;
  const cloud = project.serverStorage !== false; // dual-writes follow the project's own knob
  const imported = { record: false, conversations: 0, files: 0, docs: 0 };

  // The record — LWW against any local copy of the same project.
  onProgress("Importing the project…");
  const existing = getProject(project.id);
  if (!existing || (existing.updatedAt || 0) < (project.updatedAt || 0)) {
    const { id, ...data } = project;
    await saveProjectRecord(id, data, { cloud });
    imported.record = true;
  }

  // Conversations — each LWW by updatedAt; project chats store readable
  // ({data}) exactly as saveConversation always does for projectId records.
  const existingConvs = new Map(
    (await conversationsOfProject(project.id).catch(() => [])).map((c) => [c.id, c.updatedAt || 0]),
  );
  for (const c of archive.conversations) {
    if ((existingConvs.get(c.id) || 0) >= (c.data.updatedAt || 0)) continue;
    await saveConversation(c.id, { ...c.data, projectId: project.id }, { cloud });
    imported.conversations++;
  }

  // Files — gap-fill only (an original never changes under the same id).
  // Restored into their normal STORAGE FORM: readable for RAG-indexed docs,
  // encrypted under the history key for everything else — and if that key
  // is unavailable the file is skipped, never stored readable.
  const indexedIds = new Set(archive.ragDocs.map((d) => d.docId));
  if (await opfsAvailable()) {
    const localIds = new Set((await listOriginals()).map((m) => m.id));
    for (const f of archive.files) {
      if (localIds.has(f.id)) continue;
      const plain = b64ToBytes(f.bytes);
      let stored = plain;
      let enc = false;
      if (!indexedIds.has(f.id)) {
        try {
          stored = await encryptBytes(plain.buffer);
          enc = true;
        } catch {
          continue; // no history key — store nothing rather than plaintext
        }
      }
      await saveOriginal(f.id, new Blob([stored], { type: "application/octet-stream" }), {
        name: f.name,
        type: f.type,
        enc,
      });
      imported.files++;
    }
  }

  // The RAG index — gap-fill; vectors ride along, nothing re-embeds.
  onProgress("Importing the document index…");
  for (const d of archive.ragDocs) {
    if (await hasDoc(d.docId).catch(() => false)) continue;
    if (await importDoc(d).catch(() => false)) imported.docs++;
  }

  await refreshProjects();
  return { projectId: project.id, name: project.name, imported };
}

import test from "node:test";
import assert from "node:assert/strict";
import {
  ARCHIVE_KIND,
  b64ToBytes,
  bytesToB64,
  decodeCrockford,
  decryptVaultArchive,
  deriveVaultLocator,
  encodeCrockford,
  encryptVaultArchive,
  generateVaultSecret,
  normalizeVaultSecret,
  validateVaultArchive,
  vaultSecretValid,
} from "./vault.js";

// ---- secret generation ---------------------------------------------------------

test("generated secrets have the documented copy-safe format", () => {
  for (let i = 0; i < 50; i++) {
    const s = generateVaultSecret();
    // DR1- prefix + 8 groups of 4 Crockford chars (no I, L, O, U anywhere).
    assert.match(s, /^DR1(-[0-9ABCDEFGHJKMNPQRSTVWXYZ]{4}){8}$/);
    assert.doesNotMatch(s.slice(4), /[ILOU]/);
    assert.equal(vaultSecretValid(s), true);
  }
});

test("generated secrets are unique (160 bits of CSPRNG entropy)", () => {
  const seen = new Set();
  for (let i = 0; i < 200; i++) seen.add(generateVaultSecret());
  assert.equal(seen.size, 200);
});

test("secret payloads use the full alphabet over many draws", () => {
  // Sanity check against a broken encoder that only ever emits a few
  // symbols: 200 secrets × 32 chars must cover (almost) all 32 symbols.
  const chars = new Set();
  for (let i = 0; i < 200; i++) {
    for (const c of normalizeVaultSecret(generateVaultSecret())) chars.add(c);
  }
  assert.ok(chars.size >= 30, `only ${chars.size} distinct symbols seen`);
});

// ---- normalization (the copy-safety promises) -----------------------------------

test("normalization forgives case, separators, and the classic misreads", () => {
  const secret = generateVaultSecret();
  const bare = normalizeVaultSecret(secret);
  assert.equal(bare.length, 32);
  // lowercase, mixed separators, extra whitespace
  assert.equal(normalizeVaultSecret(secret.toLowerCase()), bare);
  assert.equal(normalizeVaultSecret(secret.replace(/-/g, " ")), bare);
  assert.equal(normalizeVaultSecret("  " + secret.replace(/-/g, "_") + "  "), bare);
  // pasted without the prefix
  assert.equal(normalizeVaultSecret(bare), bare);
  // O read for 0, I/l read for 1
  const mangled = secret.replace(/0/g, "O").replace(/1/g, "i");
  assert.equal(normalizeVaultSecret(mangled), bare);
  assert.equal(vaultSecretValid(mangled), true);
});

test("a bare payload that happens to start with DR1 is not mis-stripped", () => {
  const bare = "DR1" + "A".repeat(29); // exactly 32 chars, no prefix intended
  assert.equal(normalizeVaultSecret(bare), bare);
  assert.equal(vaultSecretValid(bare), true);
});

test("invalid secrets are rejected", () => {
  assert.equal(vaultSecretValid(""), false);
  assert.equal(vaultSecretValid("DR1-TOO-SHORT"), false);
  assert.equal(vaultSecretValid("A".repeat(31)), false);
  assert.equal(vaultSecretValid("A".repeat(33)), false);
  assert.equal(vaultSecretValid("U".repeat(32)), false); // U is not in the alphabet
});

// ---- the Crockford codec ---------------------------------------------------------

test("encode/decode round-trips arbitrary bytes", () => {
  for (const len of [1, 5, 20, 33, 64]) {
    const bytes = crypto.getRandomValues(new Uint8Array(len));
    const decoded = decodeCrockford(encodeCrockford(bytes));
    assert.deepEqual(decoded.subarray(0, len), bytes, `len ${len}`);
  }
});

test("20 bytes encode to exactly 32 chars (bit-exact, no padding)", () => {
  assert.equal(encodeCrockford(new Uint8Array(20)).length, 32);
  assert.equal(encodeCrockford(new Uint8Array(20)), "0".repeat(32));
});

// ---- key/id derivation ------------------------------------------------------------

test("derivation is deterministic and input-format-insensitive", async () => {
  const secret = generateVaultSecret();
  const a = await deriveVaultLocator(secret);
  const b = await deriveVaultLocator(secret.toLowerCase().replace(/-/g, " "));
  assert.equal(a.id, b.id);
  // The id is a 32-char Crockford string — accepted by the server's
  // /^[A-Za-z0-9_-]{16,80}$/ gate and safe in a URL path.
  assert.match(a.id, /^[0-9ABCDEFGHJKMNPQRSTVWXYZ]{32}$/);
});

test("different secrets derive different ids and keys", async () => {
  const a = await deriveVaultLocator(generateVaultSecret());
  const b = await deriveVaultLocator(generateVaultSecret());
  assert.notEqual(a.id, b.id);
});

test("the id is not the secret — deriving rejects malformed input", async () => {
  await assert.rejects(deriveVaultLocator("not-a-secret"), /valid vault secret/);
});

// ---- the encrypted blob -------------------------------------------------------------

test("encrypt/decrypt round-trips an archive; tampering is detected", async () => {
  const { key } = await deriveVaultLocator(generateVaultSecret());
  const archive = { v: 1, kind: ARCHIVE_KIND, project: { id: "p1", name: "Test" }, conversations: [], files: [], ragDocs: [] };
  const blob = await encryptVaultArchive(archive, key);
  assert.ok(blob.length > 12 + 16);
  assert.deepEqual(await decryptVaultArchive(blob, key), archive);

  const tampered = blob.slice();
  tampered[tampered.length - 1] ^= 0x01;
  await assert.rejects(decryptVaultArchive(tampered, key));
});

test("a different secret's key cannot decrypt the blob", async () => {
  const { key } = await deriveVaultLocator(generateVaultSecret());
  const { key: other } = await deriveVaultLocator(generateVaultSecret());
  const blob = await encryptVaultArchive({ hello: "world" }, key);
  await assert.rejects(decryptVaultArchive(blob, other));
});

