// Build the "Project pulse" analytics dataset from this repo's git history.
//
//   node scripts/build-pulse.mjs          # update public/pulse/data.json
//   npm run pulse                          # same, via package.json
//
// It reads `git log --numstat` and emits TWO things:
//
//   commits[] — one lightweight record per commit ({ t, a, r, f }): timestamp,
//     lines added, lines removed, and a feature flag. This is what the /pulse
//     page charts: it buckets these records by HOUR (day view), by DAY (week
//     view) or by WEEK (month view) entirely client-side, so the graphs can
//     show the shape WITHIN a single day / week / month.
//   days[]    — one record per calendar day, carrying that day's aggregates and
//     a short `summary` for the "What happened" panel. Summaries are the ONE
//     human-curated field: the commit-analytics skill rewrites them into prose
//     and marks `curated: true`; a re-run preserves a curated summary when the
//     day's subjects are unchanged.
//
// Line counts are exact from git (generated/vendored artifacts excluded from
// churn — see GENERATED). The feature flag `f` is a keyword HEURISTIC over the
// commit subject (see classify()); it drives the features chart at every
// resolution, so the graph and the totals always agree. Nothing here calls a
// model or the network — it's plain git + text.

import { execFileSync } from "node:child_process";
import { readFileSync, writeFileSync, mkdirSync, existsSync } from "node:fs";
import { fileURLToPath } from "node:url";
import { dirname, join } from "node:path";

const ROOT = join(dirname(fileURLToPath(import.meta.url)), "..");
const OUT = join(ROOT, "public", "pulse", "data.json");
const REPO = "kristerhedfors/deepresearch.se";

// A record separator no commit subject contains, so we can split the stream.
const REC = "\x1e";

// Paths excluded from the LINE-churn metric only (commits still count). These
// are committed GENERATED or VENDORED artifacts — a single `npm run bundle`
// rewrites tens of thousands of lines in source-snapshot.json / source-rag.json
// and would otherwise swamp the lines-per-day chart with non-human change.
// Kept deliberately small and evidence-driven (the two big introspection
// artifacts, vendored libs, minified/lock files, and this dataset itself).
const GENERATED = [
  /^public\/introspect\/source-snapshot\.json$/,
  /^public\/introspect\/source-rag\.json$/,
  /^public\/pulse\/data\.json$/,
  /^public\/vendor\//,
  /\.min\.(js|css)$/,
  /(^|\/)package-lock\.json$/,
  /\.lock$/,
];

/** @param {string} path @returns {boolean} */
function isGenerated(path) {
  return GENERATED.some((re) => re.test(path));
}

/**
 * Read the whole history as: for each commit, a header line
 *   REC<hash>\t<authorDateISO>\t<subject>
 * followed by numstat rows "<added>\t<removed>\t<path>".
 */
function readCommits() {
  const raw = execFileSync(
    "git",
    ["log", "--no-merges", "--numstat", `--format=${REC}%H\t%aI\t%s`],
    { cwd: ROOT, encoding: "utf8", maxBuffer: 64 * 1024 * 1024 },
  );
  const commits = [];
  for (const block of raw.split(REC)) {
    const text = block.trim();
    if (!text) continue;
    const lines = text.split("\n");
    const [hash, dateIso, ...subjectParts] = lines[0].split("\t");
    const subject = subjectParts.join("\t");
    let added = 0;
    let removed = 0;
    for (const line of lines.slice(1)) {
      if (!line.trim()) continue;
      const [a, r, ...pathParts] = line.split("\t");
      // Binary files show "-\t-": count as 0 line changes. Generated/vendored
      // artifacts are excluded from churn (see GENERATED) but the commit
      // itself still counts.
      if (isGenerated(pathParts.join("\t"))) continue;
      added += a === "-" ? 0 : Number(a) || 0;
      removed += r === "-" ? 0 : Number(r) || 0;
    }
    commits.push({ hash, iso: dateIso || "", date: (dateIso || "").slice(0, 10), subject, added, removed });
  }
  return commits;
}

/**
 * Bucket commits into a "feature / fix / refactor / docs / test / chore /
 * other" category by subject keywords. Order is load-bearing: the non-feature
 * categories are matched FIRST so "refactor: add a helper" reads as refactor,
 * not a feature. English + Swedish forms (the repo commits in both).
 * @param {string} subject
 * @returns {"feature"|"fix"|"refactor"|"docs"|"test"|"chore"|"other"}
 */
export function classify(subject) {
  const s = String(subject).toLowerCase().trim();
  if (/^(revert|merge)\b/.test(s)) return "other";
  if (/^(fix|hotfix|bug|bugfix|patch|åtgärda|fixa|rätta)\b/.test(s) || /\bfix(es|ed)?\b/.test(s)) return "fix";
  if (/^(refactor|refaktor|cleanup|clean up|tidy|rename|move|extract|split|inline|dedupe|de-?duplicate|simplify|reorganize|reorganise|omstrukturera|städa|förenkla)\b/.test(s)) return "refactor";
  if (/^(docs?|document|comment|readme|skill|guide|dokument)\b/.test(s) || /\bdocs?\b/.test(s)) return "docs";
  if (/^(test|tests|spec|coverage|testa?)\b/.test(s)) return "test";
  if (/^(chore|bump|deps?|dependency|build|ci|deploy|config|tweak|tighten|polish|style|nit|lint|format|typo|wip|justera|puts)\b/.test(s)) return "chore";
  if (/^(feat|feature|add|adds|added|new|introduce|introduces|implement|implements|support|supports|create|creates|enable|enables|ship|ships|lägg\s*till|lägger\s*till|ny|nytt|inför|stöd)\b/.test(s)) return "feature";
  if (/\b(add|adds|added|new|introduce|implement|support for|feature|lägg\s*till|inför)\b/.test(s)) return "feature";
  return "other";
}

/** Build a default one-line summary for a day from its commit subjects. */
function heuristicSummary(day) {
  const sign = day.added >= day.removed ? "+" : "";
  const churn = `${sign}${day.added}/−${day.removed} lines`;
  const feats = day.subjects.filter((s) => classify(s) === "feature").slice(0, 3);
  const plural = day.commits === 1 ? "" : "s";
  if (feats.length) {
    return `${day.commits} commit${plural}, ${churn}. New: ${feats.join("; ")}.`;
  }
  // No clear feature — name the dominant kind of work instead.
  const counts = {};
  for (const s of day.subjects) counts[classify(s)] = (counts[classify(s)] || 0) + 1;
  const kind = Object.entries(counts).sort((a, b) => b[1] - a[1])[0]?.[0] || "other";
  const label = { fix: "fixes", refactor: "refactoring", docs: "docs", test: "tests", chore: "chores", other: "changes" }[kind] || "changes";
  return `${day.commits} commit${plural}, ${churn}. Mostly ${label}.`;
}

/** Per-day aggregates + subjects (for the summaries panel), sorted ascending. */
function aggregate(commits) {
  /** @type {Record<string, any>} */
  const byDate = {};
  for (const c of commits) {
    if (!c.date) continue;
    const d = (byDate[c.date] ||= { date: c.date, commits: 0, added: 0, removed: 0, features: 0, subjects: [] });
    d.commits += 1;
    d.added += c.added;
    d.removed += c.removed;
    d.features += classify(c.subject) === "feature" ? 1 : 0;
    d.subjects.push(c.subject);
  }
  const days = Object.values(byDate).sort((a, b) => a.date.localeCompare(b.date));
  for (const d of days) {
    d.summary = heuristicSummary(d);
    d.curated = false;
  }
  return days;
}

/**
 * Preserve the ONE human-curated field — the day `summary` — across a rebuild.
 * Aggregates (commits/lines/features) are always recomputed exactly from git; a
 * day keeps its hand-written summary only when it was `curated:true` and its
 * commit subjects are unchanged.
 */
function mergeCuration(freshDays, prevPath) {
  if (!existsSync(prevPath)) return freshDays;
  let prev;
  try {
    prev = JSON.parse(readFileSync(prevPath, "utf8"));
  } catch {
    return freshDays;
  }
  const prevByDate = new Map((prev.days || []).map((d) => [d.date, d]));
  return freshDays.map((d) => {
    const p = prevByDate.get(d.date);
    const sameSubjects = p && JSON.stringify(p.subjects) === JSON.stringify(d.subjects);
    if (p && p.curated && sameSubjects) {
      return { ...d, summary: p.summary, curated: true };
    }
    return d;
  });
}

function main() {
  const raw = readCommits();
  // Per-commit records the page buckets by hour/day/week (oldest → newest).
  const commits = raw
    .filter((c) => c.iso)
    .map((c) => ({ t: c.iso, a: c.added, r: c.removed, f: classify(c.subject) === "feature" ? 1 : 0 }))
    .sort((x, y) => x.t.localeCompare(y.t));
  const days = mergeCuration(aggregate(raw), OUT);
  const totals = commits.reduce(
    (t, c) => ({ commits: t.commits + 1, added: t.added + c.a, removed: t.removed + c.r, features: t.features + c.f }),
    { commits: 0, added: 0, removed: 0, features: 0 },
  );
  const data = {
    generated: new Date().toISOString(),
    repo: REPO,
    range: days.length ? { from: days[0].date, to: days[days.length - 1].date } : null,
    totals,
    commits,
    days,
  };
  mkdirSync(dirname(OUT), { recursive: true });
  writeFileSync(OUT, JSON.stringify(data, null, 2) + "\n");
  const pending = days.filter((d) => !d.curated).length;
  console.log(
    `pulse: ${commits.length} commits over ${days.length} day(s), ` +
      `${totals.features} heuristic features → ${OUT}` +
      (pending ? `\n  ${pending} day(s) need summary review (curated:false)` : ""),
  );
}

// Only run when invoked directly, so classify() can be imported by a test.
if (process.argv[1] && fileURLToPath(import.meta.url) === process.argv[1]) {
  main();
}

#!/usr/bin/env node
// Builds the committed DENSE source-RAG index for introspection mode:
//
//   public/introspect/source-rag.json
//
// One int8-quantized embedding per (file, chunk index) of the committed
// source snapshot, so the DRS enrichment (src/introspect.js) can RETRIEVE the
// source chunks relevant to a question — no brittle intent regex, no VM. The
// index stores vectors ONLY (keyed by {p, ci}); retrieval re-chunks the
// snapshot with the SAME deterministic chunker (introspect-core.js
// chunkSourceText) to resolve text, so vectors and text can never silently
// drift — the freshness check (src/introspect.test.js) enforces the chunk
// counts still line up.
//
// Embeddings must match the model the SERVER embeds the query with at request
// time — Berget intfloat/multilingual-e5-large (1024-d), passage prefix. Two
// ways to get them:
//   1. BERGET_API_KEY (or the older BERGET_API_TOKEN) set → call Berget's
//      embeddings API directly. This is the FAST path: batches are dispatched
//      through a bounded concurrency pool (default 8 in flight) with no
//      inter-batch throttle, so a full ~2100-chunk build finishes in ~20-30 s
//      instead of minutes. Berget takes 8-16 concurrent embedding requests
//      without rate-limiting (measured 2026-07-12).
//   2. else → POST the live site's /api/embed with the break-glass creds
//      (BASIC_AUTH_USER / BASIC_AUTH_PASS) — production holds the key. This is
//      how the index is regenerated from an environment without the raw key.
//      That endpoint is SHARED and throttles under bursts, so this path stays
//      serial with a steady inter-batch delay.
//
// Tunables (env): INTROSPECT_EMBED_CONCURRENCY (in-flight batches; default 8
// direct / 1 via site), INTROSPECT_EMBED_DELAY_MS (inter-batch pause; default
// 0 direct / 700 via site), INTROSPECT_EMBED_BATCH (chunks per request).
//
// Run it whenever bundled source changes (after `npm run bundle`):
//   npm run bundle:rag
// It is NOT part of `npm run bundle` (that stays pure/offline) and NOT run in
// CI (no key) — the freshness check only flags drift; a human re-runs this.

import { existsSync, readFileSync, writeFileSync } from "node:fs";
import { createHash } from "node:crypto";
import { dirname, join } from "node:path";
import { fileURLToPath } from "node:url";
import {
  SOURCE_CHUNK_OVERLAP,
  SOURCE_CHUNK_TARGET,
  chunkSourceText,
  int8ToB64,
  quantizeInt8,
  validateRagIndex,
  validateSnapshot,
} from "../public/js/introspect-core.js";

/** Per-file content hash — the delta key. Same input the chunker sees. */
const fileHash = (text) => createHash("sha256").update(String(text ?? "")).digest("hex").slice(0, 16);

const ROOT = join(dirname(fileURLToPath(import.meta.url)), "..");
const SNAPSHOT = "public/introspect/source-snapshot.json";
const OUT = "public/introspect/source-rag.json";

const EMBED_MODEL = "intfloat/multilingual-e5-large";
const PASSAGE_PREFIX = "passage: ";
// Pre-truncate each chunk before embedding. e5's window is 512 TOKENS, and
// dense code runs ~2.4 chars/token, so a full 1400-char code chunk overflows
// (~540 tokens) and 400s. 1200 is the chunker's ADVANCE (target 1400 − overlap
// 200): capping AT the advance keeps every byte of source covered by at least
// one chunk's vector (no gaps) while trimming only the last ~200 chars of the
// densest chunks. The retrieved TEXT is always the FULL chunk (re-chunked from
// the snapshot), so this only trims a chunk's vector tail, never what the user
// sees. The rare chunk still over 512 tokens at 1200 chars is shrunk further
// on demand (embedResilient), so nothing is ever dropped.
const MAX_CHUNK_CHARS = 1200;

// The raw Berget key, if present (the fast direct path). Accept the current
// env name (BERGET_API_KEY) and the older BERGET_API_TOKEN interchangeably.
const BERGET_KEY = process.env.BERGET_API_KEY || process.env.BERGET_API_TOKEN;

const BATCH = Number(process.env.INTROSPECT_EMBED_BATCH) || 32; // ≤ the server's MAX_EMBED_TEXTS (48)
// Direct Berget serves many concurrent requests, so fan out; the shared
// /api/embed 502s under bursts, so that path stays serial (concurrency 1).
const CONCURRENCY = Number(process.env.INTROSPECT_EMBED_CONCURRENCY) || (BERGET_KEY ? 8 : 1);
// Berget enforces 300 requests/MINUTE; the site /api/embed throttles under
// bursts. A single global min-interval gate on request STARTS keeps us under
// the ceiling no matter how many retries/shrinks a build triggers — this is
// the correctness guarantee against 429s (which, untamed, cost skipped chunks
// and a 4m40s build). 230ms ≈ 260 req/min, a safe margin under Berget's 300.
const MIN_REQUEST_INTERVAL_MS =
  process.env.INTROSPECT_EMBED_INTERVAL_MS !== undefined
    ? Number(process.env.INTROSPECT_EMBED_INTERVAL_MS)
    : BERGET_KEY
      ? 230
      : 700;

const SITE = process.env.INTROSPECT_SITE || "https://deepresearch.se";

/** @param {string[]} texts @returns {Promise<Float32Array[]>} */
async function embedViaBerget(texts) {
  const res = await fetch("https://api.berget.ai/v1/embeddings", {
    method: "POST",
    headers: { authorization: "Bearer " + BERGET_KEY, "content-type": "application/json" },
    body: JSON.stringify({ model: EMBED_MODEL, input: texts.map((t) => PASSAGE_PREFIX + t) }),
  });
  if (!res.ok) throw new Error(`Berget embeddings ${res.status}: ${(await res.text()).slice(0, 200)}`);
  const data = await res.json();
  return (data.data || []).map((d) => Float32Array.from(d.embedding));
}

/** @param {string[]} texts @returns {Promise<Float32Array[]>} */
async function embedViaSite(texts) {
  const u = process.env.BASIC_AUTH_USER;
  const p = process.env.BASIC_AUTH_PASS;
  if (!u || !p) throw new Error("Set BERGET_API_TOKEN, or BASIC_AUTH_USER/BASIC_AUTH_PASS to embed via the live /api/embed.");
  const auth = "Basic " + Buffer.from(`${u}:${p}`).toString("base64");
  const res = await fetch(SITE + "/api/embed", {
    method: "POST",
    headers: { authorization: auth, "content-type": "application/json" },
    // kind:"passage" → the server adds the same passage prefix Berget uses.
    body: JSON.stringify({ texts, kind: "passage" }),
  });
  if (!res.ok) throw new Error(`/api/embed ${res.status}: ${(await res.text()).slice(0, 200)}`);
  const data = await res.json();
  return (data.vectors || []).map((b64) => {
    const buf = Buffer.from(b64, "base64");
    return new Float32Array(buf.buffer, buf.byteOffset, buf.byteLength / 4);
  });
}

const embedBatch = BERGET_KEY ? embedViaBerget : embedViaSite;

async function main() {
  const snapshot = validateSnapshot(JSON.parse(readFileSync(join(ROOT, SNAPSHOT), "utf8")));
  if (!snapshot) throw new Error(`${SNAPSHOT} missing or invalid — run \`npm run bundle\` first.`);

  // Skip test files: they're ~40% of the corpus and low-value for "how does
  // the app work / code examples FROM the project" — the app SOURCE is the
  // target. (They stay in the snapshot, so a user can still name one by path
  // and get its full text; they're just not in the retrieval index.)
  const files = snapshot.files.filter((f) => !/(\.test\.js|(^|\/)tests\/)/.test(f.p));

  // DELTA: reuse vectors for files whose content HASH is unchanged since the
  // last committed index; only NEW or CHANGED files are re-embedded. A full
  // rebuild happens only when there's no prior index, the embed model changed,
  // or the chunker params changed (all vectors would be incomparable). This is
  // what keeps a routine `npm run bundle:rag` after a one-file edit near-free
  // instead of re-embedding all ~2000 chunks.
  const prior = existsSync(join(ROOT, OUT)) ? validateRagIndex(JSON.parse(readFileSync(join(ROOT, OUT), "utf8"))) : null;
  const compatible =
    prior && prior.model === EMBED_MODEL && prior.target === SOURCE_CHUNK_TARGET && prior.overlap === SOURCE_CHUNK_OVERLAP;
  // old file -> ordered [b64,…] by ci (dropping any gaps defensively).
  /** @type {Map<string, string[]>} */
  const priorVecs = new Map();
  if (compatible) {
    for (let i = 0; i < prior.map.length; i++) {
      const { p, ci } = prior.map[i];
      if (!priorVecs.has(p)) priorVecs.set(p, []);
      priorVecs.get(p)[ci] = prior.vectors[i];
    }
  }

  // Decide, per file, reuse vs embed. `plan` holds the FINAL per-file chunk
  // vectors (reused or to-be-filled); `toEmbed` is the flat list of chunks
  // that actually need an embed call.
  const hashes = {};
  /** @type {Array<{ p: string, vecs: (string|null)[], reused: boolean }>} */
  const plan = [];
  /** @type {Array<{ p: string, ci: number, text: string }>} */
  const toEmbed = [];
  let reusedFiles = 0;
  let reusedChunks = 0;
  for (const f of files) {
    const h = fileHash(f.t);
    hashes[f.p] = h;
    const pieces = chunkSourceText(f.t);
    const old = priorVecs.get(f.p);
    const canReuse = compatible && prior.hashes[f.p] === h && old && old.length >= pieces.length && pieces.every((_, ci) => old[ci]);
    if (canReuse) {
      plan.push({ p: f.p, vecs: pieces.map((_, ci) => old[ci]), reused: true });
      reusedFiles++;
      reusedChunks += pieces.length;
    } else {
      const vecs = new Array(pieces.length).fill(null);
      plan.push({ p: f.p, vecs, reused: false });
      pieces.forEach((text, ci) => toEmbed.push({ p: f.p, ci, text: text.slice(0, MAX_CHUNK_CHARS) }));
    }
  }
  const totalChunks = plan.reduce((n, e) => n + e.vecs.length, 0);
  console.log(
    `${files.length} indexable files, ${totalChunks} chunks. ` +
      (compatible
        ? `DELTA: reusing ${reusedFiles} files / ${reusedChunks} chunks; embedding ${toEmbed.length} chunks (${files.length - reusedFiles} changed/new files)`
        : `FULL rebuild (${prior ? "model/chunker changed" : "no prior index"}): embedding ${toEmbed.length} chunks`) +
      ` via ${BERGET_KEY ? "Berget" : SITE + "/api/embed"}` +
      ` (batch ${BATCH}, concurrency ${CONCURRENCY}, ≤${Math.round(60000 / MIN_REQUEST_INTERVAL_MS)} req/min) …`,
  );

  const sleep = (ms) => new Promise((r) => setTimeout(r, ms));

  // Global min-interval gate on request STARTS. Single-threaded JS makes the
  // nextAt read-modify-write atomic across the concurrent workers, so this
  // caps the aggregate request rate — every retry and shrink goes through it,
  // which is what keeps a burst of splits from tripping Berget's 300/min 429.
  let requests = 0;
  let nextAt = 0;
  async function embedGated(texts) {
    const now = Date.now();
    const at = Math.max(now, nextAt);
    nextAt = at + MIN_REQUEST_INTERVAL_MS;
    if (at > now) await sleep(at - now);
    requests++;
    return embedBatch(texts);
  }

  // Error classifiers. A "too long" 400 is PERMANENT — e5's 512-token window,
  // which dense code chunks blow past even at 1200 chars; the only fix is a
  // smaller input. A 429 is rate-limiting — always transient, so we wait and
  // retry, NEVER skip (a skipped chunk is a coverage hole). Everything else
  // (5xx / network) gets a couple of backoff retries.
  const isTooLong = (msg) => /context length|too long|maximum context/i.test(String(msg));
  const isRateLimited = (msg) => /\b429\b|rate.?limit/i.test(String(msg));

  // Embed `items`, returning a vector per item.
  //  - Too-long 400 → shrink EVERY chunk in the batch ×0.8 and retry the batch.
  //    One dense chunk poisons the whole batch, so trimming uniformly resolves
  //    it in ~1 extra request; the alternative (binary-split down to singles)
  //    re-embeds good chunks O(log n) times and, on a dense-file batch, storms
  //    Berget's 300/min limit. Dense chunks cluster in dense files, so the
  //    collateral trim lands mostly on chunks that were code-dense anyway, and
  //    the retrieved TEXT stays full regardless.
  //  - 429 → wait and retry, indefinitely; the gate should prevent it, but if
  //    one slips through we pace down, never drop the chunk.
  //  - Transient 5xx/network → up to 2 backoff retries, then binary split so a
  //    persistently flaky single is isolated and (last resort) skipped.
  /** @param {{text:string,p:string}[]} items @returns {Promise<(Float32Array|null)[]>} */
  async function embedResilient(items) {
    if (!items.length) return [];
    let transientTries = 0;
    for (;;) {
      try {
        const vecs = await embedGated(items.map((c) => c.text));
        if (vecs.length === items.length) return vecs;
        throw new Error(`got ${vecs.length} vectors for ${items.length} texts`);
      } catch (err) {
        const msg = String(/** @type {any} */ (err)?.message || err);
        if (isRateLimited(msg)) {
          await sleep(2000);
          continue; // never counts against the chunk — just pace and retry
        }
        if (isTooLong(msg)) {
          let shrunk = false;
          for (const it of items) {
            if (it.text.length > 400) {
              it.text = it.text.slice(0, Math.floor(it.text.length * 0.8));
              shrunk = true;
            }
          }
          if (shrunk) continue; // retry the (now smaller) batch
          // Already ≤400 chars yet still rejected — fall through to skip/split.
        } else if (transientTries++ < 2) {
          await sleep(1000 * 2 ** (transientTries - 1));
          continue;
        }
        if (items.length > 1) {
          const mid = Math.ceil(items.length / 2);
          const left = await embedResilient(items.slice(0, mid));
          const right = await embedResilient(items.slice(mid));
          return [...left, ...right];
        }
        console.warn(`\n  skipping unembeddable chunk (${items[0].p}): ${msg}`);
        return [null];
      }
    }
  }

  // Embed only the changed/new chunks, writing each result back into its
  // file's plan slot (by p+ci). A skipped (unembeddable) chunk stays null.
  // Each chunk owns a unique (p, ci) slot, so parallel batches never collide —
  // the direct-Berget path fans CONCURRENCY batches out at once; the shared
  // /api/embed path stays serial (CONCURRENCY 1) with a pacing delay.
  const slotOf = new Map(plan.map((e) => [e.p, e]));
  let dims = compatible ? prior.dims : 0;
  let skipped = 0;
  let done = 0;

  // Split into batches up front; a pool of CONCURRENCY workers drains them.
  /** @type {{text:string,p:string,ci:number}[][]} */
  const batches = [];
  for (let i = 0; i < toEmbed.length; i += BATCH) batches.push(toEmbed.slice(i, i + BATCH));

  let next = 0;
  const startedAt = Date.now();
  async function worker() {
    while (next < batches.length) {
      const batch = batches[next++];
      const vecs = await embedResilient(batch);
      for (let j = 0; j < batch.length; j++) {
        const v = vecs[j];
        if (!v || !v.length) {
          skipped++;
          continue;
        }
        dims = v.length;
        slotOf.get(batch[j].p).vecs[batch[j].ci] = int8ToB64(quantizeInt8(v));
        done++;
      }
      process.stdout.write(`\r  embedded ${done}/${toEmbed.length} (${skipped} skipped)`);
    }
  }
  await Promise.all(Array.from({ length: Math.min(CONCURRENCY, batches.length) }, () => worker()));
  if (toEmbed.length)
    process.stdout.write(`\n  embedded in ${((Date.now() - startedAt) / 1000).toFixed(1)}s across ${requests} requests\n`);

  // Assemble the flat arrays in stable file/ci order, dropping any null
  // (skipped) chunk so every map entry has a real vector.
  /** @type {string[]} */
  const vectors = [];
  /** @type {Array<{ p: string, ci: number }>} */
  const map = [];
  for (const e of plan) {
    for (let ci = 0; ci < e.vecs.length; ci++) {
      if (e.vecs[ci]) {
        vectors.push(e.vecs[ci]);
        map.push({ p: e.p, ci });
      }
    }
  }

  const index = { v: 1, model: EMBED_MODEL, dims, target: SOURCE_CHUNK_TARGET, overlap: SOURCE_CHUNK_OVERLAP, hashes, vectors, map };
  const json = JSON.stringify(index);
  writeFileSync(join(ROOT, OUT), json + "\n");
  console.log(
    `Wrote ${OUT}: ${vectors.length} vectors × ${dims}d (int8), ${(json.length / 1e6).toFixed(1)} MB` +
      ` (${reusedChunks} reused, ${toEmbed.length - skipped} embedded, ${skipped} skipped)`,
  );
}

main().catch((err) => {
  console.error("bundle-source-rag failed:", err.message);
  process.exit(1);
});

#!/usr/bin/env node
// The introspection feature's source-snapshot bundler (see the
// **introspection** skill). Walks the git-TRACKED text files of this repo and
// writes them, uncompressed, into ONE deterministic JSON artifact:
//
//   public/introspect/source-snapshot.json
//
// That artifact is committed and deploys with the site like any other static
// asset, which is the whole point: the snapshot a deploy serves is BY
// CONSTRUCTION the exact source that deploy runs (same commit, same upload) —
// no GitHub fetch at runtime, no drift window, no decompression anywhere. Its
// three consumers:
//   1. src/introspect.js        — the DRS server enrichment (env.ASSETS.fetch)
//   2. public/js/stream.js + public/cure/drc.js — the browser fetches it and
//      mounts the tree into the CheerpX sandbox at /src (Tier-1 DataDevice:
//      pre-bundled raw bytes streamed host→guest; no archive to unpack)
//   3. public/js/introspect-core.js — builds the in-context source blocks
//
// Determinism: files sorted by path, no timestamp — regenerating from an
// unchanged tree is byte-identical, so `--check` (run by the unit suite,
// src/introspect.test.js) can enforce freshness: if you change any bundled
// source file, `npm test` fails until you re-run `npm run bundle`.
//
// Output format: one JSON object per line in `files` (git-diff friendly),
// {p: path, s: byte size, t: full text}. sha-256 digest over path+content.

import { execFileSync } from "node:child_process";
import { readFileSync, writeFileSync, mkdirSync, existsSync } from "node:fs";
import { dirname, join } from "node:path";
import { fileURLToPath } from "node:url";
import { createHash } from "node:crypto";

const ROOT = join(dirname(fileURLToPath(import.meta.url)), "..");
const OUT = "public/introspect/source-snapshot.json";

// Text source only — the snapshot is for reading and grep'ing, not serving
// media. Everything here must stay valid UTF-8 (checked below anyway).
const TEXT_EXT = /\.(js|mjs|cjs|d\.ts|css|html|md|json|toml|txt|webmanifest|sh|py|yml|yaml)$/i;

// Not source: vendored libs (upstream code, big), icons/media (binary),
// lockfiles (noise), generated fixtures, and the snapshot itself (self-
// reference would make the artifact impossible to stabilize).
const EXCLUDE = [
  /^public\/vendor\//,
  /^public\/icons\//,
  /^public\/introspect\//,
  /(^|\/)package-lock\.json$/,
  /^tests\/fixtures\//,
];

// Safety valve: a single tracked text file larger than this is almost
// certainly data, not source — skipped (none exist today).
const PER_FILE_MAX = 512 * 1024;

function trackedFiles() {
  const out = execFileSync("git", ["ls-files", "-z"], { cwd: ROOT, encoding: "utf8" });
  return out.split("\0").filter(Boolean);
}

export function buildSnapshotJson() {
  const paths = trackedFiles()
    .filter((p) => TEXT_EXT.test(p))
    .filter((p) => !EXCLUDE.some((re) => re.test(p)))
    .sort();
  const files = [];
  let bytes = 0;
  const hash = createHash("sha256");
  for (const p of paths) {
    const buf = readFileSync(join(ROOT, p));
    if (buf.length > PER_FILE_MAX) continue;
    if (buf.includes(0)) continue; // binary masquerading as text
    const text = buf.toString("utf8");
    if (Buffer.byteLength(text, "utf8") !== buf.length) continue; // invalid UTF-8
    files.push({ p, s: buf.length, t: text });
    bytes += buf.length;
    hash.update(p);
    hash.update("\0");
    hash.update(buf);
  }
  const digest = hash.digest("hex");
  // One file entry per line: keeps the committed artifact diff- and
  // delta-friendly across commits that touch a handful of files.
  const head = JSON.stringify({ v: 1, digest, count: files.length, bytes });
  const lines = files.map((f) => JSON.stringify(f));
  return head.slice(0, -1) + ',"files":[\n' + lines.join(",\n") + "\n]}\n";
}

function main() {
  const check = process.argv.includes("--check");
  const json = buildSnapshotJson();
  const outPath = join(ROOT, OUT);
  if (check) {
    const current = existsSync(outPath) ? readFileSync(outPath, "utf8") : "";
    if (current !== json) {
      console.error(
        `STALE: ${OUT} does not match the working tree.\n` +
          "Re-run `npm run bundle` (node scripts/bundle-source.mjs) and commit the result.",
      );
      process.exit(1);
    }
    console.log(`${OUT} is up to date.`);
    return;
  }
  mkdirSync(dirname(outPath), { recursive: true });
  writeFileSync(outPath, json);
  const parsed = JSON.parse(json);
  console.log(`Wrote ${OUT}: ${parsed.count} files, ${parsed.bytes} bytes, digest ${parsed.digest.slice(0, 12)}…`);
}

main();

// @ts-check
// User accounts (D1-backed), provisioned exclusively by Google sign-in
// (src/google.js). No passwords are stored: Google proves the email, our
// signed session cookie carries the identity afterwards. Roles are
// user | admin — ADMIN_EMAIL is the ONLY path to admin (sole-admin
// policy; the admin API cannot change roles). Disabling a user takes
// effect on their next request.

import { getDb } from "./db.js";

/** @typedef {import('./types.js').Env} Env */

/**
 * One `users` row (see src/db.js SCHEMA — settings_json/google_sub/
 * terms_accepted_at arrive via additive ALTERs, so they may be absent on
 * rows read before a migration ran).
 * @typedef {Object} User
 * @property {number} id
 * @property {string} email normalized (trimmed, lowercased)
 * @property {string | null} name
 * @property {string} role "user" | "admin"
 * @property {string} status "active" | "pending" | "disabled"
 * @property {string | null} [google_sub] Google's stable subject id
 * @property {string | null} [quota_json] per-user quota overrides (JSON)
 * @property {number | null} [terms_accepted_at] ms epoch of terms acceptance
 * @property {string | null} [settings_json] per-user settings (src/settings.js)
 * @property {number} created_at ms epoch
 */

/**
 * Trims, lowercases, and shape-checks an email. Pragmatic check only —
 * Google's email_verified is the real gate.
 * @param {any} email
 * @returns {string | null} the normalized email, or null when malformed
 */
export function normalizeEmail(email) {
  const e = String(email || "").trim().toLowerCase();
  return /^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(e) && e.length <= 254 ? e : null;
}

/**
 * @param {Env} env
 * @param {number} id
 * @returns {Promise<User | null>} null when unknown or no database
 */
export async function getUserById(env, id) {
  const db = await getDb(env);
  if (!db) return null;
  return /** @type {Promise<User | null>} */ (
    db.prepare("SELECT * FROM users WHERE id = ?").bind(id).first()
  );
}

/**
 * @param {Env} env
 * @param {any} email normalized before lookup
 * @returns {Promise<User | null>} null when unknown, malformed, or no database
 */
export async function getUserByEmail(env, email) {
  const db = await getDb(env);
  const e = normalizeEmail(email);
  if (!db || !e) return null;
  return /** @type {Promise<User | null>} */ (
    db.prepare("SELECT * FROM users WHERE email = ?").bind(e).first()
  );
}

/**
 * Every user row (minus settings_json), newest first — the /admin user list.
 * @param {Env} env
 * @returns {Promise<Record<string, unknown>[]>}
 */
export async function listUsers(env) {
  const db = await getDb(env);
  if (!db) return [];
  const { results } = await db
    .prepare("SELECT id, email, name, role, status, quota_json, created_at FROM users ORDER BY created_at DESC")
    .all();
  return results || [];
}

/**
 * Count only — feeds the admin notification badge without pulling every
 * user row (that's what /api/admin/overview's full list is for).
 * @param {Env} env
 * @returns {Promise<number>}
 */
export async function countPendingUsers(env) {
  const db = await getDb(env);
  if (!db) return 0;
  const row = /** @type {{ n: number } | null} */ (
    await db.prepare("SELECT COUNT(*) AS n FROM users WHERE status = 'pending'").first()
  );
  return row?.n || 0;
}

/**
 * First Google sign-in for an email creates the account. `sub` is Google's
 * stable subject id — stored so the account stays pinned to that Google
 * identity even if email ownership ever changes hands. `status` is
 * "pending" when the approval gate is on (src/google.js decides).
 * @param {Env} env
 * @param {{ email: string, name?: string, sub?: string, role?: string, status?: string }} fields
 * @returns {Promise<User>} the freshly inserted row
 */
export async function createUserFromGoogle(env, { email, name, sub, role, status }) {
  const db = await getDb(env);
  if (!db) throw new Error("Database not configured.");
  await db
    .prepare(
      "INSERT INTO users (email, name, role, status, google_sub, created_at) VALUES (?, ?, ?, ?, ?, ?)",
    )
    .bind(
      email,
      name?.slice(0, 120) || null,
      role === "admin" ? "admin" : "user",
      status === "pending" ? "pending" : "active",
      sub || null,
      Date.now(),
    )
    .run();
  // The INSERT above succeeded (or threw), so the row exists.
  return /** @type {Promise<User>} */ (getUserByEmail(env, email));
}

/**
 * Applies an allowlisted patch (role/status/quota_json/name — unknown keys
 * and invalid values are ignored, never written) and returns the fresh row.
 * @param {Env} env
 * @param {number} id
 * @param {any} patch untrusted admin request body
 * @returns {Promise<User | null>} null when the id doesn't exist
 */
export async function updateUser(env, id, patch) {
  const db = await getDb(env);
  if (!db) throw new Error("Database not configured.");
  const sets = [];
  const binds = [];
  if (patch.role === "user" || patch.role === "admin") {
    sets.push("role = ?");
    binds.push(patch.role);
  }
  if (patch.status === "active" || patch.status === "disabled") {
    sets.push("status = ?");
    binds.push(patch.status);
  }
  if ("quota_json" in patch) {
    sets.push("quota_json = ?");
    binds.push(patch.quota_json ? JSON.stringify(patch.quota_json) : null);
  }
  if (typeof patch.name === "string") {
    sets.push("name = ?");
    binds.push(patch.name.slice(0, 120));
  }
  if (!sets.length) return getUserById(env, id);
  binds.push(id);
  await db.prepare(`UPDATE users SET ${sets.join(", ")} WHERE id = ?`).bind(...binds).run();
  return getUserById(env, id);
}

/**
 * One-time acceptance of the terms of use (the /terms page shown on first
 * sign-in). Recorded as a timestamp so it doubles as an audit trail; the
 * IS NULL guard keeps the first timestamp authoritative.
 * @param {Env} env
 * @param {number} id
 * @returns {Promise<void>}
 */
export async function acceptTerms(env, id) {
  const db = await getDb(env);
  if (!db) throw new Error("Database not configured.");
  await db
    .prepare("UPDATE users SET terms_accepted_at = ? WHERE id = ? AND terms_accepted_at IS NULL")
    .bind(Date.now(), id)
    .run();
}

/**
 * Deletes the account and its usage history (usage_events keys user_id as
 * TEXT, hence the String()).
 * @param {Env} env
 * @param {number} id
 * @returns {Promise<void>}
 */
export async function deleteUser(env, id) {
  const db = await getDb(env);
  if (!db) throw new Error("Database not configured.");
  await db.prepare("DELETE FROM users WHERE id = ?").bind(id).run();
  await db.prepare("DELETE FROM usage_events WHERE user_id = ?").bind(String(id)).run();
}

// @ts-check
// /api/admin/* — JSON API behind the admin role (enforced in index.js).
//
// Endpoints:
//   GET    /api/admin/overview       users(+usage) + config + totals + alerts
//   GET    /api/admin/notifications  lightweight alerts + pending users, for
//                                    the in-app message center (account.js)
//   PATCH  /api/admin/users/:id      {status?, name?, quota?} quota={day:{budget_eur,searches},...}|null
//   DELETE /api/admin/users/:id
//   PUT    /api/admin/config         partial config patch -> full config
//   POST   /api/admin/alerts/:id/ack dismiss one operational alert
//   GET    /api/admin/chatlogs       full-visibility chat interaction log,
//   GET    /api/admin/chatlogs/:id   newest first (src/chatlog.js — built for
//                                    the agentic debugging workflow; see the
//                                    chat-logs skill for query params)
//   *      /api/admin/feedback*      the Feedback-mode queue (src/feedback.js)
//   *      /api/admin/security*      the security-risk review board
//                                    (src/security-risks.js — votes/score/
//                                    note/priority over SECURITY-RISKS.md §3;
//                                    ?format=text is the fix loop's input)
//   *      /api/admin/features*      the features/priority review board
//                                    (src/features.js — votes/effort/note/
//                                    priority over FEATURES.md §3;
//                                    ?format=text is the build loop's input)
//   *      /api/admin/panels*        the panel-SELECTION board (src/panels.js —
//                                    the admin panels reshaped purely by ▲/▼
//                                    thumbs; ?format=text is the attention
//                                    loop's input — which surface is in focus)
//   GET    /api/admin/boards         the admin-BOARDS discovery index
//                                    (src/admin-boards.js — one entry per
//                                    Claude-fetchable list + how to fetch its
//                                    text view; ?format=text is the "pop up
//                                    every board" entry point)
//
// Accounts are provisioned by Google sign-in (src/google.js) — there is no
// create-user endpoint; the admin manages status, names, and quotas.

import { acknowledgeAlert, listAlerts } from "./alerts.js";
import { handleChatLogs } from "./chatlog.js";
import { handleAdminFeedback } from "./feedback.js";
import { handleAdminSecurity } from "./security-risks.js";
import { handleAdminFeatures } from "./features.js";
import { handleAdminPanels } from "./panels.js";
import { handleAdminBoards } from "./admin-boards.js";
import { deleteUser, getUserById, listUsers, updateUser } from "./accounts.js";
import { getDb } from "./db.js";
import { jsonResponse } from "./http.js";
import { getConfig, saveConfig } from "./config.js";
import { getUsageAllUsers, getUsageByModel, PERIODS } from "./quota.js";
import { addUserMessage } from "./user-messages.js";

/** @typedef {import('./types.js').Env} Env */
/** @typedef {import('./types.js').Logger} Logger */
/** @typedef {import('./settings.js').Identity} Identity */

/**
 * @param {Request} request
 * @param {Env} env
 * @param {URL} url
 * @param {Logger} log
 * @param {Identity} identity
 * @returns {Promise<Response>}
 */
export async function handleAdminApi(request, env, url, log, identity) {
  const db = await getDb(env);
  if (!db) {
    return jsonResponse(
      {
        error: "Database not configured.",
        setup:
          "Run `npx wrangler d1 create deepresearch-se`, put the database_id into the [[d1_databases]] block in wrangler.toml, and redeploy.",
      },
      503,
    );
  }

  const path = url.pathname.replace(/^\/api\/admin/, "");
  const method = request.method;

  try {
    if (path === "/overview" && method === "GET") {
      return overview(env);
    }
    if (path === "/notifications" && method === "GET") {
      return notifications(env);
    }
    const userPath = path.match(/^\/users\/(\d+)$/);
    if (userPath && method === "PATCH") {
      return patchUser(request, env, log, Number(userPath[1]));
    }
    if (userPath && method === "DELETE") {
      await deleteUser(env, Number(userPath[1]));
      log.info("admin.user_deleted", { user_id: userPath[1] });
      return jsonResponse({ ok: true });
    }
    if (path === "/config" && method === "PUT") {
      const body = await request.json().catch(() => ({}));
      const config = await saveConfig(env, body);
      log.info("admin.config_saved", {});
      return jsonResponse({ config });
    }
    if ((path === "/chatlogs" || /^\/chatlogs\/\d+$/.test(path)) && method === "GET") {
      return handleChatLogs(request, env, url, log);
    }
    // The feedback queue (src/feedback.js): the agent/operator side of
    // Feedback mode — list, read, set status, reply, delete.
    if (path === "/feedback" || path.startsWith("/feedback/")) {
      return handleAdminFeedback(request, env, url, log);
    }
    // The security-risk review board (src/security-risks.js): the register's
    // §3 backlog with admin votes, manual scores, notes, and the explicit
    // priority order the security-fix loop works in.
    if (path === "/security" || path.startsWith("/security/")) {
      return handleAdminSecurity(request, env, url, log);
    }
    // The features/priority review board (src/features.js): FEATURES.md §3's
    // backlog with admin votes, effort estimates, notes, and the explicit
    // priority order the feature-build loop works in — the second loop channel.
    if (path === "/features" || path.startsWith("/features/")) {
      return handleAdminFeatures(request, env, url, log);
    }
    // The panel-selection board (src/panels.js): the admin panels themselves,
    // reshaped purely by the owner's ▲/▼ thumbs — the ATTENTION loop (which
    // admin surface the owner is working on now). ?format=text is its input.
    if (path === "/panels" || path.startsWith("/panels/")) {
      return handleAdminPanels(request, env, url, log);
    }
    // The admin-BOARDS discovery index (src/admin-boards.js): one call that
    // lists every Claude-fetchable board and how to pull its prioritized
    // text view — the "pop up all the boards" entry point.
    if (path === "/boards" && method === "GET") {
      return handleAdminBoards(request, env, url, log);
    }
    const alertPath = path.match(/^\/alerts\/(\d+)\/ack$/);
    if (alertPath && method === "POST") {
      await acknowledgeAlert(env, Number(alertPath[1]));
      log.info("admin.alert_acknowledged", { alert_id: alertPath[1] });
      return jsonResponse({ ok: true });
    }
    return jsonResponse({ error: "Not found." }, 404);
  } catch (err) {
    const message = (/** @type {any} */ (err))?.message;
    log.warn("admin.api_error", { error: message || String(err) });
    return jsonResponse({ error: message || "Admin API error." }, 400);
  }
}

// PATCH /api/admin/users/:id — {status?, name?, quota?}; quota=null clears
// the per-user override.
/**
 * @param {Request} request
 * @param {Env} env
 * @param {Logger} log
 * @param {number} userId
 */
async function patchUser(request, env, log, userId) {
  const body = /** @type {any} */ (await request.json().catch(() => ({})));
  const before = await getUserById(env, userId);
  // Role is deliberately NOT patchable: the only admin is ADMIN_EMAIL,
  // assigned by the Google sign-in flow. Sole-admin-forever policy.
  /** @type {{ status?: string, name?: string, quota_json?: any }} */
  const patch = { status: body.status, name: body.name };
  if ("quota" in body) patch.quota_json = sanitizeQuota(body.quota);
  const user = await updateUser(env, userId, patch);
  log.info("admin.user_updated", { user_id: String(userId) });
  // Message-center notices for the affected user — structured events
  // only (src/user-messages.js), never the actual quota numbers.
  if (before?.status === "pending" && patch.status === "active") {
    await addUserMessage(env, userId, "account_approved");
  }
  if ("quota" in body) {
    await addUserMessage(env, userId, "quota_changed");
  }
  return jsonResponse({ user });
}

/** @param {Env} env */
async function overview(env) {
  const [users, config, usage, byModel, alerts] = await Promise.all([
    listUsers(env),
    getConfig(env),
    getUsageAllUsers(env),
    getUsageByModel(env),
    listAlerts(env),
  ]);
  const usageByUser = Object.fromEntries(usage.map((u) => [u.user_id, u]));
  // Aggregate counts AND costs per window across all identities.
  /** @type {Record<string, number>} */
  const totals = { month_requests: 0 };
  for (const p of PERIODS) {
    for (const k of ["tokens", "searches", "berget_cost", "exa_cost", "ms"]) {
      totals[`${p}_${k}`] = 0;
    }
  }
  for (const u of usage) {
    for (const k of Object.keys(totals)) totals[k] += u[k] || 0;
  }
  return jsonResponse({
    users: users.map((u) => ({ ...u, usage: usageByUser[String(u.id)] || null })),
    admin_usage: usageByUser["admin"] || null,
    by_model: byModel,
    config,
    totals,
    alerts,
  });
}

// Lighter-weight than /overview — just what the in-app message center
// needs (account.js), so opening it doesn't drag in the full usage/config
// payload the dedicated /admin dashboard already has cached.
/** @param {Env} env */
async function notifications(env) {
  const [alerts, users] = await Promise.all([listAlerts(env), listUsers(env)]);
  const pending = users
    .filter((u) => u.status === "pending")
    .map((u) => ({ id: u.id, email: u.email, name: u.name }));
  return jsonResponse({ alerts, pending });
}

// Per-user quota overrides: keep only known numeric fields (budget_eur
// and searches per window); null clears the override entirely.
/**
 * @param {any} quota the PATCH body's quota field
 * @returns {Record<string, { budget_eur?: number, searches?: number }> | null}
 */
function sanitizeQuota(quota) {
  if (quota == null) return null;
  /** @type {Record<string, { budget_eur?: number, searches?: number }>} */
  const out = {};
  for (const p of PERIODS) {
    const q = quota[p];
    if (!q || typeof q !== "object") continue;
    /** @type {{ budget_eur?: number, searches?: number }} */
    const entry = {};
    if (q.budget_eur !== "" && q.budget_eur != null && Number.isFinite(Number(q.budget_eur))) {
      entry.budget_eur = Math.max(0, Number(q.budget_eur));
    }
    if (q.searches !== "" && q.searches != null && Number.isFinite(Number(q.searches))) {
      entry.searches = Math.max(0, Math.round(Number(q.searches)));
    }
    if (Object.keys(entry).length) out[p] = entry;
  }
  return Object.keys(out).length ? out : null;
}

// @ts-check
