// @ts-check
// Operational alerts: surfaces production issues (Berget errors, wallet
// depletion, etc.) in the admin panel and as a notification badge, instead
// of only living in Workers Logs where nobody's looking. Rows are
// upserted by `type` (a small, stable set of buckets) rather than one row
// per occurrence — a recurring issue bumps `count`/`last_seen_at` and
// un-acknowledges itself (worth re-surfacing), rather than flooding the
// table. Fails soft: no DB binding means alerts are silently a no-op, same
// as every other D1-backed feature in this app.

import { getDb } from "./db.js";

/** @typedef {import('./types.js').Env} Env */
/**
 * A classified alert: the stable type key plus what the admin panel shows.
 * @typedef {{ type: string, severity: "critical" | "warning", message: string }} AlertClassification
 */
/**
 * A D1 `alerts` row (one per type — recurrences bump count/last_seen_at).
 * @typedef {{ id: number, type: string, severity: string, message: string, detail?: string | null, count: number, first_seen_at: number, last_seen_at: number, acknowledged_at?: number | null }} AlertRow
 */

// Classifies a caught pipeline error into a stable alert type + severity +
// human message. Keep this list small and meaningful — it's read by admins,
// not a log dump. Unmatched errors fall into a generic bucket rather than
// each becoming their own type.
/**
 * @param {unknown} message the caught error's message
 * @returns {AlertClassification}
 */
export function classifyChatError(message) {
  const msg = String(message || "");
  if (/INSUFFICIENT_WALLET_BALANCE|insufficient_quota/i.test(msg)) {
    return {
      type: "berget_insufficient_balance",
      severity: "critical",
      message: "Berget wallet balance is depleted — every research request will fail until it's topped up at berget.ai.",
    };
  }
  if (/operation was aborted/i.test(msg) || /Berget API error \((?:5\d\d|429|408)\)/i.test(msg)) {
    // The connect-phase family: the 30s connect timeout's abort, or a
    // provider-side HTTP error accepting the request. pipeline.js retries
    // these within maxCompletionAttempts, so this alert means EVERY attempt
    // failed to get a stream open — sustained backend overload, not a blip.
    return {
      type: "chat_connect_failed",
      severity: "warning",
      message: "Berget failed to accept a completion request (connect timeout or provider-side error) even after retrying — backend overload or instability.",
    };
  }
  if (/empty response \d+ times? in a row/i.test(msg)) {
    return {
      type: "chat_empty_completion",
      severity: "warning",
      message: "A model returned an empty response for a research request even after retrying (see model-profiles.js's maxCompletionAttempts).",
    };
  }
  if (/finish_reason.*dropped connection/i.test(msg)) {
    return {
      type: "chat_dropped_stream",
      severity: "warning",
      message: "A model's response stream dropped mid-flight with no error frame (Berget-side connection instability).",
    };
  }
  return {
    type: "chat_stream_failed",
    severity: "warning",
    message: "A research request failed with an unexpected error.",
  };
}

// Suggested remediation per alert type — looked up at READ time (not
// stored on the row) so wording improvements apply retroactively to
// existing rows and don't require a migration. Keyed by the same stable
// types classifyChatError() produces; unmatched/custom types (a future
// raiseAlert() call this file doesn't know about yet) fall back to a
// generic "check Workers Logs" pointer rather than showing nothing.
/** @type {Record<string, string>} */
const REMEDIATIONS = {
  berget_insufficient_balance:
    "Top up the Berget.ai account balance in their dashboard (billing/wallet section) — every research request fails until it's funded again. Confirm it's resolved by sending any chat message; a 402 error means it's still empty.",
  chat_connect_failed:
    "Berget's backend for that model was too loaded to accept a new completion stream (observed live 2026-07-08 on Mistral Medium). The pipeline already retried within maxCompletionAttempts before this fired. Transient provider load usually clears on its own; if one model keeps recurring here, check Berget's status/dashboard and consider steering users off that model until it stabilizes.",
  chat_empty_completion:
    "Usually a transient model quirk — the pipeline already retries once automatically before this fires, so this alert means BOTH attempts came back empty. If one specific model keeps recurring here, consider a model-profiles.js override (e.g. widening the retry) once the pattern is clearly evidenced across several occurrences, not a one-off.",
  chat_dropped_stream:
    "Known Berget-side connection instability for certain models, not fixable from this codebase — see tests/MODEL-EVAL-FINDINGS.md's open issues. No action needed unless the rate climbs sharply; that would suggest a new, different root cause worth investigating via Workers Logs.",
  chat_stream_failed:
    "Check Workers Logs for the chat.stream_failed event (search by request id or timeframe) to see the actual error — this is a catch-all for failures that don't match a more specific known pattern yet.",
};
const DEFAULT_REMEDIATION = "Check Workers Logs for this alert's timeframe to see the underlying error in full.";

/** @param {AlertRow} row */
function withRemediation(row) {
  return { ...row, remediation: REMEDIATIONS[row.type] || DEFAULT_REMEDIATION };
}

/**
 * Upserts one alert by type (recurrence bumps count and re-surfaces it).
 * @param {Env} env
 * @param {string} type
 * @param {string} severity
 * @param {string} message
 * @param {unknown} [detail] truncated to 500 chars on the row
 */
export async function raiseAlert(env, type, severity, message, detail) {
  const db = await getDb(env);
  if (!db) return;
  const now = Date.now();
  await db
    .prepare(
      `INSERT INTO alerts (type, severity, message, detail, count, first_seen_at, last_seen_at, acknowledged_at)
       VALUES (?, ?, ?, ?, 1, ?, ?, NULL)
       ON CONFLICT(type) DO UPDATE SET
         severity = excluded.severity,
         message = excluded.message,
         detail = excluded.detail,
         count = count + 1,
         last_seen_at = excluded.last_seen_at,
         acknowledged_at = NULL`,
    )
    .bind(type, severity, message, detail ? String(detail).slice(0, 500) : null, now, now)
    .run()
    .catch(() => {}); // best-effort — an alerting bug must never break the chat
}

/**
 * All alerts, unacknowledged first, each with its remediation text attached.
 * @param {Env} env
 * @returns {Promise<Array<AlertRow & { remediation: string }>>}
 */
export async function listAlerts(env) {
  const db = await getDb(env);
  if (!db) return [];
  const { results } = await db
    .prepare(`SELECT * FROM alerts ORDER BY (acknowledged_at IS NOT NULL), last_seen_at DESC`)
    .all();
  return /** @type {AlertRow[]} */ (results || []).map(withRemediation);
}

/**
 * Unacknowledged-alert count for the admin notification badge.
 * @param {Env} env
 * @returns {Promise<number>}
 */
export async function countOpenAlerts(env) {
  const db = await getDb(env);
  if (!db) return 0;
  const row = await db.prepare(`SELECT COUNT(*) AS n FROM alerts WHERE acknowledged_at IS NULL`).first();
  return /** @type {number} */ (row?.n) || 0;
}

/**
 * @param {Env} env
 * @param {number} id
 */
export async function acknowledgeAlert(env, id) {
  const db = await getDb(env);
  if (!db) return;
  await db.prepare(`UPDATE alerts SET acknowledged_at = ? WHERE id = ?`).bind(Date.now(), id).run();
}

// Unit tests for operational-alert classification (src/alerts.js): each known
// error pattern maps to its stable type/severity; unmatched to the catch-all.
import { test, describe } from "node:test";
import assert from "node:assert/strict";
import { classifyChatError } from "./alerts.js";

describe("classifyChatError", () => {
  test("Berget wallet depletion classifies as critical", () => {
    const c = classifyChatError('Berget API error (402): {"error":{"code":"INSUFFICIENT_WALLET_BALANCE"}}');
    assert.equal(c.type, "berget_insufficient_balance");
    assert.equal(c.severity, "critical");
  });

  test("insufficient_quota variant also matches", () => {
    const c = classifyChatError('{"error":{"type":"insufficient_quota"}}');
    assert.equal(c.type, "berget_insufficient_balance");
  });

  test("empty-completion exhaustion classifies distinctly, regardless of attempt count", () => {
    const twoAttempts = classifyChatError("Berget returned an empty response 2 times in a row for this model");
    const threeAttempts = classifyChatError("Berget returned an empty response 3 times in a row for this model");
    assert.equal(twoAttempts.type, "chat_empty_completion");
    assert.equal(threeAttempts.type, "chat_empty_completion");
    assert.equal(twoAttempts.severity, "warning");
  });

  test("connect-phase failures (abort or provider-side HTTP error) classify distinctly", () => {
    const abort = classifyChatError("The operation was aborted");
    const http502 = classifyChatError("Berget API error (502): upstream unavailable");
    const http429 = classifyChatError("Berget API error (429): too many requests");
    assert.equal(abort.type, "chat_connect_failed");
    assert.equal(http502.type, "chat_connect_failed");
    assert.equal(http429.type, "chat_connect_failed");
  });

  test("deterministic 4xx Berget errors stay in the generic bucket, and wallet depletion is not shadowed", () => {
    assert.equal(classifyChatError("Berget API error (400): bad request").type, "chat_stream_failed");
    const wallet = classifyChatError('Berget API error (402): {"error":{"code":"INSUFFICIENT_WALLET_BALANCE"}}');
    assert.equal(wallet.type, "berget_insufficient_balance");
  });

  test("dropped stream (missing finish_reason) classifies distinctly", () => {
    const c = classifyChatError("Berget stream ended without a finish_reason (0 chars received) — likely a dropped connection");
    assert.equal(c.type, "chat_dropped_stream");
  });

  test("unrecognized errors fall back to the generic bucket, not a new type per message", () => {
    const c1 = classifyChatError("Some completely novel error message");
    const c2 = classifyChatError("A different novel error message");
    assert.equal(c1.type, "chat_stream_failed");
    assert.equal(c2.type, "chat_stream_failed");
  });

  test("handles non-string/undefined input without throwing", () => {
    assert.doesNotThrow(() => classifyChatError(undefined));
    assert.doesNotThrow(() => classifyChatError(null));
    assert.equal(classifyChatError(undefined).type, "chat_stream_failed");
  });
});

// @ts-check
// The pipeline's answer-streaming internals: streamCompletion (the entry the
// phase runners call — the user's model first, then the ONE-shot failover to
// the reliable JSON model when nothing visible was delivered), streamOnModel
// (a single model's full attempt loop: connect-phase retries, the mid-stream
// idle guard, the finish_reason and empty-completion detections), and
// emitChunked (already-complete text re-emitted through the same delta path).
//
// Seam with pipeline.js: pipeline.js owns the phase FLOW and calls
// streamCompletion/emitChunked with the shared PipelineCtx it built in
// runPipeline; everything between "stream this answer" and the provider wire
// — retries, failover billing/alerts, stall handling — lives here. The
// PipelineCtx/PipelineState typedefs stay in pipeline.js (referenced here
// type-only, so there is no runtime import cycle).

import { classifyChatError, raiseAlert } from "./alerts.js";
import { consumeChatStream } from "./berget.js";
import { chatCompletion, providerName } from "./providers.js";
import { addUsage } from "./quota.js";

/** @typedef {import('./types.js').Conversation} Conversation */
/** @typedef {import('./types.js').ModelProfile} ModelProfile */
/** @typedef {import('./pipeline.js').PipelineCtx} PipelineCtx */

// The answer stream's inter-chunk inactivity bound. A production report
// (2026-07-08, screenshot: "stuck after a few response tokens") exposed the
// remaining unguarded hang: the round-2 fix bounds time-to-FIRST-response
// only, so a Berget stream that goes silent MID-generation (socket open, no
// chunks, no EOF) hung the pipeline forever — and because /api/chat's 15s
// SSE keepalives kept flowing, the CLIENT's stall watchdog (which stamps
// lastByteAt on keepalives too) never fired either: a truly infinite
// spinner on both sides. 60s of inter-chunk silence is far beyond anything
// a healthy stream does (slow models pause single-digit seconds between
// tokens) and cheap insurance. The enrichment describe call has its own
// bound already (src/enrichment.js).
const STREAM_IDLE_TIMEOUT_MS = 60_000;

// Whether a failed connect attempt looks provider-side and transient (worth
// another attempt) rather than deterministic (our request is at fault — a
// 400/401/413 will fail identically on every retry). Exported for tests.
/**
 * @param {number} status HTTP status of the failed connect.
 * @returns {boolean}
 */
export function isTransientConnectStatus(status) {
  return status >= 500 || status === 429 || status === 408;
}

// Tags an error as eligible for the model failover in streamCompletion():
// set only where the failing model never delivered a byte the user still
// has on screen, so a different model's answer can't visibly diverge.
/**
 * @param {string} message
 * @returns {Error & { failover: true }}
 */
function failoverError(message) {
  const e = /** @type {Error & { failover: true }} */ (new Error(message));
  e.failover = true;
  return e;
}

// Streams one chat completion to the client; returns the full text.
//
// The user's chosen model gets its full retry budget first (streamOnModel).
// If it never delivered a visible byte — connect-phase exhaustion, an early
// stall whose fragment was discarded, clean-but-empty completions — the
// answer is retried ONCE on the pipeline's fixed reliable JSON model
// instead of erroring the chat. Observed live (2026-07-08, refs 6b753392 /
// 953b74e3): Berget's Mistral Medium refused to open a synthesis stream for
// 20+ minutes straight while Mistral Small answered the SAME requests'
// triage/gap calls in ~1-2s — retrying the dead model alone can't save
// that, but the reliable default was provably up the whole time. The
// failover is announced as a step so the user knows which model answered,
// its usage is billed to the jsonTotals bucket (that's the model that ran),
// and the provider issue still raises the admin alert an unrecovered
// failure would have — users stop hurting, admins keep seeing it.
/**
 * @param {PipelineCtx} ctx
 * @param {import('./conversation.js').Msg[]} messages
 * @returns {Promise<string>} The full streamed text.
 */
export async function streamCompletion(ctx, messages) {
  try {
    return await streamOnModel(ctx, messages, ctx.model, ctx.profile, ctx.state.totals);
  } catch (/** @type {any} */ err) {
    const fallback = ctx.jsonModel;
    if (!err?.failover || !fallback || fallback === ctx.model) throw err;
    ctx.log.warn("chat.model_failover", { from: ctx.model, to: fallback, error: err?.message || String(err) });
    const alert = classifyChatError(err?.message);
    await raiseAlert(ctx.env, alert.type, alert.severity, alert.message,
      `model: ${ctx.model} — failed over to ${fallback} — ${err?.message}`);
    const name = (/** @type {string} */ id) => String(id).split("/").pop();
    ctx.step("failover", `${name(ctx.model)} isn't responding — switching to ${name(fallback)}…`);
    try {
      const text = await streamOnModel(ctx, messages, fallback, ctx.jsonProfile, ctx.state.jsonTotals);
      ctx.state.failoverModel = fallback;
      ctx.stepDone("failover", `Answered by ${name(fallback)} — ${name(ctx.model)} was unavailable`);
      return text;
    } catch (err2) {
      ctx.stepDone("failover", `${name(fallback)} couldn't answer either`);
      throw err2;
    }
  }
}

// One model's full attempt loop; usage lands in the caller's totals bucket
// (split billing — each bucket priced at its own model's catalog rate).
/**
 * @param {PipelineCtx} ctx
 * @param {import('./conversation.js').Msg[]} messages
 * @param {string} model
 * @param {ModelProfile} profile This model's profile (retry budget).
 * @param {import('./types.js').TokenTotals} totals Billing bucket for this model's usage.
 * @returns {Promise<string>}
 */
async function streamOnModel(ctx, messages, model, profile, totals) {
  const maxAttempts = profile.maxCompletionAttempts;
  for (let attempt = 1; attempt <= maxAttempts; attempt++) {
    // Connect-phase failures get the same retry budget as the stall/empty
    // cases below — they're the CHEAPEST kind to retry (nothing has streamed
    // yet, so a second attempt can't visibly diverge from text already on
    // screen). Observed live (2026-07-08, ref 6b753392): a loaded Mistral
    // Medium sat on the synthesis request past berget.js's 30s connect
    // timeout and the abort ("The operation was aborted") threw straight
    // out of the pipeline as a fatal chat error — a provider blip the user
    // paid for with a dead research run, all searches already done.
    let upstream;
    try {
      // Cast: conversation.js's helpers hand back its looser Msg shape; the
      // messages here are the well-formed arrays the phase builders wrote.
      upstream = await chatCompletion(ctx.env, /** @type {Conversation} */ (messages), { model });
    } catch (/** @type {any} */ err) {
      // fetch() itself rejected: the connect-timeout abort or a network
      // reset. Always transient by nature.
      ctx.log.warn("chat.connect_failed", { model, attempt, error: err?.message || String(err) });
      if (attempt < maxAttempts) continue;
      throw failoverError(err?.message || String(err));
    }
    if (!upstream.ok || !upstream.body) {
      const detail = (await upstream.text().catch(() => "")).slice(0, 300);
      const transient = !upstream.body || isTransientConnectStatus(upstream.status);
      ctx.log.warn("chat.connect_failed", { model, attempt, status: upstream.status, error: detail });
      if (transient && attempt < maxAttempts) continue;
      const message = `${providerName(model)} API error (${upstream.status}): ${detail}`;
      // A deterministic 4xx is OUR request's fault — the fallback model
      // would just fail the same way, so it isn't failover-eligible.
      throw transient ? failoverError(message) : new Error(message);
    }
    let streamed;
    let received = 0;
    try {
      streamed = await consumeChatStream(
        upstream.body,
        (/** @type {string} */ t) => {
          received += t.length;
          ctx.emitDelta(t);
        },
        { idleMs: STREAM_IDLE_TIMEOUT_MS },
      );
    } catch (/** @type {any} */ err) {
      // A hang caught by the idle guard right at the START of the answer
      // (the reported case: a handful of tokens, then silence) is worth one
      // cheap retry — the same transient-blip reasoning as the empty-
      // completion retry below, and the user has barely seen any text. A
      // hang deep into a long answer is NOT retried (regenerated text would
      // visibly diverge from what is already on screen) — it surfaces as an
      // honest error with a (ref …) instead of an infinite spinner. The
      // client is told to discard the few rendered tokens (discard_text —
      // the same event the validation revise path uses) so the retried
      // answer doesn't append after them.
      ctx.log.warn("chat.stream_stalled", { model, attempt, received, error: err?.message || String(err) });
      if (received < 400) {
        if (received) ctx.emit({ status: { type: "discard_text" } });
        if (attempt < maxAttempts) continue;
        // Early stall, fragment already discarded — safe to hand to the
        // failover model, nothing of this model's answer remains on screen.
        throw failoverError(err?.message || String(err));
      }
      throw err;
    }
    const { text, usage, finishReason } = streamed;
    addUsage(totals, usage);
    if (!finishReason) {
      // A round 3 model-eval battery found Berget's connection can drop
      // mid-stream for some models with no error frame at all — the reader
      // just sees a clean EOF, so nothing throws and the caller would
      // otherwise silently return truncated (sometimes empty) text as if it
      // were a complete, successful answer. A normal completion always sets
      // finish_reason on its last chunk (standard OpenAI Chat Completions
      // behavior); its absence is the tell. Throwing here routes this
      // through chat.js's existing error handling — the user sees an honest
      // error instead of a confusing blank/truncated answer, and it's
      // finally visible in logs (chat.stream_failed) instead of invisible.
      throw new Error(`${providerName(model)} stream ended without a finish_reason (${text.length} chars received) — likely a dropped connection`);
    }
    if (text) return text;
    // A round 4 model-eval battery found a distinct failure mode from the
    // one above: a stream that completes CLEANLY (finish_reason set,
    // pipeline reaches "done") but with zero content — no dropped
    // connection, no thrown error, just an empty answer silently delivered
    // to the user. Retrying is cheap insurance against what looks like a
    // transient backend blip rather than a per-query determinism issue
    // (the same query succeeds cleanly on some runs); only after
    // exhausting maxCompletionAttempts (model-profiles.js — 2 by default,
    // higher for models evidenced to need it) do we give up and surface it.
    ctx.log.warn("chat.empty_completion", { model, attempt, maxAttempts });
    if (attempt === maxAttempts) {
      // Nothing was ever shown (the completions were empty) — eligible for
      // the failover model rather than surfacing an error.
      throw failoverError(`${providerName(model)} returned an empty response ${maxAttempts} times in a row for this model`);
    }
  }
  // Unreachable when maxCompletionAttempts >= 1 (model-profiles.js
  // guarantees it): the final attempt always returns or throws above.
  throw failoverError(`${providerName(model)} completion made no attempts`);
}

// Emits already-complete text as delta chunks (clarify questions, revised
// answers) so the client renders it through the same streaming path.
/**
 * @param {PipelineCtx} ctx
 * @param {string} text
 */
export function emitChunked(ctx, text) {
  for (let i = 0; i < text.length; i += 80) {
    ctx.emitDelta(text.slice(i, i + 80));
  }
}

// @ts-check
// Transient answer cache for connection recovery — a buffer, NOT storage.
//
// When a client loses its SSE stream mid-answer (backgrounded phone,
// download-triggered navigation), the pipeline finishes anyway
// (ctx.waitUntil) and parks the final answer here, keyed by the request id
// the client already holds from the x-request-id header. The client polls
// GET /api/chat/answer?id=… and re-renders the completed answer instead of
// asking the user to resend (and re-spend).
//
// Retention is deliberately minimal: the client DELETEs the row the moment
// an answer arrives intact (the normal case — content lives here for
// seconds), and every read/write purges rows older than ANSWER_TTL_MS, so
// even unclaimed answers are gone within minutes. Rows are only readable
// by the user who asked.

import { getDb } from "./db.js";
import { jsonResponse } from "./http.js";

/** @typedef {import('./types.js').Env} Env */
/** @typedef {import('./types.js').Logger} Logger */
/** @typedef {import('./settings.js').Identity} Identity */
/**
 * A D1 `answers` row as the read path selects it.
 * @typedef {{ status: string, ts: number, text?: string | null, stats_json?: string | null }} AnswerRow
 */

export const ANSWER_TTL_MS = 15 * 60 * 1000;

// How long a `running` row may go without a heartbeat before the poller
// treats the run as DEAD rather than merely slow. chat.js heartbeats the
// row every 15s for as long as the isolate is alive (even after the client
// disconnects); if the runtime kills the isolate for any reason (rare on
// the Workers Paid plan's 5-min CPU ceiling, but still possible — eviction,
// a waitUntil outliving its budget, a crash), the heartbeat stops and `ts`
// freezes. Past this window a poller can stop spinning on a "recovering…"
// step that would otherwise wait out the full budget+120s deadline for an
// answer that will never come. 50s = ~3 missed beats.
export const RUNNING_STALE_MS = 50 * 1000;

// Pure projection of a stored answer row into the GET response shape, given
// the current time. Split out so the running/lost/done decision is
// unit-tested without D1. Returns null for a missing row (404 upstream).
/**
 * @param {AnswerRow | null | undefined} row
 * @param {number} now
 * @param {number} [staleMs]
 * @returns {{ status: "running" | "lost" } | { status: "done", text: string, stats: any } | null}
 */
export function projectAnswer(row, now, staleMs = RUNNING_STALE_MS) {
  if (!row) return null;
  if (row.status !== "done") {
    // A `running` row whose heartbeat has gone stale means the server-side
    // run died (killed isolate / expired waitUntil) — tell the client so it
    // stops waiting instead of polling to the deadline.
    return now - Number(row.ts || 0) > staleMs ? { status: "lost" } : { status: "running" };
  }
  let stats = null;
  try {
    stats = row.stats_json ? JSON.parse(row.stats_json) : null;
  } catch {
    stats = null;
  }
  return { status: "done", text: row.text || "", stats };
}

// Called at stream start (metadata only — no content yet): gives the
// recovery poller something to distinguish "still researching" from
// "nothing will ever come".
/**
 * @param {Env} env
 * @param {Logger} log
 * @param {string} requestId
 * @param {number | string} userId
 */
export async function markAnswerRunning(env, log, requestId, userId) {
  try {
    const db = await getDb(env);
    if (!db) return;
    await purgeExpired(db);
    await db
      .prepare("INSERT OR REPLACE INTO answers (request_id, user_id, ts, status) VALUES (?, ?, ?, 'running')")
      .bind(requestId, String(userId), Date.now())
      .run();
  } catch (err) {
    log.warn("answers.mark_failed", { error: (/** @type {any} */ (err))?.message || String(err) });
  }
}

// Called periodically by chat.js while the pipeline runs (independent of
// client presence): refreshes `ts` so a poller can tell a still-alive run
// from one the runtime killed (see RUNNING_STALE_MS). Guarded to `running`
// rows so it can never resurrect or disturb a completed answer.
/**
 * @param {Env} env
 * @param {Logger} log
 * @param {string} requestId
 * @param {number | string} userId
 */
export async function heartbeatAnswer(env, log, requestId, userId) {
  try {
    const db = await getDb(env);
    if (!db) return;
    await db
      .prepare("UPDATE answers SET ts = ? WHERE request_id = ? AND user_id = ? AND status = 'running'")
      .bind(Date.now(), requestId, String(userId))
      .run();
  } catch (err) {
    log.warn("answers.heartbeat_failed", { error: (/** @type {any} */ (err))?.message || String(err) });
  }
}

// Called when the pipeline finishes: park the final answer + stats. The
// text overwrites the running marker; an empty text means the pipeline
// produced nothing (the poller gives up rather than rendering a blank).
/**
 * @param {Env} env
 * @param {Logger} log
 * @param {string} requestId
 * @param {number | string} userId
 * @param {string} text
 * @param {unknown} stats the done-event stats footer, stored as JSON
 */
export async function saveAnswer(env, log, requestId, userId, text, stats) {
  try {
    const db = await getDb(env);
    if (!db) return;
    await db
      .prepare(
        "INSERT OR REPLACE INTO answers (request_id, user_id, ts, status, text, stats_json) VALUES (?, ?, ?, 'done', ?, ?)",
      )
      .bind(requestId, String(userId), Date.now(), text, JSON.stringify(stats))
      .run();
  } catch (err) {
    log.warn("answers.save_failed", { error: (/** @type {any} */ (err))?.message || String(err) });
  }
}

// GET /api/chat/answer?id=… — {status:"running"} | {status:"done",text,stats} | 404.
/**
 * @param {Env} env
 * @param {URL} url
 * @param {Identity} identity
 * @returns {Promise<Response>}
 */
export async function handleAnswerGet(env, url, identity) {
  const db = await getDb(env);
  const id = url.searchParams.get("id") || "";
  if (!db || !id) return jsonResponse({ error: "Not found." }, 404);
  await purgeExpired(db);
  const row = await db
    .prepare("SELECT status, ts, text, stats_json FROM answers WHERE request_id = ? AND user_id = ?")
    .bind(id, String(identity.id))
    .first();
  const projected = projectAnswer(/** @type {AnswerRow | null} */ (row), Date.now());
  if (!projected) return jsonResponse({ error: "Not found." }, 404);
  return jsonResponse(projected);
}

// DELETE /api/chat/answer?id=… — the client acks a fully received answer so
// its content is purged immediately (rather than waiting out the TTL).
/**
 * @param {Env} env
 * @param {URL} url
 * @param {Identity} identity
 * @returns {Promise<Response>}
 */
export async function handleAnswerAck(env, url, identity) {
  const db = await getDb(env);
  const id = url.searchParams.get("id") || "";
  if (db && id) {
    await db
      .prepare("DELETE FROM answers WHERE request_id = ? AND user_id = ?")
      .bind(id, String(identity.id))
      .run();
  }
  return new Response(null, { status: 204 });
}

/** @param {D1Database} db */
async function purgeExpired(db) {
  await db.prepare("DELETE FROM answers WHERE ts < ?").bind(Date.now() - ANSWER_TTL_MS).run();
}

// Unit tests for the answer-recovery cache's pure projection (src/answers.js).
import { test, describe } from "node:test";
import assert from "node:assert/strict";
import { projectAnswer, RUNNING_STALE_MS } from "./answers.js";

// The D1 read/write paths are verified live; the running/lost/done decision
// is pure and is what stops the client spinning on a dead run, so it's tested.
describe("projectAnswer", () => {
  test("missing row → null (404 upstream)", () => {
    assert.equal(projectAnswer(null, 1000), null);
    assert.equal(projectAnswer(undefined, 1000), null);
  });

  test("running with a fresh heartbeat → running", () => {
    const now = 1_000_000;
    assert.deepEqual(projectAnswer({ status: "running", ts: now - 1000 }, now), { status: "running" });
    assert.deepEqual(projectAnswer({ status: "running", ts: now - (RUNNING_STALE_MS - 1) }, now), { status: "running" });
  });

  test("running with a stale heartbeat → lost (server run died)", () => {
    const now = 1_000_000;
    assert.deepEqual(projectAnswer({ status: "running", ts: now - (RUNNING_STALE_MS + 1) }, now), { status: "lost" });
  });

  test("done returns the text and parsed stats", () => {
    const out = projectAnswer(
      { status: "done", ts: 5, text: "the answer", stats_json: JSON.stringify({ model: "m", rounds: 2 }) },
      10,
    );
    assert.equal(out.status, "done");
    assert.equal(out.text, "the answer");
    assert.deepEqual(out.stats, { model: "m", rounds: 2 });
  });

  test("done with no/blank text still projects done (client treats empty as failed)", () => {
    assert.deepEqual(projectAnswer({ status: "done", ts: 5, text: "", stats_json: null }, 10), {
      status: "done",
      text: "",
      stats: null,
    });
  });

  test("done with malformed stats_json degrades stats to null, keeps the text", () => {
    const out = projectAnswer({ status: "done", ts: 5, text: "hi", stats_json: "{bad" }, 10);
    assert.equal(out.text, "hi");
    assert.equal(out.stats, null);
  });

  test("a done row is never treated as lost regardless of age", () => {
    const now = 10_000_000;
    const out = projectAnswer({ status: "done", ts: 0, text: "old but done", stats_json: null }, now);
    assert.equal(out.status, "done");
  });
});

// @ts-check
// Anthropic (Claude) provider client — the second LLM provider alongside
// Berget (src/berget.js). Raw fetch against the Anthropic Messages API —
// deliberately no SDK: the Worker has no build step and no runtime deps
// (CLAUDE.md invariant 5), and the only surface needed is streaming chat
// plus a rarely-used JSON completion.
//
// The load-bearing trick is the STREAM ADAPTER (`openAiStreamFromAnthropic`):
// it re-emits Anthropic's SSE event vocabulary (message_start /
// content_block_delta / message_delta / message_stop) as OpenAI-style SSE
// (`choices[0].delta.content`, `finish_reason`, a usage chunk, `[DONE]`), so
// the pipeline's shared consumer (berget.js `consumeChatStream`), its
// idle/total-budget guards, the finish_reason dropped-connection check, the
// empty-completion retry, and the model failover in pipeline.js all work
// UNCHANGED on Claude streams. New providers should follow this pattern:
// adapt at the wire, don't fork the pipeline.
//
// Feature-gated on the ANTHROPIC_API_KEY secret (a dashboard secret, same
// convention as BERGET_API_TOKEN — never in the repo): absent, the models
// don't appear in the catalog and nothing routes here (src/providers.js).

import { eurPerTokenFromUsd, formatPricing, parseLooseJson } from "./berget.js";

// ANTHROPIC_URL override exists solely so tests can point at a mock (the
// same convention as BERGET_URL); production always uses the default.
/** @param {import('./types.js').Env} env */
const apiBase = (env) => String(env.ANTHROPIC_URL || "https://api.anthropic.com");
/** @param {import('./types.js').Env} env */
const messagesUrl = (env) => apiBase(env) + "/v1/messages";

// Same timeout discipline as berget.js — an unbounded fetch to an LLM
// backend has bitten this project before (berget.js round-2 note): bound
// the connect phase into a normal, catchable error.
const STREAM_CONNECT_TIMEOUT_MS = 30_000;
const JSON_CALL_TIMEOUT_MS = 45_000;

// Matches berget.js's chatCompletion max_tokens — the synthesis answer cap.
const MAX_TOKENS = 4096;

// Anthropic prices are USD per 1M tokens; the quota system accounts in EUR
// — converted at the fixed shared rate documented in berget.js
// (USD_TO_EUR / eurPerTokenFromUsd, shared with src/openai.js).

// Static catalog — Anthropic's /v1/models carries no pricing, and the three
// offered models are a deliberate product choice (opus/sonnet/haiku), so a
// live fetch would add a failure mode without adding information. Prices
// are the standard (non-introductory) USD per-1M rates as of 2026-07.
// All three models accept image input (vision) and stream.
const MODELS = [
  { id: "claude-opus-4-8", name: "Claude Opus 4.8", usd_in: 5, usd_out: 25 },
  { id: "claude-sonnet-5", name: "Claude Sonnet 5", usd_in: 3, usd_out: 15 },
  { id: "claude-haiku-4-5", name: "Claude Haiku 4.5", usd_in: 1, usd_out: 5 },
];

// Anthropic model ids are a distinct namespace (claude-*); Berget ids are
// vendor/model paths (mistralai/…). The prefix is the routing key
// src/providers.js dispatches on.
/** @param {unknown} id */
export function isAnthropicModel(id) {
  return typeof id === "string" && id.startsWith("claude-");
}

/** @param {import('./types.js').Env} env */
export function anthropicConfigured(env) {
  return !!env.ANTHROPIC_API_KEY;
}

// Catalog entries in the exact shape berget.js's listModels produces
// (ModelCatalogEntry), so validation, the UI dropdown, and quota pricing
// consume them with no special-casing. Empty when the key isn't configured
// — the feature is invisible, same as Shodan/Maps without their secrets.
/**
 * @param {import('./types.js').Env} env
 * @returns {import('./types.js').ModelCatalogEntry[]}
 */
export function anthropicModels(env) {
  if (!anthropicConfigured(env)) return [];
  return MODELS.map((m) => ({
    id: m.id,
    name: m.name,
    pricing: formatPricing({ input: eurPerTokenFromUsd(m.usd_in), output: eurPerTokenFromUsd(m.usd_out), currency: "EUR" }),
    price_in: eurPerTokenFromUsd(m.usd_in),
    price_out: eurPerTokenFromUsd(m.usd_out),
    up: true,
    vision: true,
    provider: "anthropic",
  }));
}

/** @param {import('./types.js').Env} env */
function headers(env) {
  return {
    "content-type": "application/json",
    "x-api-key": String(env.ANTHROPIC_API_KEY || ""),
    "anthropic-version": "2023-06-01",
  };
}

// Claude Sonnet 5 runs ADAPTIVE thinking when the `thinking` param is
// omitted (a silent default — unlike Opus 4.8 / Haiku 4.5, where omission
// means no thinking). Thinking spends output tokens inside max_tokens and
// adds a long silent pause before the first text delta — both bad fits for
// this pipeline's time-budget planning and its 60s idle guard — so it is
// explicitly disabled to match the other models' behavior. Revisit with a
// rubric-bench A/B (tests/eval-bench.mjs) if synthesis quality on Sonnet
// looks worth the latency.
/** @param {string | undefined} model */
function thinkingConfigFor(model) {
  return model === "claude-sonnet-5" ? { type: "disabled" } : null;
}

// data:image/jpeg;base64,… → its media type + raw base64 payload.
const DATA_URL_RE = /^data:(image\/[\w.+-]+);base64,(.+)$/s;

// Converts the project's OpenAI-style message array into an Anthropic
// Messages API payload. Pure and exported for unit tests. Differences it
// bridges: `system` turns are a top-level field (not messages); image parts
// are base64 source blocks (not data-URL image_url parts); consecutive
// same-role messages are merged (defensive — appended context blocks and
// pipeline scaffolding can produce them, and Anthropic historically
// rejected non-alternating turns).
/**
 * @param {import('./types.js').Conversation} messages
 * @param {{ model?: string, maxTokens?: number, stream?: boolean }} opts
 */
export function toAnthropicPayload(messages, { model, maxTokens = MAX_TOKENS, stream = false } = {}) {
  const system = [];
  /** @type {Array<{role: string, content: any[]}>} */
  const out = [];
  for (const m of messages || []) {
    if (m?.role === "system") {
      const text = partsText(m.content);
      if (text) system.push(text);
      continue;
    }
    const role = m?.role === "assistant" ? "assistant" : "user";
    const content = toContentBlocks(m?.content);
    if (!content.length) continue;
    const prev = out[out.length - 1];
    if (prev && prev.role === role) prev.content.push(...content);
    else out.push({ role, content });
  }
  /** @type {Record<string, unknown>} */
  const payload = { model, max_tokens: maxTokens, stream, messages: out };
  const sys = system.join("\n\n");
  if (sys) payload.system = sys;
  const thinking = thinkingConfigFor(model);
  if (thinking) payload.thinking = thinking;
  return payload;
}

/** @param {import('./types.js').MessageContent | undefined} content */
function partsText(content) {
  if (typeof content === "string") return content;
  if (!Array.isArray(content)) return "";
  return content
    .flatMap((p) => (p?.type === "text" && typeof p.text === "string" ? [p.text] : []))
    .join("\n");
}

/** @param {import('./types.js').MessageContent | undefined} content */
function toContentBlocks(content) {
  if (typeof content === "string") {
    return content ? [{ type: "text", text: content }] : [];
  }
  if (!Array.isArray(content)) return [];
  const blocks = [];
  for (const part of content) {
    if (part?.type === "text" && typeof part.text === "string" && part.text) {
      blocks.push({ type: "text", text: part.text });
    } else if (part?.type === "image_url" && typeof part.image_url?.url === "string") {
      const m = DATA_URL_RE.exec(part.image_url.url);
      // Only data:image URLs pass validation.js, so a non-match is a
      // malformed part — skip it rather than erroring the request.
      if (m) blocks.push({ type: "image", source: { type: "base64", media_type: m[1], data: m[2] } });
    }
  }
  return blocks;
}

// Anthropic stop_reason → OpenAI finish_reason. The pipeline only checks
// truthiness (a missing finish_reason marks a dropped connection), but the
// mapped values keep logs/diagnostics reading consistently.
/** @type {Record<string, string>} */
const STOP_REASON_MAP = {
  end_turn: "stop",
  stop_sequence: "stop",
  max_tokens: "length",
  tool_use: "tool_calls",
};

// Wraps an Anthropic SSE body in a ReadableStream that emits the SAME wire
// format berget.js's consumeChatStream parses. Event mapping:
//   message_start          → remember input_tokens (prompt side of usage)
//   content_block_delta    → `{choices:[{delta:{content}}]}` per text_delta
//                            (thinking/tool deltas are dropped — text only)
//   message_delta          → finish_reason chunk + merged usage totals
//   message_stop           → `[DONE]`
//   error                  → the stream ERRORS (reader.read() rejects), so
//                            the consumer's try/catch and the pipeline's
//                            stall/retry handling engage normally
//   ping / block start-stop→ ignored
/** @param {ReadableStream} body */
export function openAiStreamFromAnthropic(body) {
  const reader = body.getReader();
  const decoder = new TextDecoder();
  const encoder = new TextEncoder();
  let buffer = "";
  const usage = { prompt_tokens: 0, completion_tokens: 0 };

  return new ReadableStream({
    // Loops until at least one chunk is enqueued (or the source ends):
    // a pull that enqueues nothing is NOT re-invoked by the stream
    // machinery, so events that map to zero output (message_start, ping,
    // block start/stop) would otherwise deadlock the read.
    async pull(controller) {
      while (true) {
        const { done, value } = await reader.read();
        if (done) {
          controller.close();
          return;
        }
        buffer += decoder.decode(value, { stream: true });
        const lines = buffer.split("\n");
        buffer = lines.pop() || "";
        let enqueued = false;
        for (const line of lines) {
          if (!line.startsWith("data:")) continue;
          const data = line.slice(5).trim();
          if (!data) continue;
          let evt;
          try {
            evt = JSON.parse(data);
          } catch {
            continue;
          }
          if (evt.type === "error") {
            reader.cancel().catch(() => {});
            controller.error(new Error(`Anthropic stream error: ${evt.error?.message || "unknown"}`));
            return;
          }
          for (const chunk of oaiChunksFromEvent(evt, usage)) {
            controller.enqueue(encoder.encode(`data: ${chunk}\n\n`));
            enqueued = true;
          }
        }
        if (enqueued) return;
      }
    },
    cancel(reason) {
      return reader.cancel(reason);
    },
  });
}

// One Anthropic event → zero or more OpenAI-style SSE data payloads
// (pre-serialized strings; "[DONE]" is the literal terminator). Mutates
// the shared usage accumulator. Exported for unit tests.
/**
 * @param {any} evt one parsed Anthropic SSE event
 * @param {import('./types.js').TokenTotals} usage shared accumulator
 * @returns {string[]} pre-serialized OpenAI-style data payloads
 */
export function oaiChunksFromEvent(evt, usage) {
  switch (evt?.type) {
    case "message_start": {
      const u = evt.message?.usage;
      if (typeof u?.input_tokens === "number") usage.prompt_tokens = u.input_tokens;
      if (typeof u?.output_tokens === "number") usage.completion_tokens = u.output_tokens;
      return [];
    }
    case "content_block_delta": {
      const d = evt.delta;
      if (d?.type === "text_delta" && d.text) {
        return [JSON.stringify({ choices: [{ delta: { content: d.text } }] })];
      }
      return [];
    }
    case "message_delta": {
      if (typeof evt.usage?.output_tokens === "number") usage.completion_tokens = evt.usage.output_tokens;
      const stop = evt.delta?.stop_reason;
      if (!stop) return [];
      return [
        JSON.stringify({
          choices: [{ delta: {}, finish_reason: STOP_REASON_MAP[stop] || String(stop) }],
          usage: {
            prompt_tokens: usage.prompt_tokens,
            completion_tokens: usage.completion_tokens,
            total_tokens: usage.prompt_tokens + usage.completion_tokens,
          },
        }),
      ];
    }
    case "message_stop":
      return ["[DONE]"];
    default:
      return []; // ping, content_block_start/stop, unknown future events
  }
}

// Streaming chat completion, same calling contract as berget.js's
// chatCompletion: resolves to a Response-shaped object with `ok`, `status`,
// `body` (already adapted to OpenAI-style SSE) and `text()`. A non-2xx or
// bodyless response is returned AS-IS (the real Response), so callers'
// existing error paths (`upstream.text()` for the detail) work unchanged.
// The abort signal bounds only the connect phase, exactly like Berget's.
/**
 * @param {import('./types.js').Env} env
 * @param {import('./types.js').Conversation} messages
 * @param {{ model?: string }} opts
 */
export async function anthropicChatCompletion(env, messages, { model } = {}) {
  const payload = toAnthropicPayload(messages, { model, stream: true });
  const controller = new AbortController();
  const timer = setTimeout(() => controller.abort(), STREAM_CONNECT_TIMEOUT_MS);
  let resp;
  try {
    resp = await fetch(messagesUrl(env), {
      method: "POST",
      headers: headers(env),
      body: JSON.stringify(payload),
      signal: controller.signal,
    });
  } finally {
    clearTimeout(timer);
  }
  if (!resp.ok || !resp.body) return resp;
  return {
    ok: true,
    status: resp.status,
    body: openAiStreamFromAnthropic(resp.body),
    text: async () => "",
  };
}

// Non-streaming JSON completion, same contract as berget.js's completeJson
// ({ value, usage, diagnostics }; value null on parse failure — callers
// fall back gracefully). Normally UNUSED: the JSON planning phases run on
// Berget's fixed DEFAULT_MODEL (split model routing — CLAUDE.md invariant
// 3). This exists so the dispatch stays total if a deployment ever routes
// JSON to a Claude model (e.g. Berget catalog outage fallback). Anthropic
// has no response_format param; the prompts already demand JSON-only and
// parseLooseJson repairs prose-wrapped objects.
/**
 * @param {import('./types.js').Env} env
 * @param {import('./types.js').Conversation} messages
 * @param {{ model?: string, maxTokens?: number }} opts
 */
export async function anthropicCompleteJson(env, messages, { model, maxTokens = 900 } = {}) {
  const payload = toAnthropicPayload(messages, { model, maxTokens, stream: false });
  const resp = await fetch(messagesUrl(env), {
    method: "POST",
    headers: headers(env),
    body: JSON.stringify(payload),
    signal: AbortSignal.timeout(JSON_CALL_TIMEOUT_MS),
  });
  if (!resp.ok) {
    const detail = await resp.text().catch(() => "");
    throw new Error(`Anthropic JSON call failed (${resp.status}): ${detail.slice(0, 200)}`);
  }
  const data = /** @type {any} */ (await resp.json());
  /** @type {any[]} */
  const blocks = Array.isArray(data.content) ? data.content : [];
  const content = blocks
    .filter((b) => b?.type === "text" && typeof b.text === "string")
    .map((b) => b.text)
    .join("");
  const { value, parseMode } = parseLooseJson(content);
  return {
    value,
    usage: {
      prompt_tokens: data.usage?.input_tokens || 0,
      completion_tokens: data.usage?.output_tokens || 0,
    },
    diagnostics: {
      parse_mode: parseMode,
      finish_reason: data.stop_reason || null,
      content_length: content.length,
    },
  };
}

import { test, describe } from "node:test";
import assert from "node:assert/strict";

import {
  anthropicModels,
  isAnthropicModel,
  oaiChunksFromEvent,
  openAiStreamFromAnthropic,
  toAnthropicPayload,
} from "./anthropic.js";
import { consumeChatStream } from "./berget.js";

// Builds a mock Anthropic SSE body from event objects (the shape the
// Messages API streams), so the adapter can be tested end-to-end through
// berget.js's consumeChatStream — the exact composition production uses.
function anthropicSseBody(events) {
  const encoder = new TextEncoder();
  const chunks = events.map((e) => `event: ${e.type}\ndata: ${JSON.stringify(e)}\n\n`);
  return new ReadableStream({
    pull(controller) {
      if (!chunks.length) return controller.close();
      controller.enqueue(encoder.encode(chunks.shift()));
    },
  });
}

const messageStart = (input = 12) => ({
  type: "message_start",
  message: { usage: { input_tokens: input, output_tokens: 1 } },
});
const textDelta = (text) => ({ type: "content_block_delta", index: 0, delta: { type: "text_delta", text } });
const messageDelta = (stop = "end_turn", output = 7) => ({
  type: "message_delta",
  delta: { stop_reason: stop },
  usage: { output_tokens: output },
});

describe("isAnthropicModel", () => {
  test("claude-* ids route to Anthropic; Berget paths and junk do not", () => {
    assert.equal(isAnthropicModel("claude-opus-4-8"), true);
    assert.equal(isAnthropicModel("claude-sonnet-5"), true);
    assert.equal(isAnthropicModel("mistralai/Mistral-Small-3.2-24B-Instruct-2506"), false);
    assert.equal(isAnthropicModel(undefined), false);
    assert.equal(isAnthropicModel(null), false);
  });
});

describe("anthropicModels", () => {
  test("empty without the ANTHROPIC_API_KEY secret (feature invisible)", () => {
    assert.deepEqual(anthropicModels({}), []);
  });

  test("with the key: opus/sonnet/haiku in ModelCatalogEntry shape, EUR-priced, vision, up", () => {
    const models = anthropicModels({ ANTHROPIC_API_KEY: "k" });
    assert.deepEqual(models.map((m) => m.id), ["claude-opus-4-8", "claude-sonnet-5", "claude-haiku-4-5"]);
    for (const m of models) {
      assert.equal(m.up, true);
      assert.equal(m.vision, true);
      assert.equal(m.provider, "anthropic");
      assert.ok(m.price_in > 0 && m.price_out > m.price_in, `${m.id} priced`);
      assert.match(m.pricing, /€.* in \/ €.* out per 1M tokens/);
    }
    // Relative pricing sanity: opus > sonnet > haiku.
    const [opus, sonnet, haiku] = models;
    assert.ok(opus.price_out > sonnet.price_out && sonnet.price_out > haiku.price_out);
  });
});

describe("toAnthropicPayload", () => {
  test("system turns become the top-level system field; user/assistant pass through", () => {
    const p = toAnthropicPayload(
      [
        { role: "system", content: "You are helpful." },
        { role: "user", content: "hi" },
        { role: "assistant", content: "hello" },
        { role: "user", content: "again" },
      ],
      { model: "claude-opus-4-8" },
    );
    assert.equal(p.model, "claude-opus-4-8");
    assert.equal(p.system, "You are helpful.");
    assert.deepEqual(
      p.messages.map((m) => m.role),
      ["user", "assistant", "user"],
    );
    assert.deepEqual(p.messages[0].content, [{ type: "text", text: "hi" }]);
  });

  test("consecutive same-role messages merge into one alternating turn", () => {
    const p = toAnthropicPayload(
      [
        { role: "user", content: "part one" },
        { role: "user", content: "part two" },
      ],
      { model: "claude-haiku-4-5" },
    );
    assert.equal(p.messages.length, 1);
    assert.deepEqual(p.messages[0].content.map((b) => b.text), ["part one", "part two"]);
  });

  test("image data URLs convert to base64 source blocks; malformed parts are dropped", () => {
    const p = toAnthropicPayload(
      [
        {
          role: "user",
          content: [
            { type: "text", text: "what is this?" },
            { type: "image_url", image_url: { url: "data:image/jpeg;base64,AAAA" } },
            { type: "image_url", image_url: { url: "https://example.com/x.jpg" } },
          ],
        },
      ],
      { model: "claude-opus-4-8" },
    );
    assert.deepEqual(p.messages[0].content, [
      { type: "text", text: "what is this?" },
      { type: "image", source: { type: "base64", media_type: "image/jpeg", data: "AAAA" } },
    ]);
  });

  test("sonnet-5 gets thinking explicitly disabled (adaptive-by-default model); others omit it", () => {
    // Sonnet 5 runs ADAPTIVE thinking when the param is omitted — hidden
    // token spend inside max_tokens and a long silent pause before the
    // first delta, both bad for the budget planner and the idle guard.
    const sonnet = toAnthropicPayload([{ role: "user", content: "q" }], { model: "claude-sonnet-5" });
    assert.deepEqual(sonnet.thinking, { type: "disabled" });
    const opus = toAnthropicPayload([{ role: "user", content: "q" }], { model: "claude-opus-4-8" });
    assert.equal("thinking" in opus, false);
    const haiku = toAnthropicPayload([{ role: "user", content: "q" }], { model: "claude-haiku-4-5" });
    assert.equal("thinking" in haiku, false);
  });

  test("stream flag and max_tokens ride through", () => {
    const p = toAnthropicPayload([{ role: "user", content: "q" }], {
      model: "claude-opus-4-8",
      stream: true,
      maxTokens: 900,
    });
    assert.equal(p.stream, true);
    assert.equal(p.max_tokens, 900);
  });
});

describe("openAiStreamFromAnthropic → consumeChatStream (the production composition)", () => {
  test("text deltas, usage and finish_reason arrive in the OpenAI shape", async () => {
    const body = openAiStreamFromAnthropic(
      anthropicSseBody([
        messageStart(12),
        { type: "ping" },
        { type: "content_block_start", index: 0, content_block: { type: "text", text: "" } },
        textDelta("Hel"),
        textDelta("lo"),
        { type: "content_block_stop", index: 0 },
        messageDelta("end_turn", 7),
        { type: "message_stop" },
      ]),
    );
    const seen = [];
    const out = await consumeChatStream(body, (t) => seen.push(t));
    assert.equal(out.text, "Hello");
    assert.deepEqual(seen, ["Hel", "lo"]);
    assert.equal(out.finishReason, "stop"); // end_turn mapped
    assert.equal(out.usage.prompt_tokens, 12);
    assert.equal(out.usage.completion_tokens, 7);
  });

  test("max_tokens stop_reason maps to finish_reason length", async () => {
    const body = openAiStreamFromAnthropic(
      anthropicSseBody([messageStart(), textDelta("x"), messageDelta("max_tokens", 3), { type: "message_stop" }]),
    );
    const out = await consumeChatStream(body, () => {});
    assert.equal(out.finishReason, "length");
  });

  test("a missing message_delta yields NO finish_reason — the dropped-connection tell survives adaptation", async () => {
    // pipeline.js throws on a falsy finishReason; a Claude stream that dies
    // before message_delta must present the same signature.
    const body = openAiStreamFromAnthropic(anthropicSseBody([messageStart(), textDelta("partial")]));
    const out = await consumeChatStream(body, () => {});
    assert.equal(out.text, "partial");
    assert.equal(out.finishReason, null);
  });

  test("an Anthropic error event errors the stream (catchable by the pipeline's retry path)", async () => {
    const body = openAiStreamFromAnthropic(
      anthropicSseBody([messageStart(), { type: "error", error: { type: "overloaded_error", message: "Overloaded" } }]),
    );
    await assert.rejects(consumeChatStream(body, () => {}), /Anthropic stream error: Overloaded/);
  });

  test("thinking deltas are dropped — only text reaches the client", async () => {
    const body = openAiStreamFromAnthropic(
      anthropicSseBody([
        messageStart(),
        { type: "content_block_delta", index: 0, delta: { type: "thinking_delta", thinking: "hmm" } },
        textDelta("answer"),
        messageDelta(),
        { type: "message_stop" },
      ]),
    );
    const out = await consumeChatStream(body, () => {});
    assert.equal(out.text, "answer");
  });
});

describe("oaiChunksFromEvent", () => {
  test("message_delta without a stop_reason emits nothing but still accumulates usage", () => {
    const usage = { prompt_tokens: 5, completion_tokens: 0 };
    const chunks = oaiChunksFromEvent({ type: "message_delta", delta: {}, usage: { output_tokens: 4 } }, usage);
    assert.deepEqual(chunks, []);
    assert.equal(usage.completion_tokens, 4);
  });

  test("unknown future event types are ignored (forward compatibility)", () => {
    assert.deepEqual(oaiChunksFromEvent({ type: "some_future_event" }, { prompt_tokens: 0, completion_tokens: 0 }), []);
  });
});

// @ts-check
// Static-asset serving and the public (unauthenticated) allowlist. Split out
// of the router so index.js stays about routing and this owns two coupled
// concerns: WHICH paths are served without auth (`isPublicAsset` — dominated
// by the DRC /cure public module graph) and HOW assets are served (caching
// policy + the cross-origin-isolation COEP shell). The Worker serves assets
// through env.ASSETS with run_worker_first = true, so auth covers the assets
// too — hence a deliberate, documented allowlist rather than an open static
// root.

// The public surface, served WITHOUT auth. Two kinds of things live here:
//
// Branding assets: iOS fetches apple-touch-icon and Chrome downloads
// manifest icons without credentials, so behind auth home-screen/PWA
// icons silently 401 and fall back to a generic letter.
//
// The promotional surface: the landing page (/welcome/, also served to
// signed-out visitors at /), the documentation, About, and the build
// story pages plus everything they need to render — the promo video, the
// markdown renderer, and the vendored libs (all public on GitHub anyway).
// The app itself and every /api/* stay gated.
/**
 * @param {URL} url
 * @param {string} method
 * @returns {boolean}
 */
export function isPublicAsset(url, method) {
  if (method !== "GET" && method !== "HEAD") return false;
  return (
    url.pathname === "/favicon.ico" ||
    url.pathname === "/manifest.webmanifest" ||
    url.pathname.startsWith("/icons/") ||
    url.pathname.startsWith("/welcome/") ||
    url.pathname.startsWith("/help/") ||
    url.pathname.startsWith("/build/") ||
    url.pathname.startsWith("/story/") ||
    url.pathname.startsWith("/architecture/") ||
    // Project pulse — the commit-analytics dashboard: the page plus its
    // committed dataset (pulse/data.json). Public so it is reachable from
    // BOTH tiers (the signed-in app links it, and the /cure client tier can
    // open it without an account). The dataset is derived from the public
    // git history, so serving it unauthenticated exposes nothing new.
    url.pathname.startsWith("/pulse/") ||
    // DRC — the no-account client-side tier at /cure: the page, its
    // modules, and the vault/SSE primitives it reuses. Only FILES (with
    // an extension) match here: extensionless paths under /cure/ are page
    // routes (/cure/<slug> replays) and must fall through to the wordplay
    // routing below — without the extension check they'd 404 as missing
    // assets (found live 2026-07-10: /cure/<slug> served the sign-in 401,
    // then 404, until this).
    (url.pathname.startsWith("/cure/") && /\.[a-z0-9]+$/i.test(url.pathname)) ||
    // The vault's PURE core only — NOT /js/vault.js: that module's store/load
    // orchestration statically imports the DRS storage stack (history-store/
    // opfs/projects), which is deliberately not public, and any 401 inside a
    // public module graph kills the whole /cure tier (found live 2026-07-11:
    // /cure was dead — static "d5" stamp — because drc-core.js imported
    // vault.js and its DRS chain 401'd; fixed by splitting vault-core.js out
    // and importing that). If a module here ever needs vault functionality,
    // import vault-core.js, never vault.js.
    url.pathname === "/js/vault-core.js" ||
    url.pathname === "/js/sse.js" ||
    url.pathname === "/js/drc-core.js" ||
    url.pathname === "/js/drc-providers.js" ||
    url.pathname === "/js/drc-rag.js" ||
    // drc-rag.js's import chain: rag.js/chat-rag.js (the reused pure
    // helpers) each import settings.js — all three must be public or the
    // /cure module graph fails to link (the same class of breakage the
    // extension check above fixed; found live 2026-07-10 when d6 shipped
    // with drc-rag.js absent from this list).
    url.pathname === "/js/rag.js" ||
    url.pathname === "/js/chat-rag.js" ||
    url.pathname === "/js/settings.js" ||
    url.pathname === "/js/drc-research.js" ||
    url.pathname === "/js/drc-store.js" ||
    // drc-research.js statically imports the bash-lite sandbox modules (the
    // in-browser Linux execution tier is present on DRC too): the shared pure
    // agent core (bash-core.js — also imported by the DRS driver
    // bash-agent.js) AND the CheerpX VM bridge. All must be public or the
    // /cure module graph fails to link and the whole client tier's JS dies —
    // the same breakage class as drc-rag.js above (found live 2026-07-11: the
    // sandbox commit added the imports to drc-research.js but not to this
    // allowlist, so /js/bash-agent.js and /js/sandbox.js 401'd and /cure went
    // dark).
    url.pathname === "/js/bash-core.js" ||
    url.pathname === "/js/bash-agent.js" ||
    url.pathname === "/js/sandbox.js" ||
    // sandbox.js imports sandbox-files.js (the file-mounting pure core) — both
    // must be public or the /cure module graph (drc-research.js → sandbox.js)
    // fails to link.
    url.pathname === "/js/sandbox-files.js" ||
    // sandbox.js also imports the agent activity backdrop (the faint
    // page-background command/output layer that replaced the auto-popping
    // terminal) and its pure core — both are in the same public graph, so both
    // must be allowlisted or /cure goes dark.
    url.pathname === "/js/agent-backdrop.js" ||
    url.pathname === "/js/agent-backdrop-core.js" ||
    // Introspection (developer mode): the shared pure core (imported by
    // /cure/drc.js — same public-graph rule as the modules above) and the
    // committed source-snapshot artifact both tiers fetch. The snapshot is
    // the repo's own tracked text files — public on GitHub anyway — so
    // serving it unauthenticated exposes nothing new; DRC needs it public
    // because its server-not-in-the-path posture forbids an authed endpoint.
    url.pathname === "/js/introspect-core.js" ||
    // The introspection mascot/picker component (imported by /cure/drc.js —
    // same public-graph rule; its own imports, introspect-core.js and
    // drc-providers.js, are already above).
    url.pathname === "/js/introspect-ui.js" ||
    // Provider country-of-processing flags — a leaf pure module imported by
    // /cure/drc.js and by introspect-core.js (both in the public graph).
    url.pathname === "/js/provider-region.js" ||
    url.pathname === "/introspect/source-snapshot.json" ||
    url.pathname === "/llm-assiterad-utveckling.mp4" ||
    url.pathname === "/js/markdown.js" ||
    url.pathname === "/vendor/marked.min.js" ||
    url.pathname === "/vendor/purify.min.js"
  );
}

// Serves a static asset with an EXPLICIT browser-caching policy. Without
// one (the state until 2026-07-08), browsers applied HEURISTIC caching to
// the app's ~20 unversioned ES modules — and a day with several deploys
// that changed cross-module exports left real devices with a MIXED module
// graph (a fresh stream.js importing a stale-cached activity.js). The
// import linker then fails, app.js never runs, no submit handler attaches,
// and pressing Send falls through to the browser's NATIVE form submit — a
// full page reload that looks like the chat silently resetting to a blank
// new conversation ("no queries work"). `no-cache` (= store but REVALIDATE
// every use) fixes the class: the strong etags Workers assets already emit
// make revalidation a cheap 304, and every page load links a consistent,
// current module graph. Icons/media (not part of the module graph, rarely
// changed) keep a short real TTL. The Cloudflare EDGE cache is unaffected
// and safe — it is content-addressed per deploy.
// json included (2026-07-12): the introspection source snapshot
// (/introspect/source-snapshot.json) must track the deploy it shipped with —
// a fixed TTL would serve a previous deploy's source for up to an hour, the
// exact staleness class the cache-helper skill documents. Strong etags make
// the revalidation a cheap 304.
const ASSET_REVALIDATE = /\.(js|css|html|md|json|webmanifest)$/i;

/**
 * Serves a static asset with an explicit browser-caching policy.
 * @param {Request} request
 * @param {Env} env
 * @param {string | null} [overrideUrl] serve this path instead of the request's
 * @param {{ coep?: boolean }} [opts] coep: add Cross-Origin-Embedder-Policy so
 *   the served DOCUMENT becomes cross-origin isolated (with the site-wide
 *   COOP: same-origin), which SharedArrayBuffer — and thus the CheerpX
 *   execution sandbox (public/js/sandbox.js) — requires. We use `require-corp`
 *   (NOT `credentialless`): iOS Safari / WebKit does not implement
 *   `credentialless` COEP, so it silently never isolates there —
 *   `SharedArrayBuffer` stays undefined and the VM can't boot (confirmed live
 *   on iOS 18.7 Safari: header served, `crossOriginIsolated===false`,
 *   `SharedArrayBuffer` absent). `require-corp` is honored by Chrome, Firefox,
 *   AND Safari. Its cost: every cross-origin subresource must carry CORP — the
 *   sandbox's CDN loads (jsdelivr xterm, cxrtnc CheerpX) already send
 *   `Cross-Origin-Resource-Policy: cross-origin`, and the server-fetched Maps
 *   imagery is same-origin, so the only casualty is the keyless Street View
 *   Embed IFRAME (no CORP) — an acceptable trade for a sandbox that actually
 *   boots on iOS. Applied to the DRC page always and to the DRS app shell only
 *   when the caller's bash_lite knob is on (see routeAuthed).
 * @returns {Promise<Response>}
 */
export async function serveAsset(request, env, overrideUrl = null, opts = {}) {
  // The COEP (cross-origin-isolated) shell must be served as a FRESH 200 that
  // is never cached: the COEP header is added dynamically per the bash_lite
  // knob, but the HTML content is identical whether the knob is on or off, so
  // a normal `no-cache` revalidation returns a 304 and the browser reuses its
  // stored NON-isolated response WITHOUT the COEP header — `crossOriginIsolated`
  // never turns on and the sandbox silently can't boot (the production defect
  // this fixes). So for the isolated shell we strip the request's conditional
  // headers (forcing a full 200, not a 304) and mark it `no-store`.
  const upstream = buildAssetRequest(request, overrideUrl, opts.coep);
  const res = await env.ASSETS.fetch(upstream);
  const pathname = new URL(overrideUrl || request.url).pathname;
  const headers = new Headers(res.headers);
  if (opts.coep) {
    headers.set("cross-origin-embedder-policy", "require-corp");
    headers.set("cache-control", "no-store");
  } else if (ASSET_REVALIDATE.test(pathname) || !/\.[a-z0-9]+$/i.test(pathname)) {
    // Extensionless paths are HTML routes (/, /welcome/, /admin) — revalidate.
    headers.set("cache-control", "no-cache");
  } else {
    headers.set("cache-control", "public, max-age=3600");
  }
  return new Response(res.body, { status: res.status, statusText: res.statusText, headers });
}

/**
 * Builds the request handed to env.ASSETS. Normally the original request (or an
 * override URL). For the isolated (coep) shell, conditional headers are
 * stripped so ASSETS returns a full 200 (never a 304 that would drop the
 * dynamic COEP header — see serveAsset).
 * @param {Request} request
 * @param {string | null} overrideUrl
 * @param {boolean | undefined} coep
 * @returns {Request}
 */
export function buildAssetRequest(request, overrideUrl, coep) {
  if (!coep) return overrideUrl ? new Request(overrideUrl, request) : request;
  const headers = new Headers(request.headers);
  headers.delete("if-none-match");
  headers.delete("if-modified-since");
  return new Request(overrideUrl || request.url, { method: request.method, headers });
}

/** @typedef {import('./types.js').Env} Env */

// Unit tests for assets.js — the public (no-auth) allowlist, the asset
// caching policy, and the cross-origin-isolation (COEP) request shaping.
import { test, describe, afterEach } from "node:test";
import assert from "node:assert/strict";

import { isPublicAsset, buildAssetRequest, serveAsset } from "./assets.js";

const u = (path) => new URL("https://deepresearch.se" + path);

describe("isPublicAsset", () => {
  test("only GET/HEAD are ever public", () => {
    assert.equal(isPublicAsset(u("/welcome/"), "POST"), false);
    assert.equal(isPublicAsset(u("/welcome/"), "GET"), true);
    assert.equal(isPublicAsset(u("/welcome/"), "HEAD"), true);
  });

  test("promotional + branding surfaces are public", () => {
    for (const p of ["/favicon.ico", "/manifest.webmanifest", "/icons/x.png", "/welcome/", "/help/x", "/build/", "/story/", "/architecture/"]) {
      assert.equal(isPublicAsset(u(p), "GET"), true, p);
    }
  });

  test("DRC /cure files (with extension) are public, but page routes are not", () => {
    assert.equal(isPublicAsset(u("/cure/drc.js"), "GET"), true);
    assert.equal(isPublicAsset(u("/cure/drc.css"), "GET"), true);
    // Extensionless /cure/<slug> replay routes must fall through to routing.
    assert.equal(isPublicAsset(u("/cure/my-slug"), "GET"), false);
    assert.equal(isPublicAsset(u("/cure/"), "GET"), false);
  });

  test("the whole /cure module graph is on the allowlist", () => {
    for (const p of [
      "/js/vault-core.js", "/js/sse.js", "/js/drc-core.js", "/js/drc-providers.js",
      "/js/drc-rag.js", "/js/rag.js", "/js/chat-rag.js", "/js/settings.js",
      "/js/drc-research.js", "/js/drc-store.js", "/js/bash-core.js", "/js/bash-agent.js",
      "/js/sandbox.js", "/js/sandbox-files.js", "/js/introspect-core.js",
      "/js/introspect-ui.js", "/introspect/source-snapshot.json", "/js/markdown.js",
    ]) {
      assert.equal(isPublicAsset(u(p), "GET"), true, p);
    }
  });

  test("vault.js (DRS store/load) is NOT public — only the pure core is", () => {
    // vault.js statically imports the DRS storage stack; a 401 inside the
    // public /cure graph would kill the whole tier, so it must stay gated.
    assert.equal(isPublicAsset(u("/js/vault.js"), "GET"), false);
    assert.equal(isPublicAsset(u("/js/vault-core.js"), "GET"), true);
  });

  test("the app itself and APIs stay gated", () => {
    assert.equal(isPublicAsset(u("/"), "GET"), false);
    assert.equal(isPublicAsset(u("/js/app.js"), "GET"), false);
    assert.equal(isPublicAsset(u("/api/chat"), "GET"), false);
    assert.equal(isPublicAsset(u("/js/stream.js"), "GET"), false);
  });
});

describe("buildAssetRequest", () => {
  test("returns the original request when no override and no coep", () => {
