// @ts-check
// Authentication and identity for the whole site (UI + API).
//
// User-facing sign-in is GOOGLE ONLY (src/google.js): a successful Google
// login mints the signed session cookie below, which then authenticates
// every request. Two identity sources resolve here:
//
//   - USERS: D1 accounts (created by Google sign-in), identified by the
//     session cookie `u.<uid>.<expiry>.<hmac(uid.expiry)>` and re-checked
//     against the DB on every request (disabling is immediate).
//   - ADMIN break-glass: the ADMIN_USER / ADMIN_PASS Worker secrets over
//     HTTP Basic Auth (legacy fallback: BASIC_AUTH_USER / BASIC_AUTH_PASS).
//     For curl/scripts and emergencies — no database, no Google needed.
//     Legacy admin session cookies from the pre-Google era also still map
//     here so existing installs aren't logged out.
//
// PWA longevity: sessions last 365 days and slide — any authenticated
// request past the half-life gets a fresh cookie (index.js appends it), so
// an installed PWA that is opened at least twice a year never re-logs-in.
// The cookie is HttpOnly and server-set, which also exempts it from
// Safari/ITP's 7-day cap on script-writable storage.
//
// Cookie/state HMAC key: the dedicated `SESSION_SECRET` secret (a random,
// high-entropy value — deliberately not the admin password, which the cookie
// would otherwise expose to offline brute force). It is REQUIRED and is the
// sole signing AND verification key; there is no admin-credential fallback.
// When SESSION_SECRET is unset the site cannot run sessions — the entrypoint
// (src/index.js) serves a configuration-error page instead of signing cookies
// with a weaker key. Rotating SESSION_SECRET invalidates all sessions. The
// admin break-glass Basic Auth (below) is independent of this key.

import { getUserById } from "./accounts.js";

/** @typedef {import('./types.js').Env} Env */
/** @typedef {import('./accounts.js').User} User */

/**
 * A resolved caller identity. Two shapes share it: the break-glass admin
 * (`isSecretAdmin`, no `user` row) and D1 users (`user` row attached).
 * @typedef {Object} Identity
 * @property {string} id user-row id as a string, or ADMIN_ID for break-glass
 * @property {"admin" | "user"} role
 * @property {string | null} email
 * @property {string} name
 * @property {boolean} [isSecretAdmin] true only for the break-glass identity
 * @property {boolean} [pending] awaiting-approval user (index.js parks them)
 * @property {User} [user] the D1 row (absent for break-glass)
 * @property {boolean} [refreshCookie] cookie passed its half-life — reissue it
 */

const COOKIE_NAME = "dr_session";
const SESSION_TTL_S = 365 * 24 * 3600; // 1 year, sliding
const REFRESH_BELOW_S = SESSION_TTL_S / 2;

export const ADMIN_ID = "admin";

/**
 * The break-glass Basic Auth credentials, or null when unset (which makes
 * the whole site fail closed — see identify).
 * @param {Env} env
 * @returns {{ user: string, pass: string } | null}
 */
function adminCreds(env) {
  const user = env.ADMIN_USER || env.BASIC_AUTH_USER;
  const pass = env.ADMIN_PASS || env.BASIC_AUTH_PASS;
  return user && pass ? { user: String(user), pass: String(pass) } : null;
}

/** @returns {Identity} the break-glass admin identity (no D1 row) */
export function adminIdentity() {
  return { id: ADMIN_ID, role: "admin", email: null, name: "Admin", isSecretAdmin: true };
}

/** @param {User} user @returns {Identity} */
function userIdentity(user) {
  return {
    id: String(user.id),
    role: user.role === "admin" ? "admin" : "user",
    email: user.email,
    name: user.name || user.email,
    // Approval gate: pending users authenticate but only ever see the
    // waiting page (index.js enforces) until the admin activates them.
    pending: user.status === "pending",
    user,
  };
}

/**
 * Resolves who is making this request, or null. Order: Basic header
 * (admin secrets break-glass), then session cookie. Sets `refreshCookie`
 * on the identity when the cookie has passed its half-life.
 * @param {Request} request
 * @param {Env} env
 * @returns {Promise<Identity | null>}
 */
export async function identify(request, env) {
  const creds = adminCreds(env);
  if (!creds) return null; // fail closed

  const basic = parseBasicHeader(request);
  if (basic) {
    if (safeEqual(basic.user, creds.user) && safeEqual(basic.pass, creds.pass)) {
      return adminIdentity();
    }
    return null; // explicit bad credentials — don't fall through to cookie
  }

  const session = await verifySessionCookie(request, env);
  if (!session) return null;
  const refreshCookie = session.exp * 1000 - Date.now() < REFRESH_BELOW_S * 1000;

  if (session.uid === ADMIN_ID) return { ...adminIdentity(), refreshCookie };
  const user = await getUserById(env, Number(session.uid)).catch(() => null);
  if (user && (user.status === "active" || user.status === "pending")) {
    return { ...userIdentity(user), refreshCookie };
  }
  return null;
}

/**
 * Mints the signed, year-long session cookie (Set-Cookie header value).
 * @param {Env} env
 * @param {string} [uid] user-row id as a string; defaults to the admin id
 * @returns {Promise<string>}
 */
export async function createSessionCookie(env, uid = ADMIN_ID) {
  const exp = Math.floor(Date.now() / 1000) + SESSION_TTL_S;
  const sig = await signHmac(env, `${uid}.${exp}`);
  return (
    `${COOKIE_NAME}=u.${uid}.${exp}.${sig}; Max-Age=${SESSION_TTL_S}; Path=/; ` +
    "Secure; HttpOnly; SameSite=Lax"
  );
}

/** @returns {string} a Set-Cookie value that expires the session cookie */
export function clearSessionCookie() {
  return `${COOKIE_NAME}=; Max-Age=0; Path=/; Secure; HttpOnly; SameSite=Lax`;
}

// HMAC helpers for the OAuth state cookie (src/google.js).
/**
 * @param {Env} env
 * @param {string} state
 * @returns {Promise<string>} hex HMAC tag over the namespaced state
 */
export async function signState(env, state) {
  return signHmac(env, `state.${state}`);
}
/**
 * Verifies the OAuth state cookie `<state>.<sig>` against the callback's
 * state param — both the equality and the signature must hold.
 * @param {Env} env
 * @param {string} state the `state` query param Google echoed back
 * @param {string} cookieValue
 * @returns {Promise<boolean>}
 */
export async function verifyState(env, state, cookieValue) {
  const [cState, cSig] = String(cookieValue).split(".");
  if (!cState || !cSig || !safeEqual(cState, state)) return false;
  return verifyHmac(env, `state.${state}`, cSig);
}

/**
 * @param {Request} request
 * @returns {{ user: string, pass: string } | null} decoded Basic credentials
 */
function parseBasicHeader(request) {
  const header = request.headers.get("Authorization") || "";
  if (!header.startsWith("Basic ")) return null;
  let decoded;
  try {
    decoded = atob(header.slice(6));
  } catch {
    return null;
  }
  const sep = decoded.indexOf(":");
  if (sep < 0) return null;
  return { user: decoded.slice(0, sep), pass: decoded.slice(sep + 1) };
}

/**
 * Returns {uid, exp} from a valid cookie, or null. Accepts the
 * pre-multiuser legacy format `<exp>.<sig>` as the admin identity so
 * existing sessions survive upgrades.
 * @param {Request} request
 * @param {Env} env
 * @returns {Promise<{ uid: string, exp: number } | null>}
 */
async function verifySessionCookie(request, env) {
  const cookies = request.headers.get("Cookie") || "";
  const m = cookies.match(new RegExp(`(?:^|;\\s*)${COOKIE_NAME}=([^;]+)`));
  if (!m) return null;
  const parts = m[1].split(".");

  if (parts[0] === "u" && parts.length === 4) {
    const [, uid, expStr, sig] = parts;
    const exp = parseInt(expStr, 10);
    if (!uid || !Number.isFinite(exp) || exp * 1000 < Date.now()) return null;
    return (await verifyHmac(env, `${uid}.${expStr}`, sig)) ? { uid, exp } : null;
  }

  if (parts.length === 2) {
    const [expStr, sig] = parts;
    const exp = parseInt(expStr, 10);
    if (!Number.isFinite(exp) || exp * 1000 < Date.now()) return null;
    return (await verifyHmac(env, expStr, sig)) ? { uid: ADMIN_ID, exp } : null;
  }
  return null;
}

/** @param {Uint8Array} rawBytes @returns {Promise<CryptoKey>} */
function importHmacKey(rawBytes) {
  return crypto.subtle.importKey(
    "raw",
    rawBytes,
    { name: "HMAC", hash: "SHA-256" },
    false,
    ["sign"],
  );
}

// The HMAC key for signing/verifying session (and OAuth-state) cookies.
//
// SESSION_SECRET is the SOLE key — there is NO fallback. An earlier design
// derived a key from the admin credentials when SESSION_SECRET was unset (and,
// worse, honored it alongside a configured secret), which kept every session
// cookie offline-brute-forceable against ADMIN_PASS — the cookie message
// `<uid>.<exp>` is known to its holder — and forgeable to any uid / to admin
// once ADMIN_PASS was recovered. That fallback is gone: cookie integrity is
// bounded only by SESSION_SECRET's entropy. When SESSION_SECRET is unset there
// is no signing key at all (returns []); the entrypoint (src/index.js) detects
// the missing secret up front and serves a configuration-error page rather than
// letting any auth flow run keyless. Rotating SESSION_SECRET invalidates all
// sessions.
/**
 * @param {Env} env
 * @returns {Promise<CryptoKey[]>} candidate verification keys (0 or 1 today)
 */
async function sessionHmacKeys(env) {
  if (!env.SESSION_SECRET) return [];
  const enc = new TextEncoder();
  return [await importHmacKey(enc.encode(String(env.SESSION_SECRET)))];
}

/** @param {ArrayBuffer} buf @returns {string} */
function toHex(buf) {
  return [...new Uint8Array(buf)].map((b) => b.toString(16).padStart(2, "0")).join("");
}

/**
 * @param {Env} env
 * @param {string} message
 * @returns {Promise<string>} hex HMAC-SHA-256 tag
 */
async function signHmac(env, message) {
  const [key] = await sessionHmacKeys(env);
  // Fail closed: never sign without SESSION_SECRET. index.js gates the whole
  // site on the secret before any signing path can run, so this is a
  // belt-and-braces guard, not a reachable state.
  if (!key) throw new Error("SESSION_SECRET is not configured");
  const sig = await crypto.subtle.sign("HMAC", key, new TextEncoder().encode(message));
  return toHex(sig);
}

/**
 * True if the tag matches under ANY candidate key. With no keys configured
 * nothing verifies (fail closed).
 * @param {Env} env
 * @param {string} message
 * @param {string} sig hex tag from the cookie
 * @returns {Promise<boolean>}
 */
async function verifyHmac(env, message, sig) {
  const bytes = new TextEncoder().encode(message);
  for (const key of await sessionHmacKeys(env)) {
    const expected = toHex(await crypto.subtle.sign("HMAC", key, bytes));
    if (safeEqual(sig, expected)) return true;
  }
  return false;
}

/**
 * Constant-time-ish comparison to avoid trivial timing leaks.
 * @param {unknown} a
 * @param {unknown} b
 * @returns {boolean}
 */
function safeEqual(a, b) {
  if (typeof a !== "string" || typeof b !== "string" || a.length !== b.length) return false;
  let diff = 0;
  for (let i = 0; i < a.length; i++) diff |= a.charCodeAt(i) ^ b.charCodeAt(i);
  return diff === 0;
}

// Session-cookie HMAC: keyed ONLY by SESSION_SECRET — there is no
// admin-credential fallback. The security properties exercised here:
//   - a cookie's validity depends solely on SESSION_SECRET, never on
//     ADMIN_USER/ADMIN_PASS (so a captured cookie can't be brute-forced back
//     to the break-glass password, and rotating that password can't forge one);
//   - with no SESSION_SECRET there is no signing key at all, so nothing
//     verifies (the entrypoint serves a config-error page in that state);
//   - rotating SESSION_SECRET invalidates every existing cookie.
// These touch only the admin/HMAC path (no D1).
import test from "node:test";
import assert from "node:assert/strict";
import { createSessionCookie, identify } from "./auth.js";

const SECRET = "d0a2d4e838e1c1c7c65fef7b784c9623ee113f8aab5da9aab9d62f8a311109de";
const OTHER_SECRET = "ffffffffffffffffffffffffffffffffffffffffffffffffffffffffffffffff";
const admin = { ADMIN_USER: "root", ADMIN_PASS: "weakpass" };
const withSecret = { ...admin, SESSION_SECRET: SECRET };

const cookieOf = (setCookie) => setCookie.split(";")[0];
const reqWith = (cookie) => new Request("https://x/", { headers: { Cookie: cookie } });

test("SESSION_SECRET-signed admin cookie verifies", async () => {
  const cookie = cookieOf(await createSessionCookie(withSecret, "admin"));
  const id = await identify(reqWith(cookie), withSecret);
  assert.equal(id?.role, "admin");
});

test("cookie validity is decoupled from the admin password (survives ADMIN_PASS rotation)", async () => {
  const cookie = cookieOf(await createSessionCookie(withSecret, "admin"));
  const rotated = { ...withSecret, ADMIN_PASS: "a-completely-different-password" };
  const id = await identify(reqWith(cookie), rotated);
  assert.equal(id?.role, "admin");
});

test("no admin-credential fallback: a cookie does NOT verify when SESSION_SECRET is unset", async () => {
  // Minted under SESSION_SECRET, then presented to a deployment that has the
  // admin creds but no SESSION_SECRET. With the fallback removed there is no
  // key to verify under, so it is rejected (rather than validating against an
  // admin-password-derived key, the old offline-brute-force exposure).
  const cookie = cookieOf(await createSessionCookie(withSecret, "admin"));
  assert.equal(await identify(reqWith(cookie), admin), null);
});

test("rotating SESSION_SECRET invalidates existing cookies", async () => {
  const cookie = cookieOf(await createSessionCookie(withSecret, "admin"));
  const rotated = { ...admin, SESSION_SECRET: OTHER_SECRET };
  assert.equal(await identify(reqWith(cookie), rotated), null);
});

test("tampered signature is rejected", async () => {
  const cookie = cookieOf(await createSessionCookie(withSecret, "admin"));
  const tampered = cookie.slice(0, -4) + "0000";
  assert.equal(await identify(reqWith(tampered), withSecret), null);
});

test("fails closed for the admin uid when the admin secrets are unset, even with SESSION_SECRET", async () => {
  const cookie = cookieOf(await createSessionCookie(withSecret, "admin"));
  assert.equal(await identify(reqWith(cookie), { SESSION_SECRET: SECRET }), null);
});

// @ts-check
// The bash-lite agent's SERVER FAÇADE. The actual implementation — the intent
// heuristic, the fenced-block parser, exec-result normalization, the synthesis
// transcript block, the shared step user-message, and the caps — lives in ONE
// shared pure module: public/js/bash-core.js. It sits under public/ because
// the browser can only import modules the Worker serves (the DRS loop driver
// public/js/bash-agent.js and DRC's drc-research.js both import it directly),
// while the Worker's bundler (wrangler/esbuild) can import from any repo path
// — so the server reaches the same single source of truth through this
// re-export. See bash-core.js's header for the full arrangement.
//
// Until 2026-07-11 this file carried its own copy, hand-mirrored against the
// client with "keep in lock-step" comments and a parity test. Don't
// reintroduce that: new shared logic goes in bash-core.js; anything genuinely
// server-only (like the /api/bash/step handler, src/bash-api.js) stays in src/.
//
// Server consumers and what they use:
//   - src/bash-api.js:  parseShellRequest, buildShellTranscript,
//                        buildStepUserMessage, normalizeExecResult, caps
//   - src/pipeline.js:  buildShellTranscript (ctx.shellBlock)
//   - src/chat.js:      MAX_SHELL_ROUNDS (shell_transcript bounding)

export {
  MAX_SHELL_ROUNDS,
  MAX_COMMANDS_PER_ROUND,
  MAX_OUTPUT_CHARS,
  MAX_COMMAND_CHARS,
  bashIntent,
  parseShellRequest,
  normalizeExecResult,
  formatShellResult,
  buildShellTranscript,
  buildStepUserMessage,
} from "../public/js/bash-core.js";

// Unit tests for the bash-lite server façade (src/bash-agent.js). The pure
// logic itself — intent gate, parser, normalizers, transcript, step message,
// loop driver — is implemented ONCE in public/js/bash-core.js and fully tested
// in public/js/bash-core.test.js; what this suite pins down is the FAÇADE
// contract: the server surface re-exports the exact same functions (no drift,
// no re-implementation — the guarantee that replaced the old hand-mirrored
// copy and its parity test), and the server import path stays live.
import { test, describe } from "node:test";
import assert from "node:assert/strict";
import * as facade from "./bash-agent.js";
import * as core from "../public/js/bash-core.js";

describe("server façade re-exports the shared core (single source of truth)", () => {
  test("every façade export IS the core's implementation (same function object)", () => {
    for (const name of [
      "bashIntent",
      "parseShellRequest",
      "normalizeExecResult",
      "formatShellResult",
      "buildShellTranscript",
      "buildStepUserMessage",
    ]) {
      assert.equal(facade[name], core[name], `${name} must be re-exported, not re-implemented`);
    }
  });

  test("the caps are the core's caps", () => {
    for (const name of ["MAX_SHELL_ROUNDS", "MAX_COMMANDS_PER_ROUND", "MAX_OUTPUT_CHARS", "MAX_COMMAND_CHARS"]) {
      assert.equal(facade[name], core[name], name);
      assert.equal(typeof facade[name], "number", name);
    }
  });

  test("smoke: the server surface works end to end (EN+SV, invariant 6)", () => {
    // One representative call per export, through the server import path —
    // the deep behavioral coverage lives in bash-core.test.js.
    assert.equal(facade.bashIntent("run this command: uname -a"), true);
    assert.equal(facade.bashIntent("kör det här kommandot: uname -a"), true);
    assert.deepEqual(facade.parseShellRequest("```bash\nuname -a\n```").commands, ["uname -a"]);
    assert.equal(facade.normalizeExecResult("x", null).exitCode, 1);
    assert.match(
      facade.buildShellTranscript([{ command: "true", exitCode: 0, stdout: "", stderr: "" }]),
      /Linux sandbox session/,
    );
    assert.match(facade.buildStepUserMessage({ task: "t", context: "c" }), /No commands have run yet/);
  });
});

// @ts-check
// POST /api/bash/step — ONE turn of the experimental bash-lite agent loop
// (src/bash-agent.js; the `bash_lite_mcp` knob). The sandbox itself is an
// x86 Linux emulator running IN THE BROWSER (CheerpX), so the loop is
// client-orchestrated (public/js/bash-agent.js for DRS): the browser sends
// the conversation plus the transcript of commands it has already run, this
// endpoint asks the reliable model what to run NEXT, and returns the parsed
// command proposal for the browser to execute. When the model is done, the
// client stops looping and folds the transcript into the /api/chat request
// (chat.js `shell_transcript`) as a synthesis context block.
//
// NO function calling (invariant 1): the model replies with a plain fenced
// ```bash block (bashAgentPrompt); parseShellRequest turns it into commands.
// Runs on the fixed reliable DEFAULT_MODEL — command choice must be
// dependable regardless of the user's answer-model pick — with the same quota
// gate and usage accounting as /api/quiz/grade (all spend visible; admins
// never blocked). Fully fail-soft: any failure returns done=true so the
// client stops the loop and answers normally.

import { chatCompletion, listChatModels } from "./providers.js";
import { consumeChatStream, DEFAULT_MODEL } from "./berget.js";
import { quotaBlockedResponse } from "./chat.js";
import { formatConversation, lastUserMessage, textOf } from "./conversation.js";
import { getConfig } from "./config.js";
import { jsonResponse } from "./http.js";
import { bashAgentPrompt } from "./prompts.js";
import {
  bergetCost,
  effectiveQuota,
  getUsage,
  inflightLimitResponse,
  quotaExceeded,
  recordUsage,
  releaseInflight,
  reserveInflight,
} from "./quota.js";
import { bashLiteEnabled } from "./settings.js";
import {
  MAX_SHELL_ROUNDS,
  buildShellTranscript,
  buildStepUserMessage,
  normalizeExecResult,
  parseShellRequest,
} from "./bash-agent.js";
import { validateMessages } from "./validation.js";

/** @typedef {import('./types.js').Env} Env */
/** @typedef {import('./types.js').Logger} Logger */
/** @typedef {import('./settings.js').Identity} Identity */

/**
 * @param {Request} request
 * @param {Env} env
 * @param {Logger} log
 * @param {Identity} identity
 * @returns {Promise<Response>}
 */
export async function handleBashStep(request, env, log, identity) {
  if (!env.BERGET_API_TOKEN) {
    return jsonResponse({ error: "Server not configured: BERGET_API_TOKEN secret is missing." }, 500);
  }
  // The knob must be on for this account (a browser capability, so this only
  // needs a user row + the stored flag). A client that calls this with the
  // knob off gets a clean stop, not an error.
  if (!bashLiteEnabled(env, identity)) {
    return jsonResponse({ error: "The execution sandbox is not enabled.", done: true }, 403);
  }

  /** @type {any} */
  let body;
  try {
    body = await request.json();
  } catch {
    return jsonResponse({ error: "Request body must be valid JSON." }, 400);
  }
  const invalid = validateMessages(body?.messages);
  if (invalid) return jsonResponse({ error: invalid }, 400);

  // The prior sandbox runs the client has already executed (untrusted — clamp
  // every field). Bounded so a client cannot grow the prompt without limit:
  // the loop caps at MAX_SHELL_ROUNDS rounds × a few commands each.
  const rawTranscript = Array.isArray(body?.transcript) ? body.transcript.slice(0, MAX_SHELL_ROUNDS * 8) : [];
  const transcript = rawTranscript
    .filter((/** @type {any} */ r) => r && typeof r === "object" && typeof r.command === "string" && r.command.trim())
    .map((/** @type {any} */ r) => normalizeExecResult(r.command, r));

  // Same quota gate as /api/chat and /api/quiz/grade (admins never blocked).
  const config = await getConfig(env);
  const usage = await getUsage(env, identity.id);
  const quota =
    identity.isSecretAdmin || identity.role === "admin" ? null : effectiveQuota(config, identity.user);
  const blocked = quota ? quotaExceeded(usage, quota) : null;
  if (blocked) return jsonResponse(quotaBlockedResponse(blocked), 429);

  // Per-user concurrency reservation (M-1/M-2), released in the finally below
  // on every exit path. reqId minted locally; fail-soft on any D1 trouble.
  const reqId = crypto.randomUUID();
  const reserved = await reserveInflight(env, identity.id, reqId);
  if (!reserved.ok) return jsonResponse(inflightLimitResponse(reserved), 429);

  // The per-round user message is the shared builder (bash-core.js), so DRS
  // and DRC ask the model the exact same step question.
  const userContent = buildStepUserMessage({
    task: textOf(lastUserMessage(body.messages)?.content),
    context: formatConversation(body.messages),
    priorBlock: buildShellTranscript(transcript),
  });

  const startedAt = Date.now();
  try {
    const resp = await chatCompletion(
      env,
      [
        { role: "system", content: bashAgentPrompt() },
        { role: "user", content: userContent },
      ],
      { model: DEFAULT_MODEL },
    );
    if (!resp.ok || !resp.body) {
      const detail = resp.text ? await resp.text().catch(() => "") : "";
      log.warn("bash.step_upstream_error", { user_id: identity.id, status: resp.status, detail: detail.slice(0, 200) });
      // Fail soft: tell the client to stop the loop rather than erroring.
      return jsonResponse({ commands: [], done: true, reasoning: "" });
    }
    const { text, usage: streamUsage } = await consumeChatStream(resp.body, () => {}, { idleMs: 30_000, maxMs: 60_000 });
    await recordStepUsage(env, log, identity, streamUsage, Date.now() - startedAt);
    const proposal = parseShellRequest(text);
    log.info("bash.step", {
      user_id: identity.id,
      prior_runs: transcript.length,
      commands: proposal.commands.length,
      done: proposal.done,
    });
    // Debug: the actual proposed commands (model-generated, not user content),
    // bounded — so heavy testing can trace exactly what the loop ran via the
    // log URL when LOG_LEVEL=debug.
    log.debug("bash.step_commands", {
      user_id: identity.id,
      commands: proposal.commands.map((c) => String(c).slice(0, 200)).slice(0, 6),
    });
    return jsonResponse(proposal);
  } catch (err) {
    log.error("bash.step_failed", { user_id: identity.id, error: (/** @type {any} */ (err))?.message || String(err) });
    // Fail soft — the client stops the loop and the pipeline answers normally.
    return jsonResponse({ commands: [], done: true, reasoning: "" });
  } finally {
    await releaseInflight(env, reqId);
  }
}

// The step spends real (small) Berget money on DEFAULT_MODEL — record it like
// every other spend, priced from the catalog (fail-soft: an unreachable
// catalog records the tokens at zero cost rather than failing the step).
/**
 * @param {Env} env
 * @param {Logger} log
 * @param {Identity} identity
 * @param {{ prompt_tokens?: number, completion_tokens?: number } | null | undefined} usage
 * @param {number} durationMs
 */
async function recordStepUsage(env, log, identity, usage, durationMs) {
  let entry = null;
  try {
    entry = (await listChatModels(env))?.find((m) => m.id === DEFAULT_MODEL) || null;
  } catch {
    entry = null;
  }
  const prompt_tokens = usage?.prompt_tokens || 0;
  const completion_tokens = usage?.completion_tokens || 0;
  await recordUsage(env, log, {
    user_id: identity.id,
    model: DEFAULT_MODEL,
    prompt_tokens,
    completion_tokens,
    searches: 0,
    berget_cost: bergetCost(entry, prompt_tokens, completion_tokens),
    exa_cost: 0,
    duration_ms: durationMs,
  });
}

// @ts-check
// Berget.ai client (OpenAI-compatible chat completions API).
//
// Auth uses the BERGET_API_TOKEN secret. The default model is Mistral Small,
// overridable via the BERGET_MODEL var. See CLAUDE.md ("LLM provider").

// BERGET_URL env override exists solely so local tests can point at a
// mock (like GOOGLE_TOKEN_URL); production always uses the default.
/** @param {import('./types.js').Env} env */
const apiBase = (env) => env.BERGET_URL || "https://api.berget.ai/v1";
/** @param {import('./types.js').Env} env */
const chatUrl = (env) => apiBase(env) + "/chat/completions";
/** @param {import('./types.js').Env} env */
const modelsUrl = (env) => apiBase(env) + "/models";
/** @param {import('./types.js').Env} env */
const embeddingsUrl = (env) => apiBase(env) + "/embeddings";
export const DEFAULT_MODEL = "mistralai/Mistral-Small-3.2-24B-Instruct-2506"; // alias: mistral-small
// Embedding model for the document-RAG feature (src/rag.js). Berget hosts
// intfloat/multilingual-e5-large (1024 dims, cosine, €0.03/1M tokens as of
// 2026-07) — the plain (non-instruct) variant, whose input convention is
// the well-defined "query: …" / "passage: …" prefix pair applied
// server-side in src/rag.js. Overridable via BERGET_EMBED_MODEL, but note
// the Vectorize index is created with a fixed dimension count — switching
// to a model with different dimensions requires recreating the index.
export const DEFAULT_EMBED_MODEL = "intfloat/multilingual-e5-large";
export const EMBED_DIMS = 1024;

/** @param {import('./types.js').Env} env */
export function embedModel(env) {
  return env.BERGET_EMBED_MODEL || DEFAULT_EMBED_MODEL;
}

// Neither Berget call below had a timeout until a live model-eval battery
// (2026-07-06, round 2) surfaced requests that silently died mid-pipeline
// for a few models: Workers Logs showed several phases logging normally
// (info level), then NOTHING — no warn/error, no chat.complete — for
// requests that succeed when simply re-run. That signature is consistent
// with an awaited fetch() that never settles: nothing throws for phase()'s
// try/catch to catch, so the fail-soft design this pipeline is built
// around never engages. These bound the hang into a normal, catchable
// error instead.
const JSON_CALL_TIMEOUT_MS = 45_000;
const STREAM_CONNECT_TIMEOUT_MS = 30_000;
// Bounds the model-catalog fetch the same way — an unbounded fetch to Berget
// has bitten this project before (see the round-2 note above). A TimeoutError
// from AbortSignal surfaces as a normal throw, exactly like the existing
// !resp.ok throw, so every caller's fail-soft handling (rawModelEntry's
// try/catch, listModels' callers) degrades rather than hanging.
const CATALOG_TIMEOUT_MS = 15_000;

// A round 4 model-eval battery (cybersecurity queries, mid-long time
// budget) found several models' synthesis stream just never completing:
// Workers Logs showed the request killed with outcome "exceededCpu" while
// still inside the synth phase, no chat.stream_failed, nothing — the
// client sees a clean EOF with 0 chars, "ok: true". `chatCompletion`
// already requests `max_tokens: 4096`, but Berget doesn't always honor it
// (the user's own account of Berget's infra: models run on hardware known
// to misbehave — a degenerate/repetitive generation that doesn't hit a
// natural stop can keep emitting well past the requested cap). Every
// legitimate synthesis answer observed across all eval rounds has stayed
// under ~13,000 characters; this is a generous safety valve, not a content
// limit — it exists purely so a runaway generation gets cut off by OUR
// code (a clean, catchable error) before Cloudflare's platform-level CPU
// limit kills the whole isolate with no error surfaced at all.
const STREAM_MAX_CHARS = 32_000;

/** @param {import('./types.js').Env} env */
export function defaultModel(env) {
  return env.BERGET_MODEL || DEFAULT_MODEL;
}

// True when the admin's configured site default model (src/config.js) is
// still present in the catalog and up — the only condition under which
// callers should treat it as authoritative over the Worker's built-in
// default. Shared by chat.js (applying it to an unset request) and
// user-api.js (reporting it as /api/models' `default`).
/**
 * @param {{ default_model?: string }} config the admin site config
 * @param {import('./types.js').ModelCatalogEntry[] | null | undefined} catalog
 * @returns {boolean}
 */
export function adminDefaultModelValid(config, catalog) {
  return !!(config.default_model && catalog?.some((m) => m.id === config.default_model && m.up));
}

// Berget's model catalog, filtered to models the chat can use: text models
// supporting streaming + JSON mode (the research pipeline's planning and
// validation calls depend on it). Models Berget reports as down are included
// with `up: false` so the UI can show them greyed out — they become
// selectable automatically once Berget brings them back. Cached per isolate
// to keep /api/models and per-request validation cheap.
/** @typedef {{ at: number, list: import('./types.js').ModelCatalogEntry[] | null, raw: any[] | null }} ModelsCache */
/** @type {ModelsCache} */
let modelsCache = { at: 0, list: null, raw: null };
const MODELS_TTL_MS = 5 * 60 * 1000;

// One catalog fetch feeds both views: `list` (chat-capable text models, the
// shape the UI and validation consume) and `raw` (every catalog entry as
// Berget returns it — needed to price non-chat models like the embedding
// model, which the text-only filter below would otherwise hide).
/**
 * @param {import('./types.js').Env} env
 * @returns {Promise<ModelsCache>}
 */
async function fetchCatalog(env) {
  if (modelsCache.list && Date.now() - modelsCache.at < MODELS_TTL_MS) {
    return modelsCache;
  }
  const resp = await fetch(modelsUrl(env), {
    headers: { authorization: `Bearer ${env.BERGET_API_TOKEN}` },
    signal: AbortSignal.timeout(CATALOG_TIMEOUT_MS),
  });
  if (!resp.ok) throw new Error(`Berget models fetch failed (${resp.status})`);
  const data = await resp.json();
  const raw = /** @type {any[]} */ (Array.isArray(data.data) ? data.data : []);

  const list = raw
    .filter(
      (m) =>
        m.model_type === "text" &&
        m.capabilities?.streaming &&
        m.capabilities?.json_mode,
    )
    .map((m) => ({
      id: m.id,
      name: m.name || m.id,
      pricing: formatPricing(m.pricing),
      // Raw EUR-per-token prices, kept for quota cost accounting.
      price_in: typeof m.pricing?.input === "number" ? m.pricing.input : 0,
      price_out: typeof m.pricing?.output === "number" ? m.pricing.output : 0,
      up: m.status?.up !== false,
      vision: m.capabilities?.vision === true,
    }));

  modelsCache = { at: Date.now(), list, raw };
  return modelsCache;
}

/**
 * @param {import('./types.js').Env} env
 * @returns {Promise<import('./types.js').ModelCatalogEntry[] | null>}
 */
export async function listModels(env) {
  return (await fetchCatalog(env)).list;
}

// Raw catalog entry lookup by id or alias — used to price embedding calls
// for quota accounting. Returns null (never throws) when the catalog is
// unreachable or the model unknown: cost accounting degrades to zero-cost
// rather than blocking the feature.
/**
 * @param {import('./types.js').Env} env
 * @param {string} id a model id or alias
 * @returns {Promise<any | null>}
 */
export async function rawModelEntry(env, id) {
  try {
    const { raw } = await fetchCatalog(env);
    return raw?.find((m) => m.id === id || m.aliases?.includes(id)) || null;
  } catch {
    return null;
  }
}

// "€0.30 in / €0.30 out per 1M tokens" — shown as a tooltip in the UI.
// Exported for other providers' catalog builders (src/anthropic.js,
// src/openai.js) so every dropdown entry formats identically.
/**
 * @param {{ input?: number, output?: number, currency?: string } | null | undefined} p
 * @returns {string | null}
 */
export function formatPricing(p) {
  if (!p || typeof p.input !== "number" || typeof p.output !== "number") return null;
  /** @param {number} v */
  const perM = (v) => (v * 1e6).toFixed(2).replace(/\.?0+$/, "");
  const cur = p.currency === "EUR" ? "€" : (p.currency || "") + " ";
  return `${cur}${perM(p.input)} in / ${cur}${perM(p.output)} out per 1M tokens`;
}

// USD-per-1M-tokens → EUR-per-token, for providers that price in USD
// (Anthropic, OpenAI) while the quota system accounts in EUR (quota.js
// bergetCost, admin budgets). One fixed, documented rate shared by every
// USD-priced catalog so the conversion can't drift apart per provider —
// it only affects cost-accounting granularity, and admins tune budgets
// around whatever rate is encoded here. Revisit if it drifts materially.
export const USD_TO_EUR = 0.92;
/** @param {number} usdPerMTok USD price per 1M tokens */
export const eurPerTokenFromUsd = (usdPerMTok) => (usdPerMTok * USD_TO_EUR) / 1e6;

// Starts a streaming chat completion. `model` overrides the default.
//
// The abort signal bounds only the time to receive a RESPONSE (headers) —
// once fetch() settles the timer is cleared, so a legitimately long
// stream can keep being read afterward without getting cut off mid-flight.
/**
 * @param {import('./types.js').Env} env
 * @param {import('./types.js').Conversation} messages
 * @param {{ model?: string }} [opts]
 * @returns {Promise<Response>}
 */
export function chatCompletion(env, messages, { model } = {}) {
  const payload = {
    model: model || defaultModel(env),
    stream: true,
    max_tokens: 4096,
    messages,
  };
  const controller = new AbortController();
  const timer = setTimeout(() => controller.abort(), STREAM_CONNECT_TIMEOUT_MS);
  return fetch(chatUrl(env), {
    method: "POST",
    headers: {
      "content-type": "application/json",
      authorization: `Bearer ${env.BERGET_API_TOKEN}`,
    },
    body: JSON.stringify(payload),
    signal: controller.signal,
  }).finally(() => clearTimeout(timer));
}

// Consumes one OpenAI-style SSE response body. Calls `onText` for each text
// delta as it arrives, and accumulates usage stats and the finish reason.
//
// Optional guards — the connect timeout above deliberately stops covering a
// stream once headers arrive, so a backend that ACCEPTS the request and then
// stalls mid-generation hangs the read loop forever (the same silent-hang
// family as the round-2 finding, one layer later). `idleMs` bounds the wait
// for each next chunk; `maxMs` bounds the whole consumption. Either tripping
// cancels the reader and THROWS a normal, catchable error. Both default OFF
// so the answer-synthesis path (where a long silent think can be legitimate
// on a reasoning model) is unchanged — helper calls that run BEFORE the
// pipeline (the Street View vision-describe, which blocks everything
// downstream) opt in.
//
// Returns { text, usage, finishReason }.
/**
 * @typedef {object} StreamResult
 * @property {string} text the accumulated answer text
 * @property {any | null} usage merged token-usage chunk, if the backend sent one
 * @property {string | null} finishReason the OpenAI finish_reason, if seen
 */
/**
 * @param {ReadableStream<Uint8Array>} body an OpenAI-style SSE response body
 * @param {(chunk: string) => void} onText called with each text delta
 * @param {{ idleMs?: number, maxMs?: number }} [guards] opt-in idle/total budgets (0 = off)
 * @returns {Promise<StreamResult>}
 */
export async function consumeChatStream(body, onText, { idleMs = 0, maxMs = 0 } = {}) {
  const reader = body.getReader();
  const decoder = new TextDecoder();
  let buffer = "";
  let text = "";
  /** @type {any | null} */
  let usage = null;
  /** @type {string | null} */
  let finishReason = null;
  const startedAt = Date.now();

  // One reader.read(), optionally raced against the idle/total budgets. When
  // both guards are off it is a plain read; otherwise a tripped budget cancels
  // the reader and throws a normal, catchable error.
  const nextChunk = async () => {
    if (!idleMs && !maxMs) return reader.read();
    /** @type {number[]} */
    const budgets = [];
    if (idleMs) budgets.push(idleMs);
    if (maxMs) budgets.push(maxMs - (Date.now() - startedAt));
    const waitMs = Math.min(...budgets);
    if (waitMs <= 0) {
      reader.cancel().catch(() => {});
      throw new Error(`Model stream exceeded its ${maxMs}ms total budget — treating as hung`);
    }
    /** @type {any} */
    let timer;
    try {
      return await Promise.race([
        reader.read(),
        /** @type {Promise<never>} */ (
          new Promise((_, reject) => {
            timer = setTimeout(
              () => reject(new Error(`Model stream produced nothing for ${waitMs}ms — treating as hung`)),
              waitMs,
            );
          })
        ),
      ]);
    } catch (err) {
      reader.cancel().catch(() => {});
      throw err;
    } finally {
      clearTimeout(timer);
    }
  };

  while (true) {
    const { done, value } = await nextChunk();
    if (done) break;
    buffer += decoder.decode(value, { stream: true });
    const lines = buffer.split("\n");
    buffer = /** @type {string} */ (lines.pop());

    for (const line of lines) {
      if (!line.startsWith("data:")) continue;
      const data = line.slice(5).trim();
      if (!data || data === "[DONE]") continue;

      let chunk;
      try {
        chunk = JSON.parse(data);
      } catch {
        continue; // keep-alive / non-JSON line
      }

      // Berget appends a token-usage chunk with an empty `choices` array;
      // merge it in for logging/accounting.
      if (chunk.usage) usage = { ...(usage || {}), ...chunk.usage };

      const choice = chunk.choices?.[0];
      if (!choice) continue;
      if (choice.finish_reason) finishReason = choice.finish_reason;

      const delta = choice.delta;
      if (!delta) continue;

      if (delta.content) {
        text += delta.content;
        onText(delta.content);
        if (text.length > STREAM_MAX_CHARS) {
          await reader.cancel();
          throw new Error(
            `Model stream exceeded the ${STREAM_MAX_CHARS}-char safety cap — likely a runaway/degenerate generation on the backend; aborted before it could exhaust the Worker's CPU budget`,
          );
        }
      }
    }
  }

  return { text, usage, finishReason };
}

// Non-streaming completion that asks Berget for a JSON object and parses it.
// Used by the research pipeline's triage / gap-check / validation phases.
// Returns { value, usage, diagnostics } — value is null when parsing fails
// (callers must fall back gracefully; a broken helper phase must never break
// the chat). diagnostics is metadata only (no content) for per-model
// observability: how the JSON was obtained and whether output was truncated.
/**
 * @param {import('./types.js').Env} env
 * @param {import('./types.js').Conversation} messages
 * @param {{ model?: string, maxTokens?: number }} [opts]
 * @returns {Promise<{ value: any, usage: any | null, diagnostics: { parse_mode: string, finish_reason: string | null, content_length: number } }>}
 */
export async function completeJson(env, messages, { model, maxTokens = 900 } = {}) {
  const resp = await fetch(chatUrl(env), {
    method: "POST",
    headers: {
      "content-type": "application/json",
      authorization: `Bearer ${env.BERGET_API_TOKEN}`,
    },
    body: JSON.stringify({
      model: model || defaultModel(env),
      stream: false,
      max_tokens: maxTokens,
      response_format: { type: "json_object" },
      messages,
    }),
    signal: AbortSignal.timeout(JSON_CALL_TIMEOUT_MS),
  });
  if (!resp.ok) {
    const detail = await resp.text().catch(() => "");
    throw new Error(`Berget JSON call failed (${resp.status}): ${detail.slice(0, 200)}`);
  }
  const data = await resp.json();
  const choice = data.choices?.[0];
  const content = choice?.message?.content || "";
  const { value, parseMode } = parseLooseJson(content);
  return {
    value,
    usage: data.usage || null,
    diagnostics: {
      parse_mode: parseMode, // "strict" | "repaired" | "failed"
      finish_reason: choice?.finish_reason || null,
      content_length: content.length,
    },
  };
}

// Tolerant JSON extraction — models occasionally wrap the object in prose or
// code fences despite json_mode. Returns { value, parseMode }: "strict" when
// the whole string parsed as-is, "repaired" when a balanced {...} object had
// to be extracted from surrounding text, "failed" when neither worked.
// Exported for other providers' JSON completions (src/anthropic.js).
/**
 * @param {unknown} s a model's raw output (possibly prose-wrapped JSON)
 * @returns {{ value: any, parseMode: "strict" | "repaired" | "failed" }}
 */
export function parseLooseJson(s) {
  try {
    return { value: JSON.parse(/** @type {string} */ (s)), parseMode: "strict" };
  } catch {
    // fall through to embedded-object extraction
  }
  const extracted = extractFirstBalancedObject(String(s));
  if (extracted != null) {
    try {
      return { value: JSON.parse(extracted), parseMode: "repaired" };
    } catch {
      // give up
    }
  }
  return { value: null, parseMode: "failed" };
}

// Embeddings (OpenAI-compatible POST /v1/embeddings). Used by the document
// RAG feature: the client indexes large attachments through POST /api/embed
// and src/rag.js embeds queries server-side. Same timeout discipline as
// completeJson — an unbounded fetch to Berget has already bitten this
// project once (see the round 2 note above).
const EMBED_TIMEOUT_MS = 60_000;

/**
 * @param {import('./types.js').Env} env
 * @param {string[]} texts
 * @param {{ model?: string }} [opts]
 * @returns {Promise<{ vectors: any[], usage: any | null, model: string }>}
 */
export async function embedTexts(env, texts, { model } = {}) {
  const resp = await fetch(embeddingsUrl(env), {
    method: "POST",
    headers: {
      "content-type": "application/json",
      authorization: `Bearer ${env.BERGET_API_TOKEN}`,
    },
    body: JSON.stringify({
      model: model || embedModel(env),
      input: texts,
    }),
    signal: AbortSignal.timeout(EMBED_TIMEOUT_MS),
  });
  if (!resp.ok) {
    const detail = await resp.text().catch(() => "");
    throw new Error(`Berget embeddings call failed (${resp.status}): ${detail.slice(0, 200)}`);
  }
  const data = await resp.json();
  const rows = Array.isArray(data.data) ? data.data : [];
  if (rows.length !== texts.length) {
    throw new Error(`Berget embeddings returned ${rows.length} vectors for ${texts.length} inputs`);
  }
  // The API is allowed to return rows out of order; `index` is authoritative.
  const vectors = new Array(texts.length);
  for (const row of rows) {
    if (!Array.isArray(row?.embedding)) throw new Error("Berget embeddings returned a malformed vector");
    vectors[row.index ?? rows.indexOf(row)] = row.embedding;
  }
  return { vectors, usage: data.usage || null, model: data.model || model || embedModel(env) };
}

// Brace-counting scan for the first balanced {...} block, string-aware so
// braces inside quoted strings don't throw off the depth count. Safer than a
// greedy regex when a model emits more than one JSON-shaped chunk (e.g.
// reasoning prose containing an example object, followed by the real one).
/**
 * @param {string} s
 * @returns {string | null} the first balanced `{…}` substring, or null
 */
function extractFirstBalancedObject(s) {
  const start = s.indexOf("{");
  if (start < 0) return null;
  let depth = 0;
  let inString = false;
  let escaped = false;
  for (let i = start; i < s.length; i++) {
    const c = s[i];
    if (inString) {
      if (escaped) escaped = false;
      else if (c === "\\") escaped = true;
      else if (c === '"') inString = false;
      continue;
    }
    if (c === '"') {
      inString = true;
    } else if (c === "{") {
      depth++;
    } else if (c === "}") {
      depth--;
      if (depth === 0) return s.slice(start, i + 1);
    }
  }
  return null;
}

// Unit tests for berget.js's consumeChatStream: OpenAI-style SSE parsing and
// the opt-in idle/total stream guards.
import { test, describe } from "node:test";
import assert from "node:assert/strict";

import { consumeChatStream } from "./berget.js";

// Builds an SSE body from chunks; a `null` chunk means "stall forever from
// here" (the stream never produces another read and never closes) — the
// accepted-then-hung backend shape the idle/total guards exist for.
function sseBody(chunks) {
  const encoder = new TextEncoder();
  return new ReadableStream({
    async pull(controller) {
      if (!chunks.length) return controller.close();
      const next = chunks.shift();
      if (next === null) return new Promise(() => {}); // hang: pull never settles
      controller.enqueue(encoder.encode(next));
    },
  });
}

const delta = (content) => `data: ${JSON.stringify({ choices: [{ delta: { content } }] })}\n`;
const doneChunk = `data: ${JSON.stringify({ choices: [{ delta: {}, finish_reason: "stop" }], usage: { prompt_tokens: 5, completion_tokens: 2 } })}\ndata: [DONE]\n`;

describe("consumeChatStream", () => {
  test("accumulates deltas, usage and finish_reason (no guards — unchanged default)", async () => {
    const seen = [];
    const out = await consumeChatStream(sseBody([delta("Hel"), delta("lo"), doneChunk]), (t) => seen.push(t));
    assert.equal(out.text, "Hello");
    assert.deepEqual(seen, ["Hel", "lo"]);
    assert.equal(out.finishReason, "stop");
    assert.equal(out.usage.completion_tokens, 2);
  });

  test("idleMs converts an accepted-then-stalled stream into a catchable error", async () => {
    // Production shape (2026-07-08): headers arrive (connect timeout cleared),
    // some or no content streams, then the backend goes silent forever —
    // without the guard the read loop hangs the whole request.
    await assert.rejects(
      consumeChatStream(sseBody([delta("partial"), null]), () => {}, { idleMs: 50 }),
      /produced nothing for 50ms/,
    );
  });

  test("maxMs bounds total consumption even while chunks keep trickling in", async () => {
    // A stream that never stalls long enough to trip idleMs but never ends
    // either: emit a chunk every ~10ms forever.
    const encoder = new TextEncoder();
    const trickle = new ReadableStream({
      async pull(controller) {
        await new Promise((r) => setTimeout(r, 10));
        controller.enqueue(encoder.encode(delta("x")));
      },
    });
    await assert.rejects(
      consumeChatStream(trickle, () => {}, { idleMs: 1000, maxMs: 80 }),
      /treating as hung/,
    );
  });

  test("guards do not fire on a healthy stream that finishes in time", async () => {
    const out = await consumeChatStream(sseBody([delta("ok"), doneChunk]), () => {}, { idleMs: 1000, maxMs: 5000 });
    assert.equal(out.text, "ok");
    assert.equal(out.finishReason, "stop");
  });
});

// @ts-check
// The decision-board core — the ONE shared mechanism behind the admin
// panels where Claude Code produces a list and the ADMIN's choices feed
// back into the agent loop's context (see the **decision-boards** skill).
//
// The loop every board implements:
//   1. Claude Code maintains a CATALOG of items (code, stable ids, mirroring
//      a source-of-truth doc) — the security board mirrors SECURITY-RISKS.md
//      §3; a features board mirrors its backlog doc; etc.
//   2. The admin panel renders the catalog with choice UX: ▲/▼ votes, a
//      manual score, a note, and an explicit PRIORITY per item.
//   3. Choices persist in a per-board D1 table keyed by the stable item id —
//      catalog edits never orphan them.
//   4. The loop reads the board back (?format=text) ordered by the admin's
//      choices: explicit priority IS the fixed work order; votes rank the
//      rest. The admin's ordering is the loop's plan — human-in-the-loop by
//      construction.
//   5. Acting on an item flips its catalog status in the same commit that
//      does the work, so the panel reflects reality on the next deploy.
//
// This module is the generic half: choice-state validation, the two
// orderings, and the D1 review-row helpers. Everything item-shaped
// (catalog, projection, text rendering, the endpoint) stays in the board's
// own module — src/security-risks.js is the reference consumer.
//
// Per-board D1 table shape (create per board, name is a CODE CONSTANT):
//   CREATE TABLE <board>_reviews (
//     item_id TEXT PRIMARY KEY, votes INTEGER NOT NULL DEFAULT 0,
//     score TEXT, note TEXT, priority INTEGER, updated_at INTEGER NOT NULL);

/**
 * A board review row (one item's admin choice state).
 * @typedef {{ item_id: string, votes: number, score?: string | null, note?: string | null, priority?: number | null, updated_at: number }} BoardReviewRow
 */

// ---------------------------------------------------------------------------
// Pure helpers — unit-tested in src/board.test.js
// ---------------------------------------------------------------------------

// Size caps: a score is a short designation (a CVSS vector fits), a note is
// a remark, not a document.
export const BOARD_CAPS = { score: 120, note: 2_000 };

/** @param {unknown} v @param {number} max */
const cleanStr = (v, max) => {
  if (typeof v !== "string") return null;
  const t = v.trim();
  return t ? t.slice(0, max) : null;
};

// PATCH body → {score?, note?, priority?} (only the fields present in the
// body; explicit null/"" clears a field), or {error}.
/**
 * @param {any} body
 * @returns {{ error: string } | { error?: undefined, patch: { score?: string | null, note?: string | null, priority?: number | null } }}
 */
export function validateBoardPatch(body) {
  if (!body || typeof body !== "object") return { error: "Request body must be a JSON object." };
  /** @type {{ score?: string | null, note?: string | null, priority?: number | null }} */
  const patch = {};
  if ("score" in body) patch.score = cleanStr(body.score, BOARD_CAPS.score);
  if ("note" in body) patch.note = cleanStr(body.note, BOARD_CAPS.note);
  if ("priority" in body) {
    if (body.priority == null || body.priority === "") {
      patch.priority = null;
    } else {
      const n = Number(body.priority);
      if (!Number.isInteger(n) || n < 1 || n > 999) {
        return { error: "priority must be an integer 1–999, or null to clear." };
      }
      patch.priority = n;
    }
  }
  if (!Object.keys(patch).length) {
    return { error: "Nothing to update — send score, note, and/or priority." };
  }
  return { patch };
}

// POST …/vote body → +1 | -1, or {error}.
/**
 * @param {any} body
 * @returns {{ error: string } | { error?: undefined, delta: number }}
 */
export function validateBoardVote(body) {
  const dir = body?.dir;
  if (dir === "up") return { delta: 1 };
  if (dir === "down") return { delta: -1 };
  return { error: 'vote body must be {"dir":"up"} or {"dir":"down"}.' };
}

// The two board orderings. Items must carry {status, priority, votes}; ties
// keep the INPUT order (Array.prototype.sort is stable), so callers pass the
// catalog in its documented default order and never need an explicit
// order field.
//
//   "priority" — THE WORK ORDER the agent loop consumes: open items first,
//     admin-prioritized ones at the top (ascending priority — the fixed
//     order), then the rest by votes desc, then rankOf asc.
//   "rank"     — the documented view: open first, then rankOf asc (e.g.
//     severity); votes and priority ignored.
/**
 * @template {{ status: string, priority?: number | null, votes: number }} T
 * @param {T[]} items in the board's default (catalog) order
 * @param {string} mode "priority" | "rank"
 * @param {(item: T) => number} rankOf lower = more important (e.g. severity rank)
 * @returns {T[]} a new sorted array
 */
export function orderBoardItems(items, mode, rankOf) {
  /** @param {T} i */
  const openRank = (i) => (i.status === "open" ? 0 : 1);
  const out = [...items];
  if (mode !== "priority") {
    out.sort((a, b) => openRank(a) - openRank(b) || rankOf(a) - rankOf(b));
    return out;
  }
  out.sort((a, b) => {
    const d = openRank(a) - openRank(b);
    if (d) return d;
    const ap = a.priority, bp = b.priority;
    if (ap != null && bp != null) return ap - bp;
    if ((ap != null) !== (bp != null)) return ap != null ? -1 : 1;
    return b.votes - a.votes || rankOf(a) - rankOf(b);
  });
  return out;
}

// Review row → the choice-state fields every board projection spreads into
// its item objects (defaults when the admin hasn't touched the item yet).
/**
 * @param {BoardReviewRow | undefined | null} review
 */
export function reviewState(review) {
  return {
    votes: review?.votes ?? 0,
    score: review?.score ?? null,
    note: review?.note ?? null,
    priority: review?.priority ?? null,
    reviewed_at: review?.updated_at ?? null,
  };
}

// ---------------------------------------------------------------------------
// D1 review-row helpers. `table` is interpolated and MUST be a code
// constant (a board's own module names its table), never user input.
// ---------------------------------------------------------------------------

/**
 * @param {D1Database} db
 * @param {string} table
 * @returns {Promise<Map<string, BoardReviewRow>>} item_id -> row
 */
export async function loadBoardReviews(db, table) {
  const { results } = await db.prepare(`SELECT * FROM ${table}`).all();
  return new Map((/** @type {BoardReviewRow[]} */ (results || [])).map((r) => [r.item_id, r]));
}

/**
 * @param {D1Database} db
 * @param {string} table
 * @param {string} itemId
 * @returns {Promise<BoardReviewRow | null>}
 */
export async function getBoardReview(db, table, itemId) {
  return /** @type {Promise<BoardReviewRow | null>} */ (
    db.prepare(`SELECT * FROM ${table} WHERE item_id = ?`).bind(itemId).first()
  );
}

// Upsert-friendly vote: the review row is created on first vote.
/**
 * @param {D1Database} db
 * @param {string} table
 * @param {string} itemId
 * @param {number} delta +1 | -1
 */
export async function voteBoardRow(db, table, itemId, delta) {
  const now = Date.now();
  await db
    .prepare(
      `INSERT INTO ${table} (item_id, votes, updated_at) VALUES (?, ?, ?)
       ON CONFLICT(item_id) DO UPDATE SET votes = votes + ?, updated_at = ?`,
    )
    .bind(itemId, delta, now, delta, now)
    .run();
}

// Upsert-friendly patch: only the fields present in `patch` are updated on
// an existing row; a new row gets the patched fields and NULL for the rest.
/**
 * @param {D1Database} db
 * @param {string} table
 * @param {string} itemId
 * @param {{ score?: string | null, note?: string | null, priority?: number | null }} patch
 */
export async function patchBoardRow(db, table, itemId, patch) {
  const now = Date.now();
  const sets = ["updated_at = ?"];
  /** @type {any[]} */
  const binds = [now];
  for (const k of /** @type {const} */ (["score", "note", "priority"])) {
    if (k in patch) { sets.push(`${k} = ?`); binds.push(patch[k]); }
  }
  await db
    .prepare(
      `INSERT INTO ${table} (item_id, votes, score, note, priority, updated_at)
       VALUES (?, 0, ?, ?, ?, ?)
       ON CONFLICT(item_id) DO UPDATE SET ${sets.join(", ")}`,
    )
    .bind(itemId, patch.score ?? null, patch.note ?? null, patch.priority ?? null, now, ...binds)
    .run();
}

// The decision-board core (src/board.js): choice-state validation, the two
// orderings (admin work order vs documented rank), reviewState defaults, the
// D1 review-row helpers' SQL shape, and the façade contract — a board's
// re-exported pure surface must BE this core, not a mirror (the bash-agent
// precedent).

import test from "node:test";
import assert from "node:assert/strict";

import {
  BOARD_CAPS,
  validateBoardPatch,
  validateBoardVote,
  orderBoardItems,
  reviewState,
  loadBoardReviews,
  getBoardReview,
  voteBoardRow,
  patchBoardRow,
} from "./board.js";
import * as security from "./security-risks.js";

// ---- façade contract --------------------------------------------------------

test("security board's pure surface IS the core (re-export, not a copy)", () => {
  assert.equal(security.REVIEW_CAPS, BOARD_CAPS);
  assert.equal(security.validateReviewPatch, validateBoardPatch);
  assert.equal(security.validateVote, validateBoardVote);
});

// ---- ordering ---------------------------------------------------------------

const it = (id, over = {}) => ({ id, status: "open", priority: null, votes: 0, rank: 1, ...over });
const rankOf = (i) => i.rank;

test("priority mode: explicit priority is the fixed order, ahead of votes/rank", () => {
  const items = [
    it("a", { votes: 99, rank: 0 }),
    it("b", { priority: 2 }),
    it("c", { priority: 1, rank: 9 }),
  ];
  assert.deepEqual(orderBoardItems(items, "priority", rankOf).map((i) => i.id), ["c", "b", "a"]);
});

test("priority mode: unprioritized ranked by votes desc, then rankOf asc", () => {
  const items = [it("a", { rank: 2 }), it("b", { votes: 3, rank: 2 }), it("c", { rank: 0 })];
  assert.deepEqual(orderBoardItems(items, "priority", rankOf).map((i) => i.id), ["b", "c", "a"]);
});

test("both modes: non-open items sink; ties keep input (catalog) order", () => {
  const items = [
    it("done", { status: "fixed", priority: 1 }),
    it("a"),
    it("b"), // tie with a on every key -> stable sort keeps a before b
  ];
  assert.deepEqual(orderBoardItems(items, "priority", rankOf).map((i) => i.id), ["a", "b", "done"]);
  assert.deepEqual(orderBoardItems(items, "rank", rankOf).map((i) => i.id), ["a", "b", "done"]);
});

test("rank mode ignores votes and priority; input array untouched", () => {
  const items = [it("a", { rank: 5 }), it("b", { votes: 9, priority: 1, rank: 7 })];
  const out = orderBoardItems(items, "rank", rankOf);
  assert.deepEqual(out.map((i) => i.id), ["a", "b"]);
  assert.notEqual(out, items);
  assert.equal(items[0].id, "a");
});

// ---- validation & projection --------------------------------------------------

test("validateBoardPatch: trims, caps, clears on null/empty, rejects bad priority", () => {
  const v = validateBoardPatch({ score: "  CVSS 9.8  ", note: "x".repeat(BOARD_CAPS.note + 5), priority: 7 });
  assert.equal(v.error, undefined);
  assert.equal(v.patch.score, "CVSS 9.8");
  assert.equal(v.patch.note.length, BOARD_CAPS.note);
  assert.equal(v.patch.priority, 7);
  assert.equal(validateBoardPatch({ priority: "" }).patch.priority, null);
  for (const bad of [{ priority: 0 }, { priority: 2.5 }, { priority: 1000 }, {}, null, "x"]) {
    assert.ok(validateBoardPatch(bad).error, JSON.stringify(bad));
  }
});

test("validateBoardVote: up/down only", () => {
  assert.equal(validateBoardVote({ dir: "up" }).delta, 1);
  assert.equal(validateBoardVote({ dir: "down" }).delta, -1);
  assert.ok(validateBoardVote({ dir: "left" }).error);
});

test("reviewState: defaults without a row, values with one", () => {
  assert.deepEqual(reviewState(undefined), { votes: 0, score: null, note: null, priority: null, reviewed_at: null });
  assert.deepEqual(
    reviewState({ item_id: "x", votes: 2, score: "s", note: "n", priority: 1, updated_at: 42 }),
    { votes: 2, score: "s", note: "n", priority: 1, reviewed_at: 42 },
  );
});

// ---- D1 helpers: SQL shape against a recording stub ---------------------------

function stubDb() {
  const calls = [];
  const db = {
    prepare(sql) {
      const call = { sql, binds: [] };
      calls.push(call);
      return {
        bind(...args) { call.binds = args; return this; },
        run: async () => ({}),
        first: async () => null,
        all: async () => ({ results: [{ item_id: "a", votes: 1, updated_at: 1 }] }),
      };
    },
  };
  return { db, calls };
}

test("loadBoardReviews/getBoardReview target the given table", async () => {
  const { db, calls } = stubDb();
  const map = await loadBoardReviews(db, "feature_reviews");
  assert.equal(map.get("a")?.votes, 1);
  await getBoardReview(db, "feature_reviews", "a");
  assert.match(calls[0].sql, /FROM feature_reviews/);
  assert.match(calls[1].sql, /FROM feature_reviews WHERE item_id = \?/);
  assert.deepEqual(calls[1].binds, ["a"]);
});

test("voteBoardRow: upsert increments votes", async () => {
  const { db, calls } = stubDb();
  await voteBoardRow(db, "t_reviews", "a", -1);
  assert.match(calls[0].sql, /INSERT INTO t_reviews/);
  assert.match(calls[0].sql, /ON CONFLICT\(item_id\) DO UPDATE SET votes = votes \+ \?/);
  assert.equal(calls[0].binds[0], "a");
  assert.equal(calls[0].binds[1], -1);
});

test("patchBoardRow: only present fields in the UPDATE arm; absent fields NULL on insert", async () => {
  const { db, calls } = stubDb();
  await patchBoardRow(db, "t_reviews", "a", { note: "hello" });
  const { sql, binds } = calls[0];
  assert.match(sql, /DO UPDATE SET updated_at = \?, note = \?/);
  assert.ok(!/DO UPDATE SET.*score/.test(sql), "untouched fields must not be clobbered");
  // VALUES(item_id, 0, score, note, priority, updated_at) then SET binds
  assert.equal(binds[0], "a");
  assert.equal(binds[1], null); // score -> NULL on fresh insert
  assert.equal(binds[2], "hello");
  assert.equal(binds[3], null); // priority -> NULL on fresh insert
  assert.equal(binds[5 + 1], "hello"); // the SET arm's note bind
});

// @ts-check
// Time-budget planning for the research pipeline.
//
// The UI slider sends `time_budget_s`; this module decides how to spend it.
// The pipeline has five phase types with very different costs, so planning
// works from measured history:
//
// 1. ROLLING STATS — an EWMA (alpha 0.3) of each phase's duration is kept
//    per model (models differ several-fold in speed), seeded with priors
//    measured on production runs. Stats live per isolate; the priors keep
//    cold isolates sensible. Every completed phase feeds recordPhase().
//    A model can also carry its own prior overrides (src/model-profiles.js)
//    for cases where the global priors are evidenced to be badly wrong for
//    it — consulted only until that model's own EWMA has real data.
//
// 2. STATIC ALLOCATION (planResearch) — before searching begins:
//      fixed  = triage + synthesis            (always paid)
//      avail  = budget - fixed
//      - floor: below one search's cost, run 1 query, nothing else
//      - post-validation is the quality gate: reserved first, unless the
//        budget can't hold it plus a minimal two-search plan
//      - ~60% of the remainder buys initial search angles (1..4)
//      - what's left buys gap-check iterations (each ~ check + 2 searches)
//
// 3. RUNTIME DEADLINE CHECKS (fitsDeadline) — estimates are estimates, so
//    between phases the pipeline re-checks: proceed only if the upcoming
//    work plus the remaining mandatory phases still fit in budget +15%
//    grace. Overruns cut optional work (extra gap rounds first, validation
//    last) instead of blowing the target.

import { getModelProfile } from "./model-profiles.js";

/** @typedef {import('./types.js').SearchDepth} SearchDepth */

/**
 * The static allocation planResearch returns. Same shape as
 * import('./types.js').BudgetPlan, except `estimates` also carries the
 * budget-gated phases (digest/fetch/claim — the PRIORS_MS keys), which the
 * five-phase PhaseName record there predates.
 * @typedef {Object} BudgetPlan
 * @property {number} budgetMs
 * @property {number} budgetS
 * @property {number} queries Initial search angles to run.
 * @property {number} gapIterations Gap-check rounds the budget affords.
 * @property {number} followups Follow-up queries per gap round.
 * @property {boolean} validate Whether the post-validation quality gate is reserved.
 * @property {number} maxSearches Hard cap on total searches across all rounds.
 * @property {number} maxSources Cap on the numbered source registry.
 * @property {number} digestCap Char cap on the synthesis digest.
 * @property {Record<string, number>} estimates Per-phase duration estimates (ms) the plan was built from.
 * @property {SearchDepth} searchDepth
 */

/** @type {Record<string, number>} */
const PRIORS_MS = {
  triage: 6000,
  search: 1300,
  gap: 4500,
  synth: 16000,
  validate: 13000,
  // Budget-gated deep-research phases (only ever run at mid/high tiers — see
  // wantsNotes / wantsFullContent / wantsClaimValidation): the per-wave notes
  // digest, the top-source full-content fetch, and one claim-verification
  // call. Seeded as priors so a cold isolate can budget them before their EWMA
  // warms up; each is dropped first under deadline pressure (fitsDeadline).
  digest: 4000,
  fetch: 2500,
  claim: 3500,
};
const ALPHA = 0.3;
export const MIN_BUDGET_S = 15;
export const MAX_BUDGET_S = 600; // slider tops out at 10 minutes
export const DEFAULT_BUDGET_S = 60;

// ---- rolling per-model phase stats (mechanism 1) ---------------------------

/** @type {Map<string, Record<string, number>>} */
const stats = new Map(); // model -> { phase: ewma_ms }

/**
 * Feeds one completed phase's duration into the model's EWMA. Phases not in
 * PRIORS_MS and non-positive durations are ignored.
 * @param {string} model
 * @param {string} phase
 * @param {number} ms
 */
export function recordPhase(model, phase, ms) {
  if (!(phase in PRIORS_MS) || !(ms > 0)) return;
  const m = stats.get(model) || {};
  m[phase] = m[phase] == null ? ms : Math.round(ALPHA * ms + (1 - ALPHA) * m[phase]);
  stats.set(model, m);
}

/**
 * Per-phase duration estimates for a model: its own EWMA where warmed up,
 * else its model-profile prior override, else the global prior.
 * @param {string} model
 * @returns {Record<string, number>}
 */
export function phaseEstimates(model) {
  const m = stats.get(model) || {};
  const profilePriors = /** @type {Record<string, number> | null} */ (getModelProfile(model).priorsMs);
  /** @type {Record<string, number>} */
  const out = {};
  for (const k of Object.keys(PRIORS_MS)) out[k] = m[k] ?? profilePriors?.[k] ?? PRIORS_MS[k];
  return out;
}

/**
 * @param {unknown} value The raw `time_budget_s` from the request body.
 * @returns {number} Whole seconds within [MIN_BUDGET_S, MAX_BUDGET_S].
 */
export function clampBudget(value) {
  const n = Number(value);
  if (!Number.isFinite(n)) return DEFAULT_BUDGET_S;
  return Math.min(MAX_BUDGET_S, Math.max(MIN_BUDGET_S, Math.round(n)));
}

// ---- static allocation (mechanism 2) ---------------------------------------

// Large budgets buy proportionally MORE work, not just headroom: more
// initial angles (up to 6), more follow-ups per gap round (up to 5), more
// gap rounds (up to 4), a bigger search cap, and a larger source registry
// and digest for synthesis.
/**
 * @param {string} model The user's chosen answer/synthesis model.
 * @param {number} budgetS Clamped time budget in seconds.
 * @param {string} [jsonModel] The fixed model the JSON phases run on (defaults to `model`).
 * @returns {BudgetPlan}
 */
export function planResearch(model, budgetS, jsonModel = model) {
  // The JSON planning phases (triage/gap/validate) run on jsonModel (a fixed
  // reliable model — see pipeline.js), while synthesis runs on the user's
  // chosen `model`; search is Exa (model-independent, recorded under the user
  // model). Estimate each phase against the model that actually runs it so a
  // slow reasoning model as `model` doesn't make the planner over-reserve for
  // triage that a fast Mistral now handles.
  const u = phaseEstimates(model);
  const j = jsonModel === model ? u : phaseEstimates(jsonModel);
  // The digest and claim phases are JSON-mode calls on jsonModel; the
  // full-content fetch is an Exa call (model-independent, estimated off the
  // user model's history like search). These estimates only inform the
  // runtime deadline checks for the budget-gated phases — they do NOT reduce
  // the search/gap allocation below, so planned depth (and hence default
  // behavior) is unchanged at every tier.
  const t = {
    triage: j.triage,
    gap: j.gap,
    validate: j.validate,
    synth: u.synth,
    search: u.search,
    digest: j.digest,
    fetch: u.fetch,
    claim: j.claim,
  };
  const budgetMs = budgetS * 1000;
  /** @type {BudgetPlan} */
  const plan = {
    budgetMs,
    budgetS,
    queries: 1,
    gapIterations: 0,
    followups: 3,
    validate: false,
    maxSearches: 8,
    maxSources: 18,
    digestCap: 14_000,
    estimates: t,
    searchDepth: searchDepthFor(budgetS),
  };

  let avail = budgetMs - t.triage - t.synth;
  if (avail <= t.search) {
    plan.maxSearches = 1;
    return plan; // floor plan
  }

  if (avail >= t.validate + 2 * t.search) {
    plan.validate = true;
    avail -= t.validate;
  }

  // Depth scales with the budget tier.
  const queryCap = budgetS >= 240 ? 6 : 4;
  plan.followups = budgetS >= 420 ? 5 : budgetS >= 240 ? 4 : 3;
  const gapRoundCap = budgetS >= 300 ? 4 : budgetS >= 60 ? 3 : 2;

  plan.queries = Math.max(1, Math.min(queryCap, Math.floor((avail * 0.6) / t.search)));
  let rest = avail - plan.queries * t.search;

  const gapCost = t.gap + 2 * t.search;
  while (plan.gapIterations < gapRoundCap && rest >= gapCost) {
    plan.gapIterations++;
    rest -= gapCost;
  }

  plan.maxSearches = Math.min(20, plan.queries + plan.gapIterations * plan.followups);
  if (plan.maxSearches > 8) {
    plan.maxSources = 24;
    plan.digestCap = 18_000;
  }
  return plan;
}

// Complexity-scaled effort: after triage classifies the question (see
// prompts.js's DECOMPOSITION_RULE), a "simple" question gets its research
// depth capped BELOW what the time budget alone would buy. The project's own
// de-noised benchmark found that extra research machinery at high budgets was
// net-negative on focused questions — the failure mode is OVER-researching a
// simple question because time happens to be available, diluting the answer
// (the same lesson as Anthropic's published effort-scaling rules: simple
// fact-finding warrants a handful of calls, not a survey's worth). Only ever
// scales DOWN — the budget plan remains the ceiling for every complexity —
// and an absent/unknown complexity (schema miss, older model output) leaves
// the plan untouched, so the pre-decomposition behavior is the exact
// fallback. Mutates and returns `plan` (it's the per-request state's plan).
/**
 * @param {BudgetPlan | null | undefined} plan
 * @param {unknown} complexity Triage's classification — only "simple" acts.
 * @returns {BudgetPlan | null | undefined} The same `plan` object.
 */
export function applyComplexityToPlan(plan, complexity) {
  if (!plan || complexity !== "simple") return plan;
  plan.gapIterations = Math.min(plan.gapIterations, 1);
  // One initial wave plus at most one follow-up round's worth of searches.
  plan.maxSearches = Math.min(plan.maxSearches, plan.queries + plan.followups);
  return plan;
}

// A round 6 assessment found the time-budget slider scaled how MANY
// searches ran, but never how deep any single one went: numResults was a
// hardcoded 5 (Exa's own default is 10) and `type` was always "auto",
// never Exa's "deep"/"deep-reasoning" modes — which exist specifically
// for the "spend more time, get a more thorough result" tradeoff a longer
// budget should unlock. Tiered the same way as the angle/round caps
// above. `costMultiplier` reflects Exa's real published pricing ratios
// (search $7/1k, deep $12/1k, deep-reasoning $15/1k as of 2026) relative
// to the admin-configured `exa_cost_per_search_eur`, which is assumed to
// price the standard tier — so usage accounting stays honest instead of
// under-counting real spend when a request uses a costlier tier.
// `type: "deep"` is reserved for the most generous budgets only: it's
// ~1.7x the cost of a standard search, latency is unproven at scale (not
// yet run through a real eval battery — see CLAUDE.md's model-eval
// section), and a short/default request has no business paying for it.
/**
 * @param {number} budgetS
 * @returns {SearchDepth}
 */
function searchDepthFor(budgetS) {
  if (budgetS >= 420) return { numResults: 10, type: "deep", costMultiplier: 12 / 7 };
  if (budgetS >= 240) return { numResults: 10, type: "auto", costMultiplier: 1 };
  if (budgetS >= 60) return { numResults: 8, type: "auto", costMultiplier: 1 };
  return { numResults: 5, type: "auto", costMultiplier: 1 };
}

// Exa's /contents endpoint (the budget-gated full-content fetch) is billed
// well below a standard search (~$1/1k vs $7/1k as of 2026). The admin's
// per-search price is scaled by this ratio per URL fetched, so the top-tier
// full-content spend is counted rather than silently ignored — the same
// approach searchDepth.costMultiplier takes for deeper search tiers.
export const CONTENTS_COST_MULTIPLIER = 1 / 7;

// ---- runtime deadline checks (mechanism 3) ----------------------------------

// True if `upcomingMs` more work still fits within budget (+15% grace).
/**
 * @param {number} startedAt Request start (epoch ms).
 * @param {number} budgetMs
 * @param {number} upcomingMs
 * @returns {boolean}
 */
export function fitsDeadline(startedAt, budgetMs, upcomingMs) {
  return Date.now() - startedAt + upcomingMs <= budgetMs * 1.15;
}

// ---- budget-tier gates for the deep-research phases ------------------------
//
// These decide whether the NEW, optional pipeline phases run at all. They are
// deliberately tiered ABOVE the default budget so a 15-60s request runs
// byte-identically to before these phases existed — wantsNotes is off at the
// 60s default, and full-content / claim-level validation only unlock at the
// long tiers (mirroring searchDepth's own 240s boundary). Under runtime
// deadline pressure each phase additionally gates on fitsDeadline and is
// dropped before synthesis/validation.
//
// DISABLED (2026-07): a de-noised benchmark (4 samples/cell, tests/
// denoise-driver.mjs) found these three phases NET-NEGATIVE at the deep tier —
// batch overall 2.65 (off) → 2.43 (on), with real regressions on focused
// recency/contested questions (calibration bled as distilled notes + full-page
// text diluted the answer) and NO real gain on multi-hop (1.67 → 1.89, inside
// the noise). Multi-hop needs sub-question decomposition, not more source
// material. So the activation is flipped off via this one flag while the code
// is kept for a future INTENT-gated rework (run these only for genuinely broad/
// multi-hop questions, decided by triage — not by budget alone), to be
// re-enabled only once the benchmark shows a real gain. The schema hardening in
// pipeline.js is unaffected (harmless — it only normalizes JSON behind the
// existing fail-soft fallbacks). Re-enable by flipping this to true.
const DEEP_TIER_FEATURES_ENABLED = false;

// Per-wave notes digest: mid tier and up (never at the ≤60s default).
/**
 * @param {BudgetPlan | null | undefined} plan
 * @returns {boolean}
 */
export function wantsNotes(plan) {
  return DEEP_TIER_FEATURES_ENABLED && !!plan && plan.budgetS >= 120;
}

// Full-content fetch of the top sources: only the long tiers (≥240s), where
// there is budget to read whole pages, matching searchDepth's 240s boundary.
/**
 * @param {BudgetPlan | null | undefined} plan
 * @returns {boolean}
 */
export function wantsFullContent(plan) {
  return DEEP_TIER_FEATURES_ENABLED && !!plan && plan.budgetS >= 240;
}

// Claim-level (per-claim) validation instead of the single whole-draft pass:
// long tiers only. A tight budget still runs the cheap single-pass validate.
/**
 * @param {BudgetPlan | null | undefined} plan
 * @returns {boolean}
 */
export function wantsClaimValidation(plan) {
  return DEEP_TIER_FEATURES_ENABLED && !!plan && plan.budgetS >= 240;
}

// (no @ts-check: node:test / node:assert have no type declarations in this
// repo — tsconfig's types is workers-only and @types/node would be a new
// dependency.)
// Covers budget.js: clampBudget, planResearch's tier scaling (incl. the
// split json-model estimates), the deep-tier gates, fitsDeadline's grace
// math, and applyComplexityToPlan's scale-down-only rule.
import { test, describe } from "node:test";
import assert from "node:assert/strict";
import {
  applyComplexityToPlan,
  clampBudget,
  fitsDeadline,
  planResearch,
  recordPhase,
  wantsNotes,
  wantsFullContent,
  wantsClaimValidation,
  MIN_BUDGET_S,
  MAX_BUDGET_S,
  DEFAULT_BUDGET_S,
} from "./budget.js";

describe("clampBudget", () => {
  test("clamps below the floor", () => {
    assert.equal(clampBudget(1), MIN_BUDGET_S);
  });
  test("clamps above the ceiling", () => {
    assert.equal(clampBudget(9999), MAX_BUDGET_S);
  });
  test("rounds fractional values", () => {
    assert.equal(clampBudget(60.6), 61);
  });
  test("falls back to the default for non-numeric input", () => {
    assert.equal(clampBudget("not a number"), DEFAULT_BUDGET_S);
    assert.equal(clampBudget(undefined), DEFAULT_BUDGET_S);
    assert.equal(clampBudget(NaN), DEFAULT_BUDGET_S);
  });
});

describe("planResearch — depth scales with budget tier", () => {
  // A model with no EWMA history and no model-profiles.js override falls
  // back to the global PRIORS_MS — deterministic across test runs.
  const MODEL = "test/unknown-model-" + Math.random();

  test("very short budget produces the floor plan", () => {
    const plan = planResearch(MODEL, 15);
    assert.equal(plan.maxSearches, 1);
    assert.equal(plan.searchDepth.numResults, 5);
    assert.equal(plan.searchDepth.type, "auto");
    assert.equal(plan.searchDepth.costMultiplier, 1);
  });

  test("a slow answer model with a fast JSON model plans MORE work than if the slow model did triage too", () => {
    // The JSON phases (triage/gap/validate) are estimated against jsonModel,
    // so a slow reasoning model as the answer model no longer makes the
    // planner over-reserve for triage a fast Mistral now handles.
    const slow = "test/slow-answer-model-" + Math.random();
    const fast = "test/fast-json-model-" + Math.random();
    // Prime EWMA: slow model's triage is very slow; the fast model's is quick.
    for (let i = 0; i < 20; i++) {
      recordPhase(slow, "triage", 90_000);
      recordPhase(fast, "triage", 4_000);
    }
    const mixed = planResearch(slow, 120, fast);
    const allSlow = planResearch(slow, 120); // jsonModel defaults to the slow model
    assert.ok(
      mixed.queries >= allSlow.queries,
      `mixed (${mixed.queries}) should plan at least as many angles as all-slow (${allSlow.queries})`,
    );
    // The mixed plan's triage estimate reflects the fast JSON model.
    assert.ok(mixed.estimates.triage <= 10_000);
    assert.ok(allSlow.estimates.triage >= 80_000);
  });

  test("default budget (60s) plans a moderate search depth", () => {
    const plan = planResearch(MODEL, 60);
    assert.equal(plan.searchDepth.numResults, 8);
    assert.equal(plan.searchDepth.type, "auto");
    assert.ok(plan.queries >= 1);
  });

  test("long budget (240-419s) requests Exa's own default result count", () => {
    const plan = planResearch(MODEL, 250);
    assert.equal(plan.searchDepth.numResults, 10);
    assert.equal(plan.searchDepth.type, "auto");
    assert.equal(plan.searchDepth.costMultiplier, 1);
  });

  test("the deepest tier (>=420s) switches to Exa's costlier deep mode", () => {
    const plan = planResearch(MODEL, 450);
    assert.equal(plan.searchDepth.numResults, 10);
    assert.equal(plan.searchDepth.type, "deep");
    assert.equal(plan.searchDepth.costMultiplier, 12 / 7);
  });

  test("larger budgets buy more angles, gap rounds, and a bigger source registry", () => {
    const short = planResearch(MODEL, 60);
    const long = planResearch(MODEL, 300);
    assert.ok(long.queries >= short.queries);
    assert.ok(long.gapIterations >= short.gapIterations);
    assert.ok(long.maxSearches >= short.maxSearches);
    assert.ok(long.maxSources >= short.maxSources);
    assert.ok(long.digestCap >= short.digestCap);
  });

  test("every plan carries a searchDepth even on the floor-plan early return", () => {
    // Regression check: searchDepth must be set before the `avail <= search`
    // early return, not only at the end of the function.
    const plan = planResearch(MODEL, MIN_BUDGET_S);
    assert.ok(plan.searchDepth);
    assert.equal(typeof plan.searchDepth.numResults, "number");
  });

  test("validation is reserved unless the budget can't afford it plus a minimal plan", () => {
    const plan = planResearch(MODEL, 60);
    assert.equal(plan.validate, true);
  });
});

describe("planResearch — estimates carry the budget-gated phases", () => {
  const MODEL = "test/estimates-model-" + Math.random();
  test("every plan's estimates include digest/fetch/claim so the deadline checks can budget them", () => {
    const plan = planResearch(MODEL, 300);
    for (const k of ["triage", "gap", "validate", "synth", "search", "digest", "fetch", "claim"]) {
      assert.equal(typeof plan.estimates[k], "number", `estimate ${k} present`);
    }
  });
  test("adding the new phases does not change the planned search/gap allocation", () => {
    // Regression guard: the digest/fetch/claim estimates must NOT be subtracted
    // from avail, so queries/gapIterations/maxSearches stay what they were.
    const plan = planResearch(MODEL, 300);
    assert.ok(plan.queries >= 1 && plan.maxSearches >= plan.queries);
    // A default-budget plan still validates and is unaffected.
    assert.equal(planResearch(MODEL, 60).validate, true);
  });
});

describe("budget-tier gates for the deep-research phases", () => {
  const plan = (s) => planResearch("test/gate-model-" + Math.random(), s);

  test("notes/full-content/claim-validation are ALL off at the 15-60s default tier", () => {
    for (const s of [15, 30, 60]) {
      assert.equal(wantsNotes(plan(s)), false, `notes off at ${s}s`);
      assert.equal(wantsFullContent(plan(s)), false, `full-content off at ${s}s`);
      assert.equal(wantsClaimValidation(plan(s)), false, `claim-validation off at ${s}s`);
    }
  });

  // DISABLED (2026-07): the deep-tier phases are gated off by the
  // DEEP_TIER_FEATURES_ENABLED flag in budget.js after a de-noised benchmark
  // found them net-negative (see the flag's comment). While off, every gate
  // returns false at every tier — so the mid/long tiers behave like the
  // default. The tier boundaries (120s / 240s) are preserved in the gate
  // bodies for the future intent-gated re-enable.
  test("deep-tier phases stay off even at the mid tier (>=120s) while disabled", () => {
    const p = plan(120);
    assert.equal(wantsNotes(p), false);
    assert.equal(wantsFullContent(p), false);
    assert.equal(wantsClaimValidation(p), false);
  });

  test("deep-tier phases stay off even at the long tier (>=240s) while disabled", () => {
    const p = plan(300);
    assert.equal(wantsNotes(p), false);
    assert.equal(wantsFullContent(p), false);
    assert.equal(wantsClaimValidation(p), false);
  });

  test("the gates tolerate a missing/garbage plan without throwing", () => {
    assert.equal(wantsNotes(null), false);
    assert.equal(wantsFullContent(undefined), false);
    assert.equal(wantsClaimValidation({}), false);
  });
});

describe("fitsDeadline", () => {
  test("true when comfortably within budget", () => {
    const startedAt = Date.now() - 1000; // 1s elapsed
    assert.equal(fitsDeadline(startedAt, 60_000, 5_000), true);
  });
  test("false when the upcoming work would blow the budget + grace", () => {
    const startedAt = Date.now() - 55_000; // 55s elapsed of a 60s budget
    assert.equal(fitsDeadline(startedAt, 60_000, 20_000), false);
  });
  test("the 15% grace is actually applied, not just the raw budget", () => {
    const budgetMs = 100_000;
    const startedAt = Date.now() - 100_000; // fully elapsed already
    // 100s elapsed + 12s upcoming = 112s, over the raw 100s budget but
    // under the 115s (budget * 1.15) grace ceiling.
    assert.equal(fitsDeadline(startedAt, budgetMs, 12_000), true);
    // 100s elapsed + 20s upcoming = 120s, over even the grace ceiling.
    assert.equal(fitsDeadline(startedAt, budgetMs, 20_000), false);
  });
});

describe("applyComplexityToPlan — complexity-scaled effort", () => {
  const MODEL = "test/no-history-model-complexity";

  test("'simple' caps gap rounds at 1 and searches at one wave + one follow-up round", () => {
    const plan = planResearch(MODEL, 300);
    assert.ok(plan.gapIterations > 1, "premise: a 300s plan buys >1 gap rounds");
    const out = applyComplexityToPlan(plan, "simple");
    assert.equal(out, plan); // mutates and returns the same plan object
    assert.equal(plan.gapIterations, 1);
    assert.equal(plan.maxSearches, plan.queries + plan.followups);
  });

  test("only ever scales DOWN — a floor plan is not raised", () => {
    const plan = planResearch(MODEL, 15);
    const before = { ...plan };
    applyComplexityToPlan(plan, "simple");
    assert.ok(plan.gapIterations <= before.gapIterations);
    assert.ok(plan.maxSearches <= before.maxSearches);
  });

  test("non-simple complexities leave the plan untouched (budget stays the ceiling)", () => {
    for (const complexity of ["multihop", "comparison", "survey"]) {
      const plan = planResearch(MODEL, 300);
      const before = JSON.stringify(plan);
      applyComplexityToPlan(plan, complexity);
      assert.equal(JSON.stringify(plan), before, complexity);
    }
  });

  test("absent/unknown complexity (schema miss, older model output) is a no-op", () => {
    for (const complexity of [null, undefined, "extreme", 42]) {
      const plan = planResearch(MODEL, 300);
      const before = JSON.stringify(plan);
      applyComplexityToPlan(plan, complexity);
      assert.equal(JSON.stringify(plan), before, String(complexity));
    }
  });

  test("a missing plan is tolerated", () => {
    assert.equal(applyComplexityToPlan(null, "simple"), null);
  });
});

