// @ts-check
// Global site configuration: default quotas, Exa pricing, the time-budget
// cap, the site default model, and the approval gate. Stored as one JSON
// row in the D1 `config` table (admin-editable via PUT /api/admin/config),
// cached ~30 s per isolate. Without a DB binding the defaults apply.
//
// Quota semantics (what the numbers mean, enforcement in src/quota.js):
//   - budget_eur: Berget COST cap per window (0 = uncapped)
//   - searches:   Exa search COUNT cap per window (0 = uncapped)

import { getDb } from "./db.js";
import { PERIODS } from "./quota.js";

/** @typedef {import('./types.js').Env} Env */
/** @typedef {import('./quota.js').QuotaMap} QuotaMap */

/**
 * The effective site configuration `getConfig` resolves (defaults merged
 * with the admin-edited D1 row).
 * @typedef {Object} SiteConfig
 * @property {QuotaMap} quotas default per-window quotas (h5/day/week/month)
 * @property {number} exa_cost_per_search_eur
 * @property {number} max_time_budget_s cap for the UI slider value accepted server-side
 * @property {string} default_model empty = Worker default (BERGET_MODEL var / built-in)
 * @property {boolean} require_approval new sign-ins land as "pending" until approved
 * @property {number} anim_speed intro-animation speed multiplier (1 = the
 *   default pace, which is itself 2.5× the original — see BASE_SPEED in
 *   public/cure/umbrella.js); served publicly via GET /api/anim
 */

/** @type {SiteConfig} */
export const DEFAULT_CONFIG = {
  quotas: {
    h5: { budget_eur: 0.25, searches: 30 },
    day: { budget_eur: 0.5, searches: 100 },
    week: { budget_eur: 2, searches: 400 },
    month: { budget_eur: 6, searches: 1200 },
  },
  exa_cost_per_search_eur: 0.005,
  max_time_budget_s: 600, // cap for the UI slider value accepted server-side
  default_model: "", // empty = Worker default (BERGET_MODEL var / built-in)
  // Approval gate: new Google sign-ins land as status "pending" (waiting
  // page, no API access) until the admin approves them in /admin.
  require_approval: true,
  // The /cure first-visit umbrella intro's speed, relative to its default
  // pace (admin slider in /admin; the slider's center is exactly this 1).
  anim_speed: 1,
};

/** @type {{ at: number, value: SiteConfig | null }} */
let configCache = { at: 0, value: null };
const CONFIG_TTL_MS = 30_000;

/**
 * The current site config: the cached D1 row merged over the defaults, or a
 * fresh clone of the defaults when no database is configured.
 * @param {Env} env
 * @returns {Promise<SiteConfig>}
 */
export async function getConfig(env) {
  const db = await getDb(env);
  if (!db) return structuredClone(DEFAULT_CONFIG);
  if (configCache.value && Date.now() - configCache.at < CONFIG_TTL_MS) {
    return configCache.value;
  }
  const row = await db.prepare("SELECT value FROM config WHERE key='app'").first();
  let stored = {};
  try {
    stored = row ? JSON.parse(String(row.value)) : {};
  } catch {
    stored = {};
  }
  const merged = mergeConfig(DEFAULT_CONFIG, stored);
  configCache = { at: Date.now(), value: merged };
  return merged;
}

/**
 * Merges a sanitized admin patch into the stored config and refreshes the
 * cache. Throws without a database (the admin API surfaces the error).
 * @param {Env} env
 * @param {any} patch untrusted admin request body
 * @returns {Promise<SiteConfig>} the new effective config
 */
export async function saveConfig(env, patch) {
  const db = await getDb(env);
  if (!db) throw new Error("Database not configured.");
  const current = await getConfig(env);
  const next = mergeConfig(current, sanitizeConfigPatch(patch));
  await db
    .prepare("INSERT INTO config (key, value) VALUES ('app', ?) ON CONFLICT(key) DO UPDATE SET value=excluded.value")
    .bind(JSON.stringify(next))
    .run();
  configCache = { at: Date.now(), value: next };
  return next;
}

/**
 * Overlays `patch` on `base` field by field, coercing/clamping each value so
 * a malformed or hostile patch can only ever produce a valid config.
 * @param {SiteConfig} base
 * @param {any} patch
 * @returns {SiteConfig}
 */
function mergeConfig(base, patch) {
  const out = structuredClone(base);
  if (!patch || typeof patch !== "object") return out;
  for (const p of PERIODS) {
    const q = patch.quotas?.[p];
    if (q && typeof q === "object") {
      if (Number.isFinite(q.budget_eur)) out.quotas[p].budget_eur = Math.max(0, q.budget_eur);
      if (Number.isFinite(q.searches)) out.quotas[p].searches = Math.max(0, Math.round(q.searches));
    }
  }
  if (Number.isFinite(patch.exa_cost_per_search_eur)) {
    out.exa_cost_per_search_eur = Math.max(0, patch.exa_cost_per_search_eur);
  }
  if (Number.isFinite(patch.max_time_budget_s)) {
    out.max_time_budget_s = Math.min(600, Math.max(15, Math.round(patch.max_time_budget_s)));
  }
  if (typeof patch.default_model === "string") out.default_model = patch.default_model;
  if (typeof patch.require_approval === "boolean") out.require_approval = patch.require_approval;
  if (Number.isFinite(patch.anim_speed)) {
    // Same clamp as the client's clampAnimMult: a hostile patch can only
    // ever slow to ¼× or hasten to 4× the default.
    out.anim_speed = Math.min(4, Math.max(0.25, patch.anim_speed));
  }
  return out;
}

/**
 * Only known keys survive into storage (an admin API caller can't stuff
 * arbitrary JSON into config).
 * @param {any} patch
 */
function sanitizeConfigPatch(patch) {
  return {
    quotas: patch?.quotas,
    exa_cost_per_search_eur: numOr(patch?.exa_cost_per_search_eur),
    max_time_budget_s: numOr(patch?.max_time_budget_s),
    default_model: patch?.default_model,
    require_approval: patch?.require_approval,
    anim_speed: numOr(patch?.anim_speed),
  };
}
/** @param {any} v @returns {number | undefined} */
const numOr = (v) => (Number.isFinite(Number(v)) && v !== null && v !== "" ? Number(v) : undefined);

// @ts-check
// Utilities over the OpenAI-style message array: content is either a plain
// string or a multimodal array of {type:"text",text} and
// {type:"image_url",image_url:{url}} parts.
//
// These traversal helpers manipulate content parts dynamically (mapping over
// a mixed part array, editing the text part in place), so they type content
// as `string | any[]` rather than the precise discriminated `ContentPart`
// union from types.d.ts — that union documents the shape for the pipeline,
// but narrowing it across filter/map here would need casts that add noise
// without adding safety. The precise Conversation/Message types are still
// used where property access is straightforward.

/** @typedef {string | any[]} Content */
/** @typedef {{ role?: string, content?: Content }} Msg */

const HISTORY_TURNS = 8; // conversation turns included in LLM prompts

// Text view of a message's content; multimodal arrays become concatenated
// text parts plus an "[N image(s) attached]" marker. Used by the JSON-mode
// helper phases, which are text-only.
/**
 * @param {Content} [content]
 * @returns {string}
 */
export function textOf(content) {
  if (typeof content === "string") return content;
  if (Array.isArray(content)) {
    const text = content
      .filter((p) => p?.type === "text" && typeof p.text === "string")
      .map((p) => p.text)
      .join("\n");
    const images = content.filter((p) => p?.type === "image_url").length;
    return images
      ? `${text}${text ? "\n" : ""}[${images} image${images === 1 ? "" : "s"} attached]`
      : text;
  }
  return "";
}

/**
 * @param {Msg[]} messages
 * @returns {number}
 */
export function countImages(messages) {
  let n = 0;
  for (const m of messages) {
    if (Array.isArray(m?.content)) {
      n += m.content.filter((p) => p?.type === "image_url").length;
    }
  }
  return n;
}

/**
 * @param {Msg[]} conversation
 * @returns {Msg | undefined}
 */
export function lastUserMessage(conversation) {
  return [...conversation].reverse().find((m) => m.role === "user");
}

// Text of the user message BEFORE the latest one (the prior turn's question),
// or "" when there is no earlier user turn. Triage's fallback uses it to seed
// a search from the established topic when the latest message is a bare
// back-reference ("undersök saken", "tell me more") whose literal text would
// be a meaningless query on its own.
/**
 * @param {Msg[]} conversation
 * @returns {string}
 */
export function previousUserText(conversation) {
  const users = conversation.filter((m) => m?.role === "user");
  return users.length >= 2 ? textOf(users[users.length - 2].content) : "";
}

// Image parts of a message's multimodal content (empty for string content).
/**
 * @param {Msg} [message]
 * @returns {any[]}
 */
export function imagePartsOf(message) {
  return Array.isArray(message?.content)
    ? message.content.filter((p) => p?.type === "image_url")
    : [];
}

/**
 * @param {Msg[]} conversation
 * @returns {string}
 */
export function formatConversation(conversation) {
  return conversation
    .slice(-HISTORY_TURNS)
    .map((m) => `${m.role === "user" ? "User" : "Assistant"}: ${textOf(m.content).slice(0, 2000)}`)
    .join("\n");
}

// Image-only sends ("what is this?" implied) otherwise read as an empty
// message and get ignored: give the model an explicit instruction. Only the
// outgoing copy is modified.
/**
 * @param {Msg[]} conversation
 * @returns {Msg[]}
 */
export function withImageNudge(conversation) {
  const last = conversation[conversation.length - 1];
  if (!last || last.role !== "user" || !Array.isArray(last.content)) return conversation;
  const hasText = last.content.some((p) => p?.type === "text" && p.text.trim());
  const hasImage = last.content.some((p) => p?.type === "image_url");
  if (hasText || !hasImage) return conversation;
  return [
    ...conversation.slice(0, -1),
    {
      ...last,
      content: [
        { type: "text", text: "(No text was provided.) Describe and analyze the attached image(s) helpfully." },
        ...last.content,
      ],
    },
  ];
}

// Appends server-resolved context (e.g. geocode.js's reverse-geocoded photo
// locations) to the LAST message — content the client couldn't have known
// ahead of time. Handles string content, array content with an existing
// text part, and array content with none (image-only send). Non-mutating,
// same convention as withImageNudge; a no-op when there's nothing to add.
/**
 * @param {Msg[]} conversation
 * @param {string} extraText
 * @returns {Msg[]}
 */
export function withAppendedText(conversation, extraText) {
  if (!extraText || conversation.length === 0) return conversation;
  const last = conversation[conversation.length - 1];
  if (typeof last.content === "string") {
    return [...conversation.slice(0, -1), { ...last, content: last.content + extraText }];
  }
  if (Array.isArray(last.content)) {
    const idx = last.content.findIndex((p) => p?.type === "text");
    const content =
      idx >= 0
        ? last.content.map((p, i) => (i === idx ? { ...p, text: p.text + extraText } : p))
        : [{ type: "text", text: extraText }, ...last.content];
    return [...conversation.slice(0, -1), { ...last, content }];
  }
  return conversation;
}

// Appends a server-fetched image (e.g. googlemaps.js's Street View / map) as
// an image_url part on the LAST message, so a vision model can see it exactly
// like a user-attached image. String content becomes a two-part array (its
// text plus the image); array content gets the image pushed on the end.
// Non-mutating, same convention as withAppendedText; a no-op when there's no
// url or no last message. Callers must only use this when the answering model
// is vision-capable (Berget rejects images on text-only models).
/**
 * @param {Msg[]} conversation
 * @param {string} url
 * @returns {Msg[]}
 */
export function withAppendedImage(conversation, url) {
  if (!url || conversation.length === 0) return conversation;
  const last = conversation[conversation.length - 1];
  const part = { type: "image_url", image_url: { url } };
  if (typeof last.content === "string") {
    const content = last.content
      ? [{ type: "text", text: last.content }, part]
      : [part];
    return [...conversation.slice(0, -1), { ...last, content }];
  }
  if (Array.isArray(last.content)) {
    return [...conversation.slice(0, -1), { ...last, content: [...last.content, part] }];
  }
  return conversation;
}

// Unit tests for conversation.js: the message-array/content helpers (text
// view, image counting, last/previous user turn, non-mutating appenders).
import { test, describe } from "node:test";
import assert from "node:assert/strict";
import { textOf, countImages, lastUserMessage, previousUserText, imagePartsOf, formatConversation, withImageNudge, withAppendedText, withAppendedImage } from "./conversation.js";

describe("previousUserText", () => {
  test("returns the user message before the latest one", () => {
    const convo = [
      { role: "user", content: "first question about Northvolt" },
      { role: "assistant", content: "some answer" },
      { role: "user", content: "undersök saken" },
    ];
    assert.equal(previousUserText(convo), "first question about Northvolt");
  });

  test("returns empty string when there is only one user turn", () => {
    assert.equal(previousUserText([{ role: "user", content: "only message" }]), "");
    assert.equal(previousUserText([]), "");
  });

  test("reads text out of multimodal content", () => {
    const convo = [
      { role: "user", content: [{ type: "text", text: "look at this" }, { type: "image_url", image_url: { url: "data:," } }] },
      { role: "assistant", content: "ok" },
      { role: "user", content: "and now?" },
    ];
    assert.match(previousUserText(convo), /look at this/);
  });
});

describe("textOf", () => {
  test("plain string content passes through", () => {
    assert.equal(textOf("hello"), "hello");
  });
  test("multimodal array concatenates text parts", () => {
    const content = [{ type: "text", text: "part one" }, { type: "text", text: "part two" }];
    assert.equal(textOf(content), "part one\npart two");
  });
  test("images append a count marker", () => {
    const content = [
      { type: "text", text: "look at this" },
      { type: "image_url", image_url: { url: "data:image/png;base64,x" } },
    ];
    assert.equal(textOf(content), "look at this\n[1 image attached]");
  });
  test("image-only content still gets the marker, singular vs plural", () => {
    const one = [{ type: "image_url", image_url: { url: "x" } }];
    const two = [{ type: "image_url", image_url: { url: "x" } }, { type: "image_url", image_url: { url: "y" } }];
    assert.equal(textOf(one), "[1 image attached]");
    assert.equal(textOf(two), "[2 images attached]");
  });
  test("non-string, non-array content returns empty string, not a throw", () => {
    assert.equal(textOf(null), "");
    assert.equal(textOf(undefined), "");
    assert.equal(textOf(42), "");
  });
});

describe("countImages", () => {
  test("counts image_url parts across all messages", () => {
    const messages = [
      { role: "user", content: "text only" },
      { role: "user", content: [{ type: "image_url", image_url: { url: "a" } }] },
      { role: "assistant", content: [{ type: "image_url", image_url: { url: "b" } }, { type: "image_url", image_url: { url: "c" } }] },
    ];
