// Additive migrations for databases created before the column existed.
// "duplicate column" failures are expected and swallowed; anything else in
// here must stay idempotent-or-ignorable.
const ALTERS = [
  "ALTER TABLE users ADD COLUMN google_sub TEXT",
  "ALTER TABLE users ADD COLUMN terms_accepted_at INTEGER",
  "ALTER TABLE users ADD COLUMN settings_json TEXT",
];

let migrated = false; // per isolate

/**
 * Returns the D1 binding with schema applied, or null when the database is
 * not configured. Callers must handle null (feature off, not an error).
 * @param {import('./types.js').Env} env
 * @returns {Promise<D1Database | null>}
 */
export async function getDb(env) {
  const db = env.DB;
  if (!db) return null;
  if (!migrated) {
    const statements = SCHEMA.split(";")
      .map((s) => s.trim())
      .filter(Boolean)
      .map((s) => db.prepare(s));
    await db.batch(statements);
    for (const alter of ALTERS) {
      await db.prepare(alter).run().catch(() => {});
    }
    migrated = true;
  }
  return db;
}

// @ts-check
// Fail-soft helpers for the Workers Cache API (caches.default) — the
// cross-request result cache exa.js and googlemaps.js share the pattern of:
// durable across requests in a colo, shared across isolates, TTL'd via
// Cache-Control, no binding needed. Both directions fail soft: any cache
// error just means a live call (read) or an uncached response (write), never
// a failed request. Cache keys are synthetic `.internal` URLs built by each
// caller (they namespace the entries and never leave the isolate).
//
// The hit/miss decision (and its per-caller log line with per-caller fields)
// stays at the call site — these helpers own only the mechanics and the
// `<event>_read_failed` / `<event>_write_failed` warnings, keeping every
// pre-existing log event name intact.

// Reads and JSON-parses a cached entry. Returns the parsed payload, or null
// on a miss, a parse failure, or when the Cache API isn't available (e.g.
// unit tests in Node). `event` is the log-event prefix (e.g. "exa.cache").
/**
 * @param {import('./types.js').Logger} log
 * @param {string} event log-event prefix, e.g. "exa.cache"
 * @param {string} cacheKey synthetic `.internal` URL key
 * @returns {Promise<any | null>}
 */
export async function cacheGet(log, event, cacheKey) {
  const cache = /** @type {any} */ (globalThis).caches?.default;
  if (!cache) return null;
  try {
    const hit = await cache.match(new Request(cacheKey));
    if (!hit) return null;
    return await hit.json();
  } catch (err) {
    log.warn(`${event}_read_failed`, { error: /** @type {any} */ (err)?.message || String(err) });
    return null;
  }
}

// Stores a JSON payload under the key with a max-age TTL. A write failure is
// logged and swallowed — it never affects the response being served.
/**
 * @param {import('./types.js').Logger} log
 * @param {string} event log-event prefix, e.g. "exa.cache"
 * @param {string} cacheKey synthetic `.internal` URL key
 * @param {unknown} value JSON-serializable payload to store
 * @param {number} ttlS max-age TTL in seconds
 * @returns {Promise<void>}
 */
export async function cachePut(log, event, cacheKey, value, ttlS) {
  const cache = /** @type {any} */ (globalThis).caches?.default;
  if (!cache) return;
  try {
    await cache.put(
      new Request(cacheKey),
      new Response(JSON.stringify(value), {
        headers: {
          "content-type": "application/json",
          "cache-control": `max-age=${ttlS}`,
        },
      }),
    );
  } catch (err) {
    log.warn(`${event}_write_failed`, { error: /** @type {any} */ (err)?.message || String(err) });
  }
}

// Unit tests for edge-cache.js's fail-soft Workers Cache get/put helpers,
// exercised against a mocked Cache API.
import { test, describe, afterEach } from "node:test";
import assert from "node:assert/strict";

import { cacheGet, cachePut } from "./edge-cache.js";

// A log stub that records warn calls so the fail-soft paths can be asserted.
function stubLog() {
  const warns = [];
  return { warns, warn: (event, fields) => warns.push({ event, fields }) };
}

// Node has no Cache API, so `globalThis.caches` is installed per test with a
// minimal match/put double and removed afterwards.
function installCache(cache) {
  globalThis.caches = { default: cache };
}

afterEach(() => {
  delete globalThis.caches;
});

describe("cacheGet", () => {
  test("returns null without a Cache API (Node, tests)", async () => {
    const log = stubLog();
    assert.equal(await cacheGet(log, "x.cache", "https://c.internal/k"), null);
    assert.equal(log.warns.length, 0);
  });

  test("returns null on a miss", async () => {
    installCache({ match: async () => undefined });
    const log = stubLog();
    assert.equal(await cacheGet(log, "x.cache", "https://c.internal/k"), null);
    assert.equal(log.warns.length, 0);
  });

  test("returns the parsed payload on a hit", async () => {
    installCache({ match: async () => new Response(JSON.stringify({ a: 1 })) });
    const log = stubLog();
    assert.deepEqual(await cacheGet(stubLog(), "x.cache", "https://c.internal/k"), { a: 1 });
    assert.equal(log.warns.length, 0);
  });

  test("a read error is warned as <event>_read_failed and returns null", async () => {
    installCache({ match: async () => { throw new Error("boom"); } });
    const log = stubLog();
    assert.equal(await cacheGet(log, "x.cache", "https://c.internal/k"), null);
    assert.equal(log.warns.length, 1);
    assert.equal(log.warns[0].event, "x.cache_read_failed");
    assert.equal(log.warns[0].fields.error, "boom");
  });

  test("an unparseable cached body degrades to a miss (fail-soft)", async () => {
    installCache({ match: async () => new Response("not json") });
    const log = stubLog();
    assert.equal(await cacheGet(log, "x.cache", "https://c.internal/k"), null);
    assert.equal(log.warns.length, 1);
    assert.equal(log.warns[0].event, "x.cache_read_failed");
  });
});

describe("cachePut", () => {
  test("no-op without a Cache API", async () => {
    const log = stubLog();
    await cachePut(log, "x.cache", "https://c.internal/k", { a: 1 }, 600);
    assert.equal(log.warns.length, 0);
  });

  test("stores JSON with the max-age TTL", async () => {
    const puts = [];
    installCache({ put: async (req, resp) => puts.push({ req, resp }) });
    await cachePut(stubLog(), "x.cache", "https://c.internal/k", { a: 1 }, 600);
    assert.equal(puts.length, 1);
    assert.equal(puts[0].req.url, "https://c.internal/k");
    assert.equal(puts[0].resp.headers.get("cache-control"), "max-age=600");
    assert.equal(puts[0].resp.headers.get("content-type"), "application/json");
    assert.deepEqual(await puts[0].resp.json(), { a: 1 });
  });

  test("a write error is warned as <event>_write_failed and swallowed", async () => {
    installCache({ put: async () => { throw new Error("full"); } });
    const log = stubLog();
    await cachePut(log, "x.cache", "https://c.internal/k", { a: 1 }, 600);
    assert.equal(log.warns.length, 1);
    assert.equal(log.warns[0].event, "x.cache_write_failed");
    assert.equal(log.warns[0].fields.error, "full");
  });
});

// @ts-check
// Pre-pipeline context enrichments: the opt-in Shodan and Google Maps
// phases that resolve things the latest message NAMES (a host/IP, a street
// address, an attached photo's GPS) into labeled context blocks appended to
// the conversation before any model call — so triage, search, and synthesis
// all see the data. Extracted from pipeline.js so the phase orchestrator
// stays about the research flow itself; both enrichments follow the same
// contract: silent (no step, no conversation change) when the message names
// nothing to look up, a visible activity step naming the external service
// when it does, and fail-soft in every branch — the conversation comes back
// unchanged rather than ever blocking a chat. The Google Maps runners
// live in src/maps-enrichment.js (split 2026-07-09 with the maps
// subsystem refactor); this module owns the registry and Shodan.

import { lastUserMessage, textOf, withAppendedText } from "./conversation.js";
import { runIntrospectionEnrichment } from "./introspect.js";
import { runGoogleMapsEnrichment } from "./maps-enrichment.js";
import { extractTargets, runShodanLookup } from "./shodan.js";

/** @typedef {import('./types.js').Env} Env */
/** @typedef {import('./types.js').Logger} Logger */
/** @typedef {import('./types.js').Conversation} Conversation */
/** @typedef {import('./types.js').RequestState} RequestState */

/**
 * The bundle handed to each enrichment's `run` — the same emit/step
 * helpers pipeline.js's ctx carries, before that ctx exists.
 * @typedef {{
 *   env: Env,
 *   log: Logger,
 *   emit: (event: object) => void,
 *   step: (id: string, label: string) => void,
 *   stepDone: (id: string, label: string, details?: string[]) => void,
 *   conversation: Conversation,
 *   state: RequestState,
 * }} EnrichmentCtx
 */

/**
 * One registry entry: `id` is the log/step slug, `enabled` the per-user
 * knob gate (resolved onto the state in chat.js), and `run` returns the
 * (possibly augmented) conversation.
 * @typedef {{
 *   id: string,
 *   enabled: (state: RequestState) => boolean,
 *   run: (ctx: EnrichmentCtx) => Promise<Conversation>,
 * }} Enrichment
 */

// The enrichment registry — the pre-pipeline counterpart of the
// search-source registry (src/search-sources.js), and for the same
// parallel-work reason: a new enrichment is ONE runner in this file plus
// ONE entry here; pipeline.js calls runEnrichments() once and never names
// an individual enrichment. Order matters and is deliberate: each runner
// sees the conversation as left by the previous one. Every runner must
// keep the standing contract: silent when the message names nothing to
// look up, a visible step naming the external service when it does,
// fail-soft in every branch.
/** @type {Enrichment[]} */
const ENRICHMENTS = [
  {
    id: "shodan",
    enabled: (state) => !!state.shodan,
    run: (c) => runShodanEnrichment(c.env, c.log, c.step, c.stepDone, c.conversation, c.state),
  },
  {
    id: "maps",
    enabled: (state) => !!state.googleMaps,
    // Casts: the maps runner reads its own state extension (mapView,
    // userLocation — set by chat.js when the knob is on) that this
    // enrichment-agnostic registry deliberately doesn't model, and hands
    // back conversation.js's looser Msg shape (appending blocks/images
    // can't loosen the roles the Conversation arrived with).
    run: (c) =>
      /** @type {Promise<Conversation>} */ (
        runGoogleMapsEnrichment(c.env, c.log, c.emit, c.step, c.stepDone, c.conversation,
          /** @type {import('./maps-enrichment.js').MapsState} */ (c.state))
      ),
  },
  {
    // Introspection (developer mode): a conversation asking about THIS
    // SITE's own implementation gets the deployed source snapshot appended
    // as context (src/introspect.js). Silent unless the conversation
    // engages the mode (EN+SV gate / a named repo path — introspect-core.js).
    id: "introspect",
    enabled: (state) => !!state.introspection,
    run: (c) => runIntrospectionEnrichment(c.env, c.log, c.step, c.stepDone, c.conversation, c.state),
  },
];

// Runs every knob-enabled enrichment in registry order. A throwing runner
// is contained here (the conversation passes through unchanged) so a buggy
// enrichment can never take down the chat — same fail-soft rule its
// internals already follow.
/**
 * @param {Env} env
 * @param {Logger} log
 * @param {EnrichmentCtx['emit']} emit
 * @param {EnrichmentCtx['step']} step
 * @param {EnrichmentCtx['stepDone']} stepDone
 * @param {Conversation} conversation
 * @param {RequestState} state
 * @returns {Promise<Conversation>}
 */
export async function runEnrichments(env, log, emit, step, stepDone, conversation, state) {
  let convo = conversation;
  for (const e of ENRICHMENTS) {
    if (!e.enabled(state)) continue;
    try {
      convo = await e.run({ env, log, emit, step, stepDone, conversation: convo, state });
    } catch (/** @type {any} */ err) {
      log.warn(`${e.id}.enrichment_failed`, { error: err?.message || String(err) });
    }
  }
  return convo;
}

// Shodan enrichment: resolve any host/IP the latest message names into
// live infrastructure data and append it as a labeled context block —
// an ordinary question with the knob left on costs nothing and shows no
// spurious step. Otherwise it emits a visible activity step whose
// expandable details list each host, and returns the augmented
// conversation.
/**
 * @param {Env} env
 * @param {Logger} log
 * @param {EnrichmentCtx['step']} step
 * @param {EnrichmentCtx['stepDone']} stepDone
 * @param {Conversation} conversation
 * @param {RequestState} state
 * @returns {Promise<Conversation>}
 */
export async function runShodanEnrichment(env, log, step, stepDone, conversation, state) {
  const lastUser = textOf(lastUserMessage(conversation)?.content);
  const { ips, hostnames } = extractTargets(lastUser);
  if (!ips.length && !hostnames.length) return conversation;

  step("shodan", "Querying Shodan…");
  let result = null;
  try {
    result = await runShodanLookup(env, log, conversation);
  } catch (/** @type {any} */ err) {
    log.warn("shodan.phase_failed", { error: err?.message || String(err) });
  }
  if (!result) {
    stepDone("shodan", "Shodan lookup unavailable — continuing without it");
    return conversation;
  }
  state.shodanCount = result.count;
  const label = result.count
    ? `Shodan: ${result.count} host${result.count === 1 ? "" : "s"} found`
    : "Shodan: no records for the host(s) named";
  stepDone("shodan", label, result.details);
  // Cast: conversation.js works on its looser local Msg shape; appending a
  // text block can't loosen the roles this Conversation arrived with.
  return /** @type {Conversation} */ (withAppendedText(conversation, result.block));
}

// @ts-check
// Exa web search — backs the model's `web_search` tool.
//
// REST call to POST https://api.exa.ai/search with the EXA_API_KEY secret in
// the x-api-key header. See CLAUDE.md ("Web search — Exa") for parameter
// rules and the canonical reference URL.

import { cacheGet, cachePut } from "./edge-cache.js";

const EXA_URL = "https://api.exa.ai/search";
const EXA_CONTENTS_URL = "https://api.exa.ai/contents";
// Bounds the /contents fetch the same way the two Berget calls are bounded —
// an unbounded fetch has bitten this project before. Full-content fetch is
// budget-gated top-tier work, so a hung backend must degrade, never hang.
const CONTENTS_TIMEOUT_MS = 20_000;
// Bounds the /search fetch the same way — the search wave is the pipeline's
// hot path, so a hung Exa backend must degrade to a failure() string (which
// the pipeline carries on with), never hang the request. A TimeoutError from
// AbortSignal lands in webSearch's existing catch below, same as any other
// fetch rejection.
const SEARCH_TIMEOUT_MS = 15_000;
// Cap the extracted text per source so a handful of long pages can't blow the
// synthesis digest / Worker memory. Generous enough to carry a real article.
const CONTENTS_MAX_CHARS = 6000;

// Cross-request search cache. A follow-up turn is a SEPARATE /api/chat
// request, so the in-request dedup (pipeline.js's state.ranQueries) can't
// stop it re-issuing a query an earlier turn already ran — the reported
// "exact same web search again". Caching the RESULTS keyed by the query
// makes that repeat a free, instant cache hit instead of a paid Exa call.
// Uses the Workers Cache API (caches.default): durable across requests in a
// colo, shared across isolates, TTL'd via Cache-Control, and needs no
// binding. Everything here is fail-soft — any cache error just falls
// through to a normal live search.
const CACHE_TTL_S = 600; // 10 min: long enough to absorb a follow-up
// re-issuing the same query within one research session, short enough that
// "latest"-type queries don't serve staled results across sessions.

// Stable cache key for a search. The query is normalized (trimmed,
// lowercased, whitespace collapsed) — the SAME normalization pipeline.js
// uses for its in-request dedup — so trivially-different spellings of the
// same search share one entry and the depth tier (type + numResults) is
// part of the key so a deeper re-run isn't served a shallower cached result.
// Exported for unit testing; the .internal host is a synthetic key namespace
// that never leaves the isolate.
/**
 * @param {string} query
 * @param {string} type Exa search mode ("auto" | "deep" | …)
 * @param {number} numResults
 * @returns {string} a synthetic `.internal` cache-key URL
 */
export function searchCacheKey(query, type, numResults) {
  const q = String(query || "").trim().toLowerCase().replace(/\s+/g, " ");
  const params = new URLSearchParams({ q, t: String(type), n: String(numResults) });
  return `https://exa-search-cache.internal/search?${params.toString()}`;
}

// Runs a search and returns:
//   content    — compact LLM-friendly string (numbered title/URL/highlights);
//                errors come back as strings too, so the pipeline can carry
//                on instead of the request 500ing
//   items      — [{title, url, highlights[]}] structured results for the
//                pipeline's cross-search source registry
//   sources    — [{title, url}] for the UI's expandable activity panel
//   resultCount, durationMs — for UI counters and logs
//
// depth (src/budget.js's plan.searchDepth): { numResults, type } — scales
// with the time budget instead of a fixed 5-result "auto" search
// regardless of how much depth the user actually asked for.
/**
 * One structured result carried to the pipeline's source registry.
 * @typedef {{ title: string, url: string, highlights: string[] }} SearchItem
 */
/**
 * The bundle webSearch resolves to (errors come back as `content` strings,
 * never thrown, so the pipeline can carry on).
 * @typedef {object} SearchResult
 * @property {string} content compact LLM-friendly numbered digest
 * @property {SearchItem[]} items structured results for the source registry
 * @property {import('./types.js').SseSource[]} sources title/url pairs for the UI
 * @property {number} resultCount
 * @property {number} durationMs
 * @property {boolean} [cached] true when served from the edge cache
 */
/**
 * @param {import('./types.js').Env} env
 * @param {import('./types.js').Logger} log
 * @param {string} query
 * @param {{ numResults?: number, type?: string }} [depth] the budget's search-depth tier
 * @returns {Promise<SearchResult>}
 */
export async function webSearch(env, log, query, depth = {}) {
  const numResults = depth.numResults || 5;
  const type = depth.type || "auto";
  const startedAt = Date.now();
  /** @param {string} content */
  const failure = (content) => ({
    content,
    items: [],
    sources: [],
    resultCount: 0,
    durationMs: Date.now() - startedAt,
  });

  if (!env.EXA_API_KEY) {
    log.error("exa.misconfigured", { missing: "EXA_API_KEY" });
    return failure("Web search is unavailable: EXA_API_KEY is not configured.");
  }
  if (!query) {
    log.warn("exa.empty_query", {});
    return failure("No search query was provided.");
  }

  log.debug("exa.search_query", { query }); // user content: debug level only

  // Serve an identical earlier search from the edge cache if it's still
  // fresh — a repeated query (e.g. a follow-up turn) costs nothing and
  // returns instantly. Fail-soft: any cache miss/error falls through to a
  // live search below.
  const cacheKey = searchCacheKey(query, type, numResults);
  const cached = await cacheGet(log, "exa.cache", cacheKey);
  if (cached) {
    log.info("exa.cache_hit", {
      duration_ms: Date.now() - startedAt,
      results: cached.resultCount,
      query_chars: query.length,
      type,
    });
    return { ...cached, durationMs: Date.now() - startedAt, cached: true };
  }

  let resp;
  try {
    resp = await fetch(EXA_URL, {
      method: "POST",
      headers: {
        "content-type": "application/json",
        "x-api-key": env.EXA_API_KEY,
      },
      body: JSON.stringify({
        query,
        type,
        numResults,
        contents: { highlights: true },
      }),
      signal: AbortSignal.timeout(SEARCH_TIMEOUT_MS),
    });
  } catch (err) {
    const msg = /** @type {any} */ (err)?.message || String(err);
    log.error("exa.request_failed", { error: msg, duration_ms: Date.now() - startedAt });
    return failure(`Search request failed: ${msg}`);
  }

  if (!resp.ok) {
    const detail = await resp.text().catch(() => "");
    log.error("exa.error", {
      status: resp.status,
      duration_ms: Date.now() - startedAt,
      detail: detail.slice(0, 300),
    });
    return failure(`Search error (${resp.status}): ${detail.slice(0, 300)}`);
  }

  const data = await resp.json().catch(() => ({}));
  const results = /** @type {any[]} */ (Array.isArray(data.results) ? data.results : []);
  const durationMs = Date.now() - startedAt;
  log.info("exa.search", {
    duration_ms: durationMs,
    results: results.length,
    query_chars: query.length,
    type,
    num_results_requested: numResults,
  });

  if (results.length === 0) {
    return { ...failure(`No results found for: ${query}`), durationMs };
  }

  const content = results
    .map((r, i) => {
      const highlights = Array.isArray(r.highlights) ? r.highlights.join(" … ") : "";
      return `[${i + 1}] ${r.title || "(untitled)"}\n${r.url}\n${highlights}`.trim();
    })
    .join("\n\n");

  const result = {
    content,
    items: results.map((r) => ({
      title: r.title || r.url,
      url: r.url,
      highlights: Array.isArray(r.highlights) ? r.highlights : [],
    })),
    sources: results.map((r) => ({ title: r.title || r.url, url: r.url })),
    resultCount: results.length,
  };

  // Cache the successful, non-empty result so a later identical query is a
  // free hit. Only good results are cached (errors and empty results return
  // early above and are deliberately left uncached so a retry can find
  // something). Fail-soft: a cache write error never affects the response.
  await cachePut(log, "exa.cache", cacheKey, result, CACHE_TTL_S);

  return { ...result, durationMs, cached: false };
}

// Stable cache key for a full-content fetch: the sorted, normalized URL set.
/**
 * @param {string[]} urls
 * @returns {string} a synthetic `.internal` cache-key URL
 */
export function contentsCacheKey(urls) {
  const norm = [...new Set((urls || []).map((u) => String(u || "").trim()).filter(Boolean))].sort();
  const params = new URLSearchParams({ u: norm.join("|") });
  return `https://exa-contents-cache.internal/contents?${params.toString()}`;
}

// Fetches the full page text for a small set of top sources via Exa's
// /contents endpoint (same x-api-key auth as webSearch). Budget-gated top-tier
// enrichment: bounded, cache-friendly, and fully fail-soft — a missing key, a
// timeout, an error, or a bad response all degrade to an empty result rather
// than throwing, so the pipeline proceeds on the highlights it already has.
//
// Returns { results: [{ url, title, text }], durationMs, cached }.
/**
 * @param {import('./types.js').Env} env
 * @param {string[]} urls
 * @param {import('./types.js').Logger} log
 * @returns {Promise<{ results: Array<{ url: string, title: string, text: string }>, durationMs: number, cached: boolean }>}
 */
export async function fetchContents(env, urls, log) {
  const startedAt = Date.now();
  const empty = (cached = false) => ({ results: [], durationMs: Date.now() - startedAt, cached });
  const list = [...new Set((urls || []).map((u) => String(u || "").trim()).filter(Boolean))];
  if (!list.length) return empty();
  if (!env.EXA_API_KEY) {
    log.error("exa.contents_misconfigured", { missing: "EXA_API_KEY" });
    return empty();
  }

  const cacheKey = contentsCacheKey(list);
  const cached = await cacheGet(log, "exa.contents_cache", cacheKey);
  if (cached) {
    log.info("exa.contents_cache_hit", { duration_ms: Date.now() - startedAt, results: cached.results?.length || 0 });
    return { ...cached, durationMs: Date.now() - startedAt, cached: true };
  }

  let resp;
  try {
    resp = await fetch(EXA_CONTENTS_URL, {
      method: "POST",
      headers: { "content-type": "application/json", "x-api-key": env.EXA_API_KEY },
      body: JSON.stringify({ urls: list, text: { maxCharacters: CONTENTS_MAX_CHARS } }),
      signal: AbortSignal.timeout(CONTENTS_TIMEOUT_MS),
    });
  } catch (err) {
    log.warn("exa.contents_request_failed", { error: /** @type {any} */ (err)?.message || String(err), duration_ms: Date.now() - startedAt });
    return empty();
  }
  if (!resp.ok) {
    const detail = await resp.text().catch(() => "");
    log.warn("exa.contents_error", { status: resp.status, detail: detail.slice(0, 200), duration_ms: Date.now() - startedAt });
    return empty();
  }

  const data = await resp.json().catch(() => ({}));
  const rows = /** @type {any[]} */ (Array.isArray(data.results) ? data.results : []);
  const results = rows
    .map((r) => ({
      url: r.url || "",
      title: r.title || r.url || "",
      text: typeof r.text === "string" ? r.text.slice(0, CONTENTS_MAX_CHARS) : "",
    }))
    .filter((r) => r.url && r.text);
  const durationMs = Date.now() - startedAt;
  log.info("exa.contents", { duration_ms: durationMs, requested: list.length, results: results.length });

  const result = { results };
  if (results.length) {
    await cachePut(log, "exa.contents_cache", cacheKey, result, CACHE_TTL_S);
  }
  return { ...result, durationMs, cached: false };
}

// Unit tests for exa.js's pure logic: the normalized search cache key.
import { test, describe } from "node:test";
import assert from "node:assert/strict";
import { searchCacheKey } from "./exa.js";

// The Cache API path in webSearch (caches.default) is exercised live, per
// this project's convention of verifying external-provider integration in
// production rather than mocking it. The cache KEY derivation is pure, and
// it's what decides whether a repeated search is recognized as identical —
// so it's covered here.
describe("searchCacheKey", () => {
  test("identical searches produce the same key", () => {
    const a = searchCacheKey("Northvolt bankruptcy", "auto", 5);
    const b = searchCacheKey("Northvolt bankruptcy", "auto", 5);
    assert.equal(a, b);
  });

  test("normalizes case and whitespace so trivial spelling differences hit the same entry", () => {
    const a = searchCacheKey("Northvolt bankruptcy", "auto", 5);
    const b = searchCacheKey("  northvolt   BANKRUPTCY ", "auto", 5);
    assert.equal(a, b);
  });

  test("a different query gets a different key", () => {
    assert.notEqual(
      searchCacheKey("Northvolt bankruptcy", "auto", 5),
      searchCacheKey("Northvolt revenue", "auto", 5),
    );
  });

  test("the depth tier is part of the key — a deeper re-run isn't served a shallower cached result", () => {
    assert.notEqual(
      searchCacheKey("q", "auto", 5),
      searchCacheKey("q", "deep", 10),
    );
    assert.notEqual(
      searchCacheKey("q", "auto", 5),
      searchCacheKey("q", "auto", 10),
    );
  });

  test("produces a valid absolute URL usable as a Cache API key", () => {
    const key = searchCacheKey("some query", "auto", 8);
    const url = new URL(key); // throws if not a valid absolute URL
    assert.equal(url.protocol, "https:");
    assert.equal(url.searchParams.get("q"), "some query");
    assert.equal(url.searchParams.get("t"), "auto");
    assert.equal(url.searchParams.get("n"), "8");
  });

  test("handles empty/nullish queries without throwing", () => {
    assert.equal(typeof searchCacheKey("", "auto", 5), "string");
    assert.equal(typeof searchCacheKey(undefined, "auto", 5), "string");
  });
});

