// @ts-check
// Reverse geocoding via OpenStreetMap's Nominatim — resolves a photo's GPS
// EXIF coordinates (extracted client-side by public/js/exif.js) into a
// human-readable place name. Raw decimal coordinates alone are of little
// use to either the model (which can only guess loosely from training
// data) or Exa (which can't search on a lat/lon pair) — a resolved place
// name gives both something concrete to reason and search with.
//
// Runs server-side, not client-side: same as every other third-party call
// in this app (Berget, Exa), it's Worker-mediated so it's logged and rate-
// limited consistently, and it keeps the outbound request minimal — only
// the coordinates cross the wire to Nominatim, never the filename, the
// user's question, or any account/session identifier. The User-Agent
// below identifies this as an automated client (Nominatim's usage policy
// requires *some* non-default value or they filter the traffic as an
// unidentified bot) but is deliberately generic — no site name, no URL.

import { validateImageLocations } from "./validation.js";
import { withAppendedText } from "./conversation.js";

const REVERSE_URL = "https://nominatim.openstreetmap.org/reverse";
const TIMEOUT_MS = 4000;
const GENERIC_USER_AGENT = "geocode-client/1.0";

// Returns a human-readable place name or null on any failure/timeout —
// fails soft, same as every other helper phase in this pipeline: a photo's
// location is enrichment, never a hard requirement for the chat to work.
/**
 * @param {import('./types.js').Env} env
 * @param {import('./types.js').Logger} log
 * @param {number} lat
 * @param {number} lon
 * @returns {Promise<string | null>} a place name, or null on any failure
 */
export async function reverseGeocode(env, log, lat, lon) {
  try {
    const url = `${REVERSE_URL}?format=jsonv2&lat=${lat}&lon=${lon}&zoom=14&addressdetails=0`;
    const resp = await fetch(url, {
      headers: { "User-Agent": GENERIC_USER_AGENT },
      signal: AbortSignal.timeout(TIMEOUT_MS),
    });
    if (!resp.ok) {
      log.warn("geocode.error", { status: resp.status });
      return null;
    }
    const data = await resp.json();
    return typeof data?.display_name === "string" && data.display_name ? data.display_name : null;
  } catch (err) {
    log.warn("geocode.error", { error: /** @type {any} */ (err)?.message || String(err) });
    return null;
  }
}

// Resolves every valid location in `rawLocations` and appends them to the
// conversation as one labeled context block, same convention as the
// client's own image/document metadata blocks — never silently dropped,
// never silently blended into the main text. Returns the conversation
// UNCHANGED when there's nothing valid to resolve or nothing resolves
// (Nominatim down, bad coordinates, etc.) — this must never block or
// delay the chat beyond a few resolved-in-parallel lookups.
//
// Emits a visible activity step (step_start/step_done, same SSE contract as
// the pipeline's own steps and the Shodan enrichment) that NAMES the service
// being contacted — OpenStreetMap Nominatim — so the user has the same
// "which external source is being checked" visibility for the maps lookup
// that they already have for web search and Shodan. Stays SILENT (no step)
// when there's no photo location to resolve, so an ordinary question shows
// no spurious step. `emit` is optional — a plain no-op keeps the function
// usable/testable outside the SSE path.
/**
 * @param {import('./types.js').Env} env
 * @param {import('./types.js').Logger} log
 * @param {((event: import('./types.js').SseEvent) => void) | undefined} emit optional SSE emitter
 * @param {import('./types.js').Conversation} conversation
 * @param {any} rawLocations untrusted client-reported photo GPS coordinates
 * @returns {Promise<import('./types.js').Conversation>}
 */
export async function augmentWithLocations(env, log, emit, conversation, rawLocations) {
  const locations = validateImageLocations(rawLocations);
  if (!locations.length) return conversation;

  const step = typeof emit === "function" ? emit : () => {};
  step({ status: { type: "step_start", id: "geocode", label: "Resolving photo location (OpenStreetMap)…" } });

  const resolved = await Promise.all(
    locations.map(async ({ name, lat, lon }) => ({ name, place: await reverseGeocode(env, log, lat, lon) })),
  );
  const usable = resolved.filter((r) => r.place);
  const details = usable.map((r) => `${r.name}: near ${r.place}`);

  step({
    status: {
      type: "step_done",
      id: "geocode",
      label: usable.length
        ? `Resolved ${usable.length} photo location${usable.length === 1 ? "" : "s"} via OpenStreetMap Nominatim`
        : "No place name resolved for the photo location(s)",
      details,
    },
  });

  if (!usable.length) return conversation;
  const block =
    "\n\n--- Resolved location(s) (via OpenStreetMap Nominatim) ---\n" +
    details.join("\n") +
    "\n--- End of resolved location(s) ---";
  return /** @type {import('./types.js').Conversation} */ (withAppendedText(conversation, block));
}

// @ts-check
// Google sign-in (OIDC authorization-code flow, server side — no SDK).
//
// This is the ONLY user-facing sign-in. Any Google account with a verified
// email can sign in; the account row is auto-provisioned on first login as
// a regular user (quota-capped), except the ADMIN_EMAIL address which gets
// the admin role. The admin can still disable users / adjust quotas in
// /admin, and the ADMIN_USER/ADMIN_PASS secrets remain as break-glass
// Basic Auth for scripts and emergencies.
//
// Flow:
//   GET /auth/google           -> signed single-use state cookie, 302 to Google
//   GET /auth/google/callback  -> verify state, exchange code, validate ID
//                                 token claims, provision/load user, set the
//                                 long-lived session cookie, 303 /
//
// The ID token arrives directly from Google's token endpoint over TLS, so
// per Google's docs signature verification is not required in this flow —
// but the claims are: iss, aud (our client id), exp, and email_verified.
//
// GOOGLE_AUTH_URL / GOOGLE_TOKEN_URL env overrides exist for local tests
// (pointing at a mock); production always uses the defaults.

import { createUserFromGoogle, getUserByEmail, normalizeEmail, updateUser } from "./accounts.js";
import { createSessionCookie, signState, verifyState } from "./auth.js";
import { getDb } from "./db.js";
import { getConfig } from "./config.js";

/** @typedef {import('./types.js').Env} Env */
/** @typedef {import('./types.js').Logger} Logger */
/** @typedef {import('./accounts.js').User} User */

const AUTH_URL = "https://accounts.google.com/o/oauth2/v2/auth";
const TOKEN_URL = "https://oauth2.googleapis.com/token";
const STATE_COOKIE = "dr_oauth";
const STATE_TTL_S = 600;

/** @param {Env} env @returns {boolean} both OAuth secrets are set */
export function googleConfigured(env) {
  return !!(env.GOOGLE_CLIENT_ID && env.GOOGLE_CLIENT_SECRET);
}

/**
 * The one email address granted the admin role (the ADMIN_EMAIL dashboard
 * var), normalized — or null when unset/malformed.
 * @param {Env} env
 * @returns {string | null}
 */
export function adminEmail(env) {
  return normalizeEmail(env.ADMIN_EMAIL || "");
}

/** @param {URL} url @returns {string} */
function redirectUri(url) {
  return `${url.origin}/auth/google/callback`;
}

/**
 * GET /auth/google — mints the signed single-use CSRF state cookie and
 * redirects to Google's consent screen.
 * @param {Request} request
 * @param {Env} env
 * @param {URL} url
 * @param {Logger} [log]
 * @returns {Promise<Response>}
 */
export async function handleGoogleStart(request, env, url, log) {
  if (!googleConfigured(env)) {
    return new Response("Google sign-in is not configured.", { status: 503 });
  }
  // Full-visibility trace: the EXACT redirect_uri this request builds (from the
  // request host) and the client_id, so a live tail shows precisely what Google
  // receives — the ground truth behind redirect_uri_mismatch.
  log?.info("google.start", {
    host: url.host,
    redirect_uri: redirectUri(url),
    client_id: String(env.GOOGLE_CLIENT_ID || "").slice(0, 24),
  });
  const state = [...crypto.getRandomValues(new Uint8Array(16))]
    .map((b) => b.toString(16).padStart(2, "0"))
    .join("");
  const params = new URLSearchParams({
    // googleConfigured() above guarantees the secret is set.
    client_id: String(env.GOOGLE_CLIENT_ID),
    redirect_uri: redirectUri(url),
    response_type: "code",
    scope: "openid email profile",
    state,
  });
  return new Response(null, {
    status: 302,
    headers: {
      Location: `${env.GOOGLE_AUTH_URL || AUTH_URL}?${params}`,
      "Set-Cookie":
        `${STATE_COOKIE}=${state}.${await signState(env, state)}; Max-Age=${STATE_TTL_S}; ` +
        "Path=/auth/google; Secure; HttpOnly; SameSite=Lax",
    },
  });
}

/**
 * GET /auth/google/callback — verifies the CSRF state, exchanges the code
 * server-to-server, validates the ID-token claims, provisions/loads the
 * user, and sets the long-lived session cookie. Every failure path bounces
 * to /login with a flash code (never a bare error page).
 * @param {Request} request
 * @param {Env} env
 * @param {URL} url
 * @param {Logger} log
 * @returns {Promise<Response>}
 */
export async function handleGoogleCallback(request, env, url, log) {
  /**
   * @param {string} flash login-page flash code (src/login.js loginPage)
   * @param {string} [detail] logged, never shown to the user
   */
  const fail = (flash, detail) => {
    log.warn("google.auth_failed", { reason: flash, detail: detail || undefined });
    return new Response(null, {
      status: 303,
      headers: {
        Location: `/login?flash=${flash}`,
        "Set-Cookie": clearStateCookie(),
      },
    });
  };

  if (!googleConfigured(env)) return fail("google-failed", "not configured");
  if (!(await getDb(env))) return fail("nodb");

  // CSRF: the state param must match the signed single-use cookie.
  const state = url.searchParams.get("state") || "";
  const cookie = (request.headers.get("Cookie") || "").match(
    new RegExp(`(?:^|;\\s*)${STATE_COOKIE}=([^;]+)`),
  )?.[1];
  if (!state || !cookie || !(await verifyState(env, state, cookie))) {
    return fail("google-failed", "state mismatch");
  }
  const code = url.searchParams.get("code");
  if (!code) return fail("google-failed", url.searchParams.get("error") || "no code");

  // Exchange the code server-to-server.
  let tokenData;
  try {
    const resp = await fetch(env.GOOGLE_TOKEN_URL || TOKEN_URL, {
      method: "POST",
      headers: { "content-type": "application/x-www-form-urlencoded" },
      body: new URLSearchParams({
        code,
        // googleConfigured() above guarantees both secrets are set.
        client_id: String(env.GOOGLE_CLIENT_ID),
        client_secret: String(env.GOOGLE_CLIENT_SECRET),
        redirect_uri: redirectUri(url),
        grant_type: "authorization_code",
      }),
    });
    if (!resp.ok) return fail("google-failed", `token exchange ${resp.status}`);
    tokenData = await resp.json();
  } catch (err) {
    return fail("google-failed", /** @type {any} */ (err)?.message || String(err));
  }

  const claims = decodeJwtPayload(tokenData.id_token);
  if (!claims) return fail("google-failed", "bad id_token");
  const issOk = claims.iss === "https://accounts.google.com" || claims.iss === "accounts.google.com";
  if (!issOk) return fail("google-failed", "bad iss");
  if (claims.aud !== env.GOOGLE_CLIENT_ID) return fail("google-failed", "bad aud");
  if (!(claims.exp * 1000 > Date.now())) return fail("google-failed", "expired");
  if (claims.email_verified !== true) return fail("google-unverified");
  const email = normalizeEmail(claims.email);
  if (!email) return fail("google-failed", "bad email");

  // Provision on first sign-in; ADMIN_EMAIL gets (and keeps) the admin
  // role and is always active. With the approval gate on (config
  // require_approval), everyone else lands as "pending": they get a
  // session, but only the waiting page until the admin approves — so
  // approval takes effect on their next request, no re-login.
  const isAdminEmail = email === adminEmail(env);
  let user = await getUserByEmail(env, email);
  if (!user) {
    const config = await getConfig(env);
    user = await createUserFromGoogle(env, {
      email,
      name: typeof claims.name === "string" ? claims.name : "",
      sub: typeof claims.sub === "string" ? claims.sub : "",
      role: isAdminEmail ? "admin" : "user",
      status: !isAdminEmail && config.require_approval ? "pending" : "active",
    });
    log.info("google.user_created", { role: user.role, status: user.status });
  } else {
    if (user.status === "disabled") return fail("disabled");
    if (isAdminEmail && user.role !== "admin") {
      // The row exists (we just loaded it), so the update returns it.
      user = /** @type {User} */ (await updateUser(env, user.id, { role: "admin" }));
    }
  }

  log.info("login.success", { role: user.role, via: "google" });
  // The signed-in app lives at /rver (the DeepResearch.Se/rver = "deep
  // research server" wordplay; the root redirects to DRC at /cure).
  const headers = new Headers({ Location: "/rver" });
  headers.append("Set-Cookie", clearStateCookie());
  headers.append("Set-Cookie", await createSessionCookie(env, String(user.id)));
  return new Response(null, { status: 303, headers });
}

/** @returns {string} a Set-Cookie value that expires the state cookie */
function clearStateCookie() {
  return `${STATE_COOKIE}=; Max-Age=0; Path=/auth/google; Secure; HttpOnly; SameSite=Lax`;
}

/**
 * Decodes (does NOT verify) a JWT's payload segment. Signature verification
 * is deliberately skipped — the token arrives directly from Google's token
 * endpoint over TLS (see the module header); the CLAIMS are validated by the
 * caller.
 * @param {unknown} jwt
 * @returns {any} the claims object, or null when malformed
 */
function decodeJwtPayload(jwt) {
  if (typeof jwt !== "string") return null;
  const parts = jwt.split(".");
  if (parts.length !== 3) return null;
  try {
    const b64 = parts[1].replace(/-/g, "+").replace(/_/g, "/");
    const json = atob(b64.padEnd(b64.length + ((4 - (b64.length % 4)) % 4), "="));
    return JSON.parse(
      new TextDecoder().decode(Uint8Array.from(json, (c) => c.charCodeAt(0))),
    );
  } catch {
    return null;
  }
}

// @ts-check
// The Google Maps integration's pure context-block builders — extracted from
// googlemaps.js so the labeled plain-text blocks (and the keyless link
// helpers they cite) live apart from the REST clients and lookup
// orchestration that feed them. Everything here is pure and Node-testable
// (googlemaps.test.js), the same pure-core split as googlemaps-text.js.
//
// Privacy: the blocks hand the model and the user only Google's KEYLESS Maps
// URLs — the API key never appears here (the keyed image URLs live on the
// REST side, src/googlemaps.js, and are used only for the internal fetches).

import { CROSS_MAX_M, STREETVIEW_HEADINGS } from "./googlemaps.js";
import { distanceMeters } from "./googlemaps-text.js";

/** @typedef {import('./types.js').StreetViewPov} StreetViewPov */
/** @typedef {import('./googlemaps-text.js').LatLng} LatLng */
/** @typedef {import('./googlemaps-text.js').MapView} MapView */
/** @typedef {import('./googlemaps-text.js').JumpTarget} JumpTarget */
/** @typedef {import('./googlemaps.js').Place} Place */
/** @typedef {import('./googlemaps.js').PlaceWithCoords} PlaceWithCoords */
/** @typedef {import('./googlemaps.js').WalkingRoute} WalkingRoute */

// The honest note for an explicit street-view ask that resolved to NOTHING:
// the knob is on (this code only runs then), so the model must ask which
// place is meant — never hand out "enable it in Settings" steps. A
// here-ask ("street view at my location") that reaches this point means
// the DEVICE LOCATION never arrived (permission not yet granted, denied,
// or geolocation timed out) — say that, not a useless "which address?"
// (live report 2026-07-09, ref 7a75daf2: the reply was "Where should I
// look up Street View?" at a user pointing at their own position).
/**
 * @param {boolean} [hereAsk]
 * @returns {string}
 */
export function unresolvedMapsBlock(hereAsk = false) {
  const middle = hereAsk
    ? "The user asked for something anchored at their CURRENT LOCATION (a street-view-here ask, \"where am I?\", a go-to/teleport/nearby ask that starts from their position, or an answer to such a clarify), but no device location was shared with this request — the browser has not (yet) granted this site location access, the location request timed out, or the app is running an older cached version (a full reload/relaunch fixes that). " +
      "Tell the user that, to use their current position, they need to allow location access for this site when the browser asks (or in the browser's site settings) — and if no permission prompt ever appeared, to fully reload the app — then ask again. Or they can simply name an address or place instead. "
    : "The user asked for Street View, and Google Maps & Street View is ENABLED, but no address or place name could be identified in the message. " +
      "Ask the user which address or place they mean (one short question). ";
  return (
    "\n\n--- Google Maps ---\n" +
    middle +
    "Do NOT instruct the user to enable Google Maps — it is already on.\n" +
    "--- End of Google Maps ---"
  );
}

// ---- pure link/block builders (exported for unit tests) --------------------

// Appended to every Maps context block. Without it a model that wanted to
// "show" imagery invented a Street View Static API markdown image with
// key=YOUR_API_KEY — a broken image in the reply (reported 2026-07-09,
// "Street view basaltvägen 1 enköping"). Any real imagery is rendered
// beside the reply by the client, never by the model.
const NO_FABRICATED_IMAGE_URLS =
  "NEVER construct or output Google Maps API image URLs or markdown images (e.g. maps.googleapis.com/maps/api/streetview?...) — you have no API key, so such URLs render as broken images. Any available imagery is already shown to the user beside this reply; when linking, use only the keyless links given above.";

// Keyless Google Maps Street View link (built from the pano's own
// coordinates) the model can cite and the user can open. NEVER embeds the API
// key — the keyed image URL is used only for the internal fetch.
/**
 * @param {number} lat
 * @param {number} lng
 * @returns {string}
 */
export function panoLink(lat, lng) {
  return `https://www.google.com/maps/@?api=1&map_action=pano&viewpoint=${lat},${lng}`;
}

// Keyless Google Maps link that drops a pin at the coordinates.
/**
 * @param {number} lat
 * @param {number} lng
 * @returns {string}
 */
export function mapLink(lat, lng) {
  return `https://www.google.com/maps/search/?api=1&query=${lat},${lng}`;
}

// A heading in degrees as a compass point ("143°" → "southeast"), so the
// context block reads naturally for the model and the user.
const COMPASS = ["north", "northeast", "east", "southeast", "south", "southwest", "west", "northwest"];
/**
 * @param {number} heading
 * @returns {string}
 */
export function compassDir(heading) {
  const h = ((Number(heading) % 360) + 360) % 360;
  return COMPASS[Math.round(h / 45) % 8];
}

// The labeled context block for a captured CURRENT-view frame (the POV path):
// the user panned/moved the inline panorama and asked a follow-up, and the
// exact frame on their screen was captured and (when possible) described.
// Same plain-text convention as buildMapsBlock. Pure — exported for tests.
/**
 * @param {StreetViewPov} pov
 * @param {{ date?: string, description?: string, framesShown?: number, panoramaShown?: boolean }} parts
 * @returns {string}
 */
export function buildPovBlock(pov, parts) {
  const lines = [
    "The user is viewing an interactive Street View panorama beside this chat and may have panned or moved it.",
    `Their CURRENTLY VISIBLE view was captured for this question: at coordinates ${pov.lat}, ${pov.lng}, facing ${pov.heading}° (${compassDir(pov.heading)}), pitch ${pov.pitch}°.`,
  ];
  if (parts.date) lines.push(`Street View imagery captured: ${parts.date}`);
  lines.push(`Map link: ${mapLink(pov.lat, pov.lng)}`);
  lines.push(`Street View link: ${panoLink(pov.lat, pov.lng)}`);
  if (parts.panoramaShown) {
    lines.push(
      "An interactive Street View panorama positioned at exactly this view is displayed to the user directly beside this reply — they can keep looking around from there, so refer to the view as shared context.",
    );
  } else if (parts.framesShown) {
    lines.push("The captured frame is displayed to the user directly beside this reply, so you can refer to it as shared context.");
  }
  // The user navigated here from wherever the conversation started — the
  // coordinates above are where they are NOW, so the answer must hand them
  // a link to this position, not rely on links given for the original place.
  lines.push(
    `The user has moved within Street View, so ALWAYS include the Map link above in your answer as a markdown link (e.g. [View on Google Maps](${mapLink(pov.lat, pov.lng)})) so they can open their current position.`,
  );
  if (parts.description) {
    lines.push(`Visual description of the user's current view (auto-generated): ${parts.description}`);
  } else {
    lines.push("The frame could not be examined by a vision model this time — answer from the location data above and say plainly that the view itself couldn't be inspected.");
  }
  // Conditional on purpose: the capture fires generously for panorama
  // conversations, so the question may or may not be about the view —
  // steer without misdirecting the unrelated case.
  lines.push(
    "If the question refers to something visible (a person, vehicle, sign, building — anything in the scene), answer it directly from the visual description above and never ask them to clarify who or what they mean: they mean what is in their view. If the question is unrelated to the view, answer it normally and ignore this block.",
  );
  lines.push("Google Maps & Street View is already enabled — do NOT suggest the user enable it.");
  lines.push(NO_FABRICATED_IMAGE_URLS);
  return "\n\n--- Google Maps ---\n" + lines.join("\n") + "\n--- End of Google Maps ---";
}

// Human phrasing of a jump ask, from the deterministic parse (pure).
/** @param {JumpTarget} jump */
function jumpAskText(jump) {
  if (jump.dir === "here") return "at their current position";
  const dir =
    jump.dir === "forward"
      ? "along the road/direction they are viewing"
      : jump.dir === "back"
        ? "back the way they came"
        : `to the ${jump.dir}`;
  return `about ${jump.meters} meters ${dir} of their current position`;
}

// The labeled context block for a Street View JUMP: the user asked to pop
// open Street View at their current position ("street view here") or at a
// computed one ("100 meters along this road") — the destination was derived
// deterministically from their live view/location and phrasing. Pure —
// exported for tests. `jump` carries the (possibly pano-snapped) destination.
/**
 * @param {JumpTarget} jump
 * @param {{ found?: boolean, date?: string, place?: string | null, panoramaShown?: boolean,
 *   framesShown?: number, description?: string, mapShown?: boolean }} parts
 * @returns {string}
 */
export function buildJumpBlock(jump, parts) {
  const lines = [
    `The user asked to open Street View ${jumpAskText(jump)} — computed destination: ${jump.lat}, ${jump.lng}, facing ${jump.heading}° (${compassDir(jump.heading)}).`,
  ];
  // The destination NAMED, not just its coordinates — a here-jump is often
  // a literal "where am I?", and this line is the actual answer to it.
  if (parts.place) {
    lines.push(`The destination reverse-geocodes to (OpenStreetMap Nominatim): ${parts.place}`);
  }
  if (parts.found) {
    if (parts.date) lines.push(`Street View imagery captured: ${parts.date}`);
    lines.push(`Map link: ${mapLink(jump.lat, jump.lng)}`);
    lines.push(`Street View link: ${panoLink(jump.lat, jump.lng)}`);
    if (parts.panoramaShown) {
      lines.push(
        "An interactive Street View panorama positioned at this destination is displayed to the user directly beside this reply — they can keep looking around from there, so refer to it as shared context.",
      );
    } else if (parts.framesShown) {
      lines.push("The captured Street View frame of the destination is displayed to the user directly beside this reply.");
    }
    if (parts.description) {
      lines.push(`Visual description of the destination's Street View (auto-generated): ${parts.description}`);
    } else {
      lines.push(
        "The destination's imagery could not be examined by a vision model this time — answer from the location data above and say plainly that the view itself couldn't be inspected.",
      );
    }
  } else {
    lines.push(
      "Google has NO Street View panorama near that destination. Say so plainly — never invent what it looks like or present anything else as Street View.",
    );
    lines.push(`Map link: ${mapLink(jump.lat, jump.lng)}`);
    if (parts.mapShown) {
      lines.push("An interactive Google Map of the destination is displayed to the user directly beside this reply instead.");
    }
  }
  lines.push(
    `ALWAYS include the Map link above in your answer as a markdown link (e.g. [View on Google Maps](${mapLink(jump.lat, jump.lng)})) so the user can open the destination.`,
  );
  lines.push(
    "The destination was computed from the user's own view and phrasing — do NOT ask them to confirm coordinates or clarify where they mean; answer about it directly.",
  );
  lines.push("Google Maps & Street View is already enabled — do NOT suggest the user enable it.");
  lines.push(NO_FABRICATED_IMAGE_URLS);
  return "\n\n--- Google Maps ---\n" + lines.join("\n") + "\n--- End of Google Maps ---";
}

// The labeled context block for a CROSS-BARRIER relocation ("get to the
// other side of the railway"). The load-bearing line is the VIRTUAL note:
// the reported failure was the model answering a panorama relocation with
// real-world safety guidance ("never cross the tracks directly") — twice.
// Pure — exported for unit tests.
/**
 * @param {string} barrier
 * @param {LatLng} anchor
 * @param {{ found: true, bearing: number, distance: number, lat: number, lng: number,
 *     place?: string | null, framesShown?: number, panoramaShown?: boolean, description?: string }
 *   | { found?: false, mapShown?: boolean }} [parts]
 * @returns {string}
 */
export function buildCrossBarrierBlock(barrier, anchor, parts = {}) {
  const lines = [
    `The user asked to get to the other side of the ${barrier}. This is VIRTUAL Street View panorama navigation — the user is NOT physically moving. ` +
      "Do NOT give real-world safety or route guidance (no warnings about crossing tracks, traffic, or authorized paths); just describe where the view has been relocated to.",
  ];
  if (parts.found) {
    lines.push(
      `The panorama was relocated across the ${barrier}: heading ${parts.bearing}° (${compassDir(parts.bearing)}), ` +
        `landing ≈${parts.distance} m from the previous position at ${parts.lat}, ${parts.lng} (detected as renewed Street View coverage after the ${barrier}'s coverage gap).`,
    );
    if (parts.place) lines.push(`The destination reverse-geocodes to (OpenStreetMap Nominatim): ${parts.place}`);
    lines.push(`Map link: ${mapLink(parts.lat, parts.lng)}`);
    lines.push(`Street View link: ${panoLink(parts.lat, parts.lng)}`);
    if (parts.framesShown) {
      lines.push(
        `A photo series of the virtual crossing (start → just before the ${barrier} → the other side) is displayed to the user directly beside this reply — walk them through it in order.`,
      );
    }
    if (parts.panoramaShown) {
      lines.push(
        "An interactive Street View panorama at the destination is displayed to the user directly beside this reply — they can keep looking around from there.",
      );
    }
    if (parts.description) {
      lines.push(`Visual description of the destination's Street View (auto-generated): ${parts.description}`);
    }
    lines.push(
      `ALWAYS include the Map link above in your answer as a markdown link (e.g. [View on Google Maps](${mapLink(parts.lat, parts.lng)})).`,
    );
  } else {
    lines.push(
      `No renewed Street View coverage was found beyond the ${barrier} within ~${CROSS_MAX_M} m of the current position in the probed directions. ` +
        "Say so plainly — never invent a view or a destination.",
    );
    lines.push(`Map link for the current position: ${mapLink(anchor.lat, anchor.lng)}`);
    if (parts.mapShown) {
      lines.push("An interactive Google Map of the current area is displayed to the user directly beside this reply.");
    }
  }
  lines.push("The relocation was computed from the user's own view and phrasing — do NOT ask them to confirm coordinates.");
  lines.push("Google Maps & Street View is already enabled — do NOT suggest the user enable it.");
  lines.push(NO_FABRICATED_IMAGE_URLS);
  return "\n\n--- Google Maps ---\n" + lines.join("\n") + "\n--- End of Google Maps ---";
}

// The labeled context block for a NEARBY-place search ("Gas station near
// e18 there"): Google Places searched around the user's current position
// and these are the hits, nearest-relevance first, each with its distance
// from the anchor and a keyless Map link. `parts` carries the imagery facts
// (panorama/frame shown, vision description) for the TOP hit when Street
// View covered it. Pure — exported for unit tests.
/**
 * @param {string} query
 * @param {LatLng} anchor
 * @param {PlaceWithCoords[]} places
 * @param {{ mode?: string, anchorPlace?: string | null, panoramaShown?: boolean, mapShown?: boolean,
 *   routeMapShown?: boolean, route?: WalkingRoute | null, description?: string }} [parts]
 * @returns {string}
 */
export function buildNearbyPlacesBlock(query, anchor, places, parts = {}) {
  const lines = [
    `The user asked for a nearby place ("${query}") and Google Places was searched around their CURRENT position (${anchor.lat}, ${anchor.lng}). ` +
      "The position is where they have navigated the live view (or their device location) — do NOT ask them to confirm it.",
  ];
  // Mode framing (the user's refined semantics, 2026-07-09): teleport =
  // DROP, "go to" = the actual travel, verb-less = informational search.
  if (parts.mode === "instant") {
    lines.push(
      "The user asked to TELEPORT — they have been dropped straight at the first result; the panorama beside this reply is there. " +
        "Answer briefly with where they landed and what's around it — no travel narrative, no route description.",
    );
  } else if (parts.mode === "travel") {
    lines.push(
      "The user asked to GO there — present it as the actual travel: where they started, the way there (the photo waypoints and route map beside this reply, in order), and the arrival.",
    );
  }
  // The say-where-you-are opener (search/travel modes): the answer opens
  // with the user's own position, then presents the found place.
  if (parts.anchorPlace) {
    lines.push(
      `The user's current position reverse-geocodes to (OpenStreetMap Nominatim): ${parts.anchorPlace}. ` +
        "Open the answer by saying where the user currently is, then present the found place / relocation.",
    );
  }
  if (places.length) {
    lines.push(`${places.length} result${places.length === 1 ? "" : "s"}, best match first:`);
    for (const p of places) {
      const meters = distanceMeters(anchor.lat, anchor.lng, p.lat, p.lng);
      const dist = meters >= 1000 ? `≈${(meters / 1000).toFixed(1)} km away` : `≈${meters} m away`;
      const facts = [p.type, dist, p.rating ? `rated ${p.rating} (${p.ratingCount})` : "", p.status && p.status !== "OPERATIONAL" ? p.status : ""]
        .filter(Boolean)
        .join(", ");
      lines.push(`- ${p.name} — ${p.address}${facts ? ` (${facts})` : ""} — Map link: ${mapLink(p.lat, p.lng)}`);
    }
    const top = places[0];
    if (parts.panoramaShown) {
      lines.push(
        `An interactive Street View panorama at the first result (${top.name}) is displayed to the user directly beside this reply — refer to it as shared context. ` +
          "If the user asked to \"jump\" or \"teleport\", that relocation HAS happened: the panorama IS at the destination.",
      );
    } else if (parts.mapShown) {
      lines.push(`An interactive Google Map at the first result (${top.name}) is displayed to the user directly beside this reply.`);
    }
    if (parts.routeMapShown) {
      lines.push(
        `A route map with numbered waypoints (1 = the user's position, last = ${top.name}) is displayed to the user beside this reply.`,
      );
    }
    if (parts.route) {
      const mins = parts.route.durationS ? Math.max(1, Math.round(parts.route.durationS / 60)) : null;
      lines.push(
        `Along roads/paths (Google Routes, walking): ≈${fmtMeters(parts.route.distanceMeters)}${mins ? `, about ${mins} min on foot` : ""}.`,
      );
    }
    if (parts.description) {
      lines.push(`Visual description of the first result's Street View (auto-generated): ${parts.description}`);
    }
    lines.push(
      `ALWAYS include the first result's Map link in your answer as a markdown link (e.g. [${top.name} on Google Maps](${mapLink(top.lat, top.lng)})) so the user can open it.`,
    );
  } else {
    lines.push(
      "Google Places returned NO results for this search near the current position. Say so plainly — never invent a place — and suggest widening the search or naming a place/address.",
    );
    lines.push(`Map link for the current position: ${mapLink(anchor.lat, anchor.lng)}`);
  }
  lines.push(
    "This is VIRTUAL Street View/map navigation — NEVER say you cannot teleport, move the user, or control navigation; the views beside this reply are the relocation.",
  );
  lines.push("Google Maps & Street View is already enabled — do NOT suggest the user enable it.");
  lines.push(NO_FABRICATED_IMAGE_URLS);
  return "\n\n--- Google Maps ---\n" + lines.join("\n") + "\n--- End of Google Maps ---";
}

// The labeled context block for a captured CURRENT map view (the map-view
// path, the road-map sibling of buildPovBlock): the user panned/zoomed the
// inline interactive map and asked a follow-up, and a road-map image of
// exactly the area on their screen was captured and (when possible)
// described. Pure — exported for tests.
/**
 * @param {MapView} view
 * @param {{ description?: string, mapShown?: boolean }} parts
 * @returns {string}
 */
export function buildMapViewBlock(view, parts) {
  const lines = [
    "The user is viewing an interactive Google Map beside this chat and may have panned or zoomed it.",
    `Their CURRENTLY VISIBLE map area was captured for this question: centered at coordinates ${view.lat}, ${view.lng}, zoom level ${view.zoom}.`,
    `Map link: ${mapLink(view.lat, view.lng)}`,
  ];
  if (parts.mapShown) {
    lines.push(
      "A fresh interactive Google Map positioned at exactly this view is displayed to the user directly beside this reply — they can keep exploring from there, so refer to the view as shared context.",
    );
  }
  // The user panned/zoomed away from wherever the conversation started — the
  // center above is where they are NOW, so the answer must link there.
  lines.push(
    `The user has moved within the map, so ALWAYS include the Map link above in your answer as a markdown link (e.g. [View on Google Maps](${mapLink(view.lat, view.lng)})) so they can open their current position.`,
  );
  if (parts.description) {
    lines.push(
      `Visual description of the user's current map view (auto-generated — this is a MAP image, NOT Street View): ${parts.description}`,
    );
  } else {
    lines.push(
      "The map view could not be examined by a vision model this time — answer from the coordinates above and say plainly that the view itself couldn't be inspected.",
    );
  }
  // Conditional on purpose, same as the POV block: the capture fires
  // generously for map conversations, so the question may be unrelated.
  lines.push(
    "If the question refers to something on the map (a road, a labeled place, an area — anything in their view), answer it directly from the visual description above and never ask them to clarify where they mean: they mean what is on their map. If the question is unrelated to the map, answer it normally and ignore this block.",
  );
  lines.push("Google Maps & Street View is already enabled — do NOT suggest the user enable it.");
  lines.push(NO_FABRICATED_IMAGE_URLS);
  return "\n\n--- Google Maps ---\n" + lines.join("\n") + "\n--- End of Google Maps ---";
}

// The labeled context block appended to the conversation, same plain-text
// convention as geocode.js's resolved-location block and shodan.js's host
// block. `parts` is the assembled lookup result (place / streetView / map).
/**
 * @param {string} query
 * @param {{ place: Place | null, lat: number | null, lng: number | null,
 *   streetView: { date: string, lat: number | null, lng: number | null } | null,
 *   streetViewCount?: number, hasMap?: boolean, description?: string, describedMapOnly?: boolean,
 *   followUp?: boolean, framesShown?: number, mapShown?: boolean, mapEmbedShown?: boolean }} parts
 * @returns {string}
 */
export function buildMapsBlock(query, parts) {
  const lines = [`Location looked up: ${query}`];
  const p = parts.place;
  if (p) {
    if (p.name) lines.push(`Place: ${p.name}`);
    if (p.address) lines.push(`Address: ${p.address}`);
    if (p.type) lines.push(`Type: ${p.type}`);
    if (Number.isFinite(p.rating)) {
      lines.push(`Rating: ${p.rating}${p.ratingCount ? ` (${p.ratingCount} reviews)` : ""}`);
    }
    if (p.status) lines.push(`Business status: ${p.status}`);
  }
  const lat = parts.lat;
  const lng = parts.lng;
  if (Number.isFinite(lat) && Number.isFinite(lng)) {
    lines.push(`Coordinates: ${lat}, ${lng}`);
    lines.push(`Map link: ${mapLink(/** @type {number} */ (lat), /** @type {number} */ (lng))}`);
  }
  if (parts.streetView) {
    // Link the panorama's own position when the lookup reported one (it can
    // sit up to the search radius from the resolved address), else the
    // resolved coordinates.
    const svLat = Number.isFinite(parts.streetView.lat) ? parts.streetView.lat : lat;
    const svLng = Number.isFinite(parts.streetView.lng) ? parts.streetView.lng : lng;
    if (Number.isFinite(svLat) && Number.isFinite(svLng)) {
      lines.push(`Street View link: ${panoLink(/** @type {number} */ (svLat), /** @type {number} */ (svLng))}`);
    }
    if (parts.streetView.date) lines.push(`Street View imagery captured: ${parts.streetView.date}`);
  } else {
    // The location resolved but Google has no panorama near it. Said
    // explicitly, because omitting it made the model present a road-map
    // description as "Street View imagery" (reported 2026-07-09).
    lines.push(
      "No Street View imagery is available for this location (Google has no panorama near these coordinates). If the user asked for Street View, say that plainly — never present anything else (a map, a guess) as Street View imagery.",
    );
    // With no panorama, the map link is the user's way in — the first
    // no-coverage answers shipped without any link at all (requested
    // 2026-07-09: "include a google maps link with the maps view").
    if (Number.isFinite(lat) && Number.isFinite(lng)) {
      lines.push(
        `ALWAYS include the Map link above in your answer as a markdown link (e.g. [View on Google Maps](${mapLink(/** @type {number} */ (lat), /** @type {number} */ (lng))})) so the user can open the location on Google Maps.`,
      );
    }
  }
  const svCount = parts.streetViewCount || 0;
  if (parts.followUp) {
    // pickLookup walked back to an address an EARLIER turn named: tell the
    // model this is fresh imagery of the location already under discussion,
    // so it reasons about THE image instead of denying knowledge of it.
    lines.push(
      "This is a follow-up question about the location already being discussed — the CURRENT Street View imagery of it was re-fetched and re-examined for this question.",
    );
  }
  if (parts.framesShown) {
    lines.push(
      `${parts.framesShown} Street View photo(s) of this location are displayed to the user directly beside this reply, so you can refer to them ("in the photos", "the north-facing frame") as shared context.`,
    );
  }
  if (parts.mapShown) {
    lines.push(
      "A road-map image of the area is displayed to the user directly beside this reply, so you can refer to it as shared context.",
    );
  }
  if (parts.mapEmbedShown) {
    lines.push(
      "An interactive Google Map of the area (draggable, zoomable, with a marker at the resolved location) is displayed to the user directly beside this reply, so you can refer to it as shared context.",
    );
  }
  if (parts.description) {
    // A vision model already looked at the imagery for a non-vision answer
    // model — hand over its description so the answer can relay it. Label
    // WHAT was described honestly: when only the road map could be examined
    // (no Street View coverage, or every frame fetch failed), saying
    // "Street View imagery" here made the model claim Street View it never
    // had (reported 2026-07-09).
    const describedWhat = parts.describedMapOnly
      ? "Visual description of the road map of the area (auto-generated — this is a MAP image, NOT Street View)"
      : "Visual description of the Street View imagery (auto-generated)";
    lines.push(`${describedWhat}: ${parts.description}`);
  } else {
    const imgs = [];
    if (svCount) {
      imgs.push(
        svCount === 1
          ? "one Street View photo"
          : `${svCount} Street View photos looking ${STREETVIEW_HEADINGS.slice(0, svCount).map((h) => h.dir).join(", ")} from the spot`,
      );
    }
    if (parts.hasMap) imgs.push("a road map");
    if (imgs.length) {
      lines.push(`Attached to this message for you to describe: ${imgs.join(" and ")}.`);
    } else if (parts.streetView) {
      lines.push("Street View imagery exists here; to see it the user can open the Street View link above (the answering model can't view images).");
    }
  }
  // A resolved location must never be re-asked (reported: the user wrote
  // "lidbecksgatan 10 hallstahammar" and still got "did you mean Lidköping
  // or Hallstahammar?" — a wasted turn beside already-fetched imagery).
  lines.push(
    "The location was already resolved as shown above — do NOT ask the user to confirm or disambiguate the location or city. Answer about the resolved location directly; if the user's message names a locality that differs from the resolved address, say so plainly instead of asking.",
  );
  // The knob is on (this block only exists when it is). Stop the model from
  // wrongly telling the user to enable an already-enabled feature.
  lines.push("Google Maps & Street View is already enabled — do NOT suggest the user enable it.");
  lines.push(NO_FABRICATED_IMAGE_URLS);
  return "\n\n--- Google Maps ---\n" + lines.join("\n") + "\n--- End of Google Maps ---";
}

/** @param {number} m */
const fmtMeters = (m) => (m >= 1000 ? `${(m / 1000).toFixed(1)} km` : `${Math.round(m)} m`);

// The labeled context block for the JOURNEY view ("show how we traveled"):
// the visited positions ARE the conversation's own relocations, so the
// block presents them as the journey confidently — the reported failure
// was the model disclaiming that "no verified route" exists and refusing
// to draw one. Pure — exported for unit tests.
/**
 * @param {LatLng[]} points
 * @param {{ route?: WalkingRoute | null, startPlace?: string | null, endPlace?: string | null,
 *   mapShown?: boolean, embedShown?: boolean }} [parts]
 * @returns {string}
 */
export function buildJourneyBlock(points, parts = {}) {
  const total = points.length;
  let straight = 0;
  const lines = [
    `The user asked to see how they traveled. This is the VIRTUAL journey of this conversation — the ${total} Street View/map positions visited, in order. ` +
      "Present it AS the journey (these are the actual visited positions); do not disclaim it as unverified or refuse to draw it.",
  ];
  points.forEach((p, i) => {
    const leg = i === 0 ? "" : ` — ${fmtMeters(distanceMeters(points[i - 1].lat, points[i - 1].lng, p.lat, p.lng))} from the previous stop (straight line)`;
    if (i > 0) straight += distanceMeters(points[i - 1].lat, points[i - 1].lng, p.lat, p.lng);
    const name = i === 0 && parts.startPlace ? ` (${parts.startPlace})` : i === total - 1 && parts.endPlace ? ` (${parts.endPlace})` : "";
    const role = i === 0 ? "start" : i === total - 1 ? "current position" : `stop ${i + 1}`;
    lines.push(`${i + 1}. ${role}: ${p.lat}, ${p.lng}${name}${leg}`);
  });
  lines.push(`Total straight-line distance along the stops: ≈${fmtMeters(straight)}.`);
  if (parts.route) {
    const mins = parts.route.durationS ? Math.max(1, Math.round(parts.route.durationS / 60)) : null;
    lines.push(
      `Along roads/paths (Google Routes, walking): ≈${fmtMeters(parts.route.distanceMeters)}${mins ? `, about ${mins} min on foot` : ""}.`,
    );
  } else {
    lines.push(
      "The along-road walking distance could not be computed this time (Routes API unavailable) — give the straight-line figures and say road distance would be somewhat longer; do NOT invent a walking time.",
    );
  }
  const dirLink = `https://www.google.com/maps/dir/${points.map((p) => `${p.lat},${p.lng}`).join("/")}`;
  lines.push(`Directions link through all stops: ${dirLink}`);
  if (parts.mapShown) {
    lines.push("A route map with the numbered stops and the path between them is displayed to the user directly beside this reply.");
  }
  if (parts.embedShown) {
    lines.push("An interactive map of the journey is also displayed beside this reply.");
  }
  lines.push(
    `ALWAYS include the directions link in your answer as a markdown link (e.g. [The route on Google Maps](${dirLink})).`,
  );
  lines.push("Google Maps & Street View is already enabled — do NOT suggest the user enable it.");
  lines.push(NO_FABRICATED_IMAGE_URLS);
  return "\n\n--- Google Maps ---\n" + lines.join("\n") + "\n--- End of Google Maps ---";
}

// @ts-check
// The pure text side of the Google Maps integration — extracted from
// googlemaps.js so the deterministic language analysis (address/place
// extraction, street-view intent gates, locality corrections, and the
// lookup-input derivation pickLookup) lives apart from the REST clients and
// lookup orchestration it feeds. Everything here is pure and Node-testable
// (googlemaps.test.js), the same pure-core split the client applies
// (message-content.js out of stream.js).
//
// This is the privacy-critical layer: only the candidate these functions
// extract ever crosses the wire to Google, never the whole message — the
// same minimal-request posture shodan.js/geocode.js keep.

import { textOf } from "./conversation.js";

// ---- shared shapes (consumed by googlemaps.js and maps-enrichment.js) -------
/** @typedef {import('./types.js').Conversation} Conversation */
/** @typedef {import('./types.js').Message} Message */
/** @typedef {import('./types.js').ImageLocation} ImageLocation */
/** @typedef {import('./types.js').StreetViewPov} StreetViewPov */
/** A plain coordinate pair (extra fields ride along structurally). */
/** @typedef {{ lat: number, lng: number }} LatLng */
/** The user's live interactive-map view (validated body.map_view). */
/** @typedef {{ lat: number, lng: number, zoom: number }} MapView */
/**
 * A Street View JUMP destination ("street view here", "100 m north"):
 * computed deterministically from the anchor and the phrase. `dir` is the
 * normalized direction word for block phrasing ("here", "north", "forward").
 * @typedef {{ lat: number, lng: number, heading: number, meters: number, dir: string }} JumpTarget
 */
/** How a nearby/relocation ask wants to be answered — see nearbyAskMode. */
/** @typedef {"instant" | "travel" | "search"} NearbyMode */
/** A nearby-place / relocation-to-name search around the anchor. */
/** @typedef {{ query: string, lat: number, lng: number, mode: NearbyMode }} NearbyTarget */
/** A cross-barrier relocation ask anchored at the current position. */
/** @typedef {{ barrier: string, lat: number, lng: number, heading: number, hasHeading: boolean }} CrossBarrierTarget */
/** The journey view's waypoints (from the assistant turns' mandated links). */
/** @typedef {{ points: LatLng[] }} JourneyTarget */
/**
 * What pickLookup resolves a conversation turn into — the contract between
 * the matcher registry here and the runners in maps-enrichment.js. Exactly
 * one of the optional shape fields is set (or none: a plain address/coords
 * lookup); `followUp` marks a target recovered from earlier turns/state.
 * `intent` is the deciding matcher's name, attached non-enumerably by
 * pickLookup for diagnostics only.
 * @typedef {{
 *   coords: string,
 *   address: string,
 *   followUp?: boolean,
 *   pov?: StreetViewPov,
 *   mapView?: MapView,
 *   jump?: JumpTarget,
 *   nearby?: NearbyTarget,
 *   crossBarrier?: CrossBarrierTarget,
 *   journey?: JourneyTarget,
 *   intent?: string,
 * }} LookupTarget
 */
/** The resolved current position a relocation-family matcher anchors to. */
/** @typedef {{ lat: number, lng: number, heading: number, hasHeading: boolean }} LookupAnchor */
/** The shared context every LOOKUP_MATCHERS entry receives — see buildLookupCtx. */
/**
 * @typedef {{
 *   conversation: Conversation,
 *   users: Message[],
 *   latest: string,
 *   trimmed: string,
 *   imageLocations: ImageLocation[] | null | undefined,
 *   pov: StreetViewPov | null,
 *   mapView: MapView | null,
 *   userLocation: LatLng | null,
 *   anchor: LookupAnchor | null,
 *   latestFix: string,
 * }} LookupCtx
 */

const MAX_LOCATION_CHARS = 200;

// ---- deterministic address extraction ---------------------------------------

// What marks the word before a house number as a STREET name (so
// "Maskinistvägen 11" is an address but "iPhone 15" / "on August 5" are not).
// Two safe tests, deliberately kept apart:
//  - Swedish street words are compounds ending in a street morpheme
//    (…vägen, …gatan, …gränd); testing that morpheme as a word-ENDING is safe
//    because ordinary words practically never end that way.
//  - English street words are short and some (st, rd) are substrings of common
//    words ("August", "record"), so they must match the word EXACTLY, never as
//    a mere ending.
const SWEDISH_STREET_SUFFIX_RE =
  /(vägen|väg|gatan|gata|gränden|gränd|stigen|stig|allén|allé|backen|backe|liden|torget|torg)$/u;
const ENGLISH_STREET_WORDS = new Set([
  "street", "st", "road", "rd", "avenue", "ave", "lane", "ln", "drive", "dr",
  "boulevard", "blvd", "highway", "hwy", "court", "ct", "place", "pl",
  "square", "sq", "way", "terrace", "parkway", "pkwy",
]);

// A word is address-like text: unicode letters plus the marks/apostrophes/
// hyphens that appear inside street names. \p{L} covers å/ä/ö and accents.
const WORD = "[\\p{L}][\\p{L}\\p{M}'’.-]*";
// One or more words followed by a 1-4 digit house number (optionally with a
// letter suffix like "11B"). The leading words let a preceding locality ride
// along ("Kallhäll Maskinistvägen 11").
const ADDRESS_RE = new RegExp(`(?:${WORD}\\s+){1,4}\\d{1,4}[a-zA-Z]?\\b`, "gu");

// A STANDALONE Swedish street name — a single word ending in a street morpheme
// (Maskinistvägen, Storgatan, Björkstigen). No house number needed: a word
// ending "…vägen"/"…gatan"/etc. is an unambiguous street signal, and people
// routinely ask about a street without a number ("street view of X in Y").
const SWEDISH_STREET_TOKEN_RE =
  /[\p{L}][\p{L}\p{M}-]*(?:vägen|väg|gatan|gata|gränden|gränd|stigen|stig|allén|allé|backen|backe|liden|torget|torg)\b/giu;
// A STANDALONE English street phrase — 1-3 Capitalized words then a Capitalized
// street type ("Abbey Road", "Main Street"). Requiring the type word to be
// capitalized keeps ordinary prose ("down the road") from matching, and the
// type list is limited to the unambiguous ones (dropping Drive/Place/Way/
// Court/Square, which double as common capitalized words — "Please Drive",
// "the Square" — since here no house number anchors them).
const ENGLISH_STREET_PHRASE_RE =
  /\p{Lu}[\p{L}\p{M}'’.-]*(?:\s+\p{Lu}[\p{L}\p{M}'’.-]*){0,2}\s+(?:Street|Road|Avenue|Lane|Boulevard|Highway|Terrace|Parkway)\b/gu;
// Filler / intent words that are never part of an address. Used to trim
// leading noise ("show street view of …") and to reject a bad trailing capture.
// Lowercase, accents included; localities like "kallhäll"/"järfälla" are NOT
// here, so a lowercase locality survives (the bug that sent bare
// "Maskinistvägen 11" to Google and resolved to the wrong city).
const STOPWORDS = new Set([
  // English intent/filler
  "show", "street", "streets", "view", "streetview", "google", "maps", "map", "of", "the", "a",
  "an", "at", "on", "for", "me", "my", "please", "pls", "can", "could", "would", "you", "we", "i",
  "what", "whats", "where", "which", "is", "are", "was", "were", "do", "does", "get", "give", "see",
  "look", "looks", "around", "find", "near", "in", "to", "from", "with", "and", "this", "that",
  "here", "there", "no", "not", "yes", "now", "today", "tomorrow", "thanks",
  "mean", "meant", "instead", "rather",
  // Swedish intent/filler
  "visa", "mig", "se", "titta", "vad", "finns", "det", "den", "här", "där", "ligger", "är", "och",
  "på", "pa", "vid", "gatuvy", "kan", "du", "jag", "vi", "var", "hur", "nej", "ja", "en", "ett",
  "nu", "idag", "imorgon", "tack", "menade", "menar", "istället", "snarare",
]);

/** @param {string} w */
const normWord = (w) => (w || "").toLowerCase().replace(/[^\p{L}]/gu, "");

// A trailing locality after the street span. Case-INSENSITIVE (users type
// "in järfälla", "i kallhäll" lowercase): a connector (comma / in / i / på /
// vid / near) followed by up to two place words, OR a bare word pair with NO
// connector at all ("Streetview lidbecksgatan 10 hallstahammar" — the
// reported wrong-city bug: only a CAPITALIZED bare locality used to count, so
// a lowercase one was dropped, the bare street went to Google, and it
// resolved the wrong city while the user had named the right one explicitly).
// Bare words are kept only up to the first intent/filler stopword, so "look
// like", "ligger i centrum" etc. never read as localities.
const CONNECTOR_LOCALITY_RE =
  /^\s*(?:,|\b(?:in|i|på|pa|vid|near|kommun)\b)\s*([\p{L}][\p{L}\p{M}'’.-]*(?:\s+[\p{L}][\p{L}\p{M}'’.-]*)?)/iu;
const BARE_LOCALITY_RE =
  /^\s+([\p{L}][\p{L}\p{M}'’.-]*(?:\s+[\p{L}][\p{L}\p{M}'’.-]*)?)/u;

// Given a matched street span and the text right after it, append a trailing
// locality when one is present, so "Maskinistvägen 11 in järfälla" resolves as
// "Maskinistvägen 11, järfälla" rather than a bare, ambiguous street name.
/**
 * @param {string} street
 * @param {string} rest
 * @returns {string}
 */
function withTrailingLocality(street, rest) {
  const m = rest.match(CONNECTOR_LOCALITY_RE) || rest.match(BARE_LOCALITY_RE);
  if (!m || !m[1]) return street;
  const words = [];
  for (const w of m[1].trim().split(/\s+/)) {
    if (!w || STOPWORDS.has(normWord(w))) break;
    words.push(w);
  }
  const locality = words.join(" ");
  if (!locality || street.toLowerCase().includes(locality.toLowerCase())) return street;
  return `${street}, ${locality}`;
}

// Preceding place-name words right before a street token ("kallhäll
// maskinistvägen"), walking back over non-stopwords (case-insensitive) up to
// two words. Returns "" when the words before the street are all filler.
/** @param {string} before */
function leadingLocality(before) {
  const words = before.trim().split(/\s+/).filter(Boolean);
  const kept = [];
  for (let i = words.length - 1; i >= 0 && kept.length < 2; i--) {
    const nw = normWord(words[i]);
    // Stop at filler or a token with no letters (a bare house number "5").
    if (!nw || STOPWORDS.has(nw)) break;
    kept.unshift(words[i]);
  }
  return kept.join(" ");
}

// Cleans one ADDRESS_RE match into a street span, or "" when it isn't really
// an address: the word right before the house number must be a street word
// (morpheme/exact-word tests above), and the walk-back keeps preceding
// non-filler words — a locality like "kallhäll" or "Main" rides along (even
// lowercase) while intent filler ("of", "view") stops the walk. Shared by
// extractPlace (user messages) and addressesInText (assistant answers).
/**
 * @param {string} matchText
 * @returns {string}
 */
function streetSpanOf(matchText) {
  const words = matchText.trim().replace(/\s+/g, " ").split(" ");
  if (words.length < 2) return "";
  const streetIdx = words.length - 2;
  const streetWord = normWord(words[streetIdx]);
  if (!SWEDISH_STREET_SUFFIX_RE.test(streetWord) && !ENGLISH_STREET_WORDS.has(streetWord)) return "";
  let start = streetIdx;
  while (start > 0 && !STOPWORDS.has(normWord(words[start - 1]))) start--;
  return words.slice(start).join(" ");
}

// Pulls a single geocodable street-address / street-name candidate out of free
// text, or returns "" when the message names no street. Three shapes, most
// specific first:
//   1. a numbered address ("Kallhäll Maskinistvägen 11", "Main Street 5"),
//   2. a standalone Swedish street name ("Maskinistvägen", optionally "… in
//      Kallhäll"),
//   3. a standalone English street phrase ("Abbey Road", optionally "… London").
// Deliberately conservative so ordinary "<noun> <number>" phrases ("iPhone 15",
// "Article 5", "on May 5") and plain prose don't get mistaken for addresses.
// Only this candidate ever crosses the wire, never the whole message.
/**
 * @param {string} text
 * @returns {string} the address candidate, or "" when none is named
 */
export function extractPlace(text) {
  const raw = typeof text === "string" ? text : "";

  // 1) Numbered street address (most specific).
  for (const m of raw.matchAll(ADDRESS_RE)) {
    const street = streetSpanOf(m[0]);
    if (!street) continue;
    const rest = raw.slice(m.index + m[0].length);
    return withTrailingLocality(street, rest).slice(0, MAX_LOCATION_CHARS);
  }

  // 2) & 3) Standalone street name — pick whichever (Swedish token / English
  // phrase) appears earliest in the message.
  const sv = firstMatch(raw, SWEDISH_STREET_TOKEN_RE);
  const en = firstMatch(raw, ENGLISH_STREET_PHRASE_RE);
  const hit = sv && en ? (sv.index <= en.index ? sv : en) : sv || en;
  if (hit) {
    const lead = leadingLocality(raw.slice(0, hit.index));
    const street = (lead ? lead + " " : "") + hit[0].trim();
    const rest = raw.slice(hit.index + hit[0].length);
    return withTrailingLocality(street, rest).slice(0, MAX_LOCATION_CHARS);
  }
  return "";
}

/**
 * @param {string} raw
 * @param {RegExp} re
 */
function firstMatch(raw, re) {
  re.lastIndex = 0;
  return re.exec(raw);
}

// ---- named-place street-view requests ---------------------------------------

// An EXPLICIT street-view ask, the precondition for the free-text place
// query below and for the honest unresolved note. Typo-tolerant: an
// enumerated set of common misspellings, not a loose pattern — reported
// verbatim 2026-07-08: "Streer view" missed the exact-match regex and the
// whole ask fell through to a clarify.
// Swedish gets the same breadth as English: the definite form ("gatuvyn"),
// the gatvy typo, and the synonym "gatubild(en)" (Swedish-language parity
// audit 2026-07-09).
const SV_WORDS =
  "(?:street|streer|stret|streat|steet|sreet|stere)\\s*(?:view|veiw|vew|wiev)|streetview|gatu?vy(?:n)?|gatubild(?:en)?";
const STREETVIEW_INTENT_RE = new RegExp(`\\b(?:${SV_WORDS})\\b`, "iu");
const STREETVIEW_INTENT_ALL_RE = new RegExp(`\\b(?:${SV_WORDS})\\b`, "giu");
/**
 * @param {string} text
 * @returns {boolean}
 */
export function streetViewIntent(text) {
  return STREETVIEW_INTENT_RE.test(typeof text === "string" ? text : "");
}

// Relocation-verb/deictic filler (English and Swedish alike) that can be
// left over once the street-view intent words are stripped — see the
// guard in extractPlaceQuery below.
const DEICTIC_FILLER_RE =
  /^(?:(?:go|co|gå|ga|continue|carry|fortsätt|fortsatt|take|ta|me|us|mig|oss|onwards|on|vidare|there|dit|here|här|har)(?![\p{L}\p{M}])[\s,]*)+[?!.]*$/iu;

// A named-place street-view request ("Street view of LEGO offices in
// Copenhagen", "gatuvy Turning Torso i Malmö") carries no street address for
// extractPlace — but Places Text Search resolves free-text place names fine
// (reported verbatim 2026-07-08: the LEGO ask fired nothing, and the model
// invented "enable Google Maps in Settings" instructions at a user whose
// knob was ON). When the message EXPLICITLY asks for street view, everything
// after the intent/filler words becomes the Places query. Returns "" when
// there's no explicit ask, an actual address is present (extractPlace owns
// it), or nothing usable remains — a bare "street view" follow-up must keep
// walking back instead.
/**
 * @param {string} text
 * @returns {string} the Places query, or "" when this shape doesn't apply
 */
export function extractPlaceQuery(text) {
  const raw = typeof text === "string" ? text : "";
  if (!streetViewIntent(raw) || extractPlace(raw)) return "";
  const words = raw
    .replace(STREETVIEW_INTENT_ALL_RE, " ")
    .split(/\s+/)
    .filter(Boolean);
  // Trim LEADING intent/filler only — interior connectors ("in Copenhagen")
  // belong to the place.
  let start = 0;
  while (start < words.length && STOPWORDS.has(normWord(words[start]))) start++;
  let q = words.slice(start).join(" ").replace(/[?!.]+$/u, "").trim();
  // Cut a trailing lowercase clause ("…Copenhagen, including a description
  // of the building") while keeping comma-joined proper localities
  // ("…1, København").
  q = q.replace(/,\s+\p{Ll}[\s\S]*$/u, "").trim();
  if (!q) return "";
  // A remainder that is ONLY relocation filler and deictics is no place
  // name — verbatim chat_logs #193 (2026-07-10): "Street view go there"
  // left q = "go there", which Places text search resolved to "Girls Go
  // There Salon" in Anderson, SC. The deictic resume belongs to the
  // go-there gate; this shape must fall through, never bill a lookup.
  if (DEICTIC_FILLER_RE.test(q)) return "";
  // Don't query bare filler ("street view of the area"): a single word must
  // at least look like a proper name.
  if (q.split(/\s+/).length < 2 && !/\p{Lu}/u.test(q)) return "";
  return q.slice(0, MAX_LOCATION_CHARS);
}

// ---- named-place visual questions (no street-view keyword, no address) -------

// A visual question about a NAMED PLACE — "There is a fast food restaurant in
// Uppsala, Sweden called ”Rosa Pantern”. What's the color of the building
// across the road from it?" (reported verbatim 2026-07-09, chat_logs #47) —
// carries no street address for extractPlace and no street-view keyword for
// extractPlaceQuery, so the whole ask fired nothing: no lookup, no honest
// unresolved note, and the model invented "enable Google Maps in Settings"
// instructions — the LEGO-offices failure class one layer further out.
// The extraction is deterministic and privacy-minimal (only the assembled
// place candidate crosses the wire, never the message): a NAME — quoted
// (”Rosa Pantern”, "rosapantern"), introduced by a naming cue ("called X",
// "som heter X"), or right after a place-type word ("restaurangen Rosa
// Pantern") — anchored by a place-type word or a capitalized locality
// ("in Uppsala", "i Malmö"). pickLookup fires it only when the message ALSO
// carries street-view/visual flavor (streetViewIntent or the strict
// referencesStreetView gate), so ordinary quoted titles ("the book called
// ”The Road”") never bill a lookup.

// Double-quote pairs only (typographic included — Swedish uses ”…”); single
// quotes/apostrophes live inside ordinary words ("I'm") and stay out.
const QUOTED_NAME_RE = /["“”„«»]([^"“”„«»]{2,60})["“”„«»]/gu;
const NAME_CUE_RE = /(?<![\p{L}\p{M}])(?:called|named|heter|kallas|kallad|kallat|vid namn)(?![\p{L}\p{M}])\s*/giu;
// Place-type words that mark the neighboring name as a PLACE name. Swedish
// gets the same breadth as English, definite forms included (parity rule).
const PLACE_TYPE_RE = new RegExp(
  "(?<![\\p{L}\\p{M}])(?:" +
    "restaurants?|diners?|caf[ée]s?|coffee ?shops?|bars?|pubs?|hotels?|hostels?|shops?|stores?|" +
    "supermarkets?|malls?|museums?|galler(?:y|ies)|schools?|universit(?:y|ies)|church(?:es)?|stations?|" +
    "kiosks?|pizzerias?|baker(?:y|ies)|gyms?|cinemas?|theatres?|theaters?|" +
    // Roadside/errand amenities (added with the nearby-place search,
    // 2026-07-09 — "Gas station near e18 there"): fuel, pharmacy, cash,
    // parking, care, groceries.
    "gas ?stations?|petrol ?stations?|fuel ?stations?|service ?stations?|pharmac(?:y|ies)|drugstores?|" +
    "atms?|banks?|grocer(?:y|ies)|grocery ?stores?|parking|hospitals?|clinics?|police ?stations?|" +
    "librar(?:y|ies)|bibliotek(?:et|en)?|" +
    "restaurang(?:en|er|erna)?|gatukök(?:et|en)?|kaf[ée](?:et|er)?|krog(?:en|ar|arna)?|hotell(?:et|en)?|" +
    "butik(?:en|er|erna)?|affär(?:en|er|erna)?|köpcentr(?:um|et)|museet|skol(?:a|an|or|orna)|" +
    "universitet(?:et)?|kyrk(?:a|an|or|orna)|kiosk(?:en|er)?|pizzeri(?:a|an|or)|" +
    "bageri(?:et|er)?|biograf(?:en|er)?|teater(?:n|rar)?|" +
    // The Swedish amenity parity set, definite/plural forms included; "mack"
    // is the everyday word for a gas station.
    "bensinstation(?:en|er|erna)?|bensinmack(?:en|ar)?|mack(?:en|ar|arna)?|tankställe(?:t|n)?|" +
    "apotek(?:et|en)?|bankomat(?:en|er|erna)?|uttagsautomat(?:en|er)?|parkering(?:en|ar|arna)?|" +
    "sjukhus(?:et|en)?|vårdcentral(?:en|er|erna)?|polisstation(?:en|er)?|" +
    "mataffär(?:en|er|erna)?|matbutik(?:en|er|erna)?|livsmedelsbutik(?:en|er|erna)?" +
    ")(?![\\p{L}\\p{M}])",
  "iu",
);
// A capitalized locality after a place connector ("in Uppsala", "i Malmö",
// "near Odenplan"). Deliberately NOT case-insensitive: with the i flag \p{Lu}
// would match lowercase too, and a lowercase capture would turn ordinary
// prose after "i"/"in" into a "locality". Bare "i" is lowercase-only — the
// English pronoun is always capital, the Swedish preposition practically
// always lowercase.
const PLACE_LOCALITY_RE =
  /(?<![\p{L}\p{M}])(?:[Ii]n|[Aa]t|[Pp]å|[Pp]a|[Vv]id|[Nn]ear|[Nn]ära|[Uu]tanför|[Oo]utside|i)\s+(\p{Lu}[\p{L}\p{M}'’.-]*(?:\s+\p{Lu}[\p{L}\p{M}'’.-]*)?)/gu;

// Walk forward over the words after a cue/type match, collecting the name:
// stops at intent/filler stopwords and at terminal punctuation (which ends a
// name like `”Rosa Pantern”.` cleanly), strips surrounding quotes/punctuation
// per word, keeps at most 4 words.
/** @param {string} rest */
function walkNameWords(rest) {
  const out = [];
  for (const w of rest.trim().split(/\s+/)) {
    const core = w.replace(/^[^\p{L}\d]+|[^\p{L}\d]+$/gu, "");
    if (!core || STOPWORDS.has(normWord(core))) break;
    out.push(core);
    if (/[.,!?;:"”“»]$/u.test(w) || out.length >= 4) break;
  }
  const name = out.join(" ");
  return /\p{L}/u.test(name) && name.length >= 2 ? name : "";
}

/** @param {string} raw */
function quotedNameOf(raw) {
  for (const m of raw.matchAll(QUOTED_NAME_RE)) {
    const words = m[1].trim().split(/\s+/).filter(Boolean);
    if (!words.length || words.length > 6) continue;
    const name = words.join(" ");
    if (!/\p{L}/u.test(name)) continue;
    if (words.every((w) => STOPWORDS.has(normWord(w)))) continue;
    return name;
  }
  return "";
}

/**
 * @param {string} raw
 * @param {RegExp} re
 */
function nameAfterMatch(raw, re) {
  re.lastIndex = 0;
  const m = re.exec(raw);
  if (!m) return "";
  return walkNameWords(raw.slice(m.index + m[0].length));
}

/**
 * @param {string} raw
 * @param {string} name
 */
function placeLocalityOf(raw, name) {
  const n = (name || "").toLowerCase();
  for (const m of raw.matchAll(PLACE_LOCALITY_RE)) {
    const loc = (m[1] || "").trim();
    if (!loc) continue;
    const l = loc.toLowerCase();
    // "near Rosa Pantern" captures the name itself — that's not a locality.
    if (n.includes(l) || l.includes(n)) continue;
    if (STOPWORDS.has(normWord(loc.split(/\s+/)[0]))) continue;
    return loc;
  }
  return "";
}

// The Places query for a named-place mention, or "" when the message names no
// place. Requires an anchor (place-type word or locality) alongside the name
// so a quoted book/film title never reads as a place. The street-view/visual
// gate is applied by the caller (pickLookup), not here.
/**
 * @param {string} text
 * @returns {string} the Places query, or "" when the message names no place
 */
export function extractNamedPlaceQuery(text) {
  const raw = typeof text === "string" ? text : "";
  if (!raw || extractPlace(raw)) return "";
  const name = quotedNameOf(raw) || nameAfterMatch(raw, NAME_CUE_RE) || nameAfterMatch(raw, PLACE_TYPE_RE);
  if (!name) return "";
  const locality = placeLocalityOf(raw, name);
  if (!locality && !PLACE_TYPE_RE.test(raw)) return "";
  return (locality ? `${name}, ${locality}` : name).slice(0, MAX_LOCATION_CHARS);
}

// ---- nearby-place asks (Google Places search around the current position) ----

// Reported verbatim 2026-07-09: mid-panorama, "Gas station near e18 there"
// routed to the POV scene capture ("there" is a deictic in the loose gate),
// so the model LOOKED at the current frame instead of SEARCHING — the gas
// station wasn't in view and the answer denied. A place-TYPE word plus a
// NEARBY word is a search ask, not a look ask: with a live anchor it goes
// to Places Text Search biased around the current position (pickLookup's
// `nearby` shape → enrichment.js runNearbyPlaceEnrichment).
//
// "here"/"there" count as nearby words ONLY because the type word is also
// required — "street view here" (no type) keeps its here-jump, while "is
// there a pharmacy?" resolves the idiomatic "there" into the search it is.
const NEARBY_WORD_RE =
  /(?<![\p{L}\p{M}])(?:near(?:by|est)?|closest|close by|around here|here|there|närmaste|närmsta|nörmaste|nörmsta|nära|i närheten|häromkring|i området|runt här|här|där)(?![\p{L}\p{M}])/iu;
// Leading question filler stripped off the Places query ("is there a",
// "find me", "finns det någon", "var finns") — the remainder is what gets
// searched, and Places' text search handles natural phrasing fine.
const NEARBY_LEAD_RE =
  /^(?:(?:is|are)\s+there\s+(?:a|an|any)?|find(?:\s+me)?(?:\s+(?:a|an|any))?|show(?:\s+me)?(?:\s+(?:a|an|any))?|any|hitta|visa(?:\s+mig)?|finns\s+det\s+(?:någon|nagon|något|nagot|några|nagra)?|var\s+finns)\s*/iu;
// A trailing bare deictic ("… there", "… här") adds nothing to the query —
// the location bias carries the position.
const NEARBY_TRAIL_RE =
  /[\s,]*(?:right\s+)?(?:around\s+here|close\s+by|nearby|i\s+närheten|häromkring|härifrån|here|there|här|där)?[\s?!.]*$/iu;

// A SUPERLATIVE opener ("nearest coop", "närmaste willys") makes a short
// NAME a nearby search even without a place-TYPE word — reported verbatim
// 2026-07-09: "nearest coop"-shaped asks got clarifies because Coop is a
// brand, not a type. Typo forms included, matching the move/street-view
// convention.
const NEAREST_LEAD_RE =
  /^(?:the\s+)?(?:near[e]?st|neares|neardst|closest|närmaste|närmsta|narmaste|narmsta|nörmaste|nörmsta)(?![\p{L}\p{M}])/iu;

/**
 * @param {string} text
 * @returns {string} the Places query, or "" when this isn't a nearby ask
 */
export function extractNearbyPlaceQuery(text) {
  const raw = (typeof text === "string" ? text : "").trim();
  if (!raw || raw.length > 120) return "";
  if (extractPlace(raw)) return ""; // a real address owns the message
  const asksNearby = NEARBY_WORD_RE.test(raw) || TELEPORT_VERB_RE.test(raw) || TRAVEL_TO_RE.test(raw) || NEAREST_LEAD_RE.test(raw);
  if (!asksNearby) return "";
  const q = raw.replace(TELEPORT_LEAD_RE, "").replace(NEARBY_LEAD_RE, "").replace(NEARBY_TRAIL_RE, "").trim();
  if (!q) return "";
  if (PLACE_TYPE_RE.test(raw)) {
    if (!PLACE_TYPE_RE.test(q)) return "";
    return q.slice(0, MAX_LOCATION_CHARS);
  }
  // No place-TYPE word: only the superlative + a short NAME qualifies
  // ("nearest coop") — the name must carry a non-stopword.
  const words = q.split(/\s+/).filter(Boolean);
  if (!NEAREST_LEAD_RE.test(q) || words.length < 2 || words.length > 4) return "";
  if (words.slice(1).every((w) => STOPWORDS.has(normWord(w)))) return "";
  return q.slice(0, MAX_LOCATION_CHARS);
}

// How the nearby ask wants to be ANSWERED — the user's explicitly refined
// semantics (2026-07-09): "teleport should just drop you there. If I say
// 'go to nearest …' then we do the actual travel with waypoints and map
// views."
//   "instant" — teleport/jump verbs: DROP at the destination, no travel
//               narrative, no route map, no series.
//   "travel"  — go/get/take-me/walk-to verbs: the actual travel — start
//               narrative, photo waypoints along the way, the route map.
//   "search"  — no relocation verb ("gas station near e18"): informational
//               — results + destination view + route map.
/**
 * @param {string} text
 * @returns {NearbyMode}
 */
export function nearbyAskMode(text) {
  const t = typeof text === "string" ? text : "";
  if (TELEPORT_VERB_RE.test(t)) return "instant";
  if (TRAVEL_TO_RE.test(t)) return "travel";
  return "search";
}

// Initial bearing (degrees clockwise from north) from point 1 toward point
// 2 — equirectangular like movePoint/distanceMeters, exact enough for the
// ≤ a-few-km travel captures. Pure and exported for tests.
/**
 * @param {number} lat1
 * @param {number} lng1
 * @param {number} lat2
 * @param {number} lng2
 * @returns {number} whole degrees in [0, 360)
 */
export function bearingDeg(lat1, lng1, lat2, lng2) {
  const rad = Math.PI / 180;
  const x = (lng2 - lng1) * Math.cos(((lat1 + lat2) / 2) * rad);
  const y = lat2 - lat1;
  return Math.round(((Math.atan2(x, y) * 180) / Math.PI + 360) % 360);
}

// ---- teleport & cross-barrier asks -------------------------------------------

// "jump"/"teleport" mean INSTANT relocation — the user's explicitly stated
// semantics (2026-07-09): "if I say 'jump' or 'teleport' I mean just
// relocate there, no path finding". Travel verbs ("get to", "ta mig till")
// carry the same relocation intent. Everything here is VIRTUAL panorama
// navigation — the blocks say so, because the reported failure was the
// model lecturing a panorama user to "never cross the tracks directly".
const TELEPORT_VERB_RE =
  /(?<![\p{L}\p{M}])(?:jump|teleport|beam(?:\s+(?:me|us))?|hoppa|teleportera)(?![\p{L}\p{M}])/iu;
// The continuation particle ("go ON to Stockholm", "gå VIDARE till …",
// "fortsätt till …") rides along — verbatim chat_logs #192 (2026-07-10):
// mid-journey "Go on to stockholm central station" matched nothing and fell
// into web research (train timetables). "continue"/"carry" REQUIRE the
// particle: bare "continue to <verb>" is the English infinitive
// ("continue to improve"), not a relocation.
const TRAVEL_TO_RE =
  /(?<![\p{L}\p{M}])(?:(?:get|go|move|travel|walk|head|take\s+(?:me|us)|ta\s+(?:mig|oss|iss|mej)|gå|ga|åk|förflytta|forflytta)(?:\s+(?:me|us|mig|oss|iss|mej))?(?:\s+(?:on|onwards?|vidare))?|(?:continue|carry)\s+(?:on|onwards?|vidare)|fortsätt(?:\s+vidare)?|fortsatt(?:\s+vidare)?)\s+(?:to|till|över|over|across)(?![\p{L}\p{M}])/iu;
// Strips the relocation verb phrase off a nearby-place query, so "teleport
// to the nearest gas station" searches for "nearest gas station". The
// word-boundary lookaheads matter: without them the diacritic-less Swedish
// verb "ga" ate the start of "Gas station…".
// The optional openers include "let's/lets" (and the reported adjacent-key
// typo "legs" — verbatim 2026-07-09: "Legs go to coop" got a clarify) and a
// bare "ok" ("Ok nearest gas station").
const TELEPORT_LEAD_RE =
  /^(?:(?:please|ok|okay|let'?s|lets|legs)\s+)?(?:jump|teleport|beam|hoppa|teleportera|get|go|move|travel|walk|head|take|ta|gå|ga|åk|förflytta|forflytta|continue|carry|fortsätt|fortsatt)(?![\p{L}\p{M}])(?:\s+(?:me|us|mig|oss|iss|mej)(?![\p{L}\p{M}]))?(?:\s+(?:on|onwards?|vidare)(?![\p{L}\p{M}]))?(?:\s+(?:to|till|över|over|across)(?![\p{L}\p{M}]))?\s*(?:(?:the|a|an|den|det|en|ett)\s+)?/iu;

// "The other side of the railway" — a barrier the user wants the panorama
// relocated across (reported verbatim 2026-07-09: "Get to the other side
// of the railway", twice, got a real-world safety lecture instead of a
// relocation). Diacritic-less Swedish rides along; the bare diacritic-less
// "spar"/"an" forms are excluded (ordinary words) — they need their
// definite suffix.
const BARRIER_WORDS =
  "railway|railroad|rail\\s*way|train\\s*tracks?|tracks?|rails|river|stream|canal|road|street|highway|motorway|freeway|bridge|" +
  "järnväg(?:en)?|jarnvag(?:en)?|(?:tåg)?spår(?:et|en)?|(?:tag)?spar(?:et|en)|älven|alven|ån|floden|kanalen|vägen|vagen|gatan|motorvägen|motorvagen|bron";
const OTHER_SIDE_RE = new RegExp(
  `(?:(?:other|far)\\s+side\\s+of|andra\\s+sidan(?:\\s+av)?)\\s+(?:the\\s+)?(${BARRIER_WORDS})(?![\\p{L}\\p{M}])`,
  "iu",
);
const ACROSS_BARRIER_RE = new RegExp(
  `(?:across|över|over)\\s+(?:the\\s+)?(${BARRIER_WORDS})(?![\\p{L}\\p{M}])`,
  "iu",
);

// ---- journey view ("show how we traveled") ------------------------------------

// Requested 2026-07-09: after a session of relocations, "Show how we
// traveled on maps" should draw the visited positions as a route — the
// model instead listed coordinates with a disclaimer that no travel trail
// exists. It does exist: every relocation answer carries the MANDATED
// keyless coordinate links, so the journey is recoverable from the
// conversation deterministically.
const JOURNEY_ASK_RE =
  /(?<![\p{L}\p{M}])(?:(?:show|draw|display|map|trace|plot|visa|rita|kartlägg|kartlagg)(?![\p{L}\p{M}])[\s\S]{0,40}?(?:how\s+(?:we|i)\s+(?:traveled|travelled|moved|went|got\s+here)|(?:our|my|the)\s+(?:route|path|journey|trail|trip|travels?|way\s+here)|hur\s+(?:vi|jag)\s+(?:åkte|akte|reste|rörde\s+(?:oss|mig)|rorde\s+(?:oss|mig)|tog\s+(?:oss|mig)|kom\s+hit|färdades|fardades)|(?:vår|var|min|hela)\s+(?:rutt(?:en)?|resa(?:n)?|färd(?:en)?|fard(?:en)?)|rutt(?:en)?|resan|färden|farden)|how\s+did\s+(?:we|i)\s+(?:travel|get\s+here)|hur\s+(?:åkte|akte|reste)\s+(?:vi|jag)|hur\s+kom\s+(?:vi|jag)\s+hit)(?![\p{L}\p{M}])/iu;
/**
 * @param {string} text
 * @returns {boolean}
 */
export function journeyAsk(text) {
  return JOURNEY_ASK_RE.test(typeof text === "string" ? text : "");
}

// The coordinates every Maps block MANDATES into the answers: the keyless
// Google links (query=LAT,LNG / viewpoint=LAT,LNG) and the embed reference
// lines ("panorama at LAT, LNG"). Assistant turns only — user text quoting
// a coordinate must not fabricate a stop.
const JOURNEY_COORD_RE =
  /(?:[?&]query=|viewpoint=|panorama at )(-?\d{1,2}\.\d{3,}),\s?(-?\d{1,3}\.\d{3,})/g;
// Consecutive stops closer than this are the same position (an answer's
// query= and viewpoint= links repeat the same point).
const JOURNEY_DEDUP_M = 20;
const JOURNEY_MAX_POINTS = 12;

// Walks the ASSISTANT turns in order and returns the journey's waypoints
// ([{lat,lng}...], oldest first, consecutive duplicates collapsed, capped
// to the most recent JOURNEY_MAX_POINTS). Pure and exported for tests.
/**
 * @param {Conversation} conversation
 * @returns {LatLng[]}
 */
export function extractJourneyPoints(conversation) {
  const points = [];
  for (const m of Array.isArray(conversation) ? conversation : []) {
    if (m?.role !== "assistant") continue;
    const text = textOf(m.content);
    for (const hit of text.matchAll(JOURNEY_COORD_RE)) {
      const lat = Number(hit[1]);
      const lng = Number(hit[2]);
      if (!Number.isFinite(lat) || lat < -90 || lat > 90) continue;
      if (!Number.isFinite(lng) || lng < -180 || lng > 180) continue;
      const prev = points[points.length - 1];
      if (prev && distanceMeters(prev.lat, prev.lng, lat, lng) < JOURNEY_DEDUP_M) continue;
      points.push({ lat, lng });
    }
  }
  return points.slice(-JOURNEY_MAX_POINTS);
}

// Returns { barrier } for a cross-barrier relocation ask, else null. A
// relocation/travel verb makes any phrasing count; verb-less phrasings
// must be short commands ("other side of the tracks"), so prose that
// merely mentions a river's far side never fires.
/**
 * @param {string} text
 * @returns {{ barrier: string } | null}
 */
export function extractCrossBarrierAsk(text) {
  const raw = (typeof text === "string" ? text : "").trim();
  if (!raw || raw.length > 120) return null;
  const m = raw.match(OTHER_SIDE_RE) || raw.match(ACROSS_BARRIER_RE);
  if (!m) return null;
  const hasVerb = TELEPORT_VERB_RE.test(raw) || TRAVEL_TO_RE.test(raw);
  if (!hasVerb && raw.split(/\s+/).length > 8) return null;
  return { barrier: m[1].toLowerCase().replace(/\s+/g, " ") };
}

// Meters between two coordinates — equirectangular, exact enough for the
// "≈X m away" labels in the nearby-places block (same approximation as
// movePoint). Pure and exported for tests + googlemaps.js.
/**
 * @param {number} lat1
 * @param {number} lng1
 * @param {number} lat2
 * @param {number} lng2
 * @returns {number} whole meters
 */
export function distanceMeters(lat1, lng1, lat2, lng2) {
  const rad = Math.PI / 180;
  const x = (lng2 - lng1) * rad * Math.cos(((lat1 + lat2) / 2) * rad);
  const y = (lat2 - lat1) * rad;
  return Math.round(Math.sqrt(x * x + y * y) * 6371000);
}

// ---- fragment answers to "which office?" ------------------------------------

// NUMBERED addresses anywhere in a text — used on ASSISTANT messages, whose
// research answers surface the addresses the user then refers back to
// ("Accenture has offices at Alströmergatan 12, Rådmansgatan 42, …" →
// user: "Alstromer"). Numbered-only on purpose: assistant prose mentions
// many bare street names; a street + house number is a high-precision
// candidate.
/**
 * @param {string} text
 * @returns {string[]}
 */
function addressesInText(text) {
  const raw = typeof text === "string" ? text : "";
  const out = [];
  for (const m of raw.matchAll(ADDRESS_RE)) {
    const street = streetSpanOf(m[0]);
    if (street) out.push(street);
  }
  return out;
}

// Diacritics-insensitive normalization so a user's quick "Alstromer" matches
// "Alströmergatan" (fragments are typed fast, without ö/ä/å).
/** @param {string} s */
const normForMatch = (s) =>
  (s || "").toLowerCase().normalize("NFD").replace(/\p{M}/gu, "");

// Matches a short fragment the user typed (usually answering the model's own
// "which office?" clarify) against every address the CONVERSATION has
// surfaced — assistant research answers included, which the user-only
// walk-back can never see (reported verbatim 2026-07-08: assistant listed
// three Accenture offices, user answered "Alstromer", and the model just
// asked again). Returns the address only on a UNIQUE match; ambiguous or
// unknown fragments return "" so the clarify loop can continue honestly.
/**
 * @param {Conversation} conversation
 * @param {string} fragment
 * @returns {string} the unique matched address, or ""
 */
export function matchAddressFragment(conversation, fragment) {
  const frag = normForMatch((fragment || "").trim());
  if (frag.length < 4) return "";
  const msgs = Array.isArray(conversation) ? conversation : [];
  const candidates = [];
  const seen = new Set();
  for (let i = msgs.length - 1; i >= 0; i--) {
    const t = textOf(msgs[i]?.content);
    const found = msgs[i]?.role === "assistant" ? addressesInText(t) : [extractPlace(t)].filter(Boolean);
    for (const a of found) {
      const key = normForMatch(a);
      if (!seen.has(key)) {
        seen.add(key);
        candidates.push(a);
      }
    }
  }
  const hits = candidates.filter((a) => {
    const n = normForMatch(a);
    return n.startsWith(frag) || n.includes(" " + frag) || n.includes(frag);
  });
  return hits.length === 1 ? hits[0] : "";
}

// True when this conversation is street-view flavored: some earlier USER
// turn explicitly asked for it (typo-tolerant), so a bare fragment answer
// like "Alstromer" can be read as picking a location.
/** @param {Message[]} users */
function conversationAsksStreetView(users) {
  return users.some((m) => streetViewIntent(textOf(m?.content)));
}

// ---- locality-correction extraction ------------------------------------------

// A correction turn names a CITY but no street ("I meant in hallstahammar!",
// "jag menade i hallstahammar", or just "i hallstahammar") — reported
// verbatim 2026-07-08: "lidbecksgatan 10" resolved to the wrong city, the
// user corrected with a city-only message, and every later lookup STILL
// walked back to the bare street and picked the wrong city again, because
// no single message carried street + corrected city together. pickLookup
// merges this fix onto the walked-back street. Cues are the STRONG
// correction words only (meant/instead/rather + Swedish) — weak cues like
// "not"/"actually" appear in ordinary questions and would turn arbitrary
// words into "localities".
const FIX_CUE_RE = /\b(?:meant|instead|rather|menade|menar|istället|snarare)\b/iu;
const FIX_AFTER_CUE_RE =
  /\b(?:meant|instead|rather|menade|menar|istället|snarare)\b[,!.]?\s*(?:\b(?:in|i|på|pa)\s+)?([\p{L}][\p{L}\p{M}'’.-]*(?:\s+[\p{L}][\p{L}\p{M}'’.-]*)?)/iu;
const FIX_AFTER_CONNECTOR_RE =
  /\b(?:in|i|på|pa)\s+([\p{L}][\p{L}\p{M}'’.-]*(?:\s+[\p{L}][\p{L}\p{M}'’.-]*)?)/iu;
// The WHOLE message is "in X" / "i X" (a bare one-line correction).
const FIX_BARE_MESSAGE_RE =
  /^\s*(?:in|i|på|pa)\s+([\p{L}][\p{L}\p{M}'’.-]*(?:\s+[\p{L}][\p{L}\p{M}'’.-]*)?)[\s!.?]*$/iu;

/**
 * @param {string} text
 * @returns {string} the corrected locality, or "" when this isn't a correction
 */
export function extractLocalityFix(text) {
  const raw = typeof text === "string" ? text : "";
  // A message that names a full address needs no fix-merging — extractPlace
  // handles it outright.
  if (!raw || extractPlace(raw)) return "";
  let m = null;
  if (FIX_CUE_RE.test(raw)) {
    m = raw.match(FIX_AFTER_CUE_RE) || raw.match(FIX_AFTER_CONNECTOR_RE);
  } else {
    m = raw.match(FIX_BARE_MESSAGE_RE);
  }
  if (!m || !m[1]) return "";
  const words = [];
  for (const w of m[1].trim().split(/\s+/)) {
    if (!w || STOPWORDS.has(normWord(w))) break;
    words.push(w);
  }
  return words.join(" ");
}

// Merges a locality correction onto a walked-back street: the fix REPLACES
// any comma-appended locality the address already carried (it's a
// correction), and is a no-op when the address already names it.
/**
 * @param {string} address
 * @param {string} fix
 * @returns {string}
 */
function withLocalityFix(address, fix) {
  if (!fix) return address;
  if (address.toLowerCase().includes(fix.toLowerCase())) return address;
  return `${address.split(",")[0].trim()}, ${fix}`;
}

// ---- follow-up reference gate -------------------------------------------------

// Does a message that names NO address refer back to previously discussed
// Street View imagery / the place being looked at? This is the deterministic
// gate for follow-up turns ("what color is the roof?", "vad är det för färg på
// taket?") — without it, a follow-up carries no address, no enrichment runs,
// and the model truthfully claims it has no knowledge of the image (the
// reported bug). Vocabulary: imagery words, building parts, and visual
// attributes in English and Swedish. Deliberately excludes generics like
// "see"/"there"/"look" alone (they'd re-trigger a billed lookup on ordinary
// follow-ups); "look like" is specific enough to keep. A false positive only
// costs one cached-able Maps lookup and a harmless context block; a false
// negative degrades to today's behavior — both fail-soft.
// NOTE: \b is ASCII-only in JS — it never fires next to å/ä/ö/é ("på?" has no
// \b after "å") — so the word boundaries are Unicode-aware lookarounds.
const FOLLOWUP_REFERENCE_RE = new RegExp(
  "(?<![\\p{L}\\p{M}])(?:" +
    // imagery / the view itself
    "street ?view|gatuvy(?:n)?|gatubild(?:en)?|imager?y|images?|pictures?|photos?|panoramas?|" +
    "bild(?:en|er|erna)?|foto(?:t|n|na)?|" +
    // the building and its parts
    "buildings?|house[s]?|roof(?:s|top)?|fa[cç]ades?|windows?|doors?|garages?|" +
    "gardens?|yards?|fences?|balcon(?:y|ies)|entrances?|floors?|stor(?:ey|ies|eys)|chimneys?|" +
    "hus(?:et|en)?|byggnad(?:en|er|erna)?|tak(?:et|en)?|fasad(?:en|er|erna)?|" +
    "fönst(?:er|ret|ren|erna)|dörr(?:en|ar|arna)?|trädgård(?:en|ar|arna)?|" +
    "staket(?:et|en)?|balkong(?:en|er|erna)?|entré(?:n|er|erna)?|våning(?:en|ar|arna)?|skorsten(?:en|ar)?|" +
    // visual attributes / surroundings
    "colou?rs?|visible|surroundings?|neighbou?rhoods?|parked|" +
    "look(?:s|ed|ing)? (?:like|at)|across the (?:street|road)|opposite|" +
    "färg(?:en|er|erna)?|syns|omgivning(?:en|ar|arna)?|grann(?:e|en|ar|arna)|parkerad(?:e|a)?|" +
    "ser (?:det|den|huset|byggnaden|platsen) ut|mittemot|tvärs över gatan|" +
    // panorama-referring phrases ("what am I looking at?", after panning)
    "am i (?:seeing|looking)|in front of|this view|the view|" +
    "vy(?:n|er|erna)?|tittar (?:jag|vi|man) på|ser jag|framför (?:mig|oss)|" +
    // asking the ASSISTANT what it sees ("What do you see", "vad ser du" —
    // reported verbatim 2026-07-09: both got a no-image denial mid-panorama)
    "what (?:do|can|could) you see|vad ser (?:du|ni)|vad kan (?:du|ni) se" +
    ")(?![\\p{L}\\p{M}])",
  "iu",
);

/**
 * @param {string} text
 * @returns {boolean}
 */
export function referencesStreetView(text) {
  return FOLLOWUP_REFERENCE_RE.test(typeof text === "string" ? text : "");
}

// The LOOSE gate for the live-panorama (POV) path: anything a user says
// while pointing at a live street scene. Grown in two reported rounds —
// first scene CONTENTS the strict building gate can't cover ("Describe the
// person" → no capture → the model asked "what person?"), then, when the
// noun vocabulary kept leaking (Workers Logs 2026-07-08 ~13:22Z: 4 of 5
// panorama follow-ups fired nothing), the structural classes below: bare
// DEICTIC references ("what is that?", "is it open?", "vad är det där?"),
// POSITIONAL phrasing ("the building to the left", "across from me"), and
// VISUAL-ACT verbs ("describe", "read", "zoom", "beskriv", "läs"). Kept
// SEPARATE from the strict gate on purpose: a POV capture is one cheap,
// cached Static frame and the user demonstrably has the panorama open, so
// false positives cost little — the walk-back path (no POV) keeps the
// strict gate because it re-runs a full billed lookup.
const SCENE_REFERENCE_RE = new RegExp(
  "(?<![\\p{L}\\p{M}])(?:" +
    // people & animals
    "person|people|man|men|woman|women|child(?:ren)?|kids?|guys?|dudes?|folks?|gentleman|lady|pedestrians?|someone|anyone|crowd|dogs?|cats?|" +
    "person(?:en|er|erna)?|människ(?:a|an|or|orna)|man(?:nen)?|män(?:nen)?|kvinn(?:a|an|or|orna)|barn(?:et|en)?|någon|folk|hund(?:en|ar)?|katt(?:en|er)?|" +
    // person-deictic pronouns ("what is he wearing?", "vem är hon?")
    "he|she|him|her|han|hon|honom|henne|" +
    // vehicles
    "vehicles?|vans?|trucks?|bus(?:es)?|bikes?|bicycles?|motorcycles?|scooters?|" +
    "fordon(?:et|en)?|bil(?:en|ar|arna)?|lastbil(?:en|ar)?|buss(?:en|ar|arna)?|cykel(?:n)?|cyklar(?:na)?|moped(?:en)?|" +
    // signage, businesses, street furniture, greenery
    "signs?|signage|shops?|stores?|storefronts?|business(?:es)?|restaurants?|caf[ée]s?|" +
    "trees?|statues?|graffiti|posters?|flags?|logos?|bench(?:es)?|" +
    "skylt(?:en|ar|arna)?|affär(?:en|er|erna)?|butik(?:en|er|erna)?|restaurang(?:en|er|erna)?|" +
    "träd(?:et|en)?|staty(?:n|er)?|flagg(?:a|an|or)|bänk(?:en|ar)?|" +
    // bare deictic references — the user is pointing at the scene
    // ("The one in view" — reported verbatim — carries ONLY these signals).
    // "here" included (reported verbatim 2026-07-09: "What do we have
    // here" mid-panorama logged maps_intent "none" — Swedish "här" was in
    // the list, English "here" wasn't; the parity rule cuts both ways)
    "that|this|it|these|those|there|here|views?|(?:the|that|this) ones?|" +
    "det|den|där|här|denna|detta|dessa|dom|vyn?|(?:den|det) här|" +
    // temporal continuations — the user moved the panorama and re-asks
    // ("And now" — reported verbatim 2026-07-09: it fired nothing, no
    // capture ran, and the model invented a scene; "what about now?",
    // "again?", "och nu?", "nu då?")
    "now|again|nu|igen|" +
    // positional phrasing within the view
    "left|right|behind|ahead|front|corner|opposite|across|next to|" +
    "vänster|höger|bakom|framför|hörn(?:et)?|mittemot|bredvid|" +
    // visual-act verbs
    "describe|read|zoom|identify|" +
    "beskriv(?:a)?|läs(?:a)?|zooma|identifiera|" +
    // asking the assistant what it sees, loose forms ("do you see the shop?",
    // "kan du se…?") — the full "what do you see"/"vad ser du" phrasings sit
    // in the strict gate so they work even without a live POV
    "(?:do|can|could) you see|are you seeing|ser (?:du|ni)|kan (?:du|ni) se|" +
    // question phrases about the scene
    "who is|who's|what does .{0,20} say|" +
    "vem är|vad står" +
    ")(?![\\p{L}\\p{M}])",
  "iu",
);

/**
 * @param {string} text
 * @returns {boolean}
 */
export function referencesStreetViewScene(text) {
  const t = typeof text === "string" ? text : "";
  return referencesStreetView(t) || SCENE_REFERENCE_RE.test(t);
}

// ---- street-view jumps: "street view here" & relative moves ------------------
// (requested 2026-07-09) With a live view on screen (interactive map or
// panorama), the user can pop open Street View at the position they're
// looking at ("street view here", "gatuvy här") or a computed one ("100
// meters along this road", "200 m norrut") — deterministic phrase parsing +
// flat-earth-at-this-scale destination math, no model in the loop.

// Compass words → bearing degrees (EN + SV incl. the "-ut" adverb forms).
// 8-point names FIRST: "northeast" must not read as "north" + junk.
// Diacritic-less Swedish variants (soderut, vasterut) ride along — users on
// non-Swedish keyboards type them routinely, the same reality the
// diacritics-insensitive address-fragment matching already handles. Bare
// "vast"/"ost" (English words / cheese) are deliberately NOT included —
// only the unambiguous -ut adverb and -er forms.
/** @type {[string, number][]} */
const COMPASS_WORDS = [
  ["north[- ]?east|nordost(?:ut)?|nordöst(?:ut)?", 45],
  ["south[- ]?east|sydost(?:ut)?|sydöst(?:ut)?", 135],
  ["south[- ]?west|sydväst(?:ut)?|sydvast(?:ut)?", 225],
  ["north[- ]?west|nordväst(?:ut)?|nordvast(?:ut)?", 315],
  ["north|norrut|norr", 0],
  ["south|söderut|söder|soderut|soder|syd", 180],
  ["east|österut|öster|osterut|oster|öst", 90],
  ["west|västerut|väster|vasterut|vaster|väst", 270],
];
const COMPASS_RES = COMPASS_WORDS.map(([words, bearing]) => ({
  re: new RegExp(`(?<![\\p{L}\\p{M}])(?:${words})(?![\\p{L}\\p{M}])`, "iu"),
  bearing,
}));

// A distance: "100 m", "100 meters", "0.5 km", "200 meter". Swedish "meter"
// is both singular and plural, so the EN forms cover it.
const DISTANCE_RE = /(\d+(?:[.,]\d+)?)\s*(km|kilomet(?:er|re)s?|m|met(?:er|re)s?|meter)\b/iu;
// Facing-relative words: "along this road", "down the street", "ahead",
// "framåt", "rakt fram", "längs vägen" — meaningful only from a panorama,
// whose heading says which way "along" IS. The forward word takes an
// enumerated misspelling set like the street-view word does (reported
// verbatim 2026-07-09: "Forwsrd 200m" mid-panorama fired nothing and the
// model asked for GPS coordinates one turn after a successful "Forward
// 100m"), plus diacritic-less Swedish (framat, langre fram, folj vagen).
const FORWARD_RE =
  /(?<![\p{L}\p{M}])(?:along|down|up)\s+(?:this|the|that|samma)?\s*(?:road|street|way)|(?<![\p{L}\p{M}])(?:ahead|ahed|forw[sa]rds?|fowards?|forwads?|forwrds?|further|onwards?|straight on|(?:längs|langs)\s+(?:den här\s+|denna\s+|samma\s+)?(?:vägen|gatan|vagen)|längre fram|langre fram|(?:följ|folj)\s+(?:vägen|gatan|vagen)|(?:uppför|nerför|nedför|uppfor|nerfor|nedfor)\s+(?:gatan|vägen|vagen)|framåt|framat|rakt fram|vidare)(?![\p{L}\p{M}])/iu;
const BACK_RE =
  /(?<![\p{L}\p{M}])(?:back(?:wards?)?|bakwards?|behind (?:me|us)|bakåt|bakat|tillbaka|tilbaka|tillbaks|backa)(?![\p{L}\p{M}])/iu;
// A movement/show verb — the anti-overfire requirement for bare compass
// moves ("the shop is 100 meters north of the station" while a map is open
// must NOT jump; "go 100 meters north" / a short bare "100 m north" must).
// Diacritic-less Swedish forms included (ga, fortsatt, oppna) — safe here
// because the verb only ever fires alongside a matched distance + compass.
const MOVE_VERB_RE =
  /(?<![\p{L}\p{M}])(?:go|move|walk|continue|head|jump|take me|show|open|pop|gå|ga|fortsätt|fortsatt|hoppa|ta mig|visa|öppna|oppna|flytta|förflytta|forflytta|promenera)(?![\p{L}\p{M}])/iu;

/** @param {number} n */
const clampMeters = (n) => Math.max(5, Math.min(3000, Math.round(n)));

// Parses a relative move out of the message: distance + direction. Returns
// null, or { meters, mode: "bearing"|"forward"|"back", bearing?, dir } where
// `dir` is the normalized word for block phrasing ("north", "forward"…).
/**
 * @param {string} text
 * @returns {{ meters: number, mode: "bearing", bearing: number, dir: string }
 *   | { meters: number, mode: "forward" | "back", dir: string }
 *   | null}
 */
export function extractRelativeMove(text) {
  const t = typeof text === "string" ? text : "";
  if (!t) return null;
  const dm = t.match(DISTANCE_RE);
  if (!dm) return null;
  let meters = Number(dm[1].replace(",", "."));
  if (!Number.isFinite(meters) || meters <= 0) return null;
  if (/^k/i.test(dm[2])) meters *= 1000;
  meters = clampMeters(meters);
  // Facing-relative first: "100 meters along this road" is inherently about
  // the view on screen, no extra verb needed.
  if (FORWARD_RE.test(t)) return { meters, mode: "forward", dir: "forward" };
  if (BACK_RE.test(t)) return { meters, mode: "back", dir: "back" };
  const compass = COMPASS_RES.find((c) => c.re.test(t));
  if (!compass) return null;
  // A bare compass distance fires only as a command (a move verb) or as a
  // short standalone message ("100 m norrut") — prose that merely MENTIONS
  // a distance ("the shop is 100 meters north of the station") stays out.
  if (!MOVE_VERB_RE.test(t) && t.trim().split(/\s+/).length > 6) return null;
  const dirWord = COMPASS_WORDS[COMPASS_RES.indexOf(compass)][0].split("|")[0].replace(/\[- \]\?/g, "");
  return { meters, mode: "bearing", bearing: compass.bearing, dir: dirWord };
}

// "Street view HERE": an explicit street-view ask pointing at the current
// position ("street view here", "popup street view at my current location",
// "gatuvy här", "öppna gatuvy där jag är") — no address, no place name.
const HERE_RE =
  /(?<![\p{L}\p{M}])(?:here|right here|current (?:location|position|spot|view)|this (?:location|position|spot|point)|my (?:actual |real |physical |current |own )?(?:location|position)|där jag (?:faktiskt |egentligen )?är|var jag är|min (?:nuvarande |faktiska |riktiga |verkliga |fysiska )?(?:position|plats)|nuvarande (?:plats|läge)|denna plats|den här platsen|härifrån|här)(?![\p{L}\p{M}])/iu;
/**
 * @param {string} text
 * @returns {boolean}
 */
export function streetViewHereIntent(text) {
  const t = typeof text === "string" ? text : "";
  return streetViewIntent(t) && HERE_RE.test(t);
}

// "WHERE AM I" — a plain ask about the user's own position, no street-view
// word at all (reported verbatim 2026-07-09: "Where am i now" → "Street
// view" → "My location" got three denials — every gate wanted street-view
// word + here-word in ONE message, and a bare where-am-I ask had no gate at
// all). It IS a here-ask: anchor to the device location (or live view) and
// open the view/map that answers it. Enumerated forms with an EN typo set
// and Swedish at the same breadth (invariant 6). The lookahead requires the
// phrase to end the clause (allowing a short decoration word — "now", "nu",
// "exactly" — then punctuation/end), so prose like "where are we going with
// this" or "var är vi på väg" never fires.
const WHERE_AM_I_RE =
  /(?<![\p{L}\p{M}])(?:(?:where|wher|were|whree?)\s+(?:exactly\s+)?(?:am\s+i|are\s+we)|va(?:r|rt)\s+(?:exakt\s+)?(?:är|e)\s+(?:jag|vi)|var\s+n[åa]gonstans\s+(?:är|e)\s+(?:jag|vi)|var\s+befinner\s+(?:jag\s+mig|vi\s+oss))(?=\s*(?:right\s+now|just\s+nu|now|exactly|currently|located|somewhere|nu|egentligen|n[åa]gonstans)?\s*(?:[?!.,]|$))/iu;
/**
 * @param {string} text
 * @returns {boolean}
 */
export function whereAmIIntent(text) {
  return WHERE_AM_I_RE.test(typeof text === "string" ? text : "");
}

// A short HERE-answer to the assistant's own "which address or place?"
// clarify ("My location", "här", "min plats") — the street-view word lives
// in an EARLIER user turn, so streetViewHereIntent can't see it (same
// 2026-07-09 report: "Street view" → clarify → "My location" fired nothing
// and the model invented enable-in-Settings steps at a knob-ON user).
// Deliberately tight — the fragment must be essentially nothing BUT a
// here-phrase, so a longer sentence merely containing "here" can't
// re-anchor the conversation to the device.
/**
 * @param {string} text
 * @returns {boolean}
 */
export function hereFragmentAnswer(text) {
  const t = (typeof text === "string" ? text : "").trim();
  if (!t || t.length > 48 || t.split(/\s+/).length > 4) return false;
  return HERE_RE.test(t);
}

// An EXPLICIT reference to the user's PHYSICAL location ("my actual
// location", "where I actually am", "min faktiska plats", "där jag
// faktiskt är"). Requested 2026-07-09: once a live panorama/map exists,
// follow-ups anchor to IT — moving around the map must not snap back to
// the device — so the device location only wins the anchor again when the
// user says they mean their real position, not the view they've navigated
// to. This gate is that say-so; it also makes the client re-request the
// device location even while a live view exists (message-content.js
// mirrors it).
const PHYSICAL_LOCATION_RE =
  /(?<![\p{L}\p{M}])(?:my (?:actual|real|physical|true|own) (?:location|position)|where i (?:actually|really) am|min (?:faktiska|riktiga|verkliga|fysiska|egna) (?:plats|position)|där jag (?:faktiskt|egentligen) är|var jag faktiskt är)(?![\p{L}\p{M}])/iu;
/**
 * @param {string} text
 * @returns {boolean}
 */
export function physicalLocationAsk(text) {
  return PHYSICAL_LOCATION_RE.test(typeof text === "string" ? text : "");
}

// The full here-ask decision for the latest turn: an explicit street-view-
// here ask, a plain where-am-I ask, an explicit physical-location ask, or
// a here-fragment answering an earlier street-view turn. Shared by
// pickLookup's jump gate and — via the exported conversation-level wrapper
// below — enrichment.js, which phrases the unresolved note as "allow
// location access" instead of "which address?" when the device location
// never arrived.
/**
 * @param {string} latest
 * @param {Message[]} users
 */
function isHereAsk(latest, users) {
  return (
    streetViewHereIntent(latest) ||
    whereAmIIntent(latest) ||
    physicalLocationAsk(latest) ||
    (conversationAsksStreetView(users) && hereFragmentAnswer(latest))
  );
}

/**
 * True when the conversation's latest user turn is a here-ask (see above).
 * @param {Conversation} conversation
 * @returns {boolean}
 */
export function hereAskIntent(conversation) {
  const users = Array.isArray(conversation) ? conversation.filter((m) => m?.role === "user") : [];
  return isHereAsk(textOf(users[users.length - 1]?.content), users);
}

// True when the latest turn is a relocation-family ask that would have
// matched — a "go to X", a nearby search, a barrier crossing, a "go
// there", or a fragment continuing a pending relocation — but pickLookup
// returned nothing because there was NO ANCHOR (no live view, no device
// location). The enrichment then appends the allow-location-access note
// instead of leaving the model to freestyle a clarify (verbatim
// 2026-07-09: "Lets go to hemköp stäket" with no location sent got
// "I'm not sure what that refers to… did you mean Hammarby Sjöstad?").
/**
 * @param {Conversation} conversation
 * @returns {boolean}
 */
export function needsAnchorAsk(conversation) {
  const users = Array.isArray(conversation) ? conversation.filter((m) => m?.role === "user") : [];
  const latest = textOf(users[users.length - 1]?.content);
  if (extractRelocationQuery(latest)) return true;
  if (extractNearbyPlaceQuery(latest)) return true;
  if (extractCrossBarrierAsk(latest)) return true;
  const t = latest.trim();
  if (GO_THERE_RE.test(t) && pendingRelocation(users)) return true;
  return !!t && t.length <= 40 && t.split(/\s+/).length <= 3 && !!pendingRelocation(users);
}

// Destination of a move from (lat, lng) `meters` toward `bearingDeg`.
// Equirectangular approximation — exact enough for the ≤3km moves the
// parser allows (centimeter error at this scale), rounded to ~10cm so
// repeated identical asks hit the server's capture cache.
/**
 * @param {number} lat
 * @param {number} lng
 * @param {number} bearingDeg
 * @param {number} meters
 * @returns {LatLng}
 */
export function movePoint(lat, lng, bearingDeg, meters) {
  const rad = (bearingDeg * Math.PI) / 180;
  const dLat = (meters * Math.cos(rad)) / 111320;
  const cosLat = Math.cos((lat * Math.PI) / 180);
  const dLng = (meters * Math.sin(rad)) / (111320 * (Math.abs(cosLat) > 1e-9 ? cosLat : 1e-9));
  return {
    lat: Math.round((lat + dLat) * 1e6) / 1e6,
    lng: Math.round((lng + dLng) * 1e6) / 1e6,
  };
}

// ---- relocation-to-a-NAME asks + the pending-relocation memory ---------------

// "Go to hemköp" / "teleport to willys": a relocation verb aimed at an
// arbitrary NAME (a brand, a shop — no place-TYPE word, no address).
// Reported verbatim 2026-07-09: "Go to hemköp" mid-journey fell straight
// into the web-research pipeline (sources, comparison tables, and another
// "I cannot physically move you"). The message must BEGIN with the
// relocation verb phrase (TELEPORT_LEAD_RE is ^-anchored — prose like
// "when I go to the shop…" never fires) and the remainder must be a short
// plausible name; a small idiom set ("go to sleep", "gå till jobbet")
// stays out. Returns { query, mode } or null. Place-TYPE asks ("go to
// nearest gas station") are matched earlier by the nearby gate.
const RELOCATION_JUNK = new Set([
  "sleep", "bed", "work", "hell", "heaven", "home", "town", "toilet", "bathroom",
  "sängs", "sangs", "jobbet", "hem", "helvetet", "stan", "toaletten", "badrummet",
]);
/**
 * @param {string} text
 * @returns {{ query: string, mode: NearbyMode } | null}
 */
export function extractRelocationQuery(text) {
  const raw = (typeof text === "string" ? text : "").trim();
  if (!raw || raw.length > 80) return null;
  if (extractPlace(raw)) return null; // a real address owns the message
  if (!TELEPORT_VERB_RE.test(raw) && !TRAVEL_TO_RE.test(raw)) return null;
  const stripped = raw.replace(TELEPORT_LEAD_RE, "");
  if (stripped === raw) return null; // the message must START with the verb phrase
  const q = stripped.replace(NEARBY_TRAIL_RE, "").trim();
  const words = q.split(/\s+/).filter(Boolean);
  if (!q || words.length > 4) return null;
  if (HERE_RE.test(q) || WHERE_AM_I_RE.test(q)) return null; // here-asks own these
  if (words.some((w) => RELOCATION_JUNK.has(normWord(w)))) return null;
  if (words.every((w) => STOPWORDS.has(normWord(w)))) return null;
  return { query: q.slice(0, MAX_LOCATION_CHARS), mode: nearbyAskMode(raw) };
}

// The conversation's UNFINISHED relocation — "remember we were going
// there, in the process of figuring it out" (same report: after "Go to
// hemköp" listed two stores, the pick "Stäket" fell into web research).
// Deterministically recovered from the transcript, newest first, within
// the last few user turns: a relocation-to-name ask or a nearby-place ask.
// Pure and exported for tests.
const PENDING_RELOCATION_WINDOW = 6;
/**
 * @param {Message[]} users
 * @returns {{ query: string, mode: NearbyMode } | null}
 */
export function pendingRelocation(users) {
  const list = Array.isArray(users) ? users : [];
  const stop = Math.max(0, list.length - 1 - PENDING_RELOCATION_WINDOW);
  for (let i = list.length - 2; i >= stop; i--) {
    const t = textOf(list[i]?.content);
    const reloc = extractRelocationQuery(t);
    if (reloc) return reloc;
    const nearbyQuery = extractNearbyPlaceQuery(t);
    if (nearbyQuery) return { query: nearbyQuery, mode: nearbyAskMode(t) };
  }
  return null;
}

// ---- route polylines ------------------------------------------------------------

// Google's encoded-polyline algorithm (5-decimal precision) → [{lat,lng}].
// The Routes API returns the actual road path this way; the travel mode
// samples its Street View waypoints along it, so "go to X" really walks the
// route instead of cutting straight across terrain (reported 2026-07-09:
// travel answers looked "just like teleport" — no waypoints in between).
// Malformed input degrades to the points decoded so far. Pure — tested
// against Google's reference example.
/**
 * @param {string} encoded
 * @returns {LatLng[]}
 */
export function decodePolyline(encoded) {
  const s = typeof encoded === "string" ? encoded : "";
  const points = [];
  let index = 0;
  let lat = 0;
  let lng = 0;
  while (index < s.length) {
    let result = 0;
    let shift = 0;
    let b;
    do {
      b = s.charCodeAt(index++) - 63;
      result |= (b & 0x1f) << shift;
      shift += 5;
    } while (b >= 0x20);
    lat += result & 1 ? ~(result >> 1) : result >> 1;
    result = 0;
    shift = 0;
    do {
      b = s.charCodeAt(index++) - 63;
      result |= (b & 0x1f) << shift;
      shift += 5;
    } while (b >= 0x20);
    lng += result & 1 ? ~(result >> 1) : result >> 1;
    points.push({ lat: lat / 1e5, lng: lng / 1e5 });
  }
  return points.filter((p) => Number.isFinite(p.lat) && Number.isFinite(p.lng));
}

// Intermediate sample points along a polyline, one every ~everyM meters
// (endpoints excluded — the caller owns start and destination), capped.
// The travel mode's step-by-step Street View waypoints come from this. Pure.
/**
 * @param {LatLng[]} points
 * @param {number} [everyM]
 * @param {number} [maxSamples]
 * @returns {LatLng[]}
 */
export function samplePolyline(points, everyM = 400, maxSamples = 4) {
  const pts = Array.isArray(points) ? points : [];
  const out = [];
  let acc = 0;
  for (let i = 1; i < pts.length - 1 && out.length < maxSamples; i++) {
    acc += distanceMeters(pts[i - 1].lat, pts[i - 1].lng, pts[i].lat, pts[i].lng);
    if (acc >= everyM) {
      out.push({ lat: pts[i].lat, lng: pts[i].lng });
      acc = 0;
    }
  }
  return out;
}

// ---- the lookup-intent registry -----------------------------------------------
// pickLookup used to be one long if-chain; every reported miss this far has
// been "a new ask shape fell through it". It is now an ORDERED REGISTRY of
// small named matchers over one shared context — adding an ask shape is one
// matcher function + one line in the list, and the precedence is readable
// top to bottom. Each matcher returns a target (a LookupTarget shape) or
// null; the first match wins.
//
// This is the pipeline's Maps-enrichment entry point: derive the lookup
// inputs from a conversation + any attached-photo coordinates + the client's
// live panorama POV. The core precedence, most specific first:
//   1. an attached photo's GPS coordinates,
//   2. an address the LATEST message names (a new location — the client's
//      panorama, if any, still shows the old one),
//   3. the user's CURRENT panorama view (body.street_view_pov) when the
//      message refers back to the imagery/place — capture exactly what they
//      panned/moved to,
//   4. the user's CURRENT interactive-map view (body.map_view) under the
//      same gate — the road-map sibling of 3, live when a location resolved
//      WITHOUT Street View coverage and a map embed rendered instead (the
//      client keeps exactly one of POV/map view live at a time, so 3 and 4
//      never really compete),
//   5. the walk-back: the most recent address an EARLIER user turn named
//      (the embed-less fallback — embed key missing or the Maps JS SDK
//      failed to load, where only the iframe rendered and no view exists).
// 3-5 share the referencesStreetView gate: without a back-reference in
// the message, an ordinary follow-up must not re-bill Google. The server is
// stateless and the prior turn's Maps block was appended server-side only, so
// the resent conversation text (and the client-held view) are the only durable
// records. pickLookup returns null when nothing names (or refers back to) a
// location; `followUp: true` / `pov` / `mapView` / `jump` / `nearby` /
// `crossBarrier` mark the shape so the enrichment labels the block.
// Between 2 and 3 sit the JUMPS and relocations (requested 2026-07-09):
// "street view here" and relative moves ("100 meters along this road", "gå
// 200 m norrut"), anchored to the live panorama (position + heading), else
// the live map (center), else the device's reported location
// (`body.user_location`, sent by the client only for here-asks — "street
// view here", a plain "where am I?", or a short here-fragment answering an
// earlier street-view turn; the client prefilter in message-content.js
// mirrors isHereAsk) — checked BEFORE the free-text place query so "street
// view at my current location" is never sent to Places as a literal place
// name.
//
// The shared context:
//   latest / trimmed — the newest user turn's text
//   users / conversation — for cross-turn matchers
//   pov / mapView / userLocation — the raw live-view inputs
//   anchor — the resolved current position (see matchers using it):
//            physical-location asks flip to the device; else panorama
//            (has heading) → map center → device location
//   latestFix — a locality correction in the latest turn, shared by the
//            fragment/scene/walk-back matchers

/**
 * @param {Conversation} conversation
 * @param {ImageLocation[] | null | undefined} imageLocations
 * @param {StreetViewPov | null} pov
 * @param {MapView | null} mapView
 * @param {LatLng | null} userLocation
 * @returns {LookupCtx}
 */
function buildLookupCtx(conversation, imageLocations, pov, mapView, userLocation) {
  const users = Array.isArray(conversation) ? conversation.filter((m) => m?.role === "user") : [];
  const latest = textOf(users[users.length - 1]?.content);
  const anchor =
    physicalLocationAsk(latest) && userLocation
      ? { lat: userLocation.lat, lng: userLocation.lng, heading: 0, hasHeading: false }
      : pov
        ? { lat: pov.lat, lng: pov.lng, heading: pov.heading, hasHeading: true }
        : mapView
          ? { lat: mapView.lat, lng: mapView.lng, heading: 0, hasHeading: false }
          : userLocation
            ? { lat: userLocation.lat, lng: userLocation.lng, heading: 0, hasHeading: false }
            : null;
  return {
    conversation,
    users,
    latest,
    trimmed: latest.trim(),
    imageLocations,
    pov,
    mapView,
    userLocation,
    anchor,
    latestFix: extractLocalityFix(latest),
  };
}

// An attached photo's GPS coordinates are the most specific input of all.
/** @param {LookupCtx} ctx
 * @returns {LookupTarget | null} */
function matchPhotoCoords(ctx) {
  const c = Array.isArray(ctx.imageLocations) ? ctx.imageLocations[0] : null;
  if (c && Number.isFinite(c.lat) && Number.isFinite(c.lon)) {
    return { coords: `${c.lat},${c.lon}`, address: "" };
  }
  return null;
}

// An address the LATEST message names — a new location beats everything
// the conversation was doing before. EXCEPT a cross-barrier phrase:
// "andra sidan järnvägen" reads as a standalone street name ("…vägen") to
// the address extractor, and routing it as an address sent the user to an
// unrelated resolved address entirely (verbatim 2026-07-10, chat_logs
// #180: "Hoppa till andra sidan järnvägen" → intent NewAddress →
// Berguddsvägen 104, Saltsjöbaden). A barrier phrase is never an address.
/** @param {LookupCtx} ctx
 * @returns {LookupTarget | null} */
function matchNewAddress(ctx) {
  if (extractCrossBarrierAsk(ctx.latest)) return null;
  const address = extractPlace(ctx.latest);
  return address ? { coords: "", address } : null;
}

// "Show how we traveled" — the journey view. Needs no anchor: the
// waypoints come from the mandated coordinate links in the ASSISTANT
// turns, so this works even after the live view was closed. Fewer than
// two distinct stops → nothing to draw, fall through.
/** @param {LookupCtx} ctx
 * @returns {LookupTarget | null} */
function matchJourney(ctx) {
  if (!journeyAsk(ctx.latest)) return null;
  const points = extractJourneyPoints(ctx.conversation);
  if (points.length < 2) return null;
  return { coords: "", address: "", journey: { points }, followUp: true };
}

// A relative move ("100 meters along this road", "gå 200 m norrut").
// Facing-relative moves ("along this road", "back") need a heading — only
// the panorama has one; a map/device anchor takes compass moves.
/** @param {LookupCtx} ctx
 * @returns {LookupTarget | null} */
function matchRelativeMove(ctx) {
  if (!ctx.anchor) return null;
  const move = extractRelativeMove(ctx.latest);
  if (!move || (move.mode !== "bearing" && !ctx.anchor.hasHeading)) return null;
  const bearing =
    move.mode === "bearing" ? move.bearing : move.mode === "back" ? (ctx.anchor.heading + 180) % 360 : ctx.anchor.heading;
  const dest = movePoint(ctx.anchor.lat, ctx.anchor.lng, bearing, move.meters);
  return {
    coords: "",
    address: "",
    jump: { lat: dest.lat, lng: dest.lng, heading: bearing, meters: move.meters, dir: move.dir },
    followUp: true,
  };
}

// A CROSS-BARRIER relocation ("Get to the other side of the railway",
// "hoppa över spåret"): the enrichment probes free Street View metadata
// along the travel bearing for a coverage GAP (the barrier corridor)
// followed by renewed coverage (the other side) and relocates there, with
// a photo series of the virtual crossing.
/** @param {LookupCtx} ctx
 * @returns {LookupTarget | null} */
function matchCrossBarrier(ctx) {
  if (!ctx.anchor) return null;
  const ask = extractCrossBarrierAsk(ctx.latest);
  if (!ask) return null;
  return {
    coords: "",
    address: "",
    crossBarrier: {
      barrier: ask.barrier,
      lat: ctx.anchor.lat,
      lng: ctx.anchor.lng,
      heading: ctx.anchor.heading,
      hasHeading: ctx.anchor.hasHeading,
    },
    followUp: true,
  };
}

// A NEARBY-place ask (place-TYPE word + nearby/relocation word) searches
// Places around the anchor — BEFORE the here-ask so "gas station here"
// searches rather than jumping, and before the POV scene gate so the
// deictic "there" can't demote a search ask into a frame capture.
/** @param {LookupCtx} ctx
 * @returns {LookupTarget | null} */
function matchNearbyPlace(ctx) {
  if (!ctx.anchor) return null;
  const query = extractNearbyPlaceQuery(ctx.latest);
  if (!query) return null;
  return {
    coords: "",
    address: "",
    nearby: { query, lat: ctx.anchor.lat, lng: ctx.anchor.lng, mode: nearbyAskMode(ctx.latest) },
    followUp: true,
  };
}

// A relocation verb aimed at an arbitrary NAME ("Go to hemköp") — same
// nearby target shape, so the whole Places/travel machinery serves it.
/** @param {LookupCtx} ctx
 * @returns {LookupTarget | null} */
function matchRelocationToName(ctx) {
  if (!ctx.anchor) return null;
  const ask = extractRelocationQuery(ctx.latest);
  if (!ask) return null;
  return {
    coords: "",
    address: "",
    nearby: { query: ask.query, lat: ctx.anchor.lat, lng: ctx.anchor.lng, mode: ask.mode },
    followUp: true,
  };
}

// "Go there" (and the reported adjacent-key typo "Co there") resumes the
// conversation's PENDING relocation — verbatim 2026-07-09: "Go there"
// after failed "go to coop" asks got "What specific information are you
// seeking about 'Go there'?". Always travel mode: the user said go.
// A leading street-view phrase rides along — verbatim chat_logs #193
// (2026-07-10): "Street view go there" missed this ^-anchored gate, fell
// through to the place-query path, and Places resolved the literal text
// "go there" to a salon named "Girls Go There" in Anderson, SC.
const GO_THERE_RE = new RegExp(
  `^(?:(?:please|ok|okay|let'?s|lets|legs)\\s+)?(?:(?:${SV_WORDS})[\\s,:]+)?` +
    `(?:go|co|gå|ga|continue|fortsätt|fortsatt|take\\s+(?:me|us)|ta\\s+(?:mig|oss))(?:\\s+(?:on|onwards?|vidare))?\\s+(?:there|dit)\\s*[?!.]*$`,
  "iu",
);
/** @param {LookupCtx} ctx
 * @returns {LookupTarget | null} */
function matchGoThereResume(ctx) {
  if (!ctx.anchor || !GO_THERE_RE.test(ctx.trimmed)) return null;
  const pending = pendingRelocation(ctx.users);
  if (!pending) return null;
  return {
    coords: "",
    address: "",
    nearby: { query: pending.query, lat: ctx.anchor.lat, lng: ctx.anchor.lng, mode: "travel" },
    followUp: true,
  };
}

// A here-ask ("street view here", "where am I?", a here-fragment after a
// street-view turn): pop the view at the anchor.
/** @param {LookupCtx} ctx
 * @returns {LookupTarget | null} */
function matchHereAsk(ctx) {
  if (!ctx.anchor || !isHereAsk(ctx.latest, ctx.users)) return null;
  return {
    coords: "",
    address: "",
    jump: { lat: ctx.anchor.lat, lng: ctx.anchor.lng, heading: ctx.anchor.heading, meters: 0, dir: "here" },
    followUp: true,
  };
}

// An explicit street-view ask naming a PLACE rather than an address
// ("Street view of LEGO offices in Copenhagen") — Places resolves the
// free-text name. A new named place outranks corrections/POV/walk-back,
// exactly like a new address does.
/** @param {LookupCtx} ctx
 * @returns {LookupTarget | null} */
function matchPlaceQuery(ctx) {
  const placeQuery = extractPlaceQuery(ctx.latest);
  return placeQuery ? { coords: "", address: placeQuery } : null;
}

// A VISUAL question about a NAMED place with no address and no street-view
// keyword ("what's the color of the building across the road from ”Rosa
// Pantern” in Uppsala?" — chat_logs #47): the name+anchor extraction is
// deterministic; the street-view flavor comes from the same strict gate the
// walk-back uses (plus the explicit-intent one), so an ordinary research
// question mentioning a restaurant never bills a lookup.
/** @param {LookupCtx} ctx
 * @returns {LookupTarget | null} */
function matchNamedPlace(ctx) {
  const namedPlace = extractNamedPlaceQuery(ctx.latest);
  if (!namedPlace || !(streetViewIntent(ctx.latest) || referencesStreetView(ctx.latest))) return null;
  return { coords: "", address: namedPlace };
}

// A short fragment answering the model's own "which office?" clarify
// ("Alstromer" after the assistant listed three Accenture addresses):
// matched — diacritics-insensitively — against addresses the whole
// conversation has surfaced, assistant research answers included.
/** @param {LookupCtx} ctx
 * @returns {LookupTarget | null} */
function matchAddressFragmentAnswer(ctx) {
  if (!conversationAsksStreetView(ctx.users)) return null;
  const t = ctx.trimmed;
  if (!t || t.length > 40 || t.split(/\s+/).length > 3) return null;
  const picked = matchAddressFragment(ctx.conversation, t);
  return picked ? { coords: "", address: picked, followUp: true } : null;
}

// A short fragment resolving the conversation's UNFINISHED relocation
// ("Go to hemköp" → two stores listed → "Stäket"): the pending ask's query
// and the fragment combine into one Places search ("hemköp Stäket"),
// inheriting the pending mode — so the travel the user started two turns
// ago completes instead of falling into web research.
/** @param {LookupCtx} ctx
 * @returns {LookupTarget | null} */
function matchRelocationFragmentAnswer(ctx) {
  if (!ctx.anchor) return null;
  const t = ctx.trimmed;
  if (!t || t.length > 40 || t.split(/\s+/).length > 3) return null;
  const words = t.split(/\s+/);
  if (words.every((w) => STOPWORDS.has(normWord(w)))) return null;
  const pending = pendingRelocation(ctx.users);
  if (!pending) return null;
  return {
    coords: "",
    address: "",
    nearby: { query: `${pending.query} ${t}`.slice(0, MAX_LOCATION_CHARS), lat: ctx.anchor.lat, lng: ctx.anchor.lng, mode: pending.mode },
    followUp: true,
  };
}

// The POV path uses the LOOSE gate (people/vehicles/signs — anything one
// asks pointing at a live street scene); the walk-back keeps the strict
// imagery/building gate since it re-runs a full billed lookup. A locality
// correction outranks the POV — the on-screen panorama shows the WRONG
// place by definition.
/** @param {LookupCtx} ctx
 * @returns {LookupTarget | null} */
function matchPovScene(ctx) {
  if (!ctx.pov || ctx.latestFix || !referencesStreetViewScene(ctx.latest)) return null;
  return { coords: "", address: "", pov: ctx.pov, followUp: true };
}

// The live interactive MAP gets the same loose gate: "what's that big
// building?", "vad är det där?", "and now" while panning the map must
// capture the area on screen, not walk back to a stale address.
/** @param {LookupCtx} ctx
 * @returns {LookupTarget | null} */
function matchMapScene(ctx) {
  if (!ctx.mapView || ctx.latestFix || !referencesStreetViewScene(ctx.latest)) return null;
  return { coords: "", address: "", mapView: ctx.mapView, followUp: true };
}

// The walk-back: the most recent address an EARLIER user turn named, with
// locality corrections encountered on the way riding along — and, when the
// user's own turns name nothing, the assistant's research answers, but
// ONLY when they surfaced exactly one distinct address (several stay
// silent so the model can honestly ask which one).
/** @param {LookupCtx} ctx
 * @returns {LookupTarget | null} */
function matchWalkBack(ctx) {
  if (!ctx.latestFix && !referencesStreetView(ctx.latest)) return null;
  let fix = ctx.latestFix;
  for (let i = ctx.users.length - 2; i >= 0; i--) {
    const t = textOf(ctx.users[i]?.content);
    const prior = extractPlace(t);
    if (prior) return { coords: "", address: withLocalityFix(prior, fix), followUp: true };
    if (!fix) fix = extractLocalityFix(t);
  }
  const fromAssistant = new Map();
  for (const m of Array.isArray(ctx.conversation) ? ctx.conversation : []) {
    if (m?.role !== "assistant") continue;
    for (const a of addressesInText(textOf(m.content))) {
      fromAssistant.set(normForMatch(a), a);
    }
  }
  if (fromAssistant.size === 1) {
    const only = fromAssistant.values().next().value;
    return { coords: "", address: withLocalityFix(only, fix), followUp: true };
  }
  return null;
}

// Precedence, top to bottom — the ORDER IS THE SPEC. Most-specific inputs
// first (a photo's GPS, a typed address), then the anchored relocations
// (moves, barriers, nearby/named destinations, here-asks), then the
// named/fragment resolutions, then the scene captures, and the walk-back
// last (it re-bills a full lookup, so everything cheaper gets a chance
// first).
/** @type {Array<(ctx: LookupCtx) => LookupTarget | null>} */
const LOOKUP_MATCHERS = [
  matchPhotoCoords,
  matchNewAddress,
  matchJourney,
  matchRelativeMove,
  matchCrossBarrier,
  matchNearbyPlace,
  matchRelocationToName,
  matchGoThereResume,
  matchHereAsk,
  matchPlaceQuery,
  matchNamedPlace,
  matchAddressFragmentAnswer,
  matchRelocationFragmentAnswer,
  matchPovScene,
  matchMapScene,
  matchWalkBack,
];

/**
 * @param {Conversation} conversation
 * @param {ImageLocation[] | null | undefined} imageLocations
 * @param {StreetViewPov | null} [pov]
 * @param {MapView | null} [mapView]
 * @param {LatLng | null} [userLocation]
 * @returns {LookupTarget | null}
 */
export function pickLookup(conversation, imageLocations, pov = null, mapView = null, userLocation = null) {
  const ctx = buildLookupCtx(conversation, imageLocations, pov, mapView, userLocation);
  for (const matcher of LOOKUP_MATCHERS) {
    const target = matcher(ctx);
    if (target) {
      // Which matcher decided rides on the target as DIAGNOSTICS — the
      // enrichment logs it (maps.intent) and it lands in the chat_logs
      // meta, so "how did routing go?" is answerable from the logs
      // (requested 2026-07-09 after a run of silent intent misses).
      // Non-enumerable on purpose: it is not part of the target-shape
      // contract the runners and tests consume.
      Object.defineProperty(target, "intent", { value: matcher.name.replace(/^match/, ""), enumerable: false });
      return target;
    }
  }
  return null;
}

// @ts-check
// Google Maps Platform integration ("Google Maps & Street View" in the UI) —
// an opt-in per-user knob (src/settings.js's `google_maps`, default OFF).
// When the knob is on and the GOOGLE_MAPS_API_KEY secret is set, the Worker
// resolves a location the research question is about — either a street address
// named in the message, or an attached photo's GPS EXIF coordinates — into
// Google Maps data across four Maps Platform APIs that share the one key:
//
//   • Places API (places.googleapis.com) — resolve a named address into a
//     canonical place: display name, formatted address, precise coordinates,
//     place type, rating and business status. This both enriches the answer
//     and yields the exact coordinates the two imagery APIs below key off.
//   • Street View Static API (street-view-image-backend.googleapis.com) —
//     confirm panorama coverage, its capture date, and fetch the actual
//     street-level photo for a vision model to describe.
//   • Maps Static API (static-maps-backend.googleapis.com) — a road-map image
//     of the spot (or of a whole route with markers) for spatial context.
//   • Routes API (routes.googleapis.com) — along-road walking distance/time
//     and the road polyline the travel mode's photo waypoints follow;
//     optional: when not enabled on the key, the blocks honestly report
//     straight-line figures only.
//
// Wired the same deterministic, no-function-calling way as the reverse-
// geocoder (src/geocode.js) and Shodan (src/shodan.js): the location is
// extracted deterministically (a photo's coordinates, or an address parsed
// from the message — the pure text analysis lives in src/googlemaps-text.js),
// the lookups run server-side, and the result is appended as one labeled
// context block every downstream phase can reason and search with — never
// silently blended into the user's text.
//
// This module owns the REST side: the Maps Platform clients and the
// edge-cached lookup orchestration. The pure labeled context-block builders
// live in src/googlemaps-blocks.js.
//
// Runs server-side, same as every other third-party call: Worker-mediated so
// it's logged and timeout-bounded, and the API key NEVER reaches the browser
// or any log/context block (the keyed image URLs are used only for the
// internal fetches — the citable links handed to the model/user are Google's
// keyless Maps URLs).
//
// Fails soft in every branch: no key, no location, no coverage there, a
// timeout or an API error all degrade to the conversation unchanged — Maps
// enrichment is never a hard requirement for the chat to work.

import { cacheGet, cachePut } from "./edge-cache.js";
import { decodePolyline, movePoint } from "./googlemaps-text.js";

/** @typedef {import('./types.js').Env} Env */
/** @typedef {import('./types.js').Logger} Logger */
/** @typedef {import('./types.js').StreetViewPov} StreetViewPov */
/** @typedef {import('./googlemaps-text.js').LatLng} LatLng */
/** @typedef {import('./googlemaps-text.js').MapView} MapView */
/** @typedef {import('./googlemaps-text.js').JumpTarget} JumpTarget */
/** @typedef {import('./googlemaps-text.js').CrossBarrierTarget} CrossBarrierTarget */
/**
 * A canonical place parsed out of a Places API (New) Text Search response —
 * see parsePlace. lat/lng are null when Google returned no usable location.
 * @typedef {{ name: string, address: string, lat: number | null, lng: number | null,
 *   type: string, rating: number | null, ratingCount: number, status: string }} Place
 */
/** A Place whose coordinates are known-present (placesNearbySearch filters). */
/** @typedef {Place & { lat: number, lng: number }} PlaceWithCoords */
/** A panorama found along a barrier-crossing probe ray — see runBarrierCrossing. */
/** @typedef {{ lat: number, lng: number, panoId: string, distance: number }} PanoPoint */
/** A Routes API walking route — see computeWalkingRoute. */
/** @typedef {{ distanceMeters: number, durationS: number | null, polyline: LatLng[] }} WalkingRoute */
/**
 * What runGoogleMapsLookup resolves a target into (null on any failure):
 * the display string, the canonical place (address lookups only), the
 * coordinates, Street View metadata + optional fetched imagery, and the
 * embed point for the client's interactive panorama.
 * @typedef {{
 *   displayQuery: string,
 *   place: Place | null,
 *   lat: number | null,
 *   lng: number | null,
 *   streetView: { date: string, lat: number | null, lng: number | null } | null,
 *   streetViewFrames: Array<{ dir: string, url: string }>,
 *   staticMapImage: string | null,
 *   embed: LatLng | null,
 *   details: string[],
 *   count: number,
 * }} MapsLookupResult
 */

const PLACES_SEARCH_URL = "https://places.googleapis.com/v1/places:searchText";
const STREETVIEW_META_URL = "https://maps.googleapis.com/maps/api/streetview/metadata";
const STREETVIEW_IMAGE_URL = "https://maps.googleapis.com/maps/api/streetview";
const STATICMAP_URL = "https://maps.googleapis.com/maps/api/staticmap";
const TIMEOUT_MS = 6000;
// How far from the resolved coordinates to search for a panorama. Google's
// default is 50m, which misses real coverage when Places returns a rooftop/
// parcel coordinate set back from the road (reported 2026-07-09: "Street view
// basaltvägen 1 enköping" resolved to a business lot whose metadata check
// came back ZERO_RESULTS — no imagery shown — while the street outside had
// coverage). 150m reaches the street outside any normal lot without jumping
// to a different block.
const STREETVIEW_SEARCH_RADIUS_M = 150;
const STREETVIEW_SIZE = "512x512"; // per frame; 4 frames + a map must fit Berget's ~1MB body
const STATICMAP_SIZE = "600x400"; // JPEG below — small enough to attach alongside Street View
// Cross-request result-cache TTL (Workers Cache API via edge-cache.js), the
// exact pattern src/exa.js uses for searches: a follow-up turn is a SEPARATE
// /api/chat request, and the follow-up flow (pickLookup's walk-back)
// re-looks-up the SAME location on every gated follow-up — without a cache
// each one re-bills Places + five imagery fetches at Google. Shared by the
// address lookup and the POV/map-view captures. Short TTL only — enough to
// absorb a whole session of follow-ups about one address (raised from 10 to
// 30 min after a user asking repeatedly about the same address in one
// sitting), still comfortably inside Google's performance-caching allowance
// (Street View imagery itself changes on a timescale of years).
const LOOKUP_CACHE_TTL_S = 1800;
// Four cardinal headings give the vision model a full look around the spot
// (what's across the street, the façade, neighbours) — the "multi-angle
// capture" that makes Street View actually queryable, not one fixed frame.
// Exported for buildMapsBlock (src/googlemaps-blocks.js), which names the
// frame directions when handing them to a vision answer model.
export const STREETVIEW_HEADINGS = [
  { deg: 0, dir: "north" },
  { deg: 90, dir: "east" },
  { deg: 180, dir: "south" },
  { deg: 270, dir: "west" },
];

// The server API key, typed non-null for the keyed URL/header builders:
// every caller runs behind a googleMapsAvailable gate, so the key is
// present whenever a billed request is actually built.
/**
 * @param {Env} env
 * @returns {string}
 */
const mapsApiKey = (env) => /** @type {string} */ (env.GOOGLE_MAPS_API_KEY);

/**
 * @param {Env} env
 * @returns {boolean}
 */
export function googleMapsAvailable(env) {
  return !!env.GOOGLE_MAPS_API_KEY;
}

// The browser-exposed key for the interactive Maps Embed iframe. Prefers a
// dedicated GOOGLE_MAPS_EMBED_KEY when set (ideal: a key restricted to the Maps
// Embed API only); otherwise FALLS BACK to the main GOOGLE_MAPS_API_KEY. The
// fallback is safe only because that key is HTTP-referrer-locked to the site
// (*.deepresearch.se/*), which is the mitigation for exposing it to the
// browser — without that referrer restriction, exposing the server key would
// let anyone run its billed Places/Static APIs. Empty string when neither is
// set — the client then shows only the keyless Street View link, no embed.
/**
 * @param {Env} env
 * @returns {string}
 */
export function googleMapsEmbedKey(env) {
  const embed = typeof env.GOOGLE_MAPS_EMBED_KEY === "string" ? env.GOOGLE_MAPS_EMBED_KEY : "";
  if (embed) return embed;
  return typeof env.GOOGLE_MAPS_API_KEY === "string" ? env.GOOGLE_MAPS_API_KEY : "";
}

// ---- REST calls ------------------------------------------------------------

// Base64-encode bytes in chunks so a large image doesn't blow the argument
// limit of String.fromCharCode (Workers have btoa but not Buffer).
/** @param {Uint8Array} bytes */
function bytesToBase64(bytes) {
  let binary = "";
  const CHUNK = 0x8000;
  for (let i = 0; i < bytes.length; i += CHUNK) {
    binary += String.fromCharCode(...bytes.subarray(i, i + CHUNK));
  }
  return btoa(binary);
}

/**
 * @param {Env} env
 * @param {Logger} log
 * @param {string} url
 * @param {string} event the log event name for a failed fetch
 * @returns {Promise<string | null>} a data: URL, or null on any failure
 */
async function fetchImageDataUrl(env, log, url, event) {
  try {
    const resp = await fetch(url, { signal: AbortSignal.timeout(TIMEOUT_MS) });
    if (!resp.ok) {
      log.warn(event, { status: resp.status });
      return null;
    }
    const buf = await resp.arrayBuffer();
    if (!buf || buf.byteLength === 0) return null;
    return `data:image/jpeg;base64,${bytesToBase64(new Uint8Array(buf))}`;
  } catch (/** @type {any} */ err) {
    log.warn(event, { error: err?.message || String(err) });
    return null;
  }
}

// Field mask shared by both Places Text Search calls — keeps the response,
// and the billing tier, minimal.
const PLACES_FIELD_MASK =
  "places.displayName,places.formattedAddress,places.location,places.primaryType,places.rating,places.userRatingCount,places.businessStatus";

// One raw Places API place object → the Place shape the blocks consume.
/**
 * @param {any} place
 * @returns {Place}
 */
function parsePlace(place) {
  const lat = Number(place.location?.latitude);
  const lng = Number(place.location?.longitude);
  return {
    name: place.displayName?.text || "",
    address: place.formattedAddress || "",
    lat: Number.isFinite(lat) ? lat : null,
    lng: Number.isFinite(lng) ? lng : null,
    type: typeof place.primaryType === "string" ? place.primaryType.replace(/_/g, " ") : "",
    rating: Number.isFinite(place.rating) ? place.rating : null,
    ratingCount: Number.isFinite(place.userRatingCount) ? place.userRatingCount : 0,
    status: typeof place.businessStatus === "string" ? place.businessStatus : "",
  };
}

// Places API (New) Text Search: resolve an address/place string into a single
// canonical place.
/**
 * @param {Env} env
 * @param {Logger} log
 * @param {string} query
 * @returns {Promise<Place | null>}
 */
export async function placesTextSearch(env, log, query) {
  try {
    const resp = await fetch(PLACES_SEARCH_URL, {
      method: "POST",
      headers: {
        "Content-Type": "application/json",
        "X-Goog-Api-Key": mapsApiKey(env),
        "X-Goog-FieldMask": PLACES_FIELD_MASK,
      },
      body: JSON.stringify({ textQuery: query, maxResultCount: 1 }),
      signal: AbortSignal.timeout(TIMEOUT_MS),
    });
    if (!resp.ok) {
      log.warn("googlemaps.places_error", { status: resp.status });
      return null;
    }
    /** @type {any} */
    const data = await resp.json().catch(() => null);
    const place = data?.places?.[0];
    if (!place) {
      log.info("googlemaps.places", { found: false });
      return null;
    }
    log.info("googlemaps.places", { found: true });
    return parsePlace(place);
  } catch (/** @type {any} */ err) {
    log.warn("googlemaps.places_error", { error: err?.message || String(err) });
    return null;
  }
}

// Places API (New) Text Search biased around a position — the NEARBY-place
// search ("Gas station near e18 there" from a live panorama): same endpoint
// and field mask as placesTextSearch, plus a locationBias circle at the
// anchor (bias, not restriction — Places may still return the best match
// slightly outside) and up to 3 results so the answer can name
// alternatives. Returns an array (possibly empty) or null on failure.
const NEARBY_BIAS_RADIUS_M = 5000;
/**
 * @param {Env} env
 * @param {Logger} log
 * @param {string} query
 * @param {number} lat
 * @param {number} lng
 * @returns {Promise<PlaceWithCoords[] | null>}
 */
export async function placesNearbySearch(env, log, query, lat, lng) {
  try {
    const resp = await fetch(PLACES_SEARCH_URL, {
      method: "POST",
      headers: {
        "Content-Type": "application/json",
        "X-Goog-Api-Key": mapsApiKey(env),
        "X-Goog-FieldMask": PLACES_FIELD_MASK,
      },
      body: JSON.stringify({
        textQuery: query,
        maxResultCount: 3,
        locationBias: { circle: { center: { latitude: lat, longitude: lng }, radius: NEARBY_BIAS_RADIUS_M } },
      }),
      signal: AbortSignal.timeout(TIMEOUT_MS),
    });
    if (!resp.ok) {
      log.warn("googlemaps.places_nearby_error", { status: resp.status });
      return null;
    }
    /** @type {any} */
    const data = await resp.json().catch(() => null);
    /** @type {any[]} */
    const places = Array.isArray(data?.places) ? data.places : [];
    log.info("googlemaps.places_nearby", { found: places.length });
    return /** @type {PlaceWithCoords[]} */ (
      places.map(parsePlace).filter((p) => p.lat != null && p.lng != null)
    );
  } catch (/** @type {any} */ err) {
    log.warn("googlemaps.places_nearby_error", { error: err?.message || String(err) });
    return null;
  }
}

// Street View metadata is FREE (Google does not bill metadata requests) and
// tells us whether a panorama exists at `location` before we spend on an
// image. A pano id (from the client's live panorama) takes precedence over
// the location string when given. Returns the parsed metadata (status "OK"
// means imagery exists) or null.
/**
 * @param {Env} env
 * @param {Logger} log
 * @param {string} location "lat,lng" or a raw address (Google geocodes it)
 * @param {string} [pano] a pano id, taking precedence over `location`
 * @param {number} [radius] widened search radius in meters (0 = Google's default)
 * @returns {Promise<any | null>} the raw metadata JSON (status "OK" = imagery exists)
 */
export async function streetViewMetadata(env, log, location, pano = "", radius = 0) {
  try {
    const qs = new URLSearchParams({ key: mapsApiKey(env) });
    if (pano) qs.set("pano", pano);
    else {
      qs.set("location", location);
      if (radius > 0) {
        // Widened panorama search (see STREETVIEW_SEARCH_RADIUS_M) — outdoor
        // collections only, so a business's indoor photosphere can't outrank
        // the street outside.
        qs.set("radius", String(radius));
        qs.set("source", "outdoor");
      }
    }
    const resp = await fetch(`${STREETVIEW_META_URL}?${qs}`, { signal: AbortSignal.timeout(TIMEOUT_MS) });
    if (!resp.ok) {
      log.warn("googlemaps.streetview_meta_error", { status: resp.status });
      return null;
    }
    const data = await resp.json().catch(() => null);
    log.info("googlemaps.streetview_meta", { status: data?.status || "unknown" });
    return data;
  } catch (/** @type {any} */ err) {
    log.warn("googlemaps.streetview_meta_error", { error: err?.message || String(err) });
    return null;
  }
}

/**
 * @param {Env} env
 * @param {string} location
 * @param {number} heading
 * @param {string} [pano]
 */
function streetViewImageUrl(env, location, heading, pano = "") {
  const qs = new URLSearchParams({
    size: STREETVIEW_SIZE,
    heading: String(heading),
    fov: "90",
    key: mapsApiKey(env),
    return_error_code: "true",
  });
  // Pin the very panorama the metadata check found: the image API's own
  // default search radius (50m) would otherwise re-miss a pano the widened
  // metadata search located beyond it.
  if (pano) qs.set("pano", pano);
  else {
    qs.set("location", location);
    qs.set("radius", String(STREETVIEW_SEARCH_RADIUS_M));
    qs.set("source", "outdoor");
  }
  return `${STREETVIEW_IMAGE_URL}?${qs}`;
}

// The Street View Static URL for an exact point of view — the pano id (when
// the client's live panorama reported one) pins the very panorama the user is
// standing in, and heading/pitch/fov reproduce where they panned to.
/**
 * @param {Env} env
 * @param {StreetViewPov} pov
 */
function streetViewPovImageUrl(env, pov) {
  const qs = new URLSearchParams({
    size: STREETVIEW_SIZE,
    heading: String(pov.heading),
    pitch: String(pov.pitch),
    fov: String(pov.fov),
    key: mapsApiKey(env),
    return_error_code: "true",
  });
  if (pov.panoId) qs.set("pano", pov.panoId);
  else qs.set("location", `${pov.lat},${pov.lng}`);
  return `${STREETVIEW_IMAGE_URL}?${qs}`;
}

// Captures the exact frame the user currently sees in the inline panorama
// (validated POV from body.street_view_pov): one billed Street View Static
// fetch at their heading/pitch/fov, plus the free metadata check for the
// capture date. Cached like the address lookup (the POV is integer-rounded
// client-side, so re-asking about the same view is a free hit). Returns
// { image, date } or null on any failure — fail-soft, the caller degrades.
/**
 * @param {Env} env
 * @param {Logger} log
 * @param {StreetViewPov} pov
 * @returns {Promise<{ image: string, date: string } | null>}
 */
export async function runStreetViewPovCapture(env, log, pov) {
  if (!googleMapsAvailable(env)) return null;

  const params = new URLSearchParams({
    p: pov.panoId || "",
    ll: `${pov.lat},${pov.lng}`,
    h: String(pov.heading),
    pt: String(pov.pitch),
    f: String(pov.fov),
  });
  const cacheKey = `https://googlemaps-pov-cache.internal/frame?${params.toString()}`;
  const cached = await cacheGet(log, "googlemaps.cache", cacheKey);
  if (cached && typeof cached === "object" && cached.image) {
    log.info("googlemaps.pov_cache_hit", {});
    return cached;
  }

  const [meta, image] = await Promise.all([
    streetViewMetadata(env, log, `${pov.lat},${pov.lng}`, pov.panoId),
    fetchImageDataUrl(env, log, streetViewPovImageUrl(env, pov), "googlemaps.streetview_pov_error"),
  ]);
  if (!image) return null;

  const result = { image, date: meta?.status === "OK" ? meta.date || "" : "" };
  await cachePut(log, "googlemaps.cache", cacheKey, result, LOOKUP_CACHE_TTL_S);
  return result;
}

// A road-map image of exactly the map area the user is viewing (center +
// zoom from the client's live interactive map) — the map-view sibling of
// streetViewPovImageUrl. No marker: the user panned freely, there is no
// resolved place to mark.
/**
 * @param {Env} env
 * @param {MapView} view
 */
function staticMapViewUrl(env, view) {
  const qs = new URLSearchParams({
    center: `${view.lat},${view.lng}`,
    zoom: String(view.zoom),
    size: STATICMAP_SIZE,
    scale: "1",
    format: "jpg",
    maptype: "roadmap",
    key: mapsApiKey(env),
  });
  return `${STATICMAP_URL}?${qs}`;
}

// How far around a jump destination to search for a panorama. Scales with
// the jump distance: a 1km "go north" lands wherever the math says — often
// a field or water — and the useful behavior is snapping to the nearest
// covered road, not "no Street View" (live report 2026-07-09, "Ol north
// 1km" → ZERO_RESULTS at 150m while roads sat within a few hundred
// meters). Half the jump distance keeps the snap meaningfully "about that
// far in that direction"; short jumps and here-pops keep the 150m floor.
/**
 * @param {number} meters
 * @returns {number}
 */
export function jumpSearchRadius(meters) {
  const m = Number.isFinite(meters) ? meters : 0;
  return Math.min(1000, Math.max(STREETVIEW_SEARCH_RADIUS_M, Math.round(m / 2)));
}

// Finds the panorama nearest a JUMPED-to point (a "street view here" popup
// or a relative move like "100 meters along this road") and captures one
// frame facing the travel bearing — reusing the POV capture's cached
// metadata+frame fetch. Returns { lat, lng, panoId, heading, date, image }
// (lat/lng snapped to the found panorama's own position) or null when
// Google has no panorama within the search radius of the destination.
/**
 * @param {Env} env
 * @param {Logger} log
 * @param {{ lat: number, lng: number, heading: number, meters: number }} point
 * @returns {Promise<{ lat: number, lng: number, panoId: string, heading: number,
 *   date: string, image: string | null } | null>}
 */
export async function runStreetViewJumpLookup(env, log, point) {
  if (!googleMapsAvailable(env)) return null;
  const meta = await streetViewMetadata(env, log, `${point.lat},${point.lng}`, "", jumpSearchRadius(point.meters));
  if (meta?.status !== "OK") return null;
  const panoId = typeof meta.pano_id === "string" ? meta.pano_id : "";
  const mLat = Number(meta.location?.lat);
  const mLng = Number(meta.location?.lng);
  const lat = Number.isFinite(mLat) ? mLat : point.lat;
  const lng = Number.isFinite(mLng) ? mLng : point.lng;
  let capture = null;
  try {
    capture = await runStreetViewPovCapture(env, log, { panoId, lat, lng, heading: point.heading, pitch: 0, fov: 90 });
  } catch {
    // frame capture is an enhancement — the jump itself still resolves
  }
  return { lat, lng, panoId, heading: point.heading, date: capture?.date || meta.date || "", image: capture?.image || null };
}

// Cross-barrier probe ("get to the other side of the railway"): Street View
// covers ROADS, so a rail corridor / river between two roads shows up as a
// coverage GAP along a ray of metadata probes — covered panos, then
// nothing, then covered panos again. The first renewed-coverage pano after
// a gap IS "the other side". Metadata requests are FREE (Google doesn't
// bill them), so a whole ray probes concurrently; with a panorama heading
// the ray follows the view (±45° fallbacks), from a map/device anchor the
// four cardinals are tried. Returns { bearing, before, after } (each
// { lat, lng, panoId, distance }) or null when no gap-then-coverage
// signature exists within CROSS_MAX_M.
const CROSS_STEP_M = 40;
// Exported for buildCrossBarrierBlock (src/googlemaps-blocks.js), whose
// honest no-coverage line reports how far the probe actually reached.
export const CROSS_MAX_M = 640;
const CROSS_PROBE_RADIUS_M = 30;
/**
 * @param {Env} env
 * @param {Logger} log
 * @param {CrossBarrierTarget} anchor
 * @returns {Promise<{ bearing: number, before: PanoPoint, after: PanoPoint } | null>}
 */
export async function runBarrierCrossing(env, log, anchor) {
  if (!googleMapsAvailable(env)) return null;
  const bearings = anchor.hasHeading
    ? [anchor.heading, (anchor.heading + 315) % 360, (anchor.heading + 45) % 360]
    : [0, 90, 180, 270];
  const steps = [];
  for (let d = CROSS_STEP_M; d <= CROSS_MAX_M; d += CROSS_STEP_M) steps.push(d);
  for (const bearing of bearings) {
    const metas = await Promise.all(
      steps.map((d) => {
        const p = movePoint(anchor.lat, anchor.lng, bearing, d);
        return streetViewMetadata(env, log, `${p.lat},${p.lng}`, "", CROSS_PROBE_RADIUS_M);
      }),
    );
    /** @type {PanoPoint | null} */
    let before = null;
    let inGap = false;
    for (let i = 0; i < metas.length; i++) {
      const meta = metas[i];
      const lat = Number(meta?.location?.lat);
      const lng = Number(meta?.location?.lng);
      if (meta?.status !== "OK" || !Number.isFinite(lat) || !Number.isFinite(lng)) {
        if (before) inGap = true;
        continue;
      }
      const pano = {
        lat,
        lng,
        panoId: typeof meta.pano_id === "string" ? meta.pano_id : "",
        distance: steps[i],
      };
      if (inGap && pano.panoId && pano.panoId !== before?.panoId) {
        log.info("googlemaps.barrier_crossing", { bearing, distance: pano.distance });
        // `inGap` is only ever set with `before` present — the cast is safe.
        return { bearing, before: /** @type {PanoPoint} */ (before), after: pano };
      }
      before = pano;
    }
  }
  log.info("googlemaps.barrier_crossing", { found: false });
  return null;
}

// Captures the map area the user currently sees in the inline interactive
// map (validated view from body.map_view): one billed Static Maps fetch at
// their center/zoom. Cached like the POV capture (the view is rounded
// client-side, so re-asking about the same area is a free hit). Returns
// { image } or null on any failure — fail-soft, the caller degrades.
/**
 * @param {Env} env
 * @param {Logger} log
 * @param {MapView} view
 * @returns {Promise<{ image: string } | null>}
 */
export async function runMapViewCapture(env, log, view) {
  if (!googleMapsAvailable(env)) return null;

  const params = new URLSearchParams({
    ll: `${view.lat},${view.lng}`,
    z: String(view.zoom),
  });
  const cacheKey = `https://googlemaps-mapview-cache.internal/frame?${params.toString()}`;
  const cached = await cacheGet(log, "googlemaps.cache", cacheKey);
  if (cached && typeof cached === "object" && cached.image) {
    log.info("googlemaps.mapview_cache_hit", {});
    return cached;
  }

  const image = await fetchImageDataUrl(env, log, staticMapViewUrl(env, view), "googlemaps.mapview_error");
  if (!image) return null;

  const result = { image };
  await cachePut(log, "googlemaps.cache", cacheKey, result, LOOKUP_CACHE_TTL_S);
  return result;
}

/**
 * @param {Env} env
 * @param {string} location
 */
function staticMapUrl(env, location) {
  const qs = new URLSearchParams({
    center: location,
    zoom: "18",
    size: STATICMAP_SIZE,
    scale: "1",
    format: "jpg",
    maptype: "roadmap",
    markers: `color:red|${location}`,
    key: mapsApiKey(env),
  });
  return `${STATICMAP_URL}?${qs}`;
}

// A Static Maps image of the JOURNEY: numbered markers at every stop and a
// straight-line path between them. No center/zoom — Static Maps auto-fits
// to the path and markers. Billed like the other Static fetches (~$2/1k).
// `pathPoints` (optional) draws the path along a REAL route polyline (the
// Routes API's road path, downsampled to keep the URL within limits) while
// the numbered markers stay on the logical stops; without it the path
// connects the stops straight-line.
/**
 * @param {Env} env
 * @param {Logger} log
 * @param {LatLng[]} points the logical stops (numbered markers)
 * @param {LatLng[] | null} [pathPoints] a real route polyline for the path line
 * @returns {Promise<string | null>}
 */
export async function routeMapImage(env, log, points, pathPoints = null) {
  const path = Array.isArray(pathPoints) && pathPoints.length >= 2 ? downsamplePath(pathPoints, 60) : points;
  const qs = new URLSearchParams({
    size: STATICMAP_SIZE,
    scale: "1",
    format: "jpg",
    maptype: "roadmap",
    path: "color:0x2563ebff|weight:4|" + path.map((p) => `${p.lat},${p.lng}`).join("|"),
    key: mapsApiKey(env),
  });
  points.forEach((p, i) => qs.append("markers", `label:${(i + 1) % 10}|${p.lat},${p.lng}`));
  return fetchImageDataUrl(env, log, `${STATICMAP_URL}?${qs}`, "googlemaps.routemap_error");
}

// Keep every Nth point (endpoints always) so a long polyline fits the
// Static Maps URL limit.
/**
 * @param {LatLng[]} points
 * @param {number} max
 */
function downsamplePath(points, max) {
  if (points.length <= max) return points;
  const step = Math.ceil(points.length / max);
  const out = points.filter((_, i) => i % step === 0);
  if (out[out.length - 1] !== points[points.length - 1]) out.push(points[points.length - 1]);
  return out;
}

// Along-road walking distance + duration over the journey's stops — Routes
// API v2 computeRoutes, WALK mode, minimal field mask. This API must be
// enabled on the key (routes.googleapis.com); when it isn't (or errors/
// times out) this returns null and the journey block honestly reports the
// straight-line numbers only — never a made-up walking time.
const ROUTES_URL = "https://routes.googleapis.com/directions/v2:computeRoutes";
const ROUTES_MAX_INTERMEDIATES = 8;
/**
 * @param {Env} env
 * @param {Logger} log
 * @param {LatLng[]} points
 * @returns {Promise<WalkingRoute | null>}
 */
export async function computeWalkingRoute(env, log, points) {
  if (!Array.isArray(points) || points.length < 2) return null;
  try {
    const wp = (/** @type {LatLng} */ p) => ({ location: { latLng: { latitude: p.lat, longitude: p.lng } } });
    const resp = await fetch(ROUTES_URL, {
      method: "POST",
      headers: {
        "Content-Type": "application/json",
        "X-Goog-Api-Key": mapsApiKey(env),
        // The encoded polyline is the actual ROAD PATH — the travel mode
        // samples its Street View waypoints along it and the route map
        // draws it, so "go to X" follows roads instead of a straight line.
        "X-Goog-FieldMask": "routes.distanceMeters,routes.duration,routes.polyline.encodedPolyline",
      },
      body: JSON.stringify({
        origin: wp(points[0]),
        destination: wp(points[points.length - 1]),
        intermediates: points.slice(1, -1).slice(0, ROUTES_MAX_INTERMEDIATES).map(wp),
        travelMode: "WALK",
      }),
      signal: AbortSignal.timeout(TIMEOUT_MS),
    });
    if (!resp.ok) {
      log.warn("googlemaps.routes_error", { status: resp.status });
      return null;
    }
    const data = await resp.json().catch(() => null);
    const route = data?.routes?.[0];
    const dist = Number(route?.distanceMeters);
    const dur = typeof route?.duration === "string" ? Number(route.duration.replace(/s$/, "")) : NaN;
    if (!Number.isFinite(dist) || dist <= 0) return null;
    const polyline = decodePolyline(route?.polyline?.encodedPolyline || "");
    log.info("googlemaps.routes", { distance_m: dist, polyline_points: polyline.length });
    return { distanceMeters: dist, durationS: Number.isFinite(dur) ? dur : null, polyline };
  } catch (/** @type {any} */ err) {
    log.warn("googlemaps.routes_error", { error: err?.message || String(err) });
    return null;
  }
}

// The address lookup's edge-cache key (Workers Cache API, caches.default:
// durable across requests in a colo, no binding needed, fail-soft in every
// branch — see LOOKUP_CACHE_TTL_S above for the caching rationale).
/**
 * @param {string | undefined} target
 * @param {boolean} fetchImages
 */
function lookupCacheKey(target, fetchImages) {
  const params = new URLSearchParams({
    t: (target || "").trim().toLowerCase().replace(/\s+/g, " "),
    img: fetchImages ? "1" : "0", // an imageless hit must not starve an imagery request
  });
  return `https://googlemaps-lookup-cache.internal/lookup?${params.toString()}`;
}

// Orchestrates one Maps lookup. Exactly one of `coords` ("lat,lng" of an
// attached photo) or `address` (a parsed street address) drives it; `coords`
// wins when both are present. `fetchImages` gates the (billed) imagery fetches
// — set when the caller will either attach them to a vision answer model or
// run them through the vision-describe helper. Returns the resolved data
// ({ displayQuery, place, lat, lng, streetView, streetViewFrames,
// staticMapImage, embed, details, count }) or null when nothing resolved (or
// any failure) — the caller stays silent / builds the block itself.
/**
 * @param {Env} env
 * @param {Logger} log
 * @param {{ coords?: string, address?: string, fetchImages?: boolean }} target
 * @returns {Promise<MapsLookupResult | null>}
 */
export async function runGoogleMapsLookup(env, log, { coords, address, fetchImages }) {
  if (!googleMapsAvailable(env)) return null;

  // Serve an identical earlier lookup (typically: a follow-up about the same
  // place) from the edge cache. Fail-soft: any miss/error falls through to
  // live API calls.
  const cacheKey = lookupCacheKey(coords || address, !!fetchImages);
  const cached = await cacheGet(log, "googlemaps.cache", cacheKey);
  if (cached && typeof cached === "object") {
    log.info("googlemaps.cache_hit", { frames: cached.streetViewFrames?.length || 0 });
    return cached;
  }

  // Resolve a place + coordinates. A photo's coords are used directly; an
  // address is first sent to Places to canonicalise it and get precise coords
  // (falling back to letting the imagery APIs geocode the raw string).
  /** @type {Place | null} */
  let place = null;
  /** @type {number | null} */
  let lat = null;
  /** @type {number | null} */
  let lng = null;
  let displayQuery = coords || address || "";
  if (coords) {
    const [clat, clng] = coords.split(",").map(Number);
    if (Number.isFinite(clat) && Number.isFinite(clng)) {
      lat = clat;
      lng = clng;
    }
  } else if (address) {
    place = await placesTextSearch(env, log, address);
    if (place) {
      // Prefer the formatted address — it carries the CITY, so the frames
      // title and the context block make a wrong-city resolution visible
      // (a bare place name like "Lidbecksgatan 10" hides which one).
      displayQuery = place.address || place.name || address;
      if (Number.isFinite(place.lat) && Number.isFinite(place.lng)) {
        lat = place.lat;
        lng = place.lng;
      }
    }
  }

  // The location string the imagery APIs use: precise coords when we have
  // them, else the raw address (Google geocodes it).
  const imageryLocation =
    Number.isFinite(lat) && Number.isFinite(lng) ? `${lat},${lng}` : address || "";
  if (!imageryLocation) return null;

  const svMeta = await streetViewMetadata(env, log, imageryLocation, "", STREETVIEW_SEARCH_RADIUS_M);
  const svOk = svMeta?.status === "OK";
  // The found panorama's own id and position: the id pins the imagery
  // fetches to that exact pano, and the position (which can sit up to the
  // search radius from the resolved coordinates) is what the interactive
  // embed and the keyless Street View link must center on — the client's
  // StreetViewPanorama searches only Google's default 50m radius, so
  // centering it on the resolved address would re-miss the pano.
  const svPano = svOk && typeof svMeta.pano_id === "string" ? svMeta.pano_id : "";
  const svMetaLat = svOk ? Number(svMeta.location?.lat) : NaN;
  const svMetaLng = svOk ? Number(svMeta.location?.lng) : NaN;
  const svPoint =
    Number.isFinite(svMetaLat) && Number.isFinite(svMetaLng) ? { lat: svMetaLat, lng: svMetaLng } : null;

  // Nothing to show: an address Places couldn't resolve and with no Street
  // View coverage is a false-positive address — stay silent. A photo's coords
  // are always a valid map point, so they always produce at least a map.
  if (!coords && !place && !svOk) return null;

  // Capture imagery when asked: one Street View frame per cardinal heading (a
  // full look around the spot) plus a road map. Fetched concurrently; each is
  // independently fail-soft (a missing frame just drops). Frames keep their
  // heading label so the client can caption them and the vision prompt can
  // name directions. The CALLER decides whether to attach these to a vision
  // answer model or run them through the vision-describe helper — this just
  // fetches them.
  /** @type {Array<{ dir: string, url: string }>} */
  let streetViewFrames = [];
  /** @type {string | null} */
  let staticMapImage = null;
  if (fetchImages) {
    const svJobs = svOk
      ? STREETVIEW_HEADINGS.map((h) =>
          fetchImageDataUrl(env, log, streetViewImageUrl(env, imageryLocation, h.deg, svPano), "googlemaps.streetview_image_error"),
        )
      : [];
    const [svResults, mapResult] = await Promise.all([
      Promise.all(svJobs),
      fetchImageDataUrl(env, log, staticMapUrl(env, imageryLocation), "googlemaps.staticmap_error"),
    ]);
    streetViewFrames = /** @type {Array<{ dir: string, url: string }>} */ (
      svResults.map((url, i) => ({ dir: STREETVIEW_HEADINGS[i].dir, url })).filter((f) => f.url)
    );
    staticMapImage = mapResult;
  }

  // Coordinates for the client's interactive Street View embed (only when
  // there's coverage and a real point to center on) — the panorama's own
  // position when the metadata reported one, so the embed can't re-miss it.
  const embedPoint =
    svPoint ||
    (Number.isFinite(lat) && Number.isFinite(lng)
      ? { lat: /** @type {number} */ (lat), lng: /** @type {number} */ (lng) }
      : null);
  const embed = svOk && embedPoint ? embedPoint : null;

  // Prefer the formatted address (includes the city) so the activity detail
  // reveals WHICH "Maskinistvägen 11" Google resolved — makes a wrong-city hit
  // visible instead of showing a bare, ambiguous street name.
  const bits = [];
  if (place) bits.push(place.address || place.name || "place found");
  if (svOk) bits.push(`Street View${svMeta.date ? ` (${svMeta.date})` : ""}`);
  bits.push("road map");
  const details = [`${displayQuery} → ${bits.join(", ")}`];

  const result = {
    displayQuery,
    place,
    lat,
    lng,
    streetView: svOk ? { date: svMeta.date || "", lat: svPoint?.lat ?? null, lng: svPoint?.lng ?? null } : null,
    streetViewFrames,
    staticMapImage,
    embed,
    details,
    count: 1,
  };

  // Cache only successful lookups (the null early-returns above stay uncached
  // so a retry can still find something). A write failure never affects the
  // response.
  await cachePut(log, "googlemaps.cache", cacheKey, result, LOOKUP_CACHE_TTL_S);

  return result;
}

// Unit suite for the Google Maps integration's pure logic: the deterministic
// text side (src/googlemaps-text.js — address/place extraction, every intent
// gate, the pickLookup matcher registry), the pure link/block builders
// (src/googlemaps-blocks.js), and googlemaps.js's remaining pure exports
// (jumpSearchRadius, key gating). The REST
// clients and the enrichment runners need live Google/Berget and are covered
// by live verification instead (see the live-verify skill).
//
// Layout: per-function describes first (extraction, gates, block builders),
// then the scenario suites replaying verbatim reported conversations
// (Accenture fragments, "Gas station near e18 there", the railway crossing,
// the journey view, "Where am i now"), and the "Swedish language parity"
// suite enforcing CLAUDE.md invariant 6 — every deterministic gate must take
// Swedish forms with the same breadth as English. When adding or extending a
// gate, add its Swedish parity case there in the same change.
//
// Deliberately NOT `// @ts-check`: these tests exercise fail-soft behavior
// by feeding malformed and partial shapes (empty envs, truncated targets,
// bare object literals) that strict types would reject by design.
