describe("hfBuildAttempts — filtered browse first, name ladder as fallback", () => {
  test("filtered attempt leads and carries a stable kind-scoped key", () => {
    const plan = hfQueryPlan("latest swedish speech recognition kb-whisper on hugging face");
    const attempts = hfBuildAttempts(plan, "models");
    assert.equal(attempts[0].filters.join("&"), "pipeline_tag=automatic-speech-recognition&language=sv");
    assert.equal(attempts[0].q, "kb-whisper");
    assert.match(attempts[0].key, /^models:pipeline_tag=/);
    // the name ladder follows as fallback
    assert.ok(attempts.slice(1).every((a) => a.filters.length === 0));
  });

  test("dataset attempts only apply task filters valid as task_categories", () => {
    const plan = hfQueryPlan("swedish sentiment analysis datasets on hf");
    const m = hfBuildAttempts(plan, "models");
    const d = hfBuildAttempts(plan, "datasets");
    assert.match(m[0].filters[0], /^pipeline_tag=text-classification/);
    assert.match(d[0].filters[0], /^task_categories=text-classification/);
    // Language filter is models-only (dataset language tags are unreliable —
    // probe-established: ?language=sv returned github-code etc).
    assert.ok(m[0].filters.some((f) => f === "language=sv"));
    assert.ok(!d[0].filters.some((f) => f.startsWith("language=")));
  });

  test("no filters → pure name ladder with plain keys", () => {
    const plan = hfQueryPlan("cybersecurity on hf");
    const attempts = hfBuildAttempts(plan, "models");
    assert.ok(attempts.every((a) => a.filters.length === 0));
    assert.equal(attempts[0].key, "cybersecurity");
  });
});

// @ts-check
// Per-user "History Key": lets the browser encrypt/decrypt its own
// locally-stored chat history (public/js/history-store.js) without the
// server ever seeing conversation content.
//
// Threat model this is built for:
//   - Offline extraction of the browser's storage (an IndexedDB file pulled
//     from a stolen device or a disk image) recovers only ciphertext — this
//     key is fetched fresh, once per page load, over an authenticated
//     request, and is NEVER written to any persistent browser storage
//     (not localStorage, not IndexedDB), so it isn't there to find at rest.
//   - A server compromise recovers HISTORY_KEY_SECRET (and could therefore
//     derive any given user's key on demand), but recovers no ciphertext —
//     conversation content itself never leaves the browser, ever.
//   - Only the COMBINATION — a live compromise able to mint the key, AND
//     access to that specific browser's storage — can decrypt anything.
//     That is disclosed as a limitation at /help/, not hidden.
//
// Derivation is deterministic (HMAC-SHA256, same construction as auth.js's
// session HMAC): the same signed-in identity always re-derives the same
// key. This does not sync history across devices — each browser's
// IndexedDB is its own — it only means one identity never needs a stored
// key, just the ability to re-authenticate.
//
// Fails closed like auth.js's admin secrets: without HISTORY_KEY_SECRET
// configured, callers must not fall back to an unencrypted alternative —
// that would defeat the entire point.

/** @typedef {import('./types.js').Env} Env */

/**
 * @param {Env} env
 * @returns {boolean}
 */
export function historyKeyConfigured(env) {
  return !!env.HISTORY_KEY_SECRET;
}

/**
 * Deterministically derives one user's history key (base64 HMAC-SHA256).
 * Callers must gate on historyKeyConfigured first (fail closed — see above).
 * @param {Env} env
 * @param {number | string} userId
 * @returns {Promise<string>}
 */
export async function deriveHistoryKey(env, userId) {
  const enc = new TextEncoder();
  const key = await crypto.subtle.importKey(
    "raw",
    enc.encode(env.HISTORY_KEY_SECRET),
    { name: "HMAC", hash: "SHA-256" },
    false,
    ["sign"],
  );
  const sig = await crypto.subtle.sign("HMAC", key, enc.encode(`history-key.v1.${userId}`));
  return bufToBase64(sig);
}

/** @param {ArrayBuffer} buf */
function bufToBase64(buf) {
  let binary = "";
  for (const byte of new Uint8Array(buf)) binary += String.fromCharCode(byte);
  return btoa(binary);
}

// Unit tests for the per-user history-key derivation (src/history-key.js):
// determinism, per-user/per-secret divergence, and the configured gate.
import { test, describe } from "node:test";
import assert from "node:assert/strict";
import { deriveHistoryKey, historyKeyConfigured } from "./history-key.js";

describe("historyKeyConfigured", () => {
  test("false when the secret is unset", () => {
    assert.equal(historyKeyConfigured({}), false);
  });
  test("true once the secret is set", () => {
    assert.equal(historyKeyConfigured({ HISTORY_KEY_SECRET: "s" }), true);
  });
});

describe("deriveHistoryKey", () => {
  const env = { HISTORY_KEY_SECRET: "test-secret" };

  test("returns 32 raw bytes, base64-encoded (valid AES-256 key material)", async () => {
    const key = await deriveHistoryKey(env, "42");
    const bytes = Buffer.from(key, "base64");
    assert.equal(bytes.length, 32);
  });

  test("deterministic: the same user gets the same key every time", async () => {
    const a = await deriveHistoryKey(env, "42");
    const b = await deriveHistoryKey(env, "42");
    assert.equal(a, b);
  });

  test("different users get different keys", async () => {
    const a = await deriveHistoryKey(env, "42");
    const b = await deriveHistoryKey(env, "43");
    assert.notEqual(a, b);
  });

  test("different secrets yield different keys for the same user (rotation invalidates)", async () => {
    const a = await deriveHistoryKey(env, "42");
    const b = await deriveHistoryKey({ HISTORY_KEY_SECRET: "other-secret" }, "42");
    assert.notEqual(a, b);
  });
});

// @ts-check
// Small response helpers shared across modules.

/**
 * JSON response with the correct content-type and any extra headers.
 * @param {unknown} obj serialized as the body
 * @param {number} [status]
 * @param {Record<string, string>} [extraHeaders]
 * @returns {Response}
 */
export function jsonResponse(obj, status = 200, extraHeaders = {}) {
  return new Response(JSON.stringify(obj), {
    status,
    headers: {
      "content-type": "application/json; charset=utf-8",
      ...extraHeaders,
    },
  });
}

/**
 * Wraps a stream as a text/event-stream response for SSE.
 * @param {ReadableStream} stream
 * @param {Record<string, string>} [extraHeaders]
 * @returns {Response}
 */
export function sseResponse(stream, extraHeaders = {}) {
  return new Response(stream, {
    headers: {
      "content-type": "text/event-stream; charset=utf-8",
      "cache-control": "no-cache, no-transform",
      ...extraHeaders,
    },
  });
}

// @ts-check
// Cloudflare Worker for Deepresearch.se — entrypoint.
//
// Responsibilities: assign a request id, resolve the caller's identity
// (Google-provisioned D1 user via the session cookie, or the admin-secrets
// break-glass over Basic Auth), route APIs vs static assets, slide the
// session cookie, and emit structured request logs. wrangler.toml sets
// run_worker_first = true so auth also covers the assets, which are served
// via env.ASSETS.
//
// Gate ordering (load-bearing, enforced in route/routeAuthed):
//   identity → terms acceptance → approval → handlers.
//
// Module map:
//   src/auth.js      — identity: session cookie + admin break-glass
//   src/google.js    — Google OIDC sign-in (the only user-facing login)
//   src/login.js     — sign-in page (PWAs can't answer a 401 challenge)
//   src/accounts.js  — user accounts (D1)
//   src/config.js    — global site config (D1 config table, cached)
//   src/quota.js     — usage accounting + quota enforcement
//   src/user-api.js  — /api/me + /api/models + /api/client-error + /api/history-key
//   src/history-key.js — per-user key for the client's encrypted local history
//   src/settings.js  — per-user settings (/api/settings: server_history + shodan_mcp knobs)
//   src/storage.js   — opt-in R2 cloud storage (/api/convos, /api/files, /api/storage)
//   src/rag.js       — document RAG: /api/embed proxy + /api/rag/* (Vectorize)
//   src/quiz-api.js  — /api/quiz/grade: free-text quiz-answer grading (src/quiz.js)
//   src/games.js     — /api/games: the games registry/shelf + per-game dispatch
//                      (Tokemon: src/tokemon-api.js, game core src/tokemon.js)
//   src/admin-api.js — /api/admin/* JSON API
//   src/chat.js      — /api/chat: streaming research pipeline
//   src/answers.js   — /api/chat/answer: TTL'd answer recovery cache
//   src/berget.js    — Berget.ai client + SSE consumption
//   src/exa.js       — Exa web_search
//   src/db.js        — optional D1 binding + schema
//   src/log.js       — structured JSON logger (LOG_LEVEL var)
//   src/http.js      — response helpers
//   src/assets.js    — static-asset serving + the public (no-auth) allowlist
//   src/security-headers.js — site-wide security headers + CSP policy

import { handleAdminApi } from "./admin-api.js";
import { handleAnswerAck, handleAnswerGet } from "./answers.js";
import { clearSessionCookie, createSessionCookie, identify } from "./auth.js";
import { handleChat } from "./chat.js";
import { handleMcp } from "./mcp.js";
import { handleGoogleCallback, handleGoogleStart } from "./google.js";
import { jsonResponse } from "./http.js";
import { createLogger } from "./log.js";
import { acceptTerms } from "./accounts.js";
import { configErrorPage, loginPage, pendingPage, termsPage } from "./login.js";
import {
  handleClientError,
  handleClientLog,
  handleHistoryKey,
  handleMe,
  handleMessages,
  handleModels,
} from "./user-api.js";
import { handleFeedbackApi } from "./feedback.js";
import { bashLiteEnabled, handleSettingsGet, handleSettingsPut } from "./settings.js";
import { handleBashStep } from "./bash-api.js";
import { handleStorage } from "./storage.js";
import { handleVault } from "./vault.js";
import { handleEmbed, handleRag } from "./rag.js";
import { handleQuizGrade } from "./quiz-api.js";
import { handleGames } from "./games.js";
import { handlePubGet, handlePubWrite } from "./pub.js";
import { getConfig } from "./config.js";
import { isPublicAsset, serveAsset } from "./assets.js";
import { applySecurityHeaders } from "./security-headers.js";

/** @typedef {import('./types.js').Env} Env */
/** @typedef {import('./types.js').Logger} Logger */
/** @typedef {import('./auth.js').Identity} Identity */
/**
 * What `route` hands back to `fetch`: the response, plus the resolved
 * identity (when there is one) so the session cookie can slide.
 * @typedef {{ response: Response, identity?: Identity }} RouteResult
 */

export default {
  /**
   * @param {Request} request
   * @param {Env} env
   * @param {ExecutionContext} ctx
   * @returns {Promise<Response>}
   */
  async fetch(request, env, ctx) {
    const startedAt = Date.now();
    const url = new URL(request.url);
    const requestId = crypto.randomUUID();
    const log = createLogger(env, {
      request_id: requestId,
      method: request.method,
      path: url.pathname,
      host: url.host,
    });

    try {
      const { response, identity } = await route(request, env, url, log, ctx, requestId);
      // Note: for /api/chat this marks headers-sent; the end of the SSE
      // stream is logged separately as chat.complete.
      log.info("request.complete", {
        status: response.status,
        duration_ms: Date.now() - startedAt,
      });
      const out = applySecurityHeaders(response, requestId);
      // Sliding sessions: past the cookie's half-life, reissue it so active
      // PWA users never see a login screen again.
      if (identity?.refreshCookie) {
        out.headers.append("Set-Cookie", await createSessionCookie(env, identity.id));
      }
      return out;
    } catch (err) {
      log.error("request.failed", {
        error: /** @type {any} */ (err)?.message || String(err),
        stack: /** @type {any} */ (err)?.stack,
        duration_ms: Date.now() - startedAt,
      });
      return applySecurityHeaders(
        jsonResponse({ error: "Internal server error.", request_id: requestId }, 500),
        requestId,
      );
    }
  },
};

/**
 * Top-level routing: config sanity, the public (unauthenticated) surface,
 * then the identity gate ahead of everything else. Returns the identity
 * only when resolved, so the caller can slide the session cookie.
 * @param {Request} request
 * @param {Env} env
 * @param {URL} url
 * @param {Logger} log
 * @param {ExecutionContext} ctx
 * @param {string} requestId
 * @returns {Promise<RouteResult>}
 */
async function route(request, env, url, log, ctx, requestId) {
  // Canonical host. The Worker is routed on BOTH the apex and www
  // (wrangler.toml: deepresearch.se + www.deepresearch.se), but the whole app
  // must live on ONE host. Google OAuth's redirect_uri is registered only for
  // the apex, so a request arriving on www builds a www redirect_uri Google
  // rejects — "Error 400: redirect_uri_mismatch", hit signing in via
  // www.deepresearch.se (Firefox Focus). Pinning only the redirect_uri would
  // then split the CSRF state cookie across the two hosts, so instead
  // canonicalize FIRST: 301 www.* → apex, preserving path + query, so the whole
  // flow (state cookie, redirect_uri, callback, session) stays on the one
  // registered host.
  if (url.hostname.startsWith("www.")) {
    const canonical = new URL(url.toString());
    canonical.hostname = url.hostname.slice("www.".length);
    return { response: new Response(null, { status: 301, headers: { Location: canonical.toString() } }) };
  }

  // Hard configuration requirement: SESSION_SECRET must be set. It is the sole
  // key that signs/verifies session and OAuth-state cookies — the legacy
  // admin-credential-derived fallback was removed (it re-exposed the admin
  // password to offline brute force from any captured cookie; see src/auth.js).
  // Without the secret there is no safe way to run sessions, so instead of
  // degrading, present a clear misconfiguration message across the whole site.
  if (!env.SESSION_SECRET) {
    log.error("config.missing_session_secret", {});
    if (url.pathname.startsWith("/api/")) {
      return {
        response: jsonResponse({ error: "Server not configured: SESSION_SECRET is missing." }, 503),
      };
    }
    return { response: htmlResponse(configErrorPage(), 503) };
  }

  if (isPublicAsset(url, request.method)) {
    return { response: await serveAsset(request, env) };
  }

  // ---- the wordplay URL map (all BEFORE the identity gate) -----------------
  // The .se domain completes English words, and the two product tiers live
  // under them:
  //   DeepResearch.Se/cure — DRC, "deep research SECURE" (C = CLIENT-side):
  //       the public tier. Minimal server involvement by DESIGN: this
  //       Worker serves the static page and the public replay JSONs, and
  //       nothing else — model calls go browser→provider directly, storage
  //       is browser-local (public/cure/, public/js/drc-*.js). The root /
  //       redirects here; /my/project-<hash> reopens a browser-local saved
  //       project; /cure/<slug> is a published frozen replay (src/pub.js +
  //       the publish-research skill), continue-able in place.
  //   DeepResearch.Se/rver — DRS, "deep research SERVER" (R = REMOTE, as in
  //       a remote cloud-server): the signed-in tier with the hosted
  //       pipeline, web search, accounts, and cloud storage (handled in
  //       routeAuthed; unauthenticated visitors get the login page).
  // /free and /free/project-… are legacy aliases from DRC's free-mode era.
  // The root stays the PROMOTIONAL LANDING (public/welcome/) for visitors —
  // it links both tiers; signed-in arrivals are forwarded to DRS below.
  if (
    (request.method === "GET" || request.method === "HEAD") &&
    (url.pathname === "/cure" ||
      /^\/cure\/[a-z0-9-]*$/.test(url.pathname) ||
      url.pathname === "/my" ||
      url.pathname === "/my/" ||
      url.pathname.startsWith("/my/project-") ||
      url.pathname === "/free" ||
      url.pathname === "/free/" ||
      url.pathname.startsWith("/free/project-"))
  ) {
    // The DRC page is served cross-origin isolated (COEP) so its client-side
    // execution sandbox (the experimental bash-lite tier) can boot CheerpX.
    // DRC's knob is browser-local (no server-side account to read here), and
    // the khaki page is self-contained — no cross-origin iframe to break — so
    // isolation is safe to apply unconditionally.
    return { response: await serveAsset(request, env, url.origin + "/cure/", { coep: true }) };
  }
  if (request.method === "GET" && (url.pathname === "/api/pub" || url.pathname.startsWith("/api/pub/"))) {
    const slug = url.pathname === "/api/pub" ? null : decodeURIComponent(url.pathname.slice("/api/pub/".length));
    return { response: await handlePubGet(env, slug) };
  }
  // The intro-animation speed knob (site config `anim_speed`, the admin
  // slider in /admin): public because the /cure first-visit intro reads it
  // before any identity exists. Presentation config only — one number,
  // browser-cacheable for a minute, so a slider change propagates within
  // ~90 s (this cache + the ~30 s config cache).
  if (request.method === "GET" && url.pathname === "/api/anim") {
    const cfg = await getConfig(env);
    return {
      response: jsonResponse({ speed: cfg.anim_speed }, 200, { "cache-control": "public, max-age=60" }),
    };
  }

  // ---- unauthenticated: sign-in surface -----------------------------------
  if (url.pathname === "/login" && request.method === "GET") {
    return { response: htmlResponse(loginPage(url.searchParams.get("flash") || ""), 200) };
  }
  if (url.pathname === "/auth/google" && request.method === "GET") {
    return { response: await handleGoogleStart(request, env, url, log) };
  }
  if (url.pathname === "/auth/google/callback" && request.method === "GET") {
    return { response: await handleGoogleCallback(request, env, url, log) };
  }

  // ---- everything else requires an identity ------------------------------
  const identity = await identify(request, env);
  if (!identity) {
    // Visitors hitting the root get the promotional landing page (video,
    // docs, build story, sign-in, and the DRC try-it-now link) rather
    // than a bare login form.
    if (url.pathname === "/" && request.method === "GET") {
      return {
        response: await serveAsset(request, env, url.origin + "/welcome/"),
      };
    }
    log.warn("auth.denied", { reason: "unauthenticated" });
    if (url.pathname.startsWith("/api/")) {
      return { response: jsonResponse({ error: "Authentication required." }, 401) };
    }
    // Sign-in page instead of a WWW-Authenticate challenge: installed PWAs
    // cannot show the native Basic Auth dialog (black screen on iOS).
    return { response: htmlResponse(loginPage(""), 401) };
  }

  const response = await routeAuthed(request, env, url, log, identity, ctx, requestId);
  return { response, identity };
}

/**
 * Routing behind the identity gate: logout, then the terms and approval
 * gates (in that order), then the API/admin/asset handlers.
 * @param {Request} request
 * @param {Env} env
 * @param {URL} url
 * @param {Logger} log
 * @param {Identity} identity
 * @param {ExecutionContext} ctx
 * @param {string} requestId
 * @returns {Promise<Response>}
 */
async function routeAuthed(request, env, url, log, identity, ctx, requestId) {
  if (url.pathname === "/logout" && request.method === "POST") {
    return new Response(null, {
      status: 303,
      headers: { Location: "/login", "Set-Cookie": clearSessionCookie() },
    });
  }

  // ---- terms gate, then approval gate (order is load-bearing) ------------
  const termsResponse = await termsGate(request, env, url, identity);
  if (termsResponse) return termsResponse;

  // Approval gate: pending users are parked on the waiting page — no APIs,
  // no app, no admin — until the admin flips them to active. The page
  // auto-refreshes, so approval takes effect without a re-login.
  if (identity.pending) {
    if (url.pathname.startsWith("/api/")) {
      return jsonResponse({ error: "Your account is awaiting approval.", pending: true }, 403);
    }
    return htmlResponse(pendingPage(identity), 200);
  }

  const apiResponse = await routeApi(request, env, url, log, identity, ctx, requestId);
  if (apiResponse) return apiResponse;

  // ---- admin-only: the JSON API and the admin UI assets ------------------
  if (url.pathname.startsWith("/api/admin/")) {
    if (identity.role !== "admin") return jsonResponse({ error: "Admin access required." }, 403);
    return handleAdminApi(request, env, url, log, identity);
  }
  if (url.pathname === "/admin" || url.pathname.startsWith("/admin/")) {
    if (identity.role !== "admin") {
      return new Response(null, { status: 302, headers: { Location: "/rver" } });
    }
    return serveAsset(request, env);
  }

  // Publishing (PUT/DELETE /api/pub/:slug) is the ONE write surface of the
  // published-replays feature — admin only (the public reads are routed
  // before the identity gate).
  if (url.pathname.startsWith("/api/pub/")) {
    if (identity.role !== "admin") return jsonResponse({ error: "Admin access required." }, 403);
    return handlePubWrite(request, env, log, decodeURIComponent(url.pathname.slice("/api/pub/".length)));
  }

  // The signed-in app — DRS, "deep research SERVER" — lives at /rver (the
  // URL wordplay above): serve the app shell there. A signed-in arrival at
  // the root is forwarded home (the landing is for visitors).
  //
  // When this account has the experimental bash-lite sandbox on, the app
  // shell (and its assets) are served cross-origin isolated (COEP) so CheerpX
  // can boot; off (the default) they are served exactly as before, so the
  // Street View keyless-iframe fallback is untouched for everyone else.
  const coep = bashLiteEnabled(env, identity);
  if ((url.pathname === "/rver" || url.pathname === "/rver/") && request.method === "GET") {
    return serveAsset(request, env, url.origin + "/", { coep });
  }
  if (url.pathname === "/" && request.method === "GET") {
    return new Response(null, { status: 302, headers: { Location: "/rver" } });
  }

  return serveAsset(request, env, null, { coep });
}

/**
 * Terms gate: every account must accept the terms of use once, right
 * after first sign-in — before the approval wait, the app, or any API.
 * The break-glass identity has no user row to record acceptance on and
 * is exempt (it's the operator). /build/ (About) and /story/ (build
 * history) stay readable pre-acceptance so the full text the terms
 * summarize is one tap away, and /logout is handled before this gate.
 * Static assets (js/css/vendor/markdown files, matched by file extension)
 * always pass through — they're inert code, not gated content, and
 * /build/ + /story/ need their own scripts and history.md to render.
 * @param {Request} request
 * @param {Env} env
 * @param {URL} url
 * @param {Identity} identity
 * @returns {Promise<Response | null>} null when the gate lets the request through
 */
async function termsGate(request, env, url, identity) {
  if (!identity.user || identity.user.terms_accepted_at) return null;

  if (url.pathname === "/terms/accept" && request.method === "POST") {
    await acceptTerms(env, identity.user.id);
    return new Response(null, { status: 303, headers: { Location: "/rver" } });
  }
  if (url.pathname.startsWith("/api/")) {
    return jsonResponse({ error: "The terms of use must be accepted first.", terms: true }, 403);
  }
  const isStaticAsset = request.method === "GET" && /\.[a-z0-9]+$/i.test(url.pathname);
  const isAllowedPage = request.method === "GET" && /^\/(build|story)(\/|$)/.test(url.pathname);
  if (isStaticAsset || isAllowedPage) {
    return serveAsset(request, env);
  }
  return htmlResponse(termsPage(identity), 200);
}

/**
 * The signed-in (non-admin-gated) API surface, one route per handler
 * module. Returns null when nothing matched, so routeAuthed can continue
 * to the admin routes and the asset fallback.
 * @param {Request} request
 * @param {Env} env
 * @param {URL} url
 * @param {Logger} log
 * @param {Identity} identity
 * @param {ExecutionContext} ctx
 * @param {string} requestId
 * @returns {Promise<Response | null>}
 */
async function routeApi(request, env, url, log, identity, ctx, requestId) {
  if (url.pathname === "/api/chat" && request.method === "POST") {
    return handleChat(request, env, log, identity, ctx, requestId);
  }
  // MCP server (Streamable HTTP, JSON-RPC 2.0): exposes the research pipeline
  // as a `deep_research` tool for other agents. Placed after the identity gate
  // so it inherits the same access control (break-glass Basic Auth header or a
  // signed-in session).
  if (url.pathname === "/mcp" && request.method === "POST") {
    return handleMcp(request, env, log, identity, ctx, requestId);
  }
  // Answer recovery (src/answers.js): poll a dropped stream's finished
  // answer back, or ack an intact delivery so the cached copy is purged.
  if (url.pathname === "/api/chat/answer" && request.method === "GET") {
    return handleAnswerGet(env, url, identity);
  }
  if (url.pathname === "/api/chat/answer" && request.method === "DELETE") {
    return handleAnswerAck(env, url, identity);
  }
  if (url.pathname === "/api/models" && request.method === "GET") {
    return handleModels(env, log);
  }
  if (url.pathname === "/api/me" && request.method === "GET") {
    return handleMe(env, identity);
  }
  if (url.pathname === "/api/history-key" && request.method === "GET") {
    return handleHistoryKey(env, identity);
  }
  if (url.pathname === "/api/messages" && request.method === "GET") {
    return handleMessages(env, identity);
  }
  // Per-user settings (server_history + shodan_mcp knobs).
  if (url.pathname === "/api/settings" && request.method === "GET") {
    return handleSettingsGet(env, identity);
  }
  if (url.pathname === "/api/settings" && request.method === "PUT") {
    return handleSettingsPut(request, env, log, identity);
  }
  // Feedback mode (src/feedback.js): the user's own feedback entries and
  // their dialogue threads with the development agent.
  if (url.pathname === "/api/feedback" || url.pathname.startsWith("/api/feedback/")) {
    return handleFeedbackApi(request, env, url, log, identity);
  }
  // Free-text quiz-answer grading (the inline-quiz capability —
  // src/quiz-api.js; multiple-choice picks grade client-side).
  if (url.pathname === "/api/quiz/grade" && request.method === "POST") {
    return handleQuizGrade(request, env, log, identity);
  }
  // One turn of the experimental bash-lite agent loop (src/bash-api.js): the
  // browser-orchestrated in-browser Linux sandbox asks what command to run
  // next. Knob-gated inside the handler (bash_lite_mcp).
  if (url.pathname === "/api/bash/step" && request.method === "POST") {
    return handleBashStep(request, env, log, identity);
  }
  // Document-RAG embedding proxy (used in BOTH storage modes) + the
  // server-side index endpoints (knob-gated inside src/rag.js).
  if (url.pathname === "/api/embed" && request.method === "POST") {
    return handleEmbed(request, env, log, identity);
  }
  if (url.pathname.startsWith("/api/rag/")) {
    return handleRag(request, env, url, log, identity);
  }
  // Opt-in cloud storage: encrypted conversation/project records + files.
  if (
    url.pathname === "/api/convos" ||
    url.pathname.startsWith("/api/convos/") ||
    url.pathname === "/api/projects" ||
    url.pathname.startsWith("/api/projects/") ||
    url.pathname === "/api/files" ||
    url.pathname.startsWith("/api/files/") ||
    url.pathname === "/api/storage"
  ) {
    return handleStorage(request, env, url, log, identity);
  }
  // The secret-keyed project vault (src/vault.js): client-encrypted project
  // archives under a user-held secret the server never sees. Deliberately
  // NOT knob-gated — each store is its own explicit consent, and the blob
  // is ciphertext only.
  if (url.pathname.startsWith("/api/vault/")) {
    return handleVault(request, env, url, log, identity);
  }
  // The games subsystem (src/games.js): GET /api/games lists the shelf the
  // account panel renders; /api/games/<id>/* dispatches to the registered
  // game's own API (Tokemon: src/tokemon-api.js, core in src/tokemon.js).
  if (url.pathname === "/api/games" || url.pathname.startsWith("/api/games/")) {
    return handleGames(request, env, url, log, identity);
  }
  if (url.pathname === "/api/client-error" && request.method === "POST") {
    return handleClientError(request, log, identity);
  }
  // Client telemetry beacon — first user is the in-browser sandbox filesystem
  // integration (public/js/sandbox.js), whose boot/mount/seed events run
  // client-side and reach Workers Logs only through this. See handleClientLog.
  if (url.pathname === "/api/client-log" && request.method === "POST") {
    return handleClientLog(request, log, identity);
  }
  return null;
}

/**
 * @param {string} html
 * @param {number} status
 * @returns {Response}
 */
function htmlResponse(html, status) {
  return new Response(html, {
    status,
    headers: { "content-type": "text/html; charset=utf-8" },
  });
}

// @ts-check
// The introspection enrichment (developer mode): whenever the caller's
// developer_mode knob is on, this appends the site's OWN source to the
// conversation so every phase (triage, synthesis, validation) answers
// implementation questions — and code-example requests — from the real code
// instead of denying it has any. Two parts:
//
//   1. RETRIEVAL (RAG): the source chunks most relevant to the question,
//      pulled from a committed DENSE index (public/introspect/source-rag.json,
//      scripts/bundle-source-rag.mjs — int8 embeddings per source chunk). The
//      query is embedded server-side (Berget e5, the same model the index was
//      built with) and cosine-ranked against the index. This is what makes the
//      mode work for ANY phrasing ("code examples from the site") — no brittle
//      intent regex deciding whether to engage. NO Linux VM required.
//   2. ORIENTATION: a CLAUDE.md architecture excerpt, the full file index for
//      strong "how are you built" asks, and the full text of any repo file the
//      message names by path.
//
// Both the snapshot and the RAG index are committed artifacts served by THIS
// deploy's static assets and read back through the ASSETS binding — so what is
// injected is by construction the exact source this Worker runs. All shared,
// I/O-free logic (chunker, int8 codec, retrieval, block builder) lives in the
// pure core public/js/introspect-core.js (the bash-core.js pattern).
//
// Standing enrichment contract (src/enrichment.js): fail-soft in every branch.
// Retrieval or index failures degrade to a snapshot-only (orientation) block —
// and a missing snapshot to an unchanged conversation — never an error. The
// enrichment only RUNS when developer mode is on (registry gate in
// enrichment.js), so "always inject" here means "always inject in dev mode".

import {
  RAG_PATH,
  SNAPSHOT_PATH,
  buildIntrospectionBlock,
  introspectionActive,
  mentionedSnapshotPaths,
  retrieveSourceChunks,
  validateRagIndex,
  validateSnapshot,
} from "../public/js/introspect-core.js";
import { embedTexts } from "./berget.js";
import { textOf, withAppendedText } from "./conversation.js";

const QUERY_PREFIX = "query: "; // e5 asymmetric prefix — mirrors src/rag.js
const RETRIEVE_K = 6;

/** @typedef {import('./types.js').Env} Env */
/** @typedef {import('./types.js').Logger} Logger */
/** @typedef {import('./types.js').Conversation} Conversation */
/** @typedef {import('./types.js').RequestState} RequestState */
/** @typedef {import('../public/js/introspect-core.js').Snapshot} Snapshot */

/**
 * Every user message's text, oldest first — introspection is a MODE: one
 * engaging message keeps it on for the conversation's follow-ups.
 * @param {Conversation} conversation
 * @returns {string[]}
 */
function userTexts(conversation) {
  return conversation.filter((m) => m.role === "user").map((m) => textOf(m.content));
}

/**
 * Fetch + validate the deployed source snapshot through the ASSETS binding.
 * Null (never a throw) when the artifact is missing or unreadable.
 * @param {Env} env
 * @param {Logger} log
 * @returns {Promise<Snapshot | null>}
 */
export async function loadSourceSnapshot(env, log) {
  try {
    const assets = /** @type {any} */ (env).ASSETS;
    if (!assets?.fetch) return null;
    // The binding routes by path; the host is a placeholder.
    const res = await assets.fetch(new Request("https://assets.internal" + SNAPSHOT_PATH));
    if (!res.ok) {
      log.warn("introspect.snapshot_missing", { status: res.status });
      return null;
    }
    const snapshot = validateSnapshot(await res.json());
    if (!snapshot) log.warn("introspect.snapshot_invalid", {});
    return snapshot;
  } catch (/** @type {any} */ err) {
    log.warn("introspect.snapshot_failed", { error: err?.message || String(err) });
    return null;
  }
}

/**
 * Fetch + validate the committed dense RAG index through the ASSETS binding.
 * Null (never a throw) when it's missing/unreadable — retrieval degrades to
 * the orientation-only block.
 * @param {Env} env
 * @param {Logger} log
 * @returns {Promise<import('../public/js/introspect-core.js').RagIndex | null>}
 */
export async function loadSourceRag(env, log) {
  try {
    const assets = /** @type {any} */ (env).ASSETS;
    if (!assets?.fetch) return null;
    const res = await assets.fetch(new Request("https://assets.internal" + RAG_PATH));
    if (!res.ok) {
      log.warn("introspect.rag_missing", { status: res.status });
      return null;
    }
    const index = validateRagIndex(await res.json());
    if (!index) log.warn("introspect.rag_invalid", {});
    return index;
  } catch (/** @type {any} */ err) {
    log.warn("introspect.rag_failed", { error: err?.message || String(err) });
    return null;
  }
}

/**
 * Embed the query and cosine-rank the source-RAG index. Returns the top-k
 * chunks (text resolved from the CURRENT snapshot) or [] on any failure —
 * the caller still injects the orientation block, so retrieval failing only
 * costs relevance, never the mode.
 * @param {Env} env
 * @param {Logger} log
 * @param {string} query
 * @param {Snapshot} snapshot
 * @returns {Promise<Array<{ p: string, text: string, score: number }>>}
 */
async function retrieveForQuery(env, log, query, snapshot) {
  try {
    if (!query.trim()) return [];
    const index = await loadSourceRag(env, log);
    if (!index) return [];
    const { vectors } = await embedTexts(env, [QUERY_PREFIX + query.slice(0, 2000)]);
    const qvec = vectors && vectors[0];
    if (!qvec || !qvec.length) return [];
    return retrieveSourceChunks(index, snapshot, qvec, RETRIEVE_K);
  } catch (/** @type {any} */ err) {
    log.warn("introspect.retrieve_failed", { error: err?.message || String(err) });
    return [];
  }
}

/**
 * The enrichment runner (registered in src/enrichment.js; enabled =
 * state.introspection = developer mode on). Always injects the source in dev
 * mode — retrieval finds the relevant code for the question, plus orientation.
 * @param {Env} env
 * @param {Logger} log
 * @param {(id: string, label: string) => void} step
 * @param {(id: string, label: string, details?: string[]) => void} stepDone
 * @param {Conversation} conversation
 * @param {RequestState} state
 * @returns {Promise<Conversation>}
 */
export async function runIntrospectionEnrichment(env, log, step, stepDone, conversation, state) {
  const texts = userTexts(conversation);
  if (!texts.length) return conversation;
  const latestText = texts[texts.length - 1] || "";

  step("introspect", "Reading the site's own source…");
  const snapshot = await loadSourceSnapshot(env, log);
  if (!snapshot) {
    stepDone("introspect", "Source snapshot unavailable — continuing without it");
    return conversation;
  }
  // Stash the loaded snapshot so the pipeline's source-research phase can READ
  // files from it (the agentic read loop) without a second ASSETS fetch. The
  // enrichment still injects retrieved excerpts + orientation below; the read
  // loop uses this to go deeper into whichever files the model actually needs.
  /** @type {any} */ (state).sourceSnapshot = snapshot;

  // Dense retrieval for THIS question (fail-soft to []). This is the part that
  // makes the mode phrasing-agnostic.
  const retrieved = await retrieveForQuery(env, log, latestText, snapshot);

  // The full file index is only worth its ~tokens for strong "how are you
  // built / list the files" asks; ordinary code questions ride on retrieval +
  // orientation. Named-file inlining always applies (mentionedSnapshotPaths).
  const strongIntent = introspectionActive(texts, snapshot);
  const block = buildIntrospectionBlock(snapshot, {
    latestText,
    retrieved,
    includeIndex: strongIntent,
    // A shell transcript means the client ran the sandbox loop this message —
    // with dev mode on its provider mounts the tree at /src (stream.js).
    sandboxMounted: (/** @type {any} */ (state).shellTranscript || []).length > 0,
  });
  state.introspectionCount = 1;
  const inlined = mentionedSnapshotPaths(latestText, snapshot).slice(0, 6);
  const topScore = retrieved.length ? retrieved[0].score : 0;
  stepDone(
    "introspect",
    retrieved.length
      ? `Introspection: ${retrieved.length} relevant source excerpt${retrieved.length === 1 ? "" : "s"} + orientation`
      : `Introspection: source in context (${snapshot.count} files)`,
    [
      `top matches: ${retrieved.map((r) => r.p).slice(0, 4).join(", ") || "(orientation only)"}`,
      ...(inlined.length ? [`inlined: ${inlined.join(", ")}`] : []),
    ],
  );
  log.info("introspect.applied", {
    files: snapshot.count,
    retrieved: retrieved.length,
    top_score: Number(topScore.toFixed(3)),
    top_files: retrieved.map((r) => r.p).slice(0, 6),
    inlined: inlined.length,
    include_index: strongIntent,
    block_chars: block.length,
  });
  // Same convention as the Shodan block: appended so every phase sees it.
  return /** @type {Conversation} */ (withAppendedText(conversation, block));
}

// Unit tests for the introspection enrichment (src/introspect.js) against a
// mocked ASSETS binding, plus the source-snapshot freshness check: the
// committed artifact (public/introspect/source-snapshot.json) must match the
// working tree, so a source change without `npm run bundle` fails the suite.

import { test } from "node:test";
import assert from "node:assert/strict";
import { execFileSync } from "node:child_process";
import { readFileSync } from "node:fs";
import { dirname, join } from "node:path";
import { fileURLToPath } from "node:url";

import { loadSourceSnapshot, runIntrospectionEnrichment } from "./introspect.js";

const noopLog = { debug() {}, info() {}, warn() {}, error() {} };

const SNAPSHOT = {
  v: 1,
  digest: "deadbeefcafe0123",
  count: 2,
  bytes: 0,
  files: [
    { p: "CLAUDE.md", s: 20, t: "# CLAUDE.md\norientation" },
    { p: "src/pipeline.js", s: 10, t: "// phases" },
  ],
};

const jsonRes = (payload, status = 200) =>
  new Response(payload === null ? "not found" : JSON.stringify(payload), {
    status,
    headers: { "content-type": "application/json" },
  });

// An env whose ASSETS binding routes by path so the enrichment can load the
// snapshot AND (optionally) the rag index. `rag: null` → 404 there, so
// retrieval fails soft to the orientation-only block.
/** @param {{ snapshot?: any, snapshotStatus?: number, rag?: any, berget?: boolean }} [opts] */
function makeEnv({ snapshot = SNAPSHOT, snapshotStatus = 200, rag = null, berget = false } = {}) {
  return /** @type {any} */ ({
    BERGET_API_TOKEN: berget ? "k" : undefined,
    ASSETS: {
      fetch: async (/** @type {Request} */ req) => {
        const p = new URL(req.url).pathname;
        if (p.endsWith("source-rag.json")) return rag ? jsonRes(rag) : jsonRes(null, 404);
        return jsonRes(snapshot, snapshotStatus);
      },
    },
  });
}

// Back-compat shim for the loadSourceSnapshot test: any-payload single route.
/** @param {any} payload @param {number} [status] */
function envWith(payload, status = 200) {
  return /** @type {any} */ ({
    ASSETS: { fetch: async () => jsonRes(payload, status) },
  });
}

function steps() {
  /** @type {string[]} */
  const started = [];
  /** @type {string[]} */
  const done = [];
  return {
    started,
    done,
    step: (/** @type {string} */ id, /** @type {string} */ label) => started.push(label),
    stepDone: (/** @type {string} */ id, /** @type {string} */ label) => done.push(label),
  };
}

const convo = (/** @type {string[]} */ ...texts) => texts.map((t) => ({ role: "user", content: t }));

test("loadSourceSnapshot: fetches + validates via the ASSETS binding", async () => {
  const snap = await loadSourceSnapshot(envWith(SNAPSHOT), noopLog);
  assert.ok(snap);
  assert.equal(snap.count, 2);
  // missing binding / 404 / junk all degrade to null, never a throw
  assert.equal(await loadSourceSnapshot(/** @type {any} */ ({}), noopLog), null);
  assert.equal(await loadSourceSnapshot(envWith(null, 404), noopLog), null);
  assert.equal(await loadSourceSnapshot(envWith({ nope: 1 }), noopLog), null);
});

test("runIntrospectionEnrichment: ALWAYS injects the source in dev mode — the 'Code examples from site' fix", async () => {
  // The reported bug: a plain code request that matches no intent regex must
  // STILL get the source injected (dev mode is the only gate now).
  for (const ask of ["Code examples from site", "what's the weather in Lund?", "how are you implemented?", "visa mig din källkod"]) {
    const s = steps();
    const state = /** @type {any} */ ({ introspection: true, introspectionCount: 0, shellTranscript: [] });
    const out = await runIntrospectionEnrichment(makeEnv(), noopLog, s.step, s.stepDone, /** @type {any} */ (convo(ask)), state);
    const text = /** @type {any} */ (out[out.length - 1]).content;
    assert.match(text, /--- Introspection: deepresearch\.se source/, ask);
    assert.match(text, /Never say you have no access to the source or that this isn't a coding tool/, ask);
    assert.equal(state.introspectionCount, 1, ask);
    assert.equal(s.done.length, 1, ask);
    // The loaded snapshot is stashed so the pipeline's source-read loop can
    // READ files from it without a second ASSETS fetch.
    assert.ok(state.sourceSnapshot && state.sourceSnapshot.count === 2, ask);
  }
});

test("runIntrospectionEnrichment: strong intent adds the full file index; a plain ask doesn't", async () => {
  const s1 = steps();
  const strong = /** @type {any} */ ({ introspection: true, introspectionCount: 0 });
  const a = await runIntrospectionEnrichment(makeEnv(), noopLog, s1.step, s1.stepDone, /** @type {any} */ (convo("show me your source code")), strong);
  assert.match(/** @type {any} */ (a[a.length - 1]).content, /Full file index/);

  const s2 = steps();
  const plain = /** @type {any} */ ({ introspection: true, introspectionCount: 0 });
  const b = await runIntrospectionEnrichment(makeEnv(), noopLog, s2.step, s2.stepDone, /** @type {any} */ (convo("code examples from site")), plain);
  const text = /** @type {any} */ (b[b.length - 1]).content;
  assert.doesNotMatch(text, /# Full file index/);
  assert.match(text, /name any file path/); // the lean pointer instead
});

test("runIntrospectionEnrichment: dense retrieval surfaces relevant chunks (mocked embed + rag index)", async () => {
  // A rag index whose only vector points at src/pipeline.js chunk 0, and a
  // mocked Berget embed returning a query vector aligned to it.
  const { int8ToB64, quantizeInt8 } = await import("../public/js/introspect-core.js");
  const rag = {
    v: 1, model: "e5", dims: 3, target: 1400, overlap: 200,
    vectors: [int8ToB64(quantizeInt8(Float32Array.of(0, 1, 0)))],
    map: [{ p: "src/pipeline.js", ci: 0 }],
  };
  const realFetch = globalThis.fetch;
  globalThis.fetch = async () => jsonRes({ data: [{ embedding: [0, 1, 0] }], model: "e5" });
  try {
    const s = steps();
    const state = /** @type {any} */ ({ introspection: true, introspectionCount: 0 });
    const out = await runIntrospectionEnrichment(makeEnv({ rag, berget: true }), noopLog, s.step, s.stepDone, /** @type {any} */ (convo("how do the pipeline phases work")), state);
    const text = /** @type {any} */ (out[out.length - 1]).content;
    assert.match(text, /Source excerpts most relevant to this question/);
    assert.match(text, /## src\/pipeline\.js/);
    assert.match(text, /\/\/ phases/); // the chunk text, resolved from the snapshot
    assert.match(s.done[0], /relevant source excerpt/);
  } finally {
    globalThis.fetch = realFetch;
  }
});

test("runIntrospectionEnrichment: fail-soft when the snapshot is unavailable", async () => {
  const s = steps();
  const state = /** @type {any} */ ({ introspection: true, introspectionCount: 0 });
  const conversation = convo("how are you built?");
  const out = await runIntrospectionEnrichment(makeEnv({ snapshot: null, snapshotStatus: 404 }), noopLog, s.step, s.stepDone, /** @type {any} */ (conversation), state);
  assert.equal(out, conversation); // unchanged, no throw
  assert.match(s.done[0], /unavailable/);
  assert.equal(state.introspectionCount, 0);
});

// ---- the committed artifacts stay fresh -----------------------------------------

test("source snapshot artifact matches the working tree (npm run bundle)", () => {
  const root = join(dirname(fileURLToPath(import.meta.url)), "..");
  // Exits non-zero (throws here) when public/introspect/source-snapshot.json
  // is stale — regenerate with `npm run bundle` and commit it.
  execFileSync(process.execPath, [join(root, "scripts/bundle-source.mjs"), "--check"], {
    cwd: root,
    stdio: "pipe",
  });
});

test("source-rag index is consistent with the current snapshot (no stale chunk refs)", async (t) => {
  // The rag index can't be re-embedded in CI (no key), so we can't recompute
  // it — but we CAN enforce the correctness invariant: every indexed (p, ci)
  // must still resolve against the CURRENT snapshot's deterministic chunking.
  // A source edit that shifts chunk boundaries (or removes a file) trips this
  // → re-run `npm run bundle:rag` (with a Berget key or the break-glass creds)
  // and commit the regenerated index. Vectors may lag semantically until then;
  // the retrieved TEXT is always current (retrieval re-chunks the snapshot).
  //
  // The index is an OPTIONAL enhancement — the server fails soft to an
  // orientation-only block without it — so a missing artifact SKIPS (retrieval
  // is simply off) rather than failing the suite; a PRESENT one is enforced.
  const { existsSync } = await import("node:fs");
  const { validateSnapshot, validateRagIndex, chunkSourceText } = await import("../public/js/introspect-core.js");
  const root = join(dirname(fileURLToPath(import.meta.url)), "..");
  const ragPath = join(root, "public/introspect/source-rag.json");
  if (!existsSync(ragPath)) {
    t.skip("source-rag.json absent — dense retrieval off until `npm run bundle:rag` is committed");
    return;
  }
  const read = (p) => JSON.parse(readFileSync(join(root, p), "utf8"));
  const snapshot = validateSnapshot(read("public/introspect/source-snapshot.json"));
  assert.ok(snapshot, "snapshot must exist and validate");
  const index = validateRagIndex(read("public/introspect/source-rag.json"));
  assert.ok(index, "source-rag.json present but invalid — re-run `npm run bundle:rag`");

  const counts = new Map();
  for (const f of snapshot.files) counts.set(f.p, chunkSourceText(f.t).length);
  let stale = 0;
  for (const m of index.map) {
    const n = counts.get(m.p);
    if (n === undefined || m.ci >= n) stale++;
  }
  assert.equal(stale, 0, `${stale} rag chunk refs no longer resolve — re-run \`npm run bundle:rag\``);
  // Coverage sanity floor: the builder deliberately excludes test files, so we
  // don't assert a percentage of ALL files — just that a substantial slice of
  // the source is indexed (a badly-truncated or near-empty index trips this).
  const covered = new Set(index.map.map((m) => m.p));
  assert.ok(covered.size >= 80, `rag index covers only ${covered.size} files — re-run \`npm run bundle:rag\``);
});

// @ts-check
// Minimal structured logger for Cloudflare Workers.
//
// Emits one JSON object per line, which Workers Logs and `npx wrangler tail`
// index and filter natively. Levels: debug < info < warn < error; the
// threshold comes from the LOG_LEVEL var in wrangler.toml (default "info").
//
// Privacy rules (enforced by convention at every call site):
// - Never log secrets or Authorization headers.
// - Never log chat message content. User-provided text (e.g. search queries)
//   may be logged at debug level only; info-and-above logs carry counts,
//   durations, and statuses instead.

/** @type {Record<string, number>} */
const LEVELS = { debug: 10, info: 20, warn: 30, error: 40 };

/**
 * Builds a structured logger bound to a request/environment.
 * @param {import('./types.js').Env} env
 * @param {Record<string, unknown>} [base] fields merged into every entry
 * @returns {import('./types.js').Logger}
 */
export function createLogger(env, base = {}) {
  const name = String(env.LOG_LEVEL || "info").toLowerCase();
  const threshold = LEVELS[name] ?? LEVELS.info;

  /**
   * @param {"debug"|"info"|"warn"|"error"} level
   * @param {string} event
   * @param {Record<string, unknown>} [fields]
   */
  const emit = (level, event, fields) => {
    if (LEVELS[level] < threshold) return;
    const entry = {
      time: new Date().toISOString(),
      level,
      event,
      ...base,
      ...fields,
    };
    (level === "error" ? console.error : console.log)(JSON.stringify(entry));
  };

  return {
    debug: (event, fields = {}) => emit("debug", event, fields),
    info: (event, fields = {}) => emit("info", event, fields),
    warn: (event, fields = {}) => emit("warn", event, fields),
    error: (event, fields = {}) => emit("error", event, fields),
  };
}

