// @ts-check
// Structured research notes — the pure representation/merge logic behind the
// budget-gated "notes digest" phase (see src/pipeline.js's maybeDigest and
// src/prompts.js's notesPrompt).
//
// A note distils one factual claim out of the raw source highlights and ties
// it back to the numbered source registry:
//   { claim: string, source_ids: number[], entities: string[], contradicts?: string[] }
// The digest phase (a JSON call on the cheap reliable model) produces raw
// notes from each new search wave; this module normalizes and MERGES them
// across waves (deduping by claim, unioning source ids / entities) so gap-check
// and synthesis reason over a compact claim set instead of re-reading every
// highlight. Everything here is pure and never throws — a bad note is dropped,
// never fatal, matching the fail-soft posture of the whole pipeline.

/**
 * A canonical note (normalizeNote output). `source_ids` are 1-based numbers
 * into the source registry; `contradicts` only rides when non-empty.
 * @typedef {{ claim: string, source_ids: number[], entities: string[], contradicts?: string[] }} Note
 */

/** @param {unknown} v @returns {number[]} */
function toNumberIds(v) {
  const arr = Array.isArray(v) ? v : v == null ? [] : [v];
  const out = [];
  const seen = new Set();
  for (const x of arr) {
    let n = null;
    if (typeof x === "number" && Number.isFinite(x)) n = Math.trunc(x);
    else if (typeof x === "string" && x.trim() !== "" && Number.isFinite(Number(x))) n = Math.trunc(Number(x));
    if (n == null || n < 1) continue; // source numbers are 1-based
    if (seen.has(n)) continue;
    seen.add(n);
    out.push(n);
  }
  return out;
}

/** @param {unknown} v @returns {string[]} */
function toStringList(v) {
  const arr = Array.isArray(v) ? v : typeof v === "string" ? [v] : [];
  const out = [];
  const seen = new Set();
  for (const x of arr) {
    if (typeof x !== "string") continue;
    const s = x.trim();
    if (!s) continue;
    const key = s.toLowerCase();
    if (seen.has(key)) continue;
    seen.add(key);
    out.push(s);
  }
  return out;
}

// Normalizes one raw note object into the canonical shape, or null if it has
// no usable claim. `contradicts` is only carried when present.
/**
 * @param {any} raw
 * @returns {Note | null}
 */
export function normalizeNote(raw) {
  if (!raw || typeof raw !== "object" || Array.isArray(raw)) return null;
  const claim = typeof raw.claim === "string" ? raw.claim.trim() : "";
  if (!claim) return null;
  /** @type {Note} */
  const note = {
    claim,
    source_ids: toNumberIds(raw.source_ids),
    entities: toStringList(raw.entities),
  };
  const contradicts = toStringList(raw.contradicts);
  if (contradicts.length) note.contradicts = contradicts;
  return note;
}

// Extracts an array of canonical notes from a digest phase's JSON value
// (accepts either `{notes:[...]}` or a bare array). Pure, never throws.
/**
 * @param {any} value
 * @returns {Note[]}
 */
export function extractNotes(value) {
  const rawList = Array.isArray(value)
    ? value
    : value && typeof value === "object" && Array.isArray(value.notes)
      ? value.notes
      : [];
  const out = [];
  for (const raw of rawList) {
    const note = normalizeNote(raw);
    if (note) out.push(note);
  }
  return out;
}

// Dedup key: a claim's normalized text (lowercased, whitespace-collapsed).
/** @param {Note} note */
function noteKey(note) {
  return note.claim.toLowerCase().replace(/\s+/g, " ").trim();
}

/** @param {number[]} a @param {number[]} b */
function unionNums(a, b) {
  const out = [...a];
  const seen = new Set(a);
  for (const n of b) if (!seen.has(n)) { seen.add(n); out.push(n); }
  return out;
}

/** @param {string[]} a @param {string[]} b */
function unionStrs(a, b) {
  const out = [...a];
  const seen = new Set(a.map((s) => s.toLowerCase()));
  for (const s of b) {
    const k = s.toLowerCase();
    if (!seen.has(k)) { seen.add(k); out.push(s); }
  }
  return out;
}

// Merges `incoming` notes into `existing`, deduping by claim and unioning the
// source ids / entities / contradicts of duplicates. Both inputs may be raw or
// already-normalized; the result is always a fresh array of canonical notes
// (never shares references with the inputs).
/**
 * @param {any[] | null | undefined} existing
 * @param {any[] | null | undefined} incoming
 * @returns {Note[]}
 */
export function mergeNotes(existing, incoming) {
  /** @type {Map<string, Note>} */
  const byKey = new Map();
  /** @type {Note[]} */
  const out = [];
  for (const raw of [...(existing || []), ...(incoming || [])]) {
    const note = normalizeNote(raw);
    if (!note) continue;
    const key = noteKey(note);
    const prev = byKey.get(key);
    if (prev) {
      prev.source_ids = unionNums(prev.source_ids, note.source_ids);
      prev.entities = unionStrs(prev.entities, note.entities);
      if (note.contradicts) prev.contradicts = unionStrs(prev.contradicts || [], note.contradicts);
    } else {
      /** @type {Note} */
      const copy = { claim: note.claim, source_ids: [...note.source_ids], entities: [...note.entities] };
      if (note.contradicts) copy.contradicts = [...note.contradicts];
      byKey.set(key, copy);
      out.push(copy);
    }
  }
  return out;
}

// Unique entity list across all notes (for seeding the next digest so it can
// keep entity names consistent).
/**
 * @param {Array<Partial<Note>> | null | undefined} notes
 * @returns {string[]}
 */
export function notesEntities(notes) {
  /** @type {string[]} */
  let acc = [];
  for (const n of notes || []) acc = unionStrs(acc, Array.isArray(n?.entities) ? n.entities : []);
  return acc;
}

// Renders notes as a compact text block for gap-check / synthesis, bounded to
// `capChars`. Each note: the claim, its cited source numbers, named entities,
// and any contradiction flag. Empty when there are no notes.
/**
 * @param {Array<Partial<Note>> | null | undefined} notes
 * @param {number} [capChars]
 * @returns {string}
 */
export function notesDigest(notes, capChars = 6000) {
  const lines = [];
  let used = 0;
  for (const n of notes || []) {
    if (!n?.claim) continue;
    const cites = n.source_ids?.length ? ` [${n.source_ids.map((i) => `S${i}`).join(", ")}]` : "";
    const ents = n.entities?.length ? ` (entities: ${n.entities.join(", ")})` : "";
    const contra = n.contradicts?.length ? ` (contradicts: ${n.contradicts.join("; ")})` : "";
    const line = `- ${n.claim}${cites}${ents}${contra}`;
    if (used + line.length > capChars) break;
    lines.push(line);
    used += line.length + 1;
  }
  return lines.join("\n");
}

// Unit tests for the research-notes representation (src/notes.js): note
// normalization/extraction, cross-wave merging, and the bounded digest.
import { test, describe } from "node:test";
import assert from "node:assert/strict";
import { normalizeNote, extractNotes, mergeNotes, notesEntities, notesDigest } from "./notes.js";

describe("normalizeNote", () => {
  test("canonicalizes a well-formed note", () => {
    const n = normalizeNote({
      claim: "  EVs hit 90% share  ",
      source_ids: [1, 2],
      entities: ["Norway"],
    });
    assert.deepEqual(n, { claim: "EVs hit 90% share", source_ids: [1, 2], entities: ["Norway"] });
  });
  test("returns null without a usable claim", () => {
    assert.equal(normalizeNote({ claim: "   ", source_ids: [1] }), null);
    assert.equal(normalizeNote({ source_ids: [1] }), null);
    assert.equal(normalizeNote(null), null);
    assert.equal(normalizeNote("nope"), null);
    assert.equal(normalizeNote([1, 2]), null);
  });
  test("coerces numeric-string source ids and drops junk / <1 / duplicates", () => {
    const n = normalizeNote({ claim: "x", source_ids: ["3", 3, 0, -1, "abc", 2.9] });
    assert.deepEqual(n.source_ids, [3, 2]); // "3"/3 dedup, 0/-1/abc dropped, 2.9→2
  });
  test("dedupes entities case-insensitively and drops blanks/non-strings", () => {
    const n = normalizeNote({ claim: "x", entities: ["Tesla", "tesla", "", 5, "  BYD "] });
    assert.deepEqual(n.entities, ["Tesla", "BYD"]);
  });
  test("carries contradicts only when present", () => {
    assert.equal("contradicts" in normalizeNote({ claim: "x" }), false);
    assert.deepEqual(normalizeNote({ claim: "x", contradicts: ["S4"] }).contradicts, ["S4"]);
  });
});

describe("extractNotes", () => {
  test("reads a {notes:[...]} envelope, dropping invalid notes", () => {
    const out = extractNotes({ notes: [{ claim: "a" }, { claim: "" }, null, { claim: "b", source_ids: [1] }] });
    assert.deepEqual(out.map((n) => n.claim), ["a", "b"]);
  });
  test("accepts a bare array too", () => {
    assert.deepEqual(extractNotes([{ claim: "z" }]).map((n) => n.claim), ["z"]);
  });
  test("anything else yields an empty list, never throws", () => {
    assert.deepEqual(extractNotes(null), []);
    assert.deepEqual(extractNotes("garbage"), []);
    assert.deepEqual(extractNotes({ foo: 1 }), []);
  });
});

describe("mergeNotes", () => {
  test("dedupes by claim and unions source ids / entities", () => {
    const existing = [{ claim: "Battery prices fell", source_ids: [1], entities: ["CATL"] }];
    const incoming = [
      { claim: "battery prices fell", source_ids: [2, 1], entities: ["BYD"] }, // same claim, different case
      { claim: "New gigafactory opened", source_ids: [3], entities: [] },
    ];
    const merged = mergeNotes(existing, incoming);
    assert.equal(merged.length, 2);
    assert.deepEqual(merged[0], { claim: "Battery prices fell", source_ids: [1, 2], entities: ["CATL", "BYD"] });
    assert.equal(merged[1].claim, "New gigafactory opened");
  });
  test("does not mutate or share references with the inputs", () => {
    const existing = [{ claim: "a", source_ids: [1], entities: ["X"] }];
    const merged = mergeNotes(existing, [{ claim: "a", source_ids: [2], entities: ["Y"] }]);
    assert.deepEqual(existing[0].source_ids, [1], "input left untouched");
    assert.notEqual(merged[0].source_ids, existing[0].source_ids);
  });
  test("merges contradicts across duplicates", () => {
    const merged = mergeNotes(
      [{ claim: "a", contradicts: ["S1"] }],
      [{ claim: "a", contradicts: ["S2", "s1"] }],
    );
    assert.deepEqual(merged[0].contradicts, ["S1", "S2"]);
  });
  test("handles empty / missing inputs", () => {
    assert.deepEqual(mergeNotes(undefined, undefined), []);
    assert.deepEqual(mergeNotes([], [{ claim: "solo" }]).map((n) => n.claim), ["solo"]);
  });
});

describe("notesEntities", () => {
  test("unions entities across notes, case-insensitively deduped", () => {
    const ents = notesEntities([
      { claim: "a", entities: ["Norway", "EU"] },
      { claim: "b", entities: ["norway", "China"] },
    ]);
    assert.deepEqual(ents, ["Norway", "EU", "China"]);
  });
  test("empty for no notes", () => {
    assert.deepEqual(notesEntities([]), []);
    assert.deepEqual(notesEntities(undefined), []);
  });
});

describe("notesDigest", () => {
  test("renders claims with cited sources, entities, and contradictions", () => {
    const text = notesDigest([
      { claim: "EVs at 90%", source_ids: [1, 3], entities: ["Norway"] },
      { claim: "Prices up", source_ids: [2], entities: [], contradicts: ["S1"] },
    ]);
    assert.match(text, /- EVs at 90% \[S1, S3\] \(entities: Norway\)/);
    assert.match(text, /- Prices up \[S2\] \(contradicts: S1\)/);
  });
  test("stops at the character cap", () => {
    const notes = Array.from({ length: 50 }, (_, i) => ({ claim: "claim " + i, source_ids: [i + 1], entities: [] }));
    const text = notesDigest(notes, 40);
    assert.ok(text.length <= 40 + 20); // roughly capped; not all 50 rendered
    assert.ok(text.split("\n").length < 50);
  });
  test("empty for no notes", () => {
    assert.equal(notesDigest([]), "");
    assert.equal(notesDigest(undefined), "");
  });
});

// @ts-check
// OpenAI (GPT) provider client — the third LLM provider alongside Berget
// (src/berget.js) and Anthropic (src/anthropic.js). Raw fetch against the
// OpenAI Chat Completions API — deliberately no SDK: the Worker has no build
// step and no runtime deps (CLAUDE.md invariant 5), and the only surface
// needed is streaming chat plus a rarely-used JSON completion.
//
// Unlike Anthropic, OpenAI needs NO stream adapter: its Chat Completions SSE
// IS the wire format the pipeline's shared consumer (berget.js
// `consumeChatStream`) parses — `choices[0].delta.content`, a finish_reason
// on the closing chunk, a usage chunk, `[DONE]`. The response body passes
// through untouched, so the idle/total guards, the finish_reason
// dropped-connection check, STREAM_MAX_CHARS, the empty-completion retry,
// and pipeline.js's model failover all apply unchanged. What DOES differ is
// wire PARAMETERS (see `toOpenAiPayload`): GPT-5-era reasoning models reject
// the legacy `max_tokens` (→ `max_completion_tokens`), streaming only
// reports usage when asked (`stream_options.include_usage`), and reasoning
// effort must be pinned explicitly (see REASONING_EFFORT below).
//
// Feature-gated on the OPENAI_API_KEY secret (a dashboard secret, same
// convention as BERGET_API_TOKEN / ANTHROPIC_API_KEY — never in the repo):
// absent, the models don't appear in the catalog and nothing routes here
// (src/providers.js).

import { eurPerTokenFromUsd, formatPricing, parseLooseJson } from "./berget.js";

// OPENAI_URL override exists solely so tests can point at a mock (the same
// convention as BERGET_URL/ANTHROPIC_URL); production always uses the default.
/** @param {import('./types.js').Env} env */
const apiBase = (env) => String(env.OPENAI_URL || "https://api.openai.com/v1");
/** @param {import('./types.js').Env} env */
const chatUrl = (env) => apiBase(env) + "/chat/completions";

// Same timeout discipline as berget.js — an unbounded fetch to an LLM
// backend has bitten this project before (berget.js round-2 note): bound
// the connect phase into a normal, catchable error.
const STREAM_CONNECT_TIMEOUT_MS = 30_000;
const JSON_CALL_TIMEOUT_MS = 45_000;

// Matches berget.js's chatCompletion max_tokens — the synthesis answer cap.
// Sent as `max_completion_tokens` (the GPT-5-era param; it bounds visible
// output PLUS any hidden reasoning tokens — another reason reasoning stays
// off below, so the cap buys actual answer text).
const MAX_TOKENS = 4096;

// Every GPT model in the catalog is a reasoning model whose default effort
// spends hidden reasoning tokens inside max_completion_tokens and sits
// silent before the first text delta — both bad fits for this pipeline's
// time-budget planning and its 60s idle guard (the exact same tradeoff as
// Sonnet 5's adaptive thinking, which anthropic.js explicitly disables).
// `"none"` makes them behave like non-reasoning models (supported effort
// scale as of 2026-07: none/minimal/low/medium/high/xhigh). Revisit with a
// rubric-bench A/B (tests/eval-bench.mjs) if synthesis quality looks worth
// the latency on the flagship.
const REASONING_EFFORT = "none";

// Static catalog — the offered models are a deliberate product choice (the
// current mainstream GPT lineup: the three gpt-5.6 tiers plus the compact
// gpt-5.4-mini), and a live /v1/models fetch carries no pricing, so it would
// add a failure mode without adding information (the same reasoning as
// anthropic.js's static list). Prices are the standard USD per-1M rates from
// OpenAI's pricing page as of 2026-07. All four models accept image input
// (vision) and stream via Chat Completions.
const MODELS = [
  { id: "gpt-5.6-sol", name: "GPT-5.6 Sol", usd_in: 5, usd_out: 30 },
  { id: "gpt-5.6-terra", name: "GPT-5.6 Terra", usd_in: 2.5, usd_out: 15 },
  { id: "gpt-5.6-luna", name: "GPT-5.6 Luna", usd_in: 1, usd_out: 6 },
  { id: "gpt-5.4-mini", name: "GPT-5.4 Mini", usd_in: 0.75, usd_out: 4.5 },
];

// OpenAI model ids are a distinct namespace (bare gpt-*); Berget ids are
// vendor/model paths — note Berget's catalog carries the LOOKALIKE
// `openai/gpt-oss-120b`, which starts with "openai/" and therefore stays on
// Berget. The bare prefix is the routing key src/providers.js dispatches on.
/** @param {unknown} id */
export function isOpenAiModel(id) {
  return typeof id === "string" && id.startsWith("gpt-");
}

/** @param {import('./types.js').Env} env */
export function openaiConfigured(env) {
  return !!env.OPENAI_API_KEY;
}

// Catalog entries in the exact shape berget.js's listModels produces
// (ModelCatalogEntry), so validation, the UI dropdown, and quota pricing
// consume them with no special-casing. Empty when the key isn't configured
// — the feature is invisible, same as Anthropic/Shodan/Maps without theirs.
/**
 * @param {import('./types.js').Env} env
 * @returns {import('./types.js').ModelCatalogEntry[]}
 */
export function openaiModels(env) {
  if (!openaiConfigured(env)) return [];
  return MODELS.map((m) => ({
    id: m.id,
    name: m.name,
    pricing: formatPricing({ input: eurPerTokenFromUsd(m.usd_in), output: eurPerTokenFromUsd(m.usd_out), currency: "EUR" }),
    price_in: eurPerTokenFromUsd(m.usd_in),
    price_out: eurPerTokenFromUsd(m.usd_out),
    up: true,
    vision: true,
    provider: "openai",
  }));
}

/** @param {import('./types.js').Env} env */
function headers(env) {
  return {
    "content-type": "application/json",
    authorization: `Bearer ${env.OPENAI_API_KEY || ""}`,
  };
}

// The project's message arrays are already OpenAI-shaped (text parts +
// data-URL image_url parts), so `messages` passes through untouched — this
// builder only pins the GPT-5-era wire parameters. Pure and exported for
// unit tests.
/**
 * @param {import('./types.js').Conversation} messages
 * @param {{ model?: string, maxTokens?: number, stream?: boolean, json?: boolean }} opts
 */
export function toOpenAiPayload(messages, { model, maxTokens = MAX_TOKENS, stream = false, json = false } = {}) {
  /** @type {Record<string, unknown>} */
  const payload = {
    model,
    stream,
    // GPT-5-era models reject the legacy `max_tokens` on Chat Completions.
    max_completion_tokens: maxTokens,
    reasoning_effort: REASONING_EFFORT,
    messages,
  };
  // Streaming responses only carry the terminal usage chunk (empty
  // `choices` + totals — the shape consumeChatStream merges) when asked.
  if (stream) payload.stream_options = { include_usage: true };
  if (json) payload.response_format = { type: "json_object" };
  return payload;
}

// Streaming chat completion, same calling contract as berget.js's
// chatCompletion: resolves to a Response with an OpenAI-style SSE body —
// which is exactly what OpenAI serves, so the raw Response is returned
// as-is (non-2xx included, so callers' `.text()` detail capture works).
// The abort signal bounds only the connect phase, exactly like Berget's.
/**
 * @param {import('./types.js').Env} env
 * @param {import('./types.js').Conversation} messages
 * @param {{ model?: string }} opts
 */
export function openaiChatCompletion(env, messages, { model } = {}) {
  const controller = new AbortController();
  const timer = setTimeout(() => controller.abort(), STREAM_CONNECT_TIMEOUT_MS);
  return fetch(chatUrl(env), {
    method: "POST",
    headers: headers(env),
    body: JSON.stringify(toOpenAiPayload(messages, { model, stream: true })),
    signal: controller.signal,
  }).finally(() => clearTimeout(timer));
}

// Non-streaming JSON completion, same contract as berget.js's completeJson
// ({ value, usage, diagnostics }; value null on parse failure — callers
// fall back gracefully). Normally UNUSED: the JSON planning phases run on
// Berget's fixed DEFAULT_MODEL (split model routing — CLAUDE.md invariant
// 3). This exists so the dispatch stays total if a deployment ever routes
// JSON to a GPT model (e.g. Berget catalog outage fallback). OpenAI does
// support `response_format: json_object`, so it is requested; parseLooseJson
// still repairs prose-wrapped objects as a belt-and-braces.
/**
 * @param {import('./types.js').Env} env
 * @param {import('./types.js').Conversation} messages
 * @param {{ model?: string, maxTokens?: number }} opts
 */
export async function openaiCompleteJson(env, messages, { model, maxTokens = 900 } = {}) {
  const resp = await fetch(chatUrl(env), {
    method: "POST",
    headers: headers(env),
    body: JSON.stringify(toOpenAiPayload(messages, { model, maxTokens, json: true })),
    signal: AbortSignal.timeout(JSON_CALL_TIMEOUT_MS),
  });
  if (!resp.ok) {
    const detail = await resp.text().catch(() => "");
    throw new Error(`OpenAI JSON call failed (${resp.status}): ${detail.slice(0, 200)}`);
  }
  const data = /** @type {any} */ (await resp.json());
  const choice = data.choices?.[0];
  const content = choice?.message?.content || "";
  const { value, parseMode } = parseLooseJson(content);
  return {
    value,
    usage: data.usage || null,
    diagnostics: {
      parse_mode: parseMode,
      finish_reason: choice?.finish_reason || null,
      content_length: content.length,
    },
  };
}

import { test, describe, before, after } from "node:test";
import assert from "node:assert/strict";
import http from "node:http";

import {
  isOpenAiModel,
  openaiChatCompletion,
  openaiCompleteJson,
  openaiModels,
  toOpenAiPayload,
} from "./openai.js";
import { consumeChatStream } from "./berget.js";

// Builds a mock OpenAI Chat Completions SSE body (the native wire format —
// no adapter exists for this provider, so what these chunks assert is the
// no-adapter assumption itself: the raw body must satisfy berget.js's
// consumeChatStream, the exact composition production uses).
function openaiSseLines(chunks) {
  return chunks.map((c) => `data: ${typeof c === "string" ? c : JSON.stringify(c)}\n\n`).join("");
}

function sseBody(chunks) {
  const encoder = new TextEncoder();
  const payload = encoder.encode(openaiSseLines(chunks));
  return new ReadableStream({
    start(controller) {
      controller.enqueue(payload);
      controller.close();
    },
  });
}

const contentChunk = (text) => ({ choices: [{ delta: { content: text } }] });
const finishChunk = (reason = "stop") => ({ choices: [{ delta: {}, finish_reason: reason }] });
// With stream_options.include_usage, OpenAI ends with an empty-choices
// usage chunk — the same shape as Berget's, which consumeChatStream merges.
const usageChunk = (p = 12, c = 7) => ({
  choices: [],
  usage: { prompt_tokens: p, completion_tokens: c, total_tokens: p + c },
});

describe("isOpenAiModel", () => {
  test("bare gpt-* ids route to OpenAI; Berget's openai/-path lookalikes do not", () => {
    assert.equal(isOpenAiModel("gpt-5.6-sol"), true);
    assert.equal(isOpenAiModel("gpt-5.4-mini"), true);
    assert.equal(isOpenAiModel("openai/gpt-oss-120b"), false); // Berget-hosted, vendor-path id
    assert.equal(isOpenAiModel("claude-sonnet-5"), false);
    assert.equal(isOpenAiModel("mistralai/Mistral-Small-3.2-24B-Instruct-2506"), false);
    assert.equal(isOpenAiModel(undefined), false);
    assert.equal(isOpenAiModel(null), false);
  });
});

describe("openaiModels", () => {
  test("empty without the OPENAI_API_KEY secret (feature invisible)", () => {
    assert.deepEqual(openaiModels({}), []);
  });

  test("with the key: the GPT lineup in ModelCatalogEntry shape, EUR-priced, vision, up", () => {
    const models = openaiModels({ OPENAI_API_KEY: "k" });
    assert.deepEqual(
      models.map((m) => m.id),
      ["gpt-5.6-sol", "gpt-5.6-terra", "gpt-5.6-luna", "gpt-5.4-mini"],
    );
    for (const m of models) {
      assert.equal(m.up, true);
      assert.equal(m.vision, true);
      assert.equal(m.provider, "openai");
      assert.ok(m.price_in > 0 && m.price_out > m.price_in, `${m.id} priced`);
      assert.match(m.pricing, /€.* in \/ €.* out per 1M tokens/);
    }
    // Relative pricing sanity: sol > terra > luna > mini.
    const outs = models.map((m) => m.price_out);
    assert.deepEqual([...outs].sort((a, b) => b - a), outs);
  });
});

describe("toOpenAiPayload", () => {
  test("GPT-5-era wire params: max_completion_tokens (never max_tokens), reasoning pinned off", () => {
    const p = toOpenAiPayload([{ role: "user", content: "q" }], { model: "gpt-5.6-terra" });
    assert.equal(p.model, "gpt-5.6-terra");
    assert.equal(p.max_completion_tokens, 4096);
    assert.equal("max_tokens" in p, false);
    // Hidden reasoning spends output tokens inside max_completion_tokens and
    // stalls the first delta — pinned off, the same call anthropic.js makes
    // for Sonnet 5's adaptive thinking.
    assert.equal(p.reasoning_effort, "none");
  });

  test("messages pass through untouched — the project's arrays are already OpenAI-shaped", () => {
    const messages = [
      { role: "system", content: "You are helpful." },
      {
        role: "user",
        content: [
          { type: "text", text: "what is this?" },
          { type: "image_url", image_url: { url: "data:image/jpeg;base64,AAAA" } },
        ],
      },
    ];
    const p = toOpenAiPayload(messages, { model: "gpt-5.6-sol" });
    assert.equal(p.messages, messages);
  });

  test("streaming requests the usage chunk; non-streaming does not", () => {
    const streaming = toOpenAiPayload([{ role: "user", content: "q" }], { model: "gpt-5.6-luna", stream: true });
    assert.equal(streaming.stream, true);
    assert.deepEqual(streaming.stream_options, { include_usage: true });
    const plain = toOpenAiPayload([{ role: "user", content: "q" }], { model: "gpt-5.6-luna" });
    assert.equal("stream_options" in plain, false);
  });

  test("json flag requests json_object; maxTokens rides through", () => {
    const p = toOpenAiPayload([{ role: "user", content: "q" }], { model: "gpt-5.4-mini", maxTokens: 900, json: true });
    assert.equal(p.max_completion_tokens, 900);
    assert.deepEqual(p.response_format, { type: "json_object" });
    assert.equal("response_format" in toOpenAiPayload([], { model: "gpt-5.4-mini" }), false);
  });
});

describe("native OpenAI SSE → consumeChatStream (the no-adapter assumption)", () => {
  test("text deltas, finish_reason and the trailing usage chunk arrive intact", async () => {
    const body = sseBody([contentChunk("Hel"), contentChunk("lo"), finishChunk("stop"), usageChunk(12, 7), "[DONE]"]);
    const seen = [];
    const out = await consumeChatStream(body, (t) => seen.push(t));
    assert.equal(out.text, "Hello");
    assert.deepEqual(seen, ["Hel", "lo"]);
    assert.equal(out.finishReason, "stop");
    assert.equal(out.usage.prompt_tokens, 12);
    assert.equal(out.usage.completion_tokens, 7);
  });

  test("a stream that dies early yields NO finish_reason — the dropped-connection tell", async () => {
    // pipeline.js throws on a falsy finishReason; a GPT stream cut before
    // its closing chunk must present the same signature as Berget's.
    const body = sseBody([contentChunk("partial")]);
    const out = await consumeChatStream(body, () => {});
    assert.equal(out.text, "partial");
    assert.equal(out.finishReason, null);
  });
});

// Mock-HTTP smoke (rung 2 of the add-llm-provider validation ladder): a
// real node:http server behind the OPENAI_URL override, driven end to end
// through openaiChatCompletion → consumeChatStream and openaiCompleteJson —
// verifies auth headers, the wire payload, and the stream plumbing over
// real HTTP, not just in-memory streams.
describe("openai client over mock HTTP", () => {
  const requests = [];
  const server = http.createServer((req, res) => {
    let raw = "";
