// @ts-check
// POST /api/quiz/grade — grades a quiz's FREE-TEXT answers (the "answer in
// your own words" field public/js/quiz.js offers under the alternatives).
// Multiple-choice picks never come here — the quiz payload carries the key
// and the client grades them locally; only free text needs a model's
// judgement (meaning over wording, any language). One JSON-mode call on the
// fixed reliable DEFAULT_MODEL — same routing rationale as the pipeline's
// JSON phases — with the same quota gate and usage accounting as /api/embed:
// all spend is visible, admins are never blocked.
//
// Fail-soft contract with the client: any failure here is a plain error
// response, and the client marks the answer "ungraded" (excluded from the
// score with a visible note) rather than breaking the quiz.

import { completeJson, DEFAULT_MODEL, listModels } from "./berget.js";
import { quotaBlockedResponse } from "./chat.js";
import { getConfig } from "./config.js";
import { jsonResponse } from "./http.js";
import { quizGradePrompt } from "./prompts.js";
import {
  bergetCost,
  effectiveQuota,
  getUsage,
  inflightLimitResponse,
  quotaExceeded,
  recordUsage,
  releaseInflight,
  reserveInflight,
} from "./quota.js";
import { normalizeGradeResults, validateGradeItems } from "./quiz.js";

/** @typedef {import('./types.js').Env} Env */
/** @typedef {import('./types.js').Logger} Logger */
/** @typedef {import('./settings.js').Identity} Identity */

/**
 * @param {Request} request
 * @param {Env} env
 * @param {Logger} log
 * @param {Identity} identity
 * @returns {Promise<Response>}
 */
export async function handleQuizGrade(request, env, log, identity) {
  if (!env.BERGET_API_TOKEN) {
    return jsonResponse({ error: "Server not configured: BERGET_API_TOKEN secret is missing." }, 500);
  }
  let body;
  try {
    body = await request.json();
  } catch {
    return jsonResponse({ error: "Request body must be valid JSON." }, 400);
  }
  const { items, error } = validateGradeItems(body);
  if (typeof error === "string" || !items) return jsonResponse({ error }, 400);

  // Same quota gate as /api/chat and /api/embed (admins never blocked).
  const config = await getConfig(env);
  const usage = await getUsage(env, identity.id);
  const quota =
    identity.isSecretAdmin || identity.role === "admin"
      ? null
      : effectiveQuota(config, identity.user);
  const blocked = quota ? quotaExceeded(usage, quota) : null;
  if (blocked) return jsonResponse(quotaBlockedResponse(blocked), 429);

  // Per-user concurrency reservation (M-1/M-2), released in the finally below
  // on every exit path. reqId minted locally (this endpoint isn't threaded a
  // request id). Fail-soft: reserve returns ok on any D1 trouble.
  const reqId = crypto.randomUUID();
  const reserved = await reserveInflight(env, identity.id, reqId);
  if (!reserved.ok) return jsonResponse(inflightLimitResponse(reserved), 429);

  const startedAt = Date.now();
  try {
    const r = await completeJson(
      env,
      [
        { role: "system", content: quizGradePrompt() },
        {
          role: "user",
          content: items
            .map(
              (it, i) =>
                `Item ${i + 1}:\nQuestion: ${it.question}\nReference answer: ${it.reference}\nUser's answer: ${it.answer}`,
            )
            .join("\n\n"),
        },
      ],
      { model: DEFAULT_MODEL, maxTokens: 150 * items.length + 200 },
    );
    await recordGradeUsage(env, log, identity, r.usage, Date.now() - startedAt);
    const results = normalizeGradeResults(r.value, items.length);
    if (!results) {
      log.warn("quiz.grade_unparseable", { user_id: identity.id, items: items.length, ...r.diagnostics });
      return jsonResponse({ error: "Grading produced no usable verdict." }, 502);
    }
    log.info("quiz.grade", { user_id: identity.id, items: items.length });
    return jsonResponse({ results });
  } catch (err) {
    log.error("quiz.grade_failed", { user_id: identity.id, error: (/** @type {any} */ (err))?.message || String(err) });
    return jsonResponse({ error: "Grading service unavailable." }, 502);
  } finally {
    await releaseInflight(env, reqId);
  }
}

// Grading spends real (tiny) Berget money on DEFAULT_MODEL — record it like
// every other spend, priced from the catalog (fail-soft: an unreachable
// catalog records the tokens at zero cost rather than failing the grade).
/**
 * @param {Env} env
 * @param {Logger} log
 * @param {Identity} identity
 * @param {{ prompt_tokens?: number, completion_tokens?: number } | null | undefined} usage
 * @param {number} durationMs
 */
async function recordGradeUsage(env, log, identity, usage, durationMs) {
  let entry = null;
  try {
    entry = (await listModels(env))?.find((m) => m.id === DEFAULT_MODEL) || null;
  } catch {
    entry = null;
  }
  const prompt_tokens = usage?.prompt_tokens || 0;
  const completion_tokens = usage?.completion_tokens || 0;
  await recordUsage(env, log, {
    user_id: identity.id,
    model: DEFAULT_MODEL,
    prompt_tokens,
    completion_tokens,
    searches: 0,
    berget_cost: bergetCost(entry, prompt_tokens, completion_tokens),
    exa_cost: 0,
    duration_ms: durationMs,
  });
}

// @ts-check
// The inline-quiz capability's PURE logic: detecting that the user asked to
// be quizzed, hardening the quiz-generation JSON into the shape the client
// renders, and validating/normalizing the free-text grading exchange. All
// deterministic and dependency-free so the Node unit suite exercises it
// directly (src/quiz.test.js); the pipeline phase lives in src/pipeline.js
// (runQuizGeneration) and the grading HTTP handler in src/quiz-api.js.
//
// The capability: "quiz me on <topic/this document>" turns the answer into
// an interactive quiz — the pipeline emits one `quiz` status event carrying
// the full question set (alternatives, the correct index, explanations) and
// the client (public/js/quiz.js) runs the whole interaction locally: one
// question at a time, 2-6 alternatives PLUS a free-text field, immediate
// feedback, and a final score verdict. Multiple-choice picks grade locally
// (the payload carries the key — this is a self-study tool, not an exam);
// free-text answers grade via POST /api/quiz/grade. Material comes from
// whatever the pipeline already has in front of it: the conversation
// (attached documents, project materials, RAG excerpts all ride inside it)
// plus the web-search source registry when triage chose research.

/**
 * One hardened quiz question the client renders (`correct` is the 0-based
 * index into `alternatives`).
 * @typedef {{ question: string, alternatives: string[], correct: number, explanation: string }} QuizQuestion
 */
/**
 * The full quiz payload the `quiz` SSE event carries.
 * @typedef {{ title: string, intro: string, questions: QuizQuestion[] }} Quiz
 */
/**
 * One free-text answer to grade: the quiz's correct alternative is the
 * `reference` the model judges the `answer` against.
 * @typedef {{ question: string, reference: string, answer: string }} GradeItem
 */

// How many questions when the request doesn't say ("quiz me on X").
export const DEFAULT_QUIZ_QUESTIONS = 5;
// Hard caps: a quiz is a focused exercise, not a question dump; and the
// grading endpoint reuses MAX_QUIZ_QUESTIONS as its per-request item cap.
export const MAX_QUIZ_QUESTIONS = 12;
export const MAX_QUIZ_ALTERNATIVES = 6;

// ---- intent ------------------------------------------------------------

// Whether the latest user message asks to be quizzed, and for how many
// questions. Returns { questions } or null. Deterministic (same pattern as
// hf.js's hfIntent — no model call), so an ordinary question can never
// accidentally become a quiz, and phrased-as-a-request patterns are required:
// bare mentions ("what is a pub quiz?") don't trigger. English + Swedish,
// matching the user base of the rest of the intent gates.
//
// "[qw]uiz": the FIRST production quiz request (2026-07-08, ref 614e6f19)
// arrived as "Bygg en wuiz på 10 varierade frågor…" — a q→w adjacent-key
// typo that defeated the gate and dumped the questions as a plain research
// answer. Tolerating the mistyped first letter is cheap and unambiguous
// ("wuiz" means nothing else); triage also carries a fail-soft `quiz` flag
// as the catch-all for paraphrases the regexes can't foresee
// (prompts.js triagePrompt, pipeline.js runPipeline).
const QUIZ_REQUEST_PATTERNS = [
  /\b(?:[qw]uiz(?:za)?|förhör|grill|test|testa)\s+(?:me|mig|us|oss)\b/i, // "quiz me", "förhör mig", "testa mig"
  /\b(?:make|create|generate|build|prepare|start|run|give\s+me|skapa|gör|bygg|ge\s+mig|kör|starta)\b[^.?!\n]{0,60}?\b(?:[qw]uiz|kunskapstest|förhör)\b/i,
  /\btest(?:a)?\s+(?:my|our|mina|min|våra)\s+(?:knowledge|kunskap(?:er)?)\b/i,
  /^\s*[qw]uiz\b/i, // "quiz: chapter 3", "quiz om Frankrike"
];

// "with 8 questions" / "med 8 frågor" / "10 q" — the requested length. Up to
// two words may sit between the number and the noun ("10 varierade frågor",
// "5 hard questions" — the production request above carried exactly this
// shape and the count was missed).
const QUESTION_COUNT_RE = /(\d{1,2})\s*(?:[\p{L}-]+\s+){0,2}?(?:questions?|frågor|fråga|q\b)/iu;

// The requested question count parsed on its own (null when the message
// names none) — quizIntent uses it, and pipeline.js reuses it when the
// triage `quiz` flag (not this module's regexes) detected the request.
/**
 * @param {unknown} text
 * @returns {number | null} the clamped requested count, or null when unnamed
 */
export function quizQuestionCount(text) {
  const m = String(text || "").match(QUESTION_COUNT_RE);
  if (!m) return null;
  const n = Number(m[1]);
  return n ? Math.min(MAX_QUIZ_QUESTIONS, Math.max(1, n)) : null;
}

/**
 * @param {unknown} text the latest user message
 * @returns {{ questions: number } | null} null when the message isn't a quiz ask
 */
export function quizIntent(text) {
  const s = String(text || "");
  if (!QUIZ_REQUEST_PATTERNS.some((re) => re.test(s))) return null;
  return { questions: quizQuestionCount(s) || DEFAULT_QUIZ_QUESTIONS };
}

// ---- quiz JSON hardening -------------------------------------------------

/** @param {unknown} v @param {number} max */
const clip = (v, max) => String(v ?? "").trim().slice(0, max);

// Hardens the raw quiz-generation JSON into exactly what the client renders,
// or null when nothing usable came back (the pipeline then falls through to
// a normal answer — fail-soft, never an error). Lenient by design: junk
// questions are dropped rather than failing the set; `correct` may be the
// 0-based index OR the correct alternative's text (models mix these up);
// alternatives are deduped and capped; every string is trimmed and clipped.
/**
 * @param {any} value the quiz-generation phase's raw JSON
 * @param {number} [maxQuestions]
 * @returns {Quiz | null}
 */
export function normalizeQuiz(value, maxQuestions = MAX_QUIZ_QUESTIONS) {
  const list = Array.isArray(value?.questions) ? value.questions : [];
  const cap = Math.min(MAX_QUIZ_QUESTIONS, Math.max(1, maxQuestions || MAX_QUIZ_QUESTIONS));
  const questions = [];
  for (const raw of list) {
    const q = normalizeQuestion(raw);
    if (q) questions.push(q);
    if (questions.length >= cap) break;
  }
  if (!questions.length) return null;
  const title = clip(value.title, 120) || "Quiz";
  const intro =
    clip(value.intro, 600) ||
    `**${title}** — ${questions.length} question${questions.length === 1 ? "" : "s"}. ` +
      "Answer each one below; you'll get your score at the end.";
  return { title, intro, questions };
}

/**
 * @param {any} raw
 * @returns {QuizQuestion | null}
 */
function normalizeQuestion(raw) {
  if (!raw || typeof raw !== "object") return null;
  const question = clip(raw.question ?? raw.q, 500);
  if (!question) return null;
  const seen = new Set();
  const alternatives = [];
  for (const a of Array.isArray(raw.alternatives) ? raw.alternatives : []) {
    const alt = clip(a, 300);
    const key = alt.toLowerCase();
    if (!alt || seen.has(key)) continue;
    seen.add(key);
    alternatives.push(alt);
    if (alternatives.length >= MAX_QUIZ_ALTERNATIVES) break;
  }
  if (alternatives.length < 2) return null;
  const correct = resolveCorrect(raw.correct, alternatives);
  if (correct == null) return null;
  return { question, alternatives, correct, explanation: clip(raw.explanation, 600) };
}

// `correct` as a 0-based index into the DEDUPED alternatives, or as the
// correct alternative's text. For a string, the TEXT match is tried first —
// a numeric answer like "1995" is far more often the alternative itself than
// an index — and only an unmatched all-digit string falls back to being an
// index. Anything else → null (the question is dropped: a quiz question with
// an unknown key is useless).
/**
 * @param {unknown} correct
 * @param {string[]} alternatives
 * @returns {number | null}
 */
function resolveCorrect(correct, alternatives) {
  if (typeof correct === "number") {
    return Number.isInteger(correct) && correct >= 0 && correct < alternatives.length ? correct : null;
  }
  if (typeof correct === "string") {
    const s = correct.trim();
    const i = alternatives.findIndex((a) => a.toLowerCase() === s.toLowerCase());
    if (i >= 0) return i;
    if (/^\d+$/.test(s)) {
      const n = Number(s);
      return n < alternatives.length ? n : null;
    }
  }
  return null;
}

// ---- free-text grading (POST /api/quiz/grade) ------------------------------

const MAX_GRADE_QUESTION_CHARS = 500;
const MAX_GRADE_REFERENCE_CHARS = 300;
const MAX_GRADE_ANSWER_CHARS = 1000;

// Validates the grading request body. Returns { items } or { error } —
// items are the trimmed/clipped {question, reference, answer} triples the
// prompt is built from (reference = the quiz's correct alternative).
/**
 * @param {any} body
 * @returns {{ error: string, items?: undefined } | { error?: undefined, items: GradeItem[] }}
 */
export function validateGradeItems(body) {
  const raw = body?.items;
  if (!Array.isArray(raw) || !raw.length || raw.length > MAX_QUIZ_QUESTIONS) {
    return { error: `Expected 1-${MAX_QUIZ_QUESTIONS} items.` };
  }
  const items = [];
  for (const it of raw) {
    const question = clip(it?.question, MAX_GRADE_QUESTION_CHARS);
    const reference = clip(it?.reference, MAX_GRADE_REFERENCE_CHARS);
    const answer = clip(it?.answer, MAX_GRADE_ANSWER_CHARS);
    if (!question || !reference || !answer) {
      return { error: "Each item needs a non-empty question, reference, and answer." };
    }
    items.push({ question, reference, answer });
  }
  return { items };
}

// Hardens the grading model's JSON into exactly `count` {correct, comment}
// verdicts, or null when the shape is unusable (the client then treats those
// answers as ungraded — fail-soft, never a fabricated verdict). A short or
// junk-padded results array is padded with null entries per item so a
// partial grade never misattributes verdicts across items.
/**
 * @param {any} value the grading model's raw JSON
 * @param {number} count how many items were submitted
 * @returns {Array<{ correct: boolean, comment: string } | null> | null}
 */
export function normalizeGradeResults(value, count) {
  const list = Array.isArray(value?.results) ? value.results : Array.isArray(value) ? value : null;
  if (!list) return null;
  const out = [];
  for (let i = 0; i < count; i++) {
    const r = list[i];
    out.push(
      r && typeof r === "object" && typeof r.correct === "boolean"
        ? { correct: r.correct, comment: clip(r.comment, 300) }
        : null,
    );
  }
  return out.some((r) => r !== null) ? out : null;
}

