// @ts-check
// The pipeline's JSON-hardening layer: the declared schemas for every JSON
// planning phase (triage, gap check, validation, the claim checks), the
// hardenJson runner that applies them, and normalizeTriage — the triage
// verdict's normalization plus its model-free fallback when the JSON is
// unusable.
//
// Seam with pipeline.js: pipeline.js owns the phase FLOW and runs each
// phase's parsed model JSON through hardenJson(SCHEMA, …) before its own
// fail-soft handling; this module is pure — no I/O, no SSE events, no model
// calls — so the shapes and the fallback logic are testable on their own
// (src/pipeline.test.js's normalizeTriage suite imports from here).

import { arrayOf, boolean, object, oneOf, string, stringEnum, validate } from "./schema.js";

/**
 * normalizeTriage's hardened verdict: exactly one of the three actions,
 * with the optional decomposition/quiz fields riding on research/direct.
 * @typedef {{ action: "direct", quiz?: boolean }
 *   | { action: "clarify", question: string, quiz?: boolean }
 *   | ResearchDecision} TriageDecision
 */
/**
 * @typedef {{
 *   action: "research",
 *   queries: string[],
 *   complexity?: string,
 *   subquestions?: string[],
 *   quiz?: boolean,
 * }} ResearchDecision
 */

// ---- JSON-phase schemas --------------------------------------------------

// Declared shapes for the three JSON planning phases — a hardening layer over
// the raw model JSON (src/schema.js), applied BEHIND the existing fail-soft
// fallbacks (normalizeTriage etc. stay the last-ditch net). On a clean match
// hardenJson() returns the normalized object; on ANY miss it returns the raw
// value untouched, so a malformed shape degrades exactly as it did before the
// schema existed (single search / accept draft) and never throws.
export const TRIAGE_SCHEMA = oneOf([
  // `quiz` (optional on direct AND research): triage's fail-soft backup for
  // the deterministic quizIntent gate — the first production quiz request
  // arrived with a typo ("wuiz") the regexes missed; a model reads through
  // typos and paraphrases that no pattern list can enumerate. Never the
  // primary gate: quizIntent still decides when it matches, and a stray
  // false `quiz:true` on a non-request costs one fail-soft generation
  // attempt at worst (schema.js's object() strips unknown fields, so the
  // flag must be declared here to survive hardening).
  // The `optional` casts here and below: schema.js's `optional = []` default
  // makes tsc infer never[] for the option in unannotated schema.js.
  object({ action: stringEnum(["direct"]), quiz: boolean() }, /** @type {any} */ ({ optional: ["quiz"] })),
  object({ action: stringEnum(["clarify"]), question: string({ allowEmpty: false }) }),
  object(
    {
      action: stringEnum(["research"]),
      queries: arrayOf(string({ allowEmpty: false })),
      // Decomposition fields (prompts.js DECOMPOSITION_RULE) — both optional:
      // a model that omits them (or an unknown complexity value falling
      // through normalizeTriage's lenient extraction) degrades exactly to the
      // pre-decomposition flow.
      complexity: stringEnum(["simple", "multihop", "comparison", "survey"]),
      subquestions: arrayOf(string({ allowEmpty: false })),
      quiz: boolean(),
    },
    /** @type {any} */ ({ optional: ["queries", "complexity", "subquestions", "quiz"] }),
  ),
]);
export const GAP_SCHEMA = object(
  {
    complete: boolean(),
    queries: arrayOf(string({ allowEmpty: false })),
    // Source disagreements the audit noticed (display + synthesis hint) —
    // optional, and independent of `complete`.
    conflicts: arrayOf(string({ coerce: true })),
  },
  /** @type {any} */ ({ optional: ["complete", "queries", "conflicts"] }),
);
export const VALIDATE_SCHEMA = object(
  {
    verdict: stringEnum(["pass", "revise"]),
    // Display-only list; coerce leniently to match the pipeline's historical
    // `.map(String)` treatment of a stray non-string issue.
    issues: arrayOf(string({ coerce: true })),
    revised_answer: string(),
  },
  /** @type {any} */ ({ optional: ["issues", "revised_answer"] }),
);
// Claim-level validation (high tiers): per-claim verdict and the revision.
export const CLAIM_VERIFY_SCHEMA = object(
  { verdict: stringEnum(["supported", "unsupported"]), issue: string({ coerce: true }) },
  /** @type {any} */ ({ optional: ["issue"] }),
);
export const REVISE_SCHEMA = object({ revised_answer: string() });

// Runs a JSON-phase value through its declared schema. ok → the normalized
// object; miss → the raw value, so the caller's existing fallback path runs
// unchanged. validate() never throws, so this is always safe.
/**
 * @param {object} schema One of the schema declarations above.
 * @param {any} value Raw parsed model JSON (may be anything).
 * @returns {any}
 */
export function hardenJson(schema, value) {
  const r = validate(schema, value);
  return r.ok ? r.value : value;
}

/**
 * Hardens the raw triage JSON into a usable decision, with a model-free
 * fallback (see below) when the JSON is unusable.
 * @param {any} triage Raw triage JSON (may be anything).
 * @param {string} lastUser The latest user message's text.
 * @param {string} [priorUser] The previous user turn's text ("" when none).
 * @returns {TriageDecision}
 */
export function normalizeTriage(triage, lastUser, priorUser = "") {
  // The optional quiz flag (triage's fail-soft backup for quizIntent —
  // see TRIAGE_SCHEMA) rides along on direct/research decisions; lenient
  // strict-boolean extraction so it survives the raw (schema-miss) path.
  const quiz = triage?.quiz === true ? { quiz: true } : {};
  if (triage?.action === "clarify" && typeof triage.question === "string" && triage.question.trim()) {
    return { action: "clarify", question: triage.question.trim() };
  }
  if (triage?.action === "research") {
    const queries = (Array.isArray(triage.queries) ? triage.queries : [])
      .filter((/** @type {any} */ q) => typeof q === "string" && q.trim());
    if (queries.length > 0) {
      /** @type {ResearchDecision} */
      const out = { action: "research", queries, ...quiz };
      // Optional decomposition fields (prompts.js DECOMPOSITION_RULE) —
      // lenient extraction so they survive the raw (schema-miss) path too.
      // Only attached when usable: their absence is the pre-decomposition
      // behavior everywhere downstream.
      if (["simple", "multihop", "comparison", "survey"].includes(triage.complexity)) {
        out.complexity = triage.complexity;
      }
      const subs = (Array.isArray(triage.subquestions) ? triage.subquestions : [])
        .filter((/** @type {any} */ s) => typeof s === "string" && s.trim())
        .map((/** @type {string} */ s) => s.trim())
        .slice(0, 5);
      if (subs.length) out.subquestions = subs;
      return out;
    }
  }
  if (triage?.action === "direct") return { action: "direct", ...quiz };

  // Triage failed to produce usable JSON — decide a fallback WITHOUT a model.
  // A SHORT latest message in an ongoing conversation is almost always a
  // pure back-reference ("undersök saken", "det då?") with no searchable
  // content of its own, so seed the search from the prior question (the
  // established, self-contained topic) rather than the referential phrase.
  // A LONGER follow-up is deliberately left as-is: it carries its own
  // content words (e.g. "…hur det ser ut för sd" — the entity "sd" is right
  // there), which a fuzzy search can use, so replacing it with the prior
  // topic would only DROP that focus. The real fix for an ugly unresolved
  // query is triage itself producing a clean one (triagePrompt's
  // FOLLOWUP_RESOLUTION_RULE + per-model JSON reliability, model-profiles.js)
  // — this fallback only runs on the rare parse-failure path and just avoids
  // the worst case (a bare pronoun going to the web). A short message with no
  // prior context has nothing to resolve against, so answer directly.
  const cur = lastUser.trim();
  const prior = (priorUser || "").trim();
  const looksLikeFollowup = cur.length < 40 && cur.split(/\s+/).filter(Boolean).length <= 6;
  if (prior && looksLikeFollowup) {
    return { action: "research", queries: [prior.slice(0, 300)] };
  }
  return cur.length >= 12
    ? { action: "research", queries: [cur.slice(0, 300)] }
    : { action: "direct" };
}

// Shared, load-bearing types for the Worker, as JSDoc-importable
// declarations. tsconfig always includes this `.d.ts`; no `// @ts-check`
// opt-in is needed for it. Annotated `.js` files reference these from JSDoc
// via `@param {import('./types.js').Env} env` — the `.js` specifier resolves
// to this `.d.ts` under `moduleResolution: bundler`.
//
// This is a module (each type is `export`ed), not a set of ambient globals,
// so nothing here leaks into unannotated files — a file only sees these
// types when it explicitly imports them. The Cloudflare runtime globals it
// references (Fetcher, D1Database, R2Bucket, VectorizeIndex) come from
// `@cloudflare/workers-types` via tsconfig's `types`.
//
// It emits no runtime code and must never be imported at runtime. It doubles
// as machine-readable documentation of the SSE protocol (`SseEvent`) and the
// per-request `state` shape.

// ---- Worker bindings & secrets ---------------------------------------------
// The `env` object Cloudflare hands every request. Bindings (ASSETS, DB,
// STORAGE, RAG_INDEX) are declared by wrangler.toml; the rest are dashboard
// secrets/vars read as `env.NAME`. Optional because several are feature gates
// whose absence disables a feature (see src/settings.js, src/shodan.js,
// src/googlemaps.js) rather than breaking the request.
export interface Env {
  /** Static-assets binding (public/) — always present. */
  ASSETS: Fetcher;
  /** D1 database — optional; absent means break-glass-auth-only, no quotas. */
  DB?: D1Database;
  /** R2 bucket for cloud conversation/file/RAG storage (the server_history knob). */
  STORAGE?: R2Bucket;
  /** Vectorize index for server-side RAG retrieval. */
  RAG_INDEX?: VectorizeIndex;

  // Primary LLM provider (Berget) — see src/berget.js.
  BERGET_API_TOKEN?: string;
  BERGET_MODEL?: string;
  BERGET_EMBED_MODEL?: string;
  /** Test-only override pointing the Berget client at a mock. */
  BERGET_URL?: string;

  // Second LLM provider (Anthropic/Claude) — see src/anthropic.js. The key
  // gates the feature: absent, the claude-* models don't appear at all.
  ANTHROPIC_API_KEY?: string;
  /** Test-only override pointing the Anthropic client at a mock. */
  ANTHROPIC_URL?: string;

  // Third LLM provider (OpenAI/GPT) — see src/openai.js. Same key-gating
  // convention: absent, the gpt-* models don't appear at all.
  OPENAI_API_KEY?: string;
  /** Test-only override pointing the OpenAI client at a mock. */
  OPENAI_URL?: string;

  // Web search (Exa) — see src/exa.js.
  EXA_API_KEY?: string;

  // Break-glass Basic Auth + session signing — see src/auth.js.
  ADMIN_USER?: string;
  ADMIN_PASS?: string;
  BASIC_AUTH_USER?: string;
  BASIC_AUTH_PASS?: string;
  SESSION_SECRET?: string;
  /** Derives the client's encrypted-history key — see src/history-key.js. */
  HISTORY_KEY_SECRET?: string;

  // Google OIDC sign-in — see src/google.js.
  GOOGLE_CLIENT_ID?: string;
  GOOGLE_CLIENT_SECRET?: string;
  /** Test-only overrides pointing the OAuth flow at a mock. */
  GOOGLE_AUTH_URL?: string;
  GOOGLE_TOKEN_URL?: string;
  /** Plaintext dashboard var: the account that is granted the admin role. */
  ADMIN_EMAIL?: string;

  // Enrichment secrets — see src/shodan.js, src/googlemaps.js.
  SHODAN_API_KEY?: string;
  GOOGLE_MAPS_API_KEY?: string;
  /** Optional browser-exposed Embed-API key; defaults to GOOGLE_MAPS_API_KEY. */
  GOOGLE_MAPS_EMBED_KEY?: string;

  /** debug|info|warn|error (default info) — see src/log.js. */
  LOG_LEVEL?: string;

  // Forward-compatible: other string vars/secrets may be present.
  [key: string]: unknown;
}

// ---- Logger (src/log.js) ---------------------------------------------------
/** A single structured-log call: `event` plus a bag of metadata fields. */
export type LogFn = (event: string, fields?: Record<string, unknown>) => void;
export interface Logger {
  debug: LogFn;
  info: LogFn;
  warn: LogFn;
  error: LogFn;
}

// ---- Conversation / message shapes (src/conversation.js) -------------------
/** An OpenAI-style content part: a text span or an image data URL. */
export type ContentPart =
  | { type: "text"; text: string }
  | { type: "image_url"; image_url: { url: string } };
/** Message content is a plain string or a multimodal array of parts. */
export type MessageContent = string | ContentPart[];
/** One turn in the OpenAI-style message array. */
export interface Message {
  role: "user" | "assistant" | "system";
  content: MessageContent;
}
/** The conversation is the message array `/api/chat` receives. */
export type Conversation = Message[];

// ---- Model catalog (src/providers.js) ---------------------------------------
/**
 * One entry of the chat-capable model catalog `/api/models` exposes and
 * validation/pricing consume (`listChatModels` — Berget's live catalog
 * merged with the key-gated secondary-provider entries). `price_in`/
 * `price_out` are raw EUR-per-token prices used for quota cost accounting.
 */
export interface ModelCatalogEntry {
  id: string;
  name: string;
  /** Human-readable pricing tooltip, or null when unpriced. */
  pricing: string | null;
  price_in: number;
  price_out: number;
  /** False when the provider reports the model down/in maintenance. */
  up: boolean;
  /** True when the model accepts image input. */
  vision: boolean;
  /** Which provider serves it ("anthropic" | "openai"); absent for Berget entries. */
  provider?: string;
}
export type ModelCatalog = ModelCatalogEntry[];

// ---- Per-model profile (src/model-profiles.js) -----------------------------
/** The five pipeline phase types the budget planner and EWMA track. */
export type PhaseName = "triage" | "search" | "gap" | "synth" | "validate";
/** Per-phase numeric map (durations in ms, or max_tokens), keyed by phase. */
export type PhaseDurations = Partial<Record<PhaseName, number>>;
/**
 * Evidence-driven per-model overrides layered over model-agnostic defaults.
 * `getModelProfile` returns a fully-populated object (DEFAULT merged with any
 * override), so scalar fields are always present; the nested lookup fields
 * are null when unset.
 */
export interface ModelProfile {
  /** Per-phase duration priors (ms), or null to fall back to global priors. */
  priorsMs: PhaseDurations | null;
  /** Splice a "JSON object only" reinforcement line into JSON-mode prompts. */
  jsonReinforcement: boolean;
  /** Per-phase max_tokens bump for completeJson calls, or null. */
  maxTokensOverride: PhaseDurations | null;
  /** Stop attempting the post-validation phase for this model. */
  skipValidation: boolean;
  /** Total attempts on a clean-but-empty completion (2 = one retry). */
  maxCompletionAttempts: number;
  /** Most images the model accepts per request at Berget, or null (no known limit). */
  maxImages: number | null;
}

// ---- Time-budget plan (src/budget.js) --------------------------------------
/** The Exa search-depth tier chosen for a budget (src/budget.js). */
export interface SearchDepth {
  /** Results requested per Exa search. */
  numResults: number;
  /** Exa search mode: "auto" or the thorough "deep" tier. */
  type: string;
  /** Exa price multiplier vs the standard tier, for honest cost accounting. */
  costMultiplier: number;
}
/** The static allocation `planResearch` returns for a request. */
export interface BudgetPlan {
  budgetMs: number;
  budgetS: number;
  /** Initial search angles to run. */
  queries: number;
  /** Gap-check rounds the budget affords. */
  gapIterations: number;
  /** Follow-up queries per gap round. */
  followups: number;
  /** Whether the post-validation quality gate is reserved. */
  validate: boolean;
  /** Hard cap on total searches across all rounds. */
  maxSearches: number;
  /** Cap on the numbered source registry. */
  maxSources: number;
  /** Char cap on the synthesis digest. */
  digestCap: number;
  /** Per-phase duration estimates the plan was built from. */
  estimates: Record<PhaseName, number>;
  searchDepth: SearchDepth;
}

// ---- Per-request state (src/chat.js newRequestState) -----------------------
/** Prompt/completion token tally for one billing bucket. */
export interface TokenTotals {
  prompt_tokens: number;
  completion_tokens: number;
}
/** A numbered source in the registry synthesis cites from. */
export interface SourceEntry {
  n: number;
  title: string;
  url: string;
  highlights?: string[];
}
/** A validated attached-photo GPS coordinate (src/validation.js). */
export interface ImageLocation {
  name: string;
  lat: number;
  lon: number;
}
/**
 * A validated Street View point-of-view (src/validation.js) — where the user
 * has panned/moved the inline panorama to (body.street_view_pov), so a
 * follow-up can capture exactly the frame on their screen.
 */
export interface StreetViewPov {
  /** The panorama the user is standing in ("" when unknown). */
  panoId: string;
  lat: number;
  lng: number;
  /** Degrees clockwise from north, wrapped into [0, 360). */
  heading: number;
  /** Degrees up/down, clamped to [-90, 90]. */
  pitch: number;
  /** Field of view in degrees, clamped to Street View Static's [10, 120]. */
  fov: number;
}
/**
 * The mutable per-request object threaded through chat.js and pipeline.js.
 * Token usage is split three ways — `totals` (user's answer model),
 * `jsonTotals` (the fixed JSON model), `visionTotals` (the Street View
 * describe helper) — each billed at its own model's catalog rate.
 */
export interface RequestState {
  startedAt: number;
  /** The user's chosen answer/synthesis model. */
  model: string;
  /** The fixed reliable model the JSON planning phases run on. */
  jsonModel: string;
  webSearch: boolean;
  shodan: boolean;
  /** Hosts Shodan returned data for. */
  shodanCount: number;
  /** Developer-mode gate for the introspection enrichment (src/introspect.js). */
  introspection: boolean;
  /** 1 when the source snapshot was actually folded into the conversation. */
  introspectionCount: number;
  /**
   * The deployed source snapshot the introspection enrichment loaded, stashed
   * so the pipeline's source-research phase can READ files from it (the agentic
   * read loop) without a second ASSETS fetch. Absent when dev mode is off or
   * the snapshot was unavailable.
   */
  sourceSnapshot?: import("../public/js/introspect-core.js").Snapshot | null;
  googleMaps: boolean;
  /** 1 when Google Maps data was folded in. */
  mapsCount: number;
  vision: boolean;
  /** Helper model to describe Street View for a non-vision answer model. */
  visionModel: string | null;
  /** Ranked describe-helper candidates (first = visionModel) for failover. */
  visionModels: string[];
  visionTotals: TokenTotals;
  imageLocations: ImageLocation[];
  /** The user's current panorama view, for the capture-what-they-see path. */
  streetViewPov: StreetViewPov | null;
  plan: BudgetPlan;
  searchCount: number;
  /** Searches served from the Exa result cache (not billed). */
  cachedSearchCount: number;
  /** Search waves that ran (initial + gap rounds). */
  iterations: number;
  /** Queries already issued this request, for in-request dedup. */
  ranQueries: Set<string>;
  /** Numbered source registry, deduped by URL. */
  sources: SourceEntry[];
  /** URL -> registry entry, for dedup. */
  byUrl: Map<string, SourceEntry>;
  totals: TokenTotals;
  jsonTotals: TokenTotals;
}

// ---- Pipeline context (src/pipeline.js runPipeline) ------------------------
/**
 * The bundle `runPipeline` builds once and passes to every phase helper.
 * `emit` writes one SSE event; `step`/`stepDone` are its status-event
 * shorthands; `emitDelta` streams a text chunk.
 */
export interface PipelineCtx {
  env: Env;
  log: Logger;
  emit: (event: SseEvent) => void;
  model: string;
  jsonModel: string;
  state: RequestState;
  profile: ModelProfile;
  jsonProfile: ModelProfile;
  conversation: Conversation;
  reinforceJsonOnly: boolean;
  lastUser: string;
  convText: string;
  imageParts: ContentPart[];
  emitDelta: (text: string) => void;
  step: (id: string, label: string) => void;
  stepDone: (id: string, label: string, details?: string[]) => void;
}

// ---- Per-user settings (src/settings.js parseSettings) ---------------------
/** The effective per-account knob state parseSettings coerces to. */
export interface Settings {
  /** Cloud storage of history (default ON — explicit false opts out). */
  server_history: boolean;
  /** Shodan host-intelligence enrichment (default OFF — opt-in). */
  shodan_mcp: boolean;
  /** Google Maps / Street View enrichment (default OFF — opt-in). */
  google_maps: boolean;
  /** Per-reply feedback buttons + the account panel's Feedback view (default OFF — opt-in). */
  feedback_mode: boolean;
  /** The in-browser Linux execution sandbox + bash-lite agent (default OFF — opt-in). */
  bash_lite_mcp: boolean;
  /** Developer mode: unlocks introspection mode (default OFF — opt-in). */
  developer_mode: boolean;
}

// ---- SSE protocol (/api/chat) ----------------------------------------------
// The wire vocabulary of the streaming endpoint. Clients MUST ignore unknown
// `status` types and unknown fields (forward compatibility), so this union is
// the spec, not an exhaustive closed set.

/** A source shown in an expandable search-result list. */
export interface SseSource {
  title: string;
  url: string;
}

/** Pipeline step spinner turned on. */
export interface StatusStepStart {
  type: "step_start";
  /** Names the phase/service: plan|gap1…|synth|validate|geocode|shodan|maps. */
  id: string;
  label: string;
}
/** Pipeline step resolved to a checkmark; `details` renders as a list. */
export interface StatusStepDone {
  type: "step_done";
  id: string;
  label: string;
  details?: string[];
}
/** A web search began (may arrive un-paired before its search_done). */
export interface StatusSearchStart {
  type: "search_start";
  round: number;
  query: string;
}
/** A web search finished; `sources` populates the expandable list. */
export interface StatusSearchDone {
  type: "search_done";
  round: number;
  query: string;
  results: number;
  duration_ms: number;
  sources: SseSource[];
  /** True when served from the Exa result cache (not billed). */
  cached?: boolean;
}
/** Google Maps resolved a Street-View-covered location for an inline embed. */
export interface StatusStreetViewEmbed {
  type: "streetview_embed";
  lat: number;
  lng: number;
}
/**
 * The snapped Street View frames the vision helper reasoned about, for the
 * client to render beside the answer (direction-labeled JPEG data URLs).
 * Bulky by design — the client strips the data URLs out of its research log.
 */
export interface StatusStreetViewFrames {
  type: "streetview_frames";
  query: string;
  /** Each frame carries a cardinal `dir` ("north") OR a free-form `label`
   * ("your current view" — the POV capture path). */
  frames: Array<{ dir: string; label?: string; url: string }>;
}
/** Post-validation rejected the draft: clear streamed text and keep waiting. */
export interface StatusDiscardText {
  type: "discard_text";
}
/** Terminal stats footer. */
export interface StatusDone {
  type: "done";
  model: string;
  rounds: number;
  searches: number;
  duration_ms: number;
  prompt_tokens: number;
  completion_tokens: number;
  /** Additional fields may ride along; clients ignore unknown ones. */
  [key: string]: unknown;
}
/** The discriminated union of every `status` event payload. */
export type SseStatus =
  | StatusStepStart
  | StatusStepDone
  | StatusSearchStart
  | StatusSearchDone
  | StatusStreetViewEmbed
  | StatusStreetViewFrames
  | StatusDiscardText
  | StatusDone;

/** An OpenAI-style text-delta chunk. */
export interface SseDelta {
  choices: Array<{ delta: { content?: string } }>;
}
/** A status event wrapper. */
export interface SseStatusEvent {
  status: SseStatus;
}
/** An error event, shown in the answer bubble. */
export interface SseError {
  error: string;
}
/**
 * Any event written to the `/api/chat` SSE stream: a text delta, a status
 * wrapper, or an error. (The literal `data: [DONE]` terminator is written as
 * a raw line, not an object, so it isn't part of this union.)
 */
export type SseEvent = SseDelta | SseStatusEvent | SseError;

// @ts-check
// Signed-in user JSON APIs (non-chat): the model dropdown catalog, the
// account/usage panel, the history-key fetch, the message center, and the
// client-error beacon. Routed from src/index.js; admin endpoints live in
// src/admin-api.js.

import { countOpenAlerts } from "./alerts.js";
import { countPendingUsers } from "./accounts.js";
import { adminDefaultModelValid, defaultModel } from "./berget.js";
import { listChatModels } from "./providers.js";
import { getConfig } from "./config.js";
import { getDb } from "./db.js";
import { deriveHistoryKey, historyKeyConfigured } from "./history-key.js";
import { jsonResponse } from "./http.js";
import { effectiveQuota, getUsage, PERIODS, quotaExceeded, windowReset } from "./quota.js";
import { countUnreadFeedbackReplies } from "./feedback.js";
import { countUnreadUserMessages, listUserMessages, markAllRead } from "./user-messages.js";

/** @typedef {import('./types.js').Env} Env */
/** @typedef {import('./types.js').Logger} Logger */
/** @typedef {import('./settings.js').Identity} Identity */

// GET /api/models — model catalog for the UI dropdown (filtered + cached in
// src/berget.js), plus the effective default (admin-configured when valid
// and up, else the Worker default).
/**
 * @param {Env} env
 * @param {Logger} log
 * @returns {Promise<Response>}
 */
export async function handleModels(env, log) {
  try {
    const models = await listChatModels(env);
    const config = await getConfig(env);
    const configured = adminDefaultModelValid(config, models);
    log.debug("models.list", { count: models.length });
    return jsonResponse({ models, default: configured ? config.default_model : defaultModel(env) });
  } catch (err) {
    log.error("models.error", { error: (/** @type {any} */ (err))?.message || String(err) });
    return jsonResponse({ error: "Could not load the model catalog." }, 502);
  }
}

// POST /api/client-error — navigator.sendBeacon target: the client reports
// why ITS side of a chat stream died (the server often can't tell — a
// download-triggered navigation or backgrounded tab kills the fetch without
// a clean disconnect). Whitelisted metadata only, hard-capped; the browser
// error string is not user content. Correlate via chat_request_id (the
// x-request-id the client read off the /api/chat response).
/**
 * @param {Request} request
 * @param {Logger} log
 * @param {Identity} identity
 * @returns {Promise<Response>}
 */
export async function handleClientError(request, log, identity) {
  /** @type {any} */
  let body = {};
  try {
    const raw = await request.text();
    if (raw.length <= 2048) body = JSON.parse(raw);
  } catch {
    body = {};
  }
  /** @param {unknown} v @param {number} max */
  const str = (v, max) => (typeof v === "string" ? v.slice(0, max) : undefined);
  log.warn("chat.client_error", {
    user_id: identity.id,
    chat_request_id: str(body.request_id, 64),
    error: str(body.error, 200),
    was_hidden: body.was_hidden === true,
    received_chars: Number.isFinite(body.received_chars) ? body.received_chars : 0,
  });
  return new Response(null, { status: 204 });
}

// POST /api/client-log — a general client telemetry beacon (navigator.sendBeacon
// / keepalive fetch). Its first user is the in-browser Linux sandbox filesystem
// integration (public/js/sandbox.js): booting, mounting user files, the seed
// script, exports — all of which run CLIENT-side and would otherwise be
// invisible to Workers Logs. The client batches events; the Worker re-emits each
// through the structured logger so they reach the log URL (`wrangler tail` /
// Workers Logs), correlated by user_id. Every event carries `client: true` so
// it's easy to distinguish from server-originated events.
//
// Levels are honored: a `debug` event only surfaces when LOG_LEVEL=debug, so
// heavy testing flips LOG_LEVEL to debug for per-file detail and back to info
// for production-level milestones — no client redeploy. Untrusted + bounded:
// event names and field values are clamped, the batch is capped, no message
// content is logged (invariant 4 / the log.js privacy rules). Fail-soft: always
// 204 so the client never blocks on telemetry.
/**
 * @param {Request} request
 * @param {Logger} log
 * @param {Identity} identity
 * @returns {Promise<Response>}
 */
export async function handleClientLog(request, log, identity) {
  /** @type {any} */
  let body = {};
  try {
    const raw = await request.text();
    if (raw.length <= 16384) body = JSON.parse(raw);
  } catch {
    body = {};
  }
  const scope = typeof body.scope === "string" ? body.scope.slice(0, 32) : "client";
  const ua = typeof body.ua === "string" ? body.ua.slice(0, 140) : "";
  const events = Array.isArray(body.events) ? body.events.slice(0, 100) : [];
  const LEVELS = new Set(["debug", "info", "warn", "error"]);
  // Clamp one event's arbitrary extra fields into safe log values: short
  // strings, finite numbers, booleans. Drop everything else (no nested objects,
  // no message content). Keeps the log line bounded and injection-free.
  /** @param {any} ev */
  const fieldsOf = (ev) => {
    /** @type {Record<string, unknown>} */
    const out = {};
    if (!ev || typeof ev !== "object") return out;
    let n = 0;
    for (const [k, v] of Object.entries(ev)) {
      if (k === "level" || k === "event") continue;
      if (n++ >= 20) break;
      const key = String(k).slice(0, 40);
      if (typeof v === "string") out[key] = v.slice(0, 300);
      else if (typeof v === "number" && Number.isFinite(v)) out[key] = v;
      else if (typeof v === "boolean") out[key] = v;
    }
    return out;
  };
  for (const ev of events) {
    const level = LEVELS.has(ev && ev.level) ? ev.level : "info";
    const event = typeof (ev && ev.event) === "string" ? ev.event.slice(0, 80) : "client.event";
    const emit = /** @type {(e: string, f: Record<string, unknown>) => void} */ (
      (/** @type {any} */ (log))[level] || log.info
    );
    emit(event, { client: true, user_id: identity.id, scope, ua, ...fieldsOf(ev) });
  }
  return new Response(null, { status: 204 });
}

// GET /api/history-key — a per-user key (src/history-key.js) the client
// uses to encrypt/decrypt its own locally-stored chat history
// (public/js/history-store.js). Fails closed (503) when
// HISTORY_KEY_SECRET isn't configured — there is deliberately no
// plaintext fallback, since that would defeat the point of the feature.
/**
 * @param {Env} env
 * @param {Identity} identity
 * @returns {Promise<Response>}
 */
export async function handleHistoryKey(env, identity) {
  if (!historyKeyConfigured(env)) {
    return jsonResponse({ error: "Encrypted chat history is not configured on this server." }, 503);
  }
  const key = await deriveHistoryKey(env, identity.id);
  return jsonResponse({ key });
}

// GET /api/me — identity + usage vs quota for the user dashboard.
// The Berget budget is cost-based but OPAQUE to users: only a percentage
// leaves the server (never the EUR amounts). Searches are plain counts.
/**
 * @param {Env} env
 * @param {Identity} identity
 * @returns {Promise<Response>}
 */
export async function handleMe(env, identity) {
  const config = await getConfig(env);
  const usage = await getUsage(env, identity.id);
  const quota = identity.isSecretAdmin ? null : effectiveQuota(config, identity.user);
  /** @type {Record<string, { budget_pct: number | null, searches: number, searches_limit: number, reset: number }>} */
  const windows = {};
  for (const p of PERIODS) {
    const budget = quota?.[p]?.budget_eur || 0;
    windows[p] = {
      budget_pct:
        budget > 0 ? Math.min(999, Math.round((100 * usage[p].berget_cost) / budget)) : null,
      searches: usage[p].searches,
      searches_limit: quota?.[p]?.searches || 0,
      reset: windowReset(p, Date.now(), usage.h5_oldest),
    };
  }
  const isAdmin = identity.isSecretAdmin || identity.role === "admin";
  // Notification badge (header account button, visible outside /admin and
  // the message center too): every identity gets its own unread message
  // count (quota exhausted/restored, approvals, quota changes — see
  // src/user-messages.js); admins additionally get pending sign-in
  // approvals + open operational alerts folded into the same total.
  // Unread agent replies on the user's feedback threads count too — the
  // "the developers wrote back" signal Feedback mode's dialogue depends on.
  const [unreadMessages, unreadFeedback] = await Promise.all([
    countUnreadUserMessages(env, identity.id),
    countUnreadFeedbackReplies(env, identity.id),
  ]);
  /** @type {{ unread_messages: number, unread_feedback: number, total: number, pending_users?: number, open_alerts?: number }} */
  let notifications = {
    unread_messages: unreadMessages,
    unread_feedback: unreadFeedback,
    total: unreadMessages + unreadFeedback,
  };
  if (isAdmin) {
    const [pendingUsers, openAlerts] = /** @type {[number, number]} */ (
      await Promise.all([countPendingUsers(env), countOpenAlerts(env)])
    );
    notifications = {
      unread_messages: unreadMessages,
      unread_feedback: unreadFeedback,
      pending_users: pendingUsers,
      open_alerts: openAlerts,
      total: unreadMessages + unreadFeedback + pendingUsers + openAlerts,
    };
  }
  return jsonResponse({
    id: identity.id,
    email: identity.email,
    name: identity.name,
    role: identity.role,
    unlimited: !!identity.isSecretAdmin,
    // Admins see their bars fill and overflow, but are never blocked.
    enforced: !identity.isSecretAdmin && identity.role !== "admin",
    windows,
    notifications,
    db_configured: !!(await getDb(env)),
  });
}

// GET /api/messages — the personal side of the message center (account.js):
// quota exhausted/restored, sign-in approved, quota changed by an admin.
// "Restored" isn't stored — a quota_exceeded row is annotated `resolved`
// here by checking the caller's CURRENT quota state, so a block that has
// since lifted reads as good news without a second write. Opening this
// list marks everything read (same one-shot pattern as the account panel
// already uses for /api/me).
/**
 * @param {Env} env
 * @param {Identity} identity
 * @returns {Promise<Response>}
 */
export async function handleMessages(env, identity) {
  const messages = await listUserMessages(env, identity.id, { limit: 50 });
  let currentBlock = null;
  if (messages.some((m) => m.type === "quota_exceeded")) {
    const config = await getConfig(env);
    const usage = await getUsage(env, identity.id);
    const quota = identity.isSecretAdmin ? null : effectiveQuota(config, identity.user);
    currentBlock = quota ? quotaExceeded(usage, quota) : null;
  }
  const out = messages.map((m) => {
    if (m.type !== "quota_exceeded") return { ...m, resolved: null };
    const stillBlocked = currentBlock && currentBlock.period === m.period && currentBlock.kind === m.kind;
    return { ...m, resolved: !stillBlocked };
  });
  await markAllRead(env, identity.id);
  return jsonResponse({ messages: out });
}

// @ts-check
// Per-user message center: account-level notices (quota exhausted/restored,
// sign-in approved, quota changed by an admin) — NOT a chat feature. Only
// structured enums (type/period/kind) and timestamps are ever stored, never
// free text — there is deliberately no content column. This keeps the
// feature inside the same zero-retention promise the privacy notice makes
// for actual conversations: nothing derived from a user's question or a
// model's answer ever passes through this module.
//
// "Restored" isn't a separately-logged event — it's derived at read time by
// comparing a stored quota_exceeded row's (period, kind) against the
// caller's CURRENT quota state (src/quota.js), so a stale block doesn't
// need a second write to resolve itself.

import { getDb } from "./db.js";

/** @typedef {import('./types.js').Env} Env */
/**
 * A D1 `user_messages` row — structured enums and timestamps ONLY (see the
 * header: there is deliberately no content column).
 * @typedef {{ id: number, user_id: string, type: string, period?: string | null, kind?: string | null, created_at: number, read_at?: number | null }} UserMessageRow
 */

const DEDUP_WINDOW_MS = 60 * 60 * 1000; // 1h: don't log a new row per blocked request

// type: "quota_exceeded" | "account_approved" | "quota_changed"
// period/kind: only meaningful for quota_exceeded (see src/quota.js's PERIODS
// and quotaExceeded()'s "budget"|"searches" kinds); null otherwise.
/**
 * @param {Env} env
 * @param {number | string} userId
 * @param {string} type
 * @param {{ period?: string | null, kind?: string | null }} [details]
 */
export async function addUserMessage(env, userId, type, { period = null, kind = null } = {}) {
  const db = await getDb(env);
  if (!db) return;
  const recent = await db
    .prepare(
      `SELECT id FROM user_messages
       WHERE user_id = ? AND type = ? AND period IS ? AND kind IS ? AND created_at > ?
       ORDER BY created_at DESC LIMIT 1`,
    )
    .bind(String(userId), type, period, kind, Date.now() - DEDUP_WINDOW_MS)
    .first();
  if (recent) return;
  await db
    .prepare(`INSERT INTO user_messages (user_id, type, period, kind, created_at) VALUES (?, ?, ?, ?, ?)`)
    .bind(String(userId), type, period, kind, Date.now())
    .run()
    .catch(() => {});
}

/**
 * Newest-first messages for one user.
 * @param {Env} env
 * @param {number | string} userId
 * @param {{ limit?: number }} [options]
 * @returns {Promise<UserMessageRow[]>}
 */
export async function listUserMessages(env, userId, { limit = 50 } = {}) {
  const db = await getDb(env);
  if (!db) return [];
  const { results } = await db
    .prepare(`SELECT * FROM user_messages WHERE user_id = ? ORDER BY created_at DESC LIMIT ?`)
    .bind(String(userId), limit)
    .all();
  return /** @type {UserMessageRow[]} */ (results || []);
}

/**
 * Unread-count for the notification badge (/api/me).
 * @param {Env} env
 * @param {number | string} userId
 * @returns {Promise<number>}
 */
export async function countUnreadUserMessages(env, userId) {
  const db = await getDb(env);
  if (!db) return 0;
  const row = await db
    .prepare(`SELECT COUNT(*) AS n FROM user_messages WHERE user_id = ? AND read_at IS NULL`)
    .bind(String(userId))
    .first();
  return /** @type {number} */ (row?.n) || 0;
}

/**
 * @param {Env} env
 * @param {number | string} userId
 */
export async function markAllRead(env, userId) {
  const db = await getDb(env);
  if (!db) return;
  await db
    .prepare(`UPDATE user_messages SET read_at = ? WHERE user_id = ? AND read_at IS NULL`)
    .bind(Date.now(), String(userId))
    .run();
}

// @ts-check
// Request validation for POST /api/chat: message/content shape, image caps,
// and model resolution (catalog membership, availability, vision).

import { defaultModel } from "./berget.js";
import { countImages, imagePartsOf, lastUserMessage } from "./conversation.js";
import { getModelProfile } from "./model-profiles.js";
import { MAX_SHELL_ROUNDS } from "./bash-agent.js";

const MAX_MESSAGES = 60;
const MAX_MESSAGE_CHARS = 32_000;
const MAX_IMAGES_PER_MESSAGE = 4;
const MAX_IMAGES_PER_REQUEST = 8; // history is resent every turn — keep bounded
// Berget rejects request bodies over ~1 MB ("Request payload too large";
// measured 2026-07: 1.0M chars OK, 1.2M rejected). The client downscales
// images to fit; these server caps leave headroom for text/history.
const MAX_IMAGE_CHARS = 300_000; // per image, as a data URL
const MAX_TOTAL_IMAGE_CHARS = 750_000; // per request
const MAX_IMAGE_LOCATIONS = 4; // matches MAX_IMAGES_PER_REQUEST's practical ceiling per message
const MAX_LOCATION_NAME_CHARS = 200;

// Returns an error string for invalid input, or null when acceptable.
/**
 * @param {any} messages untrusted request body field
 * @returns {string | null} an error message, or null when acceptable
 */
export function validateMessages(messages) {
  if (!Array.isArray(messages) || messages.length === 0) {
    return "Expected a non-empty `messages` array.";
  }
  if (messages.length > MAX_MESSAGES) {
    return `Conversation too long (max ${MAX_MESSAGES} messages). Start a new chat.`;
  }
  let totalImages = 0;
  let totalImageChars = 0;
  for (const m of messages) {
    if (m?.role !== "user" && m?.role !== "assistant") {
      return "Each message must have role `user` or `assistant`.";
    }
    if (typeof m.content === "string") {
      if (m.content.length > MAX_MESSAGE_CHARS) {
        return `A message exceeds the ${MAX_MESSAGE_CHARS}-character limit.`;
      }
      continue;
    }
    if (!Array.isArray(m.content) || m.content.length === 0) {
      return "Each message `content` must be a string or a non-empty array of parts.";
    }
    let textChars = 0;
    let images = 0;
    for (const part of m.content) {
      if (part?.type === "text" && typeof part.text === "string") {
        textChars += part.text.length;
      } else if (part?.type === "image_url" && typeof part.image_url?.url === "string") {
        const url = part.image_url.url;
        if (!url.startsWith("data:image/")) {
          return "Images must be attached as data:image/… URLs.";
        }
        if (url.length > MAX_IMAGE_CHARS) {
          return "An attached image is too large after encoding (~220 KB max per image). Reload the page — it now compresses images automatically.";
        }
        images++;
        totalImages++;
        totalImageChars += url.length;
      } else {
        return "Unsupported message content part.";
      }
    }
    if (textChars > MAX_MESSAGE_CHARS) {
      return `A message exceeds the ${MAX_MESSAGE_CHARS}-character limit.`;
    }
    if (images > MAX_IMAGES_PER_MESSAGE) {
      return `Too many images in one message (max ${MAX_IMAGES_PER_MESSAGE}).`;
    }
  }
  if (totalImages > MAX_IMAGES_PER_REQUEST) {
    return `Too many images in the conversation (max ${MAX_IMAGES_PER_REQUEST}). Start a new chat.`;
  }
  if (totalImageChars > MAX_TOTAL_IMAGE_CHARS) {
    return "The attached images together exceed the provider's request size limit. Remove an image or start a new chat.";
  }
  return null;
}

// Sanitizes the client-reported GPS coordinates of attached photos (from
// public/js/exif.js, forwarded as body.imageLocations) before they're used
// for anything — untrusted input, arbitrary shape. Silently drops/caps
// rather than erroring the whole request: a malformed or oversized
// location list just means less (or no) geocoding context, never a
// blocked chat. Returns [] for anything not a non-empty array.
/**
 * @param {any} raw untrusted client-reported GPS coordinates
 * @returns {import('./types.js').ImageLocation[]}
 */
export function validateImageLocations(raw) {
  if (!Array.isArray(raw)) return [];
  const out = [];
  for (const item of raw) {
    if (out.length >= MAX_IMAGE_LOCATIONS) break;
    const lat = Number(item?.lat);
    const lon = Number(item?.lon);
    if (!Number.isFinite(lat) || lat < -90 || lat > 90) continue;
    if (!Number.isFinite(lon) || lon < -180 || lon > 180) continue;
    const name = typeof item?.name === "string" && item.name ? item.name.slice(0, MAX_LOCATION_NAME_CHARS) : "photo";
    out.push({ name, lat, lon });
  }
  return out;
}

// Sanitizes the client-reported Street View point-of-view (from the inline
// StreetViewPanorama the user can pan/move — public/js/activity.js, forwarded
// as body.street_view_pov) before the server captures that exact frame.
// Untrusted input, arbitrary shape: anything unusable returns null (the
// enrichment then falls back to the address walk-back), never a blocked chat.
// Heading wraps into [0,360), pitch clamps to [-90,90], fov to Street View
// Static's [10,120]; the pano id is kept only when it looks like one.
/**
 * @param {any} raw untrusted client-reported Street View POV
 * @returns {import('./types.js').StreetViewPov | null}
 */
export function validateStreetViewPov(raw) {
  if (!raw || typeof raw !== "object") return null;
  const lat = Number(raw.lat);
  const lng = Number(raw.lng);
  if (!Number.isFinite(lat) || lat < -90 || lat > 90) return null;
  if (!Number.isFinite(lng) || lng < -180 || lng > 180) return null;
  const heading = Number(raw.heading);
  const pitch = Number(raw.pitch);
  const fov = Number(raw.fov);
  const panoId = typeof raw.panoId === "string" && /^[\w-]{1,64}$/.test(raw.panoId) ? raw.panoId : "";
  return {
    panoId,
    lat,
    lng,
    heading: Number.isFinite(heading) ? ((Math.round(heading) % 360) + 360) % 360 : 0,
    pitch: Number.isFinite(pitch) ? Math.max(-90, Math.min(90, Math.round(pitch))) : 0,
    fov: Number.isFinite(fov) ? Math.max(10, Math.min(120, Math.round(fov))) : 90,
  };
}

// Sanitizes the client-reported interactive-map view (from the inline
// google.maps.Map the user can pan/zoom — public/js/activity.js, forwarded
// as body.map_view) before the server captures a road-map image of that
// exact area. Untrusted input, arbitrary shape: anything unusable returns
// null (the enrichment then falls back to the address walk-back), never a
// blocked chat. Zoom clamps to the Static Maps API's [0,21].
/** @param {any} raw */
export function validateMapView(raw) {
  if (!raw || typeof raw !== "object") return null;
  const lat = Number(raw.lat);
  const lng = Number(raw.lng);
  if (!Number.isFinite(lat) || lat < -90 || lat > 90) return null;
  if (!Number.isFinite(lng) || lng < -180 || lng > 180) return null;
  const zoom = Number(raw.zoom);
  return {
    lat,
    lng,
    zoom: Number.isFinite(zoom) ? Math.max(0, Math.min(21, Math.round(zoom))) : 17,
  };
}

// Resolves the model for a request against the (possibly null) catalog:
// validates the override, checks availability, and enforces vision when the
// conversation carries images. Returns { model } on success or
// { error, status } to reject. Catalog unreachable → fall back to the
// default and let Berget be the judge downstream.
/**
 * @param {any} body the parsed request body ({ model?, messages })
 * @param {import('./types.js').ModelCatalogEntry[] | null | undefined} catalog
 * @param {import('./types.js').Env} env
 * @param {import('./types.js').Logger} log
 * @returns {{ model: string } | { error: string, status: number }}
 */
export function resolveModel(body, catalog, env, log) {
  let model = typeof body.model === "string" && body.model ? body.model : null;

  if (model && catalog) {
    const entry = catalog.find((m) => m.id === model);
    if (!entry) {
      log.warn("chat.invalid_model", { model: model.slice(0, 120) });
      return { error: "Unknown model.", status: 400 };
    }
    if (!entry.up) {
      log.warn("chat.model_down", { model: model.slice(0, 120) });
      return {
        error: `${entry.name} is temporarily unavailable (down for maintenance at Berget). Pick another model.`,
        status: 400,
      };
    }
  } else if (model && !catalog) {
    model = null;
  }
  const activeModel = model || defaultModel(env);

  if (countImages(body.messages) > 0 && catalog) {
    const entry = catalog.find((m) => m.id === activeModel);
    if (entry && !entry.vision) {
      const alternatives = catalog
        .filter((m) => m.vision && m.up)
        .map((m) => m.name)
        .join(", ");
      log.warn("chat.model_no_vision", { model: activeModel.slice(0, 120) });
      return {
        error:
          `${entry.name} does not support image input.` +
          (alternatives ? ` Vision-capable models: ${alternatives}.` : ""),
        status: 400,
      };
    }
    // Some vision models cap how many images one request may carry (a
    // reproduced per-model Berget limit — model-profiles.js). Only the
    // LATEST user message's images are forwarded to the answer call
    // (conversation.js/pipeline.js), so that's the count that matters.
    // Reject with a clear message instead of letting the answer call die
    // on Berget's opaque 400 ("invalid_request").
    const maxImages = getModelProfile(activeModel).maxImages;
    const latestImages = imagePartsOf(lastUserMessage(body.messages)).length;
    if (maxImages && latestImages > maxImages) {
      log.warn("chat.model_image_cap", { model: activeModel.slice(0, 120), images: latestImages, max: maxImages });
      return {
        error:
          `${entry?.name || activeModel} accepts at most ${maxImages} image${maxImages === 1 ? "" : "s"} per message. ` +
          `Remove ${latestImages - maxImages} image${latestImages - maxImages === 1 ? "" : "s"} or pick another vision-capable model.`,
        status: 400,
      };
    }
  }

  return { model: activeModel };
}

/**
 * Coerces the client's bash-lite `shell_transcript` into a clean, bounded
 * array of runs — untrusted input, so every field is typed/clamped and the
 * whole thing is capped (the loop runs at most MAX_SHELL_ROUNDS rounds × a few
 * commands). Non-array or junk entries degrade to an empty transcript, so the
 * answer path is byte-identical to a run without the sandbox.
 * @param {any} raw
 * @returns {Array<{ command: string, exitCode: number, stdout: string, stderr: string }>}
 */
export function resolveShellTranscript(raw) {
  if (!Array.isArray(raw)) return [];
  const out = [];
  for (const r of raw) {
    if (!r || typeof r !== "object" || typeof r.command !== "string" || !r.command.trim()) continue;
    out.push({
      command: r.command,
      exitCode: Number.isFinite(Number(r.exitCode)) ? Math.trunc(Number(r.exitCode)) : 1,
      stdout: typeof r.stdout === "string" ? r.stdout : "",
      stderr: typeof r.stderr === "string" ? r.stderr : "",
    });
    if (out.length >= MAX_SHELL_ROUNDS * 8) break;
  }
  return out;
}

/**
 * Coerces the client's diagnostic block (public/js/stream.js client_diag) to a
 * small, whitelisted shape for the chat log — untrusted, so every field is
 * typed and bounded. Undefined (dropped by JSON.stringify) when absent.
 * @param {any} d
 * @returns {{ coi: boolean|null, bl: boolean, sb: boolean, ran: number, css: string, sab: boolean, ua: string, fs: ({ n: number, b: number, proj: boolean, drop: number, ms: number, err: string } | undefined) } | undefined}
 */
export function sanitizeClientDiag(d) {
  if (!d || typeof d !== "object") return undefined;
  return {
    coi: d.coi === true ? true : d.coi === false ? false : null,
    bl: d.bl === true,
    sb: d.sb === true,
    ran: Number.isFinite(d.ran) ? Math.max(0, Math.min(50, Math.trunc(d.ran))) : 0,
    css: typeof d.css === "string" ? d.css.slice(0, 16) : "",
    sab: d.sab === true,
    ua: typeof d.ua === "string" ? d.ua.slice(0, 140) : "",
    // The last sandbox filesystem-mount summary (public/js/sandbox.js
    // sandboxFsSummary): whether files mounted, how many, total bytes, a
    // project mount, dropped count, boot ms, and any error — so a mount
    // problem is visible in the chat log without the debug beacon.
    fs: sanitizeFsSummary(d.fs),
  };
}

/**
 * Whitelist the sandbox filesystem-mount summary (untrusted, bounded).
 * @param {any} f
 * @returns {{ n: number, b: number, proj: boolean, drop: number, ms: number, err: string } | undefined}
 */
export function sanitizeFsSummary(f) {
  if (!f || typeof f !== "object") return undefined;
  /** @param {any} v @param {number} max */
  const int = (v, max) => (Number.isFinite(v) ? Math.max(0, Math.min(max, Math.trunc(v))) : 0);
  return {
    n: int(f.n, 1000),
    b: int(f.b, 1e12),
    proj: f.proj === true,
    drop: int(f.drop, 1000),
    ms: int(f.ms, 600000),
    err: typeof f.err === "string" ? f.err.slice(0, 200) : "",
  };
}

// Unit tests for validation.js: message/image caps, model + vision
// resolution, and the image-location / Street View POV / map-view sanitizers.
import { test, describe } from "node:test";
import assert from "node:assert/strict";
import {
  validateMessages,
  resolveModel,
  validateImageLocations,
  validateMapView,
  validateStreetViewPov,
  resolveShellTranscript,
  sanitizeClientDiag,
  sanitizeFsSummary,
} from "./validation.js";
import { DEFAULT_MODEL } from "./berget.js";

const noopLog = { warn: () => {} };

describe("validateMessages", () => {
  test("rejects a non-array or empty messages value", () => {
    assert.match(validateMessages(null), /non-empty/);
    assert.match(validateMessages([]), /non-empty/);
  });

  test("rejects more than 60 messages", () => {
    const messages = Array.from({ length: 61 }, () => ({ role: "user", content: "hi" }));
    assert.match(validateMessages(messages), /too long/);
  });

  test("accepts exactly 60 messages", () => {
    const messages = Array.from({ length: 60 }, () => ({ role: "user", content: "hi" }));
    assert.equal(validateMessages(messages), null);
  });

  test("rejects an unknown role", () => {
    const messages = [{ role: "system", content: "hi" }];
    assert.match(validateMessages(messages), /role `user` or `assistant`/);
  });

  test("rejects a string message over the character limit", () => {
    const messages = [{ role: "user", content: "x".repeat(32_001) }];
    assert.match(validateMessages(messages), /character limit/);
  });

  test("accepts a string message at exactly the character limit", () => {
    const messages = [{ role: "user", content: "x".repeat(32_000) }];
    assert.equal(validateMessages(messages), null);
  });

  test("rejects content that is neither a string nor a non-empty array", () => {
    assert.match(validateMessages([{ role: "user", content: 42 }]), /string or a non-empty array/);
    assert.match(validateMessages([{ role: "user", content: [] }]), /string or a non-empty array/);
  });

  test("rejects an unsupported content part type", () => {
    const messages = [{ role: "user", content: [{ type: "video", url: "x" }] }];
    assert.match(validateMessages(messages), /Unsupported message content part/);
  });

  test("sums text parts against the per-message character limit", () => {
    const messages = [
      {
        role: "user",
        content: [
          { type: "text", text: "x".repeat(20_000) },
          { type: "text", text: "y".repeat(20_000) },
        ],
      },
    ];
    assert.match(validateMessages(messages), /character limit/);
  });

  test("rejects an image_url part whose url is not a data:image/ URL", () => {
    const messages = [{ role: "user", content: [{ type: "image_url", image_url: { url: "https://example.com/x.png" } }] }];
    assert.match(validateMessages(messages), /data:image/);
  });

  test("rejects a single image over the per-image size cap", () => {
    const url = "data:image/png;base64," + "a".repeat(300_000);
    const messages = [{ role: "user", content: [{ type: "image_url", image_url: { url } }] }];
    assert.match(validateMessages(messages), /too large after encoding/);
  });

  test("rejects more than 4 images in one message", () => {
    const part = { type: "image_url", image_url: { url: "data:image/png;base64,x" } };
    const messages = [{ role: "user", content: [part, part, part, part, part] }];
    assert.match(validateMessages(messages), /Too many images in one message/);
  });

  test("rejects more than 8 images across the whole conversation", () => {
    const part = { type: "image_url", image_url: { url: "data:image/png;base64,x" } };
    const messages = Array.from({ length: 9 }, () => ({ role: "user", content: [part] }));
    assert.match(validateMessages(messages), /Too many images in the conversation/);
  });

  test("rejects total image bytes over the per-request cap even under the per-message/per-request count caps", () => {
    const url = "data:image/png;base64," + "a".repeat(200_000);
    const part = { type: "image_url", image_url: { url } };
    // 4 images x 200,000 chars = 800,000 > 750,000 total cap, but only 1 message and 4 images (both under their own caps).
    const messages = [{ role: "user", content: [part, part, part, part] }];
    assert.match(validateMessages(messages), /provider's request size limit/);
  });

  test("accepts a well-formed mixed text+image conversation", () => {
    const messages = [
      { role: "user", content: "hello" },
      { role: "assistant", content: "hi there" },
      {
        role: "user",
        content: [
          { type: "text", text: "look at this" },
          { type: "image_url", image_url: { url: "data:image/png;base64,abc" } },
        ],
      },
    ];
    assert.equal(validateMessages(messages), null);
  });
});

describe("resolveModel", () => {
  const catalog = [
    { id: "vision-model", name: "Vision Model", up: true, vision: true },
    { id: "text-model", name: "Text Model", up: true, vision: false },
    { id: "down-model", name: "Down Model", up: false, vision: true },
  ];

  test("no model in body and no catalog falls back to the env default", () => {
    const result = resolveModel({ messages: [] }, null, {}, noopLog);
    assert.equal(result.model, DEFAULT_MODEL);
  });

  test("unknown model id against a real catalog is rejected", () => {
    const result = resolveModel({ model: "nonexistent", messages: [] }, catalog, {}, noopLog);
    assert.equal(result.status, 400);
    assert.match(result.error, /Unknown model/);
  });

  test("a model marked down in the catalog is rejected", () => {
    const result = resolveModel({ model: "down-model", messages: [] }, catalog, {}, noopLog);
    assert.equal(result.status, 400);
    assert.match(result.error, /temporarily unavailable/);
  });

  test("a valid, up model in the catalog is accepted", () => {
    const result = resolveModel({ model: "text-model", messages: [] }, catalog, {}, noopLog);
    assert.equal(result.model, "text-model");
  });

  test("a requested model is ignored (not validated) when the catalog is unreachable", () => {
    const result = resolveModel({ model: "text-model", messages: [] }, null, {}, noopLog);
    assert.equal(result.model, DEFAULT_MODEL);
  });

  test("images present + resolved model lacks vision is rejected, listing vision-capable alternatives", () => {
    const messages = [{ role: "user", content: [{ type: "image_url", image_url: { url: "x" } }] }];
    const result = resolveModel({ model: "text-model", messages }, catalog, {}, noopLog);
    assert.equal(result.status, 400);
    assert.match(result.error, /does not support image input/);
    assert.match(result.error, /Vision Model/);
  });

  test("images present + resolved model has vision is accepted", () => {
    const messages = [{ role: "user", content: [{ type: "image_url", image_url: { url: "x" } }] }];
    const result = resolveModel({ model: "vision-model", messages }, catalog, {}, noopLog);
    assert.equal(result.model, "vision-model");
  });

  test("a model with a profiled per-request image cap rejects an over-limit latest message clearly", () => {
    // 2026-07-08 live probe: Mistral Medium 400s ("invalid_request", opaque)
    // on >2 images — model-profiles.js carries maxImages: 2. Without this
    // check the answer call dies on that opaque Berget 400 mid-stream.
    const capped = [...catalog, { id: "mistralai/Mistral-Medium-3.5-128B", name: "Mistral Medium", up: true, vision: true }];
    const img = { type: "image_url", image_url: { url: "x" } };
    const over = [{ role: "user", content: [{ type: "text", text: "q" }, img, img, img] }];
    const result = resolveModel({ model: "mistralai/Mistral-Medium-3.5-128B", messages: over }, capped, {}, noopLog);
    assert.equal(result.status, 400);
    assert.match(result.error, /at most 2 images per message/);
    assert.match(result.error, /Remove 1 image /);

    // At the cap: accepted.
    const atCap = [{ role: "user", content: [{ type: "text", text: "q" }, img, img] }];
    const ok = resolveModel({ model: "mistralai/Mistral-Medium-3.5-128B", messages: atCap }, capped, {}, noopLog);
    assert.equal(ok.model, "mistralai/Mistral-Medium-3.5-128B");
  });

  test("the image cap counts only the LATEST user message (history images are stripped for the answer call)", () => {
    const capped = [...catalog, { id: "mistralai/Mistral-Medium-3.5-128B", name: "Mistral Medium", up: true, vision: true }];
    const img = { type: "image_url", image_url: { url: "x" } };
    const messages = [
      { role: "user", content: [{ type: "text", text: "a" }, img, img] },
      { role: "assistant", content: "…" },
      { role: "user", content: [{ type: "text", text: "b" }, img, img] },
    ];
    const ok = resolveModel({ model: "mistralai/Mistral-Medium-3.5-128B", messages }, capped, {}, noopLog);
    assert.equal(ok.model, "mistralai/Mistral-Medium-3.5-128B");
  });

  test("images present but the resolved model isn't found in the catalog: not rejected on vision grounds", () => {
    const messages = [{ role: "user", content: [{ type: "image_url", image_url: { url: "x" } }] }];
    const result = resolveModel({ messages }, catalog, {}, noopLog);
    assert.equal(result.model, DEFAULT_MODEL);
  });
});

describe("validateImageLocations", () => {
  test("non-array input returns an empty list rather than throwing", () => {
    assert.deepEqual(validateImageLocations(undefined), []);
    assert.deepEqual(validateImageLocations(null), []);
    assert.deepEqual(validateImageLocations("not an array"), []);
    assert.deepEqual(validateImageLocations({}), []);
  });

  test("passes through valid entries with name/lat/lon", () => {
    const out = validateImageLocations([{ name: "photo.jpg", lat: 40.7128, lon: -74.006 }]);
    assert.deepEqual(out, [{ name: "photo.jpg", lat: 40.7128, lon: -74.006 }]);
  });

  test("drops entries with out-of-range or non-finite lat/lon", () => {
    const out = validateImageLocations([
      { name: "a", lat: 91, lon: 0 },
      { name: "b", lat: 0, lon: 181 },
      { name: "c", lat: NaN, lon: 0 },
      { name: "d", lat: "not a number", lon: 0 },
      { name: "e", lat: 10, lon: 20 }, // the only valid one
    ]);
    assert.deepEqual(out, [{ name: "e", lat: 10, lon: 20 }]);
  });

  test("boundary values (±90 lat, ±180 lon) are accepted, not off-by-one rejected", () => {
    const out = validateImageLocations([
      { name: "a", lat: 90, lon: 180 },
      { name: "b", lat: -90, lon: -180 },
    ]);
    assert.equal(out.length, 2);
  });

  test("caps the list at 4 entries", () => {
    const raw = Array.from({ length: 10 }, (_, i) => ({ name: `p${i}`, lat: i, lon: i }));
    const out = validateImageLocations(raw);
    assert.equal(out.length, 4);
    assert.equal(out[0].name, "p0");
  });

  test("a missing/non-string name defaults to 'photo'; an oversized name is truncated", () => {
    const out = validateImageLocations([
      { lat: 1, lon: 1 },
      { name: 42, lat: 2, lon: 2 },
      { name: "x".repeat(500), lat: 3, lon: 3 },
    ]);
    assert.equal(out[0].name, "photo");
    assert.equal(out[1].name, "photo");
    assert.equal(out[2].name.length, 200);
  });

  test("coerces numeric strings but rejects non-numeric ones", () => {
    const out = validateImageLocations([{ name: "a", lat: "12.5", lon: "-45.5" }]);
    assert.deepEqual(out, [{ name: "a", lat: 12.5, lon: -45.5 }]);
  });
});

describe("validateStreetViewPov", () => {
  test("returns null for junk shapes and out-of-range coordinates", () => {
    assert.equal(validateStreetViewPov(undefined), null);
    assert.equal(validateStreetViewPov(null), null);
    assert.equal(validateStreetViewPov("x"), null);
    assert.equal(validateStreetViewPov({}), null);
    assert.equal(validateStreetViewPov({ lat: 91, lng: 0 }), null);
    assert.equal(validateStreetViewPov({ lat: 0, lng: 181 }), null);
    assert.equal(validateStreetViewPov({ lat: "no", lng: 10 }), null);
  });

  test("keeps a well-formed POV, rounding the view angles", () => {
    const out = validateStreetViewPov({ panoId: "abc-DEF_123", lat: 59.4, lng: 17.9, heading: 143.6, pitch: -5.4, fov: 90 });
    assert.deepEqual(out, { panoId: "abc-DEF_123", lat: 59.4, lng: 17.9, heading: 144, pitch: -5, fov: 90 });
  });

  test("wraps heading into [0,360) and clamps pitch/fov", () => {
    const out = validateStreetViewPov({ lat: 1, lng: 2, heading: -90, pitch: 400, fov: 5 });
    assert.deepEqual(out, { panoId: "", lat: 1, lng: 2, heading: 270, pitch: 90, fov: 10 });
    const out2 = validateStreetViewPov({ lat: 1, lng: 2, heading: 725, pitch: -400, fov: 500 });
    assert.deepEqual(out2, { panoId: "", lat: 1, lng: 2, heading: 5, pitch: -90, fov: 120 });
