describe("resolveShellTranscript", () => {
  test("non-array or junk degrades to an empty transcript", () => {
    assert.deepEqual(resolveShellTranscript(undefined), []);
    assert.deepEqual(resolveShellTranscript(null), []);
    assert.deepEqual(resolveShellTranscript("x"), []);
    assert.deepEqual(resolveShellTranscript([null, 3, {}, { command: "  " }]), []);
  });

  test("types and clamps each run; a bad exitCode defaults to 1", () => {
    const out = resolveShellTranscript([
      { command: "ls", exitCode: 0, stdout: "a", stderr: "" },
      { command: "false", exitCode: "nope", stdout: 5, stderr: null },
    ]);
    assert.deepEqual(out, [
      { command: "ls", exitCode: 0, stdout: "a", stderr: "" },
      { command: "false", exitCode: 1, stdout: "", stderr: "" },
    ]);
  });

  test("caps the transcript length (untrusted input bound)", () => {
    const many = Array.from({ length: 500 }, () => ({ command: "x", exitCode: 0, stdout: "", stderr: "" }));
    // MAX_SHELL_ROUNDS * 8 is the cap; whatever it is, the output is bounded well below 500.
    assert.ok(resolveShellTranscript(many).length < 500);
  });
});

describe("sanitizeClientDiag / sanitizeFsSummary", () => {
  test("undefined for absent or non-object input", () => {
    assert.equal(sanitizeClientDiag(undefined), undefined);
    assert.equal(sanitizeClientDiag("x"), undefined);
    assert.equal(sanitizeFsSummary(null), undefined);
  });

  test("whitelists and bounds the diag fields", () => {
    const out = sanitizeClientDiag({
      coi: true, bl: true, sb: false, ran: 999, css: "0123456789abcdefGHIJ",
      sab: true, ua: "u".repeat(300), extra: "dropped",
    });
    assert.equal(out.coi, true);
    assert.equal(out.bl, true);
    assert.equal(out.sb, false);
    assert.equal(out.ran, 50); // clamped to [0,50]
    assert.equal(out.css.length, 16); // sliced to 16
    assert.equal(out.ua.length, 140); // sliced to 140
    assert.equal(out.extra, undefined); // not whitelisted
  });

  test("booleans coerce strictly: only === true is true", () => {
    assert.equal(sanitizeClientDiag({ bl: 1 }).bl, false); // 1 !== true
    assert.equal(sanitizeClientDiag({ bl: true }).bl, true);
    assert.equal(sanitizeClientDiag({}).coi, null); // tri-state defaults to null
  });

  test("nested fs summary is bounded", () => {
    const fs = sanitizeFsSummary({ n: 5000, b: -3, proj: true, drop: 2, ms: 1e9, err: "e".repeat(500), extra: 1 });
    assert.equal(fs.n, 1000); // clamped to max 1000
    assert.equal(fs.b, 0); // negative floored to 0
    assert.equal(fs.proj, true);
    assert.equal(fs.ms, 600000); // clamped to max
    assert.equal(fs.err.length, 200); // sliced
    assert.equal(fs.extra, undefined);
  });
});

// @ts-check
// The secret-keyed project vault (R2 binding `STORAGE`, key family
// `vault/{uid}/{vaultId}`): stores one CLIENT-ENCRYPTED project archive per
// vault id — an opaque byte blob AES-256-GCM encrypted in the browser under
// a key derived from a user-held secret (public/js/vault.js) that the
// server NEVER sees, not even transiently. This is deliberately a stronger
// posture than the history-key model (src/history-key.js): there the server
// could re-derive the key from its own secret; here it holds nothing that
// could ever decrypt a vault object. The vault id itself is derived from
// the same secret (HKDF, separate info string), so knowing the secret is
// both the locator and the key — the server stores unlabeled ciphertext.
//
// This is what lets a LOCAL-ONLY project (per-project cloud knob off, or
// the whole account knob off) still be backed up / moved across devices
// through the server without giving up the local-only privacy posture:
// nothing readable — no project name, no file names, no text, no index —
// ever leaves the browser. For that reason the endpoints are NOT gated on
// the `server_history` knob (unlike src/storage.js): each PUT is its own
// explicit, user-initiated act of consent, and the knob governs the
// readable-adjacent knob-driven store, not this ciphertext-only one. For
// the same reason the account-wide drain (DELETE /api/storage, flipping
// the knob off) deliberately does NOT touch vault objects — they were
// stored by explicit action while the knob may well have been off, and
// wiping them would destroy the very backups the user made on purpose.
//
// Object lifecycle: the client keeps the current vault id inside the
// (encrypted) project record and re-stores by PUT-ting the new blob under
// the NEW secret's id and deleting the old id — so storing again rotates
// the secret and the previous secret stops working. A lost secret means an
// undecryptable orphan blob; the per-user object cap below bounds how much
// of those can accumulate.

import { jsonResponse } from "./http.js";
import { storageAvailability } from "./settings.js";

/** @typedef {import('./types.js').Env} Env */
/** @typedef {import('./types.js').Logger} Logger */
/** @typedef {import('./settings.js').Identity} Identity */

// An archive carries a whole project — record, conversations, original file
// bytes (base64 inside the JSON before encryption) and the RAG index with
// vectors — so the cap is well above the convo/file caps in src/storage.js.
export const VAULT_MAX_BYTES = 100 * 1024 * 1024;
export const MAX_VAULT_OBJECTS = 50; // per user — sanity backstop, not a product limit
// AES-GCM blob = 12-byte IV + ciphertext + 16-byte tag; anything shorter
// cannot be a valid archive.
export const VAULT_MIN_BYTES = 12 + 16 + 1;

// Vault ids are HKDF-derived by the client (32 Crockford-base32 chars) —
// long enough that a short/guessable path segment is rejected outright.
/** @param {unknown} s */
export const vaultIdOk = (s) => typeof s === "string" && /^[A-Za-z0-9_-]{16,80}$/.test(s);

/** @param {number | string} uid @param {string} id */
const vaultKey = (uid, id) => `vault/${uid}/${id}`;

/** @param {Env} env @returns {R2Bucket} */
const bucket = (env) => /** @type {R2Bucket} */ (env.STORAGE);

// Router for /api/vault/:id — called from src/index.js once the identity is
// resolved. Objects are namespaced per user id: a vault blob is reachable
// only from the account that stored it (the secret alone is not enough
// from someone else's account — defense in depth on top of the unguessable
// id).
/**
 * @param {Request} request
 * @param {Env} env
 * @param {URL} url
 * @param {Logger} log
 * @param {Identity} identity
 * @returns {Promise<Response>}
 */
export async function handleVault(request, env, url, log, identity) {
  const available = storageAvailability(env, identity);
  if (!available.storage || !identity.user) {
    return jsonResponse({ error: "Cloud storage is not configured on this server." }, 503);
  }
  const uid = identity.user.id;
  const parts = url.pathname.split("/").filter(Boolean); // ["api", "vault", id]
  const id = parts[2] ? decodeURIComponent(parts[2]) : null;
  if (!id || parts.length !== 3) return jsonResponse({ error: "Not found." }, 404);
  if (!vaultIdOk(id)) return jsonResponse({ error: "Invalid vault id." }, 400);

  if (request.method === "GET") return getVault(env, uid, id);
  if (request.method === "PUT") return putVault(request, env, log, identity, uid, id);
  if (request.method === "DELETE") {
    await bucket(env).delete(vaultKey(uid, id));
    return new Response(null, { status: 204 });
  }
  return jsonResponse({ error: "Not found." }, 404);
}

/** @param {Env} env @param {number | string} uid @param {string} id */
async function getVault(env, uid, id) {
  const obj = await bucket(env).get(vaultKey(uid, id));
  if (!obj) return jsonResponse({ error: "Not found." }, 404);
  return new Response(obj.body, {
    headers: {
      // Ciphertext is all there is — there is no readable form to advertise.
      "content-type": "application/octet-stream",
      "x-vault-updated": obj.customMetadata?.updatedAt || "",
    },
  });
}

/**
 * @param {Request} request
 * @param {Env} env
 * @param {Logger} log
 * @param {Identity} identity
 * @param {number | string} uid
 * @param {string} id
 */
async function putVault(request, env, log, identity, uid, id) {
  const declared = Number(request.headers.get("content-length")) || 0;
  if (declared > VAULT_MAX_BYTES) return jsonResponse({ error: "Archive too large." }, 413);
  const bytes = await request.arrayBuffer();
  if (bytes.byteLength > VAULT_MAX_BYTES) return jsonResponse({ error: "Archive too large." }, 413);
  if (bytes.byteLength < VAULT_MIN_BYTES) {
    return jsonResponse({ error: "Not a valid encrypted archive." }, 400);
  }
  const key = vaultKey(uid, id);
  if (!(await bucket(env).head(key))) {
    let count = 0;
    let cursor;
    do {
      const page = await bucket(env).list({ prefix: `vault/${uid}/`, cursor });
      count += page.objects.length;
      cursor = page.truncated ? page.cursor : undefined;
    } while (cursor);
    if (count >= MAX_VAULT_OBJECTS) {
      return jsonResponse({ error: "Vault limit reached — delete or overwrite an existing copy." }, 409);
    }
  }
  const updatedAt = Date.now();
  await bucket(env).put(key, bytes, {
    httpMetadata: { contentType: "application/octet-stream" },
    customMetadata: { updatedAt: String(updatedAt) },
  });
  log.debug("vault.put", { user_id: identity.id, size: bytes.byteLength });
  return jsonResponse({ ok: true, id, size: bytes.byteLength, updatedAt });
}

import test from "node:test";
import assert from "node:assert/strict";
import { handleVault, vaultIdOk, MAX_VAULT_OBJECTS, VAULT_MIN_BYTES } from "./vault.js";

// In-memory stand-in for the R2 binding — just enough surface for vault.js.
function mockBucket() {
  const store = new Map();
  return {
    async get(key) {
      const v = store.get(key);
      return v ? { body: v.bytes, customMetadata: v.meta } : null;
    },
    async head(key) {
      return store.has(key) ? {} : null;
    },
    async put(key, bytes, opts) {
      store.set(key, { bytes, meta: opts?.customMetadata || {} });
    },
    async delete(key) {
      store.delete(key);
    },
    async list({ prefix }) {
      const objects = [...store.keys()].filter((k) => k.startsWith(prefix)).map((key) => ({ key }));
      return { objects, truncated: false };
    },
    _store: store,
  };
}

const log = { debug() {}, info() {}, warn() {}, error() {} };
const VALID_ID = "0123456789ABCDEFGHJKMNPQRSTVWXYZ"; // 32 chars, the client's Crockford shape

function makeEnv() {
  return { STORAGE: mockBucket() };
}

function identityFor(settingsJson = null) {
  return { id: "user:7", role: "user", email: null, name: null, user: { id: 7, settings_json: settingsJson } };
}

function call(env, identity, method, id, body) {
  const url = new URL("https://example.test/api/vault/" + encodeURIComponent(id));
  const request = new Request(url, { method, body });
  return handleVault(request, env, url, log, identity);
}

test("vaultIdOk accepts the client's derived-id shape and rejects junk", () => {
  assert.equal(vaultIdOk(VALID_ID), true);
  assert.equal(vaultIdOk("a".repeat(16)), true);
  assert.equal(vaultIdOk("a".repeat(80)), true);
  assert.equal(vaultIdOk("short"), false); // too short to be a derived id
  assert.equal(vaultIdOk("a".repeat(81)), false);
  assert.equal(vaultIdOk("has/slash-in-it-1"), false);
  assert.equal(vaultIdOk("has.dot-in-it-123"), false);
  assert.equal(vaultIdOk(""), false);
  assert.equal(vaultIdOk(null), false);
});

test("503 when the R2 binding is missing or the identity has no user row", async () => {
  const noBinding = await call({}, identityFor(), "GET", VALID_ID);
  assert.equal(noBinding.status, 503);
  const breakGlass = await call(makeEnv(), { id: "admin", role: "admin", user: null }, "GET", VALID_ID);
  assert.equal(breakGlass.status, 503);
});

test("invalid vault id is rejected before touching storage", async () => {
  const res = await call(makeEnv(), identityFor(), "GET", "short");
  assert.equal(res.status, 400);
});

test("PUT then GET round-trips the opaque bytes; DELETE removes them", async () => {
  const env = makeEnv();
  const identity = identityFor();
  const blob = crypto.getRandomValues(new Uint8Array(64)); // opaque ciphertext stand-in

  const put = await call(env, identity, "PUT", VALID_ID, blob);
  assert.equal(put.status, 200);
  const putBody = await put.json();
  assert.equal(putBody.ok, true);
  assert.equal(putBody.size, 64);

  const get = await call(env, identity, "GET", VALID_ID);
  assert.equal(get.status, 200);
  assert.equal(get.headers.get("content-type"), "application/octet-stream");
  assert.ok(get.headers.get("x-vault-updated"));
  assert.deepEqual(new Uint8Array(await get.arrayBuffer()), blob);

  const del = await call(env, identity, "DELETE", VALID_ID);
  assert.equal(del.status, 204);
  const gone = await call(env, identity, "GET", VALID_ID);
  assert.equal(gone.status, 404);
});

test("GET of a never-stored id is a 404", async () => {
  const res = await call(makeEnv(), identityFor(), "GET", VALID_ID);
  assert.equal(res.status, 404);
});

test("a body too small to be an AES-GCM blob is rejected", async () => {
  const res = await call(makeEnv(), identityFor(), "PUT", VALID_ID, new Uint8Array(VAULT_MIN_BYTES - 1));
  assert.equal(res.status, 400);
});

test("an over-cap declared content-length is rejected without reading the body", async () => {
  const env = makeEnv();
  const url = new URL("https://example.test/api/vault/" + VALID_ID);
  // Duck-typed request: a real Request recomputes content-length from the
  // body, so the declared-length path needs a hand-rolled header.
  const request = {
    method: "PUT",
    headers: new Headers({ "content-length": String(200 * 1024 * 1024) }),
    arrayBuffer: async () => {
      throw new Error("body must not be read");
    },
  };
  const res = await handleVault(request, env, url, log, identityFor());
  assert.equal(res.status, 413);
});

test("the vault works with the server_history knob OFF — that is the point", async () => {
  const env = makeEnv();
  const identity = identityFor(JSON.stringify({ server_history: false }));
  const put = await call(env, identity, "PUT", VALID_ID, new Uint8Array(64));
  assert.equal(put.status, 200);
  const get = await call(env, identity, "GET", VALID_ID);
  assert.equal(get.status, 200);
});

test("per-user object cap blocks NEW ids but allows overwriting an existing one", async () => {
  const env = makeEnv();
  const identity = identityFor();
  for (let i = 0; i < MAX_VAULT_OBJECTS; i++) {
    env.STORAGE._store.set(`vault/7/existing-${String(i).padStart(12, "0")}`, {
      bytes: new Uint8Array(64),
      meta: {},
    });
  }
  const blocked = await call(env, identity, "PUT", VALID_ID, new Uint8Array(64));
  assert.equal(blocked.status, 409);
  const overwrite = await call(env, identity, "PUT", "existing-000000000001", new Uint8Array(64));
  assert.equal(overwrite.status, 200);
});

test("objects are namespaced per user — another account cannot read them", async () => {
  const env = makeEnv();
  await call(env, identityFor(), "PUT", VALID_ID, new Uint8Array(64));
  const other = { id: "user:8", role: "user", user: { id: 8 } };
  const res = await call(env, other, "GET", VALID_ID);
  assert.equal(res.status, 404);
});

// Pure, dependency-free scoring + aggregation helpers for the LLM-judged
// research benchmark (see eval-bench.mjs for the live runner and
// bench-questions.mjs for the fixed question set).
//
// Everything here is deterministic and import-safe in plain Node — no
// network, no Berget/Exa, no DOM — so it is unit-tested directly in
// bench-score.test.js. The one function that *builds a prompt for* an LLM
// judge (buildJudgePrompt) is still pure: it only assembles a string, it
// does not call anything. Keeping the metrics that DON'T need a model
// (source diversity, citation coverage) separate from the ones that do
// (the judge's 1-5 scores) is the point — the non-LLM metrics are free,
// deterministic, and catch the round-7 "over-cites its own domain" class
// of regression without spending a judge token.

// --- domain helpers -------------------------------------------------------

// Extract a normalized registrable-ish hostname from a URL string. Mirrors
// src/pipeline.js's hostnameOf intent (lowercase, strip a leading "www.")
// but is written to be import-safe outside a Worker and tolerant of URLs
// with no scheme (Exa/registry entries are not always fully-qualified).
export function hostnameOf(url) {
  if (typeof url !== "string" || !url.trim()) return "";
  let u = url.trim();
  if (!/^[a-z][a-z0-9+.-]*:\/\//i.test(u)) u = "https://" + u; // add scheme if missing
  let host = "";
  try {
    host = new URL(u).hostname;
  } catch {
    // Fall back to a crude host slice for genuinely malformed input.
    host = u.replace(/^[a-z]+:\/\//i, "").split(/[/?#]/)[0];
  }
  host = host.toLowerCase().replace(/^www\./, "");
  return host;
}

// --- non-LLM metric: source diversity ------------------------------------

// Domain-diversity metric over a trace's source list. `sources` is an array
// of { title?, url } (the shape the SSE search_done events and the answer's
// "Sources:" registry carry). Returns a bundle of raw counts plus a single
// normalized `score` in [0,1] that a summary can average.
//
// The headline signal for the round-7 self-citation trap is `maxDomainShare`
// (what fraction of all sources came from the single most-cited domain) and
// its inverse-flavored companions. `score` blends breadth (distinct domains
// per source) with concentration (1 - Herfindahl index of the domain
// distribution) so a run that cites 12 sources all from one site scores low
// even though it has "many" sources.
export function sourceDiversity(sources) {
  const list = Array.isArray(sources) ? sources : [];
  const domains = list.map((s) => hostnameOf(s && s.url)).filter(Boolean);
  const total = domains.length;

  if (total === 0) {
    return {
      total: 0,
      uniqueDomains: 0,
      maxDomainShare: 0,
      topDomain: null,
      herfindahl: 0,
      score: 0,
      perDomain: {},
    };
  }

  const perDomain = {};
  for (const d of domains) perDomain[d] = (perDomain[d] || 0) + 1;
  const uniqueDomains = Object.keys(perDomain).length;

  let topDomain = null;
  let topCount = 0;
  for (const [d, c] of Object.entries(perDomain)) {
    if (c > topCount) {
      topCount = c;
      topDomain = d;
    }
  }
  const maxDomainShare = topCount / total;

  // Herfindahl-Hirschman index of the domain distribution: sum of squared
  // shares. 1.0 = everything from one domain (no diversity); →0 = spread
  // thin across many domains. (1 - HHI) is a clean concentration-diversity.
  let herfindahl = 0;
  for (const c of Object.values(perDomain)) {
    const share = c / total;
    herfindahl += share * share;
  }

  // Blend breadth (unique/total) with the concentration-diversity (1-HHI).
  // Both are in [0,1]; equal weight. A single source scores 1.0 on breadth
  // but the caller can read `total` to know it's thin.
  const breadth = uniqueDomains / total;
  const spread = 1 - herfindahl;
  const score = round3((breadth + spread) / 2);

  return {
    total,
    uniqueDomains,
    maxDomainShare: round3(maxDomainShare),
    topDomain,
    herfindahl: round3(herfindahl),
    score,
    perDomain,
  };
}

// --- non-LLM metric: citation coverage -----------------------------------

// Count distinct inline [n] citation markers in an answer and detect the
// presence of a trailing "Sources:" list — the two structural properties
// synthPrompt is supposed to guarantee. Returns counts plus a boolean; the
// judge separately scores whether each [n] actually SUPPORTS its sentence
// (that needs the source text, hence a model), but "are there citations at
// all, and a sources list" is mechanically checkable here for free.
export function citationCoverage(answerText) {
  const text = typeof answerText === "string" ? answerText : "";
  const nums = new Set();
  // Match [1], [12], and bracketed multi-refs like [1, 2] / [1,2,3].
  const re = /\[(\d+(?:\s*,\s*\d+)*)\]/g;
  let m;
  while ((m = re.exec(text)) !== null) {
    for (const part of m[1].split(",")) {
      const n = parseInt(part.trim(), 10);
      if (Number.isFinite(n)) nums.add(n);
    }
  }
  const distinctCitations = nums.size;
  // "Sources:" list — case-insensitive, at a line start (the synthPrompt
  // convention), tolerant of markdown bold/heading prefixes.
  const hasSourcesList = /(^|\n)\s*(?:#+\s*|\*+\s*)?sources\s*:/i.test(text);

  return {
    distinctCitations,
    hasSourcesList,
    // Highest citation index referenced — a cheap sanity signal: an answer
    // citing [9] with only 3 sources listed is likely hallucinating refs.
    maxCitationIndex: nums.size ? Math.max(...nums) : 0,
    // 1 if it has both any citation and a sources list, else a partial
    // credit so the number is aggregatable alongside the judge dimensions.
    score: round3((distinctCitations > 0 ? 0.5 : 0) + (hasSourcesList ? 0.5 : 0)),
  };
}

// --- aggregation ----------------------------------------------------------

// Aggregate an array of per-question result objects into mean/median per
// numeric dimension plus an overall. Each entry is expected to carry a
// `scores` object of { dimension: number } (the judge's citation/coverage/
// calibration on a 1-5 scale, plus the non-LLM diversity/citation scores
// normalized however the caller stored them). Non-numeric / missing values
// are skipped per-dimension (a failed run contributes nothing rather than a
// zero that silently drags the mean). `overall` is the mean of each entry's
// own overall if present, else the mean across all its numeric dimensions.
export function aggregateScores(perQuestion) {
  const entries = Array.isArray(perQuestion) ? perQuestion : [];
  const dims = {}; // dimension -> array of numbers

  const collect = (obj) => {
    if (!obj || typeof obj !== "object") return;
    for (const [k, v] of Object.entries(obj)) {
      if (typeof v === "number" && Number.isFinite(v)) {
        (dims[k] || (dims[k] = [])).push(v);
      }
    }
  };

  const perQuestionOveralls = [];
  for (const e of entries) {
    const scores = e && e.scores ? e.scores : e;
    collect(scores);
    // A per-entry overall, if the caller computed one, feeds the top line.
    if (e && typeof e.overall === "number" && Number.isFinite(e.overall)) {
      perQuestionOveralls.push(e.overall);
    } else if (scores && typeof scores === "object") {
      const nums = Object.values(scores).filter(
        (v) => typeof v === "number" && Number.isFinite(v),
      );
      if (nums.length) perQuestionOveralls.push(mean(nums));
    }
  }

  const dimensions = {};
  for (const [k, arr] of Object.entries(dims)) {
    dimensions[k] = { n: arr.length, mean: round3(mean(arr)), median: round3(median(arr)) };
  }

  return {
    count: entries.length,
    scored: perQuestionOveralls.length,
    dimensions,
    overall: {
      mean: round3(mean(perQuestionOveralls)),
      median: round3(median(perQuestionOveralls)),
    },
  };
}

// --- judge prompt builder -------------------------------------------------

// Build the strict-JSON prompt handed to a strong judge model. The judge is
// given the question, the rubric coverage points, the answer, AND the
// numbered source registry the answer cited from — so it can check whether
// each [n] actually supports the sentence it's attached to (faithfulness),
// not just whether a citation is present. Scores are 1-5; the judge must
// return ONLY a JSON object. Kept pure (string assembly only) so the runner
// can send it through /api/chat in web-search-off mode like any other
// message.
export function buildJudgePrompt({ question, rubric, answer, sources }) {
  const rubricPoints = Array.isArray(rubric) && rubric.length
    ? rubric.map((r, i) => `${i + 1}. ${r}`).join("\n")
    : "(no explicit rubric — judge coverage against what a well-researched answer to the question would need)";

  const registry = Array.isArray(sources) && sources.length
    ? sources
        .map((s, i) => `[${s.n ?? i + 1}] ${s.title || "(untitled)"} — ${s.url || "(no url)"}`)
        .join("\n")
    : "(no sources were captured in the trace)";

  return `You are a strict, impartial evaluator of an AI research assistant's answer. Score it on three dimensions, each on an integer 1-5 scale. Judge only what is present; do not reward length or fluency.

RESEARCH QUESTION:
${question}

RUBRIC — coverage points a strong answer should address:
${rubricPoints}

NUMBERED SOURCE REGISTRY the answer was allowed to cite from (each [n] in the answer refers to one of these):
${registry}

ANSWER UNDER EVALUATION:
${answer}

Score these THREE dimensions (integers 1-5, where 1 = poor, 3 = adequate, 5 = excellent):

1. citation — Citation faithfulness. For each inline [n] marker, does the cited source in the registry plausibly SUPPORT the specific claim in that sentence? Penalize citations that don't match their claim, citations to numbers absent from the registry, and confident factual claims carrying no citation at all. An answer with no sources available cannot score above 2 here.

2. coverage — Coverage of the rubric. How many of the rubric points does the answer substantively address (not just mention)? Full marks only if it covers essentially all of them with real content.

3. calibration — Calibration and honesty. Does it hedge appropriately where sources conflict, distinguish well-established from contested claims, and PLAINLY admit when the question is unanswerable or sources are insufficient — rather than inventing specifics? An answer that fabricates details for an unanswerable question scores 1.

Return ONLY a JSON object, no preamble, no markdown fences, in exactly this shape:
{"citation": <1-5>, "coverage": <1-5>, "calibration": <1-5>, "notes": "<one or two sentences justifying the scores>"}`;
}

// --- small numeric utilities (exported for the test) ----------------------

export function mean(arr) {
  const a = (arr || []).filter((v) => typeof v === "number" && Number.isFinite(v));
  if (!a.length) return 0;
  return a.reduce((s, v) => s + v, 0) / a.length;
}

export function median(arr) {
  const a = (arr || []).filter((v) => typeof v === "number" && Number.isFinite(v)).sort((x, y) => x - y);
  if (!a.length) return 0;
  const mid = Math.floor(a.length / 2);
  return a.length % 2 ? a[mid] : (a[mid - 1] + a[mid]) / 2;
}

function round3(n) {
  if (typeof n !== "number" || !Number.isFinite(n)) return 0;
  return Math.round(n * 1000) / 1000;
}

// Unit tests for the PURE helpers in bench-score.mjs. No network, no LLM —
// deterministic inputs/outputs only. Run: node --test tests/bench-score.test.js
import { test } from "node:test";
import assert from "node:assert/strict";
import {
  hostnameOf,
  sourceDiversity,
  citationCoverage,
  aggregateScores,
  mean,
  median,
} from "./bench-score.mjs";

test("hostnameOf normalizes scheme, www, and case", () => {
  assert.equal(hostnameOf("https://www.Example.com/path?q=1"), "example.com");
  assert.equal(hostnameOf("http://sub.example.com"), "sub.example.com");
  assert.equal(hostnameOf("example.org/foo"), "example.org"); // no scheme
  assert.equal(hostnameOf("WWW.NASA.GOV"), "nasa.gov");
  assert.equal(hostnameOf(""), "");
  assert.equal(hostnameOf(null), "");
  assert.equal(hostnameOf(undefined), "");
});

test("sourceDiversity: empty list is a zero bundle", () => {
  const d = sourceDiversity([]);
  assert.equal(d.total, 0);
  assert.equal(d.uniqueDomains, 0);
  assert.equal(d.maxDomainShare, 0);
  assert.equal(d.score, 0);
  assert.equal(d.topDomain, null);
  assert.deepEqual(d.perDomain, {});
  assert.deepEqual(sourceDiversity(null), sourceDiversity(undefined));
});

test("sourceDiversity: all-distinct domains score high", () => {
  const d = sourceDiversity([
    { url: "https://a.com/x" },
    { url: "https://b.org/y" },
    { url: "https://c.net/z" },
    { url: "https://d.io/w" },
  ]);
  assert.equal(d.total, 4);
  assert.equal(d.uniqueDomains, 4);
  assert.equal(d.maxDomainShare, 0.25);
  assert.equal(d.herfindahl, 0.25); // 4 * (1/4)^2
  // breadth = 1, spread = 1 - 0.25 = 0.75 -> (1+0.75)/2 = 0.875
